#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include "test.h"

void knn(
    float inputQuery[NUM_FEATURE],
    float searchSpace[NUM_PT_IN_SEARCHSPACE*NUM_FEATURE],
    float distance[NUM_PT_IN_SEARCHSPACE]
){
    float sum;
    float feature_delta;
    for(int i = 0; i < NUM_PT_IN_SEARCHSPACE; ++i){
        sum = 0.0f;
        for(int j = 0; j < NUM_FEATURE; ++j){
            feature_delta = searchSpace[i*NUM_FEATURE+j] - inputQuery[j];
            sum += feature_delta*feature_delta;
        }
        distance[i] = sum;
    }
    return;
}

int main(){
    float *inputQuery = (float*)malloc(sizeof(float) * NUM_FEATURE);
    float *searchSpace = (float*)malloc(sizeof(float) * NUM_PT_IN_SEARCHSPACE * NUM_FEATURE);
    float *distance = (float*)malloc(sizeof(float) * NUM_PT_IN_SEARCHSPACE);
    if(!inputQuery || !searchSpace || !distance){
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    for(int j = 0; j < NUM_FEATURE; ++j){
        inputQuery[j] = 0.5f * (j + 1);
    }

    for(int i = 0; i < NUM_PT_IN_SEARCHSPACE; ++i){
        for(int j = 0; j < NUM_FEATURE; ++j){
            searchSpace[i*NUM_FEATURE + j] = (float)(i % 1000) + 0.1f * j;
        }
    }

    knn(inputQuery, searchSpace, distance);

    for(int i = 0; i < 10 && i < NUM_PT_IN_SEARCHSPACE; ++i){
        printf("distance[%d] = %f\n", i, distance[i]);
    }

    free(inputQuery);
    free(searchSpace);
    free(distance);
    return 0;
}

