#include <bits/stdc++.h>
using namespace std;

int main() {
    // Match original testbench constants
    const int NUM_FEATURE = 3;
    const int NUM_PT_IN_SEARCHSPACE = 4;
    const int FRAC = 16;         // Q16.16
    const int NUM_CYCLES = 24;

    // Flattened vectors (32-bit signed per element)
    vector<int32_t> tb_inputQuery_flat(NUM_FEATURE);
    vector<int32_t> tb_searchSpace_flat(NUM_PT_IN_SEARCHSPACE * NUM_FEATURE);
    vector<int32_t> dut_distance_flat(NUM_PT_IN_SEARCHSPACE);

    // Open CSV file for writing
    std::ofstream ofs("c_output.csv", std::ofstream::out);
    if (!ofs.is_open()) {
        cerr << "Failed to open c_output.csv for writing\n";
        return 1;
    }

    // Write header row
    ofs << "cycle";
    for (int j = 0; j < NUM_FEATURE; ++j) {
        ofs << ",inputQuery[" << j << "]";
    }
    for (int idx = 0; idx < NUM_PT_IN_SEARCHSPACE * NUM_FEATURE; ++idx) {
        ofs << ",searchSpace[" << idx << "]";
    }
    for (int i = 0; i < NUM_PT_IN_SEARCHSPACE; ++i) {
        ofs << ",distance[" << i << "]";
    }
    ofs << "\n";

    // Write role row
    ofs << "meta";
    for (int j = 0; j < NUM_FEATURE; ++j) ofs << ",in";
    for (int idx = 0; idx < NUM_PT_IN_SEARCHSPACE * NUM_FEATURE; ++idx) ofs << ",in";
    for (int i = 0; i < NUM_PT_IN_SEARCHSPACE; ++i) ofs << ",out";
    ofs << "\n";

    // Helper: convert real to Q16.16 signed 32-bit (truncating toward zero)
    auto real_to_q16_16 = [&](double r) -> int32_t {
        double scaled = r * (1ULL << FRAC);
        // Truncate toward zero (cast from double to long long in C++ truncates toward zero)
        long long tmp = static_cast<long long>(scaled);
        return static_cast<int32_t>(tmp);
    };

    // Helper: format 32-bit word as uppercase hex without leading "0x" and without leading zeros
    auto to_hex32 = [&](uint32_t v) -> string {
        // Use snprintf with %X which produces uppercase hex and omits leading zeros except for zero itself
        char buf[11]; // enough for 8 hex digits + null
        if (v == 0) {
            return "0";
        }
        std::snprintf(buf, sizeof(buf), "%X", v);
        return string(buf);
    };

    // For each cycle: prepare inputs, compute distances, write CSV row
    for (int cycle = 0; cycle < NUM_CYCLES; ++cycle) {
        // prepare inputs
        double base = (cycle - (NUM_CYCLES / 2)) * 0.5; // as real
        for (int jj = 0; jj < NUM_FEATURE; ++jj) {
            double v = base + (jj) * 0.25 + ((cycle % 3) == 0 ? 0.125 : 0.0);
            tb_inputQuery_flat[jj] = real_to_q16_16(v);
        }

        for (int ii = 0; ii < NUM_PT_IN_SEARCHSPACE; ++ii) {
            for (int jj = 0; jj < NUM_FEATURE; ++jj) {
                int idx = ii * NUM_FEATURE + jj;
                double v = (ii * 3 + jj) * 0.75;
                if (((cycle + ii) % 4) == 0) v = -v;
                if ((cycle % 5) == 0) v = v + 0.333;
                v = v + cycle * 0.125;
                tb_searchSpace_flat[idx] = real_to_q16_16(v);
            }
        }

        // "Release reset" and let DUT compute distances:
        // Simulate DUT by computing sum of squared differences.
        // Both inputs and searchSpace are Q16.16 (int32_t). We compute:
        // diff = in - sp (Q16.16, int64_t)
        // square = (diff * diff) >> FRAC  -> brings back to Q16.16 scale (approx)
        // sum over features into a 64-bit accumulator, then truncate to 32-bit for output.
        for (int ii = 0; ii < NUM_PT_IN_SEARCHSPACE; ++ii) {
            int64_t acc = 0;
            for (int jj = 0; jj < NUM_FEATURE; ++jj) {
                int idx = ii * NUM_FEATURE + jj;
                int64_t a = static_cast<int64_t>(tb_inputQuery_flat[jj]);
                int64_t b = static_cast<int64_t>(tb_searchSpace_flat[idx]);
                int64_t diff = a - b; // Q16.16
                int64_t sq = diff * diff; // Q32.32
                // shift right by FRAC to keep in Q16.16 (approx for sum of squares)
                int64_t scaled = sq >> FRAC;
                acc += scaled;
            }
            // clamp to 32-bit signed range if necessary
            if (acc > std::numeric_limits<int32_t>::max()) acc = std::numeric_limits<int32_t>::max();
            if (acc < std::numeric_limits<int32_t>::min()) acc = std::numeric_limits<int32_t>::min();
            dut_distance_flat[ii] = static_cast<int32_t>(acc);
        }

        // Write CSV row
        ofs << cycle;
        // inputQuery columns: decimal integer representation
        for (int j = 0; j < NUM_FEATURE; ++j) {
            ofs << "," << static_cast<long long>(tb_inputQuery_flat[j]);
        }
        // searchSpace columns
        for (int idx = 0; idx < NUM_PT_IN_SEARCHSPACE * NUM_FEATURE; ++idx) {
            ofs << "," << static_cast<long long>(tb_searchSpace_flat[idx]);
        }
        // distance outputs: print as uppercase hex without 0x, without leading zeros
        for (int i = 0; i < NUM_PT_IN_SEARCHSPACE; ++i) {
            uint32_t as_uint = static_cast<uint32_t>(dut_distance_flat[i]);
            string hx = to_hex32(as_uint);
            ofs << "," << hx;
        }
        ofs << "\n";
    }

    // Explicitly close file
    ofs.close();
    return 0;
}

