#include <stdint.h>
#include "ap_int.h"
#include "hls_stream.h"

#define NUM_FEATURE 128
#define NUM_PT_IN_SEARCHSPACE 1024

typedef ap_int<32> q16_16_t;

extern "C" {
void knn(
    q16_16_t inputQuery[NUM_FEATURE],
    q16_16_t searchSpace[NUM_PT_IN_SEARCHSPACE * NUM_FEATURE],
    q16_16_t distance[NUM_PT_IN_SEARCHSPACE]
) {
    #pragma HLS INTERFACE m_axi port=searchSpace offset=slave bundle=gmem
    #pragma HLS INTERFACE m_axi port=distance offset=slave bundle=gmem
    #pragma HLS INTERFACE s_axilite port=inputQuery bundle=control
    #pragma HLS INTERFACE s_axilite port=return bundle=control

    q16_16_t local_inputQuery[NUM_FEATURE];
    q16_16_t local_searchSpace[NUM_PT_IN_SEARCHSPACE * NUM_FEATURE];
    q16_16_t local_distance[NUM_PT_IN_SEARCHSPACE];

    #pragma HLS ARRAY_PARTITION variable=local_inputQuery complete dim=1
    #pragma HLS ARRAY_PARTITION variable=local_searchSpace complete dim=1
    #pragma HLS ARRAY_PARTITION variable=local_distance complete dim=1

    // Load function
    auto load = [&](bool flag) {
        if (flag) {
            for (int j = 0; j < NUM_FEATURE; ++j) {
                #pragma HLS PIPELINE
                local_inputQuery[j] = inputQuery[j];
            }
            for (int i = 0; i < NUM_PT_IN_SEARCHSPACE * NUM_FEATURE; ++i) {
                #pragma HLS PIPELINE
                local_searchSpace[i] = searchSpace[i];
            }
        }
    };

    // Compute function
    auto compute = [&]() {
        for (int i = 0; i < NUM_PT_IN_SEARCHSPACE; ++i) {
            #pragma HLS PIPELINE
            ap_int<64> sum = 0;
            for (int j = 0; j < NUM_FEATURE; ++j) {
                #pragma HLS UNROLL
                ap_int<32> feature_delta = local_searchSpace[i * NUM_FEATURE + j] - local_inputQuery[j];
                sum += feature_delta * feature_delta;
            }
            local_distance[i] = (q16_16_t)(sum >> 16); // Convert back to Q16.16 format
        }
    };

    // Store function
    auto store = [&](bool flag) {
        if (flag) {
            for (int i = 0; i < NUM_PT_IN_SEARCHSPACE; ++i) {
                #pragma HLS PIPELINE
                distance[i] = local_distance[i];
            }
        }
    };

    // Execute load, compute, and store
    load(true);
    compute();
    store(true);
}
}

