                if (((cycle + ii) % 4) == 0) v = -v;
                if ((cycle % 5) == 0) v = v + 0.333;
                v = v + cycle * 0.125;
                tb_searchSpace_flat[idx] = real_to_q16_16(v);
            }
        }

        // Call DUT (knn). In C-simulation this calls the C model; in cosim Vivado HLS replaces it with RTL cosim wrapper.
        knn(tb_inputQuery_flat, tb_searchSpace_flat, dut_distance_flat);

        // Write CSV row
        ofs << cycle;
        // inputQuery columns: decimal integer representation
        for (int j = 0; j < NUM_FEATURE; ++j) {
            ofs << "," << static_cast<long long>(tb_inputQuery_flat[j]);
        }
        // searchSpace columns
        for (int idx = 0; idx < NUM_PT_IN_SEARCHSPACE * NUM_FEATURE; ++idx) {
