#include <cstdio>
#include <cstdint>
#include <cstdlib>
#include <cstring>
#include <string>

typedef int32_t DATA_TYPE;
const int N = 3;

/* DUT: syrk as provided */
void syrk(DATA_TYPE alpha, DATA_TYPE beta, DATA_TYPE A[N][N], DATA_TYPE B[N][N], DATA_TYPE C_out[N][N]) {
	int i, j, k;

	DATA_TYPE buff_A0[N][N], buff_A1[N][N];
	DATA_TYPE buff_B[N][N];
	DATA_TYPE buff_C_out[N][N];

	for (i = 0; i < N; i++) {
		for (j = 0; j < N; j++) {
			buff_A0[i][j] = A[i][j];
			buff_A1[i][j] = A[i][j];
			buff_B[i][j] = B[i][j];
			buff_C_out[i][j] = 0;
		}
	}

	for (i = 0; i < N; i++) {
		for (j = 0; j < N; j++) {
			for (k = 0; k < N; k++) {
				buff_C_out[i][j] += alpha * buff_A0[i][k] * buff_A1[j][k];
			}
		}
	}

	for (i = 0; i < N; i++) {
		for (j = 0; j < N; j++) {
			buff_C_out[i][j] += beta * buff_B[i][j];
		}
	}

	for(i = 0; i < N; i++) {
		for(j = 0; j < N; j++) {
			if (j > i) C_out[i][j] = 0;
			else C_out[i][j] = buff_C_out[i][j];
		}
	}
}

int main() {
	const int CYCLES = 24;

	/* Predefined alpha and beta values for each cycle (deterministic) */
	DATA_TYPE alpha_list[CYCLES] = {
		1, 2, 0, -1, 3, 1, 4, 2, -2, 5, 1, 0,
		2, 3, -1, 1, 6, -3, 2, 1, 7, -2, 4, 1
	};
	DATA_TYPE beta_list[CYCLES] = {
		0, 1, 2, 1, 0, -1, 2, 3, 1, 0, -2, 4,
		1, -1, 2, 3, 0, 1, -1, 2, 3, 1, 0, -3
	};

	/* Open CSV output file */
	FILE *f = std::fopen("c_output.csv", "w");
	if (!f) return 1;

	/* CSV header: cycle, then inputs (alpha,beta,A,B), then outputs (C_out) */
	std::fprintf(f, "cycle,alpha,beta,A,B,C_out\n");
	/* roles row: meta/in/in/in/in/out */
	std::fprintf(f, "meta,in,in,in,in,out\n");

	for (int cycle = 0; cycle < CYCLES; ++cycle) {
		DATA_TYPE alpha = alpha_list[cycle];
		DATA_TYPE beta = beta_list[cycle];

		DATA_TYPE A[N][N];
		DATA_TYPE B[N][N];
		DATA_TYPE C_out[N][N];

		/* Generate deterministic, varied test patterns for A and B based on cycle */
		int p = cycle % 6;
		for (int i = 0; i < N; ++i) {
			for (int j = 0; j < N; ++j) {
				switch (p) {
					case 0:
						/* ramp increasing with row and col */
						A[i][j] = (cycle + 1) + i * 3 + j;
						B[i][j] = (cycle + 2) + j * 2 - i;
						break;
					case 1:
						/* identity scaled and symmetric patterns */
						A[i][j] = (i == j) ? (cycle + 1) : 0;
						B[i][j] = (i <= j) ? (i + j + cycle) : (i - j - cycle);
						break;
					case 2:
						/* alternating sign pattern */
						A[i][j] = ((i + j + cycle) % 2 == 0) ? (i + 1) : -(j + 1);
						B[i][j] = ((i * j + cycle) % 3) - 1;
						break;
					case 3:
						/* small negative and positive mix */
						A[i][j] = (i - j) * (cycle % 4);
						B[i][j] = ((cycle + 1) % 5) * (i + j + 1);
						break;
					case 4:
						/* all ones scaled */
						A[i][j] = (cycle % 3) + 1;
						B[i][j] = ((cycle % 4) - 1);
						break;
					default:
						/* symmetric ramp */
						A[i][j] = (i + j + 1) * ((cycle % 5) + 1);
						B[i][j] = (j == i) ? (cycle % 7) : (j - i);
						break;
				}
			}
		}

		/* Call DUT once per cycle */
		syrk(alpha, beta, A, B, C_out);

		/* Serialize A and B as decimal flattened lists (row-major) separated by ';' */
		std::string A_field;
		std::string B_field;
		char buf[64];
		for (int i = 0; i < N; ++i) {
			for (int j = 0; j < N; ++j) {
				if (!(i == 0 && j == 0)) {
					A_field.push_back(';');
					B_field.push_back(';');
				}
				std::snprintf(buf, sizeof(buf), "%d", (int)A[i][j]);
				A_field += buf;
				std::snprintf(buf, sizeof(buf), "%d", (int)B[i][j]);
				B_field += buf;
			}
		}

		/* Serialize C_out as HEX uppercase flattened list (row-major) separated by ';' */
		std::string C_field;
		for (int i = 0; i < N; ++i) {
			for (int j = 0; j < N; ++j) {
				if (!(i == 0 && j == 0)) C_field.push_back(';');
				/* Cast to uint32_t for hex representation (show two's complement for negatives) */
				std::snprintf(buf, sizeof(buf), "%X", (uint32_t)C_out[i][j]);
				C_field += buf;
			}
		}

		/* Write CSV row: cycle,alpha,beta,A,B,C_out */
		std::fprintf(f, "%d,%d,%d,%s,%s,%s\n",
		             cycle,
		             (int)alpha,
		             (int)beta,
		             A_field.c_str(),
		             B_field.c_str(),
		             C_field.c_str());
	}

	/* Explicitly close file */
	std::fclose(f);
	return 0;
}

