// hls.cpp
// Top-level HLS kernel for SYRK-like operation.
// Adjusted to match the testbench types and dimensions (C++98 compatible).
#include <stdint.h>

extern "C" {

#define N 3
typedef int32_t DATA_TYPE;

void syrk(DATA_TYPE alpha, DATA_TYPE beta, DATA_TYPE A[N][N], DATA_TYPE B[N][N], DATA_TYPE C_out[N][N]) {
#pragma HLS INTERFACE m_axi port=A offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=B offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=C_out offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=alpha bundle=control
#pragma HLS INTERFACE s_axilite port=beta bundle=control
#pragma HLS INTERFACE s_axilite port=A bundle=control
#pragma HLS INTERFACE s_axilite port=B bundle=control
#pragma HLS INTERFACE s_axilite port=C_out bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int i, j, k;

    /* Local buffers */
    DATA_TYPE buff_A0[N][N];
#pragma HLS array_partition variable=buff_A0 cyclic factor=3 dim=2
    DATA_TYPE buff_A1[N][N];
    DATA_TYPE buff_B[N][N];
    DATA_TYPE buff_C_out[N][N];

    /* Load inputs into local buffers and initialize outputs */
    for (i = 0; i < N; i++) {
        for (j = 0; j < N; j++) {
#pragma HLS PIPELINE II=1
            buff_A0[i][j] = A[i][j];
            buff_A1[i][j] = A[i][j];
            buff_B[i][j] = B[i][j];
            buff_C_out[i][j] = 0;
        }
    }

    /* Compute symmetric rank-k like product: C = alpha * A * A^T (with A duplicated in buff_A1)
       Using indices consistent with the testbench expectations. */
    for (i = 0; i < N; i++) {
        for (j = 0; j < N; j++) {
            for (k = 0; k < N; k++) {
#pragma HLS PIPELINE II=1
                buff_C_out[i][j] += alpha * buff_A0[i][k] * buff_A1[j][k];
            }
        }
    }

    /* Add beta * B to the result */
    for (i = 0; i < N; i++) {
        for (j = 0; j < N; j++) {
#pragma HLS PIPELINE II=1
            buff_C_out[i][j] += beta * buff_B[i][j];
        }
    }

    /* Write back only the lower-triangular part; set upper-triangular to zero */
    for (i = 0; i < N; i++) {
        for (j = 0; j < N; j++) {
#pragma HLS PIPELINE II=1
            if (j > i) {
                C_out[i][j] = 0;
            } else {
                C_out[i][j] = buff_C_out[i][j];
            }
        }
    }
}

} // extern "C"

