		// Initialize entire padded image to 0
		for (int i = 0; i < IMG_SIZE; ++i) img_arr[i] = 0.0f;

		// Fill interior GRID_ROWS x GRID_COLS region deterministically based on img (test id)
		// starting_idx matches the implementation
		const int starting_idx = MAX_RADIUS * GRID_COLS;
		for (int p = 0; p < GRID_ROWS; ++p) {
