void jacobi_1d_int(int tsteps, int n, int64_t A[120], int64_t B[120]) {
    const int64_t SC_NUM = 33333;
    const int64_t SC_DEN = 100000;
    for (int t = 0; t < tsteps; ++t) {
        // compute B from A
        for (int i = 1; i < n - 1; ++i) {
            int64_t sum = A[i - 1] + A[i] + A[i + 1];
            int64_t prod = (sum * SC_NUM) / SC_DEN;
            B[i] = prod;
        }
        // compute A from B
        for (int i = 1; i < n - 1; ++i) {
            int64_t sum = B[i - 1] + B[i] + B[i + 1];
