// hls.cpp
// HLS implementation of jacobi_1d using 64-bit integer arithmetic to match the C testbench.
// Uses the same scaling constants and integer arithmetic as the reference C model.
// Note: Use C header <stdint.h> for compatibility with Vivado HLS C++98 mode.

#include <stdint.h>

extern "C" {

#define N 120

void jacobi_1d(int tsteps, int n, int64_t A[N], int64_t B[N]) {
#pragma HLS INTERFACE m_axi port=A offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=B offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=tsteps bundle=control
#pragma HLS INTERFACE s_axilite port=n bundle=control
#pragma HLS INTERFACE s_axilite port=A bundle=control
#pragma HLS INTERFACE s_axilite port=B bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Use the same integer scaling constants as the C reference model
    const int64_t SC_NUM = 33333;
    const int64_t SC_DEN = 100000;

    int64_t A_buf[N];
    int64_t B_buf[N];

    // Copy inputs from external memory to local buffers
    CopyIn: for (int i = 0; i < N; i++) {
#pragma HLS PIPELINE II=1
        A_buf[i] = A[i];
        B_buf[i] = B[i];
    }

    // Time stepping using integer arithmetic to match reference behavior exactly
    TimeLoop: for (int t = 0; t < tsteps; t++) {
        ComputeB: for (int i = 1; i < n - 1; i++) {
#pragma HLS PIPELINE II=1
            int64_t sum = A_buf[i - 1] + A_buf[i] + A_buf[i + 1];
            int64_t prod = (sum * SC_NUM) / SC_DEN;
            B_buf[i] = prod;
        }

        ComputeA: for (int i = 1; i < n - 1; i++) {
#pragma HLS PIPELINE II=1
            int64_t sum = B_buf[i - 1] + B_buf[i] + B_buf[i + 1];
            int64_t prod = (sum * SC_NUM) / SC_DEN;
            A_buf[i] = prod;
        }
    }

    // Write results back to external memory
    CopyOut: for (int i = 0; i < N; i++) {
#pragma HLS PIPELINE II=1
        A[i] = A_buf[i];
        B[i] = B_buf[i];
    }
}

} // extern "C"

