// Convert a 64-bit unsigned value to uppercase hex string with no "0x" prefix.
// Produces a null-terminated string in out. out must have enough space.
// This manual routine avoids reliance on "%llX" printf support in older toolchains.
static void u64_to_hex_upper(uint64_t v, char *out) {
    if (v == 0) {
        out[0] = '0';
        out[1] = '\0';
        return;
    }
    char buf[32];
    int pos = 0;
    // collect digits in reverse
    while (v != 0) {
        uint32_t d = (uint32_t)(v & 0xF);
        buf[pos++] = (d < 10) ? ('0' + d) : ('A' + (d - 10));
        v >>= 4;
    }
    // reverse into out
    int i;
    for (i = 0; i < pos; ++i) {
        out[i] = buf[pos - 1 - i];
    }
    out[pos] = '\0';
}

