    fm_t out[PAR_IN_FM_DEPTH]
) {
    const size_t spatial_size = PAR_IN_FM_HEIGHT * PAR_IN_FM_WIDTH;
    for (size_t d = 0; d < PAR_IN_FM_DEPTH; ++d) {
        fm_t sum = 0.0f;
