// hls.cpp
// Vivado HLS C++98 compatible implementation of a simple average pooling.
// - Use C headers (<stdint.h>) and plain C++98 features.
// - Tile sizes are equal to input sizes so top-level prototype matches exactly.
// - Integer average pooling (sum / (H*W)) with 64-bit accumulator (long long) to avoid overflow.
// - Keep HLS pragmas for interfaces and simple array partitioning.
// - Top-level is extern "C" to match the testbench linkage.

#include <stdint.h>

typedef int32_t fm_t;

#define PAR_IN_FM_DEPTH 3
#define PAR_IN_FM_HEIGHT 2
#define PAR_IN_FM_WIDTH 2

// Tile sizes set equal to the full dimensions so there is a single tile.
#define PAR_TILE_DEPTH PAR_IN_FM_DEPTH
#define PAR_TILE_HEIGHT PAR_IN_FM_HEIGHT
#define PAR_TILE_WIDTH PAR_IN_FM_WIDTH

// index_calc left for completeness (not used by top-level)
int index_calc(int idx_d, int idx_h, int idx_w, int IN_FM_HEIGHT, int IN_FM_WIDTH)
{
    return idx_d * IN_FM_HEIGHT * IN_FM_WIDTH + idx_h * IN_FM_WIDTH + idx_w;
}

// avg_pool_core: compute integer average across HxW for each channel.
// Template parameters are fixed small constants so HLS can unroll/pipeline.
template<int D, int H, int W>
void avg_pool_core(
    fm_t in[D][H][W],
    fm_t out[D]
)
{
OUT_FEAT:
    for (int c = 0; c < D; c++) {
#pragma HLS unroll
        // Use a wider accumulator to avoid overflow
        long long sum = 0;
    IN_ROW:
        for (int i = 0; i < H; i++) {
#pragma HLS pipeline II=1
        IN_COL:
            for (int j = 0; j < W; j++) {
#pragma HLS unroll
                sum += (long long)in[c][i][j];
            }
        }
        out[c] = (fm_t)(sum / (H * W));
    }
}

extern "C" {
void avg_pool(
    fm_t in[PAR_IN_FM_DEPTH][PAR_IN_FM_HEIGHT][PAR_IN_FM_WIDTH],
    fm_t out[PAR_IN_FM_DEPTH]
)
{
#pragma HLS INTERFACE m_axi port=in offset=slave bundle=fm_in depth=PAR_IN_FM_DEPTH*PAR_IN_FM_HEIGHT*PAR_IN_FM_WIDTH
#pragma HLS INTERFACE m_axi port=out offset=slave bundle=fm_out depth=PAR_IN_FM_DEPTH
#pragma HLS INTERFACE s_axilite port=in bundle=control
#pragma HLS INTERFACE s_axilite port=out bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local tile buffers
    fm_t in_tile[PAR_TILE_DEPTH][PAR_TILE_HEIGHT][PAR_TILE_WIDTH];
#pragma HLS array_partition variable=in_tile cyclic factor=3 dim=1
    fm_t out_tile[PAR_TILE_DEPTH];
#pragma HLS array_partition variable=out_tile cyclic factor=3 dim=1

    const int N_TILES = PAR_IN_FM_DEPTH / PAR_TILE_DEPTH; // equals 1 with current defs

TILE:
    for (int t = 0; t < N_TILES; t++) {
#pragma HLS unroll
    INP_DEPTH:
        for (int c = 0; c < PAR_TILE_DEPTH; c++) {
#pragma HLS unroll
        INP_ROW:
            for (int i = 0; i < PAR_TILE_HEIGHT; i++) {
#pragma HLS unroll
            INP_COL:
                for (int j = 0; j < PAR_TILE_WIDTH; j++) {
#pragma HLS pipeline II=1
                    in_tile[c][i][j] = in[t * PAR_TILE_DEPTH + c][i][j];
                }
            }
        }

        avg_pool_core<PAR_TILE_DEPTH, PAR_TILE_HEIGHT, PAR_TILE_WIDTH>(in_tile, out_tile);

    STORE_TILE:
        for (int c = 0; c < PAR_TILE_DEPTH; c++) {
#pragma HLS unroll
            out[t * PAR_TILE_DEPTH + c] = out_tile[c];
        }
    }
}
} // extern "C"

