// hls.cpp
// HLS top-level for block matrix multiply compatible with the provided test bench.
// Uses C-compatible headers and C++98-compatible constructs and matches the external "C"
// signature expected by the testbench (arrays of blockvec / blockmat).

#include <stdint.h>

typedef int32_t DTYPE;

/* Match testbench sizes (TESTBENCH must remain unchanged) */
const int SIZE = 8;
const int BLOCK_SIZE = 2;

typedef struct {
    DTYPE a[BLOCK_SIZE];
} blockvec;

typedef struct {
    DTYPE out[BLOCK_SIZE][BLOCK_SIZE];
} blockmat;

extern "C" {
void block_mm(
    const blockvec *Arows,    // pointer to input Arows data (SIZE elements of blockvec)
    const blockvec *Bcols,    // pointer to input Bcols data (SIZE elements of blockvec)
    blockmat *ABpartial_out,  // pointer to output blockmat
    int iteration
) {
#pragma HLS INTERFACE m_axi port=Arows offset=slave bundle=gmem0 depth=SIZE
#pragma HLS INTERFACE m_axi port=Bcols offset=slave bundle=gmem1 depth=SIZE
#pragma HLS INTERFACE m_axi port=ABpartial_out offset=slave bundle=gmem2 depth=1
#pragma HLS INTERFACE s_axilite port=Arows bundle=control
#pragma HLS INTERFACE s_axilite port=Bcols bundle=control
#pragma HLS INTERFACE s_axilite port=ABpartial_out bundle=control
#pragma HLS INTERFACE s_axilite port=iteration bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    /* Determine when to reload A (same scheme as original design) */
    int counter = iteration % (SIZE / BLOCK_SIZE);

    /* Local buffered A: indexed [block_row][global_col] */
    static DTYPE A[BLOCK_SIZE][SIZE];
#pragma HLS ARRAY_PARTITION variable=A cyclic factor=2 dim=1

    /* Load A from memory into local buffer when counter==0 */
    if (counter == 0) {
    loadA: for (int i = 0; i < SIZE; i++) {
#pragma HLS PIPELINE
            for (int j = 0; j < BLOCK_SIZE; j++) {
#pragma HLS UNROLL factor=2
                /* Access testbench-provided structure layout */
                A[j][i] = Arows[i].a[j];
            }
        }
    }

    /* Partial block result */
    DTYPE AB[BLOCK_SIZE][BLOCK_SIZE];
    /* Initialize AB to zero explicitly to be safe in all tool versions */
    for (int ii = 0; ii < BLOCK_SIZE; ++ii) {
#pragma HLS UNROLL
        for (int jj = 0; jj < BLOCK_SIZE; ++jj) {
#pragma HLS UNROLL
            AB[ii][jj] = 0;
        }
    }
#pragma HLS ARRAY_PARTITION variable=AB block factor=2 dim=1

    /* Compute partial sums across the shared dimension SIZE */
partialsum: for (int k = 0; k < SIZE; k++) {
#pragma HLS PIPELINE II=1
        for (int i = 0; i < BLOCK_SIZE; i++) {
#pragma HLS UNROLL factor=2
            for (int j = 0; j < BLOCK_SIZE; j++) {
#pragma HLS UNROLL factor=2
                AB[i][j] += A[i][k] * Bcols[k].a[j];
            }
        }
    }

    /* Write back the BLOCK_SIZE x BLOCK_SIZE partial result */
writeoutput: for (int i = 0; i < BLOCK_SIZE; i++) {
#pragma HLS PIPELINE II=1
        for (int j = 0; j < BLOCK_SIZE; j++) {
#pragma HLS UNROLL factor=2
            ABpartial_out->out[i][j] = AB[i][j];
        }
    }
}
} // extern "C"

