        for (int j = 0; j < BLOCK_SIZE; ++j) {
            csv << "," << "Bcols[" << k << "].a[" << j << "]";
        }
    }
    // Outputs ABpartial->out
    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            csv << "," << "ABpartial->out[" << i << "][" << j << "]";
        }
    }
    csv << "\n";

    // Role row: meta/in/out
    csv << "meta,";
    csv << "in";
    for (int i = 0; i < SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            csv << ",in";
        }
    }
    for (int k = 0; k < SIZE; ++k) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            csv << ",in";
        }
    }
    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            csv << ",out";
        }
    }
    csv << "\n";

    // Number of cycles
    const int CYCLES = 32;

    // Generate deterministic test vectors and call the DUT
    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        int it = cycle;

        blockvec Arows[SIZE];
        blockvec Bcols[SIZE];
        blockmat ABpartial;

        int group = cycle / (SIZE / BLOCK_SIZE); // SIZE/BLOCK_SIZE == 4

        // Fill Arows: change more slowly (group-based)
        for (int i = 0; i < SIZE; ++i) {
            int baseA = 1 + group * 3 + i;
            for (int j = 0; j < BLOCK_SIZE; ++j) {
                Arows[i].a[j] = baseA + j;
            }
        }

        // Fill Bcols: vary every cycle
        for (int k = 0; k < SIZE; ++k) {
            int baseB = 1 + cycle * 2 + k;
            for (int j = 0; j < BLOCK_SIZE; ++j) {
                Bcols[k].a[j] = baseB + j;
            }
        }

        // Call DUT
        block_mm(Arows, Bcols, &ABpartial, it);

        // Write CSV line
        csv << cycle << ",";
        csv << it;

        // Arows inputs
        for (int i = 0; i < SIZE; ++i) {
            for (int j = 0; j < BLOCK_SIZE; ++j) {
                csv << "," << Arows[i].a[j];
            }
        }

        // Bcols inputs
        for (int k = 0; k < SIZE; ++k) {
            for (int j = 0; j < BLOCK_SIZE; ++j) {
                csv << "," << Bcols[k].a[j];
            }
        }

        // ABpartial outputs in HEX uppercase, no 0x prefix
        for (int i = 0; i < BLOCK_SIZE; ++i) {
            for (int j = 0; j < BLOCK_SIZE; ++j) {
                DTYPE val = ABpartial.out[i][j];
                std::ostringstream oss;
                // Cast to uint32_t so negative values print as expected hex bit patterns
                oss << std::uppercase << std::hex << static_cast<uint32_t>(val);
                csv << "," << oss.str();
            }
        }

        csv << "\n";
    }

    csv.close();
    return 0;
}

