// test.c
// Main DUT module (standalone). Produces c_output.csv as specified.
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <stdint.h>

#define L1_SIZE 65537
#define L2_SIZE 17

/* portable compile-time assert usable in both C and C++ */
#if defined(__cplusplus)
  #define C_ASSERT(expr, msg) static_assert(expr, msg)
#else
  #define C_ASSERT(expr, msg) _Static_assert(expr, msg)
#endif

void workload(float l1[L1_SIZE], float l2[L2_SIZE], float conn[L1_SIZE * L2_SIZE]) {
    float *l1_buf = (float*)malloc((size_t)sizeof(float) * (size_t)L1_SIZE);
    if (!l1_buf) return;

    memcpy(l1_buf, l1, (size_t)sizeof(float) * (size_t)L1_SIZE);

    /* keep behavior consistent with original implementation */
    l1_buf[0] = 1.0f;

    float l2_buf[L2_SIZE];
    l2_buf[0] = 0.0f;

    for (int j = 1; j < L2_SIZE; j++) {
        float sum = 0.0f;
        for (int i = 0; i < L1_SIZE; i++) {
            sum += conn[i * L2_SIZE + j] * l1_buf[i];
        }
        l2_buf[j] = 1.0f / (1.0f + expf(-sum));
    }

    memcpy(l2, l2_buf, (size_t)sizeof(float) * (size_t)L2_SIZE);
    free(l1_buf);
}

int main(void) {
    const int CYCLES = 24; // between 20 and 50

    float *l1 = (float*)malloc((size_t)sizeof(float) * (size_t)L1_SIZE);
    float *l2 = (float*)malloc((size_t)sizeof(float) * (size_t)L2_SIZE);
    size_t tot = (size_t)L1_SIZE * (size_t)L2_SIZE;
    float *conn = (float*)malloc((size_t)sizeof(float) * tot);

    if (!l1 || !l2 || !conn) {
        if (l1) free(l1);
        if (l2) free(l2);
        if (conn) free(conn);
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    FILE *f = fopen("c_output.csv", "w");
    if (!f) {
        free(l1);
        free(l2);
        free(conn);
        fprintf(stderr, "Failed to open c_output.csv for writing\n");
        return 1;
    }

    /* CSV header: cycle,rst,en,case_id,l2[0]..l2[16] */
    fprintf(f, "cycle,rst,en,case_id");
    for (int j = 0; j < L2_SIZE; ++j) {
        fprintf(f, ",l2[%d]", j);
    }
    fprintf(f, "\n");

    /* Roles row */
    fprintf(f, "meta,in,in,in");
    for (int j = 0; j < L2_SIZE; ++j) {
        fprintf(f, ",out");
    }
    fprintf(f, "\n");

    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        int rst = (cycle < 2) ? 1 : 0;
        int en  = (cycle < 2) ? 0 : 1;
        int case_id = cycle % 6;

        if (rst) {
            for (size_t i = 0; i < (size_t)L1_SIZE; ++i) l1[i] = 0.0f;
            for (size_t k = 0; k < tot; ++k) conn[k] = 0.0f;
        } else {
            for (size_t i = 0; i < (size_t)L1_SIZE; ++i) {
                int v = (int)((i + case_id) % 5);
                l1[i] = (float)(v) * 0.125f;
            }
            for (size_t i = 0; i < (size_t)L1_SIZE; ++i) {
                for (int j = 0; j < L2_SIZE; ++j) {
                    int t = (int)((i + (size_t)j + case_id) % 11);
                    int signed_val = t - 5;
                    conn[i * L2_SIZE + j] = (float)signed_val * 0.01f;
                }
            }
        }

        workload(l1, l2, conn);

        /* Write CSV row: inputs decimal ints, outputs hex uppercase without 0x */
        fprintf(f, "%d,%d,%d,%d", cycle, rst, en, case_id);

        /* ensure float and uint32_t are same size at compile time */
        C_ASSERT(sizeof(float) == sizeof(uint32_t), "float must be 32-bit IEEE");

        for (int j = 0; j < L2_SIZE; ++j) {
            uint32_t bits;
            memcpy(&bits, &l2[j], sizeof(bits));
            if (bits == 0) {
                fprintf(f, ",0");
            } else {
                fprintf(f, ",%X", (unsigned)bits);
            }
        }
        fprintf(f, "\n");
    }

    /* Explicitly close file and free memory */
    fclose(f);
    free(l1);
    free(l2);
    free(conn);

    return 0;
}

