// hls.cpp
// HLS top function "workload" with C linkage to match the testbench.
// The implementation treats conn as a 2D array with 17 columns per row:
//   row 0 contains bias weights for the 16 outputs in columns 1..16,
//   rows 1..65536 contain weights for l1[1..65536] in columns 1..16.
// The function computes for outputs 1..16:
//   sum_j = bias_j + sum_{i=1..65536} conn[i*17 + (j+1)] * l1[i]
// then applies sigmoid and writes into l2[1..16]. l2[0] is set to 0.0f.
//
// Comments and code are compatible with Vivado HLS 2018.3 (C++98 environment).

#include <math.h>
#include <hls_math.h> // use hls::expf for better HLS support

#define N_ROWS 65537     // rows in conn (0..65536)
#define N_COLS 17        // columns in conn (0..16)
#define N_OUTS 16        // number of outputs (1..16 in l2)
#define LAST_ROW 65536   // last data row for l1/conn

extern "C" {

void workload(float l1[N_ROWS], float l2[N_COLS], float conn[N_ROWS * N_COLS]) {
#pragma HLS INTERFACE m_axi port=l1  offset=slave bundle=l11
#pragma HLS INTERFACE m_axi port=l2  offset=slave bundle=l21
#pragma HLS INTERFACE m_axi port=conn offset=slave bundle=conn1

#pragma HLS INTERFACE s_axilite port=l1  bundle=control
#pragma HLS INTERFACE s_axilite port=l2  bundle=control
#pragma HLS INTERFACE s_axilite port=conn bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local accumulator for 16 outputs
    float sum[N_OUTS];
#pragma HLS array_partition variable=sum cyclic factor=2 dim=1

    // Initialize sums with bias weights stored in row 0 columns 1..16
    for (int j = 0; j < N_OUTS; ++j) {
#pragma HLS pipeline II=1
        sum[j] = conn[0 * N_COLS + (j + 1)];
    }

    // Accumulate contributions from l1[1..65536].
    // For each row i = 1..65536, multiply the scalar l1[i] with
    // the 16 weights conn[i*17 + 1 .. i*17 + 16].
    for (int i = 1; i <= LAST_ROW; ++i) {
#pragma HLS pipeline II=1
        float in = l1[i];
        // Unroll the small inner loop of 16 iterations for good performance/synthesis
        for (int j = 0; j < N_OUTS; ++j) {
#pragma HLS unroll
            float w = conn[i * N_COLS + (j + 1)];
            sum[j] += w * in;
        }
    }

    // Apply sigmoid activation and write outputs to l2[1..16].
    // Leave l2[0] = 0.0f (as original testbench expects l2[0] present).
    l2[0] = 0.0f;
    for (int j = 0; j < N_OUTS; ++j) {
#pragma HLS pipeline II=1
        // use hls::expf for HLS-friendly single-precision exponential
        float act = 1.0f / (1.0f + hls::expf(-sum[j]));
        l2[j + 1] = act;
    }
}

} // extern "C"

