    }
    fprintf(f, "\n");

    /* Deterministic test patterns. Reset for first 2 cycles, en=0; afterwards en=1. */
    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        int rst = (cycle < 2) ? 1 : 0;
        int en  = (cycle < 2) ? 0 : 1;
        int case_id = cycle % 6; // small integer input to vary patterns

        /* Prepare inputs depending on reset and case_id */
        if (rst) {
            /* during reset, zero inputs */
            for (size_t i = 0; i < 65537; ++i) l1[i] = 0.0f;
            size_t tot = (size_t)65537 * 17;
            for (size_t k = 0; k < tot; ++k) conn[k] = 0.0f;
        } else {
            /* generate a deterministic pattern based on case_id */
            /* l1 values cycle through small multiples */
            for (size_t i = 0; i < 65537; ++i) {
                int v = (int)((i + case_id) % 5); // 0..4
                l1[i] = (float)(v) * 0.125f; // 0.0,0.125,0.25,...
            }
            /* conn pattern: small signed values to exercise positive/negative sums */
            for (size_t i = 0; i < 65537; ++i) {
                for (int j = 0; j < 17; ++j) {
                    int t = (int)((i + j + case_id) % 11); // 0..10
                    /* map to -5..5 then scale */
                    int signed_val = t - 5;
                    conn[i * 17 + j] = (float)signed_val * 0.01f;
                }
            }
        }

        /* Call DUT once per cycle (in cosim this will call into RTL) */
        workload(l1, l2, conn);

        /* Write one CSV row: inputs are decimal integers; outputs are hex uppercase (no 0x) */
        fprintf(f, "%d,%d,%d,%d", cycle, rst, en, case_id);
        for (int j = 0; j < 17; ++j) {
            /* convert float bits to uint32_t and print uppercase hex without 0x */
            uint32_t bits;
            memcpy(&bits, &l2[j], sizeof(bits));
            if (bits == 0) {
                /* print 0 for exact zero to keep output compact */
                fprintf(f, ",0");
            } else {
                /* Cast to unsigned for %X */
                fprintf(f, ",%X", (unsigned)bits);
            }
        }
        fprintf(f, "\n");
    }

    /* Explicitly close file and free memory */
    fclose(f);
    free(l1);
    free(l2);
    free(conn);

    return 0;
}

