                float gamma = DRAM_batch_norm_weights[0][out_ch];
                float beta = DRAM_batch_norm_weights[1][out_ch];
                float mean = DRAM_batch_norm_weights[2][out_ch];
                float var = DRAM_batch_norm_weights[3][out_ch];
                float normalized = gamma * (sum - mean) / sqrtf(var + epsilon) + beta;

                DRAM_image_output[out_ch][h][w] = normalized > 0.0f ? normalized : 0.0f;
            }
        }
    }
}

int main() {
    const int CYCLES = 24; // number of test cycles (rows)
    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // CSV header: cycle, then input names (if any), then outputs
    // We drive arrays in testbench, so list their names as driven inputs.
    std::fprintf(f, "cycle,DRAM_image_input,DRAM_conv_weight,DRAM_conv_bias,DRAM_batch_norm_weights,DRAM_image_output\n");
    // Role row: meta for cycle, in for driven inputs, out for DUT outputs
    std::fprintf(f, "meta,in,in,in,in,out\n");

    // Buffers
    float DRAM_image_input[CIN][HIN][WIN];
    float DRAM_conv_weight[COUT][CIN][K][K];
    float DRAM_conv_bias[COUT];
    float DRAM_batch_norm_weights[4][COUT];
    float DRAM_image_output[COUT][HIN][WIN];

    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        // Deterministic, diverse test patterns based on cycle index
        // Populate DRAM_image_input with small varied floats (can be negative)
        for (int ic = 0; ic < CIN; ++ic) {
            for (int h = 0; h < HIN; ++h) {
                for (int w = 0; w < WIN; ++w) {
                    // pattern uses cycle, channel, position
                    int base = (cycle + 1) * (ic + 1) * (h + 1) * (w + 1);
                    // alternate sign every other cycle
                    float sign = ((cycle / (1 + ic)) % 2 == 0) ? 1.0f : -1.0f;
                    DRAM_image_input[ic][h][w] = sign * (base % 7) * 0.5f + (float)(base % 3) * 0.1f;
                }
            }
        }

        // Populate conv weights small integers in float
        for (int oc = 0; oc < COUT; ++oc) {
            for (int ic = 0; ic < CIN; ++ic) {
                for (int kh = 0; kh < K; ++kh) {
                    for (int kw = 0; kw < K; ++kw) {
                        int v = ((oc + 1) * (ic + 1) * (kh + 1) * (kw + 1) + cycle) % 5; // 0..4
                        v -= 2; // -2..2
                        DRAM_conv_weight[oc][ic][kh][kw] = (float)v;
                    }
                }
            }
        }

        // Bias per out channel, vary with cycle and channel
        for (int oc = 0; oc < COUT; ++oc) {
            DRAM_conv_bias[oc] = (float)(((cycle + oc) % 5) - 2) * 0.25f;
        }

        // Batch norm weights: gamma, beta, mean, var
        for (int oc = 0; oc < COUT; ++oc) {
            DRAM_batch_norm_weights[0][oc] = 1.0f + 0.05f * (float)((cycle + oc) % 5); // gamma
            DRAM_batch_norm_weights[1][oc] = 0.1f * (float)((cycle + oc) % 4);          // beta
            DRAM_batch_norm_weights[2][oc] = 0.5f * (float)(oc) + 0.1f * (float)(cycle % 3); // mean
            DRAM_batch_norm_weights[3][oc] = 1.0f + 0.2f * (float)((oc + cycle) % 3);    // var (positive)
        }

        // Call DUT
        top(DRAM_image_input, DRAM_conv_weight, DRAM_conv_bias, DRAM_batch_norm_weights, DRAM_image_output);

        // Write CSV row:
        // cycle (decimal), inputs (we output the test-vector id as integer for each driven array), output tensor as hex words concatenated by ';'
        // Inputs are represented as decimal integers (cycle id) per spec for input columns.
        std::fprintf(f, "%d,%d,%d,%d,%d,", cycle, cycle, cycle, cycle, cycle);

        // Output: serialize each float element into its uint32 bit pattern and print in uppercase hex without 0x, separated by ';'
        bool first = true;
        for (int oc = 0; oc < COUT; ++oc) {
            for (int h = 0; h < HIN; ++h) {
                for (int w = 0; w < WIN; ++w) {
                    uint32_t bits;
                    // memcpy to avoid strict-aliasing
                    std::memcpy(&bits, &DRAM_image_output[oc][h][w], sizeof(bits));
                    if (!first) std::fprintf(f, ";");
                    first = false;
                    // Print as uppercase hex without 0x and without fixed width
                    std::fprintf(f, "%X", bits);
                }
            }
        }
        std::fprintf(f, "\n");
    }

    std::fclose(f);
    return 0;
}

