// hls.cpp
// HLS implementation of a small conv->batchnorm->relu pipeline.
// Adjusted to match the testbench shapes and use float as the data type.
// Comments in English.

#include <hls_math.h>

// Use float to match the testbench
typedef float data_t;

// Small example dimensions (must match the testbench)
const int CIN = 2;
const int HIN = 3;
const int WIN = 3;
const int COUT = 2;
const int K = 3;

// Simple memory copy helpers for the small fixed shapes
void load_image(data_t input[CIN][HIN][WIN], data_t output[CIN][HIN][WIN]) {
#pragma HLS INLINE
    for (int c = 0; c < CIN; c++) {
        for (int i = 0; i < HIN; i++) {
            for (int j = 0; j < WIN; j++) {
                output[c][i][j] = input[c][i][j];
            }
        }
    }
}

void load_kernel(data_t input[COUT][CIN][K][K], data_t output[COUT][CIN][K][K]) {
#pragma HLS INLINE
    for (int oc = 0; oc < COUT; oc++) {
        for (int ic = 0; ic < CIN; ic++) {
            for (int kh = 0; kh < K; kh++) {
                for (int kw = 0; kw < K; kw++) {
                    output[oc][ic][kh][kw] = input[oc][ic][kh][kw];
                }
            }
        }
    }
}

void load_bias(data_t input[COUT], data_t output[COUT]) {
#pragma HLS INLINE
    for (int oc = 0; oc < COUT; oc++) {
        output[oc] = input[oc];
    }
}

void load_bn_weights(data_t input[4][COUT], data_t output[4][COUT]) {
#pragma HLS INLINE
    for (int r = 0; r < 4; r++) {
        for (int c = 0; c < COUT; c++) {
            output[r][c] = input[r][c];
        }
    }
}

void store_image(data_t input[COUT][HIN][WIN], data_t output[COUT][HIN][WIN]) {
#pragma HLS INLINE
    for (int c = 0; c < COUT; c++) {
        for (int i = 0; i < HIN; i++) {
            for (int j = 0; j < WIN; j++) {
                output[c][i][j] = input[c][i][j];
            }
        }
    }
}

// 2D convolution with bias addition
void conv2d_bias(
    data_t input[CIN][HIN][WIN],
    data_t kernel[COUT][CIN][K][K],
    data_t bias[COUT],
    data_t output[COUT][HIN][WIN]
) {
    // Partition/parallelism pragmas tuned for the small sizes
#pragma HLS array_partition variable=kernel type=cyclic factor=2 dim=1
#pragma HLS array_partition variable=bias type=cyclic factor=2 dim=1
#pragma HLS array_partition variable=output type=cyclic factor=2 dim=1

    // Initialize output with bias
    for (int i = 0; i < HIN; i++) {
        for (int j = 0; j < WIN; j++) {
            for (int co = 0; co < COUT; co++) {
#pragma HLS unroll factor=2
                output[co][i][j] = bias[co];
            }
        }
    }

    // Convolution (stride=1, padding=1)
    for (int i = 0; i < HIN; i++) {
        for (int j = 0; j < WIN; j++) {
            for (int kh = 0; kh < K; kh++) {
                for (int kw = 0; kw < K; kw++) {
                    int in_row = i * 1 - 1 + kh;
                    int in_col = j * 1 - 1 + kw;
                    if (in_row >= 0 && in_row < HIN && in_col >= 0 && in_col < WIN) {
                        for (int ci = 0; ci < CIN; ci++) {
#pragma HLS unroll factor=1
                            for (int co = 0; co < COUT; co++) {
#pragma HLS unroll factor=2
                                output[co][i][j] += input[ci][in_row][in_col] * kernel[co][ci][kh][kw];
                            }
                        }
                    }
                }
            }
        }
    }
}

// Batch normalization: weights layout [gamma,beta,mean,var] x COUT
void batch_norm(
    data_t input[COUT][HIN][WIN],
    data_t weights[4][COUT],
    data_t output[COUT][HIN][WIN]
) {
    for (int c = 0; c < COUT; c++) {
        for (int h = 0; h < HIN; h++) {
            for (int w = 0; w < WIN; w++) {
                // norm = (x - mean) / sqrt(var + eps)
                data_t norm = (input[c][h][w] - weights[2][c]) / hls::sqrt(weights[3][c] + (data_t)1e-05);
                output[c][h][w] = weights[0][c] * norm + weights[1][c];
            }
        }
    }
}

// ReLU activation
void relu(
    data_t input[COUT][HIN][WIN],
    data_t output[COUT][HIN][WIN]
) {
    for (int c = 0; c < COUT; c++) {
        for (int i = 0; i < HIN; i++) {
            for (int j = 0; j < WIN; j++) {
                output[c][i][j] = (input[c][i][j] > 0) ? input[c][i][j] : (data_t)0;
            }
        }
    }
}

// Top-level function with AXI interfaces and s_axilite control ports.
// The port shapes are chosen to match the testbench (float arrays with the small dims).
extern "C" void top(
    float DRAM_image_input[CIN][HIN][WIN],
    float DRAM_conv_weight[COUT][CIN][K][K],
    float DRAM_conv_bias[COUT],
    float DRAM_batch_norm_weights[4][COUT],
    float DRAM_image_output[COUT][HIN][WIN]
) {
#pragma HLS interface m_axi port=DRAM_image_input offset=slave bundle=mem1
#pragma HLS interface m_axi port=DRAM_conv_weight offset=slave bundle=mem1
#pragma HLS interface m_axi port=DRAM_conv_bias offset=slave bundle=mem1
#pragma HLS interface m_axi port=DRAM_batch_norm_weights offset=slave bundle=mem1
#pragma HLS interface m_axi port=DRAM_image_output offset=slave bundle=mem2
#pragma HLS interface s_axilite port=DRAM_image_input bundle=control
#pragma HLS interface s_axilite port=DRAM_conv_weight bundle=control
#pragma HLS interface s_axilite port=DRAM_conv_bias bundle=control
#pragma HLS interface s_axilite port=DRAM_batch_norm_weights bundle=control
#pragma HLS interface s_axilite port=DRAM_image_output bundle=control
#pragma HLS interface s_axilite port=return bundle=control

    // Local BRAM buffers
    data_t BRAM_image_input[CIN][HIN][WIN];
    data_t BRAM_conv_weight[COUT][CIN][K][K];
    data_t BRAM_conv_bias[COUT];
    data_t BRAM_batch_norm_weights[4][COUT];
    data_t BRAM_buffer_1[COUT][HIN][WIN];
    data_t BRAM_buffer_2[COUT][HIN][WIN];

#pragma HLS array_partition variable=BRAM_conv_weight type=cyclic factor=2 dim=1
#pragma HLS array_partition variable=BRAM_conv_bias type=cyclic factor=2 dim=1
#pragma HLS array_partition variable=BRAM_batch_norm_weights type=cyclic factor=1 dim=1

    // Load from DRAM to BRAM (pass arrays directly so types match exactly)
    load_image(DRAM_image_input, BRAM_image_input);
    load_kernel(DRAM_conv_weight, BRAM_conv_weight);
    load_bias(DRAM_conv_bias, BRAM_conv_bias);
    load_bn_weights(DRAM_batch_norm_weights, BRAM_batch_norm_weights);

    // Compute
    conv2d_bias(BRAM_image_input, BRAM_conv_weight, BRAM_conv_bias, BRAM_buffer_1);
    batch_norm(BRAM_buffer_1, BRAM_batch_norm_weights, BRAM_buffer_2);
    relu(BRAM_buffer_2, BRAM_buffer_1);

    // Store result back to DRAM (pass arrays directly)
    store_image(BRAM_buffer_1, DRAM_image_output);
}

