// hls.cpp
// High-level synthesis top function for BiCG kernel
// Adjusted to match the testbench types and size (uint32_t, N=4)
// Comments are in English.

#include <stdint.h>

#define N 4

typedef uint32_t DATA_TYPE;

extern "C" {

void bicg(DATA_TYPE A[N][N], DATA_TYPE p[N], DATA_TYPE r[N], DATA_TYPE s_out[N], DATA_TYPE q_out[N]) {
#pragma HLS INTERFACE m_axi port=A offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=p offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=r offset=slave bundle=gmem2
#pragma HLS INTERFACE m_axi port=s_out offset=slave bundle=gmem3
#pragma HLS INTERFACE m_axi port=q_out offset=slave bundle=gmem4
#pragma HLS INTERFACE s_axilite port=A bundle=control
#pragma HLS INTERFACE s_axilite port=p bundle=control
#pragma HLS INTERFACE s_axilite port=r bundle=control
#pragma HLS INTERFACE s_axilite port=s_out bundle=control
#pragma HLS INTERFACE s_axilite port=q_out bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int i, j;

    // Local buffers
    DATA_TYPE buff_A[N][N];
#pragma HLS array_partition variable=buff_A block factor=2 dim=2
    DATA_TYPE buff_p[N];
#pragma HLS array_partition variable=buff_p cyclic factor=2 dim=1
    DATA_TYPE buff_r[N];
#pragma HLS array_partition variable=buff_r block factor=2 dim=1
    DATA_TYPE buff_s_out[N];
#pragma HLS array_partition variable=buff_s_out block factor=2 dim=1
    DATA_TYPE buff_q_out[N];
#pragma HLS array_partition variable=buff_q_out block factor=2 dim=1

    // Read inputs to local buffers and initialize accumulators
    for (i = 0; i < N; i++) {
#pragma HLS PIPELINE
        buff_p[i] = p[i];
        buff_r[i] = r[i];
        buff_s_out[i] = 0;
        buff_q_out[i] = 0;
        for (j = 0; j < N; j++) {
#pragma HLS UNROLL factor=2
            buff_A[i][j] = A[i][j];
        }
    }

    // Compute s_out = A^T * r  (note: original code accumulates by column index)
    for (i = 0; i < N; i++) {
#pragma HLS PIPELINE
        for (j = 0; j < N; j++) {
#pragma HLS UNROLL factor=2
            // buff_s_out[j] += buff_A[i][j] * buff_r[i];
            // All types are uint32_t; multiplication uses native integer arithmetic.
            buff_s_out[j] += buff_A[i][j] * buff_r[i];
        }
    }

    // Compute q_out = A * p
    for (i = 0; i < N; i++) {
#pragma HLS PIPELINE
        for (j = 0; j < N; j++) {
#pragma HLS UNROLL factor=2
            buff_q_out[i] += buff_A[i][j] * buff_p[j];
        }
    }

    // Write results back to output ports
    for (i = 0; i < N; i++) {
#pragma HLS PIPELINE
        s_out[i] = buff_s_out[i];
        q_out[i] = buff_q_out[i];
    }
}

} // extern "C"

