#include <cstdio>
#include <cstdint>
#include <cstdlib>
#include <cstring>

typedef int32_t DATA_TYPE;
const int N = 4;

/* DUT: mvt */
void mvt(DATA_TYPE A[N][N], DATA_TYPE x1[N], DATA_TYPE x2[N], DATA_TYPE y1[N], DATA_TYPE y2[N], DATA_TYPE x1_out[N], DATA_TYPE x2_out[N])
{
	int i, j;
	DATA_TYPE buff_A[N][N];
	DATA_TYPE buff_x1[N];
	DATA_TYPE buff_x2[N];
	DATA_TYPE buff_y1[N];
	DATA_TYPE buff_y2[N];

	for (i = 0; i < N; i++) {
		buff_x1[i] = x1[i];
		buff_x2[i] = x2[i];
		buff_y1[i] = y1[i];
		buff_y2[i] = y2[i];
		for (j = 0; j < N; j++) {
			buff_A[i][j] = A[i][j];
		}
	}

	for (i = 0; i < N; i++) {
		for (j = 0; j < N; j++) {
			buff_x1[i] = buff_x1[i] + buff_A[i][j] * buff_y1[j];
		}
	}

	for (i = 0; i < N; i++) {
		for (j = 0; j < N; j++) {
			buff_x2[i] = buff_x2[i] + buff_A[j][i] * buff_y2[j];
		}
	}

	for (i = 0; i < N; i++) {
		x1_out[i] = buff_x1[i];
		x2_out[i] = buff_x2[i];
	}
}

/* Fill inputs deterministically based on cycle number to create diverse test cases */
void fill_inputs(int cycle,
                 DATA_TYPE A[N][N],
                 DATA_TYPE x1[N],
                 DATA_TYPE x2[N],
                 DATA_TYPE y1[N],
                 DATA_TYPE y2[N])
{
    int p = cycle % 8;
    for (int i = 0; i < N; ++i) {
        x1[i] = 0;
        x2[i] = 0;
        y1[i] = 0;
        y2[i] = 0;
        for (int j = 0; j < N; ++j) {
            A[i][j] = 0;
        }
    }

    switch (p) {
        case 0: /* all zeros */
            /* already zeroed */
            break;
        case 1: /* identity A, simple sequences */
            for (int i = 0; i < N; ++i) {
                for (int j = 0; j < N; ++j) A[i][j] = (i == j) ? 1 : 0;
                x1[i] = i + 1;
                x2[i] = N - i;
                y1[i] = 1;
                y2[i] = 1;
            }
            break;
        case 2: /* all ones A, x's zero, y's small increasing */
            for (int i = 0; i < N; ++i) {
                for (int j = 0; j < N; ++j) A[i][j] = 1;
                x1[i] = 0;
                x2[i] = 0;
                y1[i] = 2*i + 1;
                y2[i] = 3*i + 1;
            }
            break;
        case 3: /* upper triangular ones */
            for (int i = 0; i < N; ++i) {
                for (int j = 0; j < N; ++j) A[i][j] = (j >= i) ? 1 : 0;
                x1[i] = 1;
                x2[i] = 2;
                y1[i] = (i % 2 == 0) ? 1 : -1;
                y2[i] = (i % 2 == 0) ? -1 : 1;
            }
            break;
        case 4: /* lower triangular with varying values */
            for (int i = 0; i < N; ++i) {
                for (int j = 0; j < N; ++j) A[i][j] = (i >= j) ? (i + 1) : 0;
                x1[i] = (i + 1) * 2;
                x2[i] = (i + 1) * 3;
                y1[i] = i;
                y2[i] = i + 1;
            }
            break;
        case 5: /* increasing matrix values */
            for (int i = 0; i < N; ++i) {
                for (int j = 0; j < N; ++j) A[i][j] = i * 10 + j + 1;
                x1[i] = i + 2;
                x2[i] = i + 3;
                y1[i] = i;
                y2[i] = 2 * i;
            }
            break;
        case 6: /* negative values */
            for (int i = 0; i < N; ++i) {
                for (int j = 0; j < N; ++j) A[i][j] = -(i + j + 1);
                x1[i] = -1;
                x2[i] = -2;
                y1[i] = i + 1;
                y2[i] = -(i + 1);
            }
            break;
        case 7: /* alternating signs */
            for (int i = 0; i < N; ++i) {
                for (int j = 0; j < N; ++j) A[i][j] = ((i + j) % 2 == 0) ? 1 : -1;
                x1[i] = (i % 2 == 0) ? i + 1 : -(i + 1);
                x2[i] = (i % 2 == 0) ? -(i + 2) : (i + 2);
                y1[i] = (i % 2 == 0) ? 2 : -2;
                y2[i] = (i % 2 == 0) ? -3 : 3;
            }
            break;
        default:
            break;
    }
}

int main()
{
    const int CYCLES = 32; /* between 20-50 as required */

    DATA_TYPE A[N][N];
    DATA_TYPE x1[N];
    DATA_TYPE x2[N];
    DATA_TYPE y1[N];
    DATA_TYPE y2[N];
    DATA_TYPE x1_out[N];
    DATA_TYPE x2_out[N];

    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    /* Header line: cycle, inputs (expanded), outputs (expanded) */
    std::fprintf(f, "cycle");
    /* A matrix elements as A[0][0],A[0][1],... */
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            std::fprintf(f, ",A[%d][%d]", i, j);
        }
    }
