// hls.cpp
// Top-level HLS implementation of the "mvt" kernel adapted for Vivado HLS C++98 environment.
// - Use stdint.h types to be compatible with older HLS toolchains.
// - Match the testbench signature: N = 4, DATA_TYPE = int32_t.
// - Pragmas adjusted so partition/unroll factors do not exceed array dimensions.

#include <stdint.h>

extern "C" {

#define N 4
typedef int32_t DATA_TYPE;

void mvt(DATA_TYPE A[N][N],
         DATA_TYPE x1[N],
         DATA_TYPE x2[N],
         DATA_TYPE y1[N],
         DATA_TYPE y2[N],
         DATA_TYPE x1_out[N],
         DATA_TYPE x2_out[N]) {
#pragma HLS INTERFACE m_axi port=A offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=x1 offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=x2 offset=slave bundle=gmem2
#pragma HLS INTERFACE m_axi port=y1 offset=slave bundle=gmem3
#pragma HLS INTERFACE m_axi port=y2 offset=slave bundle=gmem4
#pragma HLS INTERFACE m_axi port=x1_out offset=slave bundle=gmem5
#pragma HLS INTERFACE m_axi port=x2_out offset=slave bundle=gmem6
#pragma HLS INTERFACE s_axilite port=A bundle=control
#pragma HLS INTERFACE s_axilite port=x1 bundle=control
#pragma HLS INTERFACE s_axilite port=x2 bundle=control
#pragma HLS INTERFACE s_axilite port=y1 bundle=control
#pragma HLS INTERFACE s_axilite port=y2 bundle=control
#pragma HLS INTERFACE s_axilite port=x1_out bundle=control
#pragma HLS INTERFACE s_axilite port=x2_out bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int i, j;
    DATA_TYPE buff_A[N][N];
#pragma HLS array_partition variable=buff_A block factor=4 dim=2
    DATA_TYPE buff_x1[N];
#pragma HLS array_partition variable=buff_x1 cyclic factor=4 dim=1
    DATA_TYPE buff_x2[N];
#pragma HLS array_partition variable=buff_x2 block factor=4 dim=1
    DATA_TYPE buff_y1[N];
#pragma HLS array_partition variable=buff_y1 cyclic factor=2 dim=1
    DATA_TYPE buff_y2[N];
#pragma HLS array_partition variable=buff_y2 cyclic factor=4 dim=1

    // Load inputs into local buffers
    lprd_1: for (i = 0; i < N; i++) {
#pragma HLS pipeline
        buff_x1[i] = x1[i];
        buff_x2[i] = x2[i];
        buff_y1[i] = y1[i];
        buff_y2[i] = y2[i];
        lprd_2: for (j = 0; j < N; j++) {
#pragma HLS unroll factor=2
            buff_A[i][j] = A[i][j];
        }
    }

    // First matrix-vector multiply: x1 = x1 + A * y1
    lp1: for (i = 0; i < N; i++) {
#pragma HLS pipeline
        lp2: for (j = 0; j < N; j++) {
#pragma HLS pipeline
            buff_x1[i] = buff_x1[i] + buff_A[i][j] * buff_y1[j];
        }
    }

    // Second matrix-vector multiply: x2 = x2 + A^T * y2
    lp3: for (i = 0; i < N; i++) {
#pragma HLS pipeline
        lp4: for (j = 0; j < N; j++) {
#pragma HLS pipeline
            buff_x2[i] = buff_x2[i] + buff_A[j][i] * buff_y2[j];
        }
    }

    // Write back outputs
    lpwr: for (i = 0; i < N; i++) {
#pragma HLS unroll factor=4
        x1_out[i] = buff_x1[i];
        x2_out[i] = buff_x2[i];
    }
}

} // extern "C"

