// tb_hls_cosim.cpp
// Testbench for the mvt HLS kernel adapted to work with older Vivado HLS toolchains.
// - Use C headers (stdint.h, stdio.h, etc.) instead of C++11 headers like <cstdint>.
// - Do not change test patterns or output format; only update headers and namespace usage
//   to be compatible with C++98 / older libstdc++.

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>

typedef int32_t DATA_TYPE;
const int N = 4;

/* DUT: mvt */
/* The extern "C" declaration must match the HLS top-level function signature exactly. */
extern "C" void mvt(DATA_TYPE A[N][N],
                    DATA_TYPE x1[N],
                    DATA_TYPE x2[N],
                    DATA_TYPE y1[N],
                    DATA_TYPE y2[N],
                    DATA_TYPE x1_out[N],
                    DATA_TYPE x2_out[N]);

/* Fill inputs deterministically based on cycle number to create diverse test cases */
void fill_inputs(int cycle,
                 DATA_TYPE A[N][N],
                 DATA_TYPE x1[N],
                 DATA_TYPE x2[N],
                 DATA_TYPE y1[N],
                 DATA_TYPE y2[N])
{
    int p = cycle % 8;
    int i, j;
    for (i = 0; i < N; ++i) {
        x1[i] = 0;
        x2[i] = 0;
        y1[i] = 0;
        y2[i] = 0;
        for (j = 0; j < N; ++j) {
            A[i][j] = 0;
        }
    }

    switch (p) {
        case 0: /* all zeros */
            /* already zeroed */
            break;
        case 1: /* identity A, simple sequences */
            for (i = 0; i < N; ++i) {
                for (j = 0; j < N; ++j) A[i][j] = (i == j) ? 1 : 0;
                x1[i] = i + 1;
                x2[i] = N - i;
                y1[i] = 1;
                y2[i] = 1;
            }
            break;
        case 2: /* all ones A, x's zero, y's small increasing */
            for (i = 0; i < N; ++i) {
                for (j = 0; j < N; ++j) A[i][j] = 1;
                x1[i] = 0;
                x2[i] = 0;
                y1[i] = 2*i + 1;
                y2[i] = 3*i + 1;
            }
            break;
        case 3: /* upper triangular ones */
            for (i = 0; i < N; ++i) {
                for (j = 0; j < N; ++j) A[i][j] = (j >= i) ? 1 : 0;
                x1[i] = 1;
                x2[i] = 2;
                y1[i] = (i % 2 == 0) ? 1 : -1;
                y2[i] = (i % 2 == 0) ? -1 : 1;
            }
            break;
        case 4: /* lower triangular with varying values */
            for (i = 0; i < N; ++i) {
                for (j = 0; j < N; ++j) A[i][j] = (i >= j) ? (i + 1) : 0;
                x1[i] = (i + 1) * 2;
                x2[i] = (i + 1) * 3;
                y1[i] = i;
                y2[i] = i + 1;
            }
            break;
        case 5: /* increasing matrix values */
            for (i = 0; i < N; ++i) {
                for (j = 0; j < N; ++j) A[i][j] = i * 10 + j + 1;
                x1[i] = i + 2;
                x2[i] = i + 3;
                y1[i] = i;
                y2[i] = 2 * i;
            }
            break;
        case 6: /* negative values */
            for (i = 0; i < N; ++i) {
                for (j = 0; j < N; ++j) A[i][j] = -(i + j + 1);
                x1[i] = -1;
                x2[i] = -2;
                y1[i] = i + 1;
                y2[i] = -(i + 1);
            }
            break;
        case 7: /* alternating signs */
            for (i = 0; i < N; ++i) {
                for (j = 0; j < N; ++j) A[i][j] = ((i + j) % 2 == 0) ? 1 : -1;
                x1[i] = (i % 2 == 0) ? i + 1 : -(i + 1);
                x2[i] = (i % 2 == 0) ? -(i + 2) : (i + 2);
                y1[i] = (i % 2 == 0) ? 2 : -2;
                y2[i] = (i % 2 == 0) ? -3 : 3;
            }
            break;
        default:
            break;
    }
}

int main()
{
    const int CYCLES = 32; /* between 20-50 as required */

    DATA_TYPE A[N][N];
    DATA_TYPE x1[N];
    DATA_TYPE x2[N];
    DATA_TYPE y1[N];
    DATA_TYPE y2[N];
    DATA_TYPE x1_out[N];
    DATA_TYPE x2_out[N];

    FILE *f = fopen("hls_output.csv", "w");
    if (!f) return 1;

    /* Header line: cycle, inputs (expanded), outputs (expanded) */
    fprintf(f, "cycle");
    /* A matrix elements as A[0][0],A[0][1],... */
    {
        int i, j;
        for (i = 0; i < N; ++i) {
            for (j = 0; j < N; ++j) {
                fprintf(f, ",A[%d][%d]", i, j);
            }
        }
    }
    {
        int i;
        for (i = 0; i < N; ++i) fprintf(f, ",x1[%d]", i);
        for (i = 0; i < N; ++i) fprintf(f, ",x2[%d]", i);
        for (i = 0; i < N; ++i) fprintf(f, ",y1[%d]", i);
        for (i = 0; i < N; ++i) fprintf(f, ",y2[%d]", i);
        for (i = 0; i < N; ++i) fprintf(f, ",x1_out[%d]", i);
        for (i = 0; i < N; ++i) fprintf(f, ",x2_out[%d]", i);
    }
    fprintf(f, "\n");

    /* Role line: meta/in/out */
    fprintf(f, "meta");
    {
        int i;
        for (i = 0; i < N*N + 4*N; ++i) fprintf(f, ",in");
        for (i = 0; i < 2*N; ++i) fprintf(f, ",out");
    }
    fprintf(f, "\n");

    /* Execute cycles */
    {
        int cyc;
        for (cyc = 0; cyc < CYCLES; ++cyc) {
            fill_inputs(cyc, A, x1, x2, y1, y2);

            /* Call DUT (in HLS cosim this will invoke the RTL model) */
            mvt(A, x1, x2, y1, y2, x1_out, x2_out);

            /* Write one CSV row: cycle (decimal), inputs (decimal), outputs (hex uppercase, no 0x) */
            fprintf(f, "%d", cyc);

            {
                int i, j;
                for (i = 0; i < N; ++i) {
                    for (j = 0; j < N; ++j) {
                        fprintf(f, ",%d", (int)A[i][j]);
                    }
                }
            }
            {
                int i;
                for (i = 0; i < N; ++i) fprintf(f, ",%d", (int)x1[i]);
                for (i = 0; i < N; ++i) fprintf(f, ",%d", (int)x2[i]);
                for (i = 0; i < N; ++i) fprintf(f, ",%d", (int)y1[i]);
                for (i = 0; i < N; ++i) fprintf(f, ",%d", (int)y2[i]);
            }

            {
                int i;
                for (i = 0; i < N; ++i) {
                    uint32_t v = (uint32_t)x1_out[i];
                    fprintf(f, ",%X", (unsigned)v);
                }
                for (i = 0; i < N; ++i) {
                    uint32_t v = (uint32_t)x2_out[i];
                    fprintf(f, ",%X", (unsigned)v);
                }
            }
            fprintf(f, "\n");
        }
    }

    fclose(f);
    return 0;
}

