    0x650a7354u, 0x766a0abbu, 0x81c2c92eu, 0x92722c85u, 0xa2bfe8a1u, 0xa81a664bu,
    0xc24b8b70u, 0xc76c51a3u, 0xd192e819u, 0xd6990624u, 0xf40e3585u, 0x106aa070u,
    0x19a4c116u, 0x1e376c08u, 0x2748774cu, 0x34b0bcb5u, 0x391c0cb3u, 0x4ed8aa4au,
    0x5b9cca4fu, 0x682e6ff3u, 0x748f82eeu, 0x78a5636fu, 0x84c87814u, 0x8cc70208u,
    0x90befffau, 0xa4506cebu, 0xbef9a3f7u, 0xc67178f2u
};

void sha256_transform(state_t *state, const unsigned char data[]) {
    unsigned int a, b, c, d, e, f, g, h, i, j, t1, t2, m[64];

    for (i = 0, j = 0; i < 16; ++i, j += 4)
        m[i] = ((unsigned int)data[j] << 24) | ((unsigned int)data[j + 1] << 16) |
               ((unsigned int)data[j + 2] << 8) | ((unsigned int)data[j + 3]);
    for (; i < 64; ++i)
        m[i] = SIG1(m[i - 2]) + m[i - 7] + SIG0(m[i - 15]) + m[i - 16];

    a = (*state)[0];
    b = (*state)[1];
    c = (*state)[2];
    d = (*state)[3];
    e = (*state)[4];
    f = (*state)[5];
    g = (*state)[6];
    h = (*state)[7];

    for (i = 0; i < 64; ++i) {
        t1 = h + EP1(e) + CH(e, f, g) + k_table[i] + m[i];
        t2 = EP0(a) + MAJ(a, b, c);
        h = g;
        g = f;
        f = e;
        e = d + t1;
        d = c;
        c = b;
        b = a;
        a = t1 + t2;
    }

    (*state)[0] += a;
    (*state)[1] += b;
    (*state)[2] += c;
    (*state)[3] += d;
    (*state)[4] += e;
    (*state)[5] += f;
    (*state)[6] += g;
    (*state)[7] += h;
}

void sha256_init(SHA256_CTX *ctx) {
    ctx->datalen = 0;
    ctx->bitlen = 0;
    ctx->state[0] = 0x6a09e667u;
    ctx->state[1] = 0xbb67ae85u;
    ctx->state[2] = 0x3c6ef372u;
    ctx->state[3] = 0xa54ff53au;
    ctx->state[4] = 0x510e527fu;
    ctx->state[5] = 0x9b05688cu;
    ctx->state[6] = 0x1f83d9abu;
    ctx->state[7] = 0x5be0cd19u;
    memset(ctx->data, 0, sizeof(ctx->data));
}

void sha256_update(
    data_t *data_int,
    unsigned int *datalen_int,
    state_t *state,
    unsigned long long int *bitlen_int,
    const unsigned char data[],
    size_t len) {
    size_t i;

    if (len == 0) return;

    for (i = 0; i < len; ++i) {
        (*data_int)[*datalen_int] = data[i];
        (*datalen_int)++;
        if (*datalen_int == 64) {
            sha256_transform(state, *data_int);
            *bitlen_int += 512;
            *datalen_int = 0;
        }
    }
}

void sha256(SHA256_CTX *ctx, unsigned char hash[]) {
    unsigned int i;

    i = ctx->datalen;

    if (ctx->datalen < 56) {
        ctx->data[i++] = 0x80;
        while (i < 56) {
            ctx->data[i++] = 0x00;
        }
    } else {
        ctx->data[i++] = 0x80;
        while (i < 64) {
            ctx->data[i++] = 0x00;
        }
        sha256_transform(&ctx->state, ctx->data);
        memset(ctx->data, 0, 56);
    }

    ctx->bitlen += ctx->datalen * 8ULL;
    ctx->data[63] = (unsigned char)(ctx->bitlen);
    ctx->data[62] = (unsigned char)(ctx->bitlen >> 8);
    ctx->data[61] = (unsigned char)(ctx->bitlen >> 16);
    ctx->data[60] = (unsigned char)(ctx->bitlen >> 24);
    ctx->data[59] = (unsigned char)(ctx->bitlen >> 32);
    ctx->data[58] = (unsigned char)(ctx->bitlen >> 40);
    ctx->data[57] = (unsigned char)(ctx->bitlen >> 48);
    ctx->data[56] = (unsigned char)(ctx->bitlen >> 56);
    sha256_transform(&ctx->state, ctx->data);

    for (i = 0; i < 4; ++i) {
        hash[i] = (unsigned char)((ctx->state[0] >> (24 - i * 8)) & 0x000000ffu);
        hash[i + 4] = (unsigned char)((ctx->state[1] >> (24 - i * 8)) & 0x000000ffu);
        hash[i + 8] = (unsigned char)((ctx->state[2] >> (24 - i * 8)) & 0x000000ffu);
        hash[i + 12] = (unsigned char)((ctx->state[3] >> (24 - i * 8)) & 0x000000ffu);
        hash[i + 16] = (unsigned char)((ctx->state[4] >> (24 - i * 8)) & 0x000000ffu);
        hash[i + 20] = (unsigned char)((ctx->state[5] >> (24 - i * 8)) & 0x000000ffu);
        hash[i + 24] = (unsigned char)((ctx->state[6] >> (24 - i * 8)) & 0x000000ffu);
        hash[i + 28] = (unsigned char)((ctx->state[7] >> (24 - i * 8)) & 0x000000ffu);
    }
}

/* Helpers to create test messages (allocated, must be freed) */
static char* make_repeat(char c, size_t n) {
    char *s = (char*)malloc(n + 1);
    if (!s) return NULL;
    if (n > 0) memset(s, (unsigned char)c, n);
    s[n] = '\0';
    return s;
}

static char* make_pattern(size_t n) {
    char *s = (char*)malloc(n + 1);
    if (!s) return NULL;
    for (size_t i = 0; i < n; ++i) {
        s[i] = (char)(i & 0xFF);
    }
    s[n] = '\0';
    return s;
}

int main(void) {
    /* Build array of message pointers. Some are static literals, others allocated. */
    enum { MAX_MSGS = 40 };
    char *msgs[MAX_MSGS];
    size_t msg_lens[MAX_MSGS];
    int msg_count = 0;

    /* static literals */
    msgs[msg_count] = strdup(""); msg_lens[msg_count++] = 0;
    msgs[msg_count] = strdup("a"); msg_lens[msg_count++] = 1;
    msgs[msg_count] = strdup("abc"); msg_lens[msg_count++] = 3;
    msgs[msg_count] = strdup("test"); msg_lens[msg_count++] = 4;
    msgs[msg_count] = strdup("foobar"); msg_lens[msg_count++] = 6;
    msgs[msg_count] = strdup("OpenAI"); msg_lens[msg_count++] = 6;

    /* generated messages to exercise branches */
    msgs[msg_count] = make_repeat('A', 55); msg_lens[msg_count++] = 55;   /* <56 finalization path */
    msgs[msg_count] = make_repeat('B', 56); msg_lens[msg_count++] = 56;   /* >=56 finalization extra transform */
    msgs[msg_count] = make_repeat('C', 57); msg_lens[msg_count++] = 57;
    msgs[msg_count] = make_repeat('X', 63); msg_lens[msg_count++] = 63;
    msgs[msg_count] = make_repeat('D', 64); msg_lens[msg_count++] = 64;
    msgs[msg_count] = make_repeat('E', 65); msg_lens[msg_count++] = 65;
    msgs[msg_count] = make_repeat('F', 100); msg_lens[msg_count++] = 100;
    msgs[msg_count] = make_repeat('G', 127); msg_lens[msg_count++] = 127;
    msgs[msg_count] = make_repeat('H', 128); msg_lens[msg_count++] = 128;
    msgs[msg_count] = make_repeat('I', 129); msg_lens[msg_count++] = 129;
    msgs[msg_count] = make_repeat('J', 255); msg_lens[msg_count++] = 255;
    msgs[msg_count] = make_repeat('K', 256); msg_lens[msg_count++] = 256;
    msgs[msg_count] = make_repeat('L', 300); msg_lens[msg_count++] = 300;
    msgs[msg_count] = make_pattern(300); msg_lens[msg_count++] = 300;
    msgs[msg_count] = make_pattern(512); msg_lens[msg_count++] = 512;

    /* longer messages to ensure many sha256_transform calls and m[] expansion coverage */
    msgs[msg_count] = make_repeat('M', 1023); msg_lens[msg_count++] = 1023;
    msgs[msg_count] = make_repeat('N', 1024); msg_lens[msg_count++] = 1024;
    msgs[msg_count] = make_repeat('O', 1025); msg_lens[msg_count++] = 1025;
    msgs[msg_count] = make_repeat('P', 2047); msg_lens[msg_count++] = 2047;
    msgs[msg_count] = make_repeat('Q', 2048); msg_lens[msg_count++] = 2048;
    msgs[msg_count] = make_repeat('R', 2049); msg_lens[msg_count++] = 2049;
    msgs[msg_count] = make_repeat('S', 4096); msg_lens[msg_count++] = 4096;
    msgs[msg_count] = make_repeat('T', 5000); msg_lens[msg_count++] = 5000;
    msgs[msg_count] = make_repeat('U', 10000); msg_lens[msg_count++] = 10000;

    /* Ensure we did not exceed array */
    if (msg_count > MAX_MSGS) msg_count = MAX_MSGS;

    /* Open CSV file */
    FILE *f = fopen("c_output.csv", "w");
    if (!f) {
        fprintf(stderr, "Failed to open c_output.csv for writing\n");
        /* free allocated */
        for (int i = 0; i < msg_count; ++i) free(msgs[i]);
        return 1;
    }

    /* Write header */
    fprintf(f, "cycle,init,data_valid,data_in,finalize,hash_valid");
    for (int i = 0; i < SHA256_BLOCK_SIZE; ++i) {
        fprintf(f, ",hash%d", i);
    }
    fprintf(f, "\n");

    /* Roles line */
    fprintf(f, "meta,in,in,in,in,out");
    for (int i = 0; i < SHA256_BLOCK_SIZE; ++i) {
        fprintf(f, ",out");
    }
    fprintf(f, "\n");

    SHA256_CTX ctx;
    unsigned char last_hash[SHA256_BLOCK_SIZE];
    for (int i = 0; i < SHA256_BLOCK_SIZE; ++i) last_hash[i] = 0;

    unsigned int cycle = 0;

    for (int mi = 0; mi < msg_count; ++mi) {
        const char *msg = msgs[mi];
        size_t len = msg_lens[mi];

        /* INIT cycle */
        int init = 1;
        int data_valid = 0;
        unsigned int data_in = 0;
        int finalize = 0;
        int hash_valid = 0;

        sha256_init(&ctx);
        /* simulate a cycle with no input */
        sha256_update(&ctx.data, &ctx.datalen, &ctx.state, &ctx.bitlen, NULL, 0);

        fprintf(f, "%u,%d,%d,%u,%d,%d", cycle, init, data_valid, data_in, finalize, hash_valid);
        for (int i = 0; i < SHA256_BLOCK_SIZE; ++i) {
            fprintf(f, ",%02X", (unsigned int)last_hash[i]);
        }
        fprintf(f, "\n");
        ++cycle;

        /* DATA cycles - to speed up runtime for huge messages, feed in chunks of up to 256 bytes per cycle.
           We still record one CSV row per chunk (data_in reports the first byte of the chunk). */
        size_t idx = 0;
        while (idx < len) {
            init = 0;
            data_valid = 1;
            size_t chunk = len - idx;
            if (chunk > 256) chunk = 256;
            data_in = (unsigned char)msg[idx];
            finalize = 0;
            hash_valid = 0;

            /* call sha256_update for this chunk */
            sha256_update(&ctx.data, &ctx.datalen, &ctx.state, &ctx.bitlen, (const unsigned char*)(msg + idx), chunk);

            fprintf(f, "%u,%d,%d,%u,%d,%d", cycle, init, data_valid, data_in, finalize, hash_valid);
            for (int i = 0; i < SHA256_BLOCK_SIZE; ++i) {
                fprintf(f, ",%02X", (unsigned int)last_hash[i]);
            }
            fprintf(f, "\n");
            ++cycle;

            idx += chunk;
        }

        /* FINALIZE cycle */
        init = 0;
        data_valid = 0;
        data_in = 0;
        finalize = 1;

        unsigned char hash_out[SHA256_BLOCK_SIZE];
        sha256(&ctx, hash_out);

        for (int i = 0; i < SHA256_BLOCK_SIZE; ++i) last_hash[i] = hash_out[i];
        hash_valid = 1;

        /* simulate one more cycle to represent finalize being sampled */
        sha256_update(&ctx.data, &ctx.datalen, &ctx.state, &ctx.bitlen, NULL, 0);

        fprintf(f, "%u,%d,%d,%u,%d,%d", cycle, init, data_valid, data_in, finalize, hash_valid);
        for (int i = 0; i < SHA256_BLOCK_SIZE; ++i) {
            fprintf(f, ",%02X", (unsigned int)last_hash[i]);
        }
        fprintf(f, "\n");
        ++cycle;
    }

    /* Pad to at least 80 cycles (extra idle cycles) to ensure more coverage and sampling */
    while (cycle < 80) {
        int init = 0;
        int data_valid = 0;
        unsigned int data_in = 0;
        int finalize = 0;
        int hash_valid = 0;
        sha256_update(&ctx.data, &ctx.datalen, &ctx.state, &ctx.bitlen, NULL, 0);
        fprintf(f, "%u,%d,%d,%u,%d,%d", cycle, init, data_valid, data_in, finalize, hash_valid);
        for (int i = 0; i < SHA256_BLOCK_SIZE; ++i) {
            fprintf(f, ",%02X", (unsigned int)last_hash[i]);
        }
        fprintf(f, "\n");
        ++cycle;
    }

    /* flush and close */
    fflush(f);
    fclose(f);

    /* free allocated messages */
    for (int i = 0; i < msg_count; ++i) free(msgs[i]);

    return 0;
}

