// hls.cpp
// SHA-256 HLS implementation adapted to provide a C-linkage sha256_update
// that matches the testbench's expected signature (for C simulation and cosim).
//
// Notes:
// - Use C headers for maximum compatibility with Vivado HLS (C++98 mode).
// - Top-level functions meant for HLS/C linking are declared extern "C".

#include <stdint.h>
#include <stddef.h>
#include <string.h>

#define SHA256_BLOCK_SIZE 32

#define ROTLEFT(a, b) (((a) << (b)) | ((a) >> (32 - (b))))
#define ROTRIGHT(a, b) (((a) >> (b)) | ((a) << (32 - (b))))

#define CH(x, y, z) (((x) & (y)) ^ (~(x) & (z)))
#define MAJ(x, y, z) (((x) & (y)) ^ ((x) & (z)) ^ ((y) & (z)))
#define EP0(x) (ROTRIGHT(x, 2) ^ ROTRIGHT(x, 13) ^ ROTRIGHT(x, 22))
#define EP1(x) (ROTRIGHT(x, 6) ^ ROTRIGHT(x, 11) ^ ROTRIGHT(x, 25))
#define SIG0(x) (ROTRIGHT(x, 7) ^ ROTRIGHT(x, 18) ^ ((x) >> 3))
#define SIG1(x) (ROTRIGHT(x, 17) ^ ROTRIGHT(x, 19) ^ ((x) >> 10))

/* Round constants */
static const unsigned int k[64] = {
    0x428a2f98u, 0x71374491u, 0xb5c0fbcfu, 0xe9b5dba5u, 0x3956c25bu, 0x59f111f1u,
    0x923f82a4u, 0xab1c5ed5u, 0xd807aa98u, 0x12835b01u, 0x243185beu, 0x550c7dc3u,
    0x72be5d74u, 0x80deb1feu, 0x9bdc06a7u, 0xc19bf174u, 0xe49b69c1u, 0xefbe4786u,
    0x0fc19dc6u, 0x240ca1ccu, 0x2de92c6fu, 0x4a7484aau, 0x5cb0a9dcu, 0x76f988dau,
    0x983e5152u, 0xa831c66du, 0xb00327c8u, 0xbf597fc7u, 0xc6e00bf3u, 0xd5a79147u,
    0x06ca6351u, 0x14292967u, 0x27b70a85u, 0x2e1b2138u, 0x4d2c6dfcu, 0x53380d13u,
    0x650a7354u, 0x766a0abbu, 0x81c2c92eu, 0x92722c85u, 0xa2bfe8a1u, 0xa81a664bu,
    0xc24b8b70u, 0xc76c51a3u, 0xd192e819u, 0xd6990624u, 0xf40e3585u, 0x106aa070u,
    0x19a4c116u, 0x1e376c08u, 0x2748774cu, 0x34b0bcb5u, 0x391c0cb3u, 0x4ed8aa4au,
    0x5b9cca4fu, 0x682e6ff3u, 0x748f82eeu, 0x78a5636fu, 0x84c87814u, 0x8cc70208u,
    0x90befffau, 0xa4506cebu, 0xbef9a3f7u, 0xc67178f2u
};

/* Public typedefs used by the testbench/DUT interface */
typedef unsigned char data_t[64];
typedef unsigned int state_t[8];

/* Internal transform function (operates on arrays; arrays decay to pointers) */
static void sha256_transform(state_t state, const data_t data) {
    unsigned int a, b, c, d, e, f, g, h;
    unsigned int i, j, t1, t2, m[64];
#pragma HLS array_partition variable=m complete dim=1

    for (i = 0, j = 0; i < 16; ++i, j += 4) {
#pragma HLS unroll factor=4
        m[i] = ( (unsigned int)data[j] << 24 ) | ( (unsigned int)data[j + 1] << 16 ) |
               ( (unsigned int)data[j + 2] << 8 )  | ( (unsigned int)data[j + 3] );
    }
    for (; i < 64; ++i) {
#pragma HLS unroll factor=16
        m[i] = SIG1(m[i - 2]) + m[i - 7] + SIG0(m[i - 15]) + m[i - 16];
    }

    a = state[0];
    b = state[1];
    c = state[2];
    d = state[3];
    e = state[4];
    f = state[5];
    g = state[6];
    h = state[7];

    for (i = 0; i < 64; ++i) {
#pragma HLS unroll factor=4
        t1 = h + EP1(e) + CH(e, f, g) + k[i] + m[i];
        t2 = EP0(a) + MAJ(a, b, c);
        h = g;
        g = f;
        f = e;
        e = d + t1;
        d = c;
        c = b;
        b = a;
        a = t1 + t2;
    }

    state[0] += a;
    state[1] += b;
    state[2] += c;
    state[3] += d;
    state[4] += e;
    state[5] += f;
    state[6] += g;
    state[7] += h;
}

/* Initialize SHA-256 state words (used when preparing DUT-side state) */
static void sha256_init_state(state_t state) {
    state[0] = 0x6a09e667u;
    state[1] = 0xbb67ae85u;
    state[2] = 0x3c6ef372u;
    state[3] = 0xa54ff53au;
    state[4] = 0x510e527fu;
    state[5] = 0x9b05688cu;
    state[6] = 0x1f83d9abu;
    state[7] = 0x5be0cd19u;
}

/* Provide sha256_update with C linkage and the exact argument ordering
   expected by the testbench. The testbench passes pointers to data buffer,
   datalen, state and bitlen and provides bytes via "data" with a length. */
extern "C" void sha256_update(
    data_t *data_int,
    unsigned int *datalen_int,
    state_t *state,
    unsigned long long int *bitlen_int,
    const unsigned char data[],
    size_t len)
{
    size_t i;

    /* If no bytes to append, return immediately (do not modify state). */
    if (len == 0) {
        return;
    }

    for (i = 0; i < len; ++i) {
#pragma HLS pipeline
        (*data_int)[*datalen_int] = data[i];
        (*datalen_int)++;
        if (*datalen_int == 64) {
            /* call transform with dereferenced array types */
            sha256_transform(*state, *data_int);
            *bitlen_int += 512ULL;
            *datalen_int = 0;
        }
    }
}

/* Top-level HLS accelerator (kept for completeness/synthesis) */
extern "C" void sha256_accel(const unsigned char data[], unsigned int len, unsigned char hash[32]) {
#pragma HLS INTERFACE m_axi port=data offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=hash offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=data bundle=control
#pragma HLS INTERFACE s_axilite port=len bundle=control
#pragma HLS INTERFACE s_axilite port=hash bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    state_t state;
    data_t data_buffer;
    unsigned int datalen = 0;
    unsigned long long bitlen = 0ULL;
    unsigned int i;

    sha256_init_state(state);

    /* Initialize data_buffer to zero */
    for (i = 0; i < 64; i++) {
#pragma HLS unroll
        data_buffer[i] = 0;
    }

    /* Call the update helper (note argument ordering is pointer-based) */
    sha256_update(&data_buffer, &datalen, &state, &bitlen, data, (size_t)len);

    /* Padding */
    i = datalen;

    if (datalen < 56) {
        data_buffer[i++] = 0x80;
        for (; i < 56; i++) {
#pragma HLS LOOP_TRIPCOUNT min=1 max=56
            data_buffer[i] = 0x00;
        }
    } else {
        data_buffer[i++] = 0x80;
        for (; i < 64; i++) {
#pragma HLS LOOP_TRIPCOUNT min=1 max=64
            data_buffer[i] = 0x00;
        }
        sha256_transform(state, data_buffer);
        for (i = 0; i < 56; i++) {
#pragma HLS unroll
            data_buffer[i] = 0x00;
        }
    }

    bitlen += datalen * 8ULL;

    data_buffer[63] = (unsigned char)(bitlen);
    data_buffer[62] = (unsigned char)(bitlen >> 8);
    data_buffer[61] = (unsigned char)(bitlen >> 16);
    data_buffer[60] = (unsigned char)(bitlen >> 24);
    data_buffer[59] = (unsigned char)(bitlen >> 32);
    data_buffer[58] = (unsigned char)(bitlen >> 40);
    data_buffer[57] = (unsigned char)(bitlen >> 48);
    data_buffer[56] = (unsigned char)(bitlen >> 56);

    sha256_transform(state, data_buffer);

    /* Convert state to output hash (big endian) */
    for (i = 0; i < 4; ++i) {
#pragma HLS pipeline
        hash[i]      = (unsigned char)((state[0] >> (24 - i * 8)) & 0xff);
        hash[i + 4]  = (unsigned char)((state[1] >> (24 - i * 8)) & 0xff);
        hash[i + 8]  = (unsigned char)((state[2] >> (24 - i * 8)) & 0xff);
        hash[i + 12] = (unsigned char)((state[3] >> (24 - i * 8)) & 0xff);
        hash[i + 16] = (unsigned char)((state[4] >> (24 - i * 8)) & 0xff);
        hash[i + 20] = (unsigned char)((state[5] >> (24 - i * 8)) & 0xff);
        hash[i + 24] = (unsigned char)((state[6] >> (24 - i * 8)) & 0xff);
        hash[i + 28] = (unsigned char)((state[7] >> (24 - i * 8)) & 0xff);
    }
}

