#include <string>

// DUT parameters and implementation (from the provided function)
#define NPOINTS 4
#define NCLUSTERS 3
#define NFEATURES 2

void kmeans(float *feature, float *clusters, int *membership)
{
    for (int i = 0; i < NPOINTS; i++) {
        float min_dist = FLT_MAX;
        int index = 0;
        for (int j = 0; j < NCLUSTERS; j++) {
            float dist = 0.0f;
            for (int k = 0; k < NFEATURES; k++) {
                float diff = feature[NFEATURES * i + k] - clusters[NFEATURES * j + k];
                dist += diff * diff;
            }
            if (dist < min_dist) {
                min_dist = dist;
                index = j;
            }
        }
        membership[i] = index;
    }
}

int main()
{
    // Prepare CSV file
    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // CSV header: cycle, then inputs (feature, clusters), then outputs (membership)
    std::fprintf(f, "cycle,feature,clusters,membership\n");
    // Roles row: cycle is meta, inputs are in, outputs are out
    std::fprintf(f, "meta,in,in,out\n");

    // Number of deterministic test vectors (choose within 20-50)
    const int NTESTS = 24;

    // Buffers for DUT
    float feature[NPOINTS * NFEATURES];
    float clusters[NCLUSTERS * NFEATURES];
    int membership[NPOINTS];

    // Generate and run test cases deterministically
    for (int t = 0; t < NTESTS; ++t) {
        // Fill feature array deterministically based on t, point index, and feature index
        for (int i = 0; i < NPOINTS; ++i) {
            for (int k = 0; k < NFEATURES; ++k) {
                // Formula ensures variety, uses only integers and simple ops
                int base = ((t + 1) * (i + 1) * (k + 1)) % 7;
                float frac = (float)((t % 3)) * 0.1f;
                feature[i * NFEATURES + k] = (float)base + frac;
            }
        }

        // Fill clusters array deterministically based on t and cluster index
        for (int j = 0; j < NCLUSTERS; ++j) {
            for (int k = 0; k < NFEATURES; ++k) {
                int base = ((t + 2) * (j + 1) * (k + 2)) % 5;
                float frac = (float)((t + 1) % 4) * 0.2f;
                clusters[j * NFEATURES + k] = (float)base + frac;
            }
        }

        // Call DUT (one call per cycle)
        kmeans(feature, clusters, membership);

        // Prepare membership output as hex uppercase values separated by '|'
        std::string memb_str;
        for (int i = 0; i < NPOINTS; ++i) {
            char tmp[16];
            // membership values are small non-negative ints; print in hex uppercase without 0x
            std::sprintf(tmp, "%X", membership[i]);
            if (!memb_str.empty()) memb_str.push_back('|');
            memb_str += tmp;
        }

        // For inputs, we output the test-case id as a decimal integer for both feature and clusters columns.
        // This represents which deterministic vector was applied.
        std::fprintf(f, "%d,%d,%d,%s\n", t, t, t, memb_str.c_str());
    }

    // Explicitly close file
    std::fclose(f);
    return 0;
}

