// hls.cpp
// KMeans HLS implementation adjusted to match the testbench sizes.
// Comments and pragmas are written in English and use canonical Vivado HLS forms
// compatible with older toolchains. The file exposes an extern "C" top-level
// function `kmeans` with the same signature the testbench expects. Helper
// routines are declared static so they do not create external linkage.

#include <float.h> // Use C header for FLT_MAX for older toolchain compatibility

#define NCLUSTERS 3
#define NFEATURES 2
#define TILE_SIZE 2
#define NPOINTS 4
#define NUM_TILES (NPOINTS / TILE_SIZE)

//
// Helper functions: keep them with internal linkage (static) so they are not
// visible outside this translation unit. These are plain C++ functions and
// must not change linkage of the top-level entry point.
//

// Copy clusters from external memory into local array
static void load_local_cluster(float local_clusters[NCLUSTERS * NFEATURES],
                               const float *clusters) {
    // Small fixed-size arrays: fully unroll both loops for performance.
    for (int i = 0; i < NCLUSTERS; ++i) {
#pragma HLS UNROLL
        for (int j = 0; j < NFEATURES; ++j) {
#pragma HLS UNROLL
            local_clusters[i * NFEATURES + j] = clusters[i * NFEATURES + j];
        }
    }
}

// Load one tile of features into local buffer
static void load_local_feature(float local_feature[TILE_SIZE * NFEATURES],
                               const float *feature,
                               int tile_idx) {
    for (int i = 0; i < TILE_SIZE; ++i) {
#pragma HLS PIPELINE II=1
        for (int j = 0; j < NFEATURES; ++j) {
#pragma HLS UNROLL
            int global_idx = (tile_idx * TILE_SIZE + i) * NFEATURES + j;
            local_feature[i * NFEATURES + j] = feature[global_idx];
        }
    }
}

// Compute membership for one tile: for each point, find nearest cluster
static void compute_local_membership(const float local_feature[TILE_SIZE * NFEATURES],
                                     const float local_clusters[NCLUSTERS * NFEATURES],
                                     int local_membership[TILE_SIZE]) {
    for (int i = 0; i < TILE_SIZE; i++) {
#pragma HLS PIPELINE II=1
        float min_dist = FLT_MAX;
        int index = 0;
        // Small fixed number of clusters: unroll cluster loop
        for (int j = 0; j < NCLUSTERS; j++) {
#pragma HLS UNROLL
            float dist = 0.0f;
            // Small fixed number of features: unroll feature loop
            for (int k = 0; k < NFEATURES; k++) {
#pragma HLS UNROLL
                float diff = local_feature[NFEATURES * i + k] - local_clusters[NFEATURES * j + k];
                dist += diff * diff;
            }
            if (dist < min_dist) {
                min_dist = dist;
                index = j;
            }
        }
        local_membership[i] = index;
    }
}

// Store tile membership back to external memory
static void store_local_membership(const int local_membership[TILE_SIZE],
                                   int *membership,
                                   int tile_idx) {
    for (int i = 0; i < TILE_SIZE; ++i) {
#pragma HLS UNROLL
        membership[tile_idx * TILE_SIZE + i] = local_membership[i];
    }
}

extern "C" {

// Top-level function to be synthesized. Keep C linkage to match testbench.
void kmeans(float *feature, float *clusters, int *membership) {
#pragma HLS INTERFACE m_axi port=feature offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=membership offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=clusters offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=feature bundle=control
#pragma HLS INTERFACE s_axilite port=membership bundle=control
#pragma HLS INTERFACE s_axilite port=clusters bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local buffers sized according to the small testbench
    int local_membership[TILE_SIZE];
#pragma HLS ARRAY_PARTITION variable=local_membership complete dim=1

    float local_feature[TILE_SIZE * NFEATURES];
#pragma HLS ARRAY_PARTITION variable=local_feature cyclic factor=2 dim=1

    float local_clusters[NCLUSTERS * NFEATURES];
#pragma HLS ARRAY_PARTITION variable=local_clusters complete dim=1

    // Load clusters once (clusters are small in the testbench)
    load_local_cluster(local_clusters, clusters);

    // Process points in tiles
    for (int ii = 0; ii < NUM_TILES; ++ii) {
#pragma HLS PIPELINE II=1
        load_local_feature(local_feature, feature, ii);
        compute_local_membership(local_feature, local_clusters, local_membership);
        store_local_membership(local_membership, membership, ii);
    }
}

} // extern "C"

