int main() {
    const int CYCLES = 32; // number of cycles / test vectors

    // Open CSV file
    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // Write CSV header
    // cycle, r0...r7, H_0_0...H_3_2, F_0_0...F_3_2, y0...y7
    std::fprintf(f, "cycle");
    for (int i = 0; i < R_LEN; ++i) {
        std::fprintf(f, ",r%d", i);
    }
    for (int b = 0; b < BANKS; ++b) {
        for (int t = 0; t < TAPS; ++t) {
