    for (int b = 0; b < BANKS; ++b) {
        for (int t = 0; t < TAPS; ++t) {
            std::fprintf(f, ",F_%d_%d", b, t);
        }
    }
    for (int i = 0; i < R_LEN; ++i) {
        std::fprintf(f, ",y%d", i);
    }
    std::fprintf(f, "\n");

    // Write roles line: meta/in/out
    std::fprintf(f, "meta");
    for (int i = 0; i < R_LEN; ++i) std::fprintf(f, ",in");
    for (int b = 0; b < BANKS; ++b) for (int t = 0; t < TAPS; ++t) std::fprintf(f, ",in");
    for (int b = 0; b < BANKS; ++b) for (int t = 0; t < TAPS; ++t) std::fprintf(f, ",in");
    for (int i = 0; i < R_LEN; ++i) std::fprintf(f, ",out");
    std::fprintf(f, "\n");

    // Buffers for DUT
    vec_type r[R_LEN];
    vec_type H[BANKS][TAPS];
    vec_type F[BANKS][TAPS];
    vec_type y[R_LEN];

    // Integer mirror arrays for printing inputs as decimal integers
    int r_int[R_LEN];
    int H_int[BANKS][TAPS];
    int F_int[BANKS][TAPS];

    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        // Generate r: a moving impulse (only one 1 at position cycle % R_LEN), others 0
        for (int i = 0; i < R_LEN; ++i) {
            r_int[i] = (i == (cycle % R_LEN)) ? 1 : 0;
            r[i] = (vec_type)r_int[i];
        }

        // Generate H_int and F_int deterministically in four groups to increase coverage
        if (cycle < 8) {
            // baseline small positive coefficients
            for (int b = 0; b < BANKS; ++b)
                for (int t = 0; t < TAPS; ++t) {
                    H_int[b][t] = (b + 1) * (t + 1); // 1..12
                    F_int[b][t] = H_int[b][t];
                    H[b][t] = (vec_type)H_int[b][t];
                    F[b][t] = (vec_type)F_int[b][t];
                }
        } else if (cycle < 16) {
            // alternating sign per bank
            for (int b = 0; b < BANKS; ++b)
                for (int t = 0; t < TAPS; ++t) {
                    int val = (t + 1);
                    H_int[b][t] = ((b % 2) == 0) ? val : -val;
                    F_int[b][t] = ((b % 2) == 0) ? -val : val;
                    H[b][t] = (vec_type)H_int[b][t];
                    F[b][t] = (vec_type)F_int[b][t];
                }
        } else if (cycle < 24) {
            // sparse: only one bank active (cycle % BANKS), only first tap = 1
            int active = cycle % BANKS;
            for (int b = 0; b < BANKS; ++b)
                for (int t = 0; t < TAPS; ++t) {
                    if (b == active && t == 0) {
                        H_int[b][t] = 1;
                        F_int[b][t] = 1;
                    } else {
                        H_int[b][t] = 0;
                        F_int[b][t] = 0;
                    }
                    H[b][t] = (vec_type)H_int[b][t];
                    F[b][t] = (vec_type)F_int[b][t];
                }
        } else {
            // scaled by (cycle%5)-2 to include negatives and zeros
            int scale = (cycle % 5) - 2; // -2,-1,0,1,2
            for (int b = 0; b < BANKS; ++b)
                for (int t = 0; t < TAPS; ++t) {
                    H_int[b][t] = scale * (b + 1) * (t + 1);
                    F_int[b][t] = scale * ((b + 1) + (t + 1));
                    H[b][t] = (vec_type)H_int[b][t];
                    F[b][t] = (vec_type)F_int[b][t];
                }
        }

        // Call DUT
        filterbank(r, y, H, F);

        // Write CSV line: cycle, inputs (decimal ints), outputs (hex uppercase, no 0x)
        std::fprintf(f, "%d", cycle);
        // r inputs
        for (int i = 0; i < R_LEN; ++i) {
            std::fprintf(f, ",%d", r_int[i]);
        }
        // H inputs
        for (int b = 0; b < BANKS; ++b) {
            for (int t = 0; t < TAPS; ++t) {
                std::fprintf(f, ",%d", H_int[b][t]);
            }
        }
        // F inputs
        for (int b = 0; b < BANKS; ++b) {
            for (int t = 0; t < TAPS; ++t) {
                std::fprintf(f, ",%d", F_int[b][t]);
            }
        }
        // y outputs as hex uppercase without 0x
        for (int i = 0; i < R_LEN; ++i) {
            // reinterpret float bits to uint32_t safely using memcpy
            uint32_t bits = 0;
            static_assert(sizeof(bits) == sizeof(y[i]), "size mismatch");
            std::memcpy(&bits, &y[i], sizeof(bits));
            // print as uppercase hex without 0x, no fixed width
            // Special-case zero to print "0" (snprintf would do that anyway)
            if (bits == 0) {
                std::fprintf(f, ",0");
            } else {
                // Use %X to get uppercase hex
                std::fprintf(f, ",%X", bits);
            }
        }
        std::fprintf(f, "\n");
    }

    // Explicitly close file
    std::fclose(f);
    return 0;
}

