// hls.cpp
// HLS implementation of filterbank. This implementation follows the
// reference C testbench algorithm (compute Vect_H, downsample -> Vect_Dn,
// upsample -> Vect_Up, convolve with F -> Vect_F, accumulate into y).
// Bounds checks are added to avoid undefined behavior while preserving
// the intended behavior for the provided testbench parameters.
#include <stddef.h>
#include <string.h>

typedef float vec_type;

const int R_LEN = 8;
const int BANKS = 4;
const int TAPS  = 3;

extern "C" {
void filterbank(vec_type r[R_LEN], vec_type y[R_LEN], vec_type H[BANKS][TAPS], vec_type F[BANKS][TAPS]) {
#pragma HLS INTERFACE m_axi port=r offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=y offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=H offset=slave bundle=gmem2
#pragma HLS INTERFACE m_axi port=F offset=slave bundle=gmem3
#pragma HLS INTERFACE s_axilite port=r bundle=control
#pragma HLS INTERFACE s_axilite port=y bundle=control
#pragma HLS INTERFACE s_axilite port=H bundle=control
#pragma HLS INTERFACE s_axilite port=F bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int i, j, k;

    // Initialize output
    for (i = 0; i < R_LEN; i++) {
#pragma HLS unroll factor=2
        y[i] = 0.0f;
    }

    // For each bank do:
    // 1) compute Vect_H = convolve(r, H[i]) (causal FIR with TAPS)
    // 2) downsample: Vect_Dn[j] = Vect_H[j * BANKS]  (guarded by bounds)
    // 3) upsample: Vect_Up[...] assign Vect_Dn at positions j*BANKS, zeros elsewhere
    // 4) compute Vect_F = convolve(Vect_Up, F[i]) (causal FIR with TAPS)
    // 5) accumulate Vect_F into y
    for (i = 0; i < BANKS; i++) {
#pragma HLS pipeline II=1

        // Local buffers sized to R_LEN (Vect_Dn sized to TAPS)
        vec_type Vect_H[R_LEN];
#pragma HLS array_partition variable=Vect_H complete dim=1

        vec_type Vect_Dn[TAPS];
#pragma HLS array_partition variable=Vect_Dn complete dim=1

        vec_type Vect_Up[R_LEN];
#pragma HLS array_partition variable=Vect_Up complete dim=1

        vec_type Vect_F[R_LEN];
#pragma HLS array_partition variable=Vect_F complete dim=1

        // Compute Vect_H = r * H[i] (causal FIR of length TAPS)
        for (j = 0; j < R_LEN; j++) {
#pragma HLS unroll factor=2
            vec_type acc = 0.0f;
            for (k = 0; k < TAPS; k++) {
#pragma HLS unroll
                if (j - k < 0) break;
                acc += H[i][k] * r[j - k];
            }
            Vect_H[j] = acc;
        }

        // Downsample: pick entries spaced by BANKS (guard against out-of-bounds)
        for (j = 0; j < TAPS; j++) {
#pragma HLS unroll
            int idx = j * BANKS;
            if (idx >= 0 && idx < R_LEN) {
                Vect_Dn[j] = Vect_H[idx];
            } else {
                // If index would be out of range, use 0. This is a safe,
                // deterministic behavior (avoids UB) and matches expected
                // intent for testbench sizes.
                Vect_Dn[j] = 0.0f;
            }
        }

        // Upsample: zero-initialize then place Vect_Dn at indices j*BANKS (guarded)
        for (j = 0; j < R_LEN; j++) {
#pragma HLS unroll factor=2
            Vect_Up[j] = 0.0f;
        }
        for (j = 0; j < TAPS; j++) {
#pragma HLS unroll
            int idx = j * BANKS;
            if (idx >= 0 && idx < R_LEN) {
                Vect_Up[idx] = Vect_Dn[j];
            }
        }

        // Compute Vect_F = Vect_Up * F[i] (causal FIR of length TAPS)
        for (j = 0; j < R_LEN; j++) {
#pragma HLS unroll factor=2
            vec_type acc = 0.0f;
            for (k = 0; k < TAPS; k++) {
#pragma HLS unroll
                if (j - k < 0) break;
                acc += F[i][k] * Vect_Up[j - k];
            }
            Vect_F[j] = acc;
        }

        // Accumulate into y
        for (j = 0; j < R_LEN; j++) {
#pragma HLS unroll factor=2
            y[j] += Vect_F[j];
        }
    }
}
} // extern "C"

