// hls.cpp
// HLS top-level implementation for cfd_flux.
// Keep C linkage so the C testbench can link against this symbol.
//
// This file implements the same numerical kernel as the reference C/C++ testbench.
// To ensure bit-identical results between the C reference and HLS top-level,
// the inner numerical operations follow the same sequence and use float arithmetic.
//
// Note: Use C-style headers to be compatible with Vivado HLS's C++98 environment.

#include <math.h>
#include <string.h>
#include <stdlib.h>
#include <stdint.h>

#define GAMMA 1.4f
#define NVAR 5
#define NDIM 3
#define NNB 4
#define SIZE 1024

// These must match the testbench definitions (do not change the testbench).
#define TILE_ROWS 32
#define PARA_FACTOR 16

#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY 4

typedef struct {
    float x;
    float y;
    float z;
} float3;

#ifdef __cplusplus
extern "C" {
#endif

void cfd_flux(float result[SIZE * NVAR],
              float elements_surrounding_elements[SIZE * NNB],
              float normals[SIZE * NNB * NDIM],
              float variables[SIZE * NVAR],
              float fc_momentum_x[SIZE * NDIM],
              float fc_momentum_y[SIZE * NDIM],
              float fc_momentum_z[SIZE * NDIM],
              float fc_density_energy[SIZE * NDIM])
{
#pragma HLS INTERFACE m_axi port=result offset=slave bundle=result1
#pragma HLS INTERFACE m_axi port=elements_surrounding_elements offset=slave bundle=elements_surrounding_elements1
#pragma HLS INTERFACE m_axi port=normals offset=slave bundle=normals1
#pragma HLS INTERFACE m_axi port=variables offset=slave bundle=variables1
#pragma HLS INTERFACE m_axi port=fc_momentum_x offset=slave bundle=fc_momentum_x1
#pragma HLS INTERFACE m_axi port=fc_momentum_y offset=slave bundle=fc_momentum_y1
#pragma HLS INTERFACE m_axi port=fc_momentum_z offset=slave bundle=fc_momentum_z1
#pragma HLS INTERFACE m_axi port=fc_density_energy offset=slave bundle=fc_density_energy1

#pragma HLS INTERFACE s_axilite port=result bundle=control
#pragma HLS INTERFACE s_axilite port=elements_surrounding_elements bundle=control
#pragma HLS INTERFACE s_axilite port=normals bundle=control
#pragma HLS INTERFACE s_axilite port=variables bundle=control
#pragma HLS INTERFACE s_axilite port=fc_momentum_x bundle=control
#pragma HLS INTERFACE s_axilite port=fc_momentum_y bundle=control
#pragma HLS INTERFACE s_axilite port=fc_momentum_z bundle=control
#pragma HLS INTERFACE s_axilite port=fc_density_energy bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local buffers (tile-local and global copies)
    float result_inner[TILE_ROWS * NVAR];
#pragma HLS array_partition variable=result_inner block factor=32 dim=1

    float elements_surrounding_elements_inner[TILE_ROWS * NNB];
#pragma HLS array_partition variable=elements_surrounding_elements_inner cyclic factor=32 dim=1

    float normals_inner[TILE_ROWS * NNB * NDIM];
#pragma HLS array_partition variable=normals_inner cyclic factor=32 dim=1

    // Keep the large arrays as simple local copies
    float variables_inner[SIZE * NVAR];
    float fc_momentum_x_inner[SIZE * NDIM];
    float fc_momentum_y_inner[SIZE * NDIM];
    float fc_momentum_z_inner[SIZE * NDIM];
    float fc_density_energy_inner[SIZE * NDIM];

    // Copy global arrays to local arrays
    for (int i = 0; i < SIZE * NVAR; i++) {
#pragma HLS PIPELINE II=1
        variables_inner[i] = variables[i];
    }
    for (int i = 0; i < SIZE * NDIM; i++) {
#pragma HLS PIPELINE II=1
        fc_momentum_x_inner[i] = fc_momentum_x[i];
        fc_momentum_y_inner[i] = fc_momentum_y[i];
        fc_momentum_z_inner[i] = fc_momentum_z[i];
        fc_density_energy_inner[i] = fc_density_energy[i];
    }

    // Process tiles
    for (int k = 0; k < SIZE / TILE_ROWS; k++) {
#pragma HLS UNROLL factor=2
        // Copy chunk of elements_surrounding_elements and normals into tile-local buffers
        for (int i = 0; i < TILE_ROWS * NNB; i++) {
#pragma HLS PIPELINE II=1
            elements_surrounding_elements_inner[i] = elements_surrounding_elements[k * TILE_ROWS * NNB + i];
        }
        for (int i = 0; i < TILE_ROWS * NNB * NDIM; i++) {
#pragma HLS PIPELINE II=1
            normals_inner[i] = normals[k * TILE_ROWS * NNB * NDIM + i];
        }

        // Local implementation of the original cfd_flux kernel for the tile.
        {
            const float smoothing_coefficient = 0.2f;
            float ff_variable[NVAR] = {1.3999999761581421f, 1.6800000667572021f, 0.0f, 0.0f, 3.5079998970031738f};
#pragma HLS array_partition variable=ff_variable complete dim=1

            float3 ff_fc_momentum_x = {3.0160002708435059f, 0.0f, 0.0f};
            float3 ff_fc_momentum_y = {0.0f, 1.0f, 0.0f};
            float3 ff_fc_momentum_z = {0.0f, 0.0f, 1.0f};
            float3 ff_fc_density_energy = {5.4096002578735352f, 0.0f, 0.0f};

            // Process PARA_FACTOR elements in parallel within the tile
            for (int i = 0; i < TILE_ROWS / PARA_FACTOR; i++) {
#pragma HLS PIPELINE II=1
                for (int ii = 0; ii < PARA_FACTOR; ii++) {
#pragma HLS UNROLL
                    int iii = i * PARA_FACTOR + ii;          // local index in tile [0..TILE_ROWS-1]
                    int idx = k * TILE_ROWS + iii;           // global element index
                    int j, nb;
                    float3 normal;
                    float normal_len;
                    float factor;

                    // Read local/global state for element idx (use same arithmetic as reference)
                    float density_i = variables_inner[idx * NVAR + VAR_DENSITY];
                    float3 momentum_i;
                    momentum_i.x = variables_inner[idx * NVAR + (VAR_MOMENTUM + 0)];
                    momentum_i.y = variables_inner[idx * NVAR + (VAR_MOMENTUM + 1)];
                    momentum_i.z = variables_inner[idx * NVAR + (VAR_MOMENTUM + 2)];
                    float density_energy_i = variables_inner[idx * NVAR + VAR_DENSITY_ENERGY];

                    // compute velocity exactly like reference (no safe-guards)
                    float3 velocity_i;
                    velocity_i.x = momentum_i.x / density_i;
                    velocity_i.y = momentum_i.y / density_i;
                    velocity_i.z = momentum_i.z / density_i;

                    float speed_sqd_i = velocity_i.x * velocity_i.x + velocity_i.y * velocity_i.y + velocity_i.z * velocity_i.z;
                    float speed_i = sqrtf(speed_sqd_i);
                    float pressure_i = (GAMMA - 1.0f) * (density_energy_i - 0.5f * density_i * speed_sqd_i);
                    float speed_of_sound_i = sqrtf(GAMMA * pressure_i / density_i);

                    float3 fc_i_momentum_x, fc_i_momentum_y, fc_i_momentum_z;
                    float3 fc_i_density_energy;

                    fc_i_momentum_x.x = fc_momentum_x_inner[idx * NDIM + 0];
                    fc_i_momentum_x.y = fc_momentum_x_inner[idx * NDIM + 1];
                    fc_i_momentum_x.z = fc_momentum_x_inner[idx * NDIM + 2];

                    fc_i_momentum_y.x = fc_momentum_y_inner[idx * NDIM + 0];
                    fc_i_momentum_y.y = fc_momentum_y_inner[idx * NDIM + 1];
                    fc_i_momentum_y.z = fc_momentum_y_inner[idx * NDIM + 2];

                    fc_i_momentum_z.x = fc_momentum_z_inner[idx * NDIM + 0];
                    fc_i_momentum_z.y = fc_momentum_z_inner[idx * NDIM + 1];
                    fc_i_momentum_z.z = fc_momentum_z_inner[idx * NDIM + 2];

                    fc_i_density_energy.x = fc_density_energy_inner[idx * NDIM + 0];
                    fc_i_density_energy.y = fc_density_energy_inner[idx * NDIM + 1];
                    fc_i_density_energy.z = fc_density_energy_inner[idx * NDIM + 2];

                    float flux_i_density = 0.0f;
                    float3 flux_i_momentum = {0.0f, 0.0f, 0.0f};
                    float flux_i_density_energy = 0.0f;

                    float3 velocity_nb;
                    float density_nb, density_energy_nb;
                    float3 momentum_nb;
                    float3 fc_nb_momentum_x, fc_nb_momentum_y, fc_nb_momentum_z;
                    float3 fc_nb_density_energy;
                    float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

                    for (j = 0; j < NNB; j++) {
#pragma HLS UNROLL
                        // elements_surrounding_elements_inner holds neighbor indices as floats;
                        // cast to int for control flow and indexing
                        nb = (int)elements_surrounding_elements_inner[iii * NNB + j];
                        normal.x = normals_inner[(iii * NNB + j) * NDIM + 0];
                        normal.y = normals_inner[(iii * NNB + j) * NDIM + 1];
                        normal.z = normals_inner[(iii * NNB + j) * NDIM + 2];
                        normal_len = sqrtf(normal.x * normal.x + normal.y * normal.y + normal.z * normal.z);

                        if (nb >= 0) {
                            density_nb = variables_inner[nb * NVAR + VAR_DENSITY];
                            momentum_nb.x = variables_inner[nb * NVAR + (VAR_MOMENTUM + 0)];
                            momentum_nb.y = variables_inner[nb * NVAR + (VAR_MOMENTUM + 1)];
                            momentum_nb.z = variables_inner[nb * NVAR + (VAR_MOMENTUM + 2)];
                            density_energy_nb = variables_inner[nb * NVAR + VAR_DENSITY_ENERGY];

                            // mirror reference arithmetic (no safety-clips)
                            velocity_nb.x = momentum_nb.x / density_nb;
                            velocity_nb.y = momentum_nb.y / density_nb;
                            velocity_nb.z = momentum_nb.z / density_nb;

                            speed_sqd_nb = velocity_nb.x * velocity_nb.x + velocity_nb.y * velocity_nb.y + velocity_nb.z * velocity_nb.z;
                            pressure_nb = (GAMMA - 1.0f) * (density_energy_nb - 0.5f * density_nb * speed_sqd_nb);
                            speed_of_sound_nb = sqrtf(GAMMA * pressure_nb / density_nb);

                            fc_nb_momentum_x.x = fc_momentum_x_inner[nb * NDIM + 0];
                            fc_nb_momentum_x.y = fc_momentum_x_inner[nb * NDIM + 1];
                            fc_nb_momentum_x.z = fc_momentum_x_inner[nb * NDIM + 2];

                            fc_nb_momentum_y.x = fc_momentum_y_inner[nb * NDIM + 0];
                            fc_nb_momentum_y.y = fc_momentum_y_inner[nb * NDIM + 1];
                            fc_nb_momentum_y.z = fc_momentum_y_inner[nb * NDIM + 2];

                            fc_nb_momentum_z.x = fc_momentum_z_inner[nb * NDIM + 0];
                            fc_nb_momentum_z.y = fc_momentum_z_inner[nb * NDIM + 1];
                            fc_nb_momentum_z.z = fc_momentum_z_inner[nb * NDIM + 2];

                            fc_nb_density_energy.x = fc_density_energy_inner[nb * NDIM + 0];
                            fc_nb_density_energy.y = fc_density_energy_inner[nb * NDIM + 1];
                            fc_nb_density_energy.z = fc_density_energy_inner[nb * NDIM + 2];

                            factor = -normal_len * smoothing_coefficient * 0.5f * (speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                            flux_i_density += factor * (density_i - density_nb);
                            flux_i_density_energy += factor * (density_energy_i - density_energy_nb);
                            flux_i_momentum.x += factor * (momentum_i.x - momentum_nb.x);
                            flux_i_momentum.y += factor * (momentum_i.y - momentum_nb.y);
                            flux_i_momentum.z += factor * (momentum_i.z - momentum_nb.z);

                            factor = 0.5f * normal.x;
                            flux_i_density += factor * (momentum_nb.x + momentum_i.x);
                            flux_i_density_energy += factor * (fc_nb_density_energy.x + fc_i_density_energy.x);
                            flux_i_momentum.x += factor * (fc_nb_momentum_x.x + fc_i_momentum_x.x);
                            flux_i_momentum.y += factor * (fc_nb_momentum_y.x + fc_i_momentum_y.x);
                            flux_i_momentum.z += factor * (fc_nb_momentum_z.x + fc_i_momentum_z.x);

                            factor = 0.5f * normal.y;
                            flux_i_density += factor * (momentum_nb.y + momentum_i.y);
                            flux_i_density_energy += factor * (fc_nb_density_energy.y + fc_i_density_energy.y);
                            flux_i_momentum.x += factor * (fc_nb_momentum_x.y + fc_i_momentum_x.y);
                            flux_i_momentum.y += factor * (fc_nb_momentum_y.y + fc_i_momentum_y.y);
                            flux_i_momentum.z += factor * (fc_nb_momentum_z.y + fc_i_momentum_z.y);

                            factor = 0.5f * normal.z;
                            flux_i_density += factor * (momentum_nb.z + momentum_i.z);
                            flux_i_density_energy += factor * (fc_nb_density_energy.z + fc_i_density_energy.z);
                            flux_i_momentum.x += factor * (fc_nb_momentum_x.z + fc_i_momentum_x.z);
                            flux_i_momentum.y += factor * (fc_nb_momentum_y.z + fc_i_momentum_y.z);
                            flux_i_momentum.z += factor * (fc_nb_momentum_z.z + fc_i_momentum_z.z);
                        } else if (nb == -1) {
                            // Solid wall boundary
                            flux_i_momentum.x += normal.x * pressure_i;
                            flux_i_momentum.y += normal.y * pressure_i;
                            flux_i_momentum.z += normal.z * pressure_i;
                        } else if (nb == -2) {
                            // Far-field boundary (use ff_variable / ff_fc_* values)
                            factor = 0.5f * normal.x;
                            flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 0] + momentum_i.x);
                            flux_i_density_energy += factor * (ff_fc_density_energy.x + fc_i_density_energy.x);
                            flux_i_momentum.x += factor * (ff_fc_momentum_x.x + fc_i_momentum_x.x);
                            flux_i_momentum.y += factor * (ff_fc_momentum_y.x + fc_i_momentum_y.x);
                            flux_i_momentum.z += factor * (ff_fc_momentum_z.x + fc_i_momentum_z.x);

                            factor = 0.5f * normal.y;
                            flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 1] + momentum_i.y);
                            flux_i_density_energy += factor * (ff_fc_density_energy.y + fc_i_density_energy.y);
                            flux_i_momentum.x += factor * (ff_fc_momentum_x.y + fc_i_momentum_x.y);
                            flux_i_momentum.y += factor * (ff_fc_momentum_y.y + fc_i_momentum_y.y);
                            flux_i_momentum.z += factor * (ff_fc_momentum_z.y + fc_i_momentum_z.y);

                            factor = 0.5f * normal.z;
                            flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 2] + momentum_i.z);
                            flux_i_density_energy += factor * (ff_fc_density_energy.z + fc_i_density_energy.z);
                            flux_i_momentum.x += factor * (ff_fc_momentum_x.z + fc_i_momentum_x.z);
                            flux_i_momentum.y += factor * (ff_fc_momentum_y.z + fc_i_momentum_y.z);
                            flux_i_momentum.z += factor * (ff_fc_momentum_z.z + fc_i_momentum_z.z);
                        }
                    }

                    // Store computed flux into the tile-local result buffer (indexed by local iii)
                    result_inner[iii * NVAR + VAR_DENSITY] = flux_i_density;
                    result_inner[iii * NVAR + (VAR_MOMENTUM + 0)] = flux_i_momentum.x;
                    result_inner[iii * NVAR + (VAR_MOMENTUM + 1)] = flux_i_momentum.y;
                    result_inner[iii * NVAR + (VAR_MOMENTUM + 2)] = flux_i_momentum.z;
                    result_inner[iii * NVAR + VAR_DENSITY_ENERGY] = flux_i_density_energy;
                }
            }
        }

        // Copy back tile results to global result array
        for (int i = 0; i < TILE_ROWS * NVAR; i++) {
#pragma HLS PIPELINE II=1
            result[k * TILE_ROWS * NVAR + i] = result_inner[i];
        }
    }
}

#ifdef __cplusplus
} // extern "C"
#endif

hls_tb:
// tb_hls_cosim.cpp
// Testbench for HLS top-level cfd_flux that reproduces the same test patterns
// and CSV formatting as the C reference testbench (c_testbench.cpp).
//
// This testbench uses deterministic patterns and writes hls_output.csv with
// the same header, role row, cycle rows and final row as the reference,
// so the HLS output CSV can be compared bitwise to the C reference CSV.
//
// Use C-style headers to be compatible with Vivado HLS's C++98 environment.

#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <stdint.h>

#define GRID_ROWS (1024)
#define SIZE GRID_ROWS
#define TILE_ROWS 32
#define PARA_FACTOR 16
#define TOP 0
#define BOTTOM (GRID_ROWS / TILE_ROWS - 1)
#define GAMMA 1.4
#define NDIM 3
#define NNB 4
#define RK 3
#define ff_mach 1.2
#define deg_angle_of_attack 0.0f
#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)
#define TYPE float

struct float3 { float x, y, z; };

// Declare top-level DUT with exact signature as in HLS top-level
#ifdef __cplusplus
extern "C" {
#endif
void cfd_flux(float result[SIZE * NVAR], float elements_surrounding_elements [SIZE * NNB], float normals [SIZE * NNB * NDIM],
              float variables [SIZE * NVAR], float fc_momentum_x [SIZE * NDIM], float fc_momentum_y [SIZE * NDIM],
              float fc_momentum_z [SIZE * NDIM], float fc_density_energy [SIZE * NDIM]);
#ifdef __cplusplus
}
#endif

int main()
{
    // Allocate arrays once and reuse across cycles
    float* result = (float*)calloc(SIZE * NVAR, sizeof(float));
    float* elements_surrounding_elements = (float*)calloc(SIZE * NNB, sizeof(float));
    float* normals = (float*)calloc(SIZE * NNB * NDIM, sizeof(float));
    float* variables = (float*)calloc(SIZE * NVAR, sizeof(float));
    float* fc_momentum_x = (float*)calloc(SIZE * NDIM, sizeof(float));
    float* fc_momentum_y = (float*)calloc(SIZE * NDIM, sizeof(float));
    float* fc_momentum_z = (float*)calloc(SIZE * NDIM, sizeof(float));
    float* fc_density_energy = (float*)calloc(SIZE * NDIM, sizeof(float));

    if(!result || !elements_surrounding_elements || !normals || !variables || !fc_momentum_x || !fc_momentum_y || !fc_momentum_z || !fc_density_energy) {
        printf("Memory allocation failed\n");
        return 1;
    }

    // Prepare HLS/RTL output CSV
    FILE* f = fopen("hls_output.csv", "w");
    if(!f) {
        printf("Failed to open hls_output.csv for writing\n");
        // free memory before return
        free(result);
        free(elements_surrounding_elements);
        free(normals);
        free(variables);
        free(fc_momentum_x);
        free(fc_momentum_y);
        free(fc_momentum_z);
        free(fc_density_energy);
        return 1;
    }

    // CSV header: cycle, then all DUT input signal names (as function parameters except result), then sampled output signal names
    // Column names must match actual parameter names in cfd_flux
    fprintf(f, "cycle,elements_surrounding_elements,normals,variables,fc_momentum_x,fc_momentum_y,fc_momentum_z,fc_density_energy,result\n");
    // Roles row: cycle is meta, inputs are in, output is out
    fprintf(f, "meta,in,in,in,in,in,in,in,out\n");

    // Number of cycles: match the C reference testbench (40)
    const int CYCLES = 40;

    // Deterministic test patterns: exactly match the reference testbench's patterns
    for(int cycle = 0; cycle < CYCLES; ++cycle)
    {
        int pattern = cycle % 4;

        // Initialize arrays deterministically based on cycle (no randomness)
        for(int i=0;i<SIZE;i++){
            // vary values with (i + cycle) to get diversity
            variables[i*NVAR + VAR_DENSITY] = 1.4f + 0.0001f * (float)((i + cycle) % 10);
            variables[i*NVAR + (VAR_MOMENTUM+0)] = 0.1f * (float)((i + cycle) % 5);
            variables[i*NVAR + (VAR_MOMENTUM+1)] = 0.2f * (float)((i + cycle) % 3);
            variables[i*NVAR + (VAR_MOMENTUM+2)] = 0.3f * (float)((i + cycle) % 7);
            variables[i*NVAR + VAR_DENSITY_ENERGY] = 2.5f + 0.001f * (float)((i + cycle) % 8);

            // base face-center flux components; include cycle-dependent small perturbation
            float base_fx = 0.5f + 0.01f * (float)((cycle % 3));
            float base_fy = 0.5f + 0.01f * (float)(((cycle+1) % 3));
            float base_fz = 0.5f + 0.01f * (float)(((cycle+2) % 3));
            fc_momentum_x[i*NDIM + 0] = base_fx;
            fc_momentum_x[i*NDIM + 1] = 0.0f;
            fc_momentum_x[i*NDIM + 2] = 0.0f;

            fc_momentum_y[i*NDIM + 0] = 0.0f;
            fc_momentum_y[i*NDIM + 1] = base_fy;
            fc_momentum_y[i*NDIM + 2] = 0.0f;

            fc_momentum_z[i*NDIM + 0] = 0.0f;
            fc_momentum_z[i*NDIM + 1] = 0.0f;
            fc_momentum_z[i*NDIM + 2] = base_fz;

            float base_fe = 1.2f + 0.001f * (float)(cycle % 5);
            fc_density_energy[i*NDIM + 0] = base_fe;
            fc_density_energy[i*NDIM + 1] = base_fe;
            fc_density_energy[i*NDIM + 2] = base_fe;

            for(int j=0;j<NNB;j++){
                if(pattern == 0) {
                    // All interior neighbors
                    int nb_idx = (i + 1 + j) % SIZE;
                    elements_surrounding_elements[i*NNB + j] = (float)nb_idx;
                } else if(pattern == 1) {
                    // All boundaries
                    elements_surrounding_elements[i*NNB + j] = -1.0f;
                } else if(pattern == 2) {
                    // All far-field
                    elements_surrounding_elements[i*NNB + j] = -2.0f;
                } else {
                    // Mixed pattern to exercise all branches:
                    if((j % 3) == 0) {
                        int nb_idx = (i + 1) % SIZE;
                        elements_surrounding_elements[i*NNB + j] = (float)nb_idx;
                    } else if((j % 3) == 1) {
                        elements_surrounding_elements[i*NNB + j] = -1.0f; // boundary
                    } else {
                        elements_surrounding_elements[i*NNB + j] = -2.0f; // far-field
                    }
                }

                // Normals: provide varied normals (non-axis aligned sometimes)
                if(((i + cycle + j) % 7) == 0) {
                    normals[(i*NNB + j)*NDIM + 0] = 0.3f * (float)(((i + cycle + j) % 5) + 1);
                    normals[(i*NNB + j)*NDIM + 1] = 0.2f * (float)(((i + cycle + j) % 4) + 1);
                    normals[(i*NNB + j)*NDIM + 2] = 0.4f * (float)(((i + cycle + j) % 3) + 1);
                } else if(((i + cycle + j) % 5) == 0) {
                    normals[(i*NNB + j)*NDIM + 0] = 0.1f * (float)(((i + cycle + j) % 3));
                    normals[(i*NNB + j)*NDIM + 1] = 0.2f * (float)(((i + cycle + j) % 4));
                    normals[(i*NNB + j)*NDIM + 2] = 0.9f;
                } else {
                    normals[(i*NNB + j)*NDIM + 0] = 0.0f;
                    normals[(i*NNB + j)*NDIM + 1] = 0.0f;
                    normals[(i*NNB + j)*NDIM + 2] = 1.0f;
                }
            }
        }

        // Call DUT
        cfd_flux(result, elements_surrounding_elements, normals, variables, fc_momentum_x, fc_momentum_y, fc_momentum_z, fc_density_energy);

        // Sample inputs to write into CSV:
        // Per spec, input columns must be decimal integers. We'll cast representative first elements to int.
        int csv_elements_surrounding_elements = (int)elements_surrounding_elements[0];
        int csv_normals = (int)normals[0];
        int csv_variables = (int)variables[0];
        int csv_fc_momentum_x = (int)fc_momentum_x[0];
        int csv_fc_momentum_y = (int)fc_momentum_y[0];
        int csv_fc_momentum_z = (int)fc_momentum_z[0];
        int csv_fc_density_energy = (int)fc_density_energy[0];

        // Sample output: read result[0] (float) and output hex uppercase without 0x and without fixed width
        uint32_t result_bits = 0;
        memcpy(&result_bits, &result[0], sizeof(uint32_t));

        // Write a CSV row: cycle (decimal), input integers (decimal), output hex uppercase (no 0x)
        fprintf(f, "%d,%d,%d,%d,%d,%d,%d,%d,%X\n",
                cycle,
                csv_elements_surrounding_elements,
                csv_normals,
                csv_variables,
                csv_fc_momentum_x,
                csv_fc_momentum_y,
                csv_fc_momentum_z,
                csv_fc_density_energy,
                (unsigned)result_bits);
    }

    // Final targeted pass to ensure all conditional branches and code paths are exercised at least once.
    {
        for(int i=0;i<8 && i<SIZE;i++){
            // keep variables simple but different
            variables[i*NVAR + VAR_DENSITY] = 1.1f + 0.01f * (float)i;
            variables[i*NVAR + (VAR_MOMENTUM+0)] = 0.5f + 0.02f * (float)i;
            variables[i*NVAR + (VAR_MOMENTUM+1)] = 0.6f + 0.015f * (float)i;
            variables[i*NVAR + (VAR_MOMENTUM+2)] = 0.7f + 0.01f * (float)i;
            variables[i*NVAR + VAR_DENSITY_ENERGY] = 3.0f + 0.02f * (float)i;

            fc_momentum_x[i*NDIM + 0] = 0.55f + 0.01f * (float)i;
            fc_momentum_x[i*NDIM + 1] = 0.12f * (float)i;
            fc_momentum_x[i*NDIM + 2] = 0.03f * (float)i;

            fc_momentum_y[i*NDIM + 0] = 0.07f * (float)i;
            fc_momentum_y[i*NDIM + 1] = 0.60f + 0.01f * (float)i;
            fc_momentum_y[i*NDIM + 2] = 0.02f * (float)i;

            fc_momentum_z[i*NDIM + 0] = 0.01f * (float)i;
            fc_momentum_z[i*NDIM + 1] = 0.02f * (float)i;
            fc_momentum_z[i*NDIM + 2] = 0.65f + 0.01f * (float)i;

            fc_density_energy[i*NDIM + 0] = 1.44f + 0.01f * (float)i;
            fc_density_energy[i*NDIM + 1] = 1.54f + 0.01f * (float)i;
            fc_density_energy[i*NDIM + 2] = 1.64f + 0.01f * (float)i;

            // Explicitly assign neighbors to cover all branches for these elements
            // j = 0 -> interior neighbor (nb >= 0)
            elements_surrounding_elements[i*NNB + 0] = (float)((i + 2) % SIZE);
            normals[(i*NNB + 0)*NDIM + 0] = 0.9f; // trigger x component blocks
            normals[(i*NNB + 0)*NDIM + 1] = 0.1f;
            normals[(i*NNB + 0)*NDIM + 2] = 0.2f;

            // j = 1 -> boundary (-1)
            elements_surrounding_elements[i*NNB + 1] = -1.0f;
            normals[(i*NNB + 1)*NDIM + 0] = 0.2f;
            normals[(i*NNB + 1)*NDIM + 1] = 0.3f;
            normals[(i*NNB + 1)*NDIM + 2] = 0.4f;

            // j = 2 -> far-field (-2)
            elements_surrounding_elements[i*NNB + 2] = -2.0f;
            normals[(i*NNB + 2)*NDIM + 0] = 0.0f;
            normals[(i*NNB + 2)*NDIM + 1] = 0.8f; // trigger y component blocks
            normals[(i*NNB + 2)*NDIM + 2] = 0.6f;

            // j = 3 -> interior again but different neighbor
            elements_surrounding_elements[i*NNB + 3] = (float)((i + 5) % SIZE);
            normals[(i*NNB + 3)*NDIM + 0] = 0.12f;
            normals[(i*NNB + 3)*NDIM + 1] = 0.0f;
            normals[(i*NNB + 3)*NDIM + 2] = 1.0f;
        }

        // Call DUT for the final targeted pass
        cfd_flux(result, elements_surrounding_elements, normals, variables, fc_momentum_x, fc_momentum_y, fc_momentum_z, fc_density_energy);

        // Sample and write one extra CSV row labeled "final" with same formatting
        int csv_elements_surrounding_elements = (int)elements_surrounding_elements[0];
        int csv_normals = (int)normals[0];
        int csv_variables = (int)variables[0];
        int csv_fc_momentum_x = (int)fc_momentum_x[0];
        int csv_fc_momentum_y = (int)fc_momentum_y[0];
        int csv_fc_momentum_z = (int)fc_momentum_z[0];
        int csv_fc_density_energy = (int)fc_density_energy[0];

        uint32_t result_bits = 0;
        memcpy(&result_bits, &result[0], sizeof(uint32_t));

        fprintf(f, "final,%d,%d,%d,%d,%d,%d,%d,%X\n",
                csv_elements_surrounding_elements,
                csv_normals,
                csv_variables,
                csv_fc_momentum_x,
                csv_fc_momentum_y,
                csv_fc_momentum_z,
                csv_fc_density_energy,
                (unsigned)result_bits);
    }

    // Explicitly close output file
    fclose(f);

    // Free memory
    free(result);
    free(elements_surrounding_elements);
    free(normals);
    free(variables);
    free(fc_momentum_x);
    free(fc_momentum_y);
    free(fc_momentum_z);
    free(fc_density_energy);

    return 0;
}

