       Column names correspond to actual testbench variable names. */
    std::fprintf(f, "cycle,rst,en,out_0_0,out_0_1,out_1_0,out_1_1\n");
    /* Role row: meta/in/out */
    std::fprintf(f, "meta,in,in,out,out,out,out\n");

    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        /* Reset/enable convention: first 2 cycles reset active, en=0; afterwards reset released, en=1 */
        if (cycle < 2) {
            rst = 1;
            en = 0;
        } else {
            rst = 0;
            en = 1;
