           We ensure diagonal dominance by adding SIZE to diagonal to avoid division by zero in lud. */
        for (int i = 0; i < SIZE; ++i) {
            for (int j = i; j < SIZE; ++j) {
                float val;
                if (rst) {
                    /* During reset, use a simple identity-scaled pattern */
                    val = (i == j) ? (float)(SIZE + cycle) : (float)((i + j + 1 + cycle) % (SIZE) + 1);
                } else {
