// hls.cpp
// Simple LU decomposition implementation for Vivado HLS.
// This implementation mirrors the reference C testbench algorithm exactly
// (no blocking/tiled optimizations) so that HLS co-simulation produces
// identical results to the C testbench.
//
// Keep the top-level function name "lud" and the HLS interface pragmas
// so Vivado HLS recognizes the DUT.

#ifndef GRID_ROWS
#define GRID_ROWS 64
#endif

#ifndef GRID_COLS
#define GRID_COLS GRID_ROWS
#endif

#define matrix_dim GRID_ROWS
#define GRID_ROWS_CONST GRID_ROWS
#define GRID_COLS_CONST GRID_COLS

extern "C" {

/*
 * Top-level HLS function with C linkage.
 * Use a pointer parameter for the matrix so it works robustly across toolchains.
 * The interface pragmas expose 'result' as an AXI master port and control via AXI-Lite.
 */
void lud(float *result) {
#pragma HLS INTERFACE m_axi port=result offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=result bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int i, j, k;
    float sum;

    /* Unblocked LU decomposition (Doolittle-like) matching the C reference algorithm. */
    for (i = 0; i < matrix_dim; i++) {
        for (j = i; j < matrix_dim; j++) {
            sum = result[i * matrix_dim + j];
            for (k = 0; k < i; k++) {
                sum -= result[i * matrix_dim + k] * result[k * matrix_dim + j];
            }
            result[i * matrix_dim + j] = sum;
        }
        for (j = i + 1; j < matrix_dim; j++) {
            sum = result[j * matrix_dim + i];
            for (k = 0; k < i; k++) {
                sum -= result[j * matrix_dim + k] * result[k * matrix_dim + i];
            }
            /* Divide by the pivot (diagonal element). Testbench ensures diagonal dominance. */
            result[j * matrix_dim + i] = sum / result[i * matrix_dim + i];
        }
    }
}

} // extern "C"

