// hls.cpp
// Simplified and HLS-friendly implementation of the knn top function.
// This implementation matches the testbench signature exactly and computes
// squared Euclidean distances between the input query and each point in the search space.
//
// Notes:
// - Use plain C headers to be compatible with Vivado HLS 2018.3 (C++98).
// - Keep extern "C" linkage for the top-level function so the test-bench can link correctly.
// - The implementation is straightforward (no tiling or custom INTERFACE_WIDTH) to ensure
//   correct C simulation in Vivado HLS C-simulator.

#include <stdint.h>
#include <math.h>

#define NUM_FEATURE 3
#define NUM_PT_IN_SEARCHSPACE 4

extern "C" {

void knn(
    float inputQuery[NUM_FEATURE],
    float searchSpace[NUM_PT_IN_SEARCHSPACE * NUM_FEATURE],
    float distance[NUM_PT_IN_SEARCHSPACE]
) {
    // HLS interface pragmas (kept minimal and safe for simulation)
    #pragma HLS INTERFACE s_axilite port=inputQuery bundle=control
    #pragma HLS INTERFACE s_axilite port=searchSpace bundle=control
    #pragma HLS INTERFACE s_axilite port=distance bundle=control
    #pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local copy of input query for potential performance in HLS
    float local_query[NUM_FEATURE];
    #pragma HLS ARRAY_PARTITION variable=local_query complete dim=1

    // Load input query to local storage
    for (int k = 0; k < NUM_FEATURE; ++k) {
        #pragma HLS UNROLL
        local_query[k] = inputQuery[k];
    }

    // For each point in the search space, compute squared Euclidean distance
    DISTANCE_LOOP: for (int i = 0; i < NUM_PT_IN_SEARCHSPACE; ++i) {
        #pragma HLS PIPELINE II=1
        float sum = 0.0f;
        POINT_FEATURE_LOOP: for (int k = 0; k < NUM_FEATURE; ++k) {
            #pragma HLS UNROLL
            float val = searchSpace[i * NUM_FEATURE + k];
            float diff = val - local_query[k];
            sum += diff * diff;
        }
        distance[i] = sum;
    }
}

} // extern "C"

