#define WT_WIDTH 3
#define OP_LENGTH 3
#define OP_WIDTH 3

#define PE_LENGTH 3
#define PE_BREADTH 3
#define SUM_BUFFER_SIZE 3
#define BUFFER_SIZE 3

#define active_cycles (PE_LENGTH + PE_BREADTH + (OP_WIDTH * 3))

typedef struct {
    int local_cycle_count;
    int psum_count;
    int psum_buffer_internal;
} PE;

void reset();
void eyeriss_init(int DRAM_ip_data[IF_LENGTH][IF_WIDTH],
                  int DRAM_Wt_data[WT_LENGTH][WT_WIDTH],
                  int DRAM_op_data[OP_LENGTH][OP_WIDTH]);
bool eyeriss_step();

// --- DUT internal/static state (kept global for step-wise operation) ---
