static int sim_cycle; // current simulation cycle within an eyeriss run

// Instrumentation variables (these will be recorded to CSV; declared as globals so names match CSV columns)
int ip0 = 0, ip1 = 0, ip2 = 0;
int wt0 = 0, wt1 = 0, wt2 = 0;

int psum_out0 = 0, psum_out1 = 0, psum_out2 = 0;

// Snapshot of DRAM_op_data for CSV (declared as globals so column names match)
int DRAM_op_0_0 = 0, DRAM_op_0_1 = 0, DRAM_op_0_2 = 0;
int DRAM_op_1_0 = 0, DRAM_op_1_1 = 0, DRAM_op_1_2 = 0;
int DRAM_op_2_0 = 0, DRAM_op_2_1 = 0, DRAM_op_2_2 = 0;

void reset() {
    std::memset(pes, 0, sizeof(pes));
    global_cycles = 0;
    count_test    = 0;
    std::memset(PE_IFM_Buffer, 0, sizeof(PE_IFM_Buffer));
    std::memset(PE_Wt_Buffer, 0, sizeof(PE_Wt_Buffer));
}

// Modified to instrument input sampling into ip0..ip2 and wt0..wt2
void read_data_DRAM(int DRAM_ip_data[IF_LENGTH][IF_WIDTH],
                    int DRAM_Wt_data[WT_LENGTH][WT_WIDTH],
                    int horiz_in[PE_BREADTH],
                    int diag_in[PE_BREADTH][PE_LENGTH])
{
    global_cycles++;

    for (int i = 0; i < PE_LENGTH; i++) {
        int wt_val = DRAM_Wt_data[i][ (global_cycles-1) % WT_WIDTH ];
        int ip_val = DRAM_ip_data[i][ (global_cycles-1) % IF_WIDTH ];
        horiz_in[i] = wt_val;
        diag_in[i][0] = ip_val;

        // instrument into global scalars for CSV
        if (i==0) { wt0 = wt_val; ip0 = ip_val; }
        else if (i==1) { wt1 = wt_val; ip1 = ip_val; }
        else if (i==2) { wt2 = wt_val; ip2 = ip_val; }
    }
}

void process_PE(int i, int j,
                int horiz_in, int *horiz_out,
                int diag_in,  int *diag_out,
                int *psum_out)
{
    PE *pe = &pes[i][j];
    pe->local_cycle_count++;

    if (pe->local_cycle_count <= BUFFER_SIZE) {
        PE_IFM_Buffer[i*PE_BREADTH+j][pe->local_cycle_count-1] = diag_in;
        PE_Wt_Buffer[i*PE_BREADTH+j][pe->local_cycle_count-1]  = horiz_in;
    }

    if (pe->local_cycle_count > 1) {
        int idx = pe->psum_count;
        pe->psum_buffer_internal += 
            PE_IFM_Buffer[i*PE_BREADTH+j][idx] *
            PE_Wt_Buffer[i*PE_BREADTH+j][idx];
        pe->psum_count++;
    }

    if (pe->psum_count == BUFFER_SIZE) {
        *psum_out = pe->psum_buffer_internal;
        pe->psum_buffer_internal = 0;
        pe->psum_count = 0;
    } else {
        *psum_out = 0;
    }

    *horiz_out = (pe->local_cycle_count > 1) ? 
                 PE_Wt_Buffer[i*PE_BREADTH+j][pe->local_cycle_count-2] : 0;
    *diag_out  = (pe->local_cycle_count > 1) ? 
                 PE_IFM_Buffer[i*PE_BREADTH+j][pe->local_cycle_count-2] : 0;
}

void write_data_DRAM(int DRAM_op_data[OP_LENGTH][OP_WIDTH],
                     int psum0, int psum1, int psum2)
{
    if (psum0) {
        if (count_test < OP_WIDTH) DRAM_op_data[0][count_test] = psum0;
    }
    if (psum1) {
        if (count_test < OP_WIDTH) DRAM_op_data[1][count_test] = psum1;
    }
    if (psum2) {
        if (count_test < OP_WIDTH) DRAM_op_data[2][count_test] = psum2;
        count_test++;
    }
}

// eyeriss_init replaces the original eyeriss() initialization and prepares for step-wise calls
void eyeriss_init(int DRAM_ip_data[IF_LENGTH][IF_WIDTH],
                  int DRAM_Wt_data[WT_LENGTH][WT_WIDTH],
                  int DRAM_op_data[OP_LENGTH][OP_WIDTH])
{
    reset();

    // set global pointers so read/write functions inside steps can access DRAM arrays
    g_DRAM_ip_ptr = DRAM_ip_data;
    g_DRAM_wt_ptr = DRAM_Wt_data;
    g_DRAM_op_ptr = DRAM_op_data;

    std::memset(horiz_pipe, 0, sizeof(horiz_pipe));
    std::memset(diag_pipe, 0, sizeof(diag_pipe));
    std::memset(psum_pe, 0, sizeof(psum_pe));
    std::memset(DRAM_op_data, 0, sizeof(int)*OP_LENGTH*OP_WIDTH);

    sim_cycle = 0;

    // initialize instrumentation snapshots
    ip0 = ip1 = ip2 = 0;
    wt0 = wt1 = wt2 = 0;
    psum_out0 = psum_out1 = psum_out2 = 0;
    DRAM_op_0_0 = DRAM_op_0_1 = DRAM_op_0_2 =
    DRAM_op_1_0 = DRAM_op_1_1 = DRAM_op_1_2 =
    DRAM_op_2_0 = DRAM_op_2_1 = DRAM_op_2_2 = 0;
}

// eyeriss_step executes one cycle (one iteration of the original loop) and updates instrumentation globals
bool eyeriss_step()
{
    if (sim_cycle >= active_cycles) return false;

    int new_horiz[PE_BREADTH];
    int new_diag[PE_BREADTH][PE_LENGTH];
    std::memset(new_horiz, 0, sizeof(new_horiz));
    std::memset(new_diag, 0, sizeof(new_diag));

    // read data from DRAM (this updates ip0..ip2 and wt0..wt2 as instrumented above)
    read_data_DRAM(g_DRAM_ip_ptr, g_DRAM_wt_ptr, new_horiz, new_diag);

    int next_horiz[PE_LENGTH][PE_BREADTH];
    int next_diag [PE_LENGTH][PE_BREADTH];
    std::memset(next_horiz, 0, sizeof(next_horiz));
    std::memset(next_diag, 0, sizeof(next_diag));
    int local_psum_out0=0, local_psum_out1=0, local_psum_out2=0;

    for (int i = 0; i < PE_LENGTH; i++) {
        for (int j = 0; j < PE_BREADTH; j++) {
            int horiz_in = (j==0 ? new_horiz[i] : horiz_pipe[i][j-1]);
            int diag_in  = (i==0 ? new_diag[i][j] : diag_pipe[i-1][j]);
            int psum_out = 0;

            process_PE(i, j,
                       horiz_in, &next_horiz[i][j],
                       diag_in,  &next_diag [i][j],
                       &psum_out);

            if (j==0) {
                if      (i==0) local_psum_out0 = psum_out;
                else if (i==1) local_psum_out1 = psum_out;
                else if (i==2) local_psum_out2 = psum_out;
            }
        }
    }

    // write back to DRAM op array
    write_data_DRAM(g_DRAM_op_ptr, local_psum_out0, local_psum_out1, local_psum_out2);

    // copy pipes forward
    std::memcpy(horiz_pipe, next_horiz, sizeof(horiz_pipe));
    std::memcpy(diag_pipe,  next_diag,  sizeof(diag_pipe));

    // update instrumentation outputs
    psum_out0 = local_psum_out0;
    psum_out1 = local_psum_out1;
    psum_out2 = local_psum_out2;

    // snapshot DRAM_op into named globals for CSV
    if (g_DRAM_op_ptr) {
        DRAM_op_0_0 = g_DRAM_op_ptr[0][0];
        DRAM_op_0_1 = g_DRAM_op_ptr[0][1];
        DRAM_op_0_2 = g_DRAM_op_ptr[0][2];
        DRAM_op_1_0 = g_DRAM_op_ptr[1][0];
        DRAM_op_1_1 = g_DRAM_op_ptr[1][1];
        DRAM_op_1_2 = g_DRAM_op_ptr[1][2];
        DRAM_op_2_0 = g_DRAM_op_ptr[2][0];
        DRAM_op_2_1 = g_DRAM_op_ptr[2][1];
        DRAM_op_2_2 = g_DRAM_op_ptr[2][2];
    }

    sim_cycle++;
    return true;
}

// End embedded DUT

int main() {
    // Prepare two deterministic testcases to reach CSV rows between 20 and 50 (active_cycles is 15; two runs -> 30 rows)
    int DRAM_ip_data_1[IF_LENGTH][IF_WIDTH];
    int DRAM_Wt_data_1[WT_LENGTH][WT_WIDTH];
    int DRAM_op_data_1[OP_LENGTH][OP_WIDTH];

    int DRAM_ip_data_2[IF_LENGTH][IF_WIDTH];
    int DRAM_Wt_data_2[WT_LENGTH][WT_WIDTH];
    int DRAM_op_data_2[OP_LENGTH][OP_WIDTH];

    // Testcase 1: as in the provided code
    for (int i = 0; i < IF_LENGTH; i++) {
        for (int j = 0; j < IF_WIDTH; j++) {
            DRAM_ip_data_1[i][j] = (i+1) * 10 + (j+1);
        }
    }
    for (int i = 0; i < WT_LENGTH; i++) {
        for (int j = 0; j < WT_WIDTH; j++) {
            DRAM_Wt_data_1[i][j] = (i+1) * 2 + j;
        }
    }
    std::memset(DRAM_op_data_1, 0, sizeof(DRAM_op_data_1));

    // Testcase 2: different deterministic values
    for (int i = 0; i < IF_LENGTH; i++) {
        for (int j = 0; j < IF_WIDTH; j++) {
            DRAM_ip_data_2[i][j] = (i+1) * 20 + (j+2);
        }
    }
    for (int i = 0; i < WT_LENGTH; i++) {
        for (int j = 0; j < WT_WIDTH; j++) {
            DRAM_Wt_data_2[i][j] = (i+1) * 3 + (j%3);
        }
    }
    std::memset(DRAM_op_data_2, 0, sizeof(DRAM_op_data_2));

    // Open CSV file
    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) {
        std::perror("Failed to open c_output.csv");
        return 1;
    }

    // Write header row: cycle, inputs (ip0..ip2, wt0..wt2), outputs (psum_out0..2, DRAM_op_*)
    std::fprintf(f,
        "cycle,ip0,ip1,ip2,wt0,wt1,wt2,psum_out0,psum_out1,psum_out2,DRAM_op_0_0,DRAM_op_0_1,DRAM_op_0_2,DRAM_op_1_0,DRAM_op_1_1,DRAM_op_1_2,DRAM_op_2_0,DRAM_op_2_1,DRAM_op_2_2\n");

    // Write roles row
    std::fprintf(f,
        "meta,in,in,in,in,in,in,out,out,out,out,out,out,out,out,out,out,out,out\n");

    int global_cycle_counter = 0;

    // Run both testcases sequentially, recording each internal cycle
    for (int testcase = 0; testcase < 2; testcase++) {
        if (testcase == 0) {
