            // outputs hex uppercase
            std::fprintf(f, "%X,%X,%X,",
                         (unsigned int)psum_out0,
                         (unsigned int)psum_out1,
                         (unsigned int)psum_out2);
            std::fprintf(f, "%X,%X,%X,%X,%X,%X,%X,%X,%X\n",
                         (unsigned int)DRAM_op_0_0,
                         (unsigned int)DRAM_op_0_1,
                         (unsigned int)DRAM_op_0_2,
                         (unsigned int)DRAM_op_1_0,
                         (unsigned int)DRAM_op_1_1,
                         (unsigned int)DRAM_op_1_2,
                         (unsigned int)DRAM_op_2_0,
                         (unsigned int)DRAM_op_2_1,
                         (unsigned int)DRAM_op_2_2);
            global_cycle_counter++;
        }
    }

    std::fflush(f);
    std::fclose(f);

    // Also print final DRAM_op_data for both testcases to stdout for convenience (not required)
    std::cout << "Test run 1 DRAM_op_data:" << std::endl;
    for (int i = 0; i < OP_LENGTH; i++) {
        for (int j = 0; j < OP_WIDTH; j++) {
            std::cout << DRAM_op_data_1[i][j] << "\t";
        }
        std::cout << std::endl;
    }

    std::cout << "Test run 2 DRAM_op_data:" << std::endl;
    for (int i = 0; i < OP_LENGTH; i++) {
        for (int j = 0; j < OP_WIDTH; j++) {
            std::cout << DRAM_op_data_2[i][j] << "\t";
        }
        std::cout << std::endl;
    }

    return 0;
}

