// hls.cpp
// Vivado HLS top-level implementation (step-wise) that mirrors the C testbench
// behavior so that the HLS cosimulation TB (tb_hls_cosim.cpp) produces identical CSV.
// This implementation executes one cycle per call to eyeriss() and keeps internal
// static state between calls. When the passed DRAM pointers change (new testcase),
// internal state is re-initialized to match the C TB behavior.
//
// Notes:
// - Keep extern "C" instrumentation globals so the testbench can reference them.
// - Uses only C++98-compatible constructs and C headers compatible with Vivado HLS toolchain.

#include <string.h>  // for memset
#include <stdint.h>

#define STRIDE 1
#define PADDING 0
#define IF_LENGTH 5
#define IF_WIDTH 5
#define WT_LENGTH 3
#define WT_WIDTH 3
#define OP_LENGTH 3
#define OP_WIDTH 3

#define PE_LENGTH 3
#define PE_BREADTH 3
#define SUM_BUFFER_SIZE 3
#define BUFFER_SIZE 3

#define active_cycles (PE_LENGTH + PE_BREADTH + (OP_WIDTH * 3))

struct PE {
    int local_cycle_count;
    int psum_count;
    int psum_buffer_internal;
};

// Instrumentation globals expected by the testbench.
// Provide C linkage so the testbench can reference them by name.
// Mark them volatile so the testbench (external reader) always observes updates
// performed by the DUT and the compiler/HLS tool won't optimize accesses away.
extern "C" {
    volatile int ip0 = 0;
    volatile int ip1 = 0;
    volatile int ip2 = 0;

    volatile int wt0 = 0;
    volatile int wt1 = 0;
    volatile int wt2 = 0;

    volatile int psum_out0 = 0;
    volatile int psum_out1 = 0;
    volatile int psum_out2 = 0;

    volatile int DRAM_op_0_0 = 0;
    volatile int DRAM_op_0_1 = 0;
    volatile int DRAM_op_0_2 = 0;
    volatile int DRAM_op_1_0 = 0;
    volatile int DRAM_op_1_1 = 0;
    volatile int DRAM_op_1_2 = 0;
    volatile int DRAM_op_2_0 = 0;
    volatile int DRAM_op_2_1 = 0;
    volatile int DRAM_op_2_2 = 0;
} // extern "C"

// Top-level HLS function. Executed once per simulated cycle by tb_hls_cosim.cpp.
extern "C" void eyeriss(int DRAM_ip_data[IF_LENGTH][IF_WIDTH],
                        int DRAM_Wt_data[WT_LENGTH][WT_WIDTH],
                        int DRAM_op_data[OP_LENGTH][OP_WIDTH]) {

#pragma HLS INTERFACE m_axi depth=64 port=DRAM_ip_data bundle=ifm
#pragma HLS INTERFACE m_axi depth=64 port=DRAM_Wt_data bundle=ifm
#pragma HLS INTERFACE m_axi depth=64 port=DRAM_op_data bundle=ifm

#pragma HLS INTERFACE s_axilite port=DRAM_ip_data bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_Wt_data bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_op_data bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Internal persistent state (kept static across calls to behave step-wise)
    static int PE_IFM_Buffer[PE_LENGTH*PE_BREADTH][BUFFER_SIZE];
    static int PE_Wt_Buffer[PE_LENGTH*PE_BREADTH][BUFFER_SIZE];
    static PE pes[PE_LENGTH][PE_BREADTH];

    static int horiz_pipe[PE_LENGTH][PE_BREADTH];
    static int diag_pipe [PE_LENGTH][PE_BREADTH];

    static int global_cycles = 0;
    static int count_test = 0;
    static int sim_cycle = 0;

    // Keep previous DRAM pointers so we can detect when a new testcase starts
    static int (*g_DRAM_ip_ptr)[IF_WIDTH] = 0;
    static int (*g_DRAM_wt_ptr)[WT_WIDTH] = 0;
    static int (*g_DRAM_op_ptr)[OP_WIDTH] = 0;

    // Initialization/reset helper: if DRAM pointers changed, reset internal state
    if (g_DRAM_ip_ptr != DRAM_ip_data ||
        g_DRAM_wt_ptr != DRAM_Wt_data ||
        g_DRAM_op_ptr != DRAM_op_data) {
        // new testcase: reset all internal state and set pointers
        g_DRAM_ip_ptr = DRAM_ip_data;
        g_DRAM_wt_ptr = DRAM_Wt_data;
        g_DRAM_op_ptr = DRAM_op_data;

        // Reset PEs and buffers
        memset(pes, 0, sizeof(pes));
        memset(PE_IFM_Buffer, 0, sizeof(PE_IFM_Buffer));
        memset(PE_Wt_Buffer, 0, sizeof(PE_Wt_Buffer));
        memset(horiz_pipe, 0, sizeof(horiz_pipe));
        memset(diag_pipe, 0, sizeof(diag_pipe));

        global_cycles = 0;
        count_test = 0;
        sim_cycle = 0;

        // clear DRAM op array visible in memory (matches C TB eyeriss_init)
        for (int i = 0; i < OP_LENGTH; i++) {
            for (int j = 0; j < OP_WIDTH; j++) {
                DRAM_op_data[i][j] = 0;
            }
        }

        // clear instrumentation globals
        ip0 = ip1 = ip2 = 0;
        wt0 = wt1 = wt2 = 0;
        psum_out0 = psum_out1 = psum_out2 = 0;
        DRAM_op_0_0 = DRAM_op_0_1 = DRAM_op_0_2 =
        DRAM_op_1_0 = DRAM_op_1_1 = DRAM_op_1_2 =
        DRAM_op_2_0 = DRAM_op_2_1 = DRAM_op_2_2 = 0;
    }

    // If we have already completed all active cycles, do nothing (no further state changes)
    if (sim_cycle >= active_cycles) {
        // Mirror DRAM_op_data into globals (still allow TB to read)
        for (int oi = 0; oi < OP_LENGTH; oi++) {
            for (int oj = 0; oj < OP_WIDTH; oj++) {
                int v = DRAM_op_data[oi][oj];
                if (oi == 0) {
                    if (oj == 0) DRAM_op_0_0 = v;
                    else if (oj == 1) DRAM_op_0_1 = v;
                    else if (oj == 2) DRAM_op_0_2 = v;
                } else if (oi == 1) {
                    if (oj == 0) DRAM_op_1_0 = v;
                    else if (oj == 1) DRAM_op_1_1 = v;
                    else if (oj == 2) DRAM_op_1_2 = v;
                } else if (oi == 2) {
                    if (oj == 0) DRAM_op_2_0 = v;
                    else if (oj == 1) DRAM_op_2_1 = v;
                    else if (oj == 2) DRAM_op_2_2 = v;
                }
            }
        }
        return;
    }

    // Begin one-cycle behavior (modeled after the C TB step function)

    // Local arrays to hold newly read inputs
    // NOTE: new_horiz should be indexed by PE_LENGTH (one per row),
    // and new_diag is [PE_LENGTH][PE_BREADTH], matching later usage.
    int new_horiz[PE_LENGTH];
    int new_diag[PE_LENGTH][PE_BREADTH];
    for (int i = 0; i < PE_LENGTH; i++) {
        new_horiz[i] = 0;
        for (int j = 0; j < PE_BREADTH; j++) new_diag[i][j] = 0;
    }

    // read_data_DRAM: increments global_cycles and samples DRAM arrays
    global_cycles++;
    for (int i = 0; i < PE_LENGTH; i++) {
        // index wrapping as in the C TB read_data_DRAM
        int wt_val = g_DRAM_wt_ptr[i][ (global_cycles-1) % WT_WIDTH ];
        int ip_val = g_DRAM_ip_ptr[i][ (global_cycles-1) % IF_WIDTH ];
        new_horiz[i] = wt_val;
        // only column 0 receives the new input; other columns will get data from pipes
        new_diag[i][0] = ip_val;

        // instrumentation of inputs
        if (i == 0) { wt0 = wt_val; ip0 = ip_val; }
        else if (i == 1) { wt1 = wt_val; ip1 = ip_val; }
        else if (i == 2) { wt2 = wt_val; ip2 = ip_val; }
    }

    int next_horiz[PE_LENGTH][PE_BREADTH];
    int next_diag [PE_LENGTH][PE_BREADTH];
    // initialize next pipes
    for (int i = 0; i < PE_LENGTH; i++) {
        for (int j = 0; j < PE_BREADTH; j++) {
            next_horiz[i][j] = 0;
            next_diag[i][j]  = 0;
        }
    }

    // local psum outputs for column 0 PEs
    int local_psum_out0 = 0;
    int local_psum_out1 = 0;
    int local_psum_out2 = 0;

    // process each PE (same algorithm as C TB process_PE usage)
    for (int i = 0; i < PE_LENGTH; i++) {
        for (int j = 0; j < PE_BREADTH; j++) {
            int horiz_in = (j == 0) ? new_horiz[i] : horiz_pipe[i][j-1];
            int diag_in  = (i == 0) ? new_diag[i][j] : diag_pipe[i-1][j];
            int psum_out = 0;

            // process_PE body (keeps the same behavior as the C TB)
            PE *pe = &pes[i][j];
            pe->local_cycle_count++;

            if (pe->local_cycle_count <= BUFFER_SIZE) {
                PE_IFM_Buffer[i*PE_BREADTH + j][pe->local_cycle_count - 1] = diag_in;
                PE_Wt_Buffer[i*PE_BREADTH + j][pe->local_cycle_count - 1]  = horiz_in;
            }

            if (pe->local_cycle_count > 1) {
                int idx = pe->psum_count;
                pe->psum_buffer_internal +=
                    PE_IFM_Buffer[i*PE_BREADTH + j][idx] *
                    PE_Wt_Buffer[i*PE_BREADTH + j][idx];
                pe->psum_count++;
            }

            if (pe->psum_count == BUFFER_SIZE) {
                psum_out = pe->psum_buffer_internal;
                pe->psum_buffer_internal = 0;
                pe->psum_count = 0;
            } else {
                psum_out = 0;
            }

            next_horiz[i][j] = (pe->local_cycle_count > 1) ?
                               PE_Wt_Buffer[i*PE_BREADTH + j][pe->local_cycle_count - 2] : 0;
            next_diag[i][j]  = (pe->local_cycle_count > 1) ?
                               PE_IFM_Buffer[i*PE_BREADTH + j][pe->local_cycle_count - 2] : 0;

            if (j == 0) {
                if      (i == 0) local_psum_out0 = psum_out;
                else if (i == 1) local_psum_out1 = psum_out;
                else if (i == 2) local_psum_out2 = psum_out;
            }
        }
    }

    // write_data_DRAM equivalent
    if (local_psum_out0) {
        if (count_test < OP_WIDTH) g_DRAM_op_ptr[0][count_test] = local_psum_out0;
    }
    if (local_psum_out1) {
        if (count_test < OP_WIDTH) g_DRAM_op_ptr[1][count_test] = local_psum_out1;
    }
    if (local_psum_out2) {
        if (count_test < OP_WIDTH) g_DRAM_op_ptr[2][count_test] = local_psum_out2;
        count_test++;
    }

    // advance pipes
    for (int i = 0; i < PE_LENGTH; i++) {
        for (int j = 0; j < PE_BREADTH; j++) {
            horiz_pipe[i][j] = next_horiz[i][j];
            diag_pipe [i][j] = next_diag [i][j];
        }
    }

    // update instrumentation outputs for TB
    psum_out0 = local_psum_out0;
    psum_out1 = local_psum_out1;
    psum_out2 = local_psum_out2;

    // snapshot DRAM_op_data into named globals for CSV
    if (g_DRAM_op_ptr) {
        DRAM_op_0_0 = g_DRAM_op_ptr[0][0];
        DRAM_op_0_1 = g_DRAM_op_ptr[0][1];
        DRAM_op_0_2 = g_DRAM_op_ptr[0][2];
        DRAM_op_1_0 = g_DRAM_op_ptr[1][0];
        DRAM_op_1_1 = g_DRAM_op_ptr[1][1];
        DRAM_op_1_2 = g_DRAM_op_ptr[1][2];
        DRAM_op_2_0 = g_DRAM_op_ptr[2][0];
        DRAM_op_2_1 = g_DRAM_op_ptr[2][1];
        DRAM_op_2_2 = g_DRAM_op_ptr[2][2];
    }

    sim_cycle++;
}

