// tb_hls_cosim.cpp
// Cosimulation testbench for the HLS top-level eyeriss.
// Produces a CSV file with per-cycle instrumentation matching the C reference TB.
// Written to be compatible with older libstdc++/clang shipped with Vivado HLS,
// so it avoids C++11 headers like <cstdint>.

#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <stdint.h>

// Keep the same sizing constants as the C testbench so the DUT interfaces match.
#define STRIDE 1
#define PADDING 0
#define IF_LENGTH 5
#define IF_WIDTH 5
#define WT_LENGTH 3
#define WT_WIDTH 3
#define OP_LENGTH 3
#define OP_WIDTH 3

#define PE_LENGTH 3
#define PE_BREADTH 3
#define SUM_BUFFER_SIZE 3
#define BUFFER_SIZE 3

#define active_cycles (PE_LENGTH + PE_BREADTH + (OP_WIDTH * 3))

// Declare the HLS/RTL top-level function. This must match the HLSC top-level
// function signature exactly.
extern "C" void eyeriss(int DRAM_ip_data[IF_LENGTH][IF_WIDTH],
                        int DRAM_Wt_data[WT_LENGTH][WT_WIDTH],
                        int DRAM_op_data[OP_LENGTH][OP_WIDTH]);

// The original C testbench embedded some instrumentation globals (ip0.., wt0..,
// psum_out*, DRAM_op_*). In order to sample the RTL/HLS internal instrumentation
// (as the C reference TB did), declare them extern here. If these symbols are
// present in the HLS top-level translation unit they will be updated by the DUT
// during cosim and can be sampled from the testbench.
// Mark externs as volatile to match the DUT definitions.
extern "C" {
    // input sampling instrumentation
    extern volatile int ip0;
    extern volatile int ip1;
    extern volatile int ip2;
    extern volatile int wt0;
    extern volatile int wt1;
    extern volatile int wt2;

    // output instrumentation
    extern volatile int psum_out0;
    extern volatile int psum_out1;
    extern volatile int psum_out2;

    // snapshot of DRAM_op array (instrumentation)
    extern volatile int DRAM_op_0_0;
    extern volatile int DRAM_op_0_1;
    extern volatile int DRAM_op_0_2;
    extern volatile int DRAM_op_1_0;
    extern volatile int DRAM_op_1_1;
    extern volatile int DRAM_op_1_2;
    extern volatile int DRAM_op_2_0;
    extern volatile int DRAM_op_2_1;
    extern volatile int DRAM_op_2_2;
}

int main() {
    // Prepare two deterministic testcases equivalent to the provided C testbench.
    int DRAM_ip_data_1[IF_LENGTH][IF_WIDTH];
    int DRAM_Wt_data_1[WT_LENGTH][WT_WIDTH];
    int DRAM_op_data_1[OP_LENGTH][OP_WIDTH];

    int DRAM_ip_data_2[IF_LENGTH][IF_WIDTH];
    int DRAM_Wt_data_2[WT_LENGTH][WT_WIDTH];
    int DRAM_op_data_2[OP_LENGTH][OP_WIDTH];

    // Testcase 1: identical deterministic initialization as the C testbench
    int i, j;
    for (i = 0; i < IF_LENGTH; i++) {
        for (j = 0; j < IF_WIDTH; j++) {
            DRAM_ip_data_1[i][j] = (i+1) * 10 + (j+1);
        }
    }
    for (i = 0; i < WT_LENGTH; i++) {
        for (j = 0; j < WT_WIDTH; j++) {
            DRAM_Wt_data_1[i][j] = (i+1) * 2 + j;
        }
    }
    memset(DRAM_op_data_1, 0, sizeof(DRAM_op_data_1));

    // Testcase 2: different deterministic values, same pattern as C testbench
    for (i = 0; i < IF_LENGTH; i++) {
        for (j = 0; j < IF_WIDTH; j++) {
            DRAM_ip_data_2[i][j] = (i+1) * 20 + (j+2);
        }
    }
    for (i = 0; i < WT_LENGTH; i++) {
        for (j = 0; j < WT_WIDTH; j++) {
            DRAM_Wt_data_2[i][j] = (i+1) * 3 + (j%3);
        }
    }
    memset(DRAM_op_data_2, 0, sizeof(DRAM_op_data_2));

    // Open CSV file for cosim (this will be produced during HLS cosim runs).
    FILE *f = fopen("hls_output.csv", "w");
    if (!f) {
        perror("Failed to open hls_output.csv");
        return 1;
    }

    // Write header row: cycle, inputs (ip0..ip2, wt0..wt2), outputs (psum_out0..2, DRAM_op_*)
    fprintf(f,
        "cycle,ip0,ip1,ip2,wt0,wt1,wt2,psum_out0,psum_out1,psum_out2,DRAM_op_0_0,DRAM_op_0_1,DRAM_op_0_2,DRAM_op_1_0,DRAM_op_1_1,DRAM_op_1_2,DRAM_op_2_0,DRAM_op_2_1,DRAM_op_2_2\n");

    // Write roles row: meta for cycle, in for driven signals, out for sampled signals
    // Must match the number of columns in the header (19 tokens).
    fprintf(f,
        "meta,in,in,in,in,in,in,out,out,out,out,out,out,out,out,out,out,out,out\n");

    int global_cycle_counter = 0;

    // Run both testcases sequentially. For each testcase, call the top-level eyeriss
    // function repeatedly to allow the DUT to advance internal cycles. After each
    // call sample the instrumentation globals and write a CSV row. This approach
    // matches the C testbench's per-cycle recording behavior assuming the HLS
    // top-level advances internal simulation state across calls (the HLS DUT
    // should expose the same instrumentation globals).
    for (int testcase = 0; testcase < 2; testcase++) {
        int (*ip_ptr)[IF_WIDTH];
        int (*wt_ptr)[WT_WIDTH];
        int (*op_ptr)[OP_WIDTH];

        if (testcase == 0) {
            ip_ptr = DRAM_ip_data_1;
            wt_ptr = DRAM_Wt_data_1;
            op_ptr = DRAM_op_data_1;
        } else {
            ip_ptr = DRAM_ip_data_2;
            wt_ptr = DRAM_Wt_data_2;
            op_ptr = DRAM_op_data_2;
        }

        // We call the top-level function active_cycles times and sample instrumentation
        // after each call. This matches the step-wise capture performed by the C TB.
        for (int c = 0; c < active_cycles; c++) {
            // Call the top-level HLS function. The DUT is expected to internally
            // progress simulation state/cycle on each invocation or produce
            // instrumentation that the TB can sample.
            eyeriss(ip_ptr, wt_ptr, op_ptr);

            // Write a CSV row:
            // first column: global cycle index
            fprintf(f, "%d,", global_cycle_counter);

            // Inputs are ip0..ip2, wt0..wt2 (decimal)
            fprintf(f, "%d,%d,%d,%d,%d,%d,",
                         (int)ip0, (int)ip1, (int)ip2, (int)wt0, (int)wt1, (int)wt2);

            // Outputs are psum_out* and DRAM_op_* written as uppercase HEX (no 0x)
            fprintf(f, "%X,%X,%X,",
                         (unsigned int)psum_out0,
                         (unsigned int)psum_out1,
                         (unsigned int)psum_out2);

            fprintf(f, "%X,%X,%X,%X,%X,%X,%X,%X,%X\n",
                         (unsigned int)DRAM_op_0_0,
                         (unsigned int)DRAM_op_0_1,
                         (unsigned int)DRAM_op_0_2,
                         (unsigned int)DRAM_op_1_0,
                         (unsigned int)DRAM_op_1_1,
                         (unsigned int)DRAM_op_1_2,
                         (unsigned int)DRAM_op_2_0,
                         (unsigned int)DRAM_op_2_1,
                         (unsigned int)DRAM_op_2_2);

            global_cycle_counter++;
        }
    }

    fflush(f);
    fclose(f);

    // Also print final DRAM_op_data for both testcases to stdout for convenience.
    printf("Test run 1 DRAM_op_data:\n");
    for (i = 0; i < OP_LENGTH; i++) {
        for (j = 0; j < OP_WIDTH; j++) {
            printf("%d\t", DRAM_op_data_1[i][j]);
        }
        printf("\n");
    }

    printf("Test run 2 DRAM_op_data:\n");
    for (i = 0; i < OP_LENGTH; i++) {
        for (j = 0; j < OP_WIDTH; j++) {
            printf("%d\t", DRAM_op_data_2[i][j]);
        }
        printf("\n");
    }

    return 0;
}

