#include "test.h"
#include <cstdio>
#include <cstring>

void ludcmp(double A[40][40], double b[40], double x[40], double y[40]) {

    const int n = 40;

    int i, j, k;

    double w;

    for (i = 0; i < n; i++) {
        for (j = 0; j < i; j++) {
            w = A[i][j];
            for (k = 0; k < j; k++) {
                w -= A[i][k] * A[k][j];
            }
            A[i][j] = w / A[j][j];
        }
        for (j = i; j < n; j++) {
            w = A[i][j];
            for (k = 0; k < i; k++) {
                w -= A[i][k] * A[k][j];
            }
            A[i][j] = w;
        }
    }

    for (i = 0; i < n; i++) {
        w = b[i];
        for (j = 0; j < i; j++)
            w -= A[i][j] * y[j];
        y[i] = w;
    }

    for (i = n - 1; i >= 0; i--) {
        w = y[i];
        for (j = i + 1; j < n; j++)
            w -= A[i][j] * x[j];
        x[i] = w / A[i][i];
    }
}

int main() {
    const int n = 40;
    double A_orig[40][40];
    double A[40][40];
    double b[40];
    double x[40];
    double y[40];
    double x_true[40];

    for (int i = 0; i < n; i++) {
        x_true[i] = 1.0;
    }

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (i == j) A_orig[i][j] = 100.0;
            else A_orig[i][j] = 1.0;
        }
    }

    for (int i = 0; i < n; i++) {
        double sum = 0.0;
        for (int j = 0; j < n; j++) {
            sum += A_orig[i][j] * x_true[j];
        }
        b[i] = sum;
    }

    std::memcpy(A, A_orig, sizeof(A));

    for (int i = 0; i < n; i++) {
        y[i] = 0.0;
        x[i] = 0.0;
    }

    ludcmp(A, b, x, y);

    for (int i = 0; i < n; i++) {
        std::printf("x[%d] = %f (expected %f)\n", i, x[i], x_true[i]);
    }

    return 0;
}

