#include <cstdio>
#include <cstdint>
#include <cstdlib>
#include <cstring>
#include <string>

// DUT: LU decomposition and solve (copied/adapted from provided code)
void ludcmp(double A[40][40], double b[40], double x[40], double y[40]) {

    const int n = 40;

    int i, j, k;

    double w;

    for (i = 0; i < n; i++) {
        for (j = 0; j < i; j++) {
            w = A[i][j];
            for (k = 0; k < j; k++) {
                w -= A[i][k] * A[k][j];
            }
            A[i][j] = w / A[j][j];
        }
        for (j = i; j < n; j++) {
            w = A[i][j];
            for (k = 0; k < i; k++) {
                w -= A[i][k] * A[k][j];
            }
            A[i][j] = w;
        }
    }

    for (i = 0; i < n; i++) {
        w = b[i];
        for (j = 0; j < i; j++)
            w -= A[i][j] * y[j];
        y[i] = w;
    }

    for (i = n - 1; i >= 0; i--) {
        w = y[i];
        for (j = i + 1; j < n; j++)
            w -= A[i][j] * x[j];
        x[i] = w / A[i][i];
    }
}

static inline void double_to_hexstr(double v, char *outbuf, size_t bufsize) {
    // Interpret the double bitpattern as uint64_t and print uppercase hex WITHOUT 0x,
    // pad to 16 hex digits to match Verilog formatting
    uint64_t u;
    memcpy(&u, &v, sizeof(u));
    // Use unsigned long long for portability with %llX and pad to 16 chars
    std::snprintf(outbuf, bufsize, "%016llX", (unsigned long long)u);
}

int main() {
    const int CYCLES = 32; // between 20 and 50
    const int N = 40;

    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // CSV header: cycle, then inputs (A,b), then outputs (x,y)
    std::fprintf(f, "cycle,A,b,x,y\n");
    // roles row: cycle is meta; A and b are driven inputs (in); x and y are outputs (out)
    std::fprintf(f, "meta,in,in,out,out\n");

    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        // Define deterministic test vector IDs (inputs represented as integers)
        int A_id = 100 + cycle; // input identifier for matrix A (decimal integer)
        int b_id = 200 + cycle; // input identifier for vector b (decimal integer)

        // Construct the actual A matrix and b vector deterministically from IDs (integer-valued entries)
        double A[N][N];
        double Ain[N][N];
        double bvec[N];
        double bin[N];
        double x[N];
        double y[N];

        // Build matrix Ain from A_id ensuring non-zero diagonal (to avoid division by zero)
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < N; ++j) {
                if (i == j) {
                    // diagonal positive and varying
                    int diag_base = (A_id % 7) + 3; // 3..9
                    Ain[i][j] = (double)(diag_base + (i % 5));
                } else {
                    // off-diagonal small integers, can be negative
                    int val = (int)((A_id + i * 5 + j * 11) % 13) - 6; // range -6..6
                    Ain[i][j] = (double)val;
                    // Slightly reduce magnitude for stability in some rows
                    if ( (i + j + A_id) % 17 == 0 ) {
                        // Use floating-point division to match Verilog real division (avoid integer truncation)
                        Ain[i][j] = (double)val / 2.0;
                    }
                }
            }
        }

        // Build b vector from b_id deterministically
        for (int i = 0; i < N; ++i) {
            int v = (int)((b_id * (i + 1) + 3) % 23) - 11; // -11..11
            bvec[i] = (double)v;
        }

        // Copy Ain to A (since ludcmp will modify A in-place)
        for (int i = 0; i < N; ++i)
            for (int j = 0; j < N; ++j)
                A[i][j] = Ain[i][j];

        // Copy bvec to bin (not strictly necessary)
        for (int i = 0; i < N; ++i) {
            bin[i] = bvec[i];
            x[i] = 0.0;
            y[i] = 0.0;
        }

        // Call DUT once per cycle
        ludcmp(A, bin, x, y);

        // Prepare hex string representations of outputs x and y
        // We'll concatenate element hex values separated by '|' (no commas)
        std::string x_hex;
        std::string y_hex;
        char tmp[64];

        for (int i = 0; i < N; ++i) {
            double_to_hexstr(x[i], tmp, sizeof(tmp));
            if (i) x_hex.push_back('|');
            x_hex.append(tmp);
        }
        for (int i = 0; i < N; ++i) {
            double_to_hexstr(y[i], tmp, sizeof(tmp));
            if (i) y_hex.push_back('|');
            y_hex.append(tmp);
        }

        // Write CSV row: cycle (decimal), A (decimal), b (decimal), x (hex string), y (hex string)
        // According to requirements: input columns use decimal integers; output columns use hex uppercase without 0x.
        std::fprintf(f, "%d,%d,%d,%s,%s\n", cycle, A_id, b_id, x_hex.c_str(), y_hex.c_str());
    }

    std::fflush(f);
    std::fclose(f);
    return 0;
}

