// hls.cpp
// Top-level HLS function for LU decomposition + triangular solves.
// This file provides an extern "C" top function named `ludcmp` so that
// the C-style testbench can link to it. The implementation is in-place:
// A is overwritten with the LU factors (L has unit diagonal stored
// implicitly in the strictly lower part), y is the forward-substitution
// result, and x is the final solution after back-substitution.
//
// Keep the interface pragmas so Vivado HLS will infer AXI interfaces
// for the arrays and an s_axilite control interface for arguments/return.
//
// Notes:
//  - N is fixed to 40 to match the testbench.
//  - Implementation follows the same algorithm as provided originally.

extern "C" {

#define N 40

void ludcmp(double A[N][N], double b[N], double x[N], double y[N]) {
#pragma HLS INTERFACE m_axi port=A offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=b offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=x offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=y offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=A bundle=control
#pragma HLS INTERFACE s_axilite port=b bundle=control
#pragma HLS INTERFACE s_axilite port=x bundle=control
#pragma HLS INTERFACE s_axilite port=y bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int i, j, k;
    double w;

    // LU decomposition (Doolittle algorithm, L has implicit 1s on diagonal).
    for (i = 0; i < N; i++) {
        // Compute L elements (below diagonal)
        for (j = 0; j < i; j++) {
            w = A[i][j];
            for (k = 0; k < j; k++) {
                w -= A[i][k] * A[k][j];
            }
            A[i][j] = w / A[j][j];
        }
        // Compute U elements (on and above diagonal)
        for (j = i; j < N; j++) {
            w = A[i][j];
            for (k = 0; k < i; k++) {
                w -= A[i][k] * A[k][j];
            }
            A[i][j] = w;
        }
    }

    // Forward substitution: Ly = b (L has 1s on diagonal)
    for (i = 0; i < N; i++) {
        w = b[i];
        for (j = 0; j < i; j++) {
            w -= A[i][j] * y[j];
        }
        y[i] = w; // since diagonal of L is 1
    }

    // Back substitution: Ux = y
    for (i = N - 1; i >= 0; --i) {
        w = y[i];
        for (j = i + 1; j < N; j++) {
            w -= A[i][j] * x[j];
        }
        x[i] = w / A[i][i];
    }
}

} // extern "C"

