// downstream checks. Avoids C++11 headers/features so it works with
// Vivado HLS 2018.3 toolchain (clang + old libstdc++).

#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <string>
#include <cstddef>
#include <stdint.h> // use C header for fixed-width ints for C++98 compatibility

extern "C" void ludcmp(double A[40][40], double b[40], double x[40], double y[40]);

// Convert double bitpattern to uppercase hex string without 0x, padded to 16 hex digits.
// This uses memcpy and a manual nibble-to-hex conversion to avoid relying on
// %llX or snprintf behavior that may not be present/consistent in older toolchains.
static inline void double_to_hexstr(double v, char *outbuf, size_t bufsize) {
    unsigned long long u = 0ULL;
    // Copy raw bytes of the double into the integer variable.
    // Assumes sizeof(unsigned long long) == sizeof(double) (typical on target).
    ::memcpy(&u, &v, sizeof(u));
    const char hexmap[] = "0123456789ABCDEF";
    if (bufsize < 17) {
        if (bufsize > 0) outbuf[0] = '\0';
        return;
    }
    // fill 16 hex digits (most significant nibble first)
    for (int i = 0; i < 16; ++i) {
        int shift = (15 - i) * 4;
        unsigned int nibble = (unsigned int)((u >> shift) & 0xF);
        outbuf[i] = hexmap[nibble];
    }
    outbuf[16] = '\0';
}

int main() {
