	for(t = 0; t < ROWS-1 ; t++){
		for(n = 0; n < COLS; n++){
			min = Jout[n];

			if(n > 0){
				min = MIN(min,before);
			}

			if(n < COLS-1){
				min = MIN(min,Jout[n+1]);
			}
			before = Jout[n];

			Jout[n] = J[(t+1) * COLS + n] + min;
