/*
C testbench for pathfinder / pathfinder_kernel
- Produces c_output.csv with:
  * first row: column names
  * second row: roles (meta,in,out,...)
- Input columns (J) printed as decimal integers.
- Output columns printed as uppercase hexadecimal without 0x.
- Explicitly closes output file.
- Calls both pathfinder and pathfinder_kernel to maximize coverage.
- Self-contained and deterministic (no rand()).

To compile:
  gcc -O2 -std=c11 -o tb_pathfinder tb_pathfinder.c

This testbench intentionally exercises many data patterns (including
edge cases and alternating patterns) and multiple initializations
for the kernel to increase branch/data-dependent coverage.
*/
#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>

#define ROWS 1024
#define COLS 1024
#define MIN(a,b) ((a) <= (b) ? (a) : (b))

/* Implementation of the kernel function (as provided) */
void pathfinder_kernel(int32_t J[ROWS*COLS], int32_t Jout[COLS]){
    int32_t temp;
    int32_t i, t, tt, n;
    int32_t min, before;

    for(t = 0; t < ROWS-1 ; t++){
        for(n = 0; n < COLS; n++){
            min = Jout[n];

            if(n > 0){
                min = MIN(min,before);
            }

            if(n < COLS-1){
                min = MIN(min,Jout[n+1]);
            }
            before = Jout[n];

            Jout[n] = J[(t+1) * COLS + n] + min;
        }
    }
}

/* Reference implementation (as provided) */
void pathfinder(int32_t J[ROWS * COLS], int32_t Jout[COLS]) {
    int32_t dst[COLS];
    int32_t src[COLS];
    int32_t i, t, tt, n;
    int32_t min;

    memcpy(dst, J, sizeof(int32_t) * COLS);

    for(t = 0; t < ROWS-1 ; t++){
        for(n = 0; n < COLS; n++){
            min = dst[n];

            if(n > 0){
                min = MIN(min, dst[n-1]);
            }

            if(n < COLS-1){
                min = MIN(min, dst[n+1]);
            }

            src[n] = J[(t+1) * COLS + n] + min;
        }
        memcpy(dst, src, sizeof(int32_t) * COLS);
    }
    memcpy(Jout, dst, sizeof(int32_t) * COLS);
    return;
}

int main(void) {
    /* Allocate input and outputs */
    int32_t *J = (int32_t*)malloc(sizeof(int32_t) * ROWS * COLS);
    int32_t *Jout_pf = (int32_t*)malloc(sizeof(int32_t) * COLS);       /* pathfinder output */
    int32_t *Jout_kernel = (int32_t*)malloc(sizeof(int32_t) * COLS);   /* kernel output */
    int32_t *Jout_init = (int32_t*)malloc(sizeof(int32_t) * COLS);     /* initial row copy for kernel */

    if (!J || !Jout_pf || !Jout_kernel || !Jout_init) {
        fprintf(stderr, "Memory allocation failed\n");
        free(J); free(Jout_pf); free(Jout_kernel); free(Jout_init);
        return 1;
    }

    /* Prepare CSV file */
    FILE *csv = fopen("c_output.csv", "w");
    if (!csv) {
        fprintf(stderr, "Failed to open c_output.csv for writing\n");
        free(J); free(Jout_pf); free(Jout_kernel); free(Jout_init);
        return 1;
    }

    /* Header row: column names */
    /* We'll include cycle (meta), J (input, decimal), three outputs from pathfinder
       and three outputs from pathfinder_kernel. All outputs printed in HEX uppercase. */
    fprintf(csv, "cycle,J,pf_Jout[0],pf_Jout[1],pf_Jout[%d],kernel_Jout[0],kernel_Jout[1],kernel_Jout[%d]\n",
            COLS-1, COLS-1);
    /* Second row: roles for each column. First is meta, second is input, others are outputs */
    fprintf(csv, "meta,in,out,out,out,out,out,out\n");

    /* Number of deterministic test cycles and patterns per cycle
       Increased counts and a broad variety of patterns to bump coverage. */
    const int CYCLES = 30;
    const int PATTERNS = 12;

    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        for (int pat = 0; pat < PATTERNS; ++pat) {
            /* Fill J deterministically based on (row, col, cycle, pattern) to exercise many code paths */
            for (int r = 0; r < ROWS; ++r) {
                for (int c = 0; c < COLS; ++c) {
                    int idx = r * COLS + c;
                    int32_t val;
                    switch (pat) {
                        case 0:
                            /* base pattern: varying with r^c and cycle */
                            val = (int32_t)((((r ^ c) + cycle) % 17) * ((r % 4) + 1) + (c % 7));
                            break;
                        case 1:
                            /* all zeros */
                            val = 0;
                            break;
                        case 2:
                            /* strictly increasing with column and row to force left < right often */
                            val = (int32_t)((r % 5) * 10 + (c % 256));
                            break;
                        case 3:
                            /* strictly decreasing with column and row to force left > right often */
                            val = (int32_t)(((ROWS - 1 - r) % 5) * 10 + ((COLS - 1 - c) % 256));
                            break;
                        case 4:
                            /* alternating high/low to cause MIN to pick left/right variably */
                            val = (int32_t)((c & 1) ? 0x7F : 0x20);
                            break;
                        case 5:
                            /* single repeated value */
                            val = 42;
                            break;
                        case 6:
                            /* spikes at particular columns to exercise neighbor comparisons */
                            val = (int32_t)((c % 128) == (cycle % 128) ? 1000 : (c % 13));
                            break;
                        case 7:
                            /* modulo pattern to generate equals and ties */
                            val = (int32_t)((r + c + cycle) % 37);
                            break;
                        case 8:
                            /* negative values pattern */
                            val = (int32_t)(-((r + c + cycle) % 50));
                            break;
                        case 9:
                            /* large values near INT16/INT32 boundaries but still safe */
                            val = (int32_t)((c % 200) + 20000);
                            break;
                        case 10:
                            /* pattern to stress first/last column differences */
                            val = (int32_t)((c == 0) ? 999 : (c == COLS-1) ? 1001 : (c % 31));
                            break;
                        case 11:
                        default:
                            /* combined pattern to create ties and varied neighbors */
                            val = (int32_t)(((r * 3) ^ (c * 7) ^ cycle) % 61);
                            break;
                    }
                    /* Occasionally inject a larger value on specific cycles to vary flow */
                    if ((cycle % 11) == 3 && (c % 64) == 0 && pat == 0) {
                        val += 123;
                    }
                    J[idx] = val;
                }
            }

            /* Prepare initial Jout for kernel: sometimes use first row, sometimes an alternate init
               to exercise different data-dependent branches inside kernel */
            if ((pat & 1) == 0) {
                /* use the first row of J */
                memcpy(Jout_init, J, sizeof(int32_t) * COLS);
            } else {
                /* alternate initialization: zeros, increasing sequence, or repeating pattern */
                if (pat == 1) {
                    memset(Jout_init, 0, sizeof(int32_t) * COLS);
                } else if (pat == 3) {
                    for (int c = 0; c < COLS; ++c) Jout_init[c] = (int32_t)(COLS - c);
                } else if (pat == 5) {
                    for (int c = 0; c < COLS; ++c) Jout_init[c] = (int32_t)((c & 1) ? 100 : 50);
                } else if (pat == 7) {
                    /* descending pattern to hit different min choices */
                    for (int c = 0; c < COLS; ++c) Jout_init[c] = (int32_t)(COLS - 1 - c);
                } else if (pat == 9) {
                    /* set a valley in the middle */
                    for (int c = 0; c < COLS; ++c) {
                        if (c == COLS/2) Jout_init[c] = -500;
                        else Jout_init[c] = (int32_t)(c % 17);
                    }
                } else {
                    /* default: copy first row */
                    memcpy(Jout_init, J, sizeof(int32_t) * COLS);
                }
            }

            /* Call both implementations to maximize coverage */
            pathfinder(J, Jout_pf);

            /* Use a copy so we don't modify the initial values for further tests */
            memcpy(Jout_kernel, Jout_init, sizeof(int32_t) * COLS);
            pathfinder_kernel(J, Jout_kernel);

            /* Sample outputs:
               - Input 'J' column will be a deterministic id (cycle * PATTERNS + pat) (decimal)
               - Outputs printed in uppercase hex without 0x (use %X)
            */
            unsigned pf0 = (unsigned)(uint32_t)Jout_pf[0];
            unsigned pf1 = (unsigned)(uint32_t)Jout_pf[1];
            unsigned pf_last = (unsigned)(uint32_t)Jout_pf[COLS-1];

            unsigned k0 = (unsigned)(uint32_t)Jout_kernel[0];
            unsigned k1 = (unsigned)(uint32_t)Jout_kernel[1];
            unsigned klast = (unsigned)(uint32_t)Jout_kernel[COLS-1];

            /* Write one CSV row per (cycle,pattern):
               cycle (meta, decimal), J (input, decimal), then outputs in HEX uppercase */
            int input_id = cycle * PATTERNS + pat;
            fprintf(csv, "%d,%d,%X,%X,%X,%X,%X,%X\n",
                    cycle,                      /* meta */
                    input_id,                   /* J (input) - decimal */
                    pf0, pf1, pf_last,          /* pathfinder outputs in HEX */
                    k0, k1, klast);             /* kernel outputs in HEX */
        }
    }

    /* Additional targeted tests to exercise edge behaviors and branches more thoroughly */
    for (int t = 0; t < 12; ++t) {
        /* Each targeted scenario gets a unique input_id > normal range */
        int input_id = 100000 + t;

        /* Zero everything first */
        memset(J, 0, sizeof(int32_t) * ROWS * COLS);

        if (t == 0) {
            /* Only first column non-zero, increasing down the rows */
            for (int r = 0; r < ROWS; ++r) {
                J[r * COLS + 0] = (int32_t)(r % 100);
            }
            for (int c = 1; c < COLS; ++c) {
                for (int r = 0; r < ROWS; ++r) J[r * COLS + c] = 0;
            }
        } else if (t == 1) {
            /* Only last column non-zero */
            for (int r = 0; r < ROWS; ++r) {
                J[r * COLS + (COLS-1)] = (int32_t)((r * 3) % 200);
            }
        } else if (t == 2) {
            /* Jagged alternating pattern by row */
            for (int r = 0; r < ROWS; ++r) {
                for (int c = 0; c < COLS; ++c) {
                    J[r*COLS + c] = (int32_t)((r & 1) ? (c % 5) : ((c % 5) + 5));
                }
            }
        } else if (t == 3) {
            /* All equal large value */
            for (int i = 0; i < ROWS * COLS; ++i) J[i] = 30000;
        } else if (t == 4) {
            /* Ties everywhere to force MIN equal cases */
            for (int i = 0; i < ROWS * COLS; ++i) J[i] = (i % 3);
        } else if (t == 5) {
            /* Create a checkerboard negative/positive pattern */
            for (int r = 0; r < ROWS; ++r) {
                for (int c = 0; c < COLS; ++c) {
                    J[r*COLS + c] = ((r + c) & 1) ? -7 : 7;
                }
            }
        } else if (t == 6) {
            /* Large spikes in a few columns */
            for (int r = 0; r < ROWS; ++r) {
                for (int c = 0; c < COLS; ++c) {
                    J[r*COLS + c] = (c % 100 == 50) ? 200000 : (c % 13);
                }
            }
        } else if (t == 7) {
            /* Increasing rows and decreasing columns combined */
            for (int r = 0; r < ROWS; ++r) {
                for (int c = 0; c < COLS; ++c) {
                    J[r*COLS + c] = (int32_t)((r % 9) * 11 + ((COLS - c) % 13));
                }
            }
        } else if (t == 8) {
            /* Single row non-zero in the middle */
            int mid = ROWS / 2;
            for (int c = 0; c < COLS; ++c) J[mid * COLS + c] = (int32_t)(c % 19);
        } else if (t == 9) {
            /* Alternating large/small columns to force different mins */
            for (int r = 0; r < ROWS; ++r) {
                for (int c = 0; c < COLS; ++c) J[r*COLS + c] = (c & 1) ? 10000 : 1;
            }
        } else if (t == 10) {
            /* Very small ROWS/cols style pattern replicated across big array */
            for (int r = 0; r < ROWS; ++r) {
                for (int c = 0; c < COLS; ++c) {
                    J[r*COLS + c] = (int32_t)(((r % 3) * 3) + (c % 3));
                }
            }
        } else {
            /* Mixed random-like deterministic pattern */
            for (int r = 0; r < ROWS; ++r) {
                for (int c = 0; c < COLS; ++c) {
                    J[r*COLS + c] = (int32_t)(((r * 37) ^ (c * 17) ^ t) % 123);
                }
            }
        }

        /* Prepare a few different initializations for kernel to exercise before/Jout[n+1] */
        if (t % 3 == 0) {
            /* Jout_init = first row */
            memcpy(Jout_init, J, sizeof(int32_t) * COLS);
        } else if (t % 3 == 1) {
            /* Jout_init descending */
            for (int c = 0; c < COLS; ++c) Jout_init[c] = (int32_t)(COLS - c);
        } else {
            /* Jout_init zeros with a peak at column 1 */
            memset(Jout_init, 0, sizeof(int32_t) * COLS);
            Jout_init[1] = 99999;
        }

        /* Run both */
        pathfinder(J, Jout_pf);
        memcpy(Jout_kernel, Jout_init, sizeof(int32_t) * COLS);
        pathfinder_kernel(J, Jout_kernel);

        unsigned pf0 = (unsigned)(uint32_t)Jout_pf[0];
        unsigned pf1 = (unsigned)(uint32_t)Jout_pf[1];
        unsigned pf_last = (unsigned)(uint32_t)Jout_pf[COLS-1];

        unsigned k0 = (unsigned)(uint32_t)Jout_kernel[0];
        unsigned k1 = (unsigned)(uint32_t)Jout_kernel[1];
        unsigned klast = (unsigned)(uint32_t)Jout_kernel[COLS-1];

        /* Use cycle = 1000 + t for meta in CSV */
        fprintf(csv, "%d,%d,%X,%X,%X,%X,%X,%X\n",
                1000 + t,
                input_id,
                pf0, pf1, pf_last,
                k0, k1, klast);
    }

    /* Explicitly close CSV and free memory */
    if (fclose(csv) != 0) {
        fprintf(stderr, "Failed to close c_output.csv properly\n");
        /* continue to free memory and exit */
    }
    free(J);
    free(Jout_pf);
    free(Jout_kernel);
    free(Jout_init);

    return 0;
}

