// hls.cpp
// HLS implementation of the reference pathfinder algorithm.
// The top-level function signature matches the C testbench:
//   extern "C" void pathfinder_kernel(int32_t J[ROWS*COLS], int32_t Jout[COLS])
// The implementation reproduces the sequential behavior of the reference C
// testbench to guarantee identical outputs for the same inputs.
//
// Note: use C header <stdint.h> for compatibility with Vivado HLS older C++ mode.

#include <stdint.h>

#define ROWS 1024
#define COLS 1024

/* simple MIN macro for integers */
#define MIN(a,b) ((a) <= (b) ? (a) : (b))

extern "C" {

void pathfinder_kernel(int32_t J[ROWS * COLS], int32_t Jout[COLS]) {
#pragma HLS INTERFACE m_axi port=J offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=Jout offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=J bundle=control
#pragma HLS INTERFACE s_axilite port=Jout bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    /* Local line buffers */
    int32_t dst[COLS];
#pragma HLS array_partition variable=dst cyclic factor=16 dim=1
    int32_t src[COLS];
#pragma HLS array_partition variable=src cyclic factor=16 dim=1

    int32_t n, t;
    int32_t minval;

    /* Initialize dst with the first row of J */
    for (n = 0; n < COLS; n++) {
#pragma HLS PIPELINE II=1
        dst[n] = J[n];
    }

    /* Iterate rows: for each next row compute
       src[n] = J[(t+1)*COLS + n] + min(neighbors of dst) */
    for (t = 0; t < ROWS - 1; t++) {
        /* compute one output row into src */
        for (n = 0; n < COLS; n++) {
#pragma HLS PIPELINE II=1
            minval = dst[n];
            if (n > 0) {
                minval = MIN(minval, dst[n - 1]);
            }
            if (n < COLS - 1) {
                minval = MIN(minval, dst[n + 1]);
            }
            src[n] = J[(t + 1) * COLS + n] + minval;
        }
        /* copy src back to dst for next iteration */
        for (n = 0; n < COLS; n++) {
#pragma HLS PIPELINE II=1
            dst[n] = src[n];
        }
    }

    /* write final dst to Jout */
    for (n = 0; n < COLS; n++) {
#pragma HLS PIPELINE II=1
        Jout[n] = dst[n];
    }
}

} /* extern "C" */

