// tb_hls_cosim.cpp
// Testbench for HLS cosimulation.
// Uses deterministic data patterns and writes sampled outputs to a CSV file.
// Note: use C-style headers to remain compatible with older C++ standard library
// implementations bundled with Vivado HLS (pre-C++11).

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>

#define ROWS 1024
#define COLS 1024
#define TYPE int32_t
#define MIN(a,b) ((a)<=(b) ? (a) : (b))

/* Top-level HLS kernel declaration must match HLSC definition exactly. */
extern "C" void pathfinder_kernel(int32_t J[ROWS*COLS], int32_t Jout[COLS]);

int main(void) {
	/* Allocate input and output arrays */
	int32_t *J = (int32_t*)malloc(sizeof(int32_t) * ROWS * COLS);
	int32_t *Jout = (int32_t*)malloc(sizeof(int32_t) * COLS);
	if (!J || !Jout) {
		fprintf(stderr, "Memory allocation failed\n");
		if (J) free(J);
		if (Jout) free(Jout);
		return 1;
	}

	/* Prepare CSV for HLS/RTL output */
	FILE *csv = fopen("hls_output.csv", "w");
	if (!csv) {
		fprintf(stderr, "Failed to open hls_output.csv for writing\n");
		free(J);
		free(Jout);
		return 1;
	}

	/* CSV header: cycle, then input variable names, then sampled output names.
	   Using J as the input variable name and sampling three elements of Jout. */
	fprintf(csv, "cycle,J,Jout[0],Jout[1],Jout[1023]\n");
	fprintf(csv, "meta,in,out,out,out\n");

	/* Number of cycles (rows) to simulate: choose a deterministic count between 20 and 50. */
	const int CYCLES = 30;

	/* Deterministic test vectors: for each cycle, fill the entire J matrix with a pattern
	   that depends only on (row, col, cycle). No random functions used. */
	for (int cycle = 0; cycle < CYCLES; ++cycle) {
		/* Fill J deterministically */
		for (int r = 0; r < ROWS; ++r) {
			for (int c = 0; c < COLS; ++c) {
				int idx = r * COLS + c;
				int32_t val = (int32_t)((((r ^ c) + cycle) % 13) * ((r % 3) + 1) + (c % 5));
				J[idx] = val;
			}
		}

		/* Call the HLS DUT once per cycle */
		pathfinder_kernel(J, Jout);

		/* Sample outputs: Jout[0], Jout[1], Jout[1023]
		   Input column 'J' will contain the decimal pattern id (cycle).
		   Output columns are printed in hex uppercase without 0x and without fixed width. */
		unsigned out0 = (unsigned)Jout[0];
		unsigned out1 = (unsigned)Jout[1];
		unsigned out1023 = (unsigned)Jout[COLS-1];

		fprintf(csv, "%d,%d,%X,%X,%X\n", cycle, cycle, out0, out1, out1023);
	}

	/* Explicitly close CSV and free memory */
	fclose(csv);
	free(J);
	free(Jout);

	return 0;
}

