#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include "test.h"

int check_clockwise( Triangle_2D triangle_2d )
{
  int cw;
  cw = (triangle_2d.x2 - triangle_2d.x0) * (triangle_2d.y1 - triangle_2d.y0)
       - (triangle_2d.y2 - triangle_2d.y0) * (triangle_2d.x1 - triangle_2d.x0);
  return cw;
}

void clockwise_vertices( Triangle_2D *triangle_2d )
{
  bit8 tmp_x, tmp_y;
  tmp_x = triangle_2d->x0;
  tmp_y = triangle_2d->y0;
  triangle_2d->x0 = triangle_2d->x1;
  triangle_2d->y0 = triangle_2d->y1;
  triangle_2d->x1 = tmp_x;
  triangle_2d->y1 = tmp_y;
}

bit1 pixel_in_triangle( bit8 x, bit8 y, Triangle_2D triangle_2d )
{
  int pi0, pi1, pi2;
  pi0 = (x - triangle_2d.x0) * (triangle_2d.y1 - triangle_2d.y0) - (y - triangle_2d.y0) * (triangle_2d.x1 - triangle_2d.x0);
  pi1 = (x - triangle_2d.x1) * (triangle_2d.y2 - triangle_2d.y1) - (y - triangle_2d.y1) * (triangle_2d.x2 - triangle_2d.x1);
  pi2 = (x - triangle_2d.x2) * (triangle_2d.y0 - triangle_2d.y2) - (y - triangle_2d.y2) * (triangle_2d.x0 - triangle_2d.x2);
  return (pi0 >= 0 && pi1 >= 0 && pi2 >= 0) ? 1 : 0;
}

bit8 find_min( bit8 in0, bit8 in1, bit8 in2 )
{
  if (in0 < in1)
  {
    if (in0 < in2)
      return in0;
    else 
      return in2;
  }
  else 
  {
    if (in1 < in2) 
      return in1;
    else 
      return in2;
  }
}

bit8 find_max( bit8 in0, bit8 in1, bit8 in2 )
{
  if (in0 > in1)
  {
    if (in0 > in2)
      return in0;
    else 
      return in2;
  }
  else 
  {
    if (in1 > in2) 
      return in1;
    else 
      return in2;
  }
}

void projection ( Triangle_3D triangle_3d, Triangle_2D *triangle_2d, bit2 angle )
{
  if(angle == 0)
  {
    triangle_2d->x0 = triangle_3d.x0;
    triangle_2d->y0 = triangle_3d.y0;
    triangle_2d->x1 = triangle_3d.x1;
    triangle_2d->y1 = triangle_3d.y1;
    triangle_2d->x2 = triangle_3d.x2;
    triangle_2d->y2 = triangle_3d.y2;
    triangle_2d->z  = triangle_3d.z0 / 3 + triangle_3d.z1 / 3 + triangle_3d.z2 / 3;
  }
  else if(angle == 1)
  {
    triangle_2d->x0 = triangle_3d.x0;
    triangle_2d->y0 = triangle_3d.z0;
    triangle_2d->x1 = triangle_3d.x1;
    triangle_2d->y1 = triangle_3d.z1;
    triangle_2d->x2 = triangle_3d.x2;
    triangle_2d->y2 = triangle_3d.z2;
    triangle_2d->z  = triangle_3d.y0 / 3 + triangle_3d.y1 / 3 + triangle_3d.y2 / 3;
  }
  else if(angle == 2)
  {
    triangle_2d->x0 = triangle_3d.z0;
    triangle_2d->y0 = triangle_3d.y0;
    triangle_2d->x1 = triangle_3d.z1;
    triangle_2d->y1 = triangle_3d.y1;
    triangle_2d->x2 = triangle_3d.z2;
    triangle_2d->y2 = triangle_3d.y2;
    triangle_2d->z  = triangle_3d.x0 / 3 + triangle_3d.x1 / 3 + triangle_3d.x2 / 3;
  }
}

bit2 rasterization1 ( Triangle_2D triangle_2d, bit8 max_min[], Triangle_2D *triangle_2d_same, bit16 max_index[])
{
  if ( check_clockwise( triangle_2d ) == 0 )
    return 1;
  if ( check_clockwise( triangle_2d ) < 0 )
    clockwise_vertices( &triangle_2d );

  triangle_2d_same->x0 = triangle_2d.x0;
  triangle_2d_same->y0 = triangle_2d.y0;
  triangle_2d_same->x1 = triangle_2d.x1;
  triangle_2d_same->y1 = triangle_2d.y1;
  triangle_2d_same->x2 = triangle_2d.x2;
  triangle_2d_same->y2 = triangle_2d.y2;
  triangle_2d_same->z  = triangle_2d.z ;

  max_min[0] = find_min( triangle_2d.x0, triangle_2d.x1, triangle_2d.x2 );
  max_min[1] = find_max( triangle_2d.x0, triangle_2d.x1, triangle_2d.x2 );
  max_min[2] = find_min( triangle_2d.y0, triangle_2d.y1, triangle_2d.y2 );
  max_min[3] = find_max( triangle_2d.y0, triangle_2d.y1, triangle_2d.y2 );
  max_min[4] = max_min[1] - max_min[0];

  max_index[0] = (max_min[1] - max_min[0]) * (max_min[3] - max_min[2]);

  return 0;
}

bit16 rasterization2 ( bit2 flag, bit8 max_min[], bit16 max_index[], Triangle_2D triangle_2d_same, CandidatePixel fragment2[] )
{
  if ( flag )
  {
    return 0;
  }
  bit8 color = 100;
  bit16 i = 0;
  for ( bit16 k = 0; k < 100 ; k++ )
  {
    bit8 x = max_min[0];
    bit8 y = max_min[2];
    if (max_min[4] != 0) {
      x = max_min[0] + (bit8)(k % max_min[4]);
      y = max_min[2] + (bit8)(k / max_min[4]);
    }
    if( pixel_in_triangle( x, y, triangle_2d_same ) )
    {
      fragment2[i].x = x;
      fragment2[i].y = y;
      fragment2[i].z = triangle_2d_same.z;
      fragment2[i].color = color;
      i++;
      if (i >= 500) break;
    }
  }
  return i;
}

bit16 zculling ( bit16 counter, CandidatePixel fragments[], bit16 size, Pixel pixels[])
{
  static bit8 z_buffer[MAX_X][MAX_Y];
  if (counter == 0)
  {
    for ( bit16 i = 0; i < MAX_X; i++)
    {
      for ( bit16 j = 0; j < MAX_Y; j++)
      {
        z_buffer[i][j] = 255;
      }
    }
  }
  bit16 pixel_cntr = 0;
  for ( bit16 n = 0; n < 100 ; n++ )
  {
    bit8 fx = fragments[n].x;
    bit8 fy = fragments[n].y;
    if (fx < MAX_X && fy < MAX_Y) {
      if( fragments[n].z < z_buffer[fy][fx] )
      {
        pixels[pixel_cntr].x     = fragments[n].x;
        pixels[pixel_cntr].y     = fragments[n].y;
        pixels[pixel_cntr].color = fragments[n].color;
        pixel_cntr++;
        z_buffer[fragments[n].y][fragments[n].x] = fragments[n].z;
        if (pixel_cntr >= 500) break;
      }
    }
  }
  return pixel_cntr;
}

void coloringFB(bit16 counter,  bit16 size_pixels, Pixel pixels[], bit8 frame_buffer[MAX_X][MAX_Y])
{
  if ( counter == 0 )
  {
    for ( bit16 i = 0; i < MAX_X; i++)
    {
      for ( bit16 j = 0; j < MAX_Y; j++)
        frame_buffer[i][j] = 0;
    }
  }
  for ( int i = 0; i < 10000 ; i++)
  {
    bit8 px = pixels[i].x;
    bit8 py = pixels[i].y;
    if (px < MAX_X && py < MAX_Y)
      frame_buffer[ px ][ py ] = pixels[i].color;
  }
}

void output_FB(bit8 frame_buffer[MAX_X][MAX_Y], bit32 output[NUM_FB])
{
  bit32 out_FB = 0;
  for ( bit16 i = 0; i < MAX_X; i++)
  {
    for ( bit16 j = 0; j < MAX_Y; j = j + 4)
    {
      unsigned int b0 = frame_buffer[i][j + 0];
      unsigned int b1 = frame_buffer[i][j + 1];
      unsigned int b2 = frame_buffer[i][j + 2];
      unsigned int b3 = frame_buffer[i][j + 3];
      out_FB = (b0) | (b1 << 8) | (b2 << 16) | (b3 << 24);
      output[i * MAX_Y / 4 + j / 4] = out_FB;
    }
  }
}

void rendering( bit32 input[3*NUM_3D_TRI], bit32 output[NUM_FB])
{
  Triangle_3D triangle_3ds;
  Triangle_2D triangle_2ds;
  Triangle_2D triangle_2ds_same;
  bit16 size_fragment;
  CandidatePixel fragment[500];
  bit16 size_pixels;
  Pixel pixels[500];
  bit8 frame_buffer[MAX_X][MAX_Y];
  bit2 angle = 0;
  bit8 max_min[5];
  bit16 max_index[1];
  bit2 flag;

  for (bit16 i = 0; i < NUM_3D_TRI; i++)
  {
    bit32 input_lo  = input[3*i];
    bit32 input_mi  = input[3*i+1];
    bit32 input_hi  = input[3*i+2];

    triangle_3ds.x0 = (bit8)(input_lo & 0xFF);
    triangle_3ds.y0 = (bit8)((input_lo >> 8) & 0xFF);
    triangle_3ds.z0 = (bit8)((input_lo >> 16) & 0xFF);
    triangle_3ds.x1 = (bit8)((input_lo >> 24) & 0xFF);
    triangle_3ds.y1 = (bit8)(input_mi & 0xFF);
    triangle_3ds.z1 = (bit8)((input_mi >> 8) & 0xFF);
    triangle_3ds.x2 = (bit8)((input_mi >> 16) & 0xFF);
    triangle_3ds.y2 = (bit8)((input_mi >> 24) & 0xFF);
    triangle_3ds.z2 = (bit8)(input_hi & 0xFF);

    projection( triangle_3ds, &triangle_2ds, angle );
    flag = rasterization1( triangle_2ds, max_min, &triangle_2ds_same, max_index);
    size_fragment = rasterization2( flag, max_min, max_index, triangle_2ds_same, fragment );
    size_pixels = zculling( i, fragment, size_fragment, pixels);
    coloringFB ( i, size_pixels, pixels, frame_buffer);
  }

  output_FB(frame_buffer,output);
}

int main()
{
  bit32 *input = (bit32*)malloc(sizeof(bit32) * 3 * NUM_3D_TRI);
  bit32 *output = (bit32*)malloc(sizeof(bit32) * NUM_FB);
  if (!input || !output) return 1;
  for (int i = 0; i < NUM_3D_TRI; i++)
  {
    bit8 x0 = (bit8)(i & 0xFF);
    bit8 y0 = (bit8)((i*2) & 0xFF);
    bit8 z0 = (bit8)((i*3) & 0xFF);
    bit8 x1 = (bit8)((i*4) & 0xFF);
    bit8 y1 = (bit8)((i*5) & 0xFF);
    bit8 z1 = (bit8)((i*6) & 0xFF);
    bit8 x2 = (bit8)((i*7) & 0xFF);
    bit8 y2 = (bit8)((i*8) & 0xFF);
    bit8 z2 = (bit8)((i*9) & 0xFF);
    bit32 in0 = ((bit32)x0) | (((bit32)y0) << 8) | (((bit32)z0) << 16) | (((bit32)x1) << 24);
    bit32 in1 = ((bit32)y1) | (((bit32)z1) << 8) | (((bit32)x2) << 16) | (((bit32)y2) << 24);
    bit32 in2 = ((bit32)z2);
    input[3*i] = in0;
    input[3*i+1] = in1;
    input[3*i+2] = in2;
  }
  rendering(input, output);
  for (int i = 0; i < 16 && i < NUM_FB; i++)
  {
    printf("output[%d] = 0x%08x\n", i, output[i]);
  }
  free(input);
  free(output);
  return 0;
}

c_tb:
/*
 C testbench (standalone C, not C++).
 - Produces c_output.csv with header row (column names) and second row (roles meta/in/out).
 - Input columns printed as decimal integers.
 - Output columns printed as uppercase hexadecimal without "0x".
 - Explicitly closes CSV file.
 - Exercises functions/branches to achieve high coverage.
*/

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>

#ifndef __TYPEDEFS_H__
#define __TYPEDEFS_H__

enum { MAX_X = 256, MAX_Y = 256 };
enum { NUM_FB = MAX_X * MAX_Y / 4 };
enum { NUM_3D_TRI = 3192 };

typedef unsigned char bit1;
typedef unsigned char bit2;
typedef unsigned char bit8;
typedef unsigned short bit16;
typedef unsigned int bit32;

typedef struct
{
  bit8   x0;
  bit8   y0;
  bit8   z0;
  bit8   x1;
  bit8   y1;
  bit8   z1;
  bit8   x2;
  bit8   y2;
  bit8   z2;
} Triangle_3D;

typedef struct
{
  bit8   x0;
  bit8   y0;
  bit8   x1;
  bit8   y1;
  bit8   x2;
  bit8   y2;
  bit8   z;
} Triangle_2D;

typedef struct
{
  bit8   x;
  bit8   y;
  bit8   z;
  bit8   color;
} CandidatePixel;

typedef struct
{
  bit8   x;
  bit8   y;
  bit8   color;
} Pixel;

#endif

/* --- DUT functions (copied/filled from provided source) --- */

int check_clockwise( Triangle_2D triangle_2d )
{
  int cw;
  cw = (triangle_2d.x2 - triangle_2d.x0) * (triangle_2d.y1 - triangle_2d.y0)
       - (triangle_2d.y2 - triangle_2d.y0) * (triangle_2d.x1 - triangle_2d.x0);
  return cw;
}

void clockwise_vertices( Triangle_2D *triangle_2d )
{
  bit8 tmp_x, tmp_y;
  tmp_x = triangle_2d->x0;
  tmp_y = triangle_2d->y0;
  triangle_2d->x0 = triangle_2d->x1;
  triangle_2d->y0 = triangle_2d->y1;
  triangle_2d->x1 = tmp_x;
  triangle_2d->y1 = tmp_y;
}

bit1 pixel_in_triangle( bit8 x, bit8 y, Triangle_2D triangle_2d )
{
  int pi0, pi1, pi2;
  pi0 = (x - triangle_2d.x0) * (triangle_2d.y1 - triangle_2d.y0) - (y - triangle_2d.y0) * (triangle_2d.x1 - triangle_2d.x0);
  pi1 = (x - triangle_2d.x1) * (triangle_2d.y2 - triangle_2d.y1) - (y - triangle_2d.y1) * (triangle_2d.x2 - triangle_2d.x1);
  pi2 = (x - triangle_2d.x2) * (triangle_2d.y0 - triangle_2d.y2) - (y - triangle_2d.y2) * (triangle_2d.x0 - triangle_2d.x2);
  return (pi0 >= 0 && pi1 >= 0 && pi2 >= 0) ? 1 : 0;
}

bit8 find_min( bit8 in0, bit8 in1, bit8 in2 )
{
  if (in0 < in1)
  {
    if (in0 < in2)
      return in0;
    else 
      return in2;
  }
  else 
  {
    if (in1 < in2) 
      return in1;
    else 
      return in2;
  }
}

bit8 find_max( bit8 in0, bit8 in1, bit8 in2 )
{
  if (in0 > in1)
  {
    if (in0 > in2)
      return in0;
    else 
      return in2;
  }
  else 
  {
    if (in1 > in2) 
      return in1;
    else 
      return in2;
  }
}

void projection ( Triangle_3D triangle_3d, Triangle_2D *triangle_2d, bit2 angle )
{
  if(angle == 0)
  {
    triangle_2d->x0 = triangle_3d.x0;
    triangle_2d->y0 = triangle_3d.y0;
    triangle_2d->x1 = triangle_3d.x1;
    triangle_2d->y1 = triangle_3d.y1;
    triangle_2d->x2 = triangle_3d.x2;
    triangle_2d->y2 = triangle_3d.y2;
    triangle_2d->z  = triangle_3d.z0 / 3 + triangle_3d.z1 / 3 + triangle_3d.z2 / 3;
  }
  else if(angle == 1)
  {
    triangle_2d->x0 = triangle_3d.x0;
    triangle_2d->y0 = triangle_3d.z0;
    triangle_2d->x1 = triangle_3d.x1;
    triangle_2d->y1 = triangle_3d.z1;
    triangle_2d->x2 = triangle_3d.x2;
    triangle_2d->y2 = triangle_3d.z2;
    triangle_2d->z  = triangle_3d.y0 / 3 + triangle_3d.y1 / 3 + triangle_3d.y2 / 3;
  }
  else /* angle == 2 or others */
  {
    triangle_2d->x0 = triangle_3d.z0;
    triangle_2d->y0 = triangle_3d.y0;
    triangle_2d->x1 = triangle_3d.z1;
    triangle_2d->y1 = triangle_3d.y1;
    triangle_2d->x2 = triangle_3d.z2;
    triangle_2d->y2 = triangle_3d.y2;
    triangle_2d->z  = triangle_3d.x0 / 3 + triangle_3d.x1 / 3 + triangle_3d.x2 / 3;
  }
}

bit2 rasterization1 ( Triangle_2D triangle_2d, bit8 max_min[], Triangle_2D *triangle_2d_same, bit16 max_index[])
{
  if ( check_clockwise( triangle_2d ) == 0 )
    return 1;
  if ( check_clockwise( triangle_2d ) < 0 )
    clockwise_vertices( &triangle_2d );

  triangle_2d_same->x0 = triangle_2d.x0;
  triangle_2d_same->y0 = triangle_2d.y0;
  triangle_2d_same->x1 = triangle_2d.x1;
  triangle_2d_same->y1 = triangle_2d.y1;
  triangle_2d_same->x2 = triangle_2d.x2;
  triangle_2d_same->y2 = triangle_2d.y2;
  triangle_2d_same->z  = triangle_2d.z ;

  max_min[0] = find_min( triangle_2d.x0, triangle_2d.x1, triangle_2d.x2 );
  max_min[1] = find_max( triangle_2d.x0, triangle_2d.x1, triangle_2d.x2 );
  max_min[2] = find_min( triangle_2d.y0, triangle_2d.y1, triangle_2d.y2 );
  max_min[3] = find_max( triangle_2d.y0, triangle_2d.y1, triangle_2d.y2 );
  max_min[4] = (bit8)(max_min[1] - max_min[0]);

  max_index[0] = (max_min[1] - max_min[0]) * (max_min[3] - max_min[2]);

  return 0;
}

bit16 rasterization2 ( bit2 flag, bit8 max_min[], bit16 max_index[], Triangle_2D triangle_2d_same, CandidatePixel fragment2[] )
{
  if ( flag )
  {
    return 0;
  }
  bit8 color = 100;
  bit16 i = 0;
  for ( bit16 k = 0; k < 100 ; k++ )
  {
    bit8 x = max_min[0];
    bit8 y = max_min[2];
    if (max_min[4] != 0) {
      x = (bit8)(max_min[0] + (bit8)(k % max_min[4]));
      y = (bit8)(max_min[2] + (bit8)(k / max_min[4]));
    }
    if( pixel_in_triangle( x, y, triangle_2d_same ) )
    {
      fragment2[i].x = x;
      fragment2[i].y = y;
      fragment2[i].z = triangle_2d_same.z;
      fragment2[i].color = color;
      i++;
      if (i >= 500) break;
    }
  }
  return i;
}

bit16 zculling ( bit16 counter, CandidatePixel fragments[], bit16 size, Pixel pixels[])
{
  static bit8 z_buffer[MAX_X][MAX_Y];
  if (counter == 0)
  {
    for ( bit16 i = 0; i < MAX_X; i++)
    {
      for ( bit16 j = 0; j < MAX_Y; j++)
      {
        z_buffer[i][j] = 255;
      }
    }
  }
  bit16 pixel_cntr = 0;
  for ( bit16 n = 0; n < 100 ; n++ )
  {
    bit8 fx = fragments[n].x;
    bit8 fy = fragments[n].y;
    if (fx < MAX_X && fy < MAX_Y) {
      if( fragments[n].z < z_buffer[fy][fx] )
      {
        pixels[pixel_cntr].x     = fragments[n].x;
        pixels[pixel_cntr].y     = fragments[n].y;
        pixels[pixel_cntr].color = fragments[n].color;
        pixel_cntr++;
        z_buffer[fragments[n].y][fragments[n].x] = fragments[n].z;
        if (pixel_cntr >= 500) break;
      }
    }
  }
  return pixel_cntr;
}

void coloringFB(bit16 counter,  bit16 size_pixels, Pixel pixels[], bit8 frame_buffer[MAX_X][MAX_Y])
{
  if ( counter == 0 )
  {
    for ( bit16 i = 0; i < MAX_X; i++)
    {
      for ( bit16 j = 0; j < MAX_Y; j++)
        frame_buffer[i][j] = 0;
    }
  }
  /* Note: original code loops to 10000, so for direct calls pass an array at least that big.
     rendering() uses smaller arrays and has a potential UB; we keep original logic but
     avoid direct OOB by providing large arrays in direct unit tests below. */
  for ( int i = 0; i < 10000 ; i++)
  {
    bit8 px = pixels[i].x;
    bit8 py = pixels[i].y;
    if (px < MAX_X && py < MAX_Y)
      frame_buffer[ px ][ py ] = pixels[i].color;
  }
}

void output_FB(bit8 frame_buffer[MAX_X][MAX_Y], bit32 output[NUM_FB])
{
  bit32 out_FB = 0;
  for ( bit16 i = 0; i < MAX_X; i++)
  {
    for ( bit16 j = 0; j < MAX_Y; j = j + 4)
    {
      unsigned int b0 = frame_buffer[i][j + 0];
      unsigned int b1 = frame_buffer[i][j + 1];
      unsigned int b2 = frame_buffer[i][j + 2];
      unsigned int b3 = frame_buffer[i][j + 3];
      out_FB = (b0) | (b1 << 8) | (b2 << 16) | (b3 << 24);
      output[i * MAX_Y / 4 + j / 4] = out_FB;
    }
  }
}

void rendering( bit32 input[3*NUM_3D_TRI], bit32 output[NUM_FB])
{
  Triangle_3D triangle_3ds;
  Triangle_2D triangle_2ds;
  Triangle_2D triangle_2ds_same;
  bit16 size_fragment;
  CandidatePixel fragment[500];
  bit16 size_pixels;
  Pixel pixels[500];
  bit8 frame_buffer[MAX_X][MAX_Y];
  bit2 angle = 0;
  bit8 max_min[5];
  bit16 max_index[1];
  bit2 flag;

  for (bit16 i = 0; i < NUM_3D_TRI; i++)
  {
    bit32 input_lo  = input[3*i];
    bit32 input_mi  = input[3*i+1];
    bit32 input_hi  = input[3*i+2];

    triangle_3ds.x0 = (bit8)(input_lo & 0xFF);
    triangle_3ds.y0 = (bit8)((input_lo >> 8) & 0xFF);
    triangle_3ds.z0 = (bit8)((input_lo >> 16) & 0xFF);
    triangle_3ds.x1 = (bit8)((input_lo >> 24) & 0xFF);
    triangle_3ds.y1 = (bit8)(input_mi & 0xFF);
    triangle_3ds.z1 = (bit8)((input_mi >> 8) & 0xFF);
    triangle_3ds.x2 = (bit8)((input_mi >> 16) & 0xFF);
    triangle_3ds.y2 = (bit8)((input_mi >> 24) & 0xFF);
    triangle_3ds.z2 = (bit8)(input_hi & 0xFF);

    /* vary angle for coverage */
    angle = (bit2)(i % 3);

    projection( triangle_3ds, &triangle_2ds, angle );
    flag = rasterization1( triangle_2ds, max_min, &triangle_2ds_same, max_index);
    size_fragment = rasterization2( flag, max_min, max_index, triangle_2ds_same, fragment );
    size_pixels = zculling( i, fragment, size_fragment, pixels);
    coloringFB ( i, size_pixels, pixels, frame_buffer);
  }

  output_FB(frame_buffer,output);
}

/* --- Testbench main: create inputs, call rendering many times, write CSV --- */

int main(void)
{
  const int CYCLES = 32; /* number of cycles to drive triangle 0 with different values */

  bit32 *input = (bit32*)malloc(sizeof(bit32) * 3 * NUM_3D_TRI);
  bit32 *output = (bit32*)malloc(sizeof(bit32) * NUM_FB);
  if (!input || !output) {
    if (input) free(input);
    if (output) free(output);
    return 1;
  }

  /* Initialize input array deterministically (like original) */
  for (int i = 0; i < NUM_3D_TRI; i++)
  {
    bit8 x0 = (bit8)(i & 0xFF);
    bit8 y0 = (bit8)((i*2) & 0xFF);
    bit8 z0 = (bit8)((i*3) & 0xFF);
    bit8 x1 = (bit8)((i*4) & 0xFF);
    bit8 y1 = (bit8)((i*5) & 0xFF);
    bit8 z1 = (bit8)((i*6) & 0xFF);
    bit8 x2 = (bit8)((i*7) & 0xFF);
    bit8 y2 = (bit8)((i*8) & 0xFF);
    bit8 z2 = (bit8)((i*9) & 0xFF);
    bit32 in0 = ((bit32)x0) | (((bit32)y0) << 8) | (((bit32)z0) << 16) | (((bit32)x1) << 24);
    bit32 in1 = ((bit32)y1) | (((bit32)z1) << 8) | (((bit32)x2) << 16) | (((bit32)y2) << 24);
    bit32 in2 = ((bit32)z2);
    input[3*i] = in0;
    input[3*i+1] = in1;
    input[3*i+2] = in2;
  }

  /* Sanity/unit tests: direct calls to cover branches not necessarily hit by rendering */
  {
    /* check_clockwise: zero, negative, positive cases */
    Triangle_2D t_col, t_neg, t_pos;
    /* collinear -> cw == 0 */
    t_col.x0 = 0; t_col.y0 = 0;
    t_col.x1 = 1; t_col.y1 = 1;
    t_col.x2 = 2; t_col.y2 = 2;
    (void)check_clockwise(t_col);                 /* cw == 0 branch */

    /* negative cw */
    t_neg.x0 = 2; t_neg.y0 = 2;
    t_neg.x1 = 1; t_neg.y1 = 1;
    t_neg.x2 = 0; t_neg.y2 = 0;
    (void)check_clockwise(t_neg);                 /* cw < 0 branch */

    /* positive cw */
    t_pos.x0 = 0; t_pos.y0 = 0;
    t_pos.x1 = 1; t_pos.y1 = 0;
    t_pos.x2 = 0; t_pos.y2 = 1;
    (void)check_clockwise(t_pos);                 /* cw > 0 branch */

    /* clockwise_vertices */
    Triangle_2D t_swap;
    t_swap.x0 = 10; t_swap.y0 = 11; t_swap.x1 = 12; t_swap.y1 = 13;
    clockwise_vertices(&t_swap);

    /* pixel_in_triangle inside & outside */
    Triangle_2D tri;
    tri.x0 = 0; tri.y0 = 0;
    tri.x1 = 10; tri.y1 = 0;
    tri.x2 = 0; tri.y2 = 10;
    (void)pixel_in_triangle(1,1,tri);   /* inside */
    (void)pixel_in_triangle(20,20,tri); /* outside */

    /* find_min / find_max */
    (void)find_min(5,3,7);
    (void)find_max(5,3,7);

    /* projection for all angles */
    Triangle_3D t3;
    t3.x0=1;t3.y0=2;t3.z0=3;
    t3.x1=4;t3.y1=5;t3.z1=6;
    t3.x2=7;t3.y2=8;t3.z2=9;
    projection(t3,&tri,0);
    projection(t3,&tri,1);
    projection(t3,&tri,2);

    /* rasterization1 flag==1 case (collinear) */
    bit8 mm[5] = {0};
    bit16 mi[1] = {0};
    Triangle_2D tri_copy;
    (void)rasterization1(t_col, mm, &tri_copy, mi); /* t_col -> should return 1 */

    /* rasterization1 with negative cw (should trigger clockwise_vertices) */
    (void)rasterization1(t_neg, mm, &tri_copy, mi); /* cw < 0 branch */

    /* rasterization1 with positive cw */
    (void)rasterization1(t_pos, mm, &tri_copy, mi); /* normal path */

    /* rasterization2: flag true early return */
    CandidatePixel frag_arr[500] = {0};
    bit16 cnt = rasterization2(1, mm, mi, tri_copy, frag_arr);
    (void)cnt;

    /* rasterization2: flag false; craft simple triangle that includes (0,0) */
    Triangle_2D small_tri;
    small_tri.x0 = 0; small_tri.y0 = 0;
    small_tri.x1 = 0; small_tri.y1 = 1;
    small_tri.x2 = 1; small_tri.y2 = 0;
    small_tri.z = 10;
    mm[0] = 0; mm[1] = 1; mm[2] = 0; mm[3] = 1; mm[4] = 1;
    cnt = rasterization2(0, mm, mi, small_tri, frag_arr);
    /* ensure at least one fragment potentially produced */
    (void)cnt;

    /* zculling: initialize z_buffer and then test fragments */
    Pixel pixel_out[600]; /* larger to be safe for zculling/pixel count */
    CandidatePixel fragments100[100];
    for (int i = 0; i < 100; ++i) {
      fragments100[i].x = (bit8)(i & 0xFF);
      fragments100[i].y = (bit8)((i/2) & 0xFF);
      fragments100[i].z = 50; /* less than initial 255 */
      fragments100[i].color = (bit8)(i & 0xFF);
    }
    /* counter==0 should initialize z_buffer */
    bit16 pixels_found = zculling(0, fragments100, 100, pixel_out);
    (void)pixels_found;
    /* subsequent call should allow some fragments through again if z lower */
    for (int i = 0; i < 100; ++i) fragments100[i].z = 40;
    pixels_found = zculling(1, fragments100, 100, pixel_out);
    (void)pixels_found;

    /* coloringFB: supply a large pixels array to avoid OOB in the DUT's 10000 loop */
    Pixel big_pixels[10000];
    for (int i = 0; i < 10000; ++i) { big_pixels[i].x = 0; big_pixels[i].y = 0; big_pixels[i].color = 0; }
    /* set a few scattered pixels */
    big_pixels[0].x = 1; big_pixels[0].y = 2; big_pixels[0].color = 77;
    big_pixels[1].x = 3; big_pixels[1].y = 4; big_pixels[1].color = 88;
    bit8 frame_buffer[MAX_X][MAX_Y];
    coloringFB(0, 2, big_pixels, frame_buffer); /* counter==0 will clear then set */
    /* output_FB to produce some outputs */
    bit32 out_fb[NUM_FB];
    output_FB(frame_buffer, out_fb);
    /* use out_fb values to avoid unused warnings */
    (void)out_fb[0];
  }

  /* Open CSV file */
  FILE *csv = fopen("c_output.csv", "w");
  if (!csv) {
    free(input);
    free(output);
    return 1;
  }

  /* CSV header: cycle,in_tri0_lo,in_tri0_mi,in_tri0_hi,output_0..output_15 */
  fprintf(csv, "cycle,in_tri0_lo,in_tri0_mi,in_tri0_hi");
  for (int i = 0; i < 16; i++) {
    fprintf(csv, ",output_%d", i);
  }
  fprintf(csv, "\n");

  /* Roles row: meta,in,in,in, then outs */
  fprintf(csv, "meta,in,in,in");
  for (int i = 0; i < 16; i++) {
    fprintf(csv, ",out");
  }
  fprintf(csv, "\n");

  /* Drive a deterministic sequence of cycles. On each cycle modify triangle 0 input words deterministically. */
  for (int cycle = 0; cycle < CYCLES; cycle++)
  {
    /* Construct triangle 0 fields based on cycle (deterministic) to exercise many patterns */
    bit8 x0 = (bit8)(cycle & 0xFF);
    bit8 y0 = (bit8)((cycle * 2) & 0xFF);
    bit8 z0 = (bit8)((cycle * 3) & 0xFF);
    bit8 x1 = (bit8)((cycle * 4 + 1) & 0xFF);
    bit8 y1 = (bit8)((cycle * 5 + 2) & 0xFF);
    bit8 z1 = (bit8)((cycle * 6 + 3) & 0xFF);
    bit8 x2 = (bit8)((cycle * 7 + 4) & 0xFF);
    bit8 y2 = (bit8)((cycle * 8 + 5) & 0xFF);
    bit8 z2 = (bit8)((cycle * 9 + 6) & 0xFF);

    bit32 in_tri0_lo = ((bit32)x0) | (((bit32)y0) << 8) | (((bit32)z0) << 16) | (((bit32)x1) << 24);
    bit32 in_tri0_mi = ((bit32)y1) | (((bit32)z1) << 8) | (((bit32)x2) << 16) | (((bit32)y2) << 24);
    bit32 in_tri0_hi = ((bit32)z2);

    /* Drive inputs: update triangle 0 words only, keep others as initialized */
    input[0] = in_tri0_lo;
    input[1] = in_tri0_mi;
    input[2] = in_tri0_hi;

    /* Call DUT */
    rendering(input, output);

    /* Write CSV row: cycle (decimal), inputs decimal, outputs hex uppercase (no 0x) */
    fprintf(csv, "%d,%u,%u,%u", cycle, (unsigned int)in_tri0_lo, (unsigned int)in_tri0_mi, (unsigned int)in_tri0_hi);
    for (int i = 0; i < 16; i++) {
      if (i < NUM_FB) {
        fprintf(csv, ",%X", (unsigned int)output[i]);
      } else {
        fprintf(csv, ",0");
      }
    }
    fprintf(csv, "\n");
  }

  /* Explicitly close CSV file */
  fclose(csv);

  free(input);
  free(output);
  return 0;
}

