// hls.cpp
// HLS implementation matching original C reference behavior.
// Comments in English.
// This version preserves the original (functional) behavior
// of the C testbench (including the original bounding-box, rasterization,
// z-culling and frame-buffer write patterns) so that C and HLS outputs match.
// Note: minor safety fix in coloringFB to avoid out-of-bounds access during CSim
// while preserving the intended write pattern semantics.

#include <stdint.h>

#define MAX_X 256
#define MAX_Y 256
#define NUM_FB (MAX_X * MAX_Y / 4)
#define NUM_3D_TRI 3192

typedef uint8_t bit8;
typedef uint16_t bit16;
typedef uint32_t bit32;
typedef uint8_t bit2;
typedef uint8_t bit1;

typedef struct {
  bit8 x0;
  bit8 y0;
  bit8 z0;
  bit8 x1;
  bit8 y1;
  bit8 z1;
  bit8 x2;
  bit8 y2;
  bit8 z2;
} Triangle_3D;

typedef struct {
  bit8 x0;
  bit8 y0;
  bit8 x1;
  bit8 y1;
  bit8 x2;
  bit8 y2;
  bit8 z;
} Triangle_2D;

typedef struct {
  bit8 x;
  bit8 y;
  bit8 z;
  bit8 color;
} CandidatePixel;

typedef struct {
  bit8 x;
  bit8 y;
  bit8 color;
} Pixel;

/* Compute cross product test for clockwise check */
static int check_clockwise(Triangle_2D triangle_2d) {
  int cw;
  cw = (triangle_2d.x2 - triangle_2d.x0) * (triangle_2d.y1 - triangle_2d.y0)
       - (triangle_2d.y2 - triangle_2d.y0) * (triangle_2d.x1 - triangle_2d.x0);
  return cw;
}

/* Swap v0 and v1 to change winding */
static void clockwise_vertices(Triangle_2D *triangle_2d) {
  bit8 tmp_x = triangle_2d->x0;
  bit8 tmp_y = triangle_2d->y0;
  triangle_2d->x0 = triangle_2d->x1;
  triangle_2d->y0 = triangle_2d->y1;
  triangle_2d->x1 = tmp_x;
  triangle_2d->y1 = tmp_y;
}

/* Test whether pixel is inside triangle using edge functions */
static bit1 pixel_in_triangle(bit8 x, bit8 y, Triangle_2D triangle_2d) {
  int pi0 = (x - triangle_2d.x0) * (triangle_2d.y1 - triangle_2d.y0) - (y - triangle_2d.y0) * (triangle_2d.x1 - triangle_2d.x0);
  int pi1 = (x - triangle_2d.x1) * (triangle_2d.y2 - triangle_2d.y1) - (y - triangle_2d.y1) * (triangle_2d.x2 - triangle_2d.x1);
  int pi2 = (x - triangle_2d.x2) * (triangle_2d.y0 - triangle_2d.y2) - (y - triangle_2d.y2) * (triangle_2d.x0 - triangle_2d.x2);
  return (pi0 >= 0 && pi1 >= 0 && pi2 >= 0) ? 1 : 0;
}

/* Find min of three values */
static bit8 find_min(bit8 in0, bit8 in1, bit8 in2) {
  if (in0 < in1) {
    if (in0 < in2) return in0; else return in2;
  } else {
    if (in1 < in2) return in1; else return in2;
  }
}

/* Find max of three values */
static bit8 find_max(bit8 in0, bit8 in1, bit8 in2) {
  if (in0 > in1) {
    if (in0 > in2) return in0; else return in2;
  } else {
    if (in1 > in2) return in1; else return in2;
  }
}

/* Project 3D triangle to 2D based on 'angle' selector */
static void projection(Triangle_3D triangle_3d, Triangle_2D *triangle_2d, bit2 angle) {
#pragma HLS INLINE off
  if (angle == 0) {
    triangle_2d->x0 = triangle_3d.x0;
    triangle_2d->y0 = triangle_3d.y0;
    triangle_2d->x1 = triangle_3d.x1;
    triangle_2d->y1 = triangle_3d.y1;
    triangle_2d->x2 = triangle_3d.x2;
    triangle_2d->y2 = triangle_3d.y2;
    triangle_2d->z = triangle_3d.z0 / 3 + triangle_3d.z1 / 3 + triangle_3d.z2 / 3;
  } else if (angle == 1) {
    triangle_2d->x0 = triangle_3d.x0;
    triangle_2d->y0 = triangle_3d.z0;
    triangle_2d->x1 = triangle_3d.x1;
    triangle_2d->y1 = triangle_3d.z1;
    triangle_2d->x2 = triangle_3d.x2;
    triangle_2d->y2 = triangle_3d.z2;
    triangle_2d->z = triangle_3d.y0 / 3 + triangle_3d.y1 / 3 + triangle_3d.y2 / 3;
  } else if (angle == 2) {
    triangle_2d->x0 = triangle_3d.z0;
    triangle_2d->y0 = triangle_3d.y0;
    triangle_2d->x1 = triangle_3d.z1;
    triangle_2d->y1 = triangle_3d.y1;
    triangle_2d->x2 = triangle_3d.z2;
    triangle_2d->y2 = triangle_3d.y2;
    triangle_2d->z = triangle_3d.x0 / 3 + triangle_3d.x1 / 3 + triangle_3d.x2 / 3;
  }
}

/* Rasterization stage 1:
   - Check winding and reorder vertices if needed.
   - Compute min/max ranges and area estimate.
   - Return flag==1 to indicate "skip" (degenerate or invalid) only when winding==0.
   Note: Behavior intentionally matches original C reference (no additional zero-width guard).
*/
static bit2 rasterization1(Triangle_2D triangle_2d, bit8 max_min[5], Triangle_2D *triangle_2d_same, bit16 max_index[1]) {
#pragma HLS INLINE off
  if (check_clockwise(triangle_2d) == 0) return 1;
  if (check_clockwise(triangle_2d) < 0) clockwise_vertices(&triangle_2d);

  triangle_2d_same->x0 = triangle_2d.x0;
  triangle_2d_same->y0 = triangle_2d.y0;
  triangle_2d_same->x1 = triangle_2d.x1;
  triangle_2d_same->y1 = triangle_2d.y1;
  triangle_2d_same->x2 = triangle_2d.x2;
  triangle_2d_same->y2 = triangle_2d.y2;
  triangle_2d_same->z = triangle_2d.z;

  max_min[0] = find_min(triangle_2d.x0, triangle_2d.x1, triangle_2d.x2);
  max_min[1] = find_max(triangle_2d.x0, triangle_2d.x1, triangle_2d.x2);
  max_min[2] = find_min(triangle_2d.y0, triangle_2d.y1, triangle_2d.y2);
  max_min[3] = find_max(triangle_2d.y0, triangle_2d.y1, triangle_2d.y2);
  max_min[4] = (bit8)(max_min[1] - max_min[0]);

  max_index[0] = (bit16)((max_min[1] - max_min[0]) * (max_min[3] - max_min[2]));

  return 0;
}

/* Rasterization stage 2:
   - Generate candidate fragment list inside bounding box.
   - Preserve original behavior: if width==0, x and y remain at min values (no division by zero).
*/
static bit16 rasterization2(bit2 flag, bit8 max_min[5], bit16 max_index[1], Triangle_2D triangle_2d_same, CandidatePixel fragment2[500]) {
#pragma HLS INLINE off
  if (flag) return 0;
  bit8 color = 100;
  bit16 i = 0;
  for (bit16 k = 0; k < 100; k++) {
#pragma HLS unroll factor=2
    bit8 x = max_min[0];
    bit8 y = max_min[2];
    if (max_min[4] != 0) {
      x = max_min[0] + (bit8)(k % max_min[4]);
      y = max_min[2] + (bit8)(k / max_min[4]);
    }
    if (pixel_in_triangle(x, y, triangle_2d_same)) {
      fragment2[i].x = x;
      fragment2[i].y = y;
      fragment2[i].z = triangle_2d_same.z;
      fragment2[i].color = color;
      i++;
      if (i >= 500) break;
    }
  }
  return i;
}

/* Z-culling:
   - Initialize z-buffer at the first triangle (counter==0).
   - Iterate exactly 100 candidate slots (matching original reference) and apply z-test.
   - Preserve original indexing pattern.
   Note: z-buffer indexing uses [x][y] consistent with frame buffer layout.
*/
static bit16 zculling(bit16 counter, CandidatePixel fragments[500], bit16 size, Pixel pixels[500]) {
#pragma HLS INLINE off
  static bit8 z_buffer[MAX_X][MAX_Y];
#pragma HLS array_partition variable=z_buffer block factor=4 dim=2
  if (counter == 0) {
    for (bit16 i = 0; i < MAX_X; i++) {
#pragma HLS unroll factor=32
      for (bit16 j = 0; j < MAX_Y; j++) {
#pragma HLS unroll factor=8
        z_buffer[i][j] = 255;
      }
    }
  }

  bit16 pixel_cntr = 0;
  /* Iterate fixed 100 slots just like the original code (even if fewer fragments were produced) */
  for (bit16 n = 0; n < 100; n++) {
#pragma HLS unroll factor=8
    bit8 fx = fragments[n].x;
    bit8 fy = fragments[n].y;
    /* Use consistent [x][y] indexing for z-buffer to match frame buffer */
    if (fx < MAX_X && fy < MAX_Y) {
      if (fragments[n].z < z_buffer[fx][fy]) {
        pixels[pixel_cntr].x = fragments[n].x;
        pixels[pixel_cntr].y = fragments[n].y;
        pixels[pixel_cntr].color = fragments[n].color;
        pixel_cntr++;
        z_buffer[fx][fy] = fragments[n].z;
        if (pixel_cntr >= 500) break;
      }
    }
  }
  return pixel_cntr;
}

/* Color the frame buffer based on pixels list.
   - Initialize frame buffer when counter==0.
   - Write using a large fixed loop (10000) matching the original reference,
     but guard accesses to avoid out-of-bounds reads in CSim.
   - If no pixels are present (size_pixels == 0) this will skip writes.
   - If fewer pixels than 10000 are present, the writes repeat the existing pixels
     (wrap-around) to emulate repeated writing pattern while staying memory-safe.
*/
static void coloringFB(bit16 counter, bit16 size_pixels, Pixel pixels[500], bit8 frame_buffer[MAX_X][MAX_Y]) {
#pragma HLS INLINE off
  if (counter == 0) {
    for (bit16 i = 0; i < MAX_X; i++) {
#pragma HLS pipeline II=1
      for (bit16 j = 0; j < MAX_Y; j++) {
#pragma HLS unroll factor=2
        frame_buffer[i][j] = 0;
      }
    }
  }
  /* Original behavior writes through 10000 entries (500 * 20) irrespective of size_pixels.
     For simulation safety we avoid out-of-bounds by wrapping when size_pixels > 0.
     If size_pixels == 0 we do nothing. */
  for (int i = 0; i < 10000; i++) {
#pragma HLS pipeline
    if (size_pixels == 0) break;
    bit16 idx = (i < size_pixels) ? (bit16)i : (bit16)(i % size_pixels);
    bit8 px = pixels[idx].x;
    bit8 py = pixels[idx].y;
    if (px < MAX_X && py < MAX_Y) {
      frame_buffer[px][py] = pixels[idx].color;
    }
  }
}

/* Pack frame buffer into output words (4 pixels per 32-bit word) */
static void output_FB(bit8 frame_buffer[MAX_X][MAX_Y], bit32 output[NUM_FB]) {
#pragma HLS INLINE
  bit32 out_FB = 0;
  for (bit16 i = 0; i < MAX_X; i++) {
#pragma HLS unroll factor=8
    for (bit16 j = 0; j < MAX_Y; j += 4) {
#pragma HLS pipeline
      out_FB = (bit32)frame_buffer[i][j + 0] | ((bit32)frame_buffer[i][j + 1] << 8) | ((bit32)frame_buffer[i][j + 2] << 16) | ((bit32)frame_buffer[i][j + 3] << 24);
      output[i * (MAX_Y / 4) + (j / 4)] = out_FB;
    }
  }
}

/* Top-level rendering function with C linkage for HLS */
extern "C" {
void rendering(bit32 input[3 * NUM_3D_TRI], bit32 output[NUM_FB]) {
#pragma HLS INTERFACE m_axi port=input offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=output offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=input bundle=control
#pragma HLS INTERFACE s_axilite port=output bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

  Triangle_3D triangle_3ds;
  Triangle_2D triangle_2ds;
  Triangle_2D triangle_2ds_same;

  bit16 size_fragment;
  CandidatePixel fragment[500];
#pragma HLS array_partition variable=fragment cyclic factor=8 dim=1

  bit16 size_pixels;
  Pixel pixels[500];
#pragma HLS array_partition variable=pixels cyclic factor=8 dim=1

  bit8 frame_buffer[MAX_X][MAX_Y];
#pragma HLS array_partition variable=frame_buffer cyclic factor=4 dim=2
  bit2 angle = 0;

  bit8 max_min[5];
#pragma HLS array_partition variable=max_min complete dim=1
  bit16 max_index[1];
#pragma HLS array_partition variable=max_index complete dim=1
  bit2 flag;

  for (bit16 i = 0; i < NUM_3D_TRI; i++) {
#ifdef ENABLE_DATAFLOW
#pragma HLS dataflow
#endif
    /* Ensure first 100 fragment slots are deterministic (avoid reading uninitialized memory
       later in zculling which iterates fixed 100 slots). This keeps simulation deterministic
       and safe while preserving the intent of the original algorithm. */
    for (bit16 fi = 0; fi < 100; fi++) {
#pragma HLS unroll factor=8
      fragment[fi].x = 0;
      fragment[fi].y = 0;
      fragment[fi].z = 0;
      fragment[fi].color = 0;
    }

    bit32 input_lo = input[3 * i];
    bit32 input_mi = input[3 * i + 1];
    bit32 input_hi = input[3 * i + 2];

    triangle_3ds.x0 = (bit8)(input_lo & 0xFF);
    triangle_3ds.y0 = (bit8)((input_lo >> 8) & 0xFF);
    triangle_3ds.z0 = (bit8)((input_lo >> 16) & 0xFF);
    triangle_3ds.x1 = (bit8)((input_lo >> 24) & 0xFF);
    triangle_3ds.y1 = (bit8)(input_mi & 0xFF);
    triangle_3ds.z1 = (bit8)((input_mi >> 8) & 0xFF);
    triangle_3ds.x2 = (bit8)((input_mi >> 16) & 0xFF);
    triangle_3ds.y2 = (bit8)((input_mi >> 24) & 0xFF);
    triangle_3ds.z2 = (bit8)(input_hi & 0xFF);

    projection(triangle_3ds, &triangle_2ds, angle);
    flag = rasterization1(triangle_2ds, max_min, &triangle_2ds_same, max_index);
    size_fragment = rasterization2(flag, max_min, max_index, triangle_2ds_same, fragment);
    size_pixels = zculling(i, fragment, size_fragment, pixels);
    coloringFB(i, size_pixels, pixels, frame_buffer);
  }

  output_FB(frame_buffer, output);
}
} // extern "C"

