// Testbench for HLS cosimulation.
// Comments in English.
// Note: avoid <cstdint> to maintain compatibility with older libstdc++ shipped with Vivado HLS.

#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <stdint.h>

#ifndef __TYPEDEFS_H__
#define __TYPEDEFS_H__

const int MAX_X = 256;
const int MAX_Y = 256;

const int NUM_FB = MAX_X * MAX_Y / 4;

const int NUM_3D_TRI = 3192;

typedef unsigned char bit1;
typedef unsigned char bit2;
typedef unsigned char bit8;
typedef unsigned short bit16;
typedef unsigned int bit32;

typedef struct
{
  bit8   x0;
  bit8   y0;
  bit8   z0;
  bit8   x1;
  bit8   y1;
  bit8   z1;
  bit8   x2;
  bit8   y2;
  bit8   z2;
} Triangle_3D;

typedef struct
{
  bit8   x0;
  bit8   y0;
  bit8   x1;
  bit8   y1;
  bit8   x2;
  bit8   y2;
  bit8   z;
} Triangle_2D;

typedef struct
{
  bit8   x;
  bit8   y;
  bit8   z;
  bit8   color;
} CandidatePixel;

typedef struct
{
  bit8   x;
  bit8   y;
  bit8   color;
} Pixel;

#define ENABLE_DATAFLOW

#endif

// DUT prototype must match HLSC top-level function
extern "C" {
void rendering( bit32 input[3*NUM_3D_TRI], bit32 output[NUM_FB]);
}

int main()
{
  // We'll drive 3 input words for triangle 0 as scalar test signals:
  // in_tri0_lo, in_tri0_mi, in_tri0_hi
  // We'll sample outputs output_0 .. output_15
  const int CYCLES = 32;
  bit32 *input = (bit32*)malloc(sizeof(bit32) * 3 * NUM_3D_TRI);
  bit32 *output = (bit32*)malloc(sizeof(bit32) * NUM_FB);
  if (!input || !output) {
    if (input) free(input);
    if (output) free(output);
    return 1;
  }

  // Initialize input array deterministically as in original main
  for (int i = 0; i < NUM_3D_TRI; i++)
  {
    bit8 x0 = (bit8)(i & 0xFF);
    bit8 y0 = (bit8)((i*2) & 0xFF);
    bit8 z0 = (bit8)((i*3) & 0xFF);
    bit8 x1 = (bit8)((i*4) & 0xFF);
    bit8 y1 = (bit8)((i*5) & 0xFF);
    bit8 z1 = (bit8)((i*6) & 0xFF);
    bit8 x2 = (bit8)((i*7) & 0xFF);
    bit8 y2 = (bit8)((i*8) & 0xFF);
    bit8 z2 = (bit8)((i*9) & 0xFF);
    bit32 in0 = ((bit32)x0) | (((bit32)y0) << 8) | (((bit32)z0) << 16) | (((bit32)x1) << 24);
    bit32 in1 = ((bit32)y1) | (((bit32)z1) << 8) | (((bit32)x2) << 16) | (((bit32)y2) << 24);
    bit32 in2 = ((bit32)z2);
    input[3*i] = in0;
    input[3*i+1] = in1;
    input[3*i+2] = in2;
  }

  // Open CSV file for HLS/RTL outputs
  FILE *csv = std::fopen("hls_output.csv", "w");
  if (!csv) {
    free(input);
    free(output);
    return 1;
  }

  // CSV header: cycle, driven inputs (testbench signal names), sampled outputs
  std::fprintf(csv, "cycle,in_tri0_lo,in_tri0_mi,in_tri0_hi");
  for (int i = 0; i < 16; i++) {
    std::fprintf(csv, ",output_%d", i);
  }
  std::fprintf(csv, "\n");

  // Roles row: meta/in/in/in,out...
  std::fprintf(csv, "meta,in,in,in");
  for (int i = 0; i < 16; i++) {
    std::fprintf(csv, ",out");
  }
  std::fprintf(csv, "\n");

  // Run deterministic sequence of cycles. On each cycle we modify triangle 0 input words deterministically.
  for (int cycle = 0; cycle < CYCLES; cycle++)
  {
    // Construct triangle 0 fields based on cycle (deterministic)
    bit8 x0 = (bit8)(cycle & 0xFF);
    bit8 y0 = (bit8)((cycle * 2) & 0xFF);
    bit8 z0 = (bit8)((cycle * 3) & 0xFF);
    bit8 x1 = (bit8)((cycle * 4 + 1) & 0xFF);
    bit8 y1 = (bit8)((cycle * 5 + 2) & 0xFF);
    bit8 z1 = (bit8)((cycle * 6 + 3) & 0xFF);
    bit8 x2 = (bit8)((cycle * 7 + 4) & 0xFF);
    bit8 y2 = (bit8)((cycle * 8 + 5) & 0xFF);
    bit8 z2 = (bit8)((cycle * 9 + 6) & 0xFF);

    bit32 in_tri0_lo = ((bit32)x0) | (((bit32)y0) << 8) | (((bit32)z0) << 16) | (((bit32)x1) << 24);
    bit32 in_tri0_mi = ((bit32)y1) | (((bit32)z1) << 8) | (((bit32)x2) << 16) | (((bit32)y2) << 24);
    bit32 in_tri0_hi = ((bit32)z2);

    // Drive inputs: update triangle 0 words only, keep others as initialized
    input[0] = in_tri0_lo;
    input[1] = in_tri0_mi;
    input[2] = in_tri0_hi;

    // Call DUT (top-level function)
    rendering(input, output);

    // Write CSV row: cycle (decimal), inputs decimal, outputs hex uppercase (no 0x)
    std::fprintf(csv, "%d,%u,%u,%u", cycle, (unsigned int)in_tri0_lo, (unsigned int)in_tri0_mi, (unsigned int)in_tri0_hi);
    for (int i = 0; i < 16; i++) {
      if (i < NUM_FB) {
        std::fprintf(csv, ",%X", (unsigned int)output[i]);
      } else {
        std::fprintf(csv, ",0");
      }
    }
    std::fprintf(csv, "\n");
  }

  // Close CSV file explicitly
  std::fclose(csv);

  free(input);
  free(output);
  return 0;
}

