void elu(data_t input[C][H][W],
         data_t output[C][H][W],
         data_t alpha)
{
    for (int c = 0; c < C; c++) {
        for (int h = 0; h < H; h++) {
            for (int w = 0; w < W; w++) {
                data_t x = input[c][h][w];
                if (x >= 0.0f) {
                    output[c][h][w] = x;
                } else {
                    output[c][h][w] = alpha * (expf(x) - 1.0f);
                }
            }
        }
    }
}

