    std::fprintf(f, ",in"); // alpha
    for (int i = 0; i < N; ++i) std::fprintf(f, ",out");
    std::fprintf(f, "\n");

    // Buffers for DUT
    data_t din[C][H][W];
    data_t dout[C][H][W];

    for (int cycle = 0; cycle < cycles; ++cycle) {
        // Load inputs for this cycle
        const std::vector<float>& vec = inputs[cycle];
        for (int idx = 0; idx < N; ++idx) {
            int c = idx / (H * W);
