// hls.cpp
// Vivado HLS top-level implementation of ELU (Exponential Linear Unit).
//
// Notes:
// - Uses C-style fixed-size arrays for HLS.
// - Top-level function 'elu' has C linkage (extern "C") as required by the testbench.
// - Sizes C, H, W are chosen to match the cosimulation testbench (C=2, H=2, W=3).
// - Use <stdint.h> instead of <cstdint> to be compatible with Vivado HLS 2018.3 C++98 mode.

#include <hls_math.h>
#include <stdint.h>

#define C 2
#define H 2
#define W 3

typedef float data_t;

// Helper functions (normal C++ linkage). These are simple memory/elementwise ops
// to be used by the top-level ELU implementation.

void load_feature_map(data_t input_dram[C][H][W], data_t input_buffer[C][H][W]) {
    for (int c = 0; c < C; c++) {
        for (int h = 0; h < H; h++) {
            for (int w = 0; w < W; w++) {
                input_buffer[c][h][w] = input_dram[c][h][w];
            }
        }
    }
}

void store_feature_map(data_t output_buffer[C][H][W], data_t output_dram[C][H][W]) {
    for (int c = 0; c < C; c++) {
        for (int h = 0; h < H; h++) {
            for (int w = 0; w < W; w++) {
                output_dram[c][h][w] = output_buffer[c][h][w];
            }
        }
    }
}

void compute_exp(data_t input[C][H][W], data_t output[C][H][W]) {
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
                output[i][j][k] = hls::exp(input[i][j][k]);
            }
        }
    }
}

void compute_add(data_t input_1[C][H][W], data_t input_2[C][H][W], data_t output[C][H][W]) {
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
                output[i][j][k] = input_1[i][j][k] + input_2[i][j][k];
            }
        }
    }
}

void compute_mul(data_t input_1[C][H][W], data_t input_2[C][H][W], data_t output[C][H][W]) {
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
                output[i][j][k] = input_1[i][j][k] * input_2[i][j][k];
            }
        }
    }
}

void set_value(data_t bram[C][H][W], data_t value) {
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
                bram[i][j][k] = value;
            }
        }
    }
}

void select(data_t input_1[C][H][W], data_t input_2[C][H][W], data_t output[C][H][W], data_t threshold) {
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
                if (input_1[i][j][k] >= threshold) {
                    output[i][j][k] = input_1[i][j][k];
                } else {
                    output[i][j][k] = input_2[i][j][k];
                }
            }
        }
    }
}

// Top-level ELU function with C linkage for HLS cosimulation.
// The interface pragmas map the input/output arrays to AXI master ports and
// expose control registers for alpha and function return.
extern "C" {

void elu(data_t input[C][H][W], data_t output[C][H][W], data_t alpha) {
    #pragma HLS INTERFACE m_axi port=input offset=slave bundle=gmem
    #pragma HLS INTERFACE m_axi port=output offset=slave bundle=gmem
    #pragma HLS INTERFACE s_axilite port=input bundle=control
    #pragma HLS INTERFACE s_axilite port=output bundle=control
    #pragma HLS INTERFACE s_axilite port=alpha bundle=control
    #pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local buffers used as BRAMs in HLS
    data_t FM_buffer_1[C][H][W];
    data_t FM_buffer_2[C][H][W];
    data_t FM_buffer_3[C][H][W];
    data_t FM_buffer_4[C][H][W];

    // Dataflow of ELU:
    // y = x if x >= 0
    // y = alpha * (exp(x) - 1) if x < 0
    load_feature_map(input, FM_buffer_1);
    compute_exp(FM_buffer_1, FM_buffer_2);
    set_value(FM_buffer_3, (data_t)-1);
    compute_add(FM_buffer_2, FM_buffer_3, FM_buffer_4); // FM_buffer_4 = exp(x) - 1
    set_value(FM_buffer_3, alpha);
    compute_mul(FM_buffer_3, FM_buffer_4, FM_buffer_2); // FM_buffer_2 = alpha * (exp(x)-1)
    select(FM_buffer_1, FM_buffer_2, FM_buffer_3, (data_t)0); // choose between x and alpha*(exp(x)-1)
    store_feature_map(FM_buffer_3, output);
}

} // extern "C"

