}

int main() {
    const int CYCLES = 32; // between 20 and 50

    // Allocate arrays
    float coord[BATCH_SIZE * DIM];
    float weight[BATCH_SIZE];
    float cost[BATCH_SIZE];
    float target[DIM];
    int assign[BATCH_SIZE];
    // center_table size choose >= possible assign values mapped to work_mem indices
    const int CENTER_TABLE_SIZE = 8;
    int center_table[CENTER_TABLE_SIZE];
    char switch_membership[BATCH_SIZE];
    // work_mem size should be >= max(center_table value)+1
    const int WORK_MEM_SIZE = 8;
    float work_mem[WORK_MEM_SIZE];
    float cost_of_opening_x_arr[1];

    // Initialize some base patterns (will be updated each cycle deterministically)
    for (int i = 0; i < BATCH_SIZE; i++) {
        for (int j = 0; j < DIM; j++) {
            coord[i * DIM + j] = float((i + 1) * (j + 2)); // base
        }
        weight[i] = 1.0f + 0.1f * i;
