        cost[i] = float((i % 2 == 0) ? 10.0f + i : 1.0f + i*0.5f);
        assign[i] = i % 4;
        switch_membership[i] = 0;
    }
    for (int j = 0; j < DIM; j++) target[j] = float(1 + j);
    for (int k = 0; k < CENTER_TABLE_SIZE; k++) center_table[k] = k % WORK_MEM_SIZE;
    for (int k = 0; k < WORK_MEM_SIZE; k++) work_mem[k] = 100.0f + k * 10.0f;
    cost_of_opening_x_arr[0] = 0.0f;

