    // Inputs chosen (integer-friendly): assign, center_table, num, numcenter
    // Outputs: switch_membership (sampled as bitmask), cost_of_opening_x (float bits), work_mem (work_mem[0] bits)
    std::fprintf(f, "cycle,assign,center_table,num,numcenter,switch_membership,cost_of_opening_x,work_mem\n");
    std::fprintf(f, "meta,in,in,in,in,out,out,out\n");

    // Simulation cycles
    for (int cycle = 0; cycle < CYCLES; cycle++) {
        // Deterministic per-cycle stimulus:
        int num = BATCH_SIZE;
        int numcenter = 4 + (cycle % 3); // vary numcenter between 4..6

        // Update coord slightly per cycle (but keep integers when possible)
        for (int i = 0; i < BATCH_SIZE; i++) {
