        int center_table_checksum = 0;
        for (int k = 0; k < numcenter; k++) center_table_checksum += center_table[k];

        // Outputs:
        // switch_membership as bitmask (bit i = value)
        uint32_t switch_mask = 0;
        for (int i = 0; i < BATCH_SIZE && i < 32; i++) {
            if (switch_membership[i]) switch_mask |= (1u << i);
        }
        uint32_t cost_bits = float_to_bits(cost_of_opening_x_arr[0]);
        uint32_t work_mem0_bits = float_to_bits(work_mem[0]);

        // Write CSV line: inputs decimal, outputs hex uppercase without 0x
        // cycle,assign,center_table,num,numcenter,switch_membership,cost_of_opening_x,work_mem
        std::fprintf(f, "%d,%d,%d,%d,%d,%X,%X,%X\n",
                     cycle,
                     assign_checksum,
                     center_table_checksum,
                     num,
                     numcenter,
                     switch_mask,
                     cost_bits,
                     work_mem0_bits);
    }

    std::fclose(f);
    return 0;
}

