// hls.cpp
// Streamcluster top-level for Vivado HLS C simulation.
// Simplified, single-buffer implementation adjusted to the small testbench sizes
// (DIM=3, BATCH_SIZE=8). Keep extern "C" top-level and the HLS INTERFACE pragmas
// so this file can be synthesized/simulated in Vivado HLS.
//
// This version adds bounds guards so the function behaves safely when the
// runtime parameters 'num' and 'numcenter' vary. It uses small local buffers
// (single-buffer approach) appropriate for the small testbench sizes.
//
// Comments and code are written to be compatible with Vivado HLS 2018.3 toolchain.

#include <stddef.h>

#define DIM 3
#define BUF_SIZE 8
#define BATCH_SIZE 8

// Top-level function with C linkage so the testbench can link to the symbol "streamcluster".
// AXI/HLS pragmas remain to allow synthesis in Vivado HLS.
extern "C" void streamcluster(
    float* coord,
    float* weight,
    float* cost,
    float* target,
    int* assign,
    int* center_table,
    char* switch_membership,
    float* work_mem,
    int num,
    float* cost_of_opening_x,
    int numcenter
) {
#pragma HLS INTERFACE m_axi port=coord offset=slave bundle=gmemf
#pragma HLS INTERFACE m_axi port=weight offset=slave bundle=gmemf
#pragma HLS INTERFACE m_axi port=cost offset=slave bundle=gmemf
#pragma HLS INTERFACE m_axi port=target offset=slave bundle=gmemf
#pragma HLS INTERFACE m_axi port=assign offset=slave bundle=gmemi
#pragma HLS INTERFACE m_axi port=center_table offset=slave bundle=gmemi
#pragma HLS INTERFACE m_axi port=switch_membership offset=slave bundle=gmemc
#pragma HLS INTERFACE m_axi port=work_mem offset=slave bundle=gmemf
#pragma HLS INTERFACE m_axi port=cost_of_opening_x offset=slave bundle=gmemf

#pragma HLS INTERFACE s_axilite port=coord bundle=control
#pragma HLS INTERFACE s_axilite port=weight bundle=control
#pragma HLS INTERFACE s_axilite port=cost bundle=control
#pragma HLS INTERFACE s_axilite port=target bundle=control
#pragma HLS INTERFACE s_axilite port=assign bundle=control
#pragma HLS INTERFACE s_axilite port=center_table bundle=control
#pragma HLS INTERFACE s_axilite port=switch_membership bundle=control
#pragma HLS INTERFACE s_axilite port=work_mem bundle=control
#pragma HLS INTERFACE s_axilite port=num bundle=control
#pragma HLS INTERFACE s_axilite port=cost_of_opening_x bundle=control
#pragma HLS INTERFACE s_axilite port=numcenter bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Determine local iteration bounds to avoid out-of-range accesses if
    // runtime num/numcenter values differ from the compile-time BATCH_SIZE.
    int local_num = (num > 0 && num <= BATCH_SIZE) ? num : BATCH_SIZE;
    int local_numcenter = (numcenter > 0 && numcenter <= BATCH_SIZE) ? numcenter : BATCH_SIZE;

    // Local buffers sized to match the small testbench (single-buffer approach).
    // Partition small arrays for better concurrency in HLS.
    float local_coord[BATCH_SIZE * DIM];
#pragma HLS ARRAY_PARTITION variable=local_coord cyclic factor=2 dim=1
    float local_weight[BATCH_SIZE];
#pragma HLS ARRAY_PARTITION variable=local_weight cyclic factor=2 dim=1
    float local_cost[BATCH_SIZE];
#pragma HLS ARRAY_PARTITION variable=local_cost cyclic factor=2 dim=1
    int local_assign[BATCH_SIZE];
#pragma HLS ARRAY_PARTITION variable=local_assign cyclic factor=2 dim=1

    float local_target[DIM];
#pragma HLS ARRAY_PARTITION variable=local_target complete dim=1

    int local_center_table[BATCH_SIZE];
#pragma HLS ARRAY_PARTITION variable=local_center_table cyclic factor=2 dim=1

    char local_switch_membership[BATCH_SIZE];
#pragma HLS ARRAY_PARTITION variable=local_switch_membership cyclic factor=2 dim=1

    float local_work_mem[BATCH_SIZE];
#pragma HLS ARRAY_PARTITION variable=local_work_mem cyclic factor=2 dim=1

    float local_cost_of_opening_x[1];
#pragma HLS ARRAY_PARTITION variable=local_cost_of_opening_x complete dim=1

    float x_cost[BUF_SIZE];
#pragma HLS ARRAY_PARTITION variable=x_cost cyclic factor=2 dim=1

    // Initialize local buffers from external memory
    // Copy arrays (small sizes -> pipeline each iteration)
    // Only copy the number of valid elements (local_num) for per-point arrays.
    for (int i = 0; i < BATCH_SIZE; i++) {
#pragma HLS PIPELINE
        // For indices < local_num, copy the provided inputs; otherwise, initialize to safe defaults.
        if (i < local_num) {
            local_weight[i] = weight[i];
            local_cost[i] = cost[i];
            local_assign[i] = assign[i];
            local_switch_membership[i] = switch_membership[i];
            local_work_mem[i] = work_mem[i];
        } else {
            // Default initialization for unused entries to keep deterministic behavior
            local_weight[i] = 0.0f;
            local_cost[i] = 0.0f;
            local_assign[i] = 0;
            local_switch_membership[i] = 0;
            local_work_mem[i] = 0.0f;
        }
    }

    // Copy coordinates (BATCH_SIZE * DIM entries) - clamp to available local buffer
    for (int i = 0; i < BATCH_SIZE * DIM; i++) {
#pragma HLS PIPELINE
        if (i < local_num * DIM) local_coord[i] = coord[i];
        else local_coord[i] = 0.0f;
    }

    // Copy target vector (DIM)
    for (int i = 0; i < DIM; i++) {
#pragma HLS PIPELINE
        local_target[i] = target[i];
    }

    // Copy center_table entries up to local_numcenter
    for (int i = 0; i < BATCH_SIZE; i++) {
#pragma HLS PIPELINE
        if (i < local_numcenter) local_center_table[i] = center_table[i];
        else local_center_table[i] = 0;
    }

    // Make sure at least index 0 is valid (defensive)
    if (local_numcenter == 0) local_center_table[0] = 0;

    // Initialize running cost accumulator from external memory (single element)
    local_cost_of_opening_x[0] = cost_of_opening_x[0];

    // Compute loop: compute weighted squared distances and update working memory
    // Only iterate over actual points present (local_num)
    for (int i = 0; i < local_num; i++) {
#pragma HLS PIPELINE II=1
        // compute squared distance between point i and target
        float sum = 0.0f;
        for (int d = 0; d < DIM; d++) {
            float diff = local_coord[i * DIM + d] - local_target[d];
            sum += diff * diff;
        }
        // Guard index into x_cost (x_cost has BUF_SIZE entries)
        int x_cost_idx = (i < BUF_SIZE) ? i : (BUF_SIZE - 1);
        x_cost[x_cost_idx] = sum * local_weight[i];

        // compute delta current_cost and update structures accordingly
        float current_cost = x_cost[x_cost_idx] - local_cost[i];

        // read assign and map to local center index (guard index to avoid out-of-range)
        int a = local_assign[i];
        int local_center_index = 0;
        if (a >= 0 && a < local_numcenter) {
            // a indexes into center_table (which maps to an index in work_mem)
            int idx = local_center_table[a];
            local_center_index = idx;
        } else {
            // clamp invalid assign to the first valid center table entry
            local_center_index = local_center_table[0];
        }

        // guard local_center_index bounds before accessing local_work_mem
        if (local_center_index < 0) local_center_index = 0;
        if (local_center_index >= BATCH_SIZE) local_center_index = BATCH_SIZE - 1;

        if (current_cost < 0.0f) {
            // mark membership switch for this point and accumulate negative delta
            local_switch_membership[i] = 1;
            local_cost_of_opening_x[0] += current_cost;
        } else {
            // subtract current_cost from the corresponding entry in local_work_mem
            local_work_mem[local_center_index] = local_work_mem[local_center_index] - current_cost;
        }
    }

    // Store local buffers back to external memory
    // Write back only the relevant portions that callers expect to be updated.
    for (int i = 0; i < BATCH_SIZE; i++) {
#pragma HLS PIPELINE
        work_mem[i] = local_work_mem[i];
        switch_membership[i] = local_switch_membership[i];
    }

    // Store accumulated cost
    cost_of_opening_x[0] = local_cost_of_opening_x[0];

    return;
}

