// tb_hls_cosim.cpp
// Testbench for the Vivado HLS streamcluster top-level.
// Uses plain C headers (C++98 compatible) because Vivado HLS 2018.3 toolchain
// does not fully support newer C++11 headers. This testbench is intended to be
// built and run by the host toolchain used for HLS C/RTL co-simulation.

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <stdint.h>

#define BATCH_SIZE 8
#define DIM 3
#define CENTER_TABLE_SIZE 8
#define WORK_MEM_SIZE 8

// The DUT top-level must be declared with exactly the same signature as in the HLS C code.
extern "C" void streamcluster(
    float* coord,
    float* weight,
    float* cost,
    float* target,
    int* assign,
    int* center_table,
    char* switch_membership,
    float* work_mem,
    int num,
    float* cost_of_opening_x,
    int numcenter
);

// Convert float to raw 32-bit bits using memcpy (C style)
static uint32_t float_to_bits(float f) {
    uint32_t u;
    memcpy(&u, &f, sizeof(u));
    return u;
}

int main() {
    const int CYCLES = 32; // between 20 and 50

    // Allocate arrays
    float coord[BATCH_SIZE * DIM];
    float weight[BATCH_SIZE];
    float cost[BATCH_SIZE];
    float target[DIM];
    int assign[BATCH_SIZE];
    int center_table[CENTER_TABLE_SIZE];
    char switch_membership[BATCH_SIZE];
    float work_mem[WORK_MEM_SIZE];
    float cost_of_opening_x_arr[1];

    // Initialize base patterns
    for (int i = 0; i < BATCH_SIZE; i++) {
        for (int j = 0; j < DIM; j++) {
            coord[i * DIM + j] = (float)((i + 1) * (j + 2)); // base
        }
        weight[i] = 1.0f + 0.1f * i;
        cost[i] = (float)((i % 2 == 0) ? 10.0f + i : 1.0f + i*0.5f);
        assign[i] = i % 4;
        switch_membership[i] = 0;
    }
    for (int j = 0; j < DIM; j++) target[j] = (float)(1 + j);
    for (int k = 0; k < CENTER_TABLE_SIZE; k++) center_table[k] = k % WORK_MEM_SIZE;
    for (int k = 0; k < WORK_MEM_SIZE; k++) work_mem[k] = 100.0f + k * 10.0f;
    cost_of_opening_x_arr[0] = 0.0f;

    // Open CSV file for HLS/RTL outputs
    FILE* f = fopen("hls_output.csv", "w");
    if (!f) return 1;

    // Header row: cycle, then chosen input signal summaries, then outputs sampled from DUT
    fprintf(f, "cycle,assign,center_table,num,numcenter,switch_membership,cost_of_opening_x,work_mem\n");
    fprintf(f, "meta,in,in,in,in,out,out,out\n");

    // Simulation cycles
    for (int cycle = 0; cycle < CYCLES; cycle++) {
        // Deterministic per-cycle stimulus:
        int num = BATCH_SIZE;
        int numcenter = 4 + (cycle % 3); // vary numcenter between 4..6

        // Update coord slightly per cycle
        for (int i = 0; i < BATCH_SIZE; i++) {
            for (int j = 0; j < DIM; j++) {
                coord[i * DIM + j] = (float)((i + 1) * (j + 2)) + 0.25f * (cycle % 5);
            }
            // weight vary slowly
            weight[i] = 1.0f + 0.1f * ((cycle + i) % 7);
            // make cost alternate to generate negative and positive current_cost
            if ((cycle + i) % 3 == 0) cost[i] = 50.0f + (float)i; // likely current_cost negative
            else cost[i] = 0.5f + 0.2f * (float)i; // likely positive
            // assign pattern cycles
            assign[i] = (cycle + i) % numcenter;
            switch_membership[i] = 0;
        }
        // center_table mapping depends on cycle
        for (int k = 0; k < CENTER_TABLE_SIZE; k++) {
            center_table[k] = (k + (cycle % WORK_MEM_SIZE)) % WORK_MEM_SIZE;
        }
        // reset work_mem and cost_of_opening_x each cycle
        for (int k = 0; k < WORK_MEM_SIZE; k++) {
            work_mem[k] = 100.0f + k * 10.0f - 1.5f * cycle; // slight drift by cycle
        }
        cost_of_opening_x_arr[0] = 0.0f;

        // Call DUT
        streamcluster(coord, weight, cost, target, assign, center_table, switch_membership, work_mem, num, cost_of_opening_x_arr, numcenter);

        // Prepare CSV values (match original testbench' summaries)
        int assign_checksum = 0;
        for (int i = 0; i < BATCH_SIZE; i++) assign_checksum += assign[i];
        int center_table_checksum = 0;
        for (int k = 0; k < numcenter; k++) center_table_checksum += center_table[k];

        // Outputs:
        // switch_membership as bitmask (bit i = value)
        uint32_t switch_mask = 0;
        for (int i = 0; i < BATCH_SIZE && i < 32; i++) {
            if (switch_membership[i]) switch_mask |= (1u << i);
        }
        uint32_t cost_bits = float_to_bits(cost_of_opening_x_arr[0]);
        uint32_t work_mem0_bits = float_to_bits(work_mem[0]);

        // Write CSV line: inputs decimal, outputs hex uppercase without 0x
        fprintf(f, "%d,%d,%d,%d,%d,%X,%X,%X\n",
                     cycle,
                     assign_checksum,
                     center_table_checksum,
                     num,
                     numcenter,
                     (unsigned) switch_mask,
                     (unsigned) cost_bits,
                     (unsigned) work_mem0_bits);
    }

    fclose(f);
    return 0;
}

