#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include "test.h"

void sparse_matrix_multiply_HLS(data_t values_A[N * M],
                                int column_indices_A[N * M],
                                int row_ptr_A[N + 1],
                                data_t values_B[M * K],
                                int row_indices_B[M * K],
                                int col_ptr_B[M + 1],
                                data_t C[N][K]) 
{
    data_t local_values_A[N * M];
    int   local_column_indices_A[N * M];
    int   local_row_ptr_A[N + 1];

    data_t local_values_B[M * K];
    int   local_row_indices_B[M * K];
    int   local_col_ptr_B[M + 1];

    data_t accum[N][K];

    for (int i = 0; i < N + 1; i++) {
        local_row_ptr_A[i] = row_ptr_A[i];
    }
    int nnzA = row_ptr_A[N];
    for (int i = 0; i < nnzA; i++) {
        local_values_A[i]        = values_A[i];
        local_column_indices_A[i] = column_indices_A[i];
    }

    for (int i = 0; i < M + 1; i++) {
        local_col_ptr_B[i] = col_ptr_B[i];
    }
    int nnzB = col_ptr_B[M];
    for (int i = 0; i < nnzB; i++) {
        local_values_B[i]      = values_B[i];
        local_row_indices_B[i] = row_indices_B[i];
    }

    for (int i = 0; i < N; i++) {
        for (int j = 0; j < K; j++) {
            accum[i][j] = (data_t)0;
        }
    }

    for (int i = 0; i < N; i++) {
        int startA = local_row_ptr_A[i];
        int endA   = local_row_ptr_A[i + 1];
        for (int a = startA; a < endA; a++) {
            data_t a_val = local_values_A[a];
            int    col   = local_column_indices_A[a];
            int    startB = local_col_ptr_B[col];
            int    endB   = local_col_ptr_B[col + 1];
            for (int b = startB; b < endB; b++) {
                data_t b_val = local_values_B[b];
                int    row   = local_row_indices_B[b];
                accum[i][row] += a_val * b_val;
            }
        }
    }

    for (int i = 0; i < N; i++) {
        for (int j = 0; j < K; j++) {
            C[i][j] = accum[i][j];
        }
    }
}

int main() {
    srand((unsigned int)time(NULL));

    static data_t values_A[N * M];
    static int column_indices_A[N * M];
    static int row_ptr_A[N + 1];

    static data_t values_B[M * K];
    static int row_indices_B[M * K];
    static int col_ptr_B[M + 1];

    static data_t C[N][K];
    static data_t C_ref[N][K];
    static data_t A_dense[N][M];
    static data_t B_dense[M][K];

    const int density_percent = 10;

    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if ((rand() % 100) < density_percent) {
                A_dense[i][j] = (data_t)((rand() % 1000) / 100.0f - 5.0f);
            } else {
                A_dense[i][j] = 0;
            }
        }
    }

    for (int i = 0; i < M; i++) {
        for (int j = 0; j < K; j++) {
            if ((rand() % 100) < density_percent) {
                B_dense[i][j] = (data_t)((rand() % 1000) / 100.0f - 5.0f);
            } else {
                B_dense[i][j] = 0;
            }
        }
    }

    int nnzA = 0;
    row_ptr_A[0] = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if (A_dense[i][j] != 0) {
                values_A[nnzA] = A_dense[i][j];
                column_indices_A[nnzA] = j;
                nnzA++;
            }
        }
        row_ptr_A[i + 1] = nnzA;
    }
    for (int i = nnzA; i < N * M; i++) {
        values_A[i] = 0;
        column_indices_A[i] = 0;
    }

    int nnzB = 0;
    col_ptr_B[0] = 0;
    for (int i = 0; i < M; i++) {
        for (int j = 0; j < K; j++) {
            if (B_dense[i][j] != 0) {
                values_B[nnzB] = B_dense[i][j];
                row_indices_B[nnzB] = j;
                nnzB++;
            }
        }
        col_ptr_B[i + 1] = nnzB;
    }
    for (int i = nnzB; i < M * K; i++) {
        values_B[i] = 0;
        row_indices_B[i] = 0;
    }

    for (int i = 0; i < N; i++) {
        for (int j = 0; j < K; j++) {
            C[i][j] = 0;
            C_ref[i][j] = 0;
        }
    }

    sparse_matrix_multiply_HLS(values_A, column_indices_A, row_ptr_A,
                               values_B, row_indices_B, col_ptr_B,
                               C);

    for (int i = 0; i < N; i++) {
        for (int j = 0; j < K; j++) {
            data_t sum = 0;
            for (int t = 0; t < M; t++) {
                sum += A_dense[i][t] * B_dense[t][j];
            }
            C_ref[i][j] = sum;
        }
    }

    data_t max_err = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < K; j++) {
            data_t err = C[i][j] - C_ref[i][j];
            if (err < 0) err = -err;
            if (err > max_err) max_err = err;
        }
    }

    printf("Max absolute error: %f\n", (double)max_err);

    for (int i = 0; i < 8 && i < N; i++) {
        for (int j = 0; j < 8 && j < K; j++) {
            printf("%8.3f ", (double)C[i][j]);
        }
        printf("\n");
    }

    return 0;
}

