    if (!f) return 1;

    // Prepare CSV header: cycle, inputs (flattened), outputs (C elements)
    // Input columns: values_A_0..3, column_indices_A_0..3, row_ptr_A_0..2,
    //                values_B_0..3, row_indices_B_0..3, col_ptr_B_0..2
    // Output columns: C_0_0,C_0_1,C_1_0,C_1_1
