    for (int i = 0; i < N + 1; ++i) std::fprintf(f, ",row_ptr_A_%d", i);
    for (int i = 0; i < M * K; ++i) std::fprintf(f, ",values_B_%d", i);
    for (int i = 0; i < M * K; ++i) std::fprintf(f, ",row_indices_B_%d", i);
    for (int i = 0; i < M + 1; ++i) std::fprintf(f, ",col_ptr_B_%d", i);
    for (int i = 0; i < N; ++i) for (int j = 0; j < K; ++j) std::fprintf(f, ",C_%d_%d", i, j);
    std::fprintf(f, "\n");

    // Roles line
    std::fprintf(f, "meta");
    int total_inputs = (N*M) + (N*M) + (N+1) + (M*K) + (M*K) + (M+1);
    for (int i = 0; i < total_inputs; ++i) std::fprintf(f, ",in");
    for (int i = 0; i < N*K; ++i) std::fprintf(f, ",out");
    std::fprintf(f, "\n");

    // Generate deterministic testcases programmatically (no randomness)
    std::vector<TestCase> tests;
    tests.reserve(cycles);
    for (int t = 0; t < cycles; ++t) {
        TestCase tc;
        // Build A in CSR form from bits of t (lower 4 bits)
        int bitmaskA = t & 0xF; // 4 bits for 4 possible positions
        int idxA = 0;
        tc.row_ptr_A[0] = 0;
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < M; ++j) {
                int p = i * M + j;
                if ((bitmaskA >> p) & 1) {
                    // include this element
                    tc.values_A_all[idxA] = int32_t((p + 1) + (t % 3) * 4); // small positive value
                    tc.column_indices_A_all[idxA] = j;
                    idxA++;
                }
            }
            tc.row_ptr_A[i + 1] = idxA;
        }
        // Fill remaining slots with zeros
        for (int s = idxA; s < N * M; ++s) {
            tc.values_A_all[s] = 0;
            tc.column_indices_A_all[s] = 0;
        }

        // Build B in CSC form from bits of (t >> 4)
        int bitmaskB = (t >> 4) & 0xF;
        int idxB = 0;
        tc.col_ptr_B[0] = 0;
        for (int c = 0; c < M; ++c) {
            for (int r = 0; r < K; ++r) { // note: row indices range 0..N-1 (K==N here)
                int p = r * M + c; // same mapping as A but interpreted per column
                if ((bitmaskB >> p) & 1) {
                    tc.values_B_all[idxB] = int32_t((p + 1) * 2 + (t % 4));
                    tc.row_indices_B_all[idxB] = r;
                    idxB++;
                }
            }
            tc.col_ptr_B[c + 1] = idxB;
        }
        for (int s = idxB; s < M * K; ++s) {
            tc.values_B_all[s] = 0;
            tc.row_indices_B_all[s] = 0;
        }

        tests.push_back(tc);
    }

    // Run each test cycle: call DUT and record inputs+outputs
    for (int cycle = 0; cycle < cycles; ++cycle) {
        const TestCase &tc = tests[cycle];

        // Prepare arrays to pass to DUT - ensure sizes match signatures
        data_t values_A[N * M];
        int column_indices_A[N * M];
        int row_ptr_A[N + 1];
        data_t values_B[M * K];
