        }
        for (int i = 0; i < N + 1; ++i) row_ptr_A[i] = tc.row_ptr_A[i];
        for (int i = 0; i < M * K; ++i) {
            values_B[i] = tc.values_B_all[i];
            row_indices_B[i] = tc.row_indices_B_all[i];
        }
        for (int i = 0; i < M + 1; ++i) col_ptr_B[i] = tc.col_ptr_B[i];

        // Call DUT
        sparse_matrix_multiply_HLS(values_A, column_indices_A, row_ptr_A,
                                   values_B, row_indices_B, col_ptr_B, C);

        // Write CSV row: cycle, inputs (decimal), outputs (hex uppercase, no 0x)
        std::fprintf(f, "%d", cycle);
        for (int i = 0; i < N * M; ++i) std::fprintf(f, ",%d", (int)values_A[i]);
        for (int i = 0; i < N * M; ++i) std::fprintf(f, ",%d", column_indices_A[i]);
        for (int i = 0; i < N + 1; ++i) std::fprintf(f, ",%d", row_ptr_A[i]);
