            for (int j = 0; j < K; ++j) {
                // Print output as hex uppercase without 0x. Cast to unsigned to avoid negative formatting.
                uint32_t u = (uint32_t)C[i][j];
                // Format into a temporary buffer to avoid locale issues
                char buf[32];
                std::snprintf(buf, sizeof(buf), "%X", u);
                std::fprintf(f, ",%s", buf);
