// hls.cpp
// Fixed top-level for Vivado HLS (C++98-compatible).
// - Use C headers (no <cstdint> or C++11 features).
// - Provide extern "C" top-level with the exact name/signature used by the testbench.
// - Keep comments in English.

#include <stdint.h>

#define N 2
#define M 2
#define K 2

typedef int32_t data_t;

#ifdef __cplusplus
extern "C" {
#endif

// Top-level HLS function for sparse matrix multiply.
// A is in CSR format: values_A, column_indices_A, row_ptr_A (size N+1).
// B is in CSC format: values_B, row_indices_B, col_ptr_B (size M+1).
// Output C is dense matrix with shape [N][K].
void sparse_matrix_multiply_HLS(data_t values_A[N * M],
                                int column_indices_A[N * M],
                                int row_ptr_A[N + 1],
                                data_t values_B[M * K],
                                int row_indices_B[M * K],
                                int col_ptr_B[M + 1],
                                data_t C[N][K]) {
    // Local accumulator
    data_t local_C[N][K];

    // Initialize output accumulators
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < K; ++j) {
            local_C[i][j] = 0;
        }
    }

    // Compute SpMM: for each row i in A, iterate its non-zero entries
    // For each non-zero in A at column col_A with value valA, multiply
    // with the column col_A of B (stored in CSC) and accumulate into row i of C.
    for (int i = 0; i < N; ++i) {
        int startA = row_ptr_A[i];
        int endA = row_ptr_A[i + 1];
        for (int idxA = startA; idxA < endA; ++idxA) {
            data_t valA = values_A[idxA];
            int col_A = column_indices_A[idxA]; // column in A, corresponds to column index in B
            if (col_A < 0 || col_A >= M) continue; // safety check

            int startB = col_ptr_B[col_A];
            int endB = col_ptr_B[col_A + 1];
            for (int idxB = startB; idxB < endB; ++idxB) {
                int rowB = row_indices_B[idxB]; // row index in B (i.e., column index in C)
                if (rowB < 0 || rowB >= K) continue; // safety check
                local_C[i][rowB] += valA * values_B[idxB];
            }
        }
    }

    // Write back result to output array
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < K; ++j) {
            C[i][j] = local_C[i][j];
        }
    }
}

#ifdef __cplusplus
} // extern "C"
#endif

