#include <cstdio>
#include <cstdint>
#include <cstring>
#include <cstdlib>

void heat_3d(int tsteps,int n,double A[20][20][20],double B[20][20][20])
{
  int t;
  int i;
  int j;
  int k;

  for (t = 1; t <= tsteps; t++) {
    for (i = 1; i < n - 1; i++) {
      for (j = 1; j < n - 1; j++) {
        for (k = 1; k < n - 1; k++) {
          B[i][j][k] = 0.125 * (A[i + 1][j][k] - 2.0 * A[i][j][k] + A[i - 1][j][k])
                     + 0.125 * (A[i][j + 1][k] - 2.0 * A[i][j][k] + A[i][j - 1][k])
                     + 0.125 * (A[i][j][k + 1] - 2.0 * A[i][j][k] + A[i][j][k - 1])
                     + A[i][j][k];
        }
      }
    }

    for (i = 1; i < n - 1; i++) {
      for (j = 1; j < n - 1; j++) {
        for (k = 1; k < n - 1; k++) {
          A[i][j][k] = 0.125 * (B[i + 1][j][k] - 2.0 * B[i][j][k] + B[i - 1][j][k])
                     + 0.125 * (B[i][j + 1][k] - 2.0 * B[i][j][k] + B[i][j - 1][k])
                     + 0.125 * (B[i][j][k + 1] - 2.0 * B[i][j][k] + B[i][j][k - 1])
                     + B[i][j][k];
        }
      }
    }
  }
}

int main()
{
    // DUT parameters and arrays
    int tsteps = 1;
    int n = 6; // use a small n to keep runtime bounded (indices 0..5, internal 1..4)
    static double A[20][20][20];
    static double B[20][20][20];

    // Open CSV file
    FILE* f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // CSV header:
    // First column: cycle (meta)
    // Then inputs driven by testbench: tsteps,n
    // Then sampled outputs from DUT: use explicit indexed elements
    std::fprintf(f, "cycle,tsteps,n,A[1][1][1],A[2][2][2],B[1][1][1],B[3][3][3]\n");
    // Roles row
    std::fprintf(f, "meta,in,in,out,out,out,out\n");

    const int CYCLES = 12; // number of clock cycles / DUT invocations

    // Deterministic initialization pattern base (will be updated each cycle)
    for (int c = 0; c < CYCLES; ++c) {
        // Initialize arrays deterministically for this cycle.
        // We initialize the full 20^3 to safe values because DUT accesses neighbors up to index n-1.
        for (int i = 0; i < 20; ++i) {
            for (int j = 0; j < 20; ++j) {
                for (int k = 0; k < 20; ++k) {
                    // pattern depends on indices and cycle to exercise changes
                    A[i][j][k] = (double)(i * 100 + j * 10 + k) * 0.01 + 1.0 + c * 0.001;
                    B[i][j][k] = (double)(i * 100 + j * 10 + k) * 0.005 + 0.5 - c * 0.0007;
                }
            }
        }

        // Optionally vary a few interior hotspots to stress stencil
        A[2][2][2] += (double)c * 0.01;
        B[3][3][3] -= (double)c * 0.005;

        // Call DUT once per cycle
        heat_3d(tsteps, n, A, B);

        // Sample outputs: pick specific array elements.
        double out_A_111 = A[1][1][1];
        double out_A_222 = A[2][2][2];
        double out_B_111 = B[1][1][1];
        double out_B_333 = B[3][3][3];

        // Convert double bit patterns to uint64 for hex output
        uint64_t uA111, uA222, uB111, uB333;
        std::memcpy(&uA111, &out_A_111, sizeof(uA111));
        std::memcpy(&uA222, &out_A_222, sizeof(uA222));
        std::memcpy(&uB111, &out_B_111, sizeof(uB111));
        std::memcpy(&uB333, &out_B_333, sizeof(uB333));

        // Write CSV line: cycle (decimal), inputs tsteps,n (decimal), outputs (hex uppercase, no 0x)
        std::fprintf(f, "%d,%d,%d,%llX,%llX,%llX,%llX\n",
                     c,
                     tsteps,
                     n,
                     (unsigned long long)uA111,
                     (unsigned long long)uA222,
                     (unsigned long long)uB111,
                     (unsigned long long)uB333);
    }

    std::fflush(f);
    std::fclose(f);
    return 0;
}

