#include <limits>

#define rows 4
#define cols 5
#define KNOB_WINDOW_SIZE_X 5

void normalized(float v[3]);
void cross(float A[3], float B[3], float P[3]);
void normals(float vmap[rows*cols*3], float nmap[rows*cols*3]);

void normalized(float v[3])
{
    float sum = (v[0]*v[0]) + (v[1]*v[1]) + (v[2]*v[2]);
    if (sum <= 0.0f) {
        v[0] = v[1] = v[2] = 0.0f;
        return;
    }
    float t = 1.0f / sqrtf(sum);
    for (int i = 0; i < 3; i++)
        v[i] = v[i] * t;
}

void cross(float A[3], float B[3], float P[3])
{
    P[0] = A[1] * B[2] - A[2] * B[1];
    P[1] = (A[0] * B[2] - A[2] * B[0]) * -1;
    P[2] = A[0] * B[1] - A[1] * B[0];
}

void normals(float vmap[rows*cols*3], float nmap[rows*cols*3])
{
    for (int r = 0; r < rows; r++) {
        for (int c = 0; c < cols; c++) {
            int idx = (r * cols + c) * 3;
            if (c == cols - 1 || r == rows - 1) {
                nmap[idx + 0] = std::numeric_limits<float>::quiet_NaN();
                nmap[idx + 1] = std::numeric_limits<float>::quiet_NaN();
                nmap[idx + 2] = std::numeric_limits<float>::quiet_NaN();
                continue;
            }
            int idx00 = idx;
            int idx01 = (r * cols + (c + 1)) * 3;
            int idx10 = ((r + 1) * cols + c) * 3;

            float v00x = vmap[idx00 + 0];
            float v01x = vmap[idx01 + 0];
            float v10x = vmap[idx10 + 0];

            if (!std::isnan(v00x) && !std::isnan(v01x) && !std::isnan(v10x)) {
                float v00[3], v01[3], v10[3];
                v00[0] = vmap[idx00 + 0];
                v00[1] = vmap[idx00 + 1];
                v00[2] = vmap[idx00 + 2];

                v01[0] = vmap[idx01 + 0];
                v01[1] = vmap[idx01 + 1];
                v01[2] = vmap[idx01 + 2];

                v10[0] = vmap[idx10 + 0];
                v10[1] = vmap[idx10 + 1];
                v10[2] = vmap[idx10 + 2];

                float in1[3], in2[3], rvec[3];
                for (int l = 0; l < 3; l++) {
                    in1[l] = v01[l] - v00[l];
                    in2[l] = v10[l] - v00[l];
                }
                cross(in1, in2, rvec);
                normalized(rvec);

                nmap[idx + 0] = rvec[0];
                nmap[idx + 1] = rvec[1];
                nmap[idx + 2] = rvec[2];
            } else {
                nmap[idx + 0] = std::numeric_limits<float>::quiet_NaN();
                nmap[idx + 1] = std::numeric_limits<float>::quiet_NaN();
                nmap[idx + 2] = std::numeric_limits<float>::quiet_NaN();
            }
        }
