// hls.cpp
// HLS top function for computing normals from a vertex map.
// Adjusted to be compatible with Vivado HLS C++98 environment.
// Comments in English.

#include <math.h>

// Match the testbench sizes so co-simulation uses the same dimensions.
#define rows 4
#define cols 5
#define KNOB_WINDOW_SIZE_X 5

// Do not redefine the standard macro NAN from math.h.
// Provide our own helper routines instead.

static inline int my_isnan(float x) {
    // Inspect IEEE-754 bits to detect NaN (quiet or signalling).
    unsigned int ix = *((unsigned int*)&x);
    return ((ix & 0x7f800000) == 0x7f800000) && ((ix & 0x007fffff) != 0);
}

static inline float my_sqrt(float x) {
    // Use standard sqrtf for synthesis and simulation.
    return sqrtf(x);
}

static inline float my_nan() {
    // Create a canonical quiet NaN bit pattern (0x7fc00000).
    union {
        unsigned int i;
        float f;
    } u;
    u.i = 0x7fc00000u;
    return u.f;
}

extern "C" {
void normals(float vmap[rows*cols*3], float nmap[rows*cols*3]) {
#pragma HLS INTERFACE m_axi port=vmap offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=nmap offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=vmap bundle=control
#pragma HLS INTERFACE s_axilite port=nmap bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local sliding window buffers (triplets for x,y,z)
    float data0[(1+KNOB_WINDOW_SIZE_X)*3];
    float data1[KNOB_WINDOW_SIZE_X*3];

    // Initialize data0 and data1 from the first two rows of vmap
    for (int i = 0; i < (1+KNOB_WINDOW_SIZE_X)*3; i++) {
        data0[i] = vmap[i];
    }
    for (int i = 0; i < KNOB_WINDOW_SIZE_X*3; i++) {
        data1[i] = vmap[(cols*3) + i];
    }

    int j = 0;
    // Process by horizontal strides of window width (KNOB_WINDOW_SIZE_X * 3 entries)
    for (int i = 0; i < rows*cols*3; i += (KNOB_WINDOW_SIZE_X*3)) {
        for (int x = 0; x < KNOB_WINDOW_SIZE_X; x++) {
            if (j == cols - 1) {
                // Rightmost column: output NaN
                j = -1;
                nmap[i + x*3 + 0] = my_nan();
                nmap[i + x*3 + 1] = my_nan();
                nmap[i + x*3 + 2] = my_nan();
                continue;
            }

            const int index00 = (x + 0) * 3;
            const int index01 = (x + 1) * 3;
            const int index10 = (x + 0) * 3;

            float v00[3], v01[3], v10[3];

            // Read only the X component first to check NaN cheaply
            v00[0] = data0[index00];
            v01[0] = data0[index01];
            v10[0] = data1[index10];

            if (!my_isnan(v00[0]) && !my_isnan(v01[0]) && !my_isnan(v10[0])) {
                // Read remaining components
                v00[1] = data0[index00 + 1];
                v01[1] = data0[index01 + 1];
                v10[1] = data1[index10 + 1];

                v00[2] = data0[index00 + 2];
                v01[2] = data0[index01 + 2];
                v10[2] = data1[index10 + 2];

                float in1[3], in2[3], r[3];
                for (int l = 0; l < 3; l++) {
                    in1[l] = v01[l] - v00[l];
                    in2[l] = v10[l] - v00[l];
                }

                // Cross product: r = in1 x in2
                r[0] = in1[1]*in2[2] - in1[2]*in2[1];
                r[1] = (in1[0]*in2[2] - in1[2]*in2[0]) * -1.0f;
                r[2] = in1[0]*in2[1] - in1[1]*in2[0];

                // Normalize the result
                float norm_val = my_sqrt(r[0]*r[0] + r[1]*r[1] + r[2]*r[2]);
                if (norm_val != 0.0f) {
                    float t = 1.0f / norm_val;
                    r[0] *= t;
                    r[1] *= t;
                    r[2] *= t;
                }

                nmap[i + 0 + x*3] = r[0];
                nmap[i + 1 + x*3] = r[1];
                nmap[i + 2 + x*3] = r[2];
            } else {
                // If any of the required vertices is NaN, output NaN
                nmap[i + x*3 + 0] = my_nan();
                nmap[i + x*3 + 1] = my_nan();
                nmap[i + x*3 + 2] = my_nan();
            }
        }

        j++;

        // Shift data0: move last KNOB_WINDOW_SIZE_X entries into the first slot and refill
        data0[0] = data0[KNOB_WINDOW_SIZE_X * 3 + 0];
        data0[1] = data0[KNOB_WINDOW_SIZE_X * 3 + 1];
        data0[2] = data0[KNOB_WINDOW_SIZE_X * 3 + 2];

        for (int x = 0; x < KNOB_WINDOW_SIZE_X; x++) {
            int idx = i + KNOB_WINDOW_SIZE_X*3 + (x+1)*3;
            data0[(x+1)*3 + 0] = vmap[idx + 0];
            data0[(x+1)*3 + 1] = vmap[idx + 1];
            data0[(x+1)*3 + 2] = vmap[idx + 2];
        }

        for (int x = 0; x < KNOB_WINDOW_SIZE_X; x++) {
            int idx = 3*cols + i + KNOB_WINDOW_SIZE_X*3 + x*3;
            data1[x*3 + 0] = vmap[idx + 0];
            data1[x*3 + 1] = vmap[idx + 1];
            data1[x*3 + 2] = vmap[idx + 2];
        }
    }

    // Set last row to NaN
    for (int k = (rows-1)*cols*3; k < rows*cols*3; k++) {
        nmap[k] = my_nan();
    }
}
} // extern "C"

