// tb_hls_cosim.cpp
// Testbench for normals() HLS function.
// Adjusted headers for Vivado HLS C++98 compatibility.
// Comments in English.

#include <cstdio>
#include <cstdlib>
#include <stdint.h>   // Use C header to be compatible with older C++ standard library shipped with Vivado HLS
#include <cmath>
#include <cstring>
#include <limits>

#define rows 4
#define cols 5
#define KNOB_WINDOW_SIZE_X 5

// Top-level HLS function declaration must match HLSC definition exactly.
extern "C" void normals(float vmap[rows*cols*3], float nmap[rows*cols*3]);

int main()
{
    const int N = rows * cols * 3;
    float *vmap = (float*)malloc(sizeof(float) * N);
    float *nmap = (float*)malloc(sizeof(float) * N);
    if (!vmap || !nmap) {
        if (vmap) free(vmap);
        if (nmap) free(nmap);
        return 1;
    }

    FILE *f = std::fopen("hls_output.csv", "w");
    if (!f) {
        free(vmap);
        free(nmap);
        return 1;
    }

    // Header row: cycle, inputs..., outputs...
    // Inputs: case_id (we drive the vmap content based on this)
    std::fprintf(f, "cycle,case_id");
    for (int i = 0; i < N; i++) {
        std::fprintf(f, ",nmap[%d]", i);
    }
    std::fprintf(f, "\n");

    // Role row
    std::fprintf(f, "meta,in");
    for (int i = 0; i < N; i++) {
        std::fprintf(f, ",out");
    }
    std::fprintf(f, "\n");

    // Number of test cycles (between 20 and 50)
    const int cycles = 24;
    for (int cycle = 0; cycle < cycles; cycle++) {
        int case_id = cycle; // deterministic test vector id

        // Prepare vmap based on case_id (deterministic, no randomness)
        // Default: edges = NaN, interior: x=c, y=r, z=1.0
        float NANF = std::numeric_limits<float>::quiet_NaN();

        // Start by clearing to NaN
        for (int i = 0; i < N; i++) vmap[i] = NANF;

        for (int r = 0; r < rows; r++) {
            for (int c = 0; c < cols; c++) {
                int idx = (r * cols + c) * 3;
                bool isEdge = (r == rows - 1) || (c == cols - 1);
                if (isEdge) {
                    vmap[idx + 0] = NANF;
                    vmap[idx + 1] = NANF;
                    vmap[idx + 2] = NANF;
                } else {
                    // fill based on case_id to create diverse scenarios
                    switch (case_id) {
                        case 0:
                            // baseline: grid x=c, y=r, z=1
                            vmap[idx + 0] = (float)c;
                            vmap[idx + 1] = (float)r;
                            vmap[idx + 2] = 1.0f;
                            break;
                        case 1:
                            // x offset +0.5
                            vmap[idx + 0] = (float)c + 0.5f;
                            vmap[idx + 1] = (float)r;
                            vmap[idx + 2] = 1.0f;
                            break;
                        case 2:
                            // larger height
                            vmap[idx + 0] = (float)c;
                            vmap[idx + 1] = (float)r;
                            vmap[idx + 2] = 2.0f;
                            break;
                        case 3:
                            // introduce a single NaN at (1,1)
                            if (r == 1 && c == 1) {
                                vmap[idx + 0] = NANF;
                                vmap[idx + 1] = NANF;
                                vmap[idx + 2] = NANF;
                            } else {
                                vmap[idx + 0] = (float)c;
                                vmap[idx + 1] = (float)r;
                                vmap[idx + 2] = 1.0f;
                            }
                            break;
                        case 4:
                            // flat plane all interior same point (0,0,1)
                            vmap[idx + 0] = 0.0f;
                            vmap[idx + 1] = 0.0f;
                            vmap[idx + 2] = 1.0f;
                            break;
                        case 5:
                            // zero vectors inside
                            vmap[idx + 0] = 0.0f;
                            vmap[idx + 1] = 0.0f;
                            vmap[idx + 2] = 0.0f;
                            break;
                        case 6:
                            // negative coordinates
                            vmap[idx + 0] = -(float)c;
                            vmap[idx + 1] = -(float)r;
                            vmap[idx + 2] = 1.0f;
                            break;
                        case 7:
                            // tilted plane x+y
                            vmap[idx + 0] = (float)c;
                            vmap[idx + 1] = (float)r;
                            vmap[idx + 2] = (float)(c + r) * 0.5f + 1.0f;
                            break;
                        case 8:
                            // z = 1 + r + c
                            vmap[idx + 0] = (float)c;
                            vmap[idx + 1] = (float)r;
                            vmap[idx + 2] = 1.0f + (float)r + (float)c;
                            break;
                        case 9:
                            // scaled large floats
                            vmap[idx + 0] = (float)c * 1000.0f;
                            vmap[idx + 1] = (float)r * 1000.0f;
                            vmap[idx + 2] = 1000.0f;
                            break;
                        case 10:
                            // very small floats
                            vmap[idx + 0] = (float)c * 1e-6f;
                            vmap[idx + 1] = (float)r * 1e-6f;
                            vmap[idx + 2] = 1e-6f;
                            break;
                        case 11:
                            // checkerboard NaNs on interior
                            if (((r + c) & 1) == 0) {
                                vmap[idx + 0] = NANF;
                                vmap[idx + 1] = NANF;
                                vmap[idx + 2] = NANF;
                            } else {
                                vmap[idx + 0] = (float)c;
                                vmap[idx + 1] = (float)r;
                                vmap[idx + 2] = 1.0f;
                            }
                            break;
                        case 12:
                            // unit vectors along x
                            vmap[idx + 0] = 1.0f;
                            vmap[idx + 1] = 0.0f;
                            vmap[idx + 2] = 0.0f;
                            break;
                        case 13:
                            // unit vectors along y
                            vmap[idx + 0] = 0.0f;
                            vmap[idx + 1] = 1.0f;
                            vmap[idx + 2] = 0.0f;
                            break;
                        case 14:
                            // unit vectors along z
                            vmap[idx + 0] = 0.0f;
                            vmap[idx + 1] = 0.0f;
                            vmap[idx + 2] = 1.0f;
                            break;
                        case 15:
                            // diagonal gradient
                            vmap[idx + 0] = (float)c;
                            vmap[idx + 1] = (float)r;
                            vmap[idx + 2] = (float)c - (float)r;
                            break;
                        case 16:
                            // make interior symmetric slope
                            vmap[idx + 0] = (float)c * 0.3f;
                            vmap[idx + 1] = (float)r * 0.7f;
                            vmap[idx + 2] = 0.5f;
                            break;
                        case 17:
                            // create a hole by making v01 NaN for cell (0,2) checks
                            if (r == 0 && c == 2) {
                                vmap[idx + 0] = (float)c;
                                vmap[idx + 1] = (float)r;
                                vmap[idx + 2] = NANF;
                            } else {
                                vmap[idx + 0] = (float)c;
                                vmap[idx + 1] = (float)r;
                                vmap[idx + 2] = 1.0f;
                            }
                            break;
                        case 18:
                            // ramp in z only
                            vmap[idx + 0] = (float)c;
                            vmap[idx + 1] = (float)r;
                            vmap[idx + 2] = 1.0f + (float)c * 0.1f;
                            break;
                        case 19:
                            // swapped coordinates
                            vmap[idx + 0] = (float)r;
                            vmap[idx + 1] = (float)c;
                            vmap[idx + 2] = 1.0f;
                            break;
                        case 20:
                            // sinusoidal-like discrete pattern (no math sin to keep deterministic simple)
                            vmap[idx + 0] = (float)( (c % 2) ? 0.9f : 0.1f );
                            vmap[idx + 1] = (float)( (r % 2) ? 0.7f : 0.3f );
                            vmap[idx + 2] = 1.0f;
                            break;
                        case 21:
                            // gradient in x only
                            vmap[idx + 0] = (float)c;
                            vmap[idx + 1] = 0.0f;
                            vmap[idx + 2] = 1.0f;
                            break;
                        case 22:
                            // gradient in y only
                            vmap[idx + 0] = 0.0f;
                            vmap[idx + 1] = (float)r;
                            vmap[idx + 2] = 1.0f;
                            break;
                        case 23:
                            // mix: interior like baseline but center doubled
                            if (r == 1 && c == 2) {
                                vmap[idx + 0] = (float)c * 2.0f;
                                vmap[idx + 1] = (float)r * 2.0f;
                                vmap[idx + 2] = 2.0f;
                            } else {
                                vmap[idx + 0] = (float)c;
                                vmap[idx + 1] = (float)r;
                                vmap[idx + 2] = 1.0f;
                            }
                            break;
                        default:
                            vmap[idx + 0] = (float)c;
                            vmap[idx + 1] = (float)r;
                            vmap[idx + 2] = 1.0f;
                            break;
                    }
                }
            }
        }

        // Call DUT (HLS top)
        normals(vmap, nmap);

        // Write CSV line: cycle,case_id, then outputs (nmap[0..N-1]) as uppercase hex without 0x, no fixed width
        std::fprintf(f, "%d,%d", cycle, case_id);
        for (int i = 0; i < N; i++) {
            uint32_t bits;
            // copy bit pattern
            std::memcpy(&bits, &nmap[i], sizeof(bits));
            // Print hex uppercase without 0x and without fixed width
            std::fprintf(f, ",%X", (unsigned)bits);
        }
        std::fprintf(f, "\n");
    }

    std::fclose(f);
    free(vmap);
    free(nmap);
    return 0;
}

