// hls.cpp
// Fixed top-level to match the testbench signature and types.
// - Use uint32_t as DATA_TYPE to match tb_hls_cosim.cpp
// - Use N=4 to match the testbench matrix size
// - Put HLS pragmas on the function arguments (2D arrays)
// - Move array_partition pragmas to declarations (not inside loops)
// - Use 64-bit accumulator to avoid intermediate overflow, then cast to DATA_TYPE
#include <stdint.h>

extern "C" {

#define N 4
typedef uint32_t DATA_TYPE;

void syr2k(DATA_TYPE alpha, DATA_TYPE beta,
           DATA_TYPE A[N][N], DATA_TYPE B[N][N],
           DATA_TYPE C[N][N], DATA_TYPE D_out[N][N]) {
#pragma HLS INTERFACE m_axi port=A offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=B offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=C offset=slave bundle=gmem2
#pragma HLS INTERFACE m_axi port=D_out offset=slave bundle=gmem3
#pragma HLS INTERFACE s_axilite port=alpha bundle=control
#pragma HLS INTERFACE s_axilite port=beta bundle=control
#pragma HLS INTERFACE s_axilite port=A bundle=control
#pragma HLS INTERFACE s_axilite port=B bundle=control
#pragma HLS INTERFACE s_axilite port=C bundle=control
#pragma HLS INTERFACE s_axilite port=D_out bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local buffers
    DATA_TYPE buff_A0[N][N];
    DATA_TYPE buff_A1[N][N];
#pragma HLS array_partition variable=buff_A0 cyclic factor=2 dim=2
#pragma HLS array_partition variable=buff_A1 complete dim=2
    DATA_TYPE buff_B0[N][N];
    DATA_TYPE buff_B1[N][N];
    DATA_TYPE buff_C[N][N];
    DATA_TYPE buff_D_out[N][N];
    DATA_TYPE tmp1[N][N];
    DATA_TYPE tmp2[N][N];

    int i, j, k;

    // Copy inputs from AXI (2D arrays) to local buffers
    for (i = 0; i < N; i++) {
        for (j = 0; j < N; j++) {
#pragma HLS PIPELINE II=1
            buff_A0[i][j] = A[i][j];
            buff_A1[i][j] = A[i][j];
            buff_B0[i][j] = B[i][j];
            buff_B1[i][j] = B[i][j];
            buff_C[i][j] = C[i][j];
            buff_D_out[i][j] = 0;
            tmp1[i][j] = 0;
            tmp2[i][j] = 0;
        }
    }

    // Compute tmp1 = alpha * A * B^T
    for (i = 0; i < N; i++) {
        for (j = 0; j < N; j++) {
#pragma HLS PIPELINE II=1
            uint64_t sum = 0;
            for (k = 0; k < N; k++) {
                sum += (uint64_t)buff_A0[i][k] * (uint64_t)buff_B0[j][k];
            }
            uint64_t prod = (uint64_t)alpha * sum;
            tmp1[i][j] = (DATA_TYPE)prod;
        }
    }

    // Compute tmp2 = alpha * B * A^T
    for (i = 0; i < N; i++) {
        for (j = 0; j < N; j++) {
#pragma HLS PIPELINE II=1
            uint64_t sum = 0;
            for (k = 0; k < N; k++) {
                sum += (uint64_t)buff_B0[i][k] * (uint64_t)buff_A1[j][k];
            }
            uint64_t prod = (uint64_t)alpha * sum;
            tmp2[i][j] = (DATA_TYPE)prod;
        }
    }

    // Compute D_out = tmp1 + tmp2 + beta * C
    for (i = 0; i < N; i++) {
        for (j = 0; j < N; j++) {
#pragma HLS PIPELINE II=1
            uint64_t val = (uint64_t)tmp1[i][j] + (uint64_t)tmp2[i][j] + (uint64_t)beta * (uint64_t)buff_C[i][j];
            buff_D_out[i][j] = (DATA_TYPE)val;
        }
    }

    // Write back results, zero upper triangle (j > i)
    for (i = 0; i < N; i++) {
        for (j = 0; j < N; j++) {
#pragma HLS PIPELINE II=1
            if (j > i) {
                D_out[i][j] = 0;
            } else {
                D_out[i][j] = buff_D_out[i][j];
            }
        }
    }
}

} // extern "C"

