    for (int i = 0; i < N; ++i) for (int j = 0; j < N; ++j) {
        std::fprintf(f, ",B_%d_%d", i, j);
    }
    for (int i = 0; i < N; ++i) for (int j = 0; j < N; ++j) {
        std::fprintf(f, ",C_%d_%d", i, j);
    }
    for (int i = 0; i < N; ++i) for (int j = 0; j < N; ++j) {
        std::fprintf(f, ",D_out_%d_%d", i, j);
    }
    std::fprintf(f, "\n");

    // Role row: meta for cycle, in for inputs, out for outputs
    std::fprintf(f, "meta");
    std::fprintf(f, ",in"); // rst
    std::fprintf(f, ",in"); // en
    std::fprintf(f, ",in"); // alpha
    std::fprintf(f, ",in"); // beta
    for (int i = 0; i < N*N; ++i) std::fprintf(f, ",in"); // A
    for (int i = 0; i < N*N; ++i) std::fprintf(f, ",in"); // B
    for (int i = 0; i < N*N; ++i) std::fprintf(f, ",in"); // C
    for (int i = 0; i < N*N; ++i) std::fprintf(f, ",out"); // D_out
    std::fprintf(f, "\n");

    // Testbench driving signals per cycle (deterministic, no randomness)
    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        uint32_t rst = (cycle < 2) ? 1u : 0u;
        uint32_t en  = (cycle < 2) ? 0u : 1u;

        DATA_TYPE alpha = 0;
        DATA_TYPE beta  = 0;
        DATA_TYPE A[N][N];
        DATA_TYPE B[N][N];
        DATA_TYPE Cmat[N][N];
        DATA_TYPE D_out[N][N];

        // During reset, hold inputs at zero
        if (rst) {
            alpha = 0;
            beta = 0;
            for (int i = 0; i < N; ++i) for (int j = 0; j < N; ++j) {
                A[i][j] = 0;
                B[i][j] = 0;
                Cmat[i][j] = 0;
                D_out[i][j] = 0;
            }
        } else {
            // Deterministic varied inputs depending on cycle index
            alpha = (DATA_TYPE)((cycle % 3) + 1);           // 1,2,3 repeating
            beta  = (DATA_TYPE)(((cycle + 1) % 3) + 1);    // 1,2,3 repeating with offset

            for (int i = 0; i < N; ++i) {
                for (int j = 0; j < N; ++j) {
                    // Values chosen to be small positive integers and vary with cycle, i, j
                    A[i][j] = (DATA_TYPE)( (uint32_t)(cycle) + 1u + (uint32_t)(i * 4 + j) );
                    B[i][j] = (DATA_TYPE)( (uint32_t)(cycle) + 2u + (uint32_t)(i + j * 4) );
                    Cmat[i][j] = (DATA_TYPE)( (uint32_t)(cycle) + 3u + (uint32_t)(i * 2 + j * 3) );
                }
            }
        }

        // Call DUT each cycle regardless of rst/en (as testbench samples outputs each cycle)
        syr2k(alpha, beta, A, B, Cmat, D_out);

        // Write CSV row: cycle (decimal), inputs (decimal), outputs (hex uppercase no 0x)
        std::fprintf(f, "%u", (unsigned)cycle);
        std::fprintf(f, ",%u", (unsigned)rst);
        std::fprintf(f, ",%u", (unsigned)en);
        std::fprintf(f, ",%u", (unsigned)alpha);
        std::fprintf(f, ",%u", (unsigned)beta);

        for (int i = 0; i < N; ++i) for (int j = 0; j < N; ++j) {
            std::fprintf(f, ",%u", (unsigned)A[i][j]);
        }
        for (int i = 0; i < N; ++i) for (int j = 0; j < N; ++j) {
            std::fprintf(f, ",%u", (unsigned)B[i][j]);
        }
        for (int i = 0; i < N; ++i) for (int j = 0; j < N; ++j) {
            std::fprintf(f, ",%u", (unsigned)Cmat[i][j]);
        }
        for (int i = 0; i < N; ++i) for (int j = 0; j < N; ++j) {
            // Print output in hexadecimal uppercase without 0x
            std::fprintf(f, ",%llX", (unsigned long long)D_out[i][j]);
        }
        std::fprintf(f, "\n");
    }

    std::fclose(f);
    return 0;
}

