// hls.cpp
#ifndef _ATAX_H
#define _ATAX_H

#include <stdint.h> // Use C header for fixed-width integer types (works with Vivado HLS C++98)

#define N 4
typedef int32_t DATA_TYPE;

extern "C" {

void atax(DATA_TYPE A[N][N], DATA_TYPE x[N], DATA_TYPE y_out[N]) {
#pragma HLS INTERFACE m_axi port=A offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=x offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=y_out offset=slave bundle=gmem2
#pragma HLS INTERFACE s_axilite port=A bundle=control
#pragma HLS INTERFACE s_axilite port=x bundle=control
#pragma HLS INTERFACE s_axilite port=y_out bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int i, j;
    DATA_TYPE buff_A[N][N];
#pragma HLS array_partition variable=buff_A block factor=2 dim=2
    DATA_TYPE buff_x[N];
#pragma HLS array_partition variable=buff_x cyclic factor=2 dim=1
    DATA_TYPE buff_y_out[N];
#pragma HLS array_partition variable=buff_y_out cyclic factor=2 dim=1
    DATA_TYPE tmp1[N];
#pragma HLS array_partition variable=tmp1 cyclic factor=2 dim=1

    // Load inputs into local buffers and initialize temporaries
    for (i = 0; i < N; i++) {
#pragma HLS pipeline
        buff_x[i] = x[i];
        buff_y_out[i] = 0;
        tmp1[i] = 0;
        for (j = 0; j < N; j++) {
#pragma HLS pipeline II=1
            buff_A[i][j] = A[i][j];
        }
    }

    // Compute tmp1 = A * x (row-wise dot products)
    for (i = 0; i < N; i++) {
#pragma HLS pipeline
        for (j = 0; j < N; j++) {
#pragma HLS unroll factor=2
            tmp1[i] += buff_A[i][j] * buff_x[j];
        }
    }

    // Compute y_out = A^T * tmp1 (accumulate per column)
    for (i = 0; i < N; i++) {
#pragma HLS pipeline II=1
        for (j = 0; j < N; j++) {
#pragma HLS unroll factor=2
            buff_y_out[j] += buff_A[i][j] * tmp1[i];
        }
    }

    // Write back results to external memory
    for (i = 0; i < N; i++) {
#pragma HLS pipeline
        y_out[i] = buff_y_out[i];
    }
}

} // extern "C"

#endif

