        fprintf(f, "%d,%d,", in_normals_0, in_variables_0);
        fprintf(f, "%d,%d,%d,%d,", in_fc_mom_x_0, in_fc_mom_y_0, in_fc_mom_z_0, in_fc_deneng_0);
        /* outputs in hex uppercase without 0x */
        fprintf(f, "%X,%X,%X,%X,%X\n", r0, r1, r2, r3, r4);
    }

    /* Cleanup */
    fclose(f);

    free(result);
    free(elems);
    free(normals);
    free(variables);
    free(fc_momentum_x);
    free(fc_momentum_y);
    free(fc_momentum_z);
    free(fc_density_energy);

    return 0;
}

