// hls.cpp
// Vivado HLS top-level for cfd_flux
// Keep implementation compatible with C-style interface (extern "C")

#include <cmath>
#include <cstring>

#define SIZE 1024
#define TILE_ROWS 64
#define NVAR 5
#define NNB 4
#define NDIM 3
#define PARA_FACTOR 2

#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY 4

#define GAMMA 1.4f

// Simple 3-component float vector used throughout
struct float3 {
    float x, y, z;
};

extern "C" {

void cfd_flux(float result[SIZE * NVAR],
              int elements_surrounding_elements[SIZE * NNB],
              float normals[SIZE * NNB * NDIM],
              float variables[SIZE * NVAR],
              float fc_momentum_x[SIZE * NDIM],
              float fc_momentum_y[SIZE * NDIM],
              float fc_momentum_z[SIZE * NDIM],
              float fc_density_energy[SIZE * NDIM]) {

#pragma HLS INTERFACE m_axi port=result offset=slave bundle=result
#pragma HLS INTERFACE m_axi port=elements_surrounding_elements offset=slave bundle=elements_surrounding_elements
#pragma HLS INTERFACE m_axi port=normals offset=slave bundle=normals
#pragma HLS INTERFACE m_axi port=variables offset=slave bundle=variables
#pragma HLS INTERFACE m_axi port=fc_momentum_x offset=slave bundle=fc_momentum_x
#pragma HLS INTERFACE m_axi port=fc_momentum_y offset=slave bundle=fc_momentum_y
#pragma HLS INTERFACE m_axi port=fc_momentum_z offset=slave bundle=fc_momentum_z
#pragma HLS INTERFACE m_axi port=fc_density_energy offset=slave bundle=fc_density_energy

#pragma HLS INTERFACE s_axilite port=result bundle=control
#pragma HLS INTERFACE s_axilite port=elements_surrounding_elements bundle=control
#pragma HLS INTERFACE s_axilite port=normals bundle=control
#pragma HLS INTERFACE s_axilite port=variables bundle=control
#pragma HLS INTERFACE s_axilite port=fc_momentum_x bundle=control
#pragma HLS INTERFACE s_axilite port=fc_momentum_y bundle=control
#pragma HLS INTERFACE s_axilite port=fc_momentum_z bundle=control
#pragma HLS INTERFACE s_axilite port=fc_density_energy bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    const float smoothing_coefficient = 0.2f;

    // Far-field / free-stream reference data
    float ff_variable[NVAR] = {1.3999999761581421f, 1.6800000667572021f, 0.0f, 0.0f, 3.5079998970031738f};

    float3 ff_fc_momentum_x = {3.016000270843506f, 0.0f, 0.0f};
    float3 ff_fc_momentum_y = {0.0f, 1.0f, 0.0f};
    float3 ff_fc_momentum_z = {0.0f, 0.0f, 1.0f};
    float3 ff_fc_density_energy = {5.409600257873535f, 0.0f, 0.0f};

L_outer: for (int k = 0; k < SIZE / TILE_ROWS; k++) {
#pragma HLS pipeline II=1

        int base_idx = k * TILE_ROWS;

    L1: for (int i = 0; i < TILE_ROWS / PARA_FACTOR; i++) {
#pragma HLS pipeline II=1
        for (int ii = 0; ii < PARA_FACTOR; ii++) {
#pragma HLS unroll factor=2
                int iii = base_idx + i * PARA_FACTOR + ii;

                int j, nb;
                float3 normal;
                float normal_len;
                float factor;

                float density_i = variables[NVAR * iii + VAR_DENSITY];
                float3 momentum_i;
                momentum_i.x = variables[NVAR * iii + (VAR_MOMENTUM + 0)];
                momentum_i.y = variables[NVAR * iii + (VAR_MOMENTUM + 1)];
                momentum_i.z = variables[NVAR * iii + (VAR_MOMENTUM + 2)];
                float density_energy_i = variables[NVAR * iii + VAR_DENSITY_ENERGY];

                // compute_velocity
                float3 velocity_i;
                velocity_i.x = momentum_i.x / density_i;
                velocity_i.y = momentum_i.y / density_i;
                velocity_i.z = momentum_i.z / density_i;

                // compute_speed_sqd
                float speed_sqd_i = velocity_i.x * velocity_i.x + velocity_i.y * velocity_i.y + velocity_i.z * velocity_i.z;
                float speed_i = sqrtf(speed_sqd_i);

                // compute_pressure
                float pressure_i = (GAMMA - 1.0f) * (density_energy_i - 0.5f * density_i * speed_sqd_i);

                // compute_speed_of_sound
                float speed_of_sound_i = sqrtf(GAMMA * pressure_i / density_i);

                float3 fc_i_momentum_x, fc_i_momentum_y, fc_i_momentum_z;
                float3 fc_i_density_energy;

                fc_i_momentum_x.x = fc_momentum_x[iii * NDIM + 0];
                fc_i_momentum_x.y = fc_momentum_x[iii * NDIM + 1];
                fc_i_momentum_x.z = fc_momentum_x[iii * NDIM + 2];

                fc_i_momentum_y.x = fc_momentum_y[iii * NDIM + 0];
                fc_i_momentum_y.y = fc_momentum_y[iii * NDIM + 1];
                fc_i_momentum_y.z = fc_momentum_y[iii * NDIM + 2];

                fc_i_momentum_z.x = fc_momentum_z[iii * NDIM + 0];
                fc_i_momentum_z.y = fc_momentum_z[iii * NDIM + 1];
                fc_i_momentum_z.z = fc_momentum_z[iii * NDIM + 2];

                fc_i_density_energy.x = fc_density_energy[iii * NDIM + 0];
                fc_i_density_energy.y = fc_density_energy[iii * NDIM + 1];
                fc_i_density_energy.z = fc_density_energy[iii * NDIM + 2];

                float flux_i_density = 0.0f;
                float3 flux_i_momentum = {0.0f, 0.0f, 0.0f};
                float flux_i_density_energy = 0.0f;

                float3 velocity_nb;
                float density_nb, density_energy_nb;
                float3 momentum_nb;
                float3 fc_nb_momentum_x, fc_nb_momentum_y, fc_nb_momentum_z;
                float3 fc_nb_density_energy;
                float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

            L2: for (j = 0; j < NNB; j++) {
#pragma HLS pipeline II=1
                    nb = elements_surrounding_elements[iii * NNB + j];
                    normal.x = normals[(iii * NNB + j) * NDIM + 0];
                    normal.y = normals[(iii * NNB + j) * NDIM + 1];
                    normal.z = normals[(iii * NNB + j) * NDIM + 2];
                    normal_len = sqrtf(normal.x * normal.x + normal.y * normal.y + normal.z * normal.z);

                    if (nb >= 0) {
                        density_nb = variables[NVAR * nb + VAR_DENSITY];
                        momentum_nb.x = variables[NVAR * nb + (VAR_MOMENTUM + 0)];
                        momentum_nb.y = variables[NVAR * nb + (VAR_MOMENTUM + 1)];
                        momentum_nb.z = variables[NVAR * nb + (VAR_MOMENTUM + 2)];
                        density_energy_nb = variables[NVAR * nb + VAR_DENSITY_ENERGY];

                        velocity_nb.x = momentum_nb.x / density_nb;
                        velocity_nb.y = momentum_nb.y / density_nb;
                        velocity_nb.z = momentum_nb.z / density_nb;

                        speed_sqd_nb = velocity_nb.x * velocity_nb.x + velocity_nb.y * velocity_nb.y + velocity_nb.z * velocity_nb.z;
                        pressure_nb = (GAMMA - 1.0f) * (density_energy_nb - 0.5f * density_nb * speed_sqd_nb);
                        speed_of_sound_nb = sqrtf(GAMMA * pressure_nb / density_nb);

                        fc_nb_momentum_x.x = fc_momentum_x[nb * NDIM + 0];
                        fc_nb_momentum_x.y = fc_momentum_x[nb * NDIM + 1];
                        fc_nb_momentum_x.z = fc_momentum_x[nb * NDIM + 2];

                        fc_nb_momentum_y.x = fc_momentum_y[nb * NDIM + 0];
                        fc_nb_momentum_y.y = fc_momentum_y[nb * NDIM + 1];
                        fc_nb_momentum_y.z = fc_momentum_y[nb * NDIM + 2];

                        fc_nb_momentum_z.x = fc_momentum_z[nb * NDIM + 0];
                        fc_nb_momentum_z.y = fc_momentum_z[nb * NDIM + 1];
                        fc_nb_momentum_z.z = fc_momentum_z[nb * NDIM + 2];

                        fc_nb_density_energy.x = fc_density_energy[nb * NDIM + 0];
                        fc_nb_density_energy.y = fc_density_energy[nb * NDIM + 1];
                        fc_nb_density_energy.z = fc_density_energy[nb * NDIM + 2];

                        factor = -normal_len * smoothing_coefficient * 0.5f * (speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                        flux_i_density += factor * (density_i - density_nb);
                        flux_i_density_energy += factor * (density_energy_i - density_energy_nb);
                        flux_i_momentum.x += factor * (momentum_i.x - momentum_nb.x);
                        flux_i_momentum.y += factor * (momentum_i.y - momentum_nb.y);
                        flux_i_momentum.z += factor * (momentum_i.z - momentum_nb.z);

                        factor = 0.5f * normal.x;
                        flux_i_density += factor * (momentum_nb.x + momentum_i.x);
                        flux_i_density_energy += factor * (fc_nb_density_energy.x + fc_i_density_energy.x);
                        flux_i_momentum.x += factor * (fc_nb_momentum_x.x + fc_i_momentum_x.x);
                        flux_i_momentum.y += factor * (fc_nb_momentum_y.x + fc_i_momentum_y.x);
                        flux_i_momentum.z += factor * (fc_nb_momentum_z.x + fc_i_momentum_z.x);

                        factor = 0.5f * normal.y;
                        flux_i_density += factor * (momentum_nb.y + momentum_i.y);
                        flux_i_density_energy += factor * (fc_nb_density_energy.y + fc_i_density_energy.y);
                        flux_i_momentum.x += factor * (fc_nb_momentum_x.y + fc_i_momentum_x.y);
                        flux_i_momentum.y += factor * (fc_nb_momentum_y.y + fc_i_momentum_y.y);
                        flux_i_momentum.z += factor * (fc_nb_momentum_z.y + fc_i_momentum_z.y);

                        factor = 0.5f * normal.z;
                        flux_i_density += factor * (momentum_nb.z + momentum_i.z);
                        flux_i_density_energy += factor * (fc_nb_density_energy.z + fc_i_density_energy.z);
                        flux_i_momentum.x += factor * (fc_nb_momentum_x.z + fc_i_momentum_x.z);
                        flux_i_momentum.y += factor * (fc_nb_momentum_y.z + fc_i_momentum_y.z);
                        flux_i_momentum.z += factor * (fc_nb_momentum_z.z + fc_i_momentum_z.z);
                    } else if (nb == -1) {
                        // wall boundary: add pressure contribution only to momentum flux
                        flux_i_momentum.x += normal.x * pressure_i;
                        flux_i_momentum.y += normal.y * pressure_i;
                        flux_i_momentum.z += normal.z * pressure_i;
                    } else if (nb == -2) {
                        // far-field boundary: use free-stream / ff_* values
                        factor = 0.5f * normal.x;
                        flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 0] + momentum_i.x);
                        flux_i_density_energy += factor * (ff_fc_density_energy.x + fc_i_density_energy.x);
                        flux_i_momentum.x += factor * (ff_fc_momentum_x.x + fc_i_momentum_x.x);
                        flux_i_momentum.y += factor * (ff_fc_momentum_y.x + fc_i_momentum_y.x);
                        flux_i_momentum.z += factor * (ff_fc_momentum_z.x + fc_i_momentum_z.x);

                        factor = 0.5f * normal.y;
                        flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 1] + momentum_i.y);
                        flux_i_density_energy += factor * (ff_fc_density_energy.y + fc_i_density_energy.y);
                        flux_i_momentum.x += factor * (ff_fc_momentum_x.y + fc_i_momentum_x.y);
                        flux_i_momentum.y += factor * (ff_fc_momentum_y.y + fc_i_momentum_y.y);
                        flux_i_momentum.z += factor * (ff_fc_momentum_z.y + fc_i_momentum_z.y);

                        factor = 0.5f * normal.z;
                        flux_i_density += factor * (ff_variable[VAR_MOMENTUM + 2] + momentum_i.z);
                        flux_i_density_energy += factor * (ff_fc_density_energy.z + fc_i_density_energy.z);
                        flux_i_momentum.x += factor * (ff_fc_momentum_x.z + fc_i_momentum_x.z);
                        flux_i_momentum.y += factor * (ff_fc_momentum_y.z + fc_i_momentum_y.z);
                        flux_i_momentum.z += factor * (ff_fc_momentum_z.z + fc_i_momentum_z.z);
                    }
                }

                result[iii * NVAR + VAR_DENSITY] = flux_i_density;
                result[iii * NVAR + (VAR_MOMENTUM + 0)] = flux_i_momentum.x;
                result[iii * NVAR + (VAR_MOMENTUM + 1)] = flux_i_momentum.y;
                result[iii * NVAR + (VAR_MOMENTUM + 2)] = flux_i_momentum.z;
                result[iii * NVAR + VAR_DENSITY_ENERGY] = flux_i_density_energy;
            }
        }
    }
}

} // extern "C"

hls_tb:
// tb_hls_cosim.cpp
// HLS cosimulation testbench for cfd_flux
// Keeps the original test patterns and CSV output format.
// Uses C headers compatible with Vivado HLS C++98 mode.

#include <cstdio>
#include <cstdlib>
#include <cmath>
#include <cstring>
#include <stdint.h> /* Use C header for compatibility with older libstdc++ / C++98 */

/* HLS testbench for cfd_flux
   Keep structure and style consistent with original C testbench.
   This file writes hls_output.csv which should contain RTL/cosim outputs.
*/

/* DUT interface macros and types (must match HLS DUT) */
#define GRID_ROWS (1024)
#define SIZE GRID_ROWS
#define TILE_ROWS 64
#define PARA_FACTOR 2
#define TOP 0
#define BOTTOM (GRID_ROWS / TILE_ROWS - 1)
#define GAMMA 1.4
#define NDIM 3
#define NNB 4
#define RK 3
#define ff_mach 1.2
#define deg_angle_of_attack 0.0f
#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)
#define TYPE float

typedef struct { float x, y, z; } float3;

/* extern "C" declaration must match HLS top-level exactly */
extern "C" void cfd_flux(float result[SIZE * NVAR], int elements_surrounding_elements [SIZE * NNB], float normals [SIZE * NNB * NDIM], 
                float variables [SIZE * NVAR], float fc_momentum_x [SIZE * NDIM], float fc_momentum_y [SIZE * NDIM], 
                float fc_momentum_z [SIZE * NDIM], float fc_density_energy [SIZE * NDIM]);

/* Helper to convert float to raw 32-bit representation for CSV output */
static inline uint32_t float_to_u32(float f) {
    union { float f; uint32_t u; } conv;
    conv.f = f;
    return conv.u;
}

int main()
{
    /* Allocate arrays */
    float* result = (float*)malloc(sizeof(float)*SIZE*NVAR);
    int* elems = (int*)malloc(sizeof(int)*SIZE*NNB);
    float* normals = (float*)malloc(sizeof(float)*SIZE*NNB*NDIM);
    float* variables = (float*)malloc(sizeof(float)*SIZE*NVAR);
    float* fc_momentum_x = (float*)malloc(sizeof(float)*SIZE*NDIM);
    float* fc_momentum_y = (float*)malloc(sizeof(float)*SIZE*NDIM);
    float* fc_momentum_z = (float*)malloc(sizeof(float)*SIZE*NDIM);
    float* fc_density_energy = (float*)malloc(sizeof(float)*SIZE*NDIM);

    if(!result || !elems || !normals || !variables || !fc_momentum_x || !fc_momentum_y || !fc_momentum_z || !fc_density_energy) {
        fprintf(stderr, "Allocation failed\n");
        return 1;
    }

    /* Prepare CSV file for HLS/RTL outputs */
    FILE* f = fopen("hls_output.csv", "w");
    if(!f) {
        fprintf(stderr, "Cannot open hls_output.csv for writing\n");
        return 1;
    }

    /* CSV header:
       First column: cycle (meta)
       Then input signals driven to DUT (sampled representative positions):
         elements_surrounding_elements[0],elements_surrounding_elements[1],
         normals[0],variables[0],
         fc_momentum_x[0],fc_momentum_y[0],fc_momentum_z[0],fc_density_energy[0]
       Then outputs sampled from DUT:
         result[0], result[1], result[2], result[3], result[4]
    */
    fprintf(f, "cycle,");
    fprintf(f, "elements_surrounding_elements[0],elements_surrounding_elements[1],");
    fprintf(f, "normals[0],variables[0],");
    fprintf(f, "fc_momentum_x[0],fc_momentum_y[0],fc_momentum_z[0],fc_density_energy[0],");
    fprintf(f, "result[0],result[1],result[2],result[3],result[4]\n");

    /* Role row */
    fprintf(f, "meta,");
    fprintf(f, "in,in,");
    fprintf(f, "in,in,");
    fprintf(f, "in,in,in,in,");
    fprintf(f, "out,out,out,out,out\n");

    /* Number of cycles: choose 20 (within 20..50) */
    const int CYCLES = 20;

    /* Initialize arrays to safe defaults */
    for (int i = 0; i < SIZE*NVAR; ++i) variables[i] = 1.0f;
    for (int i = 0; i < SIZE*NDIM; ++i) {
        fc_momentum_x[i] = 0.1f;
        fc_momentum_y[i] = 0.1f;
        fc_momentum_z[i] = 0.1f;
        fc_density_energy[i] = 0.1f;
    }
    for (int i = 0; i < SIZE*NNB; ++i) elems[i] = -2; /* default boundary condition */
    for (int i = 0; i < SIZE*NNB*NDIM; ++i) normals[i] = 1.0f;

    /* Drive test patterns equivalent to original C testbench */
    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        /* Modify variables deterministically */
        for (int idx = 0; idx < SIZE*NVAR; ++idx) {
            /* keep values positive and non-zero to avoid div-by-zero */
            variables[idx] = 1.0f + (float)((idx + cycle) % 5);
        }

        /* Modify face-centered arrays deterministically */
        for (int idx = 0; idx < SIZE*NDIM; ++idx) {
            fc_momentum_x[idx] = 0.1f * (1.0f + (float)((idx + cycle) % 3));
            fc_momentum_y[idx] = 0.2f * (1.0f + (float)((idx + cycle) % 4));
            fc_momentum_z[idx] = 0.3f * (1.0f + (float)((idx + cycle) % 5));
            fc_density_energy[idx] = 0.05f * (1.0f + (float)((idx + cycle) % 6));
        }

        /* Reset elems and normals to defaults */
        for (int i = 0; i < SIZE*NNB; ++i) elems[i] = -2;
        for (int i = 0; i < SIZE*NNB*NDIM; ++i) normals[i] = 1.0f;

        /* For cell 0, set neighbors based on cycle to exercise branches:
           cycle % 4 == 0 -> nb = 0 (interior neighbor)
           cycle % 4 == 1 -> nb = -1 (wall)
           cycle % 4 == 2 -> nb = -2 (far-field)
           cycle % 4 == 3 -> nb = 1 (interior neighbor 1)
        */
        int pattern = cycle % 4;
        for (int j = 0; j < NNB; ++j) {
            int idx = 0*NNB + j;
            if (pattern == 0) elems[idx] = 0;
            else if (pattern == 1) elems[idx] = -1;
            else if (pattern == 2) elems[idx] = -2;
            else elems[idx] = 1;
            /* vary normals for these neighbors */
            normals[(0*NNB + j)*NDIM + 0] = (float)(1 + ((cycle + j) % 3));
            normals[(0*NNB + j)*NDIM + 1] = (float)(1 + ((cycle + j + 1) % 3));
            normals[(0*NNB + j)*NDIM + 2] = (float)(1 + ((cycle + j + 2) % 3));
        }

        /* Also tweak a couple of other small indices to add variety but remain safe */
        elems[1] = (cycle % 5 == 0) ? 2 : -2;
        elems[2] = (cycle % 6 == 0) ? 3 : -2;

        /* Call DUT once per cycle (this will invoke RTL/HLS implementation during cosim) */
        cfd_flux(result, elems, normals, variables, fc_momentum_x, fc_momentum_y, fc_momentum_z, fc_density_energy);

        /* Sample inputs for CSV (as decimal integers) */
        int in_elems_0 = elems[0];
        int in_elems_1 = elems[1];
        int in_normals_0 = (int)normals[0];
        int in_variables_0 = (int)variables[0];
        int in_fc_mom_x_0 = (int)fc_momentum_x[0];
        int in_fc_mom_y_0 = (int)fc_momentum_y[0];
        int in_fc_mom_z_0 = (int)fc_momentum_z[0];
        int in_fc_deneng_0 = (int)fc_density_energy[0];

        /* Sample outputs: result[0..4] (as hex uppercase, raw bits, no 0x) */
        uint32_t r0 = float_to_u32(result[0]);
        uint32_t r1 = float_to_u32(result[1]);
        uint32_t r2 = float_to_u32(result[2]);
        uint32_t r3 = float_to_u32(result[3]);
        uint32_t r4 = float_to_u32(result[4]);

        /* Write CSV row */
        fprintf(f, "%d,", cycle);
        fprintf(f, "%d,%d,", in_elems_0, in_elems_1);
        fprintf(f, "%d,%d,", in_normals_0, in_variables_0);
        fprintf(f, "%d,%d,%d,%d,", in_fc_mom_x_0, in_fc_mom_y_0, in_fc_mom_z_0, in_fc_deneng_0);
        /* outputs in hex uppercase without 0x */
        fprintf(f, "%X,%X,%X,%X,%X\n", r0, r1, r2, r3, r4);
    }

    /* Cleanup */
    fclose(f);

    free(result);
    free(elems);
    free(normals);
    free(variables);
    free(fc_momentum_x);
    free(fc_momentum_y);
    free(fc_momentum_z);
    free(fc_density_energy);

    return 0;
}

