// hls.cpp
// Top-level HLS function for matrix multiply-accumulate (MAC).
// English comments only.
// The function is declared with extern "C" to match the testbench linkage.

extern "C" {

#define DATA_SIZE 16
#define MAX_SIZE 16

void mac_accel(
    const int *a,
    const int *b,
    int *c,
    int a_row,
    int a_col,
    int b_col
) {
#pragma HLS INTERFACE m_axi port=a offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=b offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=c offset=slave bundle=gmem2
#pragma HLS INTERFACE s_axilite port=a bundle=control
#pragma HLS INTERFACE s_axilite port=b bundle=control
#pragma HLS INTERFACE s_axilite port=c bundle=control
#pragma HLS INTERFACE s_axilite port=a_row bundle=control
#pragma HLS INTERFACE s_axilite port=a_col bundle=control
#pragma HLS INTERFACE s_axilite port=b_col bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int b_row = a_col;
    int c_row = a_row;
    int c_col = b_col;

    // Local buffers for A, B and C
    int localA[MAX_SIZE][MAX_SIZE];
#pragma HLS array_partition variable=localA cyclic factor=2 dim=1

    int localB[MAX_SIZE][MAX_SIZE];
#pragma HLS array_partition variable=localB complete dim=2

    int localC[MAX_SIZE][MAX_SIZE];
#pragma HLS array_partition variable=localC cyclic factor=2 dim=1

    // Initialize localC to zero to avoid reading uninitialized values
    init_c: for (int i = 0; i < MAX_SIZE; i++) {
#pragma HLS PIPELINE II=1
        for (int j = 0; j < MAX_SIZE; j++) {
#pragma HLS PIPELINE II=1
            localC[i][j] = 0;
        }
    }

    // Read matrix A from external memory into localA (row-major)
    readA: for (int loc = 0; loc < a_row * a_col; loc++) {
#pragma HLS PIPELINE II=1
        int i = loc / a_col;
        int j = loc % a_col;
        localA[i][j] = a[loc];
    }

    // Read matrix B from external memory into localB (row-major).
    // b has dimensions b_row x b_col, where b_row == a_col.
    readB: for (int loc = 0; loc < b_row * b_col; loc++) {
#pragma HLS PIPELINE II=1
        int i = loc / b_col;
        int j = loc % b_col;
        localB[i][j] = b[loc];
    }

    // Compute matrix multiply-accumulate:
    // localC = A * B, with dimensions c_row x c_col
    systolic_k: for (int k = 0; k < a_col; k++) {
#pragma HLS PIPELINE II=1
        systolic_i: for (int i = 0; i < c_row; i++) {
            systolic_j: for (int j = 0; j < c_col; j++) {
#pragma HLS PIPELINE II=1
                int last = localC[i][j];
                int a_val = (i < a_row && k < a_col) ? localA[i][k] : 0;
                int b_val = (k < b_row && j < b_col) ? localB[k][j] : 0;
                int result = last + a_val * b_val;
                localC[i][j] = result;
            }
        }
    }

    // Write result matrix C back to external memory (row-major)
    writeC: for (int loc = 0; loc < c_row * c_col; loc++) {
#pragma HLS PIPELINE II=1
        int i = loc / c_col;
        int j = loc % c_col;
        c[loc] = localC[i][j];
    }
}

} // extern "C"

