    test_images[1][(WIDTH/2) + (WIDTH/2)*WIDTH] = 255;

    // 2: horizontal edge (top half 255, bottom half 0)
    for(int r=0;r<WIDTH;r++){
        for(int c=0;c<WIDTH;c++){
            test_images[2][c + r*WIDTH] = (r < WIDTH/2) ? 255 : 0;
        }
    }

    // 3: vertical edge (left half 255, right half 0)
    for(int r=0;r<WIDTH;r++){
        for(int c=0;c<WIDTH;c++){
            test_images[3][c + r*WIDTH] = (c < WIDTH/2) ? 255 : 0;
        }
    }

    // 4: diagonal gradient (increasing values)
    for(int r=0;r<WIDTH;r++){
        for(int c=0;c<WIDTH;c++){
            test_images[4][c + r*WIDTH] = (r*WIDTH + c) * 16; // values 0..240
        }
    }

    // 5: checkerboard (0 / 255)
    for(int r=0;r<WIDTH;r++){
        for(int c=0;c<WIDTH;c++){
            test_images[5][c + r*WIDTH] = ((r + c) % 2) ? 255 : 0;
        }
    }

    // 6: deterministic pattern with period 3
    for(int r=0;r<WIDTH;r++){
        for(int c=0;c<WIDTH;c++){
            test_images[6][c + r*WIDTH] = ((r + 2*c) % 3) * 127; // values 0,127,254
        }
    }

    // 7: row-wise ramp 0,64,128,192
    for(int r=0;r<WIDTH;r++){
        for(int c=0;c<WIDTH;c++){
            test_images[7][c + r*WIDTH] = c * 64;
        }
    }

    // EDGE_THRESHOLD test values (deterministic)
    const int thresholds[] = {0, 100, 200};
    const int num_thresholds = sizeof(thresholds)/sizeof(thresholds[0]);

    // Prepare list of (image_id, threshold) pairs to create cycles
    const int cycles = num_images * num_thresholds; // 8 * 3 = 24 cycles
    int image_id_list[cycles];
    int threshold_list[cycles];
    int idx = 0;
    for(int img = 0; img < num_images; img++){
        for(int t = 0; t < num_thresholds; t++){
            image_id_list[idx] = img;
            threshold_list[idx] = thresholds[t];
            idx++;
        }
    }

    // Output image buffer
    int output_image[WIDTH*WIDTH];

    // Open CSV file
    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // Write header: cycle,inputImage,EDGE_THRESHOLD,outputImage_0,...,outputImage_15
    std::fprintf(f, "cycle,inputImage,EDGE_THRESHOLD");
    for(int i=0;i<WIDTH*WIDTH;i++){
        std::fprintf(f, ",outputImage_%d", i);
    }
    std::fprintf(f, "\n");

    // Write roles row: meta/in/in,out,...
    std::fprintf(f, "meta,in,in");
    for(int i=0;i<WIDTH*WIDTH;i++){
        std::fprintf(f, ",out");
    }
    std::fprintf(f, "\n");

    // For each cycle call DUT and write one CSV row
    for(int cyc = 0; cyc < cycles; cyc++) {
        int img_id = image_id_list[cyc];
        int thr = threshold_list[cyc];

        // Call DUT
        sobel(test_images[img_id], output_image, thr);

        // Write CSV row: cycle (decimal), inputImage (image id decimal), EDGE_THRESHOLD decimal,
        // then each outputImage element as hex uppercase without 0x and no fixed width
        std::fprintf(f, "%d,%d,%d", cyc, img_id, thr);
        for(int i=0;i<WIDTH*WIDTH;i++){
            // output values are small (0 or 255 or other), print hex uppercase without prefix
            // Use manual formatting to avoid leading zeros
            if (output_image[i] == 0) {
                std::fprintf(f, ",0");
            } else {
                // For positive values, print as uppercase hex
                std::fprintf(f, ",%X", (unsigned int)output_image[i]);
            }
        }
        std::fprintf(f, "\n");
    }

    // Explicitly close file
    std::fclose(f);
    return 0;
}

