// hls.cpp
// Sobel edge detector top-level for Vivado HLS
// - Mirrors the reference C testbench behavior exactly
// - Builds a padded image buffer (WIDTH+2 x WIDTH+2) with zero padding
// - Computes Gx and Gy using the Sobel kernels
// - Computes gradient = (int) sqrt(Gx*Gx + Gy*Gy)
// - Compares using '>' against EDGE_THRESHOLD and writes 255 or 0
//
// Use plain C headers for compatibility with older Vivado HLS toolchain (C++98).
// The top-level function is exported with C linkage for HLS compatibility.

#include <stdint.h>
#include <string.h>
#include <math.h>

#ifndef WIDTH
#define WIDTH 4
#endif

#ifndef HEIGHT
#define HEIGHT WIDTH
#endif

extern "C" {
void sobel(int *inputImage, int *outputImage, int EDGE_THRESHOLD) {
#pragma HLS INTERFACE m_axi port=inputImage offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=outputImage offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=inputImage bundle=control
#pragma HLS INTERFACE s_axilite port=outputImage bundle=control
#pragma HLS INTERFACE s_axilite port=EDGE_THRESHOLD bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    /* Local padded image buffer to match the C reference implementation */
    int image_data[WIDTH + 2][WIDTH + 2];

    /* Initialize padded buffer to zero and copy inputImage into the center */
    for (int p = 0; p < WIDTH + 2; p++) {
        for (int q = 0; q < WIDTH + 2; q++) {
#pragma HLS PIPELINE II=1
            image_data[p][q] = 0;
        }
    }

    for (int p = 1; p <= WIDTH; p++) {
        for (int q = 1; q <= WIDTH; q++) {
#pragma HLS PIPELINE II=1
            /* p and q are 1-based inside padded buffer; map to inputImage indices (column + row*WIDTH) */
            image_data[p][q] = inputImage[(q - 1) + (p - 1) * WIDTH];
        }
    }

    /* Compute Gx, Gy and gradient exactly as in the C reference */
    for (int i = 1; i < WIDTH + 1; i++) {
        for (int j = 1; j < WIDTH + 1; j++) {
#pragma HLS PIPELINE II=1
            int Gx = (image_data[i - 1][j - 1] + 2 * image_data[i - 1][j] + image_data[i - 1][j + 1])
                     - (image_data[i + 1][j - 1] + 2 * image_data[i + 1][j] + image_data[i + 1][j + 1]);

            int Gy = (image_data[i - 1][j - 1] + 2 * image_data[i][j - 1] + image_data[i + 1][j - 1])
                     - (image_data[i - 1][j + 1] + 2 * image_data[i][j + 1] + image_data[i + 1][j + 1]);

            /* Use the same sqrt and cast to int behavior as the reference C code */
            int gradient = (int) sqrt((double)(Gx * Gx + Gy * Gy));

            if (gradient > EDGE_THRESHOLD) {
                outputImage[(j - 1) + WIDTH * (i - 1)] = 255;
            } else {
                outputImage[(j - 1) + WIDTH * (i - 1)] = 0;
            }
        }
    }
}
} // extern "C"

