// DUT configuration
#define N 8
typedef int32_t IN_TYPE;
typedef double TEMP_TYPE;

// DUT implementation (as provided, adapted to types above)
void dft(IN_TYPE sample_real[N], IN_TYPE sample_imag[N]) {
    int i, j;
    TEMP_TYPE w;
    TEMP_TYPE c, s;

    TEMP_TYPE temp_real[N];
    TEMP_TYPE temp_imag[N];

    const TEMP_TYPE two_pi_over_N = 2.0 * 3.141592653589 / (TEMP_TYPE)N;

    for (i = 0; i < N; i++) {
        temp_real[i] = 0.0;
        temp_imag[i] = 0.0;

        w = two_pi_over_N * (TEMP_TYPE)i;

        for (j = 0; j < N; j++) {
            c = cos(j * w);
            s = sin(j * w);

            temp_real[i] += ((TEMP_TYPE)sample_real[j] * c - (TEMP_TYPE)sample_imag[j] * s);
            temp_imag[i] += ((TEMP_TYPE)sample_real[j] * s - (TEMP_TYPE)sample_imag[j] * c);
        }
    }

    for (i = 0; i < N; i++) {
        sample_real[i] = (IN_TYPE)temp_real[i];
        sample_imag[i] = (IN_TYPE)temp_imag[i];
    }
}

int main() {
    const int NUM_CYCLES = 24;

    // Input signals driven by testbench (these names will appear in CSV as inputs)
    IN_TYPE in_sample_real[N];
    IN_TYPE in_sample_imag[N];

    // Arrays passed to DUT and read back as outputs
    IN_TYPE sample_real[N];
    IN_TYPE sample_imag[N];

    // Prepare output CSV
    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // Write header: cycle, then input signal element names, then output signal element names
    // Input names: in_sample_real[0]..in_sample_real[N-1], in_sample_imag[0]..in_sample_imag[N-1]
    // Output names: sample_real[0]..sample_real[N-1], sample_imag[0]..sample_imag[N-1]
    std::fprintf(f, "cycle");
    for (int i = 0; i < N; ++i) {
        std::fprintf(f, ",in_sample_real[%d]", i);
    }
    for (int i = 0; i < N; ++i) {
        std::fprintf(f, ",in_sample_imag[%d]", i);
    }
    for (int i = 0; i < N; ++i) {
        std::fprintf(f, ",sample_real[%d]", i);
    }
    for (int i = 0; i < N; ++i) {
        std::fprintf(f, ",sample_imag[%d]", i);
    }
    std::fprintf(f, "\n");

    // Role row
    std::fprintf(f, "meta");
    for (int i = 0; i < N * 2; ++i) std::fprintf(f, ",in");
    for (int i = 0; i < N * 2; ++i) std::fprintf(f, ",out");
    std::fprintf(f, "\n");

    // Deterministic test vectors for each cycle (no randomness)
    for (int cycle = 0; cycle < NUM_CYCLES; ++cycle) {
        // Define input vectors for this cycle
        // First 12 cycles: hand-picked patterns; remaining cycles: deterministic formula
        if (cycle == 0) {
            // impulse at 0, real only
            IN_TYPE r[N] = {1,0,0,0,0,0,0,0};
            IN_TYPE im[N] = {0};
            std::memcpy(in_sample_real, r, sizeof(r));
            std::memcpy(in_sample_imag, im, sizeof(im));
        } else if (cycle == 1) {
            IN_TYPE r[N] = {0,1,0,0,0,0,0,0};
            IN_TYPE im[N] = {0};
            std::memcpy(in_sample_real, r, sizeof(r));
            std::memcpy(in_sample_imag, im, sizeof(im));
        } else if (cycle == 2) {
            IN_TYPE r[N] = {0,0,1,0,0,0,0,0};
            IN_TYPE im[N] = {0};
            std::memcpy(in_sample_real, r, sizeof(r));
            std::memcpy(in_sample_imag, im, sizeof(im));
        } else if (cycle == 3) {
            IN_TYPE r[N] = {0,0,0,1,0,0,0,0};
            IN_TYPE im[N] = {0};
            std::memcpy(in_sample_real, r, sizeof(r));
            std::memcpy(in_sample_imag, im, sizeof(im));
        } else if (cycle == 4) {
            // all ones (DC)
            for (int i = 0; i < N; ++i) { in_sample_real[i] = 1; in_sample_imag[i] = 0; }
        } else if (cycle == 5) {
            // ramp real, imag zeros
            for (int i = 0; i < N; ++i) { in_sample_real[i] = i; in_sample_imag[i] = 0; }
        } else if (cycle == 6) {
            // alternating signs
            for (int i = 0; i < N; ++i) { in_sample_real[i] = (i % 2) ? -1 : 1; in_sample_imag[i] = 0; }
        } else if (cycle == 7) {
            // small sinusoid-like pattern (discrete)
            IN_TYPE r[N] = {0,1,0,-1,0,1,0,-1};
            IN_TYPE im[N] = {0};
            std::memcpy(in_sample_real, r, sizeof(r));
            std::memcpy(in_sample_imag, im, sizeof(im));
        } else if (cycle == 8) {
            // increasing sequence and decreasing imag
            IN_TYPE r[N] = {1,2,3,4,5,6,7,8};
            IN_TYPE im[N] = {8,7,6,5,4,3,2,1};
            std::memcpy(in_sample_real, r, sizeof(r));
            std::memcpy(in_sample_imag, im, sizeof(im));
        } else if (cycle == 9) {
            // imag impulse
            IN_TYPE r[N] = {0};
            IN_TYPE im[N] = {1,0,0,0,0,0,0,0};
            std::memcpy(in_sample_real, r, sizeof(r));
            std::memcpy(in_sample_imag, im, sizeof(im));
        } else if (cycle == 10) {
            // imag ramp
            for (int i = 0; i < N; ++i) { in_sample_real[i] = 0; in_sample_imag[i] = i; }
        } else if (cycle == 11) {
            // both ones
            for (int i = 0; i < N; ++i) { in_sample_real[i] = 1; in_sample_imag[i] = 1; }
        } else {
            // Deterministic formula based on cycle index to give varied patterns
            // Ensure values remain modest
            for (int i = 0; i < N; ++i) {
                in_sample_real[i] = (IN_TYPE)(((cycle * 3 + i * 2) % 11) - 5);   // values -5..5
                in_sample_imag[i] = (IN_TYPE)(((cycle * 2 + i * 3) % 9) - 4);    // values -4..4
            }
        }

        // Copy inputs into DUT parameter arrays
        for (int i = 0; i < N; ++i) {
            sample_real[i] = in_sample_real[i];
            sample_imag[i] = in_sample_imag[i];
        }

        // Call DUT once per cycle
        dft(sample_real, sample_imag);

        // Write CSV row:
        // cycle (decimal), inputs (decimal), outputs (hex uppercase, no 0x)
        std::fprintf(f, "%d", cycle);
        // inputs: in_sample_real
        for (int i = 0; i < N; ++i) {
            std::fprintf(f, ",%d", (int)in_sample_real[i]);
        }
        // inputs: in_sample_imag
        for (int i = 0; i < N; ++i) {
            std::fprintf(f, ",%d", (int)in_sample_imag[i]);
        }
        // outputs: sample_real (hex uppercase)
        for (int i = 0; i < N; ++i) {
            // cast to unsigned for hex representation
            uint32_t v = (uint32_t)sample_real[i];
            std::fprintf(f, ",%X", v);
        }
        // outputs: sample_imag (hex uppercase)
        for (int i = 0; i < N; ++i) {
            uint32_t v = (uint32_t)sample_imag[i];
            std::fprintf(f, ",%X", v);
        }
        std::fprintf(f, "\n");
    }

    std::fclose(f);
    return 0;
}

