// hls.cpp
// HLS top function for DFT. Adjusted to be compatible with Vivado HLS.
// The implementation uses the same numeric formulas (including the same PI
// approximation) as the C reference testbench so that outputs match exactly.
//
// Notes:
//  - Keep extern "C" linkage so the testbench can link to this function.
//  - Interface pragmas are provided for Vivado HLS synthesis/simulation.
//  - Use double precision (TEMP_TYPE) for intermediate computations.

#include <stdint.h>
#include <math.h>

extern "C" {

#define N 8

// Use the same types as the C testbench
typedef int32_t IN_TYPE;
typedef double TEMP_TYPE;

// Top-level HLS function
void dft(IN_TYPE sample_real[N], IN_TYPE sample_imag[N]) {
#pragma HLS INTERFACE m_axi port=sample_real offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=sample_imag offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=sample_real bundle=control
#pragma HLS INTERFACE s_axilite port=sample_imag bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Temporary accumulators
    TEMP_TYPE temp_real[N];
#pragma HLS array_partition variable=temp_real cyclic factor=8 dim=1
    TEMP_TYPE temp_imag[N];
#pragma HLS array_partition variable=temp_imag cyclic factor=8 dim=1

    // Use the same PI approximation as the C testbench to ensure identical results
    const TEMP_TYPE two_pi_over_N = 2.0 * (TEMP_TYPE)3.141592653589 / (TEMP_TYPE)N;

    // Compute DFT in an O(N^2) straightforward way.
    for (int i = 0; i < N; ++i) {
#pragma HLS pipeline II=1
        temp_real[i] = 0.0;
        temp_imag[i] = 0.0;

        TEMP_TYPE w = two_pi_over_N * (TEMP_TYPE)i;

        for (int j = 0; j < N; ++j) {
#pragma HLS pipeline II=1
            TEMP_TYPE angle = (TEMP_TYPE)j * w;
            TEMP_TYPE c = cos(angle);
            TEMP_TYPE s = sin(angle);

            TEMP_TYPE xr = (TEMP_TYPE)sample_real[j];
            TEMP_TYPE xi = (TEMP_TYPE)sample_imag[j];

            // Match the reference C testbench formula exactly:
            // temp_real += xr * c - xi * s
            // temp_imag += xr * s - xi * c
            temp_real[i] += (xr * c - xi * s);
            temp_imag[i] += (xr * s - xi * c);
        }
    }

    // Cast back to integer outputs (same truncation behaviour as the C testbench)
    for (int i = 0; i < N; ++i) {
#pragma HLS pipeline II=1
        sample_real[i] = (IN_TYPE)temp_real[i];
        sample_imag[i] = (IN_TYPE)temp_imag[i];
    }
}

} // extern "C"

