// Testbench for the HLS DFT top function.
// This testbench uses the exact same test vectors and CSV format as the
// provided C testbench. It drives the HLS top function and writes CSV
// rows with inputs (decimal) and outputs (hex uppercase).
//
// Do not modify test vectors  they must match the original C testbench.

#include <cstdio>
#include <cstdlib>
#include <math.h>
