// hls.cpp
// Top-level LU decomposition function for Vivado HLS.
// The top function uses C linkage so the testbench (cosim) can call it.

#define N 40

#ifdef __cplusplus
extern "C" {
#endif

// Perform an in-place Doolittle-like LU decomposition without pivoting.
// A is an NxN matrix stored in row-major order.
//
// Notes for HLS:
// - The A port is mapped to an AXI master interface (m_axi) so host/cosim can
//   read/write the matrix in memory. A lightweight AXI-lite control interface
//   is provided for the pointer and return.
//
// - Use local temporaries (sum) to avoid multiple memory reads/writes where
//   possible; this is also friendlier for HLS simulation/synthesis.
void lu(double A[N][N]) {
#pragma HLS INTERFACE m_axi port=A offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=A bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int i, j, k;

    // Simple in-place Doolittle-like LU without pivoting.
    for (i = 0; i < N; i++) {
        // Compute L column entries below diagonal for column i
        for (j = 0; j < i; j++) {
            double sum = A[i][j];
            for (k = 0; k < j; k++) {
                sum -= A[i][k] * A[k][j];
            }
            A[i][j] = sum / A[j][j];
        }
        // Compute U row entries on and above diagonal for row i
        for (j = i; j < N; j++) {
            double sum = A[i][j];
            for (k = 0; k < i; k++) {
                sum -= A[i][k] * A[k][j];
            }
            A[i][j] = sum;
        }
    }
}

#ifdef __cplusplus
} // extern "C"
#endif

