// test.cpp
#include <stdio.h>
#include <math.h>

// Define types and sizes locally so this module is independently compilable.
typedef float data_t;
#define C 33
#define H 15
#define W 15

// Apply tanh element-wise for a 3D array.
// Named tanh_array to avoid collision with the math library tanh.
void tanh_array(data_t input[C][H][W], data_t output[C][H][W]) {
    for (int c = 0; c < C; ++c) {
        for (int h = 0; h < H; ++h) {
            for (int w = 0; w < W; ++w) {
                output[c][h][w] = tanhf(input[c][h][w]);
            }
        }
    }
}

int main() {
    static data_t input[C][H][W];
    static data_t output[C][H][W];

    for (int c = 0; c < C; ++c) {
        for (int h = 0; h < H; ++h) {
            for (int w = 0; w < W; ++w) {
                input[c][h][w] = ((float)(c * H * W + h * W + w) * 0.001f) - 1.0f;
            }
        }
    }

    tanh_array(input, output);

    printf("output[0][0][0] = %f\n", output[0][0][0]);
    printf("output[C-1][H-1][W-1] = %f\n", output[C-1][H-1][W-1]);
    // Ensure this index is in bounds given our chosen dimensions
    printf("output[32][14][14] = %f\n", output[32][14][14]);

    return 0;
}

