// hls.cpp
// HLS top-level that matches the C testbench behavior exactly.
// - The DUT processes exactly one element per invocation (simulating one element per cycle).
// - The DUT preserves previous output elements between calls.
// - A local, self-contained tanh implementation is used to avoid including the system math
//   headers which may declare a conflicting 'tanh' symbol in the global namespace.
// - Internal state (output buffer and pointer) is static so it persists across invocations.
// - The top-level name is 'tanh' (extern "C") to match the testbench signature.
//
// NOTE: keep headers minimal and C-style to maximize compatibility with older Vivado HLS toolchains.

#include <string.h> // for memcpy/memset

typedef float data_t;

#define C 2
#define H 2
#define W 3

// Small range-controlled exponential approximation using range reduction + series.
// Good enough for the modest values used in the testbench (inputs roughly within -6..+6).
static double local_exp(double x) {
    // Handle extreme values explicitly
    if (x < -50.0) return 0.0;
    if (x > 50.0) return 1e308; // large number to represent overflow-ish behavior

    // Range reduction: x = k*ln2 + r with r in approximately [-ln2/2, ln2/2]
    const double ln2 = 0.6931471805599453;
    int k = (int)(x / ln2 + (x >= 0.0 ? 0.5 : -0.5));
    double r = x - k * ln2;

    // Compute exp(r) via Taylor series around 0
    double term = 1.0;
    double sum = 1.0;
    for (int n = 1; n < 40; ++n) {
        term *= r / (double)n;
        sum += term;
        // convergence: absolute term very small
        if (term > -1e-16 && term < 1e-16) break;
    }

    // Multiply by 2^k (k is modest for our input range)
    double result = sum;
    if (k > 0) {
        for (int i = 0; i < k; ++i) result *= 2.0;
    } else if (k < 0) {
        for (int i = 0; i < -k; ++i) result *= 0.5;
    }
    return result;
}

// Local, self-contained float tanh implementation to avoid using the system tanh/tanhf symbol.
static inline float local_tanhf(float x) {
    double xd = (double)x;
    double e = local_exp(2.0 * xd);
    // If exponential is extremely large treat as saturation to avoid NaNs
    if (e > 1e200) {
        return x > 0.0f ? 1.0f : -1.0f;
    }
    double y = (e - 1.0) / (e + 1.0);
    return (float)y;
}

// Top-level must have C linkage and the exact name used by the testbench.
extern "C" void tanh(data_t input[C][H][W], data_t output[C][H][W]) {
#pragma HLS INTERFACE m_axi port=input offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=output offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=input bundle=control
#pragma HLS INTERFACE s_axilite port=output bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Persistent output buffer and processing pointer
    static data_t out_buf[C][H][W];
    static int ptr = 0;
    static int initialized = 0;

    // Initialize persistent state on first invocation
    if (!initialized) {
        for (int c = 0; c < C; ++c) {
            for (int h = 0; h < H; ++h) {
                for (int w = 0; w < W; ++w) {
                    out_buf[c][h][w] = 0.0f;
                }
            }
        }
        ptr = 0;
        initialized = 1;
    }

    // Process exactly one element per call to match the cycle-by-cycle behavior of the C testbench.
    {
        const int N = C * H * W;
        int cur = ptr % N;
        int cc = cur / (H * W);
        int rem = cur % (H * W);
        int hh = rem / W;
        int ww = rem % W;

        // Compute tanh for this one element using the local implementation
        out_buf[cc][hh][ww] = local_tanhf(input[cc][hh][ww]);

        // Advance pointer (wrap-around)
        ptr = (ptr + 1) % N;
    }

    // Copy persistent buffer to the output argument (the testbench expects the full feature map).
    for (int c = 0; c < C; ++c) {
        for (int h = 0; h < H; ++h) {
            for (int w = 0; w < W; ++w) {
                output[c][h][w] = out_buf[c][h][w];
            }
        }
    }
}

