// Initial permutation: produce two 32-bit halves in state
static void IP(des_state_t state, const des_block_t in) {
    state[0] =
        BITNUM(in, 57, 31) | BITNUM(in, 49, 30) | BITNUM(in, 41, 29) |
        BITNUM(in, 33, 28) | BITNUM(in, 25, 27) | BITNUM(in, 17, 26) |
        BITNUM(in, 9, 25) | BITNUM(in, 1, 24) | BITNUM(in, 59, 23) |
        BITNUM(in, 51, 22) | BITNUM(in, 43, 21) | BITNUM(in, 35, 20) |
        BITNUM(in, 27, 19) | BITNUM(in, 19, 18) | BITNUM(in, 11, 17) |
        BITNUM(in, 3, 16) | BITNUM(in, 61, 15) | BITNUM(in, 53, 14) |
        BITNUM(in, 45, 13) | BITNUM(in, 37, 12) | BITNUM(in, 29, 11) |
        BITNUM(in, 21, 10) | BITNUM(in, 13, 9) | BITNUM(in, 5, 8) |
        BITNUM(in, 63, 7) | BITNUM(in, 55, 6) | BITNUM(in, 47, 5) |
        BITNUM(in, 39, 4) | BITNUM(in, 31, 3) | BITNUM(in, 23, 2) |
        BITNUM(in, 15, 1) | BITNUM(in, 7, 0);

    state[1] =
        BITNUM(in, 56, 31) | BITNUM(in, 48, 30) | BITNUM(in, 40, 29) |
        BITNUM(in, 32, 28) | BITNUM(in, 24, 27) | BITNUM(in, 16, 26) |
        BITNUM(in, 8, 25) | BITNUM(in, 0, 24) | BITNUM(in, 58, 23) |
        BITNUM(in, 50, 22) | BITNUM(in, 42, 21) | BITNUM(in, 34, 20) |
        BITNUM(in, 26, 19) | BITNUM(in, 18, 18) | BITNUM(in, 10, 17) |
        BITNUM(in, 2, 16) | BITNUM(in, 60, 15) | BITNUM(in, 52, 14) |
        BITNUM(in, 44, 13) | BITNUM(in, 36, 12) | BITNUM(in, 28, 11) |
        BITNUM(in, 20, 10) | BITNUM(in, 12, 9) | BITNUM(in, 4, 8) |
        BITNUM(in, 62, 7) | BITNUM(in, 54, 6) | BITNUM(in, 46, 5) |
        BITNUM(in, 38, 4) | BITNUM(in, 30, 3) | BITNUM(in, 22, 2) |
        BITNUM(in, 14, 1) | BITNUM(in, 6, 0);
}

// Inverse initial permutation: reconstruct bytes from two 32-bit halves
static void InvIP(const des_state_t state, des_block_t out) {
    out[0] = BITNUMINTR(state[1], 7, 7) | BITNUMINTR(state[0], 7, 6) |
             BITNUMINTR(state[1], 15, 5) | BITNUMINTR(state[0], 15, 4) |
             BITNUMINTR(state[1], 23, 3) | BITNUMINTR(state[0], 23, 2) |
             BITNUMINTR(state[1], 31, 1) | BITNUMINTR(state[0], 31, 0);

    out[1] = BITNUMINTR(state[1], 6, 7) | BITNUMINTR(state[0], 6, 6) |
             BITNUMINTR(state[1], 14, 5) | BITNUMINTR(state[0], 14, 4) |
             BITNUMINTR(state[1], 22, 3) | BITNUMINTR(state[0], 22, 2) |
             BITNUMINTR(state[1], 30, 1) | BITNUMINTR(state[0], 30, 0);

    out[2] = BITNUMINTR(state[1], 5, 7) | BITNUMINTR(state[0], 5, 6) |
             BITNUMINTR(state[1], 13, 5) | BITNUMINTR(state[0], 13, 4) |
             BITNUMINTR(state[1], 21, 3) | BITNUMINTR(state[0], 21, 2) |
             BITNUMINTR(state[1], 29, 1) | BITNUMINTR(state[0], 29, 0);

    out[3] = BITNUMINTR(state[1], 4, 7) | BITNUMINTR(state[0], 4, 6) |
             BITNUMINTR(state[1], 12, 5) | BITNUMINTR(state[0], 12, 4) |
             BITNUMINTR(state[1], 20, 3) | BITNUMINTR(state[0], 20, 2) |
             BITNUMINTR(state[1], 28, 1) | BITNUMINTR(state[0], 28, 0);

    out[4] = BITNUMINTR(state[1], 3, 7) | BITNUMINTR(state[0], 3, 6) |
             BITNUMINTR(state[1], 11, 5) | BITNUMINTR(state[0], 11, 4) |
             BITNUMINTR(state[1], 19, 3) | BITNUMINTR(state[0], 19, 2) |
             BITNUMINTR(state[1], 27, 1) | BITNUMINTR(state[0], 27, 0);

    out[5] = BITNUMINTR(state[1], 2, 7) | BITNUMINTR(state[0], 2, 6) |
             BITNUMINTR(state[1], 10, 5) | BITNUMINTR(state[0], 10, 4) |
             BITNUMINTR(state[1], 18, 3) | BITNUMINTR(state[0], 18, 2) |
             BITNUMINTR(state[1], 26, 1) | BITNUMINTR(state[0], 26, 0);

    out[6] = BITNUMINTR(state[1], 1, 7) | BITNUMINTR(state[0], 1, 6) |
             BITNUMINTR(state[1], 9, 5) | BITNUMINTR(state[0], 9, 4) |
             BITNUMINTR(state[1], 17, 3) | BITNUMINTR(state[0], 17, 2) |
             BITNUMINTR(state[1], 25, 1) | BITNUMINTR(state[0], 25, 0);

    out[7] = BITNUMINTR(state[1], 0, 7) | BITNUMINTR(state[0], 0, 6) |
             BITNUMINTR(state[1], 8, 5) | BITNUMINTR(state[0], 8, 4) |
             BITNUMINTR(state[1], 16, 3) | BITNUMINTR(state[0], 16, 2) |
             BITNUMINTR(state[1], 24, 1) | BITNUMINTR(state[0], 24, 0);
}

// DES 'f' function: expansion, key mixing, S-boxes, P-permutation
static unsigned int f(unsigned int state, const des_subkey_t key) {
    unsigned char lrgstate[6];
#pragma HLS array_partition variable=lrgstate block factor=2 dim=1
    unsigned int t1, t2;

    t1 = BITNUMINTL(state, 31, 0) | ((state & 0xf0000000u) >> 1) |
         BITNUMINTL(state, 4, 5) | BITNUMINTL(state, 3, 6) |
         ((state & 0x0f000000u) >> 3) | BITNUMINTL(state, 8, 11) |
         BITNUMINTL(state, 7, 12) | ((state & 0x00f00000u) >> 5) |
         BITNUMINTL(state, 12, 17) | BITNUMINTL(state, 11, 18) |
         ((state & 0x000f0000u) >> 7) | BITNUMINTL(state, 16, 23);

    t2 = BITNUMINTL(state, 15, 0) | ((state & 0x0000f000u) << 15) |
         BITNUMINTL(state, 20, 5) | BITNUMINTL(state, 19, 6) |
         ((state & 0x00000f00u) << 13) | BITNUMINTL(state, 24, 11) |
         BITNUMINTL(state, 23, 12) | ((state & 0x000000f0u) << 11) |
         BITNUMINTL(state, 28, 17) | BITNUMINTL(state, 27, 18) |
         ((state & 0x0000000fu) << 9) | BITNUMINTL(state, 0, 23);

    lrgstate[0] = (t1 >> 24) & 0x000000ffu;
    lrgstate[1] = (t1 >> 16) & 0x000000ffu;
    lrgstate[2] = (t1 >> 8) & 0x000000ffu;
    lrgstate[3] = (t2 >> 24) & 0x000000ffu;
    lrgstate[4] = (t2 >> 16) & 0x000000ffu;
    lrgstate[5] = (t2 >> 8) & 0x000000ffu;

    lrgstate[0] ^= key[0];
    lrgstate[1] ^= key[1];
    lrgstate[2] ^= key[2];
    lrgstate[3] ^= key[3];
    lrgstate[4] ^= key[4];
    lrgstate[5] ^= key[5];

    state = (sbox1[SBOXBIT(lrgstate[0] >> 2)] << 28) |
            (sbox2[SBOXBIT(((lrgstate[0] & 0x03) << 4) | (lrgstate[1] >> 4))] << 24) |
            (sbox3[SBOXBIT(((lrgstate[1] & 0x0f) << 2) | (lrgstate[2] >> 6))] << 20) |
            (sbox4[SBOXBIT(lrgstate[2] & 0x3f)] << 16) |
            (sbox5[SBOXBIT(lrgstate[3] >> 2)] << 12) |
            (sbox6[SBOXBIT(((lrgstate[3] & 0x03) << 4) | (lrgstate[4] >> 4))] << 8) |
            (sbox7[SBOXBIT(((lrgstate[4] & 0x0f) << 2) | (lrgstate[5] >> 6))] << 4) |
            sbox8[SBOXBIT(lrgstate[5] & 0x3f)];

    state = BITNUMINTL(state, 15, 0) | BITNUMINTL(state, 6, 1) |
            BITNUMINTL(state, 19, 2) | BITNUMINTL(state, 20, 3) |
            BITNUMINTL(state, 28, 4) | BITNUMINTL(state, 11, 5) |
            BITNUMINTL(state, 27, 6) | BITNUMINTL(state, 16, 7) |
            BITNUMINTL(state, 0, 8) | BITNUMINTL(state, 14, 9) |
            BITNUMINTL(state, 22, 10) | BITNUMINTL(state, 25, 11) |
            BITNUMINTL(state, 4, 12) | BITNUMINTL(state, 17, 13) |
            BITNUMINTL(state, 30, 14) | BITNUMINTL(state, 9, 15) |
            BITNUMINTL(state, 1, 16) | BITNUMINTL(state, 7, 17) |
            BITNUMINTL(state, 23, 18) | BITNUMINTL(state, 13, 19) |
            BITNUMINTL(state, 31, 20) | BITNUMINTL(state, 26, 21) |
            BITNUMINTL(state, 2, 22) | BITNUMINTL(state, 8, 23) |
            BITNUMINTL(state, 18, 24) | BITNUMINTL(state, 12, 25) |
            BITNUMINTL(state, 29, 26) | BITNUMINTL(state, 5, 27) |
            BITNUMINTL(state, 21, 28) | BITNUMINTL(state, 10, 29) |
            BITNUMINTL(state, 3, 30) | BITNUMINTL(state, 24, 31);

    return state;
}

// Expose key schedule setup with C linkage so the C testbench can link to it.
extern "C" void des_key_setup(const unsigned char key[8], des_key_t schedule, DES_MODE mode) {
    unsigned int i, j, to_gen, C, D;
    const unsigned int key_rnd_shift[16] = {1, 1, 2, 2, 2, 2, 2, 2, 1, 2, 2, 2, 2, 2, 2, 1};
#pragma HLS array_partition variable=key_rnd_shift cyclic factor=8 dim=1
    const unsigned int key_perm_c[28] = {
        56, 48, 40, 32, 24, 16, 8,  0,  57, 49, 41, 33, 25, 17, 9,  1,
        58, 50, 42, 34, 26, 18, 10, 2,  59, 51, 43, 35
    };
#pragma HLS array_partition variable=key_perm_c cyclic factor=8 dim=1
    const unsigned int key_perm_d[28] = {
        62, 54, 46, 38, 30, 22, 14, 6,  61, 53, 45, 37, 29, 21, 13, 5,
        60, 52, 44, 36, 28, 20, 12, 4,  27, 19, 11, 3
    };
#pragma HLS array_partition variable=key_perm_d cyclic factor=2 dim=1
    const unsigned int key_compression[48] = {
        13, 16, 10, 23, 0,  4,  2,  27, 14, 5,  20, 9,  22, 18, 11, 3,
        25, 7,  15, 6,  26, 19, 12, 1,  40, 51, 30, 36, 46, 54, 29, 39,
        50, 44, 32, 47, 43, 48, 38, 55, 33, 52, 45, 41, 49, 35, 28, 31
    };
#pragma HLS array_partition variable=key_compression complete dim=1

    // Initialize C and D
    C = 0;
    D = 0;
    for (i = 0, j = 31; i < 28; ++i, --j) {
#pragma HLS unroll factor=8
        C |= BITNUM(key, key_perm_c[i], j);
    }
    for (i = 0, j = 31; i < 28; ++i, --j) {
#pragma HLS pipeline
        D |= BITNUM(key, key_perm_d[i], j);
    }

    for (i = 0; i < 16; ++i) {
#pragma HLS unroll factor=4
        C = ((C << key_rnd_shift[i]) | (C >> (28 - key_rnd_shift[i]))) & 0xfffffff0u;
        D = ((D << key_rnd_shift[i]) | (D >> (28 - key_rnd_shift[i]))) & 0xfffffff0u;

        if (mode == DES_DECRYPT)
            to_gen = 15 - i;
        else
            to_gen = i;

        for (j = 0; j < 6; ++j) {
#pragma HLS unroll
            schedule[to_gen][j] = 0;
        }
        for (j = 0; j < 24; ++j) {
#pragma HLS pipeline
            schedule[to_gen][j / 8] |= BITNUMINTR(C, key_compression[j], 7 - (j % 8));
        }
        for (; j < 48; ++j) {
#pragma HLS pipeline
            schedule[to_gen][j / 8] |= BITNUMINTR(D, key_compression[j] - 28, 7 - (j % 8));
        }
    }
}

// Top-level DES function for HLS with C linkage
extern "C" void des(des_block_t *in, des_block_t *out, des_key_t *key) {
#pragma HLS INTERFACE m_axi port=in offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=out offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=key offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=in bundle=control
#pragma HLS INTERFACE s_axilite port=out bundle=control
#pragma HLS INTERFACE s_axilite port=key bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    unsigned int idx, t;
    des_state_t state;
    IP(state, *in);

    for (idx = 0; idx < 15; ++idx) {
#pragma HLS pipeline II=1
        t = state[1];
        state[1] = f(state[1], (*key)[idx]) ^ state[0];
        state[0] = t;
    }

    state[0] = f(state[1], (*key)[15]) ^ state[0];

    InvIP(state, *out);
}

