// tb_hls_cosim.cpp
// HLS C-simulation testbench for DES (drives the HLS DUT).
// Produces CSV output matching the C reference testbench.

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>

// Keep typedefs and enums identical to HLS code
#define DES_BLOCK_SIZE 8

typedef unsigned char des_key_t[16][6];
typedef unsigned char des_subkey_t[6];
typedef unsigned char des_block_t[8];
typedef unsigned int des_state_t[2];

typedef enum { DES_ENCRYPT, DES_DECRYPT } DES_MODE;

// Declare top-level HLS functions with the exact same signatures as in hls.cpp
extern "C" void des_key_setup(const unsigned char key[8], des_key_t schedule, DES_MODE mode);
extern "C" void des(des_block_t *in, des_block_t *out, des_key_t *key);

int main(void) {
    // Testbench variables (names used in CSV must match these)
    unsigned char user_key[8];
    des_key_t schedule;
    des_block_t plain;
    des_block_t cipher;
    des_block_t decipher;

    // Deterministic test vectors (24 cycles) - same values as the C testbench
    const uint64_t key_vals[24] = {
        0x0000000000000000ULL, 0xFFFFFFFFFFFFFFFFULL, 0x0101010101010101ULL,
        0xFEFEFEFEFEFEFEFEULL, 0x133457799BBCDFF1ULL, 0x0000000000000001ULL,
        0x8000000000000000ULL, 0x0123456789ABCDEFULL, 0x89ABCDEF01234567ULL,
        0x13579BDF2468ACE0ULL, 0x0F0F0F0F0F0F0F0FULL, 0xF0F0F0F0F0F0F0F0ULL,
        0x1234567890ABCDEFULL, 0xAAAAAAAAAAAAAAAAULL, 0x5555555555555555ULL,
        0xCAFEBABEDEADBEEFULL, 0xDEADBEEFCAFEBABEULL, 0x0011223344556677ULL,
        0x7766554433221100ULL, 0x7F7F7F7F7F7F7F7FULL, 0x8080808080808080ULL,
        0xABCDEF0123456789ULL, 0xFEDCBA9876543210ULL, 0x1111111111111111ULL
    };
    const uint64_t plain_vals[24] = {
        0x0123456789ABCDEFULL, 0x0000000000000000ULL, 0xFFFFFFFFFFFFFFFFULL,
        0x0123456789ABCDEFULL, 0x1111111111111111ULL, 0x2222222222222222ULL,
        0x3333333333333333ULL, 0x4444444444444444ULL, 0x5555555555555555ULL,
        0x6666666666666666ULL, 0x7777777777777777ULL, 0x8888888888888888ULL,
        0x9999999999999999ULL, 0xAAAAAAAAAAAAAAAAULL, 0xBBBBBBBBBBBBBBBBULL,
        0xCCCCCCCCCCCCCCCCULL, 0xDDDDDDDDDDDDDDDDULL, 0xEEEEEEEEEEEEEEEEULL,
        0xFFFFFFFFFFFFFFFFULL, 0x0001020304050607ULL, 0x1020304050607080ULL,
        0x89ABCDEF01234567ULL, 0xFEDCBA9876543210ULL, 0x0011223344556677ULL
    };

    // Open CSV file (HLS/RTL outputs) - we want the same CSV format and contents
    FILE *fp = fopen("hls_output.csv", "w");
    if (!fp) return 1;

    // CSV header: cycle, then inputs (user_key, plain), then outputs (cipher, decipher)
    fprintf(fp, "cycle,user_key,plain,cipher,decipher\n");
    // Roles line
    fprintf(fp, "meta,in,in,out,out\n");

    const int cycles = 24;
    for (int cycle = 0; cycle < cycles; ++cycle) {
        // Load user_key and plain with big-endian byte order (index 0 is MSB)
        uint64_t kv = key_vals[cycle];
        uint64_t pv = plain_vals[cycle];
        for (int i = 0; i < 8; ++i) {
            user_key[i] = (unsigned char)((kv >> (56 - 8 * i)) & 0xFFULL);
            plain[i] = (unsigned char)((pv >> (56 - 8 * i)) & 0xFFULL);
        }

        // Generate schedule and encrypt using HLS DUT
        des_key_setup(user_key, schedule, DES_ENCRYPT);
        des(&plain, &cipher, &schedule);

        // Generate decryption schedule and decrypt using HLS DUT
        des_key_setup(user_key, schedule, DES_DECRYPT);
        des(&cipher, &decipher, &schedule);

        // Convert inputs to decimal (uint64) for CSV
        uint64_t user_key_dec = 0;
        uint64_t plain_dec = 0;
        for (int i = 0; i < 8; ++i) {
            user_key_dec = (user_key_dec << 8) | (uint64_t)user_key[i];
            plain_dec = (plain_dec << 8) | (uint64_t)plain[i];
        }

        // Convert outputs to uppercase hex strings without 0x prefix
        char cipher_hex[8 * 2 + 1];
        char decipher_hex[8 * 2 + 1];
        for (int i = 0; i < 8; ++i) {
            sprintf(&cipher_hex[i * 2], "%02X", cipher[i]);
            sprintf(&decipher_hex[i * 2], "%02X", decipher[i]);
        }
        cipher_hex[16] = '\0';
        decipher_hex[16] = '\0';

        // Write CSV row: cycle,user_key(decimal),plain(decimal),cipher(hex),decipher(hex)
        fprintf(fp, "%d,%llu,%llu,%s,%s\n",
                     cycle,
                     (unsigned long long)user_key_dec,
                     (unsigned long long)plain_dec,
                     cipher_hex,
                     decipher_hex);
    }

    fclose(fp);

    return 0;
}

