// Minimal hls::stream replacement for testing
namespace hls {
template <typename T>
class stream {
  std::deque<T> dq;

 public:
  stream() = default;
  void write(const T &v) { dq.push_back(v); }
  // provide operator<< and operator>> similar to HLS
  stream<T> &operator<<(const T &v) {
    write(v);
    return *this;
  }
  stream<T> &operator>>(T &out) {
    if (dq.empty()) {
      // If empty, push default
      out = T();
    } else {
      out = dq.front();
      dq.pop_front();
    }
    return *this;
  }
  bool empty() const { return dq.empty(); }
  void clear() { dq.clear(); }
};
}  // namespace hls

// DUT parameterization (matching typical HLS usage)
using FM_TYPE = int32_t;
using WT_TYPE = int32_t;
constexpr int DIM_IN = 5;
constexpr int DIM_OUT = 3;
constexpr int PARALLEL = 2;
constexpr bool RELU = true;

// The Device Under Test (ported from provided code)
void linear_input_stationary(
    hls::stream<std::array<FM_TYPE, PARALLEL>> &input,
    WT_TYPE weight[DIM_OUT][DIM_IN],
    WT_TYPE bias[DIM_OUT],
    FM_TYPE output[DIM_OUT]) {

    for (int dim_out = 0; dim_out < DIM_OUT; dim_out++) {
        output[dim_out] = bias[dim_out];
    }

    for (int dim_in_base = 0; dim_in_base < DIM_IN; dim_in_base += PARALLEL) {
        std::array<FM_TYPE, PARALLEL> in_slice;
        input >> in_slice;
        for (int dim_out = 0; dim_out < DIM_OUT; dim_out++) {
            FM_TYPE addend = 0;
            for (int dim_in_offset = 0; dim_in_offset < PARALLEL;
                 dim_in_offset++) {
                int dim_in = dim_in_base + dim_in_offset;
                FM_TYPE in_el = in_slice[dim_in_offset];
                if (dim_in < DIM_IN) {
                    addend += in_el * weight[dim_out][dim_in];
                }
            }
            output[dim_out] += addend;
        }
    }

    for (int dim_out = 0; dim_out < DIM_OUT; dim_out++) {
        if (RELU && output[dim_out] < 0)
            output[dim_out] = 0;
    }
}

int main() {
  // Configuration for testbench
  const int NUM_CYCLES = 24;  // total cycles (CSV lines will be NUM_CYCLES + 2)
  const int num_slices = (DIM_IN + PARALLEL - 1) / PARALLEL;

  // Prepare CSV file
  std::ofstream ofs("c_output.csv");
  if (!ofs) {
    std::cerr << "Failed to open c_output.csv for writing\n";
    return 1;
  }

  // Build header (cycle, inputs..., outputs...)
  // Inputs: weight_0_0 ... weight_DIM_OUT_DIM_IN-1, bias_0...bias_DIM_OUT-1, input_<slice>_<offset>
  // Outputs: output_0 ... output_DIM_OUT-1
  ofs << "cycle";
  // weight columns
  for (int o = 0; o < DIM_OUT; ++o) {
    for (int i = 0; i < DIM_IN; ++i) {
      ofs << ",weight_" << o << "_" << i;
    }
  }
  // bias columns
  for (int o = 0; o < DIM_OUT; ++o) {
    ofs << ",bias_" << o;
  }
  // input stream slice columns (flattened)
  for (int s = 0; s < num_slices; ++s) {
    for (int p = 0; p < PARALLEL; ++p) {
      ofs << ",input_" << s << "_" << p;
    }
  }
  // outputs
  for (int o = 0; o < DIM_OUT; ++o) {
    ofs << ",output_" << o;
  }
  ofs << "\n";

  // Second row: roles (meta/in/out)
  ofs << "meta";
  for (int o = 0; o < DIM_OUT; ++o) {
    for (int i = 0; i < DIM_IN; ++i) {
      ofs << ",in";
    }
  }
  for (int o = 0; o < DIM_OUT; ++o) {
    ofs << ",in";
  }
  for (int s = 0; s < num_slices; ++s) {
    for (int p = 0; p < PARALLEL; ++p) {
      ofs << ",in";
    }
  }
  for (int o = 0; o < DIM_OUT; ++o) {
    ofs << ",out";
  }
  ofs << "\n";

  // Test vectors: deterministic, varied across cycles
  for (int cycle = 0; cycle < NUM_CYCLES; ++cycle) {
