    WT_TYPE weight[DIM_OUT][DIM_IN];
    WT_TYPE bias[DIM_OUT];
    hls::stream<std::array<FM_TYPE, PARALLEL>> in_stream;

    // Deterministic pattern for weights and bias varying with cycle
    // weight[o][i] = (o+1)*(i+2) + cycle%5
    for (int o = 0; o < DIM_OUT; ++o) {
      for (int i = 0; i < DIM_IN; ++i) {
        weight[o][i] = static_cast<WT_TYPE>((o + 1) * (i + 2) + (cycle % 5));
      }
    }
    for (int o = 0; o < DIM_OUT; ++o) {
      // bias cycles through negative and positive values
      bias[o] = static_cast<WT_TYPE>(o - (cycle % 4));
    }

    // Prepare input stream slices deterministically:
    // in_val = cycle*10 + slice_index*3 + offset - to exercise negative and positive
    for (int s = 0; s < num_slices; ++s) {
      std::array<FM_TYPE, PARALLEL> slice;
      for (int p = 0; p < PARALLEL; ++p) {
        slice[p] = static_cast<FM_TYPE>(cycle * 10 + s * 3 + p - (s % 2));
      }
      in_stream << slice;
    }

    // Call DUT
    FM_TYPE output[DIM_OUT];
    linear_input_stationary(in_stream, weight, bias, output);

    // Emit CSV row
    ofs << cycle;
    // weights in decimal
    for (int o = 0; o < DIM_OUT; ++o) {
      for (int i = 0; i < DIM_IN; ++i) {
        ofs << "," << static_cast<long long>(weight[o][i]);
      }
    }
    // biases
    for (int o = 0; o < DIM_OUT; ++o) {
      ofs << "," << static_cast<long long>(bias[o]);
    }
    // input slices (same order as pushed)
    for (int s = 0; s < num_slices; ++s) {
      for (int p = 0; p < PARALLEL; ++p) {
        // recompute same value to log (deterministic)
        FM_TYPE v = static_cast<FM_TYPE>(cycle * 10 + s * 3 + p - (s % 2));
        ofs << "," << static_cast<long long>(v);
      }
    }
    // outputs in hex uppercase, no 0x, no fixed width
    for (int o = 0; o < DIM_OUT; ++o) {
      uint32_t ux = static_cast<uint32_t>(static_cast<int32_t>(output[o]));
      std::ostringstream ss;
      ss << std::hex << std::uppercase << ux;
      ofs << "," << ss.str();
    }
    ofs << "\n";
  }

  ofs.close();
  return 0;
}

