// hls.cpp
// HLS top function for a small linear layer (input-stationary).
// Uses C-style headers/types to be compatible with Vivado HLS 2018.3 (C++98).
// The interface matches the testbench's expectation: input is a flat array of DIM_IN elements.

#include <stdint.h>

#define DIM_IN 5
#define DIM_OUT 3
#define PARALLEL 2
#define RELU 1

typedef int32_t FM_TYPE;
typedef int32_t WT_TYPE;

// Top-level function must use C linkage for HLS cosimulation/synthesis.
extern "C" {

void linear_input_stationary(
    const FM_TYPE input[DIM_IN],
    const WT_TYPE weight[DIM_OUT][DIM_IN],
    const WT_TYPE bias[DIM_OUT],
    FM_TYPE output[DIM_OUT]) {
#pragma HLS INTERFACE m_axi port=input offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=weight offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=bias offset=slave bundle=gmem2
#pragma HLS INTERFACE m_axi port=output offset=slave bundle=gmem3
#pragma HLS INTERFACE s_axilite port=input bundle=control
#pragma HLS INTERFACE s_axilite port=weight bundle=control
#pragma HLS INTERFACE s_axilite port=bias bundle=control
#pragma HLS INTERFACE s_axilite port=output bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local output buffer fully partitioned for parallel update
    FM_TYPE output_local[DIM_OUT];
#pragma HLS ARRAY_PARTITION variable=output_local complete dim=1

    // Initialize output_local with bias
    for (int dim_out = 0; dim_out < DIM_OUT; ++dim_out) {
#pragma HLS UNROLL
        output_local[dim_out] = bias[dim_out];
    }

    // Process input in chunks of PARALLEL.
    // For indices past DIM_IN the load uses a guard and substitutes 0,
    // matching the behavior of the original stream-based DUT (which ignores out-of-range elements).
    for (int dim_in_base = 0; dim_in_base < DIM_IN; dim_in_base += PARALLEL) {
#pragma HLS PIPELINE
        FM_TYPE in_slice[PARALLEL];
#pragma HLS ARRAY_PARTITION variable=in_slice complete dim=1

        // Load input slice (guard out-of-range)
        for (int i = 0; i < PARALLEL; ++i) {
#pragma HLS UNROLL
            int idx = dim_in_base + i;
            if (idx < DIM_IN) {
                in_slice[i] = input[idx];
            } else {
                in_slice[i] = 0;
            }
        }

        // Compute partial sums and accumulate into output_local
        for (int dim_out = 0; dim_out < DIM_OUT; ++dim_out) {
#pragma HLS UNROLL
            FM_TYPE addend = 0;
            for (int dim_in_offset = 0; dim_in_offset < PARALLEL; ++dim_in_offset) {
#pragma HLS UNROLL
                int dim_in = dim_in_base + dim_in_offset;
                if (dim_in < DIM_IN) {
                    addend += in_slice[dim_in_offset] * weight[dim_out][dim_in];
                }
            }
            output_local[dim_out] += addend;
        }
    }

    // Apply ReLU if enabled
    for (int dim_out = 0; dim_out < DIM_OUT; ++dim_out) {
#pragma HLS UNROLL
        if (RELU && output_local[dim_out] < 0) {
            output_local[dim_out] = 0;
        }
    }

    // Write back outputs
    for (int dim_out = 0; dim_out < DIM_OUT; ++dim_out) {
#pragma HLS UNROLL
        output[dim_out] = output_local[dim_out];
    }
}

} // extern "C"

