    const WT_TYPE bias[DIM_OUT],
    FM_TYPE output[DIM_OUT]);

// Helper: convert 32-bit unsigned value to uppercase hex string (no 0x, no leading zeros except single "0")
static std::string to_hex_upper(uint32_t value) {
  if (value == 0) return std::string("0");
  char buf[9]; // up to 8 hex digits + null
  buf[8] = '\0';
  int pos = 8;
  while (value != 0 && pos > 0) {
    uint32_t nibble = value & 0xF;
    value >>= 4;
    --pos;
    if (nibble < 10) buf[pos] = char('0' + nibble);
    else buf[pos] = char('A' + (nibble - 10));
  }
  int len = 8 - pos;
  return std::string(&buf[pos], len);
}

int main() {
  // Configuration for testbench
  const int NUM_CYCLES = 24;  // total cycles (CSV lines will be NUM_CYCLES + 2)
