// hls.cpp
// HLS implementation of the DUT used by the C reference testbench.
// This file preserves the float-based signature and the arithmetic
// performed by the C testbench so that CSV outputs match.
// Interface pragmas are retained for Vivado HLS compatibility.

#include <math.h>
#include <string.h>

extern "C" void top(
    float DRAM_x[128],
    float DRAM_A[128][64],
    float DRAM_B[64][128],
    float DRAM_y[128],
    float DRAM_bias[1],
    float DRAM_result[1])
{
#pragma HLS INTERFACE m_axi port=DRAM_x offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_A offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_B offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_y offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_bias offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_result offset=slave bundle=mem2
#pragma HLS INTERFACE s_axilite port=DRAM_x bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_A bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_B bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_y bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_bias bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_result bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local temporaries matching the reference C implementation.
    // Make these static to avoid excessive stack usage during C/RTL cosimulation.
    static float Ax[128];
    static float By[64];

    // Initialize Ax to zeros
    for (int i = 0; i < 128; ++i) {
#pragma HLS PIPELINE II=1
        Ax[i] = 0.0f;
    }

    // Compute Ax[i] = sum_{j=0..63} A[i][j] * x[j]
    for (int i = 0; i < 128; ++i) {
        // Keep inner loop pipelinable in HLS
        for (int j = 0; j < 64; ++j) {
#pragma HLS PIPELINE II=1
            Ax[i] += DRAM_A[i][j] * DRAM_x[j];
        }
    }

    // Initialize By to zeros
    for (int i = 0; i < 64; ++i) {
#pragma HLS PIPELINE II=1
        By[i] = 0.0f;
    }

    // Compute By[i] = sum_{j=0..127} B[i][j] * y[j]
    for (int i = 0; i < 64; ++i) {
        for (int j = 0; j < 128; ++j) {
#pragma HLS PIPELINE II=1
            By[i] += DRAM_B[i][j] * DRAM_y[j];
        }
    }

    // Compute scalar sum = bias + sum(Ax) + sum(By)
    float sum = DRAM_bias[0];
    for (int i = 0; i < 128; ++i) {
#pragma HLS PIPELINE II=1
        sum += Ax[i];
    }
    for (int i = 0; i < 64; ++i) {
#pragma HLS PIPELINE II=1
        sum += By[i];
    }

    // Apply sigmoid: 1 / (1 + exp(-sum))
    // Use the single-precision expf to match float-based signature
    DRAM_result[0] = 1.0f / (1.0f + expf(-sum));
}

