void convolution(
    const char           coeffs[256],
    float                factor,
    short                bias,
    unsigned short       width,
    unsigned short       height,
    unsigned short       stride,
    const unsigned char  src[MAX_IMAGE_WIDTH * MAX_IMAGE_HEIGHT],
    unsigned char        dst[MAX_IMAGE_WIDTH * MAX_IMAGE_HEIGHT])
{
    int half_v = FILTER_V_SIZE / 2;
    int half_h = FILTER_H_SIZE / 2;
    for (int y = 0; y < height; y++) {
        for (int x = 0; x < width; x++) {
            int sum = 0;
            for (int ky = -half_v; ky <= half_v; ky++) {
                for (int kx = -half_h; kx <= half_h; kx++) {
                    int src_y = y + ky;
                    int src_x = x + kx;
                    if (src_y < 0) src_y = -src_y;
                    if (src_x < 0) src_x = -src_x;
                    if (src_y >= height) src_y = 2 * height - src_y - 1;
                    if (src_x >= width) src_x = 2 * width - src_x - 1;
                    int coef_index = (ky + half_v) * FILTER_H_SIZE + (kx + half_h);
                    sum += src[src_y * width + src_x] * coeffs[coef_index];
                }
            }
            int result = (int)(factor * sum) + bias;
            if (result < 0) result = 0;
            else if (result > 255) result = 255;
            dst[y * width + x] = (unsigned char)result;
        }
    }
}

