    std::fprintf(f, "cycle");
    for (int i = 0; i < used_coeffs; ++i) std::fprintf(f, ",coeff_%d", i);
    std::fprintf(f, ",factor,bias,width,height,stride");
    for (int i = 0; i < img_size; ++i) std::fprintf(f, ",src_%d", i);
    for (int i = 0; i < img_size; ++i) std::fprintf(f, ",dst_%d", i);
