    for (int i = 0; i < img_size; ++i) std::fprintf(f, ",out");
    std::fprintf(f, "\n");

    // Prepare working arrays
    char coeffs[256];
    unsigned char src[MAX_IMAGE_WIDTH * MAX_IMAGE_HEIGHT];
    unsigned char dst[MAX_IMAGE_WIDTH * MAX_IMAGE_HEIGHT];

    // Define a set of base kernels to vary tests
    const int kernels_count = 4;
    const int base_kernels[kernels_count][9] = {
        {0,1,0, 1,1,1, 0,1,0},          // blur-ish
        {1,0,-1, 1,0,-1, 1,0,-1},       // edge-ish
        {1,2,1, 2,4,2, 1,2,1},          // strong blur / weighted
        {-1,-1,-1, -1,8,-1, -1,-1,-1}   // laplacian
    };

