    const int cycles = 24;
    for (int cyc = 0; cyc < cycles; ++cyc) {
        // Fill coeffs: zero out then set first 9 based on pattern
        std::memset(coeffs, 0, sizeof(coeffs));
        int ksel = cyc % kernels_count;
        int scale = 1 + (cyc % 3); // 1..3 scaling to vary magnitude
        for (int i = 0; i < used_coeffs; ++i) {
            int v = base_kernels[ksel][i] * scale;
            // clamp to signed char range
            if (v > 127) v = 127;
            if (v < -128) v = -128;
            coeffs[i] = (char)v;
        }

        // Choose integer factor (print as decimal integer)
