        } else if (cyc % 6 == 1) {
            // all zeros
            for (int i = 0; i < img_size; ++i) src[i] = 0;
        } else {
            // patterned values to exercise boundaries and varied sums
            int base = (cyc * 7) & 0xFF;
            for (int y = 0; y < (int)height; ++y) {
                for (int x = 0; x < (int)width; ++x) {
                    int idx = y * width + x;
