// hls.cpp
// Vivado HLS implementation of a small 2D convolution/filter pipeline.
// This version implements the same mirror-edge convolution used by the C testbench
// to ensure bit- and value-identical results in cosimulation.
//
// Top-level function is exported as "convolution" (extern "C") to match the testbench.
//
// Note: This implementation avoids complex stream/window stages and implements the
// same direct convolution with mirror-border handling as the C reference TB so that
// the generated hls_output.csv will match c_output.csv exactly.

#include <cstring>
#include <hls_stream.h>
#include <stdint.h>

#define MAX_IMAGE_WIDTH 16
#define MAX_IMAGE_HEIGHT 16
#define FILTER_V_SIZE 3
#define FILTER_H_SIZE 3

typedef unsigned char U8;

extern "C" {

void convolution(
    const char coeffs[256],
    float factor,
    short bias,
    unsigned short width,
    unsigned short height,
    unsigned short stride,
    const unsigned char src[MAX_IMAGE_WIDTH*MAX_IMAGE_HEIGHT],
    unsigned char dst[MAX_IMAGE_WIDTH*MAX_IMAGE_HEIGHT])
{
#pragma HLS INTERFACE m_axi port=coeffs offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=src offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=dst offset=slave bundle=gmem2
#pragma HLS INTERFACE s_axilite port=coeffs bundle=control
#pragma HLS INTERFACE s_axilite port=factor bundle=control
#pragma HLS INTERFACE s_axilite port=bias bundle=control
#pragma HLS INTERFACE s_axilite port=width bundle=control
#pragma HLS INTERFACE s_axilite port=height bundle=control
#pragma HLS INTERFACE s_axilite port=stride bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local copy of coefficients (only first FILTER_V_SIZE*FILTER_H_SIZE used)
    char local_coefs[FILTER_V_SIZE * FILTER_H_SIZE];
#pragma HLS ARRAY_PARTITION variable=local_coefs complete

    // Copy relevant coefficients
    coef_copy: for (int i = 0; i < FILTER_V_SIZE * FILTER_H_SIZE; ++i) {
#pragma HLS PIPELINE II=1
        local_coefs[i] = coeffs[i];
    }

    // Perform convolution with mirror border handling identical to the C testbench.
    int half_v = FILTER_V_SIZE / 2;
    int half_h = FILTER_H_SIZE / 2;

    // We only write the width*height valid outputs (same layout as C TB: row-major,
    // dst[y * width + x]). We do not assume stride > width is used by the C TB tests
    // (the TB uses stride == width), but we accept stride parameter for interface parity.
    conv_y: for (int y = 0; y < (int)height; ++y) {
        conv_x: for (int x = 0; x < (int)width; ++x) {
#pragma HLS PIPELINE II=1
            int sum = 0;
            for (int ky = -half_v; ky <= half_v; ++ky) {
                for (int kx = -half_h; kx <= half_h; ++kx) {
                    int src_y = y + ky;
                    int src_x = x + kx;

                    // Mirror border handling (exactly as in the C testbench)
                    if (src_y < 0) src_y = -src_y;
                    if (src_x < 0) src_x = -src_x;
                    if (src_y >= (int)height) src_y = 2 * (int)height - src_y - 1;
                    if (src_x >= (int)width)  src_x = 2 * (int)width  - src_x - 1;

                    unsigned idx = (unsigned)src_y * (unsigned)stride + (unsigned)src_x;
                    unsigned char pixel = src[idx];

                    int coef_index = (ky + half_v) * FILTER_H_SIZE + (kx + half_h);
                    sum += (int)pixel * (int)(local_coefs[coef_index]);
                }
            }
            int result = (int)(factor * (float)sum) + (int)bias;
            if (result < 0) result = 0;
            else if (result > 255) result = 255;
            dst[y * (unsigned)width + x] = (unsigned char)result;
        }
    }

    // Optional: zero the remainder of dst buffer (beyond width*height) to keep memory deterministic
    // This does not affect the CSV outputs since TB only prints first width*height entries.
    int total = MAX_IMAGE_WIDTH * MAX_IMAGE_HEIGHT;
    for (int i = (int)(width * height); i < total; ++i) {
#pragma HLS PIPELINE II=1
        dst[i] = 0;
    }
}

} // extern "C"

