// Helper: convert double to uint64_t bit pattern
static uint64_t double_to_bits(double v) {
    uint64_t bits = 0;
    static_assert(sizeof(double) == sizeof(uint64_t), "Unexpected double size");
    std::memcpy(&bits, &v, sizeof(bits));
    return bits;
}

int main() {
    const int CYCLES = 24; // number of test cycles (rows)
    // We will report these output indices for A and B
    const int idxs[] = {0, 1, 2, 10, 50, 119};
    const int NIDX = sizeof(idxs)/sizeof(idxs[0]);

    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // CSV Header: cycle, inputs (tsteps,n), then sampled outputs A[...] and B[...]
    std::fprintf(f, "cycle,tsteps,n");
    for (int i = 0; i < NIDX; ++i) {
        std::fprintf(f, ",A[%d]", idxs[i]);
    }
    for (int i = 0; i < NIDX; ++i) {
        std::fprintf(f, ",B[%d]", idxs[i]);
    }
    std::fprintf(f, "\n");

    // Role row: meta for cycle, in for inputs, out for outputs
    std::fprintf(f, "meta,in,in");
    for (int i = 0; i < NIDX; ++i) std::fprintf(f, ",out");
    for (int i = 0; i < NIDX; ++i) std::fprintf(f, ",out");
    std::fprintf(f, "\n");

    // Predefined tsteps and n test vectors (deterministic)
    int tsteps_vec[CYCLES];
    int n_vec[CYCLES];
    for (int c = 0; c < CYCLES; ++c) {
        // Create a variety of scalar inputs (deterministic)
        // tsteps vary but DUT ignores it; n varied but DUT uses fixed internals.
        tsteps_vec[c] = 40 + (c % 5) - (c % 3); // values around 40
        n_vec[c] = 120 - (c % 7) * 2; // values <= 120
        if (n_vec[c] < 3) n_vec[c] = 3;
    }

    // Per-cycle simulation: initialize arrays deterministically, call DUT, sample outputs
    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        int tsteps = tsteps_vec[cycle];
        int n = n_vec[cycle];

        double A[120];
        double B[120];

        // Initialize arrays with one of several deterministic patterns based on cycle
        int pattern = cycle % 4;
        if (pattern == 0) {
            // ramp and zeros
            for (int i = 0; i < 120; ++i) {
                A[i] = (double)i;
                B[i] = 0.0;
            }
        } else if (pattern == 1) {
            // descending and small repeating values
            for (int i = 0; i < 120; ++i) {
                A[i] = (double)(1000 - i);
                B[i] = (double)(i % 3);
            }
        } else if (pattern == 2) {
            // small fractional pattern plus cycle offset
            for (int i = 0; i < 120; ++i) {
                A[i] = (double)( (i % 7) ) * 0.5 + (double)cycle;
                B[i] = (double)( (i % 5) ) * 1.25;
            }
        } else { // pattern == 3
            // linear scaled values and signed small values
            for (int i = 0; i < 120; ++i) {
                A[i] = (double)(i * 2 + cycle) / 3.0;
                B[i] = (double)(((i + cycle) % 11) - 5);
            }
        }

        // Call DUT once per cycle
        jacobi_1d(tsteps, n, A, B);

        // Write CSV row: cycle,tsteps,n (inputs in decimal), then outputs (A[idx],B[idx]) in HEX (uppercase, no 0x)
        std::fprintf(f, "%d,%d,%d", cycle, tsteps, n);
        // A outputs
        for (int k = 0; k < NIDX; ++k) {
            int idx = idxs[k];
            uint64_t bits = double_to_bits(A[idx]);
            // Print as uppercase hex without 0x and without fixed width
            std::fprintf(f, ",%llX", (unsigned long long)bits);
        }
        // B outputs
