            uint64_t bits = double_to_bits(B[idx]);
            std::fprintf(f, ",%llX", (unsigned long long)bits);
        }
        std::fprintf(f, "\n");
    }

    std::fflush(f);
    std::fclose(f);
    return 0;
}

