// Top-level HLS function for 1D Jacobi stencil
// The top-level function is declared with C linkage as required by the testbench.

#define N 120
#define TSTEPS 40

// Declare the top-level function with C linkage to prevent name mangling.
extern "C" void jacobi_1d(int tsteps, int n, double A[N], double B[N]) {
#pragma HLS INTERFACE m_axi port=A offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=B offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=tsteps bundle=control
#pragma HLS INTERFACE s_axilite port=n bundle=control
#pragma HLS INTERFACE s_axilite port=A bundle=control
#pragma HLS INTERFACE s_axilite port=B bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int t, i;

    // Use fixed iteration counts for synthesis
    for (t = 0; t < TSTEPS; t++) {
    #pragma HLS PIPELINE II=1
        for (i = 1; i < N - 1; i++) {
            B[i] = 0.33333 * (A[i - 1] + A[i] + A[i + 1]);
        }

        for (i = 1; i < N - 1; i++) {
            A[i] = 0.33333 * (B[i - 1] + B[i] + B[i + 1]);
        }
    }
}

