// hls.cpp
// Top-level block matrix multiply for Vivado HLS.
// Adjusted to match the testbench sizes (SIZE=4, BLOCK_SIZE=2).
// Keep extern "C" linkage for the top function.

#include <ap_int.h>

typedef int DTYPE;
#define SIZE 4
#define BLOCK_SIZE 2

typedef struct {
    DTYPE a[BLOCK_SIZE];
} blockvec;

typedef struct {
    DTYPE out[BLOCK_SIZE][BLOCK_SIZE];
} blockmat;

extern "C" void block_mm(
    const blockvec Arows[SIZE],
    const blockvec Bcols[SIZE],
    blockmat *ABpartial,
    int it
) {
#pragma HLS INTERFACE m_axi port=Arows offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=Bcols offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=ABpartial offset=slave bundle=gmem2
#pragma HLS INTERFACE s_axilite port=Arows bundle=control
#pragma HLS INTERFACE s_axilite port=Bcols bundle=control
#pragma HLS INTERFACE s_axilite port=ABpartial bundle=control
#pragma HLS INTERFACE s_axilite port=it bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Use counter to optionally reload A (as in original example).
    int counter = it % (SIZE / BLOCK_SIZE);

    // Local buffer for A: BLOCK_SIZE x SIZE
    DTYPE A[BLOCK_SIZE][SIZE];
#pragma HLS array_partition variable=A cyclic factor=2 dim=2

    if (counter == 0) {
        // Load Arows into local A buffer.
        for (int i = 0; i < SIZE; i++) {
#pragma HLS unroll factor=4
            blockvec tempA = Arows[i];
            for (int j = 0; j < BLOCK_SIZE; j++) {
#pragma HLS pipeline
                A[j][i] = tempA.a[j];
            }
        }
    }

    // Partial AB accumulation for this block.
    DTYPE AB[BLOCK_SIZE][BLOCK_SIZE] = {0};
#pragma HLS array_partition variable=AB complete dim=2

    // Multiply-accumulate over k dimension (SIZE).
    for (int k = 0; k < SIZE; k++) {
#pragma HLS unroll factor=2
        blockvec tempB = Bcols[k];
        for (int i = 0; i < BLOCK_SIZE; i++) {
#pragma HLS unroll factor=2
            for (int j = 0; j < BLOCK_SIZE; j++) {
#pragma HLS unroll factor=2
                AB[i][j] += A[i][k] * tempB.a[j];
            }
        }
    }

    // Write back the partial block result to ABpartial.
    for (int i = 0; i < BLOCK_SIZE; i++) {
#pragma HLS pipeline II=1
        for (int j = 0; j < BLOCK_SIZE; j++) {
#pragma HLS unroll factor=2
            ABpartial->out[i][j] = AB[i][j];
        }
    }
}

