        0,       // 6
        0,       // 7
        1,       // 8
        2,       // 9
        4,       //10
        8,       //11
       16,       //12
       32,       //13
      -16,       //14
       64,       //15
      -64,       //16
      100,       //17
     -100,       //18
     1000,       //19
    -1000,       //20
    123456,      //21
   -123456,      //22
    214748,      //23
   -214748,      //24
    99999,       //25
   -99999,       //26
        3,       //27
       -3,       //28
      127,       //29
     -127,       //30
        5        //31
    };

    // DUT I/O storage (1x1x1)
    data_t input[C][H][W];
    data_t output[C][H][W];

    for (int cycle = 0; cycle < N; ++cycle) {
