// Top-level HLS design implementing a sigmoid function using float data type.
// This file is intended for Vivado HLS 2018.3.
// Note: array dimensions must match the testbench.

#include <hls_math.h>

// Define constants (must match testbench dimensions)
#define C 1
#define H 1
#define W 1

// Define data type
typedef float data_t;

extern "C" {

void sigmoid(data_t input[C][H][W], data_t output[C][H][W]) {
#pragma HLS INTERFACE m_axi port=input offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=output offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=input bundle=control
#pragma HLS INTERFACE s_axilite port=output bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    data_t FM_buffer_1[C][H][W];
    data_t FM_buffer_2[C][H][W];
    data_t FM_buffer_3[C][H][W];

    // load_feature_map
    for (int c = 0; c < C; c++) {
        for (int h = 0; h < H; h++) {
            for (int w = 0; w < W; w++) {
#pragma HLS PIPELINE II=1
                FM_buffer_1[c][h][w] = input[c][h][w];
            }
        }
    }

    // negative
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
#pragma HLS PIPELINE II=1
                FM_buffer_2[i][j][k] = -FM_buffer_1[i][j][k];
            }
        }
    }

    // compute_exp
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
#pragma HLS PIPELINE II=1
                FM_buffer_1[i][j][k] = hls::exp(FM_buffer_2[i][j][k]);
            }
        }
    }

    // set_value to 1
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
#pragma HLS PIPELINE II=1
                FM_buffer_3[i][j][k] = 1.0f;
            }
        }
    }

    // compute_add: FM_buffer_3 + FM_buffer_1 -> FM_buffer_2
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
#pragma HLS PIPELINE II=1
                FM_buffer_2[i][j][k] = FM_buffer_3[i][j][k] + FM_buffer_1[i][j][k];
            }
        }
    }

    // compute_div: FM_buffer_3 / FM_buffer_2 -> FM_buffer_1
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
#pragma HLS PIPELINE II=1
                FM_buffer_1[i][j][k] = FM_buffer_3[i][j][k] / FM_buffer_2[i][j][k];
            }
        }
    }

    // store_feature_map
    for (int c = 0; c < C; c++) {
        for (int h = 0; h < H; h++) {
            for (int w = 0; w < W; w++) {
#pragma HLS PIPELINE II=1
                output[c][h][w] = FM_buffer_1[c][h][w];
            }
        }
    }
}

}

