// tb_hls_cosim.cpp
// Testbench for HLS cosimulation.
// This testbench uses only C89/C99 compatible headers and language constructs
// (no C++11 features) to be compatible with Vivado HLS 2018.3 toolchain.
// It must match the top-level HLS function signature exactly.

#include <stdio.h>
#include <stdint.h>
#include <math.h>
#include <string.h>

/* DUT configuration and type (must match HLS design) */
typedef float data_t;
const int C = 1;
const int H = 1;
const int W = 1;
const int DATA_WIDTH = 32;
const int FRAC = 16;

/* Extern top-level declaration for HLS cosim (must match HLS top-level signature exactly) */
#ifdef __cplusplus
extern "C"
#endif
void sigmoid(data_t input[C][H][W],
             data_t output[C][H][W]);

int main()
{
    /* Prepare CSV file for HLS/RTL output */
    FILE *f = fopen("hls_output.csv", "w");
    if (!f) return 1;

    /* Header: cycle, then driven inputs, then observed outputs */
    fprintf(f, "cycle,reset,en,input,output\n");
    /* Roles row: cycle is meta; reset/en/input are driven by testbench (in); output is sampled from DUT (out) */
    fprintf(f, "meta,in,in,in,out\n");

    /* Testbench vectors (32 cycles) */
    const int N = 32;
    int test_inputs[N] = {
        0,       /* cycle 0: reset active */
        0,       /* cycle 1: reset active */
       -8,       /* 2 */
       -4,       /* 3 */
       -2,       /* 4 */
       -1,       /* 5 */
        0,       /* 6 */
        0,       /* 7 */
        1,       /* 8 */
        2,       /* 9 */
        4,       /*10 */
        8,       /*11 */
       16,       /*12 */
       32,       /*13 */
      -16,       /*14 */
       64,       /*15 */
      -64,       /*16 */
      100,       /*17 */
     -100,       /*18 */
     1000,       /*19 */
    -1000,       /*20 */
    123456,      /*21 */
   -123456,      /*22 */
    214748,      /*23 */
   -214748,      /*24 */
    99999,       /*25 */
   -99999,       /*26 */
        3,       /*27 */
       -3,       /*28 */
      127,       /*29 */
     -127,       /*30 */
        5        /*31 */
    };

    /* DUT I/O storage (1x1x1) */
    data_t input[C][H][W];
    data_t output[C][H][W];

    int cycle;
    for (cycle = 0; cycle < N; ++cycle) {
        /* reset and enable policy:
           first 2 cycles reset=1 and en=0; afterwards reset=0 and en=1 */
        int reset = (cycle < 2) ? 1 : 0;
        int en = (cycle < 2) ? 0 : 1;

        /* Drive input: during reset we still provide the vector value (per test vector) */
        int in_val = test_inputs[cycle];

        /* Assign into DUT input array (cast integer to float) */
        input[0][0][0] = (data_t) in_val;

        /* Call DUT every cycle (in HLS cosim this will invoke RTL model) */
        sigmoid(input, output);

        /* Convert float output to fixed-point Q<...,FRAC> to match Verilog DUT output encoding.
           Scale, round to nearest, clamp to [0, 2^FRAC - 1], then print as 8-digit hex uppercase (no 0x). */
        const unsigned long long scale = (1ull << FRAC);
        long long scaled_ll = llround((double)output[0][0][0] * (double)scale);
        if (scaled_ll < 0) scaled_ll = 0;
        unsigned long long max_val = ((1ull << FRAC) - 1ull); /* e.g., 65535 for FRAC=16 */
        if ((unsigned long long)scaled_ll > max_val) scaled_ll = (long long)max_val;
        uint32_t out_fixed = (uint32_t) scaled_ll;

        /* Write CSV row: cycle,reset,en,input(decimal),output(hex uppercase no 0x)
           Print fixed-point value as 8 hex digits to match Verilog formatting (leading zeros). */
        fprintf(f, "%d,%d,%d,%d,%08X\n", cycle, reset, en, in_val, out_fixed);
    }

    fflush(f);
    fclose(f);
    return 0;
}

