#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <math.h>
#include "test.h"

static inline int16_t saturate_int16(int32_t v) {
    if (v > INT16_MAX) return INT16_MAX;
    if (v < INT16_MIN) return INT16_MIN;
    return (int16_t)v;
}

void top(fix16_t DRAM_x[M],
         fix16_t DRAM_A[M][K],
         fix16_t DRAM_B[K][N],
         fix16_t DRAM_y[N],
         fix16_t DRAM_bias[1],
         fix16_t DRAM_result[1]) {
    int32_t mid1[K];
    int32_t mid2[N];

    for (int i = 0; i < K; i++) {
        int32_t acc = 0;
        for (int j = 0; j < M; j++) {
            int32_t prod = (int32_t)DRAM_A[j][i] * (int32_t)DRAM_x[j];
            acc += (prod >> FRAC_BITS);
        }
        mid1[i] = acc;
    }

    for (int k = 0; k < N; k++) {
        int32_t acc = 0;
        for (int i = 0; i < K; i++) {
            int32_t prod = (int32_t)DRAM_B[i][k] * (int32_t)mid1[i];
            acc += (prod >> FRAC_BITS);
        }
        mid2[k] = acc;
    }

    int64_t dot = 0;
    for (int k = 0; k < N; k++) {
        int64_t prod = (int64_t)mid2[k] * (int64_t)DRAM_y[k];
        dot += (prod >> FRAC_BITS);
    }

    int32_t out = (int32_t)dot;
    DRAM_result[0] = saturate_int16(out);
}

int main() {
    fix16_t x[M];
    fix16_t A[M][K];
    fix16_t B[K][N];
    fix16_t y[N];
    fix16_t bias[1];
    fix16_t result[1];

    srand((unsigned)time(NULL));
    for (int i = 0; i < M; i++) {
        float v = ((float)rand() / RAND_MAX) * 2.0f - 1.0f;
        x[i] = (fix16_t)lrintf(v * (1 << FRAC_BITS));
    }
    for (int i = 0; i < M; i++) {
        for (int j = 0; j < K; j++) {
            float v = ((float)rand() / RAND_MAX) * 2.0f - 1.0f;
            A[i][j] = (fix16_t)lrintf(v * (1 << FRAC_BITS));
        }
    }
    for (int i = 0; i < K; i++) {
        for (int j = 0; j < N; j++) {
            float v = ((float)rand() / RAND_MAX) * 2.0f - 1.0f;
            B[i][j] = (fix16_t)lrintf(v * (1 << FRAC_BITS));
        }
    }
    for (int i = 0; i < N; i++) {
        float v = ((float)rand() / RAND_MAX) * 2.0f - 1.0f;
        y[i] = (fix16_t)lrintf(v * (1 << FRAC_BITS));
    }
    bias[0] = 0;

    top(x, A, B, y, bias, result);

    float result_f = (float)result[0] / (float)(1 << FRAC_BITS);

    double ref_mid1[K];
    double ref_mid2[N];
    for (int i = 0; i < K; i++) {
        double acc = 0.0;
        for (int j = 0; j < M; j++) {
            double va = (double)A[j][i] / (1 << FRAC_BITS);
            double vx = (double)x[j] / (1 << FRAC_BITS);
            acc += va * vx;
        }
        ref_mid1[i] = acc;
    }
    for (int k = 0; k < N; k++) {
        double acc = 0.0;
        for (int i = 0; i < K; i++) {
            double vb = (double)B[i][k] / (1 << FRAC_BITS);
            acc += vb * ref_mid1[i];
        }
        ref_mid2[k] = acc;
    }
    double ref_dot = 0.0;
    for (int k = 0; k < N; k++) {
        double vy = (double)y[k] / (1 << FRAC_BITS);
        ref_dot += ref_mid2[k] * vy;
    }

    printf("Fixed-point result = %f\n", result_f);
    printf("Floating-point reference = %f\n", ref_dot);
    return 0;
}

