#include <cstdio>
#include <cstdint>
#include <cstdlib>
#include <cstring>
#include <climits>

#define M 64
#define K 128
#define N 128
#define FRAC_BITS 11

typedef int16_t fix16_t;

/* DUT implementation (from provided source) */
static inline int16_t saturate_int16(int32_t v) {
    if (v > INT16_MAX) return INT16_MAX;
    if (v < INT16_MIN) return INT16_MIN;
    return (int16_t)v;
}

void top(fix16_t DRAM_x[M],
         fix16_t DRAM_A[M][K],
         fix16_t DRAM_B[K][N],
         fix16_t DRAM_y[N],
         fix16_t DRAM_bias[1],
         fix16_t DRAM_result[1]) {
    int32_t mid1[K];
    int32_t mid2[N];

    for (int i = 0; i < K; i++) {
        int32_t acc = 0;
        for (int j = 0; j < M; j++) {
            int32_t prod = (int32_t)DRAM_A[j][i] * (int32_t)DRAM_x[j];
            acc += (prod >> FRAC_BITS);
        }
        mid1[i] = acc;
    }

    for (int k = 0; k < N; k++) {
        int32_t acc = 0;
        for (int i = 0; i < K; i++) {
            int32_t prod = (int32_t)DRAM_B[i][k] * (int32_t)mid1[i];
            acc += (prod >> FRAC_BITS);
        }
        mid2[k] = acc;
    }

    int64_t dot = 0;
    for (int k = 0; k < N; k++) {
        int64_t prod = (int64_t)mid2[k] * (int64_t)DRAM_y[k];
        dot += (prod >> FRAC_BITS);
    }

    int32_t out = (int32_t)dot;
    DRAM_result[0] = saturate_int16(out);
}

/* Testbench producing deterministic test vectors and CSV output */
/* CSV columns:
   cycle,DRAM_x[0],DRAM_x[1],DRAM_A[0][0],DRAM_B[0][0],DRAM_y[0],DRAM_bias[0],DRAM_result[0]
   Roles:
   meta,in,in,in,in,in,in,out
*/

int main() {
    const int CYCLES = 32; /* produce 32 cycles (rows) */

    fix16_t DRAM_x[M];
    fix16_t DRAM_A[M][K];
    fix16_t DRAM_B[K][N];
    fix16_t DRAM_y[N];
    fix16_t DRAM_bias[1];
    fix16_t DRAM_result[1];

    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    /* Header row */
    std::fprintf(f, "cycle,DRAM_x[0],DRAM_x[1],DRAM_A[0][0],DRAM_B[0][0],DRAM_y[0],DRAM_bias[0],DRAM_result[0]\n");
    /* Roles row */
    std::fprintf(f, "meta,in,in,in,in,in,in,out\n");

    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        /* Fill arrays deterministically based on cycle index.
           We include some special patterns for first few cycles,
           then a deterministic pseudo-pattern for the rest.
        */
        if (cycle == 0) {
            /* All zeros */
            std::memset(DRAM_x, 0, sizeof(DRAM_x));
            std::memset(DRAM_A, 0, sizeof(DRAM_A));
            std::memset(DRAM_B, 0, sizeof(DRAM_B));
            std::memset(DRAM_y, 0, sizeof(DRAM_y));
            DRAM_bias[0] = 0;
        } else if (cycle == 1) {
            /* All ones (1.0 in fixed-point) */
            fix16_t one = (fix16_t)(1 << FRAC_BITS);
            for (int j = 0; j < M; ++j) DRAM_x[j] = one;
            for (int j = 0; j < M; ++j)
                for (int i = 0; i < K; ++i) DRAM_A[j][i] = one;
            for (int i = 0; i < K; ++i)
                for (int k = 0; k < N; ++k) DRAM_B[i][k] = one;
            for (int k = 0; k < N; ++k) DRAM_y[k] = one;
            DRAM_bias[0] = 0;
        } else if (cycle == 2) {
            /* All -1 */
            fix16_t negone = (fix16_t)(-(1 << FRAC_BITS));
            for (int j = 0; j < M; ++j) DRAM_x[j] = negone;
            for (int j = 0; j < M; ++j)
                for (int i = 0; i < K; ++i) DRAM_A[j][i] = negone;
            for (int i = 0; i < K; ++i)
                for (int k = 0; k < N; ++k) DRAM_B[i][k] = negone;
            for (int k = 0; k < N; ++k) DRAM_y[k] = negone;
            DRAM_bias[0] = 0;
        } else if (cycle == 3) {
            /* Max saturation test: extreme positive */
            for (int j = 0; j < M; ++j) DRAM_x[j] = INT16_MAX;
            for (int j = 0; j < M; ++j)
                for (int i = 0; i < K; ++i) DRAM_A[j][i] = INT16_MAX;
            for (int i = 0; i < K; ++i)
                for (int k = 0; k < N; ++k) DRAM_B[i][k] = INT16_MAX;
            for (int k = 0; k < N; ++k) DRAM_y[k] = INT16_MAX;
            DRAM_bias[0] = 0;
        } else if (cycle == 4) {
            /* Max negative saturation test */
            for (int j = 0; j < M; ++j) DRAM_x[j] = INT16_MIN;
            for (int j = 0; j < M; ++j)
                for (int i = 0; i < K; ++i) DRAM_A[j][i] = INT16_MIN;
            for (int i = 0; i < K; ++i)
                for (int k = 0; k < N; ++k) DRAM_B[i][k] = INT16_MIN;
            for (int k = 0; k < N; ++k) DRAM_y[k] = INT16_MIN;
            DRAM_bias[0] = 0;
        } else if (cycle == 5) {
            /* Identity-like: A is identity on min(M,K) diagonal, B identity, x is ramp, y ones */
            std::memset(DRAM_A, 0, sizeof(DRAM_A));
            std::memset(DRAM_B, 0, sizeof(DRAM_B));
            for (int j = 0; j < M; ++j) {
                DRAM_x[j] = (fix16_t)((((j % 8) - 4) * (1 << FRAC_BITS)) / 8); /* small ramp -0.5..+0.375 */
            }
            for (int i = 0; i < K && i < M; ++i) {
                DRAM_A[i][i] = (fix16_t)(1 << FRAC_BITS);
            }
            for (int i = 0; i < K && i < N; ++i) {
                DRAM_B[i][i] = (fix16_t)(1 << FRAC_BITS);
            }
            for (int k = 0; k < N; ++k) DRAM_y[k] = (fix16_t)(1 << FRAC_BITS);
            DRAM_bias[0] = 0;
        } else if (cycle == 6) {
            /* Sparse: only first element nonzero */
            std::memset(DRAM_A, 0, sizeof(DRAM_A));
            std::memset(DRAM_B, 0, sizeof(DRAM_B));
            for (int j = 0; j < M; ++j) DRAM_x[j] = 0;
            DRAM_x[0] = (fix16_t)(1 << FRAC_BITS);
            DRAM_A[0][0] = (fix16_t)(1 << FRAC_BITS);
            DRAM_B[0][0] = (fix16_t)(1 << FRAC_BITS);
            for (int k = 0; k < N; ++k) DRAM_y[k] = 0;
            DRAM_y[0] = (fix16_t)(1 << FRAC_BITS);
            DRAM_bias[0] = 0;
        } else if (cycle == 7) {
            /* Alternating signs in x and y, small coefficients in A/B */
            for (int j = 0; j < M; ++j)
                DRAM_x[j] = (fix16_t)((((j & 1) ? 1 : -1) * (1 << FRAC_BITS)) / 4); /* ±0.25 */
            for (int j = 0; j < M; ++j)
                for (int i = 0; i < K; ++i)
                    DRAM_A[j][i] = (fix16_t)((((j + i) & 1) ? 1 : -1) * ((1 << FRAC_BITS) / 8)); /* ±0.125 */
            for (int i = 0; i < K; ++i)
                for (int k = 0; k < N; ++k)
                    DRAM_B[i][k] = (fix16_t)((((i + k) & 1) ? 1 : -1) * ((1 << FRAC_BITS) / 8));
            for (int k = 0; k < N; ++k)
                DRAM_y[k] = (fix16_t)((((k & 1) ? -1 : 1) * (1 << FRAC_BITS)) / 2); /* ±0.5 */
            DRAM_bias[0] = 0;
        } else {
            /* Deterministic pseudo-pattern depending on cycle to create variety */
            int scaleA = ((cycle & 3) + 1) * ((1 << FRAC_BITS) / 16); /* 16,32,48,64 scaled small */
            if (scaleA == 0) scaleA = 1;
            int scaleB = ((cycle & 7) + 1) * ((1 << FRAC_BITS) / 32);
            if (scaleB == 0) scaleB = 1;
            int scalex = ((cycle & 5) + 1) * ((1 << FRAC_BITS) / 16);
            if (scalex == 0) scalex = 1;
            int scaley = ((cycle & 6) + 1) * ((1 << FRAC_BITS) / 32);
            if (scaley == 0) scaley = 1;

            for (int j = 0; j < M; ++j) {
                int v = ((j * 131 + cycle * 17) % 201) - 100; /* -100..100 */
                int32_t val = v * scalex;
                if (val > INT16_MAX) val = INT16_MAX;
                if (val < INT16_MIN) val = INT16_MIN;
                DRAM_x[j] = (fix16_t)val;
            }
            for (int j = 0; j < M; ++j) {
                for (int i = 0; i < K; ++i) {
                    int v = ((j * 31 + i * 97 + cycle * 13) % 201) - 100;
                    int32_t val = v * scaleA;
                    if (val > INT16_MAX) val = INT16_MAX;
                    if (val < INT16_MIN) val = INT16_MIN;
                    DRAM_A[j][i] = (fix16_t)val;
                }
            }
            for (int i = 0; i < K; ++i) {
                for (int k = 0; k < N; ++k) {
                    int v = ((i * 29 + k * 83 + cycle * 19) % 201) - 100;
                    int32_t val = v * scaleB;
                    if (val > INT16_MAX) val = INT16_MAX;
                    if (val < INT16_MIN) val = INT16_MIN;
                    DRAM_B[i][k] = (fix16_t)val;
                }
            }
            for (int k = 0; k < N; ++k) {
                int v = ((k * 47 + cycle * 23) % 201) - 100;
                int32_t val = v * scaley;
                if (val > INT16_MAX) val = INT16_MAX;
                if (val < INT16_MIN) val = INT16_MIN;
                DRAM_y[k] = (fix16_t)val;
            }
            DRAM_bias[0] = 0;
        }

        /* Call DUT once per cycle */
        top(DRAM_x, DRAM_A, DRAM_B, DRAM_y, DRAM_bias, DRAM_result);

        /* Sample selected input/output signals to CSV */
        /* Inputs: DRAM_x[0], DRAM_x[1], DRAM_A[0][0], DRAM_B[0][0], DRAM_y[0], DRAM_bias[0] (decimal)
           Output: DRAM_result[0] (hex uppercase, no 0x)
        */
        int dx0 = (int)DRAM_x[0];
        int dx1 = (int)DRAM_x[1];
        int da00 = (int)DRAM_A[0][0];
        int db00 = (int)DRAM_B[0][0];
        int dy0 = (int)DRAM_y[0];
        int dbias0 = (int)DRAM_bias[0];
        uint16_t out_hex = (uint16_t)DRAM_result[0];

        /* Write CSV line */
        std::fprintf(f, "%d,%d,%d,%d,%d,%d,%d,%X\n",
                     cycle,
                     dx0,
                     dx1,
                     da00,
                     db00,
                     dy0,
                     dbias0,
                     (unsigned)out_hex);
    }

    std::fclose(f);
    return 0;
}

