// hls.cpp
// HLS top function that reproduces the reference C fixed-point behavior.
// Uses int16_t fixed-point inputs with 11 fractional bits (FRAC_BITS = 11).
// The implementation follows the same sequence of operations and the same
// right-shift truncation used by the C reference, avoiding extra widening
// that would change results. This file is written to be compatible with
// older Vivado HLS toolchains (C++98 compatible).

#include <stdint.h>
#include <limits.h>

#define M 64
#define K 128
#define N 128
#define FRAC_BITS 11

typedef int16_t fix16_t;

/* Saturate a 32-bit value to signed 16-bit range (match C reference behavior) */
static inline fix16_t saturate_int16_from32(int32_t v) {
    if (v > (int32_t)INT16_MAX) return (fix16_t)INT16_MAX;
    if (v < (int32_t)INT16_MIN) return (fix16_t)INT16_MIN;
    return (fix16_t)v;
}

extern "C" {

void top(
    fix16_t DRAM_x[M],
    fix16_t DRAM_A[M][K],
    fix16_t DRAM_B[K][N],
    fix16_t DRAM_y[N],
    fix16_t DRAM_bias[1],
    fix16_t DRAM_result[1])
{
#pragma HLS INTERFACE m_axi port=DRAM_x offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_A offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_B offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_y offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_bias offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_result offset=slave bundle=mem2
#pragma HLS INTERFACE s_axilite port=DRAM_x bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_A bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_B bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_y bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_bias bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_result bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    /* mid1: result of A^T * x (length K) -- use int32 as in C reference */
    int32_t mid1[K];
    /* mid2: result of B^T * mid1 (length N) -- use int32 to match C reference */
    int32_t mid2[N];

    /* Compute mid1 = A^T * x
       mid1[i] = sum_j ((A[j][i] * x[j]) >> FRAC_BITS)
       Use 32-bit intermediate product (fits for int16*int16) and standard >> */
    for (int i = 0; i < K; ++i) {
#pragma HLS PIPELINE II=1
        int32_t acc = 0;
        for (int j = 0; j < M; ++j) {
            int32_t prod = (int32_t)DRAM_A[j][i] * (int32_t)DRAM_x[j]; /* fits in 32-bit */
            acc += (prod >> FRAC_BITS);
        }
        mid1[i] = acc;
    }

    /* Compute mid2 = B^T * mid1
       Use 32-bit multiply/accumulate to match the reference C implementation. */
    for (int k = 0; k < N; ++k) {
#pragma HLS PIPELINE II=1
        int32_t acc = 0;
        for (int i = 0; i < K; ++i) {
            int32_t prod = (int32_t)DRAM_B[i][k] * (int32_t)mid1[i];
            acc += (prod >> FRAC_BITS);
        }
        mid2[k] = acc;
    }

    /* Compute final dot product: dot = sum_k ( (mid2[k] * y[k]) >> FRAC_BITS )
       Use 64-bit accumulator for the dot (same as C reference). */
    int64_t dot = 0;
    for (int k = 0; k < N; ++k) {
#pragma HLS PIPELINE II=1
        int64_t prod = (int64_t)mid2[k] * (int64_t)DRAM_y[k];
        dot += (prod >> FRAC_BITS);
    }

    /* Cast dot to 32-bit (matching C reference cast) then saturate to 16-bit */
    int32_t out32 = (int32_t)dot;
    DRAM_result[0] = saturate_int16_from32(out32);
}

} // extern "C"

