// tb_hls_cosim.cpp
// HLS C/RTL co-simulation testbench for the HLS top function.
// This testbench produces the same deterministic test vectors as the C reference
// and writes a CSV file with selected inputs and the output. The DUT signature
// matches the HLS top function (int16_t fixed-point arrays).
// Written to be compatible with older Vivado HLS toolchains (C++98 compatible).

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>

#define M 64
#define K 128
#define N 128
#define FRAC_BITS 11

typedef int16_t fix16_t;

/* Declare DUT with exactly the same signature as in HLS code */
extern "C" void top(fix16_t DRAM_x[M],
                    fix16_t DRAM_A[M][K],
                    fix16_t DRAM_B[K][N],
                    fix16_t DRAM_y[N],
                    fix16_t DRAM_bias[1],
                    fix16_t DRAM_result[1]);

/* Testbench producing deterministic test vectors and CSV output */
/* CSV columns:
   cycle,DRAM_x[0],DRAM_x[1],DRAM_A[0][0],DRAM_B[0][0],DRAM_y[0],DRAM_bias[0],DRAM_result[0]
   Roles:
   meta,in,in,in,in,in,in,out
*/

int main() {
    const int CYCLES = 32; /* produce 32 cycles (rows) */

    fix16_t DRAM_x[M];
    fix16_t DRAM_A[M][K];
    fix16_t DRAM_B[K][N];
    fix16_t DRAM_y[N];
    fix16_t DRAM_bias[1];
    fix16_t DRAM_result[1];

    FILE *f = fopen("hls_output.csv", "w");
    if (!f) return 1;

    /* Header row */
    fprintf(f, "cycle,DRAM_x[0],DRAM_x[1],DRAM_A[0][0],DRAM_B[0][0],DRAM_y[0],DRAM_bias[0],DRAM_result[0]\n");
    /* Roles row */
    fprintf(f, "meta,in,in,in,in,in,in,out\n");

    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        /* Fill arrays deterministically based on cycle index.
           We include some special patterns for first few cycles,
           then a deterministic pseudo-pattern for the rest.
        */
        if (cycle == 0) {
            /* All zeros */
            memset(DRAM_x, 0, sizeof(DRAM_x));
            memset(DRAM_A, 0, sizeof(DRAM_A));
            memset(DRAM_B, 0, sizeof(DRAM_B));
            memset(DRAM_y, 0, sizeof(DRAM_y));
            DRAM_bias[0] = 0;
        } else if (cycle == 1) {
            /* All ones (1.0 in fixed-point) */
            fix16_t one = (fix16_t)(1 << FRAC_BITS);
            int j,i,k;
            for (j = 0; j < M; ++j) DRAM_x[j] = one;
            for (j = 0; j < M; ++j)
                for (i = 0; i < K; ++i) DRAM_A[j][i] = one;
            for (i = 0; i < K; ++i)
                for (k = 0; k < N; ++k) DRAM_B[i][k] = one;
            for (k = 0; k < N; ++k) DRAM_y[k] = one;
            DRAM_bias[0] = 0;
        } else if (cycle == 2) {
            /* All -1 */
            fix16_t negone = (fix16_t)(-(1 << FRAC_BITS));
            int j,i,k;
            for (j = 0; j < M; ++j) DRAM_x[j] = negone;
            for (j = 0; j < M; ++j)
                for (i = 0; i < K; ++i) DRAM_A[j][i] = negone;
            for (i = 0; i < K; ++i)
                for (k = 0; k < N; ++k) DRAM_B[i][k] = negone;
            for (k = 0; k < N; ++k) DRAM_y[k] = negone;
            DRAM_bias[0] = 0;
        } else if (cycle == 3) {
            /* Max saturation test: extreme positive */
            int j,i,k;
            for (j = 0; j < M; ++j) DRAM_x[j] = (fix16_t)INT16_MAX;
            for (j = 0; j < M; ++j)
                for (i = 0; i < K; ++i) DRAM_A[j][i] = (fix16_t)INT16_MAX;
            for (i = 0; i < K; ++i)
                for (k = 0; k < N; ++k) DRAM_B[i][k] = (fix16_t)INT16_MAX;
            for (k = 0; k < N; ++k) DRAM_y[k] = (fix16_t)INT16_MAX;
            DRAM_bias[0] = 0;
        } else if (cycle == 4) {
            /* Max negative saturation test */
            int j,i,k;
            for (j = 0; j < M; ++j) DRAM_x[j] = (fix16_t)INT16_MIN;
            for (j = 0; j < M; ++j)
                for (i = 0; i < K; ++i) DRAM_A[j][i] = (fix16_t)INT16_MIN;
            for (i = 0; i < K; ++i)
                for (k = 0; k < N; ++k) DRAM_B[i][k] = (fix16_t)INT16_MIN;
            for (k = 0; k < N; ++k) DRAM_y[k] = (fix16_t)INT16_MIN;
            DRAM_bias[0] = 0;
        } else if (cycle == 5) {
            /* Identity-like: A is identity on min(M,K) diagonal, B identity, x is ramp, y ones */
            int i,j,k;
            memset(DRAM_A, 0, sizeof(DRAM_A));
            memset(DRAM_B, 0, sizeof(DRAM_B));
            for (j = 0; j < M; ++j) {
                DRAM_x[j] = (fix16_t)((((j % 8) - 4) * (1 << FRAC_BITS)) / 8); /* small ramp -0.5..+0.375 */
            }
            for (i = 0; i < K && i < M; ++i) {
                DRAM_A[i][i] = (fix16_t)(1 << FRAC_BITS);
            }
            for (i = 0; i < K && i < N; ++i) {
                DRAM_B[i][i] = (fix16_t)(1 << FRAC_BITS);
            }
            for (k = 0; k < N; ++k) DRAM_y[k] = (fix16_t)(1 << FRAC_BITS);
            DRAM_bias[0] = 0;
        } else if (cycle == 6) {
            /* Sparse: only first element nonzero */
            int j,i,k;
            memset(DRAM_A, 0, sizeof(DRAM_A));
            memset(DRAM_B, 0, sizeof(DRAM_B));
            for (j = 0; j < M; ++j) DRAM_x[j] = 0;
            DRAM_x[0] = (fix16_t)(1 << FRAC_BITS);
            DRAM_A[0][0] = (fix16_t)(1 << FRAC_BITS);
            DRAM_B[0][0] = (fix16_t)(1 << FRAC_BITS);
            for (k = 0; k < N; ++k) DRAM_y[k] = 0;
            DRAM_y[0] = (fix16_t)(1 << FRAC_BITS);
            DRAM_bias[0] = 0;
        } else if (cycle == 7) {
            /* Alternating signs in x and y, small coefficients in A/B */
            int j,i,k;
            for (j = 0; j < M; ++j)
                DRAM_x[j] = (fix16_t)((((j & 1) ? 1 : -1) * (1 << FRAC_BITS)) / 4); /* +/- 0.25 */
            for (j = 0; j < M; ++j)
                for (i = 0; i < K; ++i)
                    DRAM_A[j][i] = (fix16_t)((((j + i) & 1) ? 1 : -1) * ((1 << FRAC_BITS) / 8)); /* +/- 0.125 */
            for (i = 0; i < K; ++i)
                for (k = 0; k < N; ++k)
                    DRAM_B[i][k] = (fix16_t)((((i + k) & 1) ? 1 : -1) * ((1 << FRAC_BITS) / 8));
            for (k = 0; k < N; ++k)
                DRAM_y[k] = (fix16_t)((((k & 1) ? -1 : 1) * (1 << FRAC_BITS)) / 2); /* +/- 0.5 */
            DRAM_bias[0] = 0;
        } else {
            /* Deterministic pseudo-pattern depending on cycle to create variety */
            int scaleA = ((cycle & 3) + 1) * ((1 << FRAC_BITS) / 16); /* small scales */
            if (scaleA == 0) scaleA = 1;
            int scaleB = ((cycle & 7) + 1) * ((1 << FRAC_BITS) / 32);
            if (scaleB == 0) scaleB = 1;
            int scalex = ((cycle & 5) + 1) * ((1 << FRAC_BITS) / 16);
            if (scalex == 0) scalex = 1;
            int scaley = ((cycle & 6) + 1) * ((1 << FRAC_BITS) / 32);
            if (scaley == 0) scaley = 1;

            int j,i,k;
            for (j = 0; j < M; ++j) {
                int v = ((j * 131 + cycle * 17) % 201) - 100; /* -100..100 */
                int32_t val = v * scalex;
                if (val > INT16_MAX) val = INT16_MAX;
                if (val < INT16_MIN) val = INT16_MIN;
                DRAM_x[j] = (fix16_t)val;
            }
            for (j = 0; j < M; ++j) {
                for (i = 0; i < K; ++i) {
                    int v = ((j * 31 + i * 97 + cycle * 13) % 201) - 100;
                    int32_t val = v * scaleA;
                    if (val > INT16_MAX) val = INT16_MAX;
                    if (val < INT16_MIN) val = INT16_MIN;
                    DRAM_A[j][i] = (fix16_t)val;
                }
            }
            for (i = 0; i < K; ++i) {
                for (k = 0; k < N; ++k) {
                    int v = ((i * 29 + k * 83 + cycle * 19) % 201) - 100;
                    int32_t val = v * scaleB;
                    if (val > INT16_MAX) val = INT16_MAX;
                    if (val < INT16_MIN) val = INT16_MIN;
                    DRAM_B[i][k] = (fix16_t)val;
                }
            }
            for (k = 0; k < N; ++k) {
                int v = ((k * 47 + cycle * 23) % 201) - 100;
                int32_t val = v * scaley;
                if (val > INT16_MAX) val = INT16_MAX;
                if (val < INT16_MIN) val = INT16_MIN;
                DRAM_y[k] = (fix16_t)val;
            }
            DRAM_bias[0] = 0;
        }

        /* Call DUT once per cycle */
        top(DRAM_x, DRAM_A, DRAM_B, DRAM_y, DRAM_bias, DRAM_result);

        /* Sample selected input/output signals to CSV */
        /* Inputs: DRAM_x[0], DRAM_x[1], DRAM_A[0][0], DRAM_B[0][0], DRAM_y[0], DRAM_bias[0] (decimal)
           Output: DRAM_result[0] (hex uppercase, no 0x)
        */
        int dx0 = (int)DRAM_x[0];
        int dx1 = (int)DRAM_x[1];
        int da00 = (int)DRAM_A[0][0];
        int db00 = (int)DRAM_B[0][0];
        int dy0 = (int)DRAM_y[0];
        int dbias0 = (int)DRAM_bias[0];
        unsigned int out_hex = (unsigned int)((uint16_t)DRAM_result[0]);

        /* Write CSV line */
        fprintf(f, "%d,%d,%d,%d,%d,%d,%d,%X\n",
                cycle,
                dx0,
                dx1,
                da00,
                db00,
                dy0,
                dbias0,
                out_hex);
    }

    fclose(f);
    return 0;
}

