#include "test.h"
#include <iomanip>

void block_mm(hls::stream<blockvec> &Arows, hls::stream<blockvec> &Bcols,
        blockmat &ABpartial, int it) {
    int counter = it % (SIZE / BLOCK_SIZE);
    static DTYPE A[BLOCK_SIZE][SIZE];
    if (counter == 0) {
        for (int i = 0; i < SIZE; i++) {
            blockvec tempA = Arows.read();
            for (int j = 0; j < BLOCK_SIZE; j++) {
                A[j][i] = tempA.a[j];
            }
        }
    }
    DTYPE AB[BLOCK_SIZE][BLOCK_SIZE] = { 0 };
    for (int k = 0; k < SIZE; k++) {
        blockvec tempB = Bcols.read();
        for (int i = 0; i < BLOCK_SIZE; i++) {
            for (int j = 0; j < BLOCK_SIZE; j++) {
                AB[i][j] = AB[i][j] + A[i][k] * tempB.a[j];
            }
        }
    }
    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            ABpartial.out[i][j] = AB[i][j];
        }
    }
}

int main() {
    hls::stream<blockvec> Arows;
    hls::stream<blockvec> Bcols;

    DTYPE A[BLOCK_SIZE][SIZE];
    DTYPE B[SIZE][BLOCK_SIZE];

    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int k = 0; k < SIZE; k++) {
            A[i][k] = (i + 1) + k * 10;
        }
    }

    for (int k = 0; k < SIZE; k++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            B[k][j] = (k + 1) + j * 100;
        }
    }

    for (int k = 0; k < SIZE; k++) {
        blockvec vb;
        for (int i = 0; i < BLOCK_SIZE; i++) vb.a[i] = A[i][k];
        Arows.write(vb);
    }

    for (int k = 0; k < SIZE; k++) {
        blockvec vb;
        for (int j = 0; j < BLOCK_SIZE; j++) vb.a[j] = B[k][j];
        Bcols.write(vb);
    }

    blockmat ABpartial;
    block_mm(Arows, Bcols, ABpartial, 0);

    DTYPE REF[BLOCK_SIZE][BLOCK_SIZE] = {0};
    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            DTYPE sum = 0;
            for (int k = 0; k < SIZE; k++) sum += A[i][k] * B[k][j];
            REF[i][j] = sum;
        }
    }

    std::cout << "Computed ABpartial:\n";
    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            std::cout << std::setw(8) << ABpartial.out[i][j];
        }
        std::cout << "\n";
    }

    std::cout << "Reference result:\n";
    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            std::cout << std::setw(8) << REF[i][j];
        }
        std::cout << "\n";
    }

    bool ok = true;
    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            if (ABpartial.out[i][j] != REF[i][j]) ok = false;
        }
    }

    if (ok) std::cout << "PASS\n";
    else std::cout << "FAIL\n";

    return ok ? 0 : 1;
}

