#include <cstdint>
#include <cstdlib>
#include <cstdio>
#include <iostream>
#include <fstream>
#include <sstream>
#include <vector>
#include <deque>
#include <iomanip>
#include <string>

// Define simplified HLS stream and required types to match the DUT signature.
namespace hls {
    template<typename T>
    class stream {
    public:
        stream() {}
        void write(const T &v) { buf.push_back(v); }
        T read() {
            if (buf.empty()) {
                // In testbench we ensure reads are available. If not, return default.
                return T();
            }
            T v = buf.front();
            buf.pop_front();
            return v;
        }
        bool empty() const { return buf.empty(); }
        size_t size() const { return buf.size(); }
    private:
        std::deque<T> buf;
    };
}

// Parameters for the DUT (kept small to keep simulation light)
using DTYPE = int32_t;
const int BLOCK_SIZE = 2;
const int SIZE = 4; // must be multiple of BLOCK_SIZE

struct blockvec {
    DTYPE a[BLOCK_SIZE];
};
struct blockmat {
    DTYPE out[BLOCK_SIZE][BLOCK_SIZE];
};

// DUT: reproduced from the user's code (with our types)
void block_mm(hls::stream<blockvec> &Arows, hls::stream<blockvec> &Bcols,
        blockmat &ABpartial, int it) {
    int counter = it % (SIZE / BLOCK_SIZE);
    static DTYPE A[BLOCK_SIZE][SIZE];
    if (counter == 0) {
        for (int i = 0; i < SIZE; i++) {
            blockvec tempA = Arows.read();
            for (int j = 0; j < BLOCK_SIZE; j++) {
                A[j][i] = tempA.a[j];
            }
        }
    }
    DTYPE AB[BLOCK_SIZE][BLOCK_SIZE] = { 0 };
    for (int k = 0; k < SIZE; k++) {
        blockvec tempB = Bcols.read();
        for (int i = 0; i < BLOCK_SIZE; i++) {
            for (int j = 0; j < BLOCK_SIZE; j++) {
                AB[i][j] = AB[i][j] + A[i][k] * tempB.a[j];
            }
        }
    }
    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            ABpartial.out[i][j] = AB[i][j];
        }
    }
}

int main() {
    // Number of cycles to simulate (between 20 and 50)
    const int CYCLES = 24;

    // Streams to connect to DUT
    hls::stream<blockvec> Arows;
    hls::stream<blockvec> Bcols;

    // Prepare output CSV
    std::ofstream fout("c_output.csv", std::ofstream::out | std::ofstream::trunc);
    if (!fout.is_open()) {
        std::perror("Failed to open c_output.csv");
        return 1;
    }

    // CSV header: cycle, inputs (Arows, Bcols, it), then outputs (ABpartial.out[i][j])
    fout << "cycle,Arows,Bcols,it,ABpartial.out[0][0],ABpartial.out[0][1],ABpartial.out[1][0],ABpartial.out[1][1]\n";
    // Role row
    fout << "meta,in,in,in,out,out,out,out\n";

    // Deterministic test vectors:
    // For simplicity we push SIZE items into each stream every cycle.
    // We will record the first pushed element of that cycle in the CSV input columns.
    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        int it = cycle;

        // Prepare and push SIZE blockvec items into Arows and Bcols.
        // Patterns chosen to be deterministic and varied.
        blockvec firstA; blockvec firstB;
        for (int p = 0; p < SIZE; ++p) {
            blockvec va;
            // Arows values: a[0] = cycle*100 + p*2 + 1, a[1] = cycle*100 + p*2 + 2
            va.a[0] = static_cast<DTYPE>(cycle * 100 + p * 2 + 1);
            va.a[1] = static_cast<DTYPE>(cycle * 100 + p * 2 + 2);
            Arows.write(va);
            if (p == 0) firstA = va;

            blockvec vb;
            // Bcols values: a[0] = cycle*10 + p*2 + 3, a[1] = cycle*10 + p*2 + 4
            vb.a[0] = static_cast<DTYPE>(cycle * 10 + p * 2 + 3);
            vb.a[1] = static_cast<DTYPE>(cycle * 10 + p * 2 + 4);
            Bcols.write(vb);
            if (p == 0) firstB = vb;
        }

        // Call DUT for this cycle
        blockmat ABpartial;
        // Initialize ABpartial.out to distinguish if DUT fails to write
        for (int i = 0; i < BLOCK_SIZE; ++i)
            for (int j = 0; j < BLOCK_SIZE; ++j)
                ABpartial.out[i][j] = 0xDEADBEEF;

        block_mm(Arows, Bcols, ABpartial, it);

        // Encode the first pushed blockvec for Arows and Bcols into a single decimal integer for CSV input columns.
        // Packing: (a0 << 16) | (a1 & 0xFFFF)
        int64_t packedA = (static_cast<int64_t>(firstA.a[0]) << 16) | (static_cast<int64_t>(firstA.a[1]) & 0xFFFF);
        int64_t packedB = (static_cast<int64_t>(firstB.a[0]) << 16) | (static_cast<int64_t>(firstB.a[1]) & 0xFFFF);

        // Prepare hex strings for outputs (uppercase, no 0x)
        auto to_hex = [](DTYPE v) -> std::string {
            std::stringstream ss;
            // For negative values, represent as unsigned hex of the underlying bits
            uint32_t uv = static_cast<uint32_t>(v);
            ss << std::hex << std::uppercase << uv;
            return ss.str();
        };

        // Write CSV row: cycle,Arows,Bcols,it,ABpartial.out[0][0],...
        fout << cycle << ",";
        fout << packedA << ",";
        fout << packedB << ",";
        fout << it << ",";
        fout << to_hex(ABpartial.out[0][0]) << ",";
        fout << to_hex(ABpartial.out[0][1]) << ",";
        fout << to_hex(ABpartial.out[1][0]) << ",";
        fout << to_hex(ABpartial.out[1][1]) << "\n";
    }

    fout.close();
    return 0;
}

