// hls.cpp
// HLS top function for block partial matrix multiply.
// Compatible with Vivado HLS (C++98 environment).
//
// Behavior notes (to match the original stream-based C testbench):
// - The original stream-based DUT reads SIZE blockvec items from the Arows stream
//   only when iteration % (SIZE / BLOCK_SIZE) == 0. The testbench pushes SIZE
//   blockvecs into the Arows stream every cycle before calling the DUT. Therefore,
//   between two reloads the stream accumulates multiple pushed "blocks" and the DUT
//   consumes the oldest pushed block when reload occurs. This produces a one-block
//   FIFO behavior (with FIFO depth equal to reload interval).
//
// - To reproduce identical behavior using a pointer-based interface (where the
//   testbench passes only the current cycle's Arows array), the top function must
//   internally emulate that small FIFO of pushed Arows blocks. We implement a
//   circular buffer that stores the last R = (SIZE / BLOCK_SIZE) pushed Arows
//   blocks. Each call the current Arows array is enqueued; when reload is required
//   the oldest enqueued block is dequeued and used to populate the persistent A_local.
//   This matches the sequence of A used by the stream-based DUT.
//
// Interface (must not change):
// extern "C" void block_mm(const DTYPE *Arows, const DTYPE *Bcols, DTYPE *ABpartial_out, int iteration)
// Arows and Bcols are flattened arrays of length SIZE * BLOCK_SIZE:
//   element at block index p, element idx  =>  arr[p * BLOCK_SIZE + idx]
// ABpartial_out is flattened row-major [i * BLOCK_SIZE + j]

#include <stdint.h>

#define SIZE 4
#define BLOCK_SIZE 2
#define R (SIZE / BLOCK_SIZE)

typedef int32_t DTYPE;

extern "C" {

void block_mm(
    const DTYPE *Arows,        // pointer to input Arows blocks, layout: [block_index * BLOCK_SIZE + element_index]
    const DTYPE *Bcols,        // pointer to input Bcols blocks, layout: [k * BLOCK_SIZE + element_index]
    DTYPE *ABpartial_out,      // pointer to output block (flattened): [i * BLOCK_SIZE + j]
    int iteration
) {
    // Determine when to (re)load A from the provided Arows buffer.
    int reload_counter = iteration % R;

    // Persistent local storage for A: BLOCK_SIZE x SIZE.
    // This retains values across function calls (cycles).
    static DTYPE A_local[BLOCK_SIZE][SIZE];
    // Initialize to zero on first use (static zero-initialized by C rules),
    // but ensure explicit initialization for clarity in HLS simulation.
    static int A_local_initialized = 0;
    if (!A_local_initialized) {
        for (int i = 0; i < BLOCK_SIZE; ++i)
            for (int j = 0; j < SIZE; ++j)
                A_local[i][j] = 0;
        A_local_initialized = 1;
    }

    // Emulated FIFO for Arows pushes:
    // Each cycle the testbench pushes an entire array of SIZE blockvecs.
    // We store the last R such pushed arrays in a circular buffer so that when
    // a reload occurs we consume the oldest one (mimicking the stream FIFO).
    static DTYPE A_fifo[R][SIZE * BLOCK_SIZE];
    static int fifo_wr = 0;
    static int fifo_rd = 0;
    static int fifo_cnt = 0;
    // Initialize FIFO to zeros on first use
    static int A_fifo_initialized = 0;
    if (!A_fifo_initialized) {
        for (int ri = 0; ri < R; ++ri)
            for (int n = 0; n < SIZE * BLOCK_SIZE; ++n)
                A_fifo[ri][n] = 0;
        A_fifo_initialized = 1;
    }

    // Enqueue current cycle's Arows into the FIFO (copy flattened array)
    for (int n = 0; n < SIZE * BLOCK_SIZE; ++n) {
        A_fifo[fifo_wr][n] = Arows[n];
    }
    fifo_wr = (fifo_wr + 1) % R;
    if (fifo_cnt < R) {
        fifo_cnt++;
    } else {
        // If FIFO is full, overwrite oldest: advance read pointer to keep indices consistent.
        fifo_rd = (fifo_rd + 1) % R;
    }

    // When starting a new A-block set (reload_counter == 0), dequeue the oldest
    // enqueued Arows block and copy into the persistent A_local buffer.
    if (reload_counter == 0) {
        if (fifo_cnt > 0) {
            int pop_idx = fifo_rd;
            // Map flattened layout [p * BLOCK_SIZE + idx] to A_local[idx][p]
            for (int p = 0; p < SIZE; ++p) {
                for (int idx = 0; idx < BLOCK_SIZE; ++idx) {
                    A_local[idx][p] = A_fifo[pop_idx][p * BLOCK_SIZE + idx];
                }
            }
            fifo_rd = (fifo_rd + 1) % R;
            fifo_cnt--;
        } else {
            // Defensive: no data in FIFO (shouldn't happen with the testbench),
            // leave A_local unchanged (it was initialized to zero).
        }
    }

    // Accumulator for the partial BLOCK_SIZE x BLOCK_SIZE multiply.
    DTYPE AB[BLOCK_SIZE][BLOCK_SIZE];
    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            AB[i][j] = 0;
        }
    }

    // For each k in 0..SIZE-1, load the k-th B column block and accumulate:
    // AB[i][j] += A_local[i][k] * Bcols[k * BLOCK_SIZE + j]
    for (int k = 0; k < SIZE; ++k) {
        DTYPE tempB[BLOCK_SIZE];
        for (int idx = 0; idx < BLOCK_SIZE; ++idx) {
            tempB[idx] = Bcols[k * BLOCK_SIZE + idx];
        }
        for (int i = 0; i < BLOCK_SIZE; ++i) {
            for (int j = 0; j < BLOCK_SIZE; ++j) {
                AB[i][j] += A_local[i][k] * tempB[j];
            }
        }
    }

    // Write back the AB block to the flattened output buffer in row-major order:
    // index = i * BLOCK_SIZE + j
    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            ABpartial_out[i * BLOCK_SIZE + j] = AB[i][j];
        }
    }
}

} // extern "C"

