// tb_hls_cosim.cpp
// HLS cosimulation testbench that drives the pointer-based extern "C" top function.
// Test vectors and CSV format are kept identical to the original C testbench.
// This file must not change the test patterns  only adapt to call the pointer-based top.
//
// The testbench constructs flat arrays Arows_arr and Bcols_arr (each SIZE * BLOCK_SIZE)
// exactly matching the layout expected by the HLS top function:
//   element at block index p, element idx  =>  arr[p * BLOCK_SIZE + idx]
//
// The CSV output format mirrors the reference C testbench so the two CSVs can be compared.

#include <stdint.h>
#include <stdlib.h>
#include <stdio.h>
#include <iostream>
#include <fstream>
#include <sstream>
#include <iomanip>
#include <string>

typedef int32_t DTYPE;
const int BLOCK_SIZE = 2;
const int SIZE = 4; // must be multiple of BLOCK_SIZE

struct blockvec {
    DTYPE a[BLOCK_SIZE];
};
struct blockmat {
    DTYPE out[BLOCK_SIZE][BLOCK_SIZE];
};

// External top-level DUT declaration (must match HLS C function signature exactly).
extern "C" void block_mm(const DTYPE *Arows, const DTYPE *Bcols, DTYPE *ABpartial_out, int iteration);

// Helper: convert a DTYPE value to an uppercase hex string representing the underlying 32-bit bits.
// For negative values, this prints the unsigned hex of the bit pattern.
// NOTE: we match the reference C testbench formatting: no leading zeros, uppercase, no "0x".
static std::string to_hex(DTYPE v) {
    std::ostringstream ss;
    uint32_t uv = static_cast<uint32_t>(v);
    ss << std::hex << std::uppercase << uv;
    return ss.str();
}

int main() {
    // Number of cycles to simulate (between 20 and 50)
    const int CYCLES = 24;

    // Prepare output CSV for HLS/RTL cosimulation results
    std::ofstream fout("hls_output.csv", std::ofstream::out | std::ofstream::trunc);
    if (!fout.is_open()) {
        perror("Failed to open hls_output.csv");
        return 1;
    }

    // CSV header: cycle, inputs (Arows, Bcols, it), then outputs (ABpartial.out[i][j])
    fout << "cycle,Arows,Bcols,it,ABpartial.out[0][0],ABpartial.out[0][1],ABpartial.out[1][0],ABpartial.out[1][1]\n";
    // Role row
    fout << "meta,in,in,in,out,out,out,out\n";

    // Deterministic test vectors:
    // For simplicity we fill SIZE items into each "cycle" into arrays and call the DUT.
    // We record the first element of the arrays for CSV input columns.
    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        int it = cycle;

        // Allocate flat arrays that follow the HLS top function memory layout:
        // Arows: SIZE blocks, each block has BLOCK_SIZE elements -> total SIZE * BLOCK_SIZE
        DTYPE Arows_arr[SIZE * BLOCK_SIZE];
        DTYPE Bcols_arr[SIZE * BLOCK_SIZE];

        blockvec firstA; blockvec firstB;

        for (int p = 0; p < SIZE; ++p) {
            // Arows values: a[0] = cycle*100 + p*2 + 1, a[1] = cycle*100 + p*2 + 2
            DTYPE a0 = static_cast<DTYPE>(cycle * 100 + p * 2 + 1);
            DTYPE a1 = static_cast<DTYPE>(cycle * 100 + p * 2 + 2);
            Arows_arr[p * BLOCK_SIZE + 0] = a0;
            Arows_arr[p * BLOCK_SIZE + 1] = a1;
            if (p == 0) {
                firstA.a[0] = a0;
                firstA.a[1] = a1;
            }

            // Bcols values: a[0] = cycle*10 + p*2 + 3, a[1] = cycle*10 + p*2 + 4
            DTYPE b0 = static_cast<DTYPE>(cycle * 10 + p * 2 + 3);
            DTYPE b1 = static_cast<DTYPE>(cycle * 10 + p * 2 + 4);
            Bcols_arr[p * BLOCK_SIZE + 0] = b0;
            Bcols_arr[p * BLOCK_SIZE + 1] = b1;
            if (p == 0) {
                firstB.a[0] = b0;
                firstB.a[1] = b1;
            }
        }

        // Call DUT for this cycle
        DTYPE ABpartial_out[BLOCK_SIZE * BLOCK_SIZE];
        // Initialize ABpartial_out to distinguish if DUT fails to write
        for (int i = 0; i < BLOCK_SIZE * BLOCK_SIZE; ++i) {
            ABpartial_out[i] = (DTYPE)0xDEADBEEF;
        }

        // Call the C-style HLS top function
        block_mm(Arows_arr, Bcols_arr, ABpartial_out, it);

        // Assemble blockmat from flat ABpartial_out
        blockmat ABpartial;
        for (int i = 0; i < BLOCK_SIZE; ++i)
            for (int j = 0; j < BLOCK_SIZE; ++j)
                ABpartial.out[i][j] = ABpartial_out[i * BLOCK_SIZE + j];

        // Encode the first pushed blockvec for Arows and Bcols into a single decimal integer for CSV input columns.
        // Packing: (a0 << 16) | (a1 & 0xFFFF)
        long long packedA = (static_cast<long long>(firstA.a[0]) << 16) | (static_cast<long long>(firstA.a[1]) & 0xFFFF);
        long long packedB = (static_cast<long long>(firstB.a[0]) << 16) | (static_cast<long long>(firstB.a[1]) & 0xFFFF);

        // Write CSV row: cycle,Arows,Bcols,it,ABpartial.out[0][0],...
        fout << cycle << ",";
        fout << packedA << ",";
        fout << packedB << ",";
        fout << it << ",";
        fout << to_hex(ABpartial.out[0][0]) << ",";
        fout << to_hex(ABpartial.out[0][1]) << ",";
        fout << to_hex(ABpartial.out[1][0]) << ",";
        fout << to_hex(ABpartial.out[1][1]) << "\n";
    }

    fout.close();
    return 0;
}

