// hls.cpp
// Vivado HLS top-level for block matrix multiply using hls::stream inputs.
// This implementation matches the C testbench behavior: the A buffer is
// preserved across calls (static) and only reloaded when counter == 0.
// The function signature and behavior are kept identical to the testbench.
#include <stdint.h>
#include <hls_stream.h>

const int BLOCK_SIZE = 2;
const int SIZE = 4;

typedef int32_t DTYPE;

struct blockvec {
    DTYPE a[BLOCK_SIZE];
};

struct blockmat {
    DTYPE out[BLOCK_SIZE][BLOCK_SIZE];
};

extern "C" {

void block_mm(hls::stream<blockvec> &Arows, hls::stream<blockvec> &Bcols, blockmat &ABpartial, int it) {
    // Interface pragmas for HLS
#pragma HLS INTERFACE axis port=Arows
#pragma HLS INTERFACE axis port=Bcols
#pragma HLS INTERFACE s_axilite port=ABpartial bundle=control
#pragma HLS INTERFACE s_axilite port=it bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Persistent A buffer across invocations (matches C testbench static behavior)
    static DTYPE A[BLOCK_SIZE][SIZE];
#pragma HLS ARRAY_PARTITION variable=A cyclic factor=2 dim=1

    // Determine when to reload Arows from the stream
    int counter = it % (SIZE / BLOCK_SIZE);

    if (counter == 0) {
        // Load SIZE blockvec entries from Arows stream into A
        for (int i = 0; i < SIZE; ++i) {
#pragma HLS PIPELINE
            blockvec bv = Arows.read();
            for (int j = 0; j < BLOCK_SIZE; ++j) {
#pragma HLS UNROLL factor=2
                A[j][i] = bv.a[j];
            }
        }
    }

    // Initialize partial result AB
    DTYPE AB[BLOCK_SIZE][BLOCK_SIZE];
#pragma HLS ARRAY_PARTITION variable=AB complete dim=1
    for (int i = 0; i < BLOCK_SIZE; ++i) {
        for (int j = 0; j < BLOCK_SIZE; ++j) {
            AB[i][j] = 0;
        }
    }

    // Read SIZE Bcols entries from stream and accumulate into AB
    for (int k = 0; k < SIZE; ++k) {
#pragma HLS PIPELINE II=1
        blockvec bvB = Bcols.read();
        for (int j = 0; j < BLOCK_SIZE; ++j) {
#pragma HLS UNROLL factor=2
            DTYPE tempB = bvB.a[j];
            for (int i = 0; i < BLOCK_SIZE; ++i) {
#pragma HLS UNROLL factor=2
                AB[i][j] += A[i][k] * tempB;
            }
        }
    }

    // Write result to output struct
    for (int i = 0; i < BLOCK_SIZE; ++i) {
#pragma HLS PIPELINE
        for (int j = 0; j < BLOCK_SIZE; ++j) {
#pragma HLS UNROLL factor=2
            ABpartial.out[i][j] = AB[i][j];
        }
    }
}

} // extern "C"

