                                dS[i*COLS + j],
                                dW[i*COLS + j],
                                dE[i*COLS + j],
                                Jc, v0sqr);

        /* Force some out-of-range values in a couple of cells (ITERATION 0)
           to ensure both clamp branches are executed for coverage.
           These are intentionally targeted and minimal-impact. */
        if (iter == 0 && i == 0 && j == 0) {
          /* force negative to exercise cval < 0 branch */
          cval = -0.5f;
        } else if (iter == 0 && i == 0 && j == 1) {
          /* force >1 to exercise cval > 1 branch */
          cval = 1.5f;
        }

        if (cval < 0.0f) cval = 0.0f;
