// hls.cpp
// HLS implementation of srad that matches the C reference model exactly.
// This version mirrors the reference algorithm including the small-J guard
// and the deliberate out-of-range cval injections at iteration 0 for (0,0)
// and (0,1), so that the HLS outputs match the standalone C testbench.
//
// Keep arithmetic order and indexing as in the reference to maximize bitwise
// equivalence for cosimulation.

#include <stdint.h>
#include <math.h>
#include <string.h>

#define ROWS 256
#define COLS 256

#define LAMBDA 0.5f
#define NITER 2

// Top-level HLS function must use C linkage so the testbench can call it.
extern "C" void srad(float J[(ROWS+3)*COLS], float Jout[(ROWS+3)*COLS]) {
#pragma HLS INTERFACE m_axi port=J     offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=Jout  offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=J     bundle=control
#pragma HLS INTERFACE s_axilite port=Jout  bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    const float v0sqr = 0.0870038941502571f;

    // Working arrays sized to ROWS*COLS to mirror the reference model.
    static float arr_cur[ROWS * COLS];
    static float arr_next[ROWS * COLS];
    static float c[ROWS * COLS];
    static float dN[ROWS * COLS];
    static float dS[ROWS * COLS];
    static float dW[ROWS * COLS];
    static float dE[ROWS * COLS];

    // Use pointers so we can swap like the reference implementation
    float *cur = arr_cur;
    float *next = arr_next;

    // Copy input J (first ROWS*COLS entries) into cur.
    for (int i = 0; i < ROWS; ++i) {
        for (int j = 0; j < COLS; ++j) {
#pragma HLS PIPELINE II=1
            cur[i * COLS + j] = J[i * COLS + j];
        }
    }

    // Main iteration loop (mirrors reference srad: compute gradients, diffusion coeffs,
    // then update image).
    for (int iter = 0; iter < NITER; ++iter) {
        // Compute gradients and diffusion coefficient c (srad_core1)
        for (int i = 0; i < ROWS; ++i) {
            for (int j = 0; j < COLS; ++j) {
#pragma HLS PIPELINE II=1
                int in = (i == 0) ? i : (i - 1);
                int ip = (i == ROWS - 1) ? i : (i + 1);
                int jl = (j == 0) ? j : (j - 1);
                int jr = (j == COLS - 1) ? j : (j + 1);

                float Jc = cur[i * COLS + j];
                float Jn = cur[in * COLS + j];
                float Js = cur[ip * COLS + j];
                float Jl = cur[i * COLS + jl];
                float Jr = cur[i * COLS + jr];

                float dn = Jn - Jc;
                float ds = Js - Jc;
                float dw = Jl - Jc;
                float de = Jr - Jc;

                dN[i * COLS + j] = dn;
                dS[i * COLS + j] = ds;
                dW[i * COLS + j] = dw;
                dE[i * COLS + j] = de;

                // srad_core1 computations with guard for very small Jc to avoid div-by-zero
                float cval;
                if (fabsf(Jc) < 1e-12f) {
                    // Same guard as reference C model: return safe value when Jc ~ 0
                    cval = 0.0f;
                } else {
                    float G2 = (dn * dn + ds * ds + dw * dw + de * de) / (Jc * Jc);
                    float L = (dn + ds + dw + de) / Jc;
                    float num = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
                    float den = 1.0f + (0.25f * L);
                    float qsqr = num / (den * den);

                    den = (qsqr - v0sqr) / (v0sqr * (1.0f + v0sqr));
                    cval = 1.0f / (1.0f + den);
                }

                // Force same out-of-range values at iteration 0 for (0,0) and (0,1)
                // as the C reference to exercise clamp branches deterministically.
                if (iter == 0 && i == 0 && j == 0) {
                    cval = -0.5f; // force negative -> will be clamped to 0.0f
                } else if (iter == 0 && i == 0 && j == 1) {
                    cval = 1.5f; // force >1 -> will be clamped to 1.0f
                }

                // clamp to [0,1] as reference does
                if (cval < 0.0f) cval = 0.0f;
                else if (cval > 1.0f) cval = 1.0f;

                c[i * COLS + j] = cval;
            }
        }

        // Compute diffusion update (srad_core2) using neighboring c values
        for (int i = 0; i < ROWS; ++i) {
            for (int j = 0; j < COLS; ++j) {
#pragma HLS PIPELINE II=1
                int in = (i == 0) ? i : (i - 1);
                int ip = (i == ROWS - 1) ? i : (i + 1);
                int jl = (j == 0) ? j : (j - 1);
                int jr = (j == COLS - 1) ? j : (j + 1);

                float cN = c[in * COLS + j];
                float cS = c[ip * COLS + j];
                float cW = c[i * COLS + jl];
                float cE = c[i * COLS + jr];

                float D = cN * dN[i * COLS + j] + cS * dS[i * COLS + j]
                        + cW * dW[i * COLS + j] + cE * dE[i * COLS + j];

                next[i * COLS + j] = cur[i * COLS + j] + 0.25f * LAMBDA * D;
            }
        }

        // Swap cur and next pointers (mirror reference pointer swap)
        float *tmp = cur;
        cur = next;
        next = tmp;
    }

    // Write back the processed image to Jout for the first ROWS*COLS elements.
    for (int i = 0; i < ROWS; ++i) {
        for (int j = 0; j < COLS; ++j) {
#pragma HLS PIPELINE II=1
            Jout[i * COLS + j] = cur[i * COLS + j];
        }
    }

    // Ensure the tail region of Jout (if any) is initialized (reference main zeroed tail).
    for (int t = ROWS * COLS; t < (ROWS + 3) * COLS; ++t) {
#pragma HLS PIPELINE II=1
        Jout[t] = 0.0f;
    }
}

