            unsigned long long v = (unsigned long long)hex_sum[i];
            int rem = (int)sizeof(buf) - off;
            if (rem > 0) {
                int w = std::snprintf(buf + off, rem, ",%llX", v);
                if (w > 0) off += w;
            }
        }
        if ((int)sizeof(buf) - off > 0) std::snprintf(buf + off, (int)sizeof(buf) - off, "\n");

        // Write the row to file
        std::fputs(buf, f);
    }

    std::fflush(f);
    std::fclose(f);

    return 0;
}

