#include "test.h"

float heaviside(float x) {
    float out = 0.0f;
    if (x > -0.0001f) out = 0.5f;
    if (x >  0.0001f) out = 1.0f;
    return out;
}

float mgvf_kernel(float result[GRID_ROWS * GRID_COLS], float imgvf[GRID_ROWS * GRID_COLS], float I[GRID_ROWS * GRID_COLS])
{
    float total_diff = 0.0f;

    for (int i = 0; i < GRID_ROWS; i++) {
        for (int j = 0; j < GRID_COLS; j++) {
            float old_val = imgvf[i * GRID_COLS + j];

            float UL    = ((i == 0              ||  j == 0              ) ? 0.0f : (imgvf[(i - 1   ) * GRID_COLS + (j - 1  )] - old_val));
            float U     = ((i == 0                                      ) ? 0.0f : (imgvf[(i - 1   ) * GRID_COLS + (j      )] - old_val));
            float UR    = ((i == 0              ||  j == GRID_COLS - 1  ) ? 0.0f : (imgvf[(i - 1   ) * GRID_COLS + (j + 1  )] - old_val));

            float L     = ((                        j == 0              ) ? 0.0f : (imgvf[(i       ) * GRID_COLS + (j - 1  )] - old_val));
            float R     = ((                        j == GRID_COLS - 1  ) ? 0.0f : (imgvf[(i       ) * GRID_COLS + (j + 1  )] - old_val));

            float DL    = ((i == GRID_ROWS - 1  ||  j == 0              ) ? 0.0f : (imgvf[(i + 1   ) * GRID_COLS + (j - 1  )] - old_val));
            float D     = ((i == GRID_ROWS - 1                          ) ? 0.0f : (imgvf[(i + 1   ) * GRID_COLS + (j      )] - old_val));
            float DR    = ((i == GRID_ROWS - 1  ||  j == GRID_COLS - 1  ) ? 0.0f : (imgvf[(i + 1   ) * GRID_COLS + (j + 1  )] - old_val));

            float vHe = old_val + MU_O_LAMBDA * (heaviside(UL) * UL + heaviside(U) * U + heaviside(UR) * UR + heaviside(L) * L + heaviside(R) * R + heaviside(DL) * DL + heaviside(D) * D + heaviside(DR) * DR);

            float vI = I[i * GRID_COLS + j];
            float new_val = vHe - (ONE_O_LAMBDA * vI * (vHe - vI));
            result[i * GRID_COLS + j] = new_val;

            total_diff += fabsf(new_val - old_val);
        }
    }

    return (total_diff / (float)(GRID_ROWS * GRID_COLS));
}

void mgvf(float result[GRID_ROWS * GRID_COLS], float imgvf[GRID_ROWS * GRID_COLS], float I[GRID_ROWS * GRID_COLS])
{
    int i;
    float diff = 1.0f;
    for (i = 0; i < ITERATION / 2; i++) {
        diff = mgvf_kernel(result, imgvf, I);
        diff = mgvf_kernel(imgvf, result, I);
    }
    (void)diff;
    return;
}

int main()
{
    const size_t N = (size_t)GRID_ROWS * (size_t)GRID_COLS;
    float *result = (float*)malloc(sizeof(float) * N);
    float *imgvf  = (float*)malloc(sizeof(float) * N);
    float *I      = (float*)malloc(sizeof(float) * N);

    if (!result || !imgvf || !I) {
        fprintf(stderr, "Allocation failed\n");
        return 1;
    }

    for (size_t idx = 0; idx < N; ++idx) {
        imgvf[idx] = (float)(idx % 255) / 255.0f;
        I[idx] = (float)((idx * 17) % 255) / 255.0f;
        result[idx] = 0.0f;
    }

    mgvf(result, imgvf, I);

    double sum = 0.0;
    for (size_t idx = 0; idx < 1000 && idx < N; ++idx) {
        sum += result[idx];
    }
    printf("checksum(first 1000) = %.6f\n", (float)sum);

    free(result);
    free(imgvf);
    free(I);
    return 0;
}

