/*
C Testbench for mgvf / heaviside DUT
- Produces c_output.csv
- First CSV line: column names
- Second CSV line: roles (meta/in/out)
- Inputs reported as decimal integers
- Outputs reported as uppercase hex without "0x" (full 8 hex digits)
- Explicitly closes output file
- Exercises heaviside branches (<= -0.0001, between, > 0.0001)
- Exercises edge conditions in mgvf_kernel
- All allocations freed
- Adds targeted kernel invocations to improve coverage
*/

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

/* Parameters (kept small for reasonably fast simulation) */
#define GRID_ROWS 8
#define GRID_COLS 8
#define ITERATION 4
#define MU 0.5f
#define LAMBDA (8.0f * MU + 1.0f)
#define MU_O_LAMBDA  (MU / LAMBDA)
#define ONE_O_LAMBDA (1.0f / LAMBDA)
typedef float TYPE;

/* DUT functions (from provided code) */
float heaviside(float x) {
    float out = 0.0f;
    if (x > -0.0001f) out = 0.5f;
    if (x >  0.0001f) out = 1.0f;
    return out;
}

float mgvf_kernel(float result[GRID_ROWS * GRID_COLS], float imgvf[GRID_ROWS * GRID_COLS], float I[GRID_ROWS * GRID_COLS])
{
