// hls.cpp
// HLS implementation of the MGvF algorithm.
// Top-level function is exported as "mgvf" (extern "C") to match the C testbench.
// Adjusted grid/iteration/constants to match the testbench (GRID_ROWS=8, GRID_COLS=8, ITERATION=4).
// Comments in English.

#include <math.h>

#define GRID_ROWS 8
#define GRID_COLS 8
#define ITERATION 4

// Use the same MU/LAMBDA relationship as the testbench:
// MU = 0.5, LAMBDA = 8*MU + 1 = 5.0
#define MU 0.5f
#define LAMBDA (8.0f * MU + 1.0f)
#define MU_O_LAMBDA (MU / LAMBDA)
#define ONE_O_LAMBDA (1.0f / LAMBDA)

extern "C" {

// Heaviside-like function used by algorithm
static float heaviside(float x) {
    float out = 0.0f;
    if (x > -0.0001f) out = 0.5f;
    if (x >  0.0001f) out = 1.0f;
    return out;
}

// Single iteration over the full grid. Returns average absolute difference.
static float lc_mgvf_iter(float result[GRID_ROWS * GRID_COLS],
                          float imgvf[GRID_ROWS * GRID_COLS],
                          float I[GRID_ROWS * GRID_COLS]) {
    float total_diff = 0.0f;

    for (int i = 0; i < GRID_ROWS; i++) {
        for (int j = 0; j < GRID_COLS; j++) {
            float old_val = imgvf[i * GRID_COLS + j];

            float UL = ((i == 0 || j == 0) ? 0.0f : (imgvf[(i - 1) * GRID_COLS + (j - 1)] - old_val));
            float U  = ((i == 0) ? 0.0f : (imgvf[(i - 1) * GRID_COLS + j] - old_val));
            float UR = ((i == 0 || j == GRID_COLS - 1) ? 0.0f : (imgvf[(i - 1) * GRID_COLS + (j + 1)] - old_val));

            float L  = ((j == 0) ? 0.0f : (imgvf[i * GRID_COLS + (j - 1)] - old_val));
            float R  = ((j == GRID_COLS - 1) ? 0.0f : (imgvf[i * GRID_COLS + (j + 1)] - old_val));

            float DL = ((i == GRID_ROWS - 1 || j == 0) ? 0.0f : (imgvf[(i + 1) * GRID_COLS + (j - 1)] - old_val));
            float D  = ((i == GRID_ROWS - 1) ? 0.0f : (imgvf[(i + 1) * GRID_COLS + j] - old_val));
            float DR = ((i == GRID_ROWS - 1 || j == GRID_COLS - 1) ? 0.0f : (imgvf[(i + 1) * GRID_COLS + (j + 1)] - old_val));

            float vHe = old_val + MU_O_LAMBDA * (heaviside(UL) * UL + heaviside(U) * U + heaviside(UR) * UR
                                                + heaviside(L) * L + heaviside(R) * R
                                                + heaviside(DL) * DL + heaviside(D) * D + heaviside(DR) * DR);

            float vI = I[i * GRID_COLS + j];
            float new_val = vHe - (ONE_O_LAMBDA * vI * (vHe - vI));
            result[i * GRID_COLS + j] = new_val;

            total_diff += fabsf(new_val - old_val);
        }
    }

    return (total_diff / (float)(GRID_ROWS * GRID_COLS));
}

// Internal implementation that runs ITERATION iterations.
// This function is internal; the HLS top-level wrapper 'mgvf' calls it.
static void lc_mgvf(float result[GRID_ROWS * GRID_COLS],
                    float imgvf[GRID_ROWS * GRID_COLS],
                    float I[GRID_ROWS * GRID_COLS]) {
    float diff = 1.0f;
    // We perform iteration pairs like original code (two calls per loop).
    for (int i = 0; i < ITERATION / 2; i++) {
        diff = lc_mgvf_iter(result, imgvf, I);
        diff = lc_mgvf_iter(imgvf, result, I);
    }
    (void)diff;
}

// Top-level HLS function exported with C linkage and having HLS INTERFACE pragmas.
// Name must be 'mgvf' to match the testbench.
void mgvf(float result[GRID_ROWS * GRID_COLS],
          float imgvf[GRID_ROWS * GRID_COLS],
          float I[GRID_ROWS * GRID_COLS]) {
    #pragma HLS INTERFACE m_axi port=result offset=slave bundle=result1
    #pragma HLS INTERFACE m_axi port=imgvf offset=slave bundle=imgvf1
    #pragma HLS INTERFACE m_axi port=I offset=slave bundle=I1

    #pragma HLS INTERFACE s_axilite port=result bundle=control
    #pragma HLS INTERFACE s_axilite port=imgvf bundle=control
    #pragma HLS INTERFACE s_axilite port=I bundle=control
    #pragma HLS INTERFACE s_axilite port=return bundle=control

    // Call internal implementation
    lc_mgvf(result, imgvf, I);
}

} // extern "C"

