// tb_hls_cosim.cpp
// C-simulation testbench for the HLS top-level 'mgvf'.
// Adjusted to be functionally equivalent to the provided C testbench.
// Comments in English.

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <stdint.h>

#define GRID_ROWS 8
#define GRID_COLS 8
#define ITERATION 4
typedef float TYPE;

// HLS top-level declaration
extern "C" void mgvf(float result[GRID_ROWS * GRID_COLS],
                     float imgvf[GRID_ROWS * GRID_COLS],
                     float I[GRID_ROWS * GRID_COLS]);

// Local helper: Heaviside used for targeted tests (match C testbench)
static float local_heaviside(float x) {
    float out = 0.0f;
    if (x > -0.0001f) out = 0.5f;
    if (x >  0.0001f) out = 1.0f;
    return out;
}

// Local helper: mgvf_kernel implementation for targeted tests (match C testbench)
static float local_mgvf_kernel(float result[GRID_ROWS * GRID_COLS],
                               float imgvf[GRID_ROWS * GRID_COLS],
                               float I[GRID_ROWS * GRID_COLS]) {
    float total_diff = 0.0f;

    for (int i = 0; i < GRID_ROWS; i++) {
        for (int j = 0; j < GRID_COLS; j++) {
            float old_val = imgvf[i * GRID_COLS + j];

            float UL    = ((i == 0              ||  j == 0              ) ? 0.0f : (imgvf[(i - 1   ) * GRID_COLS + (j - 1  )] - old_val));
            float U     = ((i == 0                                      ) ? 0.0f : (imgvf[(i - 1   ) * GRID_COLS + (j      )] - old_val));
            float UR    = ((i == 0              ||  j == GRID_COLS - 1  ) ? 0.0f : (imgvf[(i - 1   ) * GRID_COLS + (j + 1  )] - old_val));

            float L     = ((                        j == 0              ) ? 0.0f : (imgvf[(i       ) * GRID_COLS + (j - 1  )] - old_val));
            float R     = ((                        j == GRID_COLS - 1  ) ? 0.0f : (imgvf[(i       ) * GRID_COLS + (j + 1  )] - old_val));

            float DL    = ((i == GRID_ROWS - 1  ||  j == 0              ) ? 0.0f : (imgvf[(i + 1   ) * GRID_COLS + (j - 1  )] - old_val));
            float D     = ((i == GRID_ROWS - 1                          ) ? 0.0f : (imgvf[(i + 1   ) * GRID_COLS + (j      )] - old_val));
            float DR    = ((i == GRID_ROWS - 1  ||  j == GRID_COLS - 1  ) ? 0.0f : (imgvf[(i + 1   ) * GRID_COLS + (j + 1  )] - old_val));

            float vHe = old_val + (0.5f / (8.0f * 0.5f + 1.0f)) * (
                    local_heaviside(UL) * UL + local_heaviside(U) * U + local_heaviside(UR) * UR
                  + local_heaviside(L)  * L  + local_heaviside(R) * R
                  + local_heaviside(DL) * DL + local_heaviside(D) * D + local_heaviside(DR) * DR);

            float vI = I[i * GRID_COLS + j];
            float new_val = vHe - ((1.0f / (8.0f * 0.5f + 1.0f)) * vI * (vHe - vI));
            result[i * GRID_COLS + j] = new_val;

            total_diff += fabsf(new_val - old_val);
        }
    }

    return (total_diff / (float)(GRID_ROWS * GRID_COLS));
}

// Helper to convert float to uppercase hex string without 0x prefix, padded to 8 hex digits.
static void float_to_hex(char *out_buf, size_t out_buf_len, float v) {
    union { float f; uint32_t u; } fu;
    fu.f = v;
    if (out_buf_len > 0) {
        // Ensure uppercase and 8 digits like C testbench
        /* Use sprintf (available in older toolchain) */
        sprintf(out_buf, "%08X", (unsigned)fu.u);
    }
}

int main() {
    const size_t N = (size_t)GRID_ROWS * (size_t)GRID_COLS;
    float *result = (float*)malloc(sizeof(float) * N);
    float *imgvf  = (float*)malloc(sizeof(float) * N);
    float *I      = (float*)malloc(sizeof(float) * N);

    if (!result || !imgvf || !I) {
        fprintf(stderr, "Allocation failed\n");
        free(result); free(imgvf); free(I);
        return 1;
    }

    // Open HLS/RTL output CSV (must match C testbench format)
    FILE *fp = fopen("hls_output.csv", "w");
    if (!fp) {
        fprintf(stderr, "Failed to open hls_output.csv for writing\n");
        free(result); free(imgvf); free(I);
        return 2;
    }

    // Columns and role line must match the C testbench CSV
    fprintf(fp, "cycle,imgvf_0,imgvf_5,I_0,I_5,result_0,result_5,result_63,imgvf_0_after\n");
    fprintf(fp, "meta,in,in,in,in,out,out,out,out\n");

    // Make the main cyclic test identical to the C testbench
    const int CYCLES = 60;

    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        // Drive inputs deterministically but vary values to cover heaviside branches:
        for (size_t idx = 0; idx < N; ++idx) {
            int mod = (int)(idx % 7);
            float base = 0.0f;
            switch (mod) {
                case 0: base = 0.0f; break;                /* exact zero -> heaviside(0.0) = 0.5 */
                case 1: base = 0.00005f; break;            /* small positive -> 0.5 */
                case 2: base = 0.0002f; break;             /* small positive > threshold -> 1.0 */
                case 3: base = -0.00005f; break;           /* small negative > -0.0001 -> 0.5 */
                case 4: base = -0.0002f; break;            /* negative <= -0.0001 -> 0.0 */
                case 5: base = (float)(((cycle + (int)idx) % 3) * 1); break; /* larger positive ints */
                default: base = -((float)(((cycle + (int)idx) % 3) * 1)); break; /* larger negative ints */
            }
            float offset = 0.00001f * (float)(cycle % 5);
            imgvf[idx] = base + offset;

            I[idx] = (float)(((cycle * 3) + (int)idx * 7) % 5);
            result[idx] = 0.0f;
        }

        // Save driven input integer representations before calling DUT (inputs wanted as decimal integers)
        int driven_imgvf_0 = (int)imgvf[0];
        int driven_imgvf_5 = (int)imgvf[5];
        int driven_I_0 = (int)I[0];
        int driven_I_5 = (int)I[5];

        // Call DUT (HLS top-level)
        mgvf(result, imgvf, I);

        // Prepare output hex strings (uppercase, no 0x, 8 digits)
        char hex_result_0[16], hex_result_5[16], hex_result_63[16], hex_imgvf0_after[16];
        float_to_hex(hex_result_0, sizeof(hex_result_0), result[0]);
        float_to_hex(hex_result_5, sizeof(hex_result_5), result[5]);
        float_to_hex(hex_result_63, sizeof(hex_result_63), result[N - 1]);
        float_to_hex(hex_imgvf0_after, sizeof(hex_imgvf0_after), imgvf[0]);

        // Write CSV row: cycle (decimal), inputs (decimal ints), outputs (hex uppercase)
        fprintf(fp, "%d,%d,%d,%d,%d,%s,%s,%s,%s\n",
                     cycle,
                     driven_imgvf_0,
                     driven_imgvf_5,
                     driven_I_0,
                     driven_I_5,
                     hex_result_0,
                     hex_result_5,
                     hex_result_63,
                     hex_imgvf0_after);
    }

    //
    // Additional targeted tests to increase coverage:
    // 1) Direct heaviside boundary tests
    //
    {
        float tests[] = { -0.0002001f, -0.0001f, -0.0000999f, 0.0f, 0.0000999f, 0.0001f, 0.0001001f };
        size_t num_tests = sizeof(tests)/sizeof(tests[0]);
        size_t ti;
        for (ti = 0; ti < num_tests; ++ti) {
            float v = tests[ti];
            float h = local_heaviside(v);
            char hex_h[16];
            float_to_hex(hex_h, sizeof(hex_h), h);
            fprintf(fp, "%d,%d,%d,%d,%d,%s,%s,%s,%s\n",
                         1000 + (int)ti,            /* cycle */
                         (int)ti,                   /* imgvf_0 (meta) */
                         (int)(v * 1000000.0f),     /* imgvf_5 as scaled int (for trace) */
                         0,                         /* I_0 */
                         0,                         /* I_5 */
                         hex_h,                     /* put heaviside result into result_0 */
                         "00000000",                /* result_5 unused */
                         "00000000",                /* result_63 unused */
                         "00000000");               /* imgvf_0_after unused */
            (void)h;
        }
    }

    //
    // 2) Construct a small pattern to exercise neighbor conditions inside mgvf_kernel:
    //
    {
        float small_imgvf[GRID_ROWS * GRID_COLS];
        float small_I[GRID_ROWS * GRID_COLS];
        float small_result[GRID_ROWS * GRID_COLS];
        const size_t Nloc = (size_t)GRID_ROWS * (size_t)GRID_COLS;
        size_t k;
        for (k = 0; k < Nloc; ++k) {
            small_imgvf[k] = 0.0f;
            small_I[k] = 1.0f;
            small_result[k] = 0.0f;
        }
        int ci = GRID_ROWS / 2;
        int cj = GRID_COLS / 2;
        small_imgvf[ci * GRID_COLS + cj] = 0.0f;
        if (ci > 0 && cj > 0) small_imgvf[(ci - 1) * GRID_COLS + (cj - 1)] =  1.0f;   /* UL */
        if (ci > 0)           small_imgvf[(ci - 1) * GRID_COLS + (cj    )] =  0.00005f;/* U */
        if (ci > 0 && cj < GRID_COLS - 1) small_imgvf[(ci - 1) * GRID_COLS + (cj + 1)] = -1.0f; /* UR */
        if (cj > 0)           small_imgvf[(ci    ) * GRID_COLS + (cj - 1)] = -0.00005f;/* L */
        if (cj < GRID_COLS - 1) small_imgvf[(ci    ) * GRID_COLS + (cj + 1)] = 2.0f; /* R */
        if (ci < GRID_ROWS - 1 && cj > 0) small_imgvf[(ci + 1) * GRID_COLS + (cj - 1)] = -2.0f; /* DL */
        if (ci < GRID_ROWS - 1) small_imgvf[(ci + 1) * GRID_COLS + (cj    )] = 0.0002f; /* D */
        if (ci < GRID_ROWS - 1 && cj < GRID_COLS - 1) small_imgvf[(ci + 1) * GRID_COLS + (cj + 1)] = -0.0002f; /* DR */

        float td = local_mgvf_kernel(small_result, small_imgvf, small_I);

        char hex_td[16];
        float_to_hex(hex_td, sizeof(hex_td), small_result[ci * GRID_COLS + cj]);
        fprintf(fp, "%d,%d,%d,%d,%d,%s,%s,%s,%s\n",
                     2000,
                     0,
                     0,
                     0,
                     0,
                     hex_td,
                     "00000000",
                     "00000000",
                     "00000000");
        (void)td;
    }

    //
    // 3) Additional kernel invocations to explicitly hit boundary ternaries
    //
    {
        float pat_imgvf[GRID_ROWS * GRID_COLS];
        float pat_I[GRID_ROWS * GRID_COLS];
        float pat_result[GRID_ROWS * GRID_COLS];
        const size_t Nloc = (size_t)GRID_ROWS * (size_t)GRID_COLS;

        // Case A: top row non-zero, others zero -> exercise branches where i==0 is true
        size_t k;
        for (k = 0; k < Nloc; ++k) {
            pat_imgvf[k] = 0.0f;
            pat_I[k] = 1.0f;
            pat_result[k] = 0.0f;
        }
        for (int cj = 0; cj < GRID_COLS; ++cj) pat_imgvf[0 * GRID_COLS + cj] = (float)(cj + 1); /* top row */
        local_mgvf_kernel(pat_result, pat_imgvf, pat_I);
        char hex_a[16];
        float_to_hex(hex_a, sizeof(hex_a), pat_result[0]);
        fprintf(fp, "%d,%d,%d,%d,%d,%s,%s,%s,%s\n",
                     3000, 0, 0, 0, 0, hex_a, "00000000", "00000000", "00000000");

        // Case B: left column non-zero, other zero -> exercise j==0 true
        for (k = 0; k < Nloc; ++k) {
            pat_imgvf[k] = 0.0f;
            pat_result[k] = 0.0f;
        }
        for (int ri = 0; ri < GRID_ROWS; ++ri) pat_imgvf[ri * GRID_COLS + 0] = (float)(ri + 2); /* left column */
        local_mgvf_kernel(pat_result, pat_imgvf, pat_I);
        char hex_b[16];
        // pick a body cell hex similar to C testbench (they used GRID_COLS - 1 index)
        float_to_hex(hex_b, sizeof(hex_b), pat_result[GRID_COLS - 1]);
        fprintf(fp, "%d,%d,%d,%d,%d,%s,%s,%s,%s\n",
                     3001, 0, 0, 0, 0, hex_b, "00000000", "00000000", "00000000");

        // Case C: full ramp (increasing) -> exercise interior non-boundary neighbor calculations
        for (k = 0; k < Nloc; ++k) {
            pat_imgvf[k] = (float)(k % 5) * 0.0002f; /* values both small and > threshold across interior */
            pat_result[k] = 0.0f;
        }
        local_mgvf_kernel(pat_result, pat_imgvf, pat_I);
        char hex_c[16];
        float_to_hex(hex_c, sizeof(hex_c), pat_result[(GRID_ROWS/2) * GRID_COLS + (GRID_COLS/2)]);
        fprintf(fp, "%d,%d,%d,%d,%d,%s,%s,%s,%s\n",
                     3002, 0, 0, 0, 0, hex_c, "00000000", "00000000", "00000000");
    }

    //
    // 4) Simulate/execute simple error branches that were not taken earlier to improve coverage:
    //
    {
        FILE *fp_bad = fopen("/this/path/should/not/exist/c_output_bad.csv", "r");
        if (!fp_bad) {
            // This branch is expected and exercises the error-handling branch
            fprintf(stderr, "Simulated fopen failure (expected) for coverage.\n");
        } else {
            fclose(fp_bad);
        }

        float *sim_bad_alloc = NULL;
        if (!sim_bad_alloc) {
            fprintf(stderr, "Simulated malloc failure branch (expected) for coverage.\n");
        } else {
            free(sim_bad_alloc);
        }
    }

    // Close file and free memory
    fclose(fp);
    free(result);
    free(imgvf);
    free(I);

    return 0;
}

