// hls.cpp
// HLS top-level FIR implementation compatible with the testbench.
// - Uses a static delay line to retain state across function calls.
// - Matches the testbench signature: extern "C" void fir(int input, int *output, int taps[NUM_TAPS])
// - Keeps pragmas for Vivado HLS interfaces.
// - Comments in English.

#define NUM_TAPS 5

typedef int DTYPE;

extern "C" {
void fir(int input, int *output, const int taps[NUM_TAPS]) {
#pragma HLS INTERFACE s_axilite port=input bundle=control
#pragma HLS INTERFACE s_axilite port=output bundle=control
#pragma HLS INTERFACE m_axi     port=taps   offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Static delay line preserves filter state across consecutive calls (cycles)
    static DTYPE delay_line[NUM_TAPS] = {0};

    // Shift delay line
    for (int i = NUM_TAPS - 1; i > 0; --i) {
#pragma HLS UNROLL
        delay_line[i] = delay_line[i - 1];
    }
    delay_line[0] = input;

    // FIR multiply-accumulate
    DTYPE result = 0;
    for (int i = 0; i < NUM_TAPS; ++i) {
#pragma HLS PIPELINE
        result += delay_line[i] * taps[i];
    }

    *output = result;
}
}

