#include <stdint.h>

#define INPUT_SYMBOL_SIZE 256
#define SYMBOL_BITS 32
#define RADIX 16
#define BITS_PER_LOOP 4

typedef struct {
    uint32_t frequency;
    uint32_t symbol;
} Symbol;

typedef uint8_t Digit;

extern "C" {
void huffman_sort(
    Symbol in[INPUT_SYMBOL_SIZE],
    int num_symbols,
    Symbol out[INPUT_SYMBOL_SIZE]) {

#pragma HLS INTERFACE m_axi port=in offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=out offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=in bundle=control
#pragma HLS INTERFACE s_axilite port=out bundle=control
#pragma HLS INTERFACE s_axilite port=num_symbols bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    Symbol previous_sorting[INPUT_SYMBOL_SIZE];
    Symbol sorting[INPUT_SYMBOL_SIZE];
#pragma HLS array_partition variable=previous_sorting block factor=32 dim=1

    uint32_t digit_histogram[RADIX];
    uint32_t digit_location[RADIX];
    Digit current_digit[INPUT_SYMBOL_SIZE];

    // Clamp num_symbols to valid range
    int n = num_symbols;
    if (n < 0) n = 0;
    if (n > INPUT_SYMBOL_SIZE) n = INPUT_SYMBOL_SIZE;

copy_in_to_sorting:
    for (int j = 0; j < n; j++) {
#pragma HLS pipeline II=1
        sorting[j] = in[j];
    }

radix_sort:
    for (int shift = 0; shift < SYMBOL_BITS; shift += BITS_PER_LOOP) {
    init_histogram:
        for (int i = 0; i < RADIX; i++) {
#pragma HLS unroll
            digit_histogram[i] = 0;
        }

    compute_histogram:
        for (int j = 0; j < n; j++) {
#pragma HLS pipeline II=1
            Digit digit = (Digit)((sorting[j].frequency >> shift) & (RADIX - 1));
            current_digit[j] = digit;
            digit_histogram[digit]++;
            previous_sorting[j] = sorting[j];
        }

        digit_location[0] = 0;
    find_digit_location:
        for (int i = 1; i < RADIX; i++) {
#pragma HLS unroll
            digit_location[i] = digit_location[i - 1] + digit_histogram[i - 1];
        }

    re_sort:
        for (int j = 0; j < n; j++) {
#pragma HLS pipeline II=1
            Digit digit = current_digit[j];
            sorting[digit_location[digit]] = previous_sorting[j];
            out[digit_location[digit]] = previous_sorting[j];
            digit_location[digit]++;
        }
    }
}
}

