/* Testbench generating deterministic frames and writing c_output.csv
   CSV format:
   - First row: header. First column "cycle", then inputs driven by testbench, then sampled outputs.
   - Second row: roles: meta/in/out
   - cycle starts at 0 and increments each iteration.
   - reset (named "reset") active for cycles 0 and 1 (reset=1, en=0). From cycle 2 onward reset=0 en=1.
   - Outputs printed in HEX uppercase without 0x, inputs in decimal.
*/

int main() {
    const int NUM_CYCLES = 32; /* between 20 and 50 */
    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    /* Selected output sample positions (row,col):
       corners: (0,0),(0,19),(19,0),(19,19)
       interior: (1,1),(1,10),(10,1),(10,10),(9,9)
       For each pixel we record R,G,B separately.
    */
    const int sample_count = 9;
    const int sample_pos[sample_count][2] = {
        {0,0}, {0,19}, {19,0}, {19,19},
        {1,1}, {1,10}, {10,1}, {10,10}, {9,9}
    };

    /* Write CSV header */
    std::fprintf(f, "cycle,reset,en");
    for (int s = 0; s < sample_count; s++) {
        int r = sample_pos[s][0];
        int c = sample_pos[s][1];
        std::fprintf(f, ",pixel_out[%d][%d].R,pixel_out[%d][%d].G,pixel_out[%d][%d].B", r, c, r, c, r, c);
    }
    std::fprintf(f, "\n");

    /* Write roles line */
    std::fprintf(f, "meta,in,in");
    for (int s = 0; s < sample_count; s++) {
        std::fprintf(f, ",out,out,out");
    }
    std::fprintf(f, "\n");

    static rgb_pixel pixel_in[MAX_HEIGHT][MAX_WIDTH];
    static rgb_pixel pixel_out[MAX_HEIGHT][MAX_WIDTH];

    /* Deterministic test vectors per cycle:
       - cycle 0,1: reset=1 en=0 -> pixel_in all zeros
       - cycle >=2 and en==1: pixel_in varies with a simple formula depending on cycle, row, col
         pattern ensures variety but is deterministic and bounded (masked to 0xFF)
    */

    for (int cycle = 0; cycle < NUM_CYCLES; cycle++) {
        int reset = (cycle < 2) ? 1 : 0;
        int en = (cycle < 2) ? 0 : 1;

        /* Prepare pixel_in */
        for (int i = 0; i < MAX_HEIGHT; i++) {
            for (int j = 0; j < MAX_WIDTH; j++) {
                if (reset) {
                    pixel_in[i][j].R = 0;
                    pixel_in[i][j].G = 0;
                    pixel_in[i][j].B = 0;
                } else if (!en) {
                    /* If disabled but not reset (not used here), keep zeros */
                    pixel_in[i][j].R = 0;
                    pixel_in[i][j].G = 0;
                    pixel_in[i][j].B = 0;
                } else {
                    /* Deterministic varying pattern:
                       R = (row * 10 + col + cycle * 3) & 0xFF
                       G = (row * 5 + col * 2 + cycle * 5) & 0xFF
                       B = (row + col * 3 + cycle * 7) & 0xFF
                    */
                    pixel_in[i][j].R = (unsigned char)((i * 10 + j + cycle * 3) & 0xFF);
                    pixel_in[i][j].G = (unsigned char)((i * 5 + j * 2 + cycle * 5) & 0xFF);
                    pixel_in[i][j].B = (unsigned char)((i + j * 3 + cycle * 7) & 0xFF);
                }
                /* initialize outputs to a known state */
                pixel_out[i][j].R = pixel_out[i][j].G = pixel_out[i][j].B = 0;
            }
        }

        /* Call DUT once per cycle */
        video_2dfilter(pixel_in, pixel_out);

        /* Write CSV line: cycle (decimal), reset (decimal), en (decimal), then sampled outputs in HEX uppercase without 0x */
        std::fprintf(f, "%d,%d,%d", cycle, reset, en);
        for (int s = 0; s < sample_count; s++) {
            int r = sample_pos[s][0];
            int c = sample_pos[s][1];
            unsigned int vR = (unsigned int)pixel_out[r][c].R;
            unsigned int vG = (unsigned int)pixel_out[r][c].G;
            unsigned int vB = (unsigned int)pixel_out[r][c].B;
            /* Print without 0x, uppercase, no fixed width */
            std::fprintf(f, ",%X,%X,%X", vR, vG, vB);
        }
        std::fprintf(f, "\n");
    }

    std::fclose(f);
    return 0;
}

