void covariance(int m,int n,double float_n,double data[M][N],double cov[N][N],double mean[N])
{
  int i;
  int j;
  int k;

  for (j = 0; j < N; j++) {
    mean[j] = 0.0;
    for (i = 0; i < M; i++) {
      mean[j] += data[i][j];
    }
    mean[j] /= float_n;
  }

  for (i = 0; i < M; i++) {
    for (j = 0; j < N; j++) {
      data[i][j] -= mean[j];
    }
  }

  for (i = 0; i < N; i++) {
    for (j = i; j < N; j++) {
      cov[i][j] = 0.0;
      for (k = 0; k < M; k++) {
        cov[i][j] += data[k][i] * data[k][j];
      }
      cov[i][j] /= float_n - 1.0;
      cov[j][i] = cov[i][j];
