// hls.cpp
// HLS top function for covariance. Top-level uses extern "C" so
// the linkage matches the testbench. The array dimensions used
// here must match those in the testbench (M=4, N=3).
// The implementation uses the runtime parameters m and n to
// iterate only over the valid portion of the arrays.
// Comments in English as requested.

#include <stddef.h>

#define M 4
#define N 3

extern "C" {
void covariance(int m, int n, double float_n, double data[M][N], double cov[N][N], double mean[N]) {
#pragma HLS INTERFACE m_axi port=data offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=cov offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=mean offset=slave bundle=gmem2
#pragma HLS INTERFACE s_axilite port=m bundle=control
#pragma HLS INTERFACE s_axilite port=n bundle=control
#pragma HLS INTERFACE s_axilite port=float_n bundle=control
#pragma HLS INTERFACE s_axilite port=data bundle=control
#pragma HLS INTERFACE s_axilite port=cov bundle=control
#pragma HLS INTERFACE s_axilite port=mean bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int i, j, k;

    // Compute mean over m rows and n columns
    for (j = 0; j < n; j++) {
        mean[j] = 0.0;
        for (i = 0; i < m; i++) {
            mean[j] += data[i][j];
        }
        // avoid division by zero; float_n is provided by testbench
        if (float_n != 0.0) {
            mean[j] /= float_n;
        } else {
            mean[j] = 0.0;
        }
    }

    // Subtract mean from data (only for valid m x n region)
    for (i = 0; i < m; i++) {
        for (j = 0; j < n; j++) {
            data[i][j] -= mean[j];
        }
    }

    // Compute covariance matrix (n x n), only upper triangle then mirror
    for (i = 0; i < n; i++) {
        for (j = i; j < n; j++) {
            double acc = 0.0;
            for (k = 0; k < m; k++) {
                acc += data[k][i] * data[k][j];
            }
            if (float_n - 1.0 != 0.0) {
                cov[i][j] = acc / (float_n - 1.0);
            } else {
                cov[i][j] = 0.0;
            }
            cov[j][i] = cov[i][j];
        }
    }
}
}

