            for (j = 0; j < N; ++j) {
                unsigned long long u = 0;
                memcpy(&u, &mean[j], sizeof(u));
                fprintf(f, ",%llX", (unsigned long long)u);
            }

            fprintf(f, "\n");
        }
    }

    fclose(f);
    return 0;
}

