void merge(TYPE a[SIZE], int start, int m, int stop){
    TYPE temp[SIZE];
    int i, j, k;

    for(i = start; i <= m; i++){
        temp[i] = a[i];
    }

    for(j = m + 1; j <= stop; j++){
        temp[m + 1 + stop - j] = a[j];
    }

    i = start;
    j = stop;

    for(k = start; k <= stop; k++){
        TYPE tmp_j = temp[j];
        TYPE tmp_i = temp[i];
        if(tmp_j < tmp_i) {
            a[k] = tmp_j;
            j--;
        } else {
            a[k] = tmp_i;
            i++;
        }
    }
}

void ms_mergesort(TYPE a[SIZE]) {
    int start, stop;
    int i, m, from, mid, to;

    start = 0;
    stop = SIZE - 1;

    for(m = 1; m <= (stop - start); m += m) {
        for(i = start; i <= stop; i += m + m) {
            from = i;
            mid = i + m - 1;
            to = i + m + m - 1;
            if(mid > stop) break;
            if(to < stop){
                merge(a, from, mid, to);
            }
            else{
                merge(a, from, mid, stop);
            }
        }
    }
}

int main() {
    struct bench_args_t args;
    int i;
    srand(12345);

    for(i = 0; i < SIZE; i++) {
        args.a[i] = (TYPE)(rand() % 100000);
    }

    ms_mergesort(args.a);

    int sorted = 1;
    for(i = 1; i < SIZE; i++) {
        if(args.a[i-1] > args.a[i]) { sorted = 0; break; }
    }

    if(sorted) {
        printf("Array sorted successfully.\n");
    } else {
        printf("Array NOT sorted.\n");
    }

    printf("First 16 elements:\n");
    for(i = 0; i < 16 && i < SIZE; i++) {
        printf("%d ", (int)args.a[i]);
    }
    printf("\n");

    return sorted ? 0 : 1;
}

