// hls.cpp
// Vivado HLS top-level implementation of a mergesort variant.
// Written to be compatible with Vivado HLS (C++98 environment).
// Internal helpers use C++ linkage; the top-level function uses C linkage.

#include <stdint.h>

#define SIZE 2048
#define TYPE int32_t

// Internal helper functions (C++ linkage)
static void merge(TYPE *a, int start, int m, int stop) {
    // Temporary buffer used for merge; partitioned for HLS performance
    TYPE temp[SIZE];
#pragma HLS array_partition variable=temp block factor=8 dim=1
    int i, j, k;

    // Copy left side in order
    for (i = start; i <= m; i++) {
        temp[i] = a[i];
    }

    // Copy right side in reversed order to simplify merging
    for (j = m + 1; j <= stop; j++) {
        temp[m + 1 + stop - j] = a[j];
    }

    i = start;
    j = stop;

    // Merge back to original array
    for (k = start; k <= stop; k++) {
        TYPE tmp_j = temp[j];
        TYPE tmp_i = temp[i];
        if (tmp_j < tmp_i) {
            a[k] = tmp_j;
            j--;
        } else {
            a[k] = tmp_i;
            i++;
        }
    }
}

static void sort(TYPE *a) {
    int start = 0;
    int stop = SIZE - 1;
    int i, m, from, mid, to;

    // Iterative bottom-up mergesort: m is the current run length
    for (m = 1; m < (stop - start + 1); m <<= 1) {
        for (i = start; i <= stop; i += (m << 1)) {
            from = i;
            mid = i + m - 1;
            to = i + (m << 1) - 1;
            if (to <= stop) {
                merge(a, from, mid, to);
            } else {
                merge(a, from, mid, stop);
            }
        }
    }
}

// Top-level HLS function with C linkage required by Vivado HLS/Cosim
extern "C" {

void ms_mergesort(TYPE *a) {
#pragma HLS INTERFACE m_axi port=a offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=a bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control
    sort(a);
}

} // extern "C"

