#include <cstdio>
#include <cstdint>
#include <cstdlib>
#include <cstring>
#include <cmath>

// Define data_t consistent with integer inputs/outputs to match CSV hex output requirement.
using data_t = int32_t;

// Fixed-point parameters (match Verilog)
constexpr int WIDTH = 32;
constexpr int FRACT = 16; // Q16.16

// Software model of DUT that mirrors Verilog fixed-point behavior and tanh approximation
void top(data_t DRAM_x[64], data_t DRAM_A[64*128], data_t DRAM_B[128*64],
         data_t DRAM_y[64], data_t DRAM_bias[1], data_t DRAM_result[1]) {
    // Use wide integer types for intermediate accumulations. __int128 is used to emulate wide ACC_W.
    __int128 Ax[128];
    for (int j = 0; j < 128; ++j) Ax[j] = 0;

    // Ax[j] += A[i*128 + j] * x[i]
    for (int i = 0; i < 64; ++i) {
        for (int j = 0; j < 128; ++j) {
            Ax[j] += (__int128)DRAM_A[i*128 + j] * (__int128)DRAM_x[i];
        }
    }

    // BAx accumulation with wide type
    __int128 BAx[64];
    for (int j = 0; j < 64; ++j) BAx[j] = 0;

    for (int i = 0; i < 128; ++i) {
        for (int j = 0; j < 64; ++j) {
            BAx[j] += (__int128)DRAM_B[i*64 + j] * Ax[i];
        }
    }

    // Fixed-point tanh approximation (match Verilog implementation)
    auto tanh_approx = [](const __int128 x_fp) -> __int128 {
        // x_fp is Q16.16
        __int128 abs_x = x_fp < 0 ? -x_fp : x_fp;
        // saturate if |x| >= 2.0  (2 << FRACT)
        if (abs_x >= ( (__int128)2 << FRACT )) {
            return x_fp < 0 ? -((__int128)1 << FRACT) : ((__int128)1 << FRACT);
        } else {
            // Compute x2 = (x*x) >>> FRACT to keep Q16.16
            __int128 tmp = x_fp * x_fp; // wide
            __int128 x2 = tmp >> FRACT; // Q16.16

            // num = (x * (27 + x2)) >>> FRACT
            __int128 const27 = (__int128)27 << FRACT; // 27 in Q16.16
            __int128 num = (x_fp * (const27 + x2)) >> FRACT;

            // den = 27 + 9*x2  (Q16.16)
            __int128 den = const27 + (__int128)9 * x2;

            if (den == 0) return 0;
            return num / den; // result is Q16.16
        }
    };

    // Sum accumulator in Q16.16
    __int128 sum_acc = 0;

    for (int i = 0; i < 64; ++i) {
        // tmp_int_sum = BAx[i] + DRAM_y[i] + bias
        // BAx is a wide integer (represents integer), y and bias are WIDTH-bit integers.
        __int128 tmp_int_sum = BAx[i]
                             + (__int128)DRAM_y[i]
                             + (__int128)DRAM_bias[0];

        // Convert integer sum to Q16.16
        __int128 val_fp = tmp_int_sum << FRACT;

        // compute tanh approximation in Q16.16
        __int128 tanh_val = tanh_approx(val_fp);

        // accumulate (sum_acc is Q16.16)
        sum_acc += tanh_val;
    }

    // Final result: truncate fractional bits (simple shift right FRACT), then store as 32-bit data_t
    // This matches Verilog: DRAM_result_flat <= sum_acc[ (FRACT + WIDTH - 1) -: WIDTH ];
    data_t result = static_cast<data_t>( (int64_t)(sum_acc >> FRACT) );
    DRAM_result[0] = result;
}

int main() {
    // Number of cycles (rows) in CSV (between 20 and 50)
    const int cycles = 32;

    // Allocate DRAM arrays
    static data_t DRAM_x[64];
    static data_t DRAM_A[64*128];
    static data_t DRAM_B[128*64];
    static data_t DRAM_y[64];
    static data_t DRAM_bias[1];
    static data_t DRAM_result[1];

    // Open CSV file
    FILE* f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // Header row: cycle, then input signal names, then output signal names
    // Column names must match parameter names exactly.
    std::fprintf(f, "cycle,DRAM_x,DRAM_A,DRAM_B,DRAM_y,DRAM_bias,DRAM_result\n");
    // Roles row: meta for cycle, in for inputs, out for outputs
    std::fprintf(f, "meta,in,in,in,in,in,out\n");

    // Deterministic test vectors: for each cycle populate arrays with small integer patterns.
    for (int c = 0; c < cycles; ++c) {
        // Fill DRAM_x: values in range [-5,5]
        for (int i = 0; i < 64; ++i) {
            DRAM_x[i] = static_cast<data_t>(((i * 7 + c * 3) % 11) - 5);
        }

        // Fill DRAM_A: values in range [-3,3]
        for (int i = 0; i < 64; ++i) {
            for (int j = 0; j < 128; ++j) {
