typedef ap_fixed<16,5> data_t;

// Top-level kernel function
extern "C" void top(
    data_t DRAM_x[64],
    data_t DRAM_A[64][128],
    data_t DRAM_B[128][64],
    data_t DRAM_y[64],
    data_t DRAM_bias[1],
    data_t DRAM_result[1]
) {
#pragma HLS interface m_axi port=DRAM_x offset=slave bundle=mem1
#pragma HLS interface m_axi port=DRAM_A offset=slave bundle=mem1
#pragma HLS interface m_axi port=DRAM_B offset=slave bundle=mem1
#pragma HLS interface m_axi port=DRAM_y offset=slave bundle=mem1
#pragma HLS interface m_axi port=DRAM_bias offset=slave bundle=mem1
#pragma HLS interface m_axi port=DRAM_result offset=slave bundle=mem2

#pragma HLS interface s_axilite port=DRAM_x bundle=control
#pragma HLS interface s_axilite port=DRAM_A bundle=control
#pragma HLS interface s_axilite port=DRAM_B bundle=control
#pragma HLS interface s_axilite port=DRAM_y bundle=control
#pragma HLS interface s_axilite port=DRAM_bias bundle=control
#pragma HLS interface s_axilite port=DRAM_result bundle=control
#pragma HLS interface s_axilite port=return bundle=control

    data_t BRAM_x[64];
    data_t BRAM_A[64][128];
    data_t BRAM_B[128][64];
    data_t BRAM_y[64];
    data_t BRAM_bias[1];
    data_t BRAM_result_local[1];
    data_t BRAM_xA[128];
    data_t BRAM_xAB[64];

    // Load data from DRAM to BRAM
    for (int i = 0; i < 64; i++) {
#pragma HLS pipeline II=1
        BRAM_x[i] = DRAM_x[i];
        BRAM_y[i] = DRAM_y[i];
    }
    for (int i = 0; i < 64; i++) {
        for (int j = 0; j < 128; j++) {
#pragma HLS pipeline II=1
            BRAM_A[i][j] = DRAM_A[i][j];
        }
    }
    for (int i = 0; i < 128; i++) {
        for (int j = 0; j < 64; j++) {
#pragma HLS pipeline II=1
            BRAM_B[i][j] = DRAM_B[i][j];
        }
    }
    BRAM_bias[0] = DRAM_bias[0];

#pragma HLS array_partition variable=BRAM_A cyclic factor=8 dim=2
#pragma HLS array_partition variable=BRAM_xA cyclic factor=8 dim=1

    // Compute BRAM_xA = BRAM_A^T * BRAM_x
    for (int j = 0; j < 128; j++) {
#pragma HLS unroll factor=8
        BRAM_xA[j] = 0;
    }
    for (int j = 0; j < 128; j++) {
#pragma HLS unroll factor=8
        for (int i = 0; i < 64; i++) {
#pragma HLS unroll factor=1
            BRAM_xA[j] += BRAM_A[i][j] * BRAM_x[i];
        }
    }

#pragma HLS array_partition variable=BRAM_y cyclic factor=8 dim=1
#pragma HLS array_partition variable=BRAM_B cyclic factor=8 dim=1
#pragma HLS array_partition variable=BRAM_xAB cyclic factor=8 dim=1

    // Compute BRAM_xAB = BRAM_B^T * BRAM_y
    for (int j = 0; j < 64; j++) {
#pragma HLS unroll factor=8
        BRAM_xAB[j] = 0;
    }
    for (int j = 0; j < 64; j++) {
#pragma HLS unroll factor=1
        for (int i = 0; i < 128; i++) {
#pragma HLS unroll factor=8
            BRAM_xAB[j] += BRAM_B[i][j] * BRAM_y[i];
        }
    }

    // Compute dot product of BRAM_xA and BRAM_xAB plus bias
    BRAM_result_local[0] = BRAM_bias[0];
    for (int i = 0; i < 64; i++) {
#pragma HLS unroll factor=1
        BRAM_result_local[0] += BRAM_xA[i] * BRAM_xAB[i];
    }

    // Store result back to DRAM
    DRAM_result[0] = BRAM_result_local[0];
}

