    // out is filled row-major (i * N + j)
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            int idx = i * N + j;
            uint16_t val = 0;
            switch (pid) {
                case 0:
                    // All zeros
                    val = 0;
                    break;
                case 1:
                    // Original example: zero on diag, else (i+j)%10 + 1
                    if (i == j) val = 0;
                    else val = static_cast<uint16_t>((i + j) % 10 + 1);
                    break;
                case 2:
                    // Row-major incremental values 1..25
                    val = static_cast<uint16_t>(i * N + j + 1);
                    break;
                case 3:
                    // Symmetric-ish: distance is abs(i-j) + 1, diagonal 0
                    if (i == j) val = 0;
                    else val = static_cast<uint16_t>(std::abs(i - j) + 1);
                    break;
                case 4:
                    // Larger distances dependent on positions
                    if (i == j) val = 0;
                    else val = static_cast<uint16_t>((i + j) * 10 + 7);
                    break;
                case 5:
                    // A pattern that favors a particular route: low costs along row 0
                    if (i == j) val = 0;
                    else if (i == 0 || j == 0) val = 1; // cheap to/from node 0
                    else val = static_cast<uint16_t>(5 + ((i * j) % 7));
                    break;
                case 6:
                    // Decreasing values further from diagonal
                    if (i == j) val = 0;
                    else val = static_cast<uint16_t>(10 - std::abs(i - j));
                    break;
                default:
                    val = static_cast<uint16_t>(i + j + 1);
                    break;
            }
            out[idx] = val;
        }
    }
