// hls.cpp
//
// Vivado HLS top-level implementation for a small TSP-like kernel.
// This file uses C-style integer headers for compatibility with Vivado HLS 2018.3's toolchain.

#include <stdint.h>

extern "C" {

#define N 5

// Compute factorial of n (small n only). Kept simple for HLS.
static inline unsigned long factorial(int n) {
    unsigned long ret = 1;
    for (int i = 1; i <= n; ++i) {
#pragma HLS pipeline II=1
        ret *= i;
    }
    return ret;
}

static inline unsigned int min_uint(unsigned int a, unsigned int b) {
    return (a < b) ? a : b;
}

// Compute path distance according to permutation 'perm' using 2D distances table.
static void getDistance(const int perm[N], const uint16_t distances[N][N], unsigned int* ret) {
    unsigned int sum = 0;
    for (int i = 0; i < N - 1; ++i) {
#pragma HLS unroll factor=2
        sum += distances[perm[i]][perm[i + 1]];
    }
    *ret = sum;
}

// Convert index i_ into a permutation and compute its distance.
static void compute(unsigned long i_, const uint16_t distances[N][N], unsigned int* result) {
#pragma HLS INLINE
    unsigned long i = i_;
    int perm[N] = {0};
#pragma HLS array_partition variable=perm complete dim=1

    // Generate factorial number system digits
    for (int k = 0; k < N; ++k) {
#pragma HLS pipeline
        perm[k] = i / factorial(N - 1 - k);
        i = i % factorial(N - 1 - k);
    }

    // Convert factorial digits to a permutation (insertion method)
    for (int k = N - 1; k > 0; --k) {
#pragma HLS pipeline
        for (int j = k - 1; j >= 0; --j) {
#pragma HLS pipeline
            if (perm[j] <= perm[k]) {
                perm[k] += 1;
            }
        }
    }

    unsigned int dist = 0;
    getDistance(perm, distances, &dist);
    *result = dist;
}

// Top-level function for HLS. Expects a flattened N*N distances array and returns the shortest found distance.
void tsp(const uint16_t distances[N*N], unsigned int* shortestDistance) {
#pragma HLS INTERFACE m_axi port=distances offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=distances bundle=control
#pragma HLS INTERFACE s_axilite port=shortestDistance bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    uint16_t distances_local[N][N];
#pragma HLS array_partition variable=distances_local complete dim=2

    // Copy input distances to local 2D array
    for (int i = 0; i < N*N; ++i) {
#pragma HLS pipeline
        distances_local[i / N][i % N] = distances[i];
    }

    const unsigned long factorialN = factorial(N - 1);
    const unsigned int UINT_MAX = 0xFFFFFFFF;

    unsigned int candidate0 = UINT_MAX;
    unsigned int candidate1 = UINT_MAX;
    unsigned int candidate2 = UINT_MAX;
    unsigned int candidate3 = UINT_MAX;

    // Process permutations in groups of 4 to exploit parallelism in HLS simulation/synthesis.
    for (unsigned long i_ = 0; i_ < factorialN; i_ += 4) {
#pragma HLS pipeline
        unsigned int c0, c1, c2, c3;
        compute(i_ + 0, distances_local, &c0);
        compute(i_ + 1, distances_local, &c1);
        compute(i_ + 2, distances_local, &c2);
        compute(i_ + 3, distances_local, &c3);
        candidate0 = min_uint(candidate0, c0);
        candidate1 = min_uint(candidate1, c1);
        candidate2 = min_uint(candidate2, c2);
        candidate3 = min_uint(candidate3, c3);
    }

    unsigned int min01 = min_uint(candidate0, candidate1);
    unsigned int min23 = min_uint(candidate2, candidate3);
    *shortestDistance = min_uint(min01, min23);
}

} // extern "C"

