inline long int factorial(const int n) {
    long int ret = 1;
    for (int i = 0; i < n; ++i)
        ret = ret * (i + 1);
    return ret;
}

unsigned int getDistance(const int perm[N], const uint16_t distances[N][N]) {
    unsigned int ret = 0;
    for (int i = 0; i < N - 1; ++i)
        ret += distances[perm[i]][perm[i + 1]];
    return ret;
}

// Reference permutation -> distance computation used by the testbench.
int compute(unsigned long int i_, const uint16_t distances[N][N]) {
    unsigned long int i = i_;
    int perm[N] = {0};

    for (int k = 0; k < N; ++k) {
        perm[k] = i / factorial(N - 1 - k);
        i = i % factorial(N - 1 - k);
    }

    for (char k = N - 1; k > 0; --k)
        for (char j = k - 1; j >= 0; --j)
            perm[k] += (perm[j] <= perm[k]);

    return static_cast<int>(getDistance(perm, distances));
}

// Fill a deterministic NxN distance pattern based on pid.
int fill_pattern(int pid, uint16_t out[25]) {
    // pid selects a deterministic pattern for the 5x5 distance matrix
    // out is filled row-major (i * N + j)
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            int idx = i * N + j;
            uint16_t val = 0;
            switch (pid) {
                case 0:
                    // All zeros
                    val = 0;
                    break;
                case 1:
                    // Zero on diag, else (i+j)%10 + 1
                    if (i == j) val = 0;
                    else val = (uint16_t)((i + j) % 10 + 1);
                    break;
                case 2:
                    // Row-major incremental values 1..25
                    val = (uint16_t)(i * N + j + 1);
                    break;
                case 3:
                    // Symmetric-ish: distance is abs(i-j) + 1, diagonal 0
                    if (i == j) val = 0;
                    else val = (uint16_t)(abs(i - j) + 1);
                    break;
                case 4:
                    // Larger distances dependent on positions
                    if (i == j) val = 0;
                    else val = (uint16_t)((i + j) * 10 + 7);
                    break;
                case 5:
                    // A pattern that favors a particular route: low costs along row 0
                    if (i == j) val = 0;
                    else if (i == 0 || j == 0) val = 1; // cheap to/from node 0
                    else val = (uint16_t)(5 + ((i * j) % 7));
                    break;
                case 6:
                    // Decreasing values further from diagonal
                    if (i == j) val = 0;
                    else val = (uint16_t)(10 - abs(i - j));
                    break;
                default:
                    val = (uint16_t)(i + j + 1);
                    break;
            }
            out[idx] = val;
        }
    }
    return 0;
}

int main() {
    // Input signal variables (driven by testbench)
    int reset = 0;
    int en = 0;
    uint16_t streamDistances_0 = 0;  uint16_t streamDistances_1 = 0;  uint16_t streamDistances_2 = 0;
    uint16_t streamDistances_3 = 0;  uint16_t streamDistances_4 = 0;  uint16_t streamDistances_5 = 0;
    uint16_t streamDistances_6 = 0;  uint16_t streamDistances_7 = 0;  uint16_t streamDistances_8 = 0;
    uint16_t streamDistances_9 = 0;  uint16_t streamDistances_10 = 0; uint16_t streamDistances_11 = 0;
    uint16_t streamDistances_12 = 0; uint16_t streamDistances_13 = 0; uint16_t streamDistances_14 = 0;
    uint16_t streamDistances_15 = 0; uint16_t streamDistances_16 = 0; uint16_t streamDistances_17 = 0;
    uint16_t streamDistances_18 = 0; uint16_t streamDistances_19 = 0; uint16_t streamDistances_20 = 0;
    uint16_t streamDistances_21 = 0; uint16_t streamDistances_22 = 0; uint16_t streamDistances_23 = 0;
    uint16_t streamDistances_24 = 0;

    // Array of pointers to the individual input variables (for assignment and CSV emission)
    uint16_t* streamPtrs[25] = {
        &streamDistances_0,  &streamDistances_1,  &streamDistances_2,
        &streamDistances_3,  &streamDistances_4,  &streamDistances_5,
        &streamDistances_6,  &streamDistances_7,  &streamDistances_8,
        &streamDistances_9,  &streamDistances_10, &streamDistances_11,
        &streamDistances_12, &streamDistances_13, &streamDistances_14,
        &streamDistances_15, &streamDistances_16, &streamDistances_17,
        &streamDistances_18, &streamDistances_19, &streamDistances_20,
        &streamDistances_21, &streamDistances_22, &streamDistances_23,
        &streamDistances_24
    };

    // Open CSV file for HLS/RTL output
    FILE* f = fopen("hls_output.csv", "w");
    if (!f) return 1;

    // Write CSV header line (column names)
    fprintf(f, "cycle,reset,en");
    for (int i = 0; i < 25; ++i) {
        fprintf(f, ",streamDistances_%d", i);
    }
    fprintf(f, ",shortestDistance\n");

    // Write roles line: meta/in/in,...
    fprintf(f, "meta,in,in");
    for (int i = 0; i < 25; ++i) {
        fprintf(f, ",in");
    }
    fprintf(f, ",out\n");

    const int total_cycles = 32; // between 20 and 50
    const int num_patterns = 7;  // patterns indexed 0..6 (0 reserved for reset zeros)
    uint16_t tmp[25];
    unsigned int shortestDistance = 0;

    for (int cycle = 0; cycle < total_cycles; ++cycle) {
        // Apply reset/en policy:
        if (cycle < 2) {
            reset = 1;
            en = 0;
        } else {
            reset = 0;
            en = 1;
        }

        // Choose pattern
        int pid = 0;
        if (reset) {
            pid = 0; // zero matrix during reset
        } else {
            pid = 1 + ((cycle - 2) % (num_patterns - 1)); // cycle through patterns 1..6
        }

        // Fill temporary pattern
        fill_pattern(pid, tmp);

        // Drive individual streamDistances_x variables deterministically
        for (int i = 0; i < 25; ++i) {
            *streamPtrs[i] = tmp[i];
        }

        // Build array to pass to DUT
        uint16_t streamArr[25];
        for (int i = 0; i < 25; ++i) streamArr[i] = *streamPtrs[i];

        // Call DUT once per cycle (pass address for output)
        tsp(streamArr, &shortestDistance);

        // Emit CSV row
        fprintf(f, "%d,%d,%d", cycle, reset, en);
        // stream distances as decimal integers
        for (int i = 0; i < 25; ++i) {
            fprintf(f, ",%u", (unsigned int)(*streamPtrs[i]));
        }
        // shortestDistance as uppercase hex without 0x
        fprintf(f, ",%X\n", shortestDistance);
    }

    // Explicitly close file
    fclose(f);

    return 0;
}

