int main()
{
    // CSV output file
    FILE* f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // Write CSV header (first line: column names)
    // Columns: cycle, rst, en, then sampled outputs (we declare sample0..sample2 in the testbench)
    std::fprintf(f, "cycle,rst,en,sample0,sample1,sample2\n");

    // Second line: roles (meta/in/out)
    std::fprintf(f, "meta,in,in,out,out,out\n");

    // Testbench signals and DUT memory
    const int TOTAL = GRID_ROWS * GRID_COLS;
    float result[TOTAL];
    float grad_x[TOTAL];
    float grad_y[TOTAL];

    // Select three sample positions (must be within the region that DUT writes to)
    // Pick (row, col): (3,4), (4,5), (5,6) -- all within [MAX_RADIUS, GRID_* - MAX_RADIUS)
    const int s0_r = 3, s0_c = 4;
    const int s1_r = 4, s1_c = 5;
    const int s2_r = 5, s2_c = 6;
    const int idx0 = s0_r * GRID_COLS + s0_c;
    const int idx1 = s1_r * GRID_COLS + s1_c;
    const int idx2 = s2_r * GRID_COLS + s2_c;

    // Number of cycles (rows in CSV). Keep between 20 and 50.
    const int NUM_CYCLES = 24;

    for (int cycle = 0; cycle < NUM_CYCLES; ++cycle) {
        // reset and enable signals per specification:
        int rst = (cycle < 2) ? 1 : 0;
        int en  = (cycle < 2) ? 0 : 1;

        // Prepare deterministic, pre-defined test vectors for grad_x and grad_y.
        // During reset (rst==1), we'll drive zeros.
        if (rst) {
            for (int i = 0; i < TOTAL; ++i) {
                grad_x[i] = 0.0f;
                grad_y[i] = 0.0f;
                result[i] = 0.0f; // clear result as well
            }
        } else {
            // Choose one of several deterministic patterns based on cycle number
            int pattern = (cycle - 2) % 6;
            for (int r = 0; r < GRID_ROWS; ++r) {
                for (int c = 0; c < GRID_COLS; ++c) {
                    int idx = r * GRID_COLS + c;
                    switch (pattern) {
                        case 0:
                            // constant x-gradient, zero y-gradient
                            grad_x[idx] = 1.0f;
                            grad_y[idx] = 0.0f;
                            break;
                        case 1:
                            // coordinates as gradients
                            grad_x[idx] = (float)c;
                            grad_y[idx] = (float)r;
                            break;
                        case 2:
                            // centered ramps (positive and negative)
                            grad_x[idx] = (float)(c - (GRID_COLS/2));
                            grad_y[idx] = (float)(r - (GRID_ROWS/2));
                            break;
                        case 3:
                            // small patterned fractional values
                            grad_x[idx] = (float)((c + r) % 3 - 1) * 0.5f;
                            grad_y[idx] = (float)((2*c + r) % 5 - 2) * 0.25f;
                            break;
                        case 4:
                            // checker-like alternating signs and magnitudes
                            grad_x[idx] = ((c & 1) ? 1.0f : -1.0f) * (((r & 1) ? 1.0f : 0.5f));
                            grad_y[idx] = ((r & 1) ? -0.75f : 0.75f) * ((c & 1) ? 1.0f : 0.5f);
                            break;
                        default: // case 5
                            // slight scaling with cycle to vary over time
                            grad_x[idx] = c * 0.1f + cycle * 0.01f;
                            grad_y[idx] = r * 0.05f - cycle * 0.005f;
                            break;
                    }
                    // Initialize result to zero before DUT computation to avoid leftover values
                    result[idx] = 0.0f;
                }
            }
        }

        // Always call DUT once per cycle (even during reset), as required.
        // The en signal is not used by the DUT itself; testbench models its effect by driving inputs to zeros during reset.
        gicov(result, grad_x, grad_y);

        // Sample outputs from DUT: we store three float samples and then print their bit patterns as hex
        float sample0 = result[idx0];
        float sample1 = result[idx1];
        float sample2 = result[idx2];

        // Convert float bits to integer representation for hex output
        uint32_t bits0, bits1, bits2;
        std::memcpy(&bits0, &sample0, sizeof(bits0));
        std::memcpy(&bits1, &sample1, sizeof(bits1));
        std::memcpy(&bits2, &sample2, sizeof(bits2));

        // Write CSV row:
        // cycle (decimal), rst (decimal), en (decimal), sample0 (HEX), sample1 (HEX), sample2 (HEX)
        // Hex printed uppercase without 0x prefix, no fixed width.
        std::fprintf(f, "%d,%d,%d,%llX,%llX,%llX\n",
                     cycle,
                     rst,
                     en,
                     (unsigned long long)bits0,
                     (unsigned long long)bits1,
                     (unsigned long long)bits2);
    }

    // Explicitly close output file
    std::fclose(f);
    return 0;
}

