// tb_hls_cosim.cpp
// Testbench for HLS cosimulation.
// Updated to use C headers compatible with older Vivado HLS toolchain
// while keeping the test semantics unchanged.

#include <stdio.h>
#include <math.h>
#include <string.h>
#include <stdint.h>

#define GRID_ROWS 8
#define GRID_COLS 10
#define MAX_RADIUS 2
#define NPOINTS 16
#define NCIRCLES 2

// Top-level HLS function declaration must match the HLS C code exactly.
extern "C" void gicov(float result[GRID_ROWS * GRID_COLS],
                      float grad_x[GRID_ROWS * GRID_COLS],
                      float grad_y[GRID_ROWS * GRID_COLS]);

// HLS testbench: semantically equivalent to the provided C testbench.
// Outputs a single CSV file named "hls_output.csv" suitable for HLS/RTL cosim checking.
int main()
{
    // Open HLS/RTL output CSV
    FILE* f = fopen("hls_output.csv", "w");
    if (!f) return 1;

    // CSV header: cycle, rst, en, sample0, sample1, sample2
    fprintf(f, "cycle,rst,en,sample0,sample1,sample2\n");
    // Roles line: meta,in,in,out,out,out
    fprintf(f, "meta,in,in,out,out,out\n");

    const int TOTAL = GRID_ROWS * GRID_COLS;
    float result[TOTAL];
    float grad_x[TOTAL];
    float grad_y[TOTAL];

    // Sample positions (must be within the region DUT writes to)
    const int s0_r = 3, s0_c = 4;
    const int s1_r = 4, s1_c = 5;
    const int s2_r = 5, s2_c = 6;
    const int idx0 = s0_r * GRID_COLS + s0_c;
    const int idx1 = s1_r * GRID_COLS + s1_c;
    const int idx2 = s2_r * GRID_COLS + s2_c;

    const int NUM_CYCLES = 24;

    for (int cycle = 0; cycle < NUM_CYCLES; ++cycle) {
        int rst = (cycle < 2) ? 1 : 0;
        int en  = (cycle < 2) ? 0 : 1;

        if (rst) {
            for (int i = 0; i < TOTAL; ++i) {
                grad_x[i] = 0.0f;
                grad_y[i] = 0.0f;
                result[i] = 0.0f;
            }
        } else {
            int pattern = (cycle - 2) % 6;
            for (int r = 0; r < GRID_ROWS; ++r) {
                for (int c = 0; c < GRID_COLS; ++c) {
                    int idx = r * GRID_COLS + c;
                    switch (pattern) {
                        case 0:
                            grad_x[idx] = 1.0f;
                            grad_y[idx] = 0.0f;
                            break;
                        case 1:
                            grad_x[idx] = (float)c;
                            grad_y[idx] = (float)r;
                            break;
                        case 2:
                            grad_x[idx] = (float)(c - (GRID_COLS/2));
                            grad_y[idx] = (float)(r - (GRID_ROWS/2));
                            break;
                        case 3:
                            grad_x[idx] = (float)((c + r) % 3 - 1) * 0.5f;
                            grad_y[idx] = (float)((2*c + r) % 5 - 2) * 0.25f;
                            break;
                        case 4:
                            grad_x[idx] = ((c & 1) ? 1.0f : -1.0f) * (((r & 1) ? 1.0f : 0.5f));
                            grad_y[idx] = ((r & 1) ? -0.75f : 0.75f) * ((c & 1) ? 1.0f : 0.5f);
                            break;
                        default: // case 5
                            grad_x[idx] = c * 0.1f + cycle * 0.01f;
                            grad_y[idx] = r * 0.05f - cycle * 0.005f;
                            break;
                    }
                    result[idx] = 0.0f;
                }
            }
        }

        // Always call DUT once per cycle
        gicov(result, grad_x, grad_y);

        // Sample three output locations and print their bit patterns as hex
        float sample0 = result[idx0];
        float sample1 = result[idx1];
        float sample2 = result[idx2];

        uint32_t bits0, bits1, bits2;
        memcpy(&bits0, &sample0, sizeof(bits0));
        memcpy(&bits1, &sample1, sizeof(bits1));
        memcpy(&bits2, &sample2, sizeof(bits2));

        // Print as 8-digit hex (32-bit values) to ensure wide tool compatibility
        fprintf(f, "%d,%d,%d,%08X,%08X,%08X\n",
                     cycle,
                     rst,
                     en,
                     (unsigned int)bits0,
                     (unsigned int)bits1,
                     (unsigned int)bits2);
    }

    fclose(f);
    return 0;
}

