static uint32_t float_to_u32_hex_bits(FM_TYPE v) {
    uint32_t bits = 0;
    static_assert(sizeof(FM_TYPE) == sizeof(uint32_t), "FM_TYPE must be 32-bit float");
    std::memcpy(&bits, &v, sizeof(bits));
    return bits;
}

int main() {
    const int NUM_CYCLES = 25; // between 20 and 50, deterministic
    // Testbench-driven inputs (weights and biases are kept constant across cycles)
    WT_TYPE weight[DIM_OUT][DIM_IN] = {
