// hls.cpp
#include <stdint.h>

// Use simple typedefs so code is C++98 friendly
typedef float FM_TYPE;
typedef float WT_TYPE;

// Match the testbench sizes (must match tb_hls_cosim.cpp)
#define DIM_IN 5
#define DIM_OUT 3
#define PARALLEL 2
#define RELU 1

// Top-level must use C linkage for HLS and the testbench
extern "C" void linear_input_stationary(
    FM_TYPE input[DIM_IN],
    WT_TYPE weight[DIM_OUT][DIM_IN],
    WT_TYPE bias[DIM_OUT],
    FM_TYPE output[DIM_OUT]) {
#pragma HLS INTERFACE m_axi port=input offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=weight offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=bias offset=slave bundle=gmem2
#pragma HLS INTERFACE m_axi port=output offset=slave bundle=gmem3
#pragma HLS INTERFACE s_axilite port=input bundle=control
#pragma HLS INTERFACE s_axilite port=weight bundle=control
#pragma HLS INTERFACE s_axilite port=bias bundle=control
#pragma HLS INTERFACE s_axilite port=output bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Initialize output with bias
    for (int dim_out = 0; dim_out < DIM_OUT; dim_out++) {
#pragma HLS PIPELINE II=1
        output[dim_out] = bias[dim_out];
    }

    // Compute weighted sum
    for (int dim_out = 0; dim_out < DIM_OUT; dim_out++) {
        FM_TYPE acc = output[dim_out];
        for (int dim_in = 0; dim_in < DIM_IN; dim_in++) {
#pragma HLS PIPELINE II=1
            acc += input[dim_in] * weight[dim_out][dim_in];
        }
        output[dim_out] = acc;
    }

    // Apply ReLU if enabled
    if (RELU) {
        for (int dim_out = 0; dim_out < DIM_OUT; dim_out++) {
#pragma HLS PIPELINE II=1
            if (output[dim_out] < 0) {
                output[dim_out] = 0;
            }
        }
    }
}

