// test.cpp
#include "test.h"
#include <time.h>

void bbgemm(TYPE m1[N], TYPE m2[N], TYPE prod[N]){
    int i, j, k;
    int i_row, k_row;
    TYPE temp;
    for (i = 0; i < row_size; ++i) {
        i_row = i * row_size;
        for (k = 0; k < row_size; ++k) {
            k_row = k * row_size;
            temp = m1[i_row + k];
            for (j = 0; j < row_size; ++j) {
                prod[i_row + j] += temp * m2[k_row + j];
            }
        }
    }
}

int main() {
    static TYPE m1[N];
    static TYPE m2[N];
