#pragma HLS INTERFACE m_axi port=m2 offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=prod offset=slave bundle=gmem2
#pragma HLS INTERFACE s_axilite port=m1 bundle=control
#pragma HLS INTERFACE s_axilite port=m2 bundle=control
#pragma HLS INTERFACE s_axilite port=prod bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Blocked matrix multiply
    // Matrices are row-major, square of size row_size x row_size
    int i, k, j, jj, kk;
    int i_row, k_row;
    TYPE temp_x, mul;

