// hls.cpp
// HLS implementation of the Durbin algorithm (top-level).
// Comments and pragmas are written for Vivado HLS compatibility.
// The top-level function is extern "C" to match the cosim testbench.

extern "C" {

void durbin(double r[40], double y[40]) {
#pragma HLS INTERFACE m_axi port=r offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=y offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=r bundle=control
#pragma HLS INTERFACE s_axilite port=y bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    const int n = 40;

    // Local copies to reduce external memory accesses and make HLS scheduling easier.
    double r_loc[40];
#pragma HLS ARRAY_PARTITION variable=r_loc block factor=2 dim=1
    double y_loc[40];
#pragma HLS ARRAY_PARTITION variable=y_loc block factor=2 dim=1
    double z[40];
#pragma HLS ARRAY_PARTITION variable=z block factor=2 dim=1

    // Copy inputs from external memory to local arrays
    for (int i = 0; i < n; ++i) {
#pragma HLS PIPELINE II=1
        r_loc[i] = r[i];
        y_loc[i] = 0.0;
    }

    double alpha = 0.0;
    double beta = 0.0;
    double sum = 0.0;

    // Initialize first reflection coefficient
    y_loc[0] = -r_loc[0];
    beta = 1.0;
    alpha = -r_loc[0];

    // Main Durbin recursion
    for (int k = 1; k < n; ++k) {
        // Update beta
        beta = (1.0 - alpha * alpha) * beta;

        // Compute partial correlation sum: sum_{i=0..k-1} r[k-i-1] * y[i]
        sum = 0.0;
        for (int i = 0; i < k; ++i) {
#pragma HLS PIPELINE II=1
            sum += r_loc[k - i - 1] * y_loc[i];
        }

        // Compute next reflection coefficient alpha
        alpha = -(r_loc[k] + sum) / beta;

        // Update temporary vector z
        for (int i = 0; i < k; ++i) {
#pragma HLS PIPELINE II=1
            z[i] = y_loc[i] + alpha * y_loc[k - i - 1];
        }

        // Write back updated y values
        for (int i = 0; i < k; ++i) {
#pragma HLS PIPELINE II=1
            y_loc[i] = z[i];
        }

        // New reflection coefficient
        y_loc[k] = alpha;
    }

    // Write results back to external memory
    for (int i = 0; i < n; ++i) {
#pragma HLS PIPELINE II=1
        y[i] = y_loc[i];
    }
}

} // extern "C"

