        for (int j = 1; j < DRIVEN_R; ++j) {
            int mapping = (cycle + j) % 3; /* 0,1,2 */
            /* map to -2,0,2 */
            int val = mapping * 2 - 2;
            r[j] = (double)val;
        }
        /* r[DRIVEN_R..39] remain 0.0 */

        /* Call DUT (HLS top-level) */
        durbin(r, y);

        /* Write CSV row:
           cycle (decimal), inputs r0..r9 as decimal integers,
           outputs y0..y39 as Q16.48 signed 64-bit hex (uppercase) */
        fprintf(f, "%d", cycle);

        for (int j = 0; j < DRIVEN_R; ++j) {
            /* Print inputs as decimal integers */
            int iv = (int)r[j];
            fprintf(f, ",%d", iv);
        }

        for (int i = 0; i < N; ++i) {
            /* Convert double y[i] to Q16.48 fixed-point signed 64-bit (two's complement) */
            long long q = 0;
            if (isnan((double)y[i])) {
                q = 0;
            } else if (y[i] >= 0.0) {
                long double scaled = (long double)y[i] * (long double)SCALE;
                if (scaled > (long double)LLONG_MAX) q = LLONG_MAX;
                else q = llround_portable(scaled);
            } else {
                long double scaled = (long double)y[i] * (long double)SCALE;
                if (scaled < (long double)LLONG_MIN) q = LLONG_MIN;
                else q = llround_portable(scaled);
            }
            uint64_t out = (uint64_t)((unsigned long long)q);
            fprintf(f, ",%llX", (unsigned long long)out);
        }

        fprintf(f, "\n");
    }

    fclose(f);
    return 0;
}

