// hls.cpp
// HLS implementation of ELU adapted to work with the testbench (integer inputs).
// Uses float intermediate buffers for exponential computation, final results cast back to int32_t.
//
// Notes:
// - Keep top-level function extern "C" and the same interface as the testbench.
// - Use stdint.h for fixed-width integer type compatibility with Vivado HLS C++98 toolchain.

#include <hls_math.h>
#include <stdint.h>

#define C 2
#define H 2
#define W 2

typedef int32_t data_t;

extern "C" {

void elu(data_t input[C][H][W], data_t output[C][H][W], data_t alpha) {
#pragma HLS INTERFACE m_axi port=input offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=output offset=slave bundle=gmem1
#pragma HLS INTERFACE s_axilite port=input bundle=control
#pragma HLS INTERFACE s_axilite port=output bundle=control
#pragma HLS INTERFACE s_axilite port=alpha bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Use float intermediate buffers for correct exponential computation.
    float FM_buffer_1[C][H][W];
    float FM_buffer_2[C][H][W];
    float FM_buffer_3[C][H][W];
    float FM_buffer_4[C][H][W];

    // load_feature_map: copy integer inputs into float buffer
    for (int c = 0; c < C; c++) {
        for (int h = 0; h < H; h++) {
            for (int w = 0; w < W; w++) {
#pragma HLS PIPELINE II=1
                FM_buffer_1[c][h][w] = (float)input[c][h][w];
            }
        }
    }

    // compute_exp: FM_buffer_2 = exp(FM_buffer_1)
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
#pragma HLS PIPELINE II=1
                FM_buffer_2[i][j][k] = hls::exp(FM_buffer_1[i][j][k]);
            }
        }
    }

    // set_value FM_buffer_3 to -1.0f
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
#pragma HLS PIPELINE II=1
                FM_buffer_3[i][j][k] = -1.0f;
            }
        }
    }

    // compute_add FM_buffer_2 + FM_buffer_3 -> FM_buffer_4  (exp(x) - 1)
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
#pragma HLS PIPELINE II=1
                FM_buffer_4[i][j][k] = FM_buffer_2[i][j][k] + FM_buffer_3[i][j][k];
            }
        }
    }

    // set_value FM_buffer_3 to alpha (as float)
    float alpha_f = (float)alpha;
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
#pragma HLS PIPELINE II=1
                FM_buffer_3[i][j][k] = alpha_f;
            }
        }
    }

    // compute_mul FM_buffer_3 * FM_buffer_4 -> FM_buffer_2  (alpha * (exp(x)-1))
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
#pragma HLS PIPELINE II=1
                FM_buffer_2[i][j][k] = FM_buffer_3[i][j][k] * FM_buffer_4[i][j][k];
            }
        }
    }

    // select: if FM_buffer_1 >= 0 then FM_buffer_3 = FM_buffer_1 else FM_buffer_3 = FM_buffer_2
    for (int i = 0; i < C; i++) {
        for (int j = 0; j < H; j++) {
            for (int k = 0; k < W; k++) {
#pragma HLS PIPELINE II=1
                if (FM_buffer_1[i][j][k] >= 0.0f) {
                    FM_buffer_3[i][j][k] = FM_buffer_1[i][j][k];
                } else {
                    FM_buffer_3[i][j][k] = FM_buffer_2[i][j][k];
                }
            }
        }
    }

    // store_feature_map: cast back to integer outputs (truncation toward zero)
    for (int c = 0; c < C; c++) {
        for (int h = 0; h < H; h++) {
            for (int w = 0; w < W; w++) {
#pragma HLS PIPELINE II=1
                output[c][h][w] = (data_t)FM_buffer_3[c][h][w];
            }
        }
    }
}

} // extern "C"

