#include "test.h"

void needwun(char SEQA[ALEN], char SEQB[BLEN],
             char alignedA[ALEN+BLEN], char alignedB[ALEN+BLEN],
             int M[(ALEN+1)*(BLEN+1)], char ptr[(ALEN+1)*(BLEN+1)]){

    int score, up_left, up, left, max;
    int row, row_up, r;
    int a_idx, b_idx;
    int a_str_idx, b_str_idx;

    for(a_idx=0; a_idx<(ALEN+1); a_idx++){
        M[a_idx] = a_idx * GAP_SCORE;
    }
    for(b_idx=0; b_idx<(BLEN+1); b_idx++){
        M[b_idx*(ALEN+1)] = b_idx * GAP_SCORE;
    }

    for(b_idx=1; b_idx<(BLEN+1); b_idx++){
        for(a_idx=1; a_idx<(ALEN+1); a_idx++){
            if(SEQA[a_idx-1] == SEQB[b_idx-1]){
                score = MATCH_SCORE;
            } else {
                score = MISMATCH_SCORE;
            }

            row_up = (b_idx-1)*(ALEN+1);
            row = (b_idx)*(ALEN+1);

            up_left = M[row_up + (a_idx-1)] + score;
            up      = M[row_up + (a_idx  )] + GAP_SCORE;
            left    = M[row    + (a_idx-1)] + GAP_SCORE;

            max = MAX(up_left, MAX(up, left));

            M[row + a_idx] = max;
            if(max == left){
                ptr[row + a_idx] = SKIPB;
            } else if(max == up){
                ptr[row + a_idx] = SKIPA;
            } else{
                ptr[row + a_idx] = ALIGN;
            }
        }
    }

    a_idx = ALEN;
    b_idx = BLEN;
    a_str_idx = 0;
    b_str_idx = 0;

    while(a_idx>0 || b_idx>0) {
        r = b_idx*(ALEN+1);
        if (ptr[r + a_idx] == ALIGN){
            alignedA[a_str_idx++] = SEQA[a_idx-1];
            alignedB[b_str_idx++] = SEQB[b_idx-1];
            a_idx--;
            b_idx--;
        }
        else if (ptr[r + a_idx] == SKIPB){
            alignedA[a_str_idx++] = SEQA[a_idx-1];
            alignedB[b_str_idx++] = '-';
            a_idx--;
        }
        else{
            alignedA[a_str_idx++] = '-';
            alignedB[b_str_idx++] = SEQB[b_idx-1];
            b_idx--;
        }
    }

    for( ; a_str_idx<ALEN+BLEN; a_str_idx++ ) {
      alignedA[a_str_idx] = '_';
    }
    for( ; b_str_idx<ALEN+BLEN; b_str_idx++ ) {
      alignedB[b_str_idx] = '_';
    }
}

void nw(char* SEQA, char* SEQB,
             char* alignedA, char* alignedB, int num_jobs) {

    int M[(ALEN+1)*(BLEN+1)];
    char ptr[(ALEN+1)*(BLEN+1)];
    int i;
    for (i=0; i<100 ; i++) {
        needwun(SEQA + i*ALEN, SEQB + i*BLEN, alignedA + i*(ALEN+BLEN), alignedB + i*(ALEN+BLEN), M, ptr);
    }
    return;
}

int main() {
    int total_jobs = 100;
    char *SEQA = (char*)malloc(total_jobs * ALEN * sizeof(char));
    char *SEQB = (char*)malloc(total_jobs * BLEN * sizeof(char));
    char *alignedA = (char*)malloc(total_jobs * (ALEN+BLEN) * sizeof(char));
    char *alignedB = (char*)malloc(total_jobs * (ALEN+BLEN) * sizeof(char));
    if(!SEQA || !SEQB || !alignedA || !alignedB) return 1;
    for(int i=0;i<total_jobs;i++){
        for(int j=0;j<ALEN;j++){
            SEQA[i*ALEN + j] = 'A' + (j % 26);
        }
        for(int j=0;j<BLEN;j++){
            SEQB[i*BLEN + j] = 'A' + ((j+1) % 26);
        }
    }
    nw(SEQA, SEQB, alignedA, alignedB, total_jobs);
    for(int k=0;k<1;k++){
        fwrite(alignedA + k*(ALEN+BLEN), 1, ALEN+BLEN, stdout);
        putchar('\n');
        fwrite(alignedB + k*(ALEN+BLEN), 1, ALEN+BLEN, stdout);
        putchar('\n');
    }
    free(SEQA);
    free(SEQB);
    free(alignedA);
    free(alignedB);
    return 0;
}

