            alignedA[a_str_idx++] = SEQA[a_idx-1];
            alignedB[b_str_idx++] = '-';
            a_idx--;
        }
        else{
            alignedA[a_str_idx++] = '-';
            alignedB[b_str_idx++] = SEQB[b_idx-1];
            b_idx--;
        }
    }

    for( ; a_str_idx<ALEN+BLEN; a_str_idx++ ) {
      alignedA[a_str_idx] = '_';
    }
    for( ; b_str_idx<ALEN+BLEN; b_str_idx++ ) {
      alignedB[b_str_idx] = '_';
    }
}

void nw(char* SEQA, char* SEQB,
             char* alignedA, char* alignedB, int num_jobs) {

    int M[(ALEN+1)*(BLEN+1)];
    char ptr[(ALEN+1)*(BLEN+1)];
    int i;
    for (i=0; i<100 ; i++) {
        needwun(SEQA + i*ALEN, SEQB + i*BLEN, alignedA + i*(ALEN+BLEN), alignedB + i*(ALEN+BLEN), M, ptr);
    }
    return;
}

static void bytes_to_hex_upper(const unsigned char* data, int len, std::string &out) {
    static const char hexchars[] = "0123456789ABCDEF";
