// hls.cpp
// Vivado HLS C++ implementation of the NW-style alignment kernel.
// Top-level function is defined as extern "C" void nw(...) to match the testbench.
// This version implements a correct Needleman-Wunsch dynamic programming table
// and traceback for one or more jobs. It avoids complicated rolling-buffer bugs
// and prevents out-of-bounds accesses that caused CSim SIGSEGV before.
//
// Notes:
// - ALEN and BLEN must match the testbench sizes (128).
// - The function processes num_jobs sequences sequentially (each job has ALEN and BLEN bytes).
// - Output alignments are padded with '_' to fill ALEN+BLEN bytes.
// - All comments in English.

#include <string.h>
#include <stdint.h>

#define ALEN 128
#define BLEN 128

#define MATCH_SCORE 1
#define MISMATCH_SCORE -1
#define GAP_SCORE -1

#define ALIGN '\\'
#define SKIPA '^'
#define SKIPB '<'

extern "C" {

// Top-level HLS interface: keep the same pragmas so Vivado HLS recognizes the ports.
void nw(char* SEQA, char* SEQB, char* alignedA, char* alignedB, int num_jobs) {
#pragma HLS INTERFACE m_axi port=SEQA offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=SEQB offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=alignedA offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=alignedB offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=SEQA bundle=control
#pragma HLS INTERFACE s_axilite port=SEQB bundle=control
#pragma HLS INTERFACE s_axilite port=alignedA bundle=control
#pragma HLS INTERFACE s_axilite port=alignedB bundle=control
#pragma HLS INTERFACE s_axilite port=num_jobs bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Process jobs sequentially. The testbench uses num_jobs = 1, but this is general.
    for (int job = 0; job < num_jobs; ++job) {
#pragma HLS PIPELINE II=1
        // Pointers to this job's sequences and outputs
        char* seqA = SEQA + job * ALEN;
        char* seqB = SEQB + job * BLEN;
        char* outA = alignedA + job * (ALEN + BLEN);
        char* outB = alignedB + job * (ALEN + BLEN);

        // DP score matrix and traceback pointer matrix.
        // Use int16_t for scores to reduce memory; dimensions are constants.
        static int16_t score[ALEN + 1][BLEN + 1];
        static char ptr[ALEN + 1][BLEN + 1];

        // Initialize first row and first column
        for (int i = 0; i <= ALEN; ++i) {
#pragma HLS PIPELINE II=1
            score[i][0] = (int16_t)(i * GAP_SCORE);
            ptr[i][0] = SKIPB; // coming from above (gap in B) when i>0
        }
        for (int j = 0; j <= BLEN; ++j) {
#pragma HLS PIPELINE II=1
            score[0][j] = (int16_t)(j * GAP_SCORE);
            ptr[0][j] = SKIPA; // coming from left (gap in A) when j>0
        }
        // (0,0) pointer is arbitrary
        ptr[0][0] = ALIGN;

        // Fill DP table
        for (int i = 1; i <= ALEN; ++i) {
            for (int j = 1; j <= BLEN; ++j) {
#pragma HLS PIPELINE II=1
                int16_t diag = score[i-1][j-1] + (seqA[i-1] == seqB[j-1] ? MATCH_SCORE : MISMATCH_SCORE);
                int16_t up = score[i-1][j] + GAP_SCORE;    // gap in B (consume A)
                int16_t left = score[i][j-1] + GAP_SCORE;  // gap in A (consume B)

                int16_t best = diag;
                char best_dir = ALIGN;
                if (up > best) {
                    best = up;
                    best_dir = SKIPB; // move up: A char aligned to gap
                }
                if (left > best) {
                    best = left;
                    best_dir = SKIPA; // move left: B char aligned to gap
                }
                score[i][j] = best;
                ptr[i][j] = best_dir;
            }
        }

        // Traceback: build reversed alignment, then reverse into outputs
        char revA[ALEN + BLEN];
        char revB[ALEN + BLEN];
        int rev_len = 0;

        int i = ALEN;
        int j = BLEN;
        while (i > 0 || j > 0) {
            if (i > 0 && j > 0 && ptr[i][j] == ALIGN) {
                // match/mismatch
                revA[rev_len] = seqA[i-1];
                revB[rev_len] = seqB[j-1];
                ++rev_len;
                --i; --j;
            } else if (i > 0 && (j == 0 || ptr[i][j] == SKIPB)) {
                // move up: A char and gap in B
                revA[rev_len] = seqA[i-1];
                revB[rev_len] = '-';
                ++rev_len;
                --i;
            } else {
                // move left: gap in A and B char
                revA[rev_len] = '-';
                revB[rev_len] = seqB[j-1];
                ++rev_len;
                --j;
            }
        }

        // reverse into outputs and pad with '_' to full ALEN+BLEN length
        int out_len = ALEN + BLEN;
        int idx = 0;
        for (int k = rev_len - 1; k >= 0; --k) {
#pragma HLS PIPELINE II=1
            outA[idx] = revA[k];
            outB[idx] = revB[k];
            ++idx;
        }
        // pad remaining bytes with '_'
        for (; idx < out_len; ++idx) {
#pragma HLS PIPELINE II=1
            outA[idx] = '_';
            outB[idx] = '_';
        }
    } // end jobs loop
}

} // extern "C"

