#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include "test.h"

void correlation(double float_n, double data[ROWS][COLS], double corr[COLS][COLS], double mean[COLS], double stddev[COLS])
{
  int i;
  int j;
  int k;
  double eps = 0.1;

  for (j = 0; j < COLS; j++) {
    mean[j] = 0.0;

    for (i = 0; i < ROWS; i++) {
      mean[j] += data[i][j];
    }
    mean[j] /= float_n;
  }


  for (j = 0; j < COLS; j++) {
    stddev[j] = 0.0;

    for (i = 0; i < ROWS; i++) {
      double diff = data[i][j] - mean[j];
      stddev[j] += diff * diff;
    }
    stddev[j] /= float_n;
    stddev[j] = sqrt(stddev[j]);

    stddev[j] = (stddev[j] <= eps ? 1.0 : stddev[j]);
  }

  for (i = 0; i < ROWS; i++) {
    for (j = 0; j < COLS; j++) {
      data[i][j] -= mean[j];
      data[i][j] /= sqrt(float_n) * stddev[j];
    }
  }

  for (i = 0; i < COLS - 1; i++) {
    corr[i][i] = 1.0;

    for (j = i + 1; j < COLS; j++) {
      corr[i][j] = 0.0;

      for (k = 0; k < ROWS; k++) {
        corr[i][j] += data[k][i] * data[k][j];
      }
      corr[j][i] = corr[i][j];
    }
  }
  corr[COLS - 1][COLS - 1] = 1.0;
}

int main(void)
{
  double data[ROWS][COLS];
  double corr[COLS][COLS];
  double mean[COLS];
  double stddev[COLS];
  int i, j;

  for (i = 0; i < ROWS; i++) {
    for (j = 0; j < COLS; j++) {
      data[i][j] = (double)((i * 31 + j * 17) % 100) / 100.0;
    }
  }

  correlation((double)ROWS, data, corr, mean, stddev);

  printf("First 5 means:\n");
  for (j = 0; j < 5 && j < COLS; j++) {
    printf("%d: %f\n", j, mean[j]);
  }

  printf("\nFirst 5 stddevs:\n");
  for (j = 0; j < 5 && j < COLS; j++) {
    printf("%d: %f\n", j, stddev[j]);
  }

  printf("\nTop-left 5x5 of correlation matrix:\n");
  for (i = 0; i < 5 && i < COLS; i++) {
    for (j = 0; j < 5 && j < COLS; j++) {
      printf("%8.4f ", corr[i][j]);
    }
    printf("\n");
  }

  return 0;
}

