        }
    }
    for (int j = 0; j < COLS; ++j) std::fprintf(f, ",out");
    for (int j = 0; j < COLS; ++j) std::fprintf(f, ",out");
    for (int i = 0; i < COLS; ++i) for (int j = 0; j < COLS; ++j) std::fprintf(f, ",out");
    std::fprintf(f, "\n");

    // Drive testcases deterministically. Inputs are integers (printed as decimal).
    // float_n will be kept equal to ROWS (an integer).
    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        double float_n = (double)ROWS; // input

        // Prepare input data (integers, deterministic, diverse)
        int input_ints[ROWS][COLS];
        int pattern = cycle % 6;
        for (int i = 0; i < ROWS; ++i) {
            for (int j = 0; j < COLS; ++j) {
                int v = 0;
                switch (pattern) {
                    case 0:
                        // increasing with cycle for diversity
                        v = i * COLS + j + cycle;
                        break;
                    case 1:
                        // all zeros
                        v = 0;
                        break;
                    case 2:
                        // identical columns (all ones) -> zero stddev, exercise eps clamp
                        v = 1;
                        break;
                    case 3:
                        // negative values
                        v = - (i + j + (cycle % 5));
                        break;
                    case 4:
                        // constant per row plus cycle
                        v = (i + 1) + (cycle % 4);
                        break;
                    case 5:
                        // modulo pattern to get mixed small negatives/positives
                        v = ((cycle + 1) * (i + 2) * (j + 3)) % 7 - 3;
                        break;
                }
                input_ints[i][j] = v;
            }
        }

        // Copy inputs into double array to call DUT
        double data[ROWS][COLS];
        for (int i = 0; i < ROWS; ++i) for (int j = 0; j < COLS; ++j) data[i][j] = (double)input_ints[i][j];

        // Prepare outputs
        double corr[COLS][COLS];
        double mean[COLS];
        double stddev[COLS];

        // Call DUT
        correlation(float_n, data, corr, mean, stddev);

        // Write CSV row:
        // cycle as integer
        std::fprintf(f, "%d,", cycle);
        // inputs: float_n (print as decimal integer), then data inputs (as driven integers)
        std::fprintf(f, "%.0f", float_n);
        for (int i = 0; i < ROWS; ++i) {
            for (int j = 0; j < COLS; ++j) {
                std::fprintf(f, ",%d", input_ints[i][j]);
            }
        }

        // outputs: mean[], stddev[], corr[][] as hex uppercase of IEEE-754 bits, no 0x, no fixed width
        char buf[64];
        for (int j = 0; j < COLS; ++j) {
            double_to_hex_upper(mean[j], buf, sizeof(buf));
            std::fprintf(f, ",%s", buf);
        }
        for (int j = 0; j < COLS; ++j) {
            double_to_hex_upper(stddev[j], buf, sizeof(buf));
            std::fprintf(f, ",%s", buf);
        }
        for (int i = 0; i < COLS; ++i) {
            for (int j = 0; j < COLS; ++j) {
                double_to_hex_upper(corr[i][j], buf, sizeof(buf));
                std::fprintf(f, ",%s", buf);
            }
        }
        std::fprintf(f, "\n");
    }

    std::fclose(f);
    return 0;
}

