// hls.cpp
// HLS implementation of correlation tailored to the cosim testbench.
// Top-level function uses extern "C" linkage and matches the testbench
// signature exactly (double float_n, data[4][3], corr[3][3], mean[3], stddev[3]).
extern "C" {

#define N_SAMPLES 4
#define N_FEATURES 3

// Simple sqrt approximation using Newton-Raphson method.
// Pure software routine (keeps everything deterministic for CSim).
static double hls_sqrt(double x) {
    if (x <= 0.0) return 0.0;
    double approx = x;
    for (int i = 0; i < 10; i++) {
        approx = 0.5 * (approx + x / approx);
    }
    return approx;
}

// Top-level HLS function.
// Note: float_n is passed as double by the testbench; convert to int internally.
void correlation(
    double float_n,
    double data[N_SAMPLES][N_FEATURES],
    double corr[N_FEATURES][N_FEATURES],
    double mean[N_FEATURES],
    double stddev[N_FEATURES])
{
#pragma HLS INTERFACE m_axi port=data offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=corr offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=mean offset=slave bundle=gmem2
#pragma HLS INTERFACE m_axi port=stddev offset=slave bundle=gmem3
#pragma HLS INTERFACE s_axilite port=float_n bundle=control
#pragma HLS INTERFACE s_axilite port=data bundle=control
#pragma HLS INTERFACE s_axilite port=corr bundle=control
#pragma HLS INTERFACE s_axilite port=mean bundle=control
#pragma HLS INTERFACE s_axilite port=stddev bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    const double eps = 0.1;

    // Convert float_n (double) to integer sample count.
    int n = (int) float_n;
    if (n <= 0) n = N_SAMPLES;
    if (n > N_SAMPLES) n = N_SAMPLES;

    // Compute mean for each feature
    for (int j = 0; j < N_FEATURES; j++) {
        double sum = 0.0;
        for (int i = 0; i < n; i++) {
            sum += data[i][j];
        }
        mean[j] = sum / (double)n;
    }

    // Compute standard deviation for each feature
    for (int j = 0; j < N_FEATURES; j++) {
        double sum_sq = 0.0;
        for (int i = 0; i < n; i++) {
            double diff = data[i][j] - mean[j];
            sum_sq += diff * diff;
        }
        double var = sum_sq / (double)n;
        double sd = hls_sqrt(var);
        stddev[j] = (sd <= eps) ? 1.0 : sd;
    }

    // Normalize data in-place: (x - mean) / (sqrt(n) * stddev)
    double norm_factor = hls_sqrt((double)n);
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < N_FEATURES; j++) {
            data[i][j] = (data[i][j] - mean[j]) / (norm_factor * stddev[j]);
        }
    }
    // For any unused rows (if n < N_SAMPLES), leave them untouched (not needed for testbench)

    // Compute correlation matrix (symmetric)
    for (int i = 0; i < N_FEATURES; i++) {
        for (int j = 0; j < N_FEATURES; j++) {
            corr[i][j] = 0.0;
        }
    }

    for (int i = 0; i < N_FEATURES; i++) {
        corr[i][i] = 1.0;
        for (int j = i + 1; j < N_FEATURES; j++) {
            double sum = 0.0;
            for (int k = 0; k < n; k++) {
                sum += data[k][i] * data[k][j];
            }
            corr[i][j] = sum;
            corr[j][i] = sum;
        }
    }
}

} // extern "C"

