// Testbench for the HLS correlation function.
// Uses C headers (compatible with older Vivado HLS toolchain).
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <stdint.h>
#include <string.h>

/*
 Note:
 Vivado HLS 2018.3 uses an older C++ mode (C++98) and toolchain where
 the inttypes.h format macros (PRIX64, etc.) may not be available or
 behave inconsistently in C++ compilation. To keep compatibility
 with the provided toolchain, this testbench avoids relying on
 PRIX64 and instead prints the 64-bit integer as unsigned long long.
*/

// Top-level HLS function (must match HLSC definition exactly)
extern "C" void correlation(double float_n, double data[4][3], double corr[3][3], double mean[3], double stddev[3]);

// Convert double to uppercase hex string of IEEE-754 bits (no 0x prefix).
static void double_to_hex_upper(double v, char *out, size_t out_len) {
    uint64_t bits = 0;
    /* memcpy is used instead of static_assert to be compatible with older toolchain */
    memcpy(&bits, &v, sizeof(bits));
    /* Print using unsigned long long cast to avoid depending on PRIX64 macro */
    snprintf(out, out_len, "%llX", (unsigned long long)bits);
}

int main() {
    // Simulation cycles: choose 24 cycles (within 20-50)
    const int CYCLES = 24;
    FILE *f = fopen("hls_output.csv", "w");
    if (!f) return 1;

    // Header line: cycle,float_n, data inputs, outputs(mean,stddev,corr)
    fprintf(f, "cycle,float_n");
    for (int i = 0; i < 4; ++i) {
        for (int j = 0; j < 3; ++j) {
            fprintf(f, ",data[%d][%d]", i, j);
        }
    }
    for (int j = 0; j < 3; ++j) {
        fprintf(f, ",mean[%d]", j);
    }
    for (int j = 0; j < 3; ++j) {
        fprintf(f, ",stddev[%d]", j);
    }
    for (int i = 0; i < 3; ++i) {
        for (int j = 0; j < 3; ++j) {
            fprintf(f, ",corr[%d][%d]", i, j);
        }
    }
    fprintf(f, "\n");

    // Second line: roles
    fprintf(f, "meta,in");
    for (int i = 0; i < 4; ++i) {
        for (int j = 0; j < 3; ++j) {
            fprintf(f, ",in");
        }
    }
    for (int j = 0; j < 3; ++j) fprintf(f, ",out");
    for (int j = 0; j < 3; ++j) fprintf(f, ",out");
    for (int i = 0; i < 3; ++i) for (int j = 0; j < 3; ++j) fprintf(f, ",out");
    fprintf(f, "\n");

    // Drive testcases deterministically. Inputs are integers (printed as decimal).
    // float_n will be kept equal to ROWS (an integer).
    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        double float_n = (double)4; // input (ROWS)

        // Prepare input data (integers, deterministic, diverse)
        int input_ints[4][3];
        int pattern = cycle % 6;
        for (int i = 0; i < 4; ++i) {
            for (int j = 0; j < 3; ++j) {
                int v = 0;
                switch (pattern) {
                    case 0:
                        v = i * 3 + j + cycle;
                        break;
                    case 1:
                        v = 0;
                        break;
                    case 2:
                        v = 1;
                        break;
                    case 3:
                        v = - (i + j + (cycle % 5));
                        break;
                    case 4:
                        v = (i + 1) + (cycle % 4);
                        break;
                    case 5:
                        v = ((cycle + 1) * (i + 2) * (j + 3)) % 7 - 3;
                        break;
                }
                input_ints[i][j] = v;
            }
        }

        // Copy inputs into double array to call DUT
        double data[4][3];
        for (int i = 0; i < 4; ++i) for (int j = 0; j < 3; ++j) data[i][j] = (double)input_ints[i][j];

        // Prepare outputs
        double corr[3][3];
        double mean[3];
        double stddev[3];

        // Call DUT
        correlation(float_n, data, corr, mean, stddev);

        // Write CSV row:
        fprintf(f, "%d,", cycle);
        fprintf(f, "%.0f", float_n);
        for (int i = 0; i < 4; ++i) {
            for (int j = 0; j < 3; ++j) {
                fprintf(f, ",%d", input_ints[i][j]);
            }
        }

        // outputs: mean[], stddev[], corr[][] as hex uppercase of IEEE-754 bits, no 0x, no fixed width
        char buf[64];
        for (int j = 0; j < 3; ++j) {
            double_to_hex_upper(mean[j], buf, sizeof(buf));
            fprintf(f, ",%s", buf);
        }
        for (int j = 0; j < 3; ++j) {
            double_to_hex_upper(stddev[j], buf, sizeof(buf));
            fprintf(f, ",%s", buf);
        }
        for (int i = 0; i < 3; ++i) {
            for (int j = 0; j < 3; ++j) {
                double_to_hex_upper(corr[i][j], buf, sizeof(buf));
                fprintf(f, ",%s", buf);
            }
        }
        fprintf(f, "\n");
    }

    fclose(f);
    return 0;
}

