// hls.cpp
// Top-level Jacobi 2D kernel for Vivado HLS.
// The top-level function uses extern "C" linkage to match the testbench exactly.
// The arrays are statically sized to N = 90 to match the testbench; the runtime parameter 'n'
// controls the effective working size. This file uses only C++98-compatible constructs.

#include <stddef.h>

#define N 90

extern "C" void jacobi_2d(int tsteps, int n, double A[N][N], double B[N][N]) {
    // AXI master interfaces for the 2D arrays, and AXI-lite control interface
#pragma HLS INTERFACE m_axi port=A offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=B offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=A bundle=control
#pragma HLS INTERFACE s_axilite port=B bundle=control
#pragma HLS INTERFACE s_axilite port=tsteps bundle=control
#pragma HLS INTERFACE s_axilite port=n bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Normalize and guard 'n' to the statically sized arrays.
    int limit = n;
    if (limit > N) limit = N;
    if (limit < 2) return; // nothing to do for too-small sizes

    // Run Jacobi iterations for 'tsteps' timesteps, using the effective size 'limit'.
    // We update B from A, then A from B, for each timestep.
    for (int t = 0; t < tsteps; t++) {
        // Update B from A
        for (int i = 1; i < limit - 1; i++) {
            for (int j = 1; j < limit - 1; j++) {
#pragma HLS PIPELINE II=1
                B[i][j] = 0.2 * (A[i][j] + A[i][j - 1] + A[i][j + 1] + A[i + 1][j] + A[i - 1][j]);
            }
        }

        // Update A from B
        for (int i = 1; i < limit - 1; i++) {
            for (int j = 1; j < limit - 1; j++) {
#pragma HLS PIPELINE II=1
                A[i][j] = 0.2 * (B[i][j] + B[i][j - 1] + B[i][j + 1] + B[i + 1][j] + B[i - 1][j]);
            }
        }
    }
}

