void seidel(int tsteps,int n,double A[120][120])
{
  int t;
  int i;
  int j;

  for (t = 0; t <= 39; t++) {

    for (i = 1; i <= 118; i++) {

      for (j = 1; j <= 118; j++) {
        A[i][j] = (A[i - 1][j - 1] + A[i - 1][j] + A[i - 1][j + 1] + A[i][j - 1] + A[i][j] + A[i][j + 1] + A[i + 1][j - 1] + A[i + 1][j] + A[i + 1][j + 1]) / 9.0;
      }
    }
  }
}

int main()
{
    int tsteps = 40;
    int n = 120;
    static double A[120][120];
    int i, j;

    for (i = 0; i < 120; i++) {
        for (j = 0; j < 120; j++) {
            A[i][j] = (double)(i * 120 + j);
        }
    }

    clock_t start = clock();
    seidel(tsteps, n, A);
    clock_t end = clock();

    double elapsed = (double)(end - start) / (double)CLOCKS_PER_SEC;
    printf("Elapsed time: %f seconds\n", elapsed);

    for (i = 0; i < 5; i++) {
        for (j = 0; j < 5; j++) {
            printf("%f ", A[i][j]);
        }
        printf("\n");
    }

    return 0;
}

