      }
    }
  }
}

static uint64_t dbl_to_u64(double v) {
    uint64_t x;
    std::memcpy(&x, &v, sizeof(x));
    return x;
}

int main() {
    const int cycles = 30; // produce 30 cycles => 30 data rows
    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // CSV header: cycle, then inputs, then outputs
    // Inputs we drive: tsteps, n, pattern_id, rst, en
    // Outputs we sample from DUT: out_A_1_1, out_A_2_3, out_A_60_60, out_checksum
    std::fprintf(f, "cycle,tsteps,n,pattern_id,rst,en,out_A_1_1,out_A_2_3,out_A_60_60,out_checksum\n");
    // Roles row
    std::fprintf(f, "meta,in,in,in,in,in,out,out,out,out\n");

    // Deterministic test vectors for tsteps, n, pattern_id
    int tsteps_vec[cycles];
    int n_vec[cycles];
    int pattern_vec[cycles];

    for (int i = 0; i < cycles; ++i) {
        // vary tsteps deterministically but keep reasonable values
        // (function ignores tsteps, but we still drive it)
        tsteps_vec[i] = (i % 5) * 10; // 0,10,20,30,40 cycles...
        n_vec[i] = 120; // the function expects a 120-sized array; keep constant
        pattern_vec[i] = i % 6; // six different initialization patterns (0..5)
    }

    for (int cycle = 0; cycle < cycles; ++cycle) {
        int rst = (cycle < 2) ? 1 : 0; // reset active for first 2 cycles
        int en  = (cycle < 2) ? 0 : 1; // enable low for first 2 cycles

        int tsteps = tsteps_vec[cycle];
        int n = n_vec[cycle];
        int pattern_id = pattern_vec[cycle];

        // Initialize A deterministically according to pattern_id and cycle index
        double A[120][120];
        for (int i = 0; i < 120; ++i) {
            for (int j = 0; j < 120; ++j) {
                double val = 0.0;
                switch (pattern_id) {
                    case 0:
                        // all zeros
                        val = 0.0;
                        break;
                    case 1:
                        // uniform value depending on cycle
                        val = 1.0 + (double)cycle;
                        break;
                    case 2:
                        // ramp pattern
                        val = (double)(i * 120 + j + cycle);
                        break;
                    case 3:
                        // checkerboard toggling with cycle
                        val = ((i + j + cycle) & 1) ? 1.0 : 0.0;
                        break;
                    case 4:
                        // border ones, interior zero
                        if (i == 0 || j == 0 || i == 119 || j == 119) val = 1.0;
                        else val = 0.0;
                        break;
                    case 5:
                        // diagonal weighted by index
                        val = (i == j) ? (double)(i + cycle) : 0.0;
                        break;
                    default:
                        val = 0.0;
                }
                A[i][j] = val;
            }
        }

        // If reset is active, emulate reset by zeroing A regardless of pattern (deterministic)
        if (rst) {
            for (int i = 0; i < 120; ++i)
                for (int j = 0; j < 120; ++j)
                    A[i][j] = 0.0;
        }

        // Call DUT every cycle as required
        seidel(tsteps, n, A);

        // Sample outputs: pick a few matrix entries and a checksum
        double outA11 = A[1][1];
        double outA23 = A[2][3];
        double outA6060 = A[60][60];

        double checksum = 0.0;
        for (int i = 0; i < 120; ++i)
            for (int j = 0; j < 120; ++j)
                checksum += A[i][j];

        uint64_t bits_A11 = dbl_to_u64(outA11);
        uint64_t bits_A23 = dbl_to_u64(outA23);
        uint64_t bits_A6060 = dbl_to_u64(outA6060);
        uint64_t bits_checksum = dbl_to_u64(checksum);

        // Emit CSV row:
        // Inputs as decimal integers; outputs as uppercase hex without 0x prefix
        std::fprintf(f, "%d,%d,%d,%d,%d,%d,%llX,%llX,%llX,%llX\n",
                     cycle,
                     tsteps,
                     n,
