// hls.cpp
// Top-level Seidel stencil implementation for Vivado HLS.
// The top function is declared with extern "C" to avoid C++ name mangling
// so that the HLS tool (and the cosim harness) can link to it.

#include <stddef.h>

extern "C" {

void seidel(int tsteps, int n, double A[120][120]) {
#pragma HLS INTERFACE m_axi port=A offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=tsteps bundle=control
#pragma HLS INTERFACE s_axilite port=n bundle=control
#pragma HLS INTERFACE s_axilite port=A bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    const double inv9 = 1.0 / 9.0;

    // Time-stepped 2D Jacobi-style update (9-point average),
    // in-place update as in the original Seidel kernel.
    for (int t = 0; t < tsteps; t++) {
        for (int i = 1; i < n - 1; i++) {
            for (int j = 1; j < n - 1; j++) {
#pragma HLS pipeline II=1
                A[i][j] = (A[i - 1][j - 1] + A[i - 1][j] + A[i - 1][j + 1] +
                           A[i][j - 1]     + A[i][j]     + A[i][j + 1] +
                           A[i + 1][j - 1] + A[i + 1][j] + A[i + 1][j + 1]) * inv9;
            }
        }
    }
}

} // extern "C"

