// tb_hls_cosim.cpp
// Testbench for Vivado HLS cosimulation (C++98-compatible).
// Produces a CSV file with a few selected matrix entries and a checksum.
// Avoids C++11 headers; uses C headers and C++98 features only.

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

/* Declare the DUT with C linkage so that the HLS-generated cosim
   wrapper can resolve the symbol. */
extern "C" void seidel(int tsteps, int n, double A[120][120]);

/* Convert a double to its 64-bit IEEE-754 bit pattern.
   Return type uses unsigned long long for portability with older runtimes. */
static unsigned long long dbl_to_u64(double v) {
    unsigned long long x = 0ULL;
    /* Use memcpy to avoid strict-aliasing and type-punning issues. */
    memcpy(&x, &v, sizeof(v));
    return x;
}

int main() {
    const int cycles = 30; // produce 30 cycles => 30 data rows
    FILE *f = fopen("hls_output.csv", "w");
    if (!f) return 1;

    // CSV header: cycle, then inputs, then outputs
    // Inputs we drive (testbench signals): tsteps, n, pattern_id, rst, en
    // Outputs we sample from DUT: out_A_1_1, out_A_2_3, out_A_60_60, out_checksum
    fprintf(f, "cycle,tsteps,n,pattern_id,rst,en,out_A_1_1,out_A_2_3,out_A_60_60,out_checksum\n");
    // Roles row
    fprintf(f, "meta,in,in,in,in,in,out,out,out,out\n");

    // Deterministic test vectors for tsteps, n, pattern_id
    int tsteps_vec[cycles];
    int n_vec[cycles];
    int pattern_vec[cycles];

    int i;
    for (i = 0; i < cycles; ++i) {
        // vary tsteps deterministically but keep reasonable values
        tsteps_vec[i] = (i % 5) * 10; // 0,10,20,30,40, then repeat
        n_vec[i] = 120; // the function expects a 120-sized array; keep constant
        pattern_vec[i] = i % 6; // six different initialization patterns (0..5)
    }

    for (int cycle = 0; cycle < cycles; ++cycle) {
        int rst = (cycle < 2) ? 1 : 0; // reset active for first 2 cycles
        int en  = (cycle < 2) ? 0 : 1; // enable low for first 2 cycles

        int tsteps = tsteps_vec[cycle];
        int n = n_vec[cycle];
        int pattern_id = pattern_vec[cycle];

        // Initialize A deterministically according to pattern_id and cycle index
        double A[120][120];
        int ii, jj;
        for (ii = 0; ii < 120; ++ii) {
            for (jj = 0; jj < 120; ++jj) {
                double val = 0.0;
                switch (pattern_id) {
                    case 0:
                        // all zeros
                        val = 0.0;
                        break;
                    case 1:
                        // uniform value depending on cycle
                        val = 1.0 + (double)cycle;
                        break;
                    case 2:
                        // ramp pattern
                        val = (double)(ii * 120 + jj + cycle);
                        break;
                    case 3:
                        // checkerboard toggling with cycle
                        val = ((ii + jj + cycle) & 1) ? 1.0 : 0.0;
                        break;
                    case 4:
                        // border ones, interior zero
                        if (ii == 0 || jj == 0 || ii == 119 || jj == 119) val = 1.0;
                        else val = 0.0;
                        break;
                    case 5:
                        // diagonal weighted by index
                        val = (ii == jj) ? (double)(ii + cycle) : 0.0;
                        break;
                    default:
                        val = 0.0;
                }
                A[ii][jj] = val;
            }
        }

        // If reset is active, emulate reset by zeroing A regardless of pattern (deterministic)
        if (rst) {
            for (ii = 0; ii < 120; ++ii)
                for (jj = 0; jj < 120; ++jj)
                    A[ii][jj] = 0.0;
        }

        // Call DUT every cycle as required
        seidel(tsteps, n, A);

        // Sample outputs: pick a few matrix entries and a checksum
        double outA11 = A[1][1];
        double outA23 = A[2][3];
        double outA6060 = A[60][60];

        double checksum = 0.0;
        for (ii = 0; ii < 120; ++ii)
            for (jj = 0; jj < 120; ++jj)
                checksum += A[ii][jj];

        unsigned long long bits_A11 = dbl_to_u64(outA11);
        unsigned long long bits_A23 = dbl_to_u64(outA23);
        unsigned long long bits_A6060 = dbl_to_u64(outA6060);
        unsigned long long bits_checksum = dbl_to_u64(checksum);

        // Emit CSV row:
        // Inputs as decimal integers; outputs as uppercase hex without 0x prefix
        fprintf(f, "%d,%d,%d,%d,%d,%d,%llX,%llX,%llX,%llX\n",
                     cycle,
                     tsteps,
                     n,
                     pattern_id,
                     rst,
                     en,
                     (unsigned long long)bits_A11,
                     (unsigned long long)bits_A23,
                     (unsigned long long)bits_A6060,
                     (unsigned long long)bits_checksum
        );
    }

    fclose(f);
    return 0;
}

