static void InvIP(des_state_t *state, des_block_t *in) {
    (*in)[0] = BITNUMINTR((*state)[1], 7, 7) | BITNUMINTR((*state)[0], 7, 6) |
               BITNUMINTR((*state)[1], 15, 5) | BITNUMINTR((*state)[0], 15, 4) |
               BITNUMINTR((*state)[1], 23, 3) | BITNUMINTR((*state)[0], 23, 2) |
