        /* 17-24: more diverse */
        {0xFF,0x00,0xFF,0x00,0xFF,0x00,0xFF,0x00},
        {0x00,0xFF,0x00,0xFF,0x00,0xFF,0x00,0xFF},
        {0x12,0x34,0x56,0x78,0x9A,0xBC,0xDE,0xF0},
        {0xF0,0xDE,0xBC,0x9A,0x78,0x56,0x34,0x12},
        {0x00,0x11,0x22,0x33,0x44,0x55,0x66,0x77},
        {0x88,0x99,0xAA,0xBB,0xCC,0xDD,0xEE,0xFF},
        {0xFE,0xDC,0xBA,0x98,0x76,0x54,0x32,0x10},
        {0x01,0x01,0x02,0x03,0x05,0x08,0x0D,0x15},
        /* 25-31: leftovers */
        {0xDE,0xAD,0xBE,0xEF,0x00,0x11,0x22,0x33},
        {0x44,0x55,0x66,0x77,0x88,0x99,0xAA,0xBB},
        {0xCC,0xDD,0xEE,0xFF,0x00,0xFF,0x00,0xFF},
        {0x13,0x37,0xC0,0xFF,0xEE,0xBE,0xBA,0xAD},
        {0x00,0x00,0x00,0x01,0x00,0x00,0x00,0x02},
        {0x7F,0x7E,0x7D,0x7C,0x7B,0x7A,0x79,0x78},
        {0x10,0x32,0x54,0x76,0x98,0xBA,0xDC,0xFE}
    };

    /* Output CSV file */
    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) {
        std::perror("Failed to open c_output.csv");
        return 1;
    }

    /* Build CSV header:
     * cycle,key_bytes_0..7,plain_0..7,out_0..7
     */
    std::fprintf(f, "cycle");
    for (int i = 0; i < 8; ++i) std::fprintf(f, ",key_bytes_%d", i);
    for (int i = 0; i < 8; ++i) std::fprintf(f, ",plain_%d", i);
    for (int i = 0; i < 8; ++i) std::fprintf(f, ",out_%d", i);
    std::fprintf(f, "\n");

    /* Second row: roles */
    std::fprintf(f, "meta");
    for (int i = 0; i < 8; ++i) std::fprintf(f, ",in");
    for (int i = 0; i < 8; ++i) std::fprintf(f, ",in");
    for (int i = 0; i < 8; ++i) std::fprintf(f, ",out");
    std::fprintf(f, "\n");

    /* Testbench runtime variables (names correspond to CSV columns) */
    unsigned int cycle;
    unsigned char key_bytes_arr[8];
    unsigned char key_bytes_0, key_bytes_1, key_bytes_2, key_bytes_3;
    unsigned char key_bytes_4, key_bytes_5, key_bytes_6, key_bytes_7;

    unsigned char plain_0, plain_1, plain_2, plain_3;
    unsigned char plain_4, plain_5, plain_6, plain_7;

    unsigned char out_0, out_1, out_2, out_3;
    unsigned char out_4, out_5, out_6, out_7;

    des_key_t schedule;
    des_block_t inblock;
    des_block_t outblock;

    /* For each cycle, drive inputs deterministically, run DUT, sample outputs */
    for (cycle = 0; cycle < CYCLES; ++cycle) {
        /* Drive key bytes and plaintext bytes from vectors */
        for (int b = 0; b < 8; ++b) {
            key_bytes_arr[b] = test_keys[cycle][b];
        }
        key_bytes_0 = key_bytes_arr[0];
        key_bytes_1 = key_bytes_arr[1];
        key_bytes_2 = key_bytes_arr[2];
        key_bytes_3 = key_bytes_arr[3];
        key_bytes_4 = key_bytes_arr[4];
        key_bytes_5 = key_bytes_arr[5];
        key_bytes_6 = key_bytes_arr[6];
        key_bytes_7 = key_bytes_arr[7];

        for (int b = 0; b < 8; ++b) {
            inblock[b] = test_plains[cycle][b];
        }
        plain_0 = inblock[0];
        plain_1 = inblock[1];
        plain_2 = inblock[2];
        plain_3 = inblock[3];
        plain_4 = inblock[4];
        plain_5 = inblock[5];
        plain_6 = inblock[6];
        plain_7 = inblock[7];

        /* Prepare key schedule and run DES encryption */
        des_key_setup(key_bytes_arr, schedule, DES_ENCRYPT);
        des(&inblock, &outblock, &schedule);

        /* Sample outputs */
        out_0 = outblock[0];
        out_1 = outblock[1];
        out_2 = outblock[2];
        out_3 = outblock[3];
        out_4 = outblock[4];
        out_5 = outblock[5];
        out_6 = outblock[6];
        out_7 = outblock[7];

        /* Write a CSV row:
         * cycle (decimal), inputs (decimal), outputs (HEX uppercase, no 0x)
         */
        std::fprintf(f, "%u", (unsigned)cycle);

        /* key bytes as decimal */
        std::fprintf(f, ",%u", (unsigned)key_bytes_0);
        std::fprintf(f, ",%u", (unsigned)key_bytes_1);
        std::fprintf(f, ",%u", (unsigned)key_bytes_2);
        std::fprintf(f, ",%u", (unsigned)key_bytes_3);
        std::fprintf(f, ",%u", (unsigned)key_bytes_4);
        std::fprintf(f, ",%u", (unsigned)key_bytes_5);
        std::fprintf(f, ",%u", (unsigned)key_bytes_6);
        std::fprintf(f, ",%u", (unsigned)key_bytes_7);

        /* plain bytes as decimal */
        std::fprintf(f, ",%u", (unsigned)plain_0);
        std::fprintf(f, ",%u", (unsigned)plain_1);
        std::fprintf(f, ",%u", (unsigned)plain_2);
        std::fprintf(f, ",%u", (unsigned)plain_3);
        std::fprintf(f, ",%u", (unsigned)plain_4);
        std::fprintf(f, ",%u", (unsigned)plain_5);
        std::fprintf(f, ",%u", (unsigned)plain_6);
        std::fprintf(f, ",%u", (unsigned)plain_7);

        /* outputs as HEX uppercase without 0x, no fixed width */
        std::fprintf(f, ",%X", (unsigned)out_0);
        std::fprintf(f, ",%X", (unsigned)out_1);
        std::fprintf(f, ",%X", (unsigned)out_2);
        std::fprintf(f, ",%X", (unsigned)out_3);
        std::fprintf(f, ",%X", (unsigned)out_4);
        std::fprintf(f, ",%X", (unsigned)out_5);
        std::fprintf(f, ",%X", (unsigned)out_6);
        std::fprintf(f, ",%X", (unsigned)out_7);

        std::fprintf(f, "\n");
    }

    /* Explicitly close file */
    std::fclose(f);

    return 0;
}

