// hls.cpp
// DES key schedule implementation for Vivado HLS.
// Top-level function uses extern "C" linkage as required by the HLS testbench.
//
// This file avoids C++11 headers and uses plain C-style types so it is
// compatible with Vivado HLS 2018.3 (Clang 3.1 + old libstdc++).

extern "C" {

// Basic type aliases used by the testbench/DUT.
#define DES_BLOCK_SIZE 8

typedef unsigned char des_key_t[16][6];
typedef unsigned char des_subkey_t[6];
typedef unsigned char des_block_t[8];
typedef unsigned int des_state_t[2];

typedef enum { DES_ENCRYPT, DES_DECRYPT } DES_MODE;

/* Bit extraction macros:
 * - BITNUM extracts a single bit from a byte array and places it at
 *   a destination bit position.
 * - BITNUMINTR extracts a bit from a 32-bit integer (right-shift based).
 * - BITNUMINTL extracts a bit from a 32-bit integer using left-shift then mask.
 *
 * These are written in a form suitable for HLS translation.
 */
#define BITNUM(a, b, c) (((a[(b) / 8] >> (7 - ((b) % 8))) & 0x01) << (c))
#define BITNUMINTR(a, b, c) ((((a) >> (31 - (b))) & 0x00000001) << (c))
#define BITNUMINTL(a, b, c) ((((a) << (b)) & 0x80000000) >> (c))

#define SBOXBIT(a) (((a) & 0x20) | (((a) & 0x1f) >> 1) | (((a) & 0x01) << 4))

/* S-box tables (static const for internal linkage) */
