    TYPE filter_vals[f_size] = {
         1,  0, -1,
         2,  0, -2,
         1,  0, -1
    };
    for (int i = 0; i < f_size; ++i) filter[i] = filter_vals[i];

    // Initialize sol to zero
    for (int i = 0; i < row_size * col_size; ++i) sol[i] = 0;

