    std::ofstream ofs("c_output.csv", std::ofstream::out | std::ofstream::trunc);
    if (!ofs.is_open()) {
        std::perror("Failed to open c_output.csv");
        return 1;
    }

    // Header row
    // cycle, inputs: reset,en, orig[0]..orig[15], filter[0]..filter[8], outputs: sol[0]..sol[15]
    ofs << "cycle";
    ofs << ",reset,en";
    for (int i = 0; i < row_size * col_size; ++i) {
        ofs << ",orig[" << i << "]";
    }
    for (int i = 0; i < f_size; ++i) {
        ofs << ",filter[" << i << "]";
