    const int total_cycles = 6; // small bounded number
    // Prepare zeroed arrays for reset behavior
    TYPE orig_zero[row_size * col_size];
    TYPE filter_zero[f_size];
    for (int i = 0; i < row_size * col_size; ++i) orig_zero[i] = 0;
    for (int i = 0; i < f_size; ++i) filter_zero[i] = 0;

    for (int cycle = 0; cycle < total_cycles; ++cycle) {
        int reset = (cycle < 2) ? 1 : 0; // first 2 cycles reset active
        int en = (cycle < 2) ? 0 : 1;    // en=0 while reset active, then en=1

        // Select inputs for this cycle: if reset or en==0, drive zeros to DUT
        TYPE *cur_orig = (reset || !en) ? orig_zero : orig;
        TYPE *cur_filter = (reset || !en) ? filter_zero : filter;

        // Call DUT every cycle as required
        // The DUT writes into sol; to ensure deterministic behavior, zero sol before call
        for (int i = 0; i < row_size * col_size; ++i) sol[i] = 0;
        stencil(cur_orig, sol, cur_filter);

        // Write CSV row
        std::ostringstream row;
        // cycle
        row << cycle;
        // inputs: reset,en
        row << "," << reset << "," << en;
        // orig elements in decimal
        for (int i = 0; i < row_size * col_size; ++i) {
            row << "," << (int)cur_orig[i];
        }
        // filter elements in decimal
        for (int i = 0; i < f_size; ++i) {
            row << "," << (int)cur_filter[i];
        }
        // outputs sol elements in HEX uppercase, no 0x, no fixed width
        for (int i = 0; i < row_size * col_size; ++i) {
            // Cast to unsigned to get two's complement hex for negative numbers
            uint32_t uv = static_cast<uint32_t>(sol[i]);
            std::ostringstream h;
            h << std::uppercase << std::hex << uv;
            row << "," << h.str();
        }

        ofs << row.str() << "\n";
    }

    ofs.close();
    return 0;
}

