// hls.cpp
// Vivado HLS top-level implementation for block matrix multiply partial sum.
// This version matches the cosimulation testbench interface (BlockStream)
// and is written to compile under the older C++98 toolchain used by Vivado HLS.
//
// Notes:
// - The top-level function uses extern "C" as required.
// - A is declared static so that it retains previously loaded values across calls.
// - The BlockStream type mirrors the testbench BlockStream so the signatures match.
// - Avoids use of std::vector to be compatible with older libstdc++ versions.

#include <stdint.h>
#include <string.h>

#define SIZE 4
#define BLOCK_SIZE 2

typedef uint32_t DTYPE;

typedef struct {
    DTYPE a[BLOCK_SIZE];
} blockvec;

typedef struct {
    DTYPE out[BLOCK_SIZE][BLOCK_SIZE];
} blockmat;

// Simple fixed-capacity BlockStream that matches the testbench BlockStream.
// Implemented with a circular buffer to avoid dependency on std::vector.
struct BlockStream {
    // Capacity should be large enough for the testbench use.
    enum { CAP = 256 };
    blockvec buf[CAP];
    int head;
    int tail;
    int count;
    // Default constructor initializes indices
    BlockStream() : head(0), tail(0), count(0) {}
    // Append an element to the stream (no overflow checking for simplicity)
    void write(const blockvec &v) {
        if (count < CAP) {
            buf[tail] = v;
            tail = (tail + 1) % CAP;
            ++count;
        } else {
            // If the buffer were to overflow, drop the new entry.
            // For the provided testbench CAP is sufficiently large.
        }
    }
    // Read an element from the stream. If empty, return zero-initialized blockvec.
    blockvec read() {
        blockvec zero;
        // Ensure zero-initialized
        for (int i = 0; i < BLOCK_SIZE; ++i) zero.a[i] = 0;
        if (count == 0) return zero;
        blockvec v = buf[head];
        head = (head + 1) % CAP;
        --count;
        return v;
    }
};

extern "C" void block_mm(
    BlockStream &Arows, // stream-like container for block rows
    BlockStream &Bcols, // stream-like container for block columns
    blockmat &ABpartial,
    int it
) {
    // Counter determines when to (re)load A from the Arows stream.
    int counter = it % (SIZE / BLOCK_SIZE);

    // Persistent storage for A so values remain across function invocations.
    static DTYPE A[BLOCK_SIZE][SIZE];
    // Initialize static memory once.
    static bool initialized = false;
    if (!initialized) {
        for (int ii = 0; ii < BLOCK_SIZE; ++ii)
            for (int jj = 0; jj < SIZE; ++jj)
                A[ii][jj] = 0;
        initialized = true;
    }

    // If counter==0, read SIZE blockvec entries from Arows and store into A.
    if (counter == 0) {
        for (int i = 0; i < SIZE; i++) {
            blockvec tempA = Arows.read();
            for (int j = 0; j < BLOCK_SIZE; j++) {
                A[j][i] = tempA.a[j];
            }
        }
    }

    // Local partial result, zero-initialized each call.
    DTYPE AB[BLOCK_SIZE][BLOCK_SIZE];
    for (int i = 0; i < BLOCK_SIZE; ++i)
        for (int j = 0; j < BLOCK_SIZE; ++j)
            AB[i][j] = 0;

    // For each k, read one blockvec from Bcols and accumulate A[*][k] * Bcols.a[*]
    for (int k = 0; k < SIZE; k++) {
        blockvec tempB = Bcols.read();
        for (int i = 0; i < BLOCK_SIZE; i++) {
            for (int j = 0; j < BLOCK_SIZE; j++) {
                AB[i][j] += A[i][k] * tempB.a[j];
            }
        }
    }

    // Write results back to output
    for (int i = 0; i < BLOCK_SIZE; i++) {
        for (int j = 0; j < BLOCK_SIZE; j++) {
            ABpartial.out[i][j] = AB[i][j];
        }
    }
}

