// hls.cpp
// Top-level block matrix multiply partial sum for Vivado HLS
// Uses C headers to be compatible with Vivado HLS (C++98 toolchain)

#include <stdint.h>

typedef int32_t DTYPE;
#define SIZE 4
#define BLOCK_SIZE 2

typedef struct {
    DTYPE a[BLOCK_SIZE];
} blockvec;

typedef struct {
    DTYPE out[BLOCK_SIZE][BLOCK_SIZE];
} blockmat;

extern "C" void block_mm(
    const blockvec *Arows, // pointer to input blockvec array representing A rows
    const blockvec *Bcols, // pointer to input blockvec array representing B columns
    blockmat *ABpartial,   // pointer to output blockmat
    int iteration
) {
#pragma HLS INTERFACE m_axi port=Arows offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=Bcols offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=ABpartial offset=slave bundle=gmem2
#pragma HLS INTERFACE s_axilite port=Arows bundle=control
#pragma HLS INTERFACE s_axilite port=Bcols bundle=control
#pragma HLS INTERFACE s_axilite port=ABpartial bundle=control
#pragma HLS INTERFACE s_axilite port=iteration bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int counter = iteration % (SIZE / BLOCK_SIZE);
    static DTYPE A[BLOCK_SIZE][SIZE];
#pragma HLS array_partition variable=A cyclic factor=2 dim=2

    if (counter == 0) {
        // Load A from external memory (Arows) into local buffer A
        loadA: for (int i = 0; i < SIZE; i++) {
#pragma HLS unroll factor=4
            blockvec tempA = Arows[i];
            for (int j = 0; j < BLOCK_SIZE; j++) {
#pragma HLS pipeline
                A[j][i] = tempA.a[j];
            }
        }
    }

    // Partial block result accumulator
    DTYPE AB[BLOCK_SIZE][BLOCK_SIZE] = {0};
#pragma HLS array_partition variable=AB cyclic factor=2 dim=2

    // Compute partial matrix multiplication using A and Bcols
    partialsum: for (int k = 0; k < SIZE; k++) {
#pragma HLS pipeline
        blockvec tempB = Bcols[k];
        for (int i = 0; i < BLOCK_SIZE; i++) {
#pragma HLS unroll factor=2
            for (int j = 0; j < BLOCK_SIZE; j++) {
#pragma HLS unroll
                AB[i][j] += A[i][k] * tempB.a[j];
            }
        }
    }

    // Write out partial result to external memory
    writeoutput: for (int i = 0; i < BLOCK_SIZE; i++) {
#pragma HLS unroll
        for (int j = 0; j < BLOCK_SIZE; j++) {
#pragma HLS pipeline
            ABpartial->out[i][j] = AB[i][j];
        }
    }
}

