// Testbench for block_mm compatible with Vivado HLS 2018.3 (C++98 toolchain)
// Uses plain C headers where appropriate to keep compatibility.

#include <stdio.h>
#include <stdlib.h>
#include <vector>
#include <string>
#include <sstream>
#include <fstream>
#include <iostream>
#include <iomanip>
#include <cassert>
#include <stdint.h>

using namespace std;

// DUT-related type and constants (match hls.cpp)
typedef int32_t DTYPE;
const int SIZE = 4;
const int BLOCK_SIZE = 2;

typedef struct {
  DTYPE a[BLOCK_SIZE];
} blockvec;

typedef struct {
  DTYPE out[BLOCK_SIZE][BLOCK_SIZE];
} blockmat;

// Simple FIFO stream to emulate Stream-like behavior for the testbench
struct Stream {
  std::vector<blockvec> fifo;
  void write(const blockvec &v) { fifo.push_back(v); }
  blockvec read() {
    if (fifo.empty()) {
      // If underflow, return zeros (should not happen with proper testbench)
      blockvec z;
      for (int i = 0; i < BLOCK_SIZE; ++i) z.a[i] = 0;
      return z;
    }
    blockvec v = fifo.front();
    fifo.erase(fifo.begin());
    return v;
  }
  size_t size() const { return fifo.size(); }
};

// Declare DUT (must match HLS top signature exactly)
extern "C" void block_mm(const blockvec *Arows, const blockvec *Bcols, blockmat *ABpartial, int it);

// Helper: convert signed DTYPE to uppercase hex without 0x, using two's complement representation
static string to_hex_noprefix_upper(DTYPE val) {
  std::stringstream ss;
  ss << std::uppercase << std::hex << (static_cast<uint32_t>(val));
  string hx = ss.str();
  if (hx.empty()) hx = "0";
  return hx;
}

// Format a single blockvec as hex pair "H0:H1"
static string format_blockvec_hex(const blockvec &bv) {
  std::stringstream ss;
  ss << to_hex_noprefix_upper(bv.a[0]) << ":" << to_hex_noprefix_upper(bv.a[1]);
  return ss.str();
}

// Format list of count blockvecs from the stream's fifo starting at index 0 (without popping)
static string format_stream_peek(Stream &S, int count) {
  std::stringstream ss;
  for (int idx = 0; idx < count; ++idx) {
    if (idx > 0) ss << ";";
    if ((size_t)idx < S.fifo.size()) {
      ss << format_blockvec_hex(S.fifo[idx]);
    } else {
      // Underflow case in peek, represent as zeros
      blockvec z;
      for (int i = 0; i < BLOCK_SIZE; ++i) z.a[i] = 0;
      ss << format_blockvec_hex(z);
    }
  }
  return ss.str();
}

int main() {
  // Testbench configuration
  const int CYCLES = 24; // between 20 and 50
  Stream Arows;
  Stream Bcols;
  blockmat ABpartial;

  // Prepare deterministic test vectors (no randomness)
  // We need:
  // - For every time counter==0 (it % (SIZE/BLOCK_SIZE) == 0) -> reload Arows with SIZE elements.
  //   SIZE/BLOCK_SIZE = 2, so reload occurs on even it: 0,2,4,...
  // - For every call we need SIZE Bcols elements.
  // Pre-fill streams for all cycles.

  // Fill Arows for each reload (there will be ceil(CYCLES/2) reloads)
  int reloads = (CYCLES + 1) / 2;
  for (int r = 0; r < reloads; ++r) {
    // For each column i = 0..SIZE-1 produce a blockvec
    for (int i = 0; i < SIZE; ++i) {
      blockvec bv;
      // deterministic pattern: a[0] = (r+1)*100 + (i+1); a[1] = (r+1)*200 + (i+1)
      bv.a[0] = (r + 1) * 100 + (i + 1);
      bv.a[1] = (r + 1) * 200 + (i + 1);
      Arows.write(bv);
    }
  }

  // Fill Bcols for each cycle: for each cycle, SIZE blockvecs
  for (int c = 0; c < CYCLES; ++c) {
    for (int k = 0; k < SIZE; ++k) {
      blockvec bv;
      // deterministic pattern: a[0] = c*10 + (k+1); a[1] = c*1000 + (k+1)
      bv.a[0] = c * 10 + (k + 1);
      bv.a[1] = c * 1000 + (k + 1);
      Bcols.write(bv);
    }
  }

  // Open CSV file (HLS/RTL output)
  std::ofstream ofs("hls_output.csv");
  if (!ofs) {
    std::perror("Failed to open hls_output.csv");
    return 1;
  }

  // Header row:
  // cycle, then all inputs driven to DUT (Arows,Bcols,it), then DUT outputs ABpartial.out[...]
  ofs << "cycle,Arows,Bcols,it,ABpartial.out[0][0],ABpartial.out[0][1],ABpartial.out[1][0],ABpartial.out[1][1]\n";
  // Roles row: cycle meta; inputs are in; outputs are out
  ofs << "meta,in,in,in,out,out,out,out\n";

  // Prepare a zero buffer to pass when Arows is not reloaded on that cycle
  blockvec zeroA[SIZE];
  for (int i = 0; i < SIZE; ++i) {
    for (int j = 0; j < BLOCK_SIZE; ++j) zeroA[i].a[j] = 0;
  }

  // Run cycles
  for (int cycle = 0; cycle < CYCLES; ++cycle) {
    int it = cycle;

    // For Arows: DUT reads SIZE entries only when counter == 0
    int counter = it % (SIZE / BLOCK_SIZE);
    string arows_cell = "";
    const blockvec *Arows_ptr = &zeroA[0];

    if (counter == 0) {
      // Peek next SIZE entries from Arows (front of fifo)
      arows_cell = format_stream_peek(Arows, SIZE);
      // Point to the front of the Arows FIFO (will simulate consumption after DUT call)
      if (Arows.fifo.size() >= (size_t)SIZE) {
        Arows_ptr = &Arows.fifo[0];
      } else {
        // Not enough data: point to zero buffer to avoid invalid memory access
        Arows_ptr = &zeroA[0];
      }
    }

    // For Bcols: DUT reads SIZE entries every call. Use front of Bcols FIFO.
    string bcols_cell = format_stream_peek(Bcols, SIZE);
    const blockvec *Bcols_ptr = &zeroA[0];
    if (Bcols.fifo.size() >= (size_t)SIZE) {
      Bcols_ptr = &Bcols.fifo[0];
    } else {
      Bcols_ptr = &zeroA[0];
    }

    // Call DUT
    block_mm(Arows_ptr, Bcols_ptr, &ABpartial, it);

    // After DUT call, simulate the streams being consumed as the original Stream::read would do:
    // - If counter == 0, Arows consumed SIZE entries
    if (counter == 0) {
      if ((int)Arows.fifo.size() >= SIZE) {
        Arows.fifo.erase(Arows.fifo.begin(), Arows.fifo.begin() + SIZE);
      } else {
        Arows.fifo.clear();
      }
    }
    // - Bcols consumed SIZE entries every cycle
    if ((int)Bcols.fifo.size() >= SIZE) {
      Bcols.fifo.erase(Bcols.fifo.begin(), Bcols.fifo.begin() + SIZE);
    } else {
      Bcols.fifo.clear();
    }

    // Prepare CSV row:
    // cycle (decimal), inputs, it (decimal), outputs in hex uppercase without 0x
    ofs << cycle << ",";
    // Arows cell (if empty, leave empty)
    ofs << arows_cell << ",";
    ofs << bcols_cell << ",";
    ofs << it;
    for (int i = 0; i < BLOCK_SIZE; ++i) {
      for (int j = 0; j < BLOCK_SIZE; ++j) {
        ofs << ",";
        string hx = to_hex_noprefix_upper(ABpartial.out[i][j]);
        ofs << hx;
      }
    }
    ofs << "\n";
  }

  // Explicitly close output file as required
  ofs.close();

  // --- Additional small self-tests to increase coverage ---
  // 1) Test Stream underflow behavior (should return zeros)
  {
    Stream emptyS;
    blockvec z = emptyS.read(); // triggers underflow branch inside read()
    for (int i = 0; i < BLOCK_SIZE; ++i) {
      // expect zeros
      assert(z.a[i] == 0);
    }
  }

  // 2) Test Stream write/read/size functions
  {
    Stream s;
    blockvec w;
    w.a[0] = 7;
    w.a[1] = -3;
    s.write(w);
    assert(s.size() == 1);
    blockvec r = s.read();
    assert(s.size() == 0);
    assert(r.a[0] == 7 && r.a[1] == -3);
  }

  // 3) Test hex formatting helper with negative and positive values
  {
    DTYPE p = 123456;
    DTYPE n = -1; // expect two's complement to be printed
    string hp = to_hex_noprefix_upper(p);
    string hn = to_hex_noprefix_upper(n);
    // basic sanity checks
    assert(!hp.empty());
    assert(!hn.empty());
    // Example prints to stdout for developer visibility (safe)
    cout << "Example hex positive: " << hp << "  negative (two's complement): " << hn << endl;
  }

  // Indicate success
  cout << "HLS simulation finished. CSV file written to hls_output.csv" << endl;

  return 0;
}

