// hls.cpp
// Sobel edge detector top-level for Vivado HLS
// Note: keep the top-level as extern "C" so the testbench can link to it.
// WIDTH and HEIGHT are set to match the testbench (4) to avoid out-of-bounds accesses
// when the testbench supplies 4x4 images.
#include <stdint.h>
#include <stdlib.h> // provide abs() in the global namespace for older toolchains

#define WIDTH 4
#define HEIGHT 4

typedef unsigned char data_t;

extern "C" void sobel(int *inputImage, int *outputImage, int EDGE_THRESHOLD) {
#pragma HLS INTERFACE m_axi port=inputImage offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=outputImage offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=EDGE_THRESHOLD bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Line buffers have two extra columns for the left/right padding handling
    data_t lineBuffer1[WIDTH + 2];
#pragma HLS array_partition variable=lineBuffer1 cyclic factor=2 dim=1
#pragma HLS RESOURCE variable=lineBuffer1 core=RAM_2P_BRAM
    data_t lineBuffer2[WIDTH + 2];
#pragma HLS array_partition variable=lineBuffer2 block factor=2 dim=1
#pragma HLS RESOURCE variable=lineBuffer2 core=RAM_2P_BRAM
    data_t pixelWindow[3][3];
#pragma HLS array_partition variable=pixelWindow complete dim=2

    // Initialize buffers to zero to avoid depending on undefined memory contents
    for (int i = 0; i < WIDTH + 2; ++i) {
#pragma HLS unroll
        lineBuffer1[i] = 0;
        lineBuffer2[i] = 0;
    }
    for (int r = 0; r < 3; ++r) {
        for (int c = 0; c < 3; ++c) {
#pragma HLS unroll
            pixelWindow[r][c] = 0;
        }
    }

    // Sliding window over the image with 1-pixel zero padding on left/right and
    // implicit zero padding on the top (because line buffers start as zeros).
    // We iterate one extra row (row == HEIGHT) of zeros at the bottom to flush the
    // pipeline so that an output is produced for the last image row as well.
    for (int row = 0; row < HEIGHT + 1; row++) {
#pragma HLS pipeline
        for (int col = 0; col < WIDTH + 2; col++) {
#pragma HLS unroll factor=2
            data_t newPixel;

            // Left and right padded columns are set to zero
            if (col == 0 || col == WIDTH + 1) {
                newPixel = 0;
            } else if (row == HEIGHT) {
                // Extra bottom padding row: treat as zeros (do not read inputImage)
                newPixel = 0;
            } else {
                // inputImage is an array of ints (0..255 typically); cast into data_t
                newPixel = (data_t) inputImage[row * WIDTH + (col - 1)];
            }

            // Shift the 3x3 window left and insert newest column values
            pixelWindow[0][0] = pixelWindow[0][1];
            pixelWindow[0][1] = pixelWindow[0][2];
            pixelWindow[0][2] = lineBuffer1[col];
            pixelWindow[1][0] = pixelWindow[1][1];
            pixelWindow[1][1] = pixelWindow[1][2];
            pixelWindow[1][2] = lineBuffer2[col];
            pixelWindow[2][0] = pixelWindow[2][1];
            pixelWindow[2][1] = pixelWindow[2][2];
            pixelWindow[2][2] = newPixel;

            // Update line buffers (push newPixel into the newest line buffer slot)
            lineBuffer1[col] = lineBuffer2[col];
            lineBuffer2[col] = newPixel;

            // Only produce output when the full 3x3 window is valid (exclude padding cols)
            // row > 0 ensures we skip the very first (top) padding row; because we loop
            // up to HEIGHT inclusive, row==HEIGHT will produce outputs corresponding to
            // the last image row (using bottom padding).
            if (col > 0 && col < WIDTH + 1 && row > 0) {
                int Gx = (pixelWindow[0][0] + 2 * pixelWindow[0][1] + pixelWindow[0][2]) -
                         (pixelWindow[2][0] + 2 * pixelWindow[2][1] + pixelWindow[2][2]);
                int Gy = (pixelWindow[0][0] + 2 * pixelWindow[1][0] + pixelWindow[2][0]) -
                         (pixelWindow[0][2] + 2 * pixelWindow[1][2] + pixelWindow[2][2]);

                // Use C abs from <stdlib.h> to ensure availability in older toolchains
                int gradient = (int)(abs(Gx) + abs(Gy));

                if (gradient >= EDGE_THRESHOLD) {
                    gradient = 255;
                }

                // Write the output corresponding to the center of the 3x3 window;
                // note the row-1/col-1 because we started outputting only after the first row/col
                outputImage[(row - 1) * WIDTH + (col - 1)] = gradient;
            }
        }
    }
}

