// tb_hls_cosim.cpp
// Testbench for the sobel HLS top-level.
// This testbench is kept functionally identical to the original but uses C-style
// headers so it compiles with older C++98 toolchains bundled with Vivado HLS.

#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>
#include <stdint.h>

#define WIDTH 4

// DUT prototype must match the HLSC top-level function exactly
extern "C" void sobel(int *inputImage, int *outputImage, int EDGE_THRESHOLD);

int main() {
    const int CYCLES = 24; // produce between 20 and 50 CSV rows
    const int PIXELS = WIDTH * WIDTH;

    // Predefined thresholds for each cycle (deterministic)
    int thresholds[CYCLES] = {
        10, 20, 30, 40, 60, 80, 100, 120,
        140, 160, 180, 200, 15, 25, 50, 5,
        128, 200, 10, 255, 100, 40, 0, 30
    };

    // Open CSV file for HLS/RTL outputs
    FILE *f = fopen("hls_output.csv", "w");
    if (!f) return 1;

    // Header row: cycle, inputImage_0..inputImage_15, EDGE_THRESHOLD, outputImage_0..outputImage_15
    fprintf(f, "cycle");
    for (int i = 0; i < PIXELS; ++i) {
        fprintf(f, ",inputImage_%d", i);
    }
    fprintf(f, ",EDGE_THRESHOLD");
    for (int i = 0; i < PIXELS; ++i) {
        fprintf(f, ",outputImage_%d", i);
    }
    fprintf(f, "\n");

    // Role row: meta,in...,in,out...
    fprintf(f, "meta");
    for (int i = 0; i < PIXELS; ++i) fprintf(f, ",in");
    fprintf(f, ",in"); // EDGE_THRESHOLD
    for (int i = 0; i < PIXELS; ++i) fprintf(f, ",out");
    fprintf(f, "\n");

    // Buffers
    int inputImage[PIXELS];
    int outputImage[PIXELS];

    // Generate deterministic test vectors for each cycle and call DUT
    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        // Generate several distinct patterns deterministically
        if (cycle == 0) {
            // all zeros
            for (int p = 0; p < PIXELS; ++p) inputImage[p] = 0;
        } else if (cycle == 1) {
            // all max (255)
            for (int p = 0; p < PIXELS; ++p) inputImage[p] = 255;
        } else if (cycle == 2) {
            // checkerboard 0/255
            for (int r = 0; r < WIDTH; ++r) for (int c = 0; c < WIDTH; ++c)
                inputImage[c + r*WIDTH] = ((r + c) % 2) ? 255 : 0;
        } else if (cycle == 3) {
            // vertical stripes
            for (int r = 0; r < WIDTH; ++r) for (int c = 0; c < WIDTH; ++c)
                inputImage[c + r*WIDTH] = (c % 2) ? 255 : 0;
        } else if (cycle == 4) {
            // horizontal stripes
            for (int r = 0; r < WIDTH; ++r) for (int c = 0; c < WIDTH; ++c)
                inputImage[c + r*WIDTH] = (r % 2) ? 255 : 0;
        } else if (cycle == 5) {
            // diagonal gradient (small values)
            for (int r = 0; r < WIDTH; ++r) for (int c = 0; c < WIDTH; ++c)
                inputImage[c + r*WIDTH] = (r + c) * 32; // values within 0..~192
        } else if (cycle == 6) {
            // ramp by index
            for (int p = 0; p < PIXELS; ++p) inputImage[p] = (p * 10) % 256;
        } else if (cycle == 7) {
            // inverted ramp
            for (int p = 0; p < PIXELS; ++p) inputImage[p] = 255 - ((p * 10) % 256);
        } else if (cycle == 8) {
            // single impulse center
            for (int p = 0; p < PIXELS; ++p) inputImage[p] = 0;
            int mid = (WIDTH/2) + (WIDTH/2)*WIDTH;
            if (mid >= 0 && mid < PIXELS) inputImage[mid] = 255;
        } else if (cycle == 9) {
            // small 2x2 block in corner
            for (int p = 0; p < PIXELS; ++p) inputImage[p] = 0;
            inputImage[0] = 255;
            inputImage[1] = 255;
            inputImage[WIDTH] = 255;
            inputImage[WIDTH+1] = 255;
        } else {
            // deterministic arithmetic pattern for diversity
            for (int p = 0; p < PIXELS; ++p) {
                inputImage[p] = ( (p * 37) + (cycle * 13) ) % 256;
            }
        }

        int EDGE_THRESHOLD = thresholds[cycle];

        // Call DUT (this will be replaced by HLS/RTL cosim when applicable)
        sobel(inputImage, outputImage, EDGE_THRESHOLD);

        // Write CSV row: cycle, inputs (decimal), threshold, outputs (hex uppercase, no 0x)
        fprintf(f, "%d", cycle);
        for (int p = 0; p < PIXELS; ++p) {
            fprintf(f, ",%d", inputImage[p]);
        }
        fprintf(f, ",%d", EDGE_THRESHOLD);
        for (int p = 0; p < PIXELS; ++p) {
            int v = outputImage[p] & 0xFF;
            if (v == 0) {
                fprintf(f, ",0");
            } else {
                // print uppercase hex without 0x
                char buf[16];
                sprintf(buf, "%X", v);
                fprintf(f, ",%s", buf);
            }
        }
        fprintf(f, "\n");
    }

    fclose(f);
    return 0;
}

