#include "test.h"
#include <math.h>
#include <stdio.h>
#include <stdlib.h>
#include <inttypes.h>

static inline double fixed_to_double_int64(int64_t v) {
    return (double)v / (double)(1ULL << FRAC_BITS);
}

static inline int64_t double_to_fixed_int64(double d) {
    double scaled = d * (double)(1ULL << FRAC_BITS);
    if (scaled >= (double)INT64_C(0x7FFFFFFFFFFFFFFF)) return INT64_C(0x7FFFFFFFFFFFFFFF);
    if (scaled <= (double)INT64_C(-0x7FFFFFFFFFFFFFFF)) return INT64_C(-0x7FFFFFFFFFFFFFFF);
    return (int64_t)llround(scaled);
}

static inline data_t saturate_to_data_t(int64_t v) {
    if (v > INT16_MAX) return INT16_MAX;
    if (v < INT16_MIN) return INT16_MIN;
    return (data_t)v;
}

void top(data_t x[WIDTH], data_t A[WIDTH][WIDTH], data_t B[WIDTH][WIDTH], data_t y[WIDTH], data_t bias[1], data_t result[1]) {
    int64_t sum = 0;
    for (int i = 0; i < WIDTH; ++i) {
        int64_t prod_sum_ax = 0;
        int64_t prod_sum_by = 0;
        for (int j = 0; j < WIDTH; ++j) {
            prod_sum_ax += (int32_t)A[i][j] * (int32_t)x[j];
            prod_sum_by += (int32_t)B[i][j] * (int32_t)y[j];
        }
        int64_t ax = prod_sum_ax >> FRAC_BITS;
        int64_t by = prod_sum_by >> FRAC_BITS;
        sum += ax + by;
    }
    sum += (int64_t)bias[0];
    double sd = fixed_to_double_int64(sum);
    double s = 1.0 / (1.0 + exp(-sd));
    int64_t fixed_res = double_to_fixed_int64(s);
    result[0] = saturate_to_data_t(fixed_res);
}

int main() {
    static data_t x[WIDTH];
    static data_t y[WIDTH];
    static data_t A[WIDTH][WIDTH];
    static data_t B[WIDTH][WIDTH];
    static data_t bias[1];
    static data_t result[1];

    for (int i = 0; i < WIDTH; ++i) {
        double xv = 0.01 * (double)i;
        double yv = 0.02 * (double)i;
        int64_t fx = double_to_fixed_int64(xv);
        int64_t fy = double_to_fixed_int64(yv);
        x[i] = saturate_to_data_t(fx);
        y[i] = saturate_to_data_t(fy);
    }

    for (int i = 0; i < WIDTH; ++i) {
        for (int j = 0; j < WIDTH; ++j) {
            double aval = ((i + 1) * (j + 1)) * 0.0005;
            double bval = ((i + 1) - (j + 1)) * 0.0003;
            A[i][j] = saturate_to_data_t(double_to_fixed_int64(aval));
            B[i][j] = saturate_to_data_t(double_to_fixed_int64(bval));
        }
    }

    bias[0] = saturate_to_data_t(double_to_fixed_int64(0.0));

    top(x, A, B, y, bias, result);

    double out = fixed_to_double_int64((int64_t)result[0]);
    printf("Result fixed raw: %" PRId16 "\n", result[0]);
    printf("Result as double: %.12f\n", out);

    return 0;
}

