// hls.cpp
// HLS top-level and implementation using fixed-point integers compatible with
// the C-style cosimulation testbench (int16_t inputs/outputs).
//
// Comments and pragmas are in English.
// The top function uses extern "C" and a plain int16_t interface so that the
// provided C testbench (which typedefs data_t as int16_t) can call it
// directly. Internally we perform Q-format fixed-point arithmetic with
// FRAC_BITS fractional bits using wider integer accumulators to preserve
// precision and avoid overflow where possible.

#include <ap_int.h>
#include <stdint.h>

// Keep these constants in sync with the testbench
#define WIDTH 64
#define TOTAL_BITS 16
#define INT_BITS 5
#define FRAC_BITS (TOTAL_BITS - INT_BITS)

extern "C" {

// Use C-friendly 16-bit host type for DRAM interface
typedef int16_t host_t;

// Top-level function uses host_t arrays (C-compatible). Internally we do
// fixed-point integer arithmetic assuming inputs are Q(FRAC_BITS) format.
void top(host_t DRAM_x[WIDTH],
         host_t DRAM_A[WIDTH][WIDTH],
         host_t DRAM_B[WIDTH][WIDTH],
         host_t DRAM_y[WIDTH],
         host_t DRAM_bias[1],
         host_t DRAM_result[1]) {
#pragma HLS INTERFACE m_axi port=DRAM_x offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_A offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_B offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_y offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_bias offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_result offset=slave bundle=mem2
#pragma HLS INTERFACE s_axilite port=DRAM_x bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_A bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_B bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_y bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_bias bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_result bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local BRAM copies use the host type for storage of raw Q-format integers
    host_t BRAM_x[WIDTH];
    host_t BRAM_A[WIDTH][WIDTH];
    host_t BRAM_B[WIDTH][WIDTH];
    host_t BRAM_y[WIDTH];
    host_t BRAM_bias[1];
    host_t BRAM_result_host[1];

    // Intermediate buffers use wider integer types to avoid overflow during
    // accumulation. All intermediate values are kept in the same Q-format
    // (i.e., scaled by 2^FRAC_BITS).
    long long BRAM_gemm[WIDTH][WIDTH]; // stores gemm result in Q-format
    long long BRAM_mmv[WIDTH];         // stores mmv result in Q-format

    // Load inputs from DRAM into local BRAM buffers
    for (int idx0 = 0; idx0 < WIDTH; idx0++) {
#pragma HLS PIPELINE II=1
        BRAM_x[idx0] = DRAM_x[idx0];
    }

    for (int idx0 = 0; idx0 < WIDTH; idx0++) {
        for (int idx1 = 0; idx1 < WIDTH; idx1++) {
#pragma HLS PIPELINE II=1
            BRAM_A[idx0][idx1] = DRAM_A[idx0][idx1];
            BRAM_B[idx0][idx1] = DRAM_B[idx0][idx1];
        }
    }

    for (int idx0 = 0; idx0 < WIDTH; idx0++) {
#pragma HLS PIPELINE II=1
        BRAM_y[idx0] = DRAM_y[idx0];
    }

    // Bias is loaded but not used in the current computation (kept for API compatibility)
    for (int idx0 = 0; idx0 < 1; idx0++) {
#pragma HLS PIPELINE II=1
        BRAM_bias[idx0] = DRAM_bias[idx0];
    }

    // Partition arrays to help HLS parallelize memory accesses (keeps original hints).
#pragma HLS ARRAY_PARTITION variable=BRAM_B cyclic factor=8 dim=1
#pragma HLS ARRAY_PARTITION variable=BRAM_A cyclic factor=8 dim=2
#pragma HLS ARRAY_PARTITION variable=BRAM_B cyclic factor=8 dim=2
#pragma HLS ARRAY_PARTITION variable=BRAM_gemm cyclic factor=8 dim=2
#pragma HLS ARRAY_PARTITION variable=BRAM_y cyclic factor=8 dim=1
#pragma HLS ARRAY_PARTITION variable=BRAM_gemm cyclic factor=8 dim=2

    // GEMM: compute BRAM_gemm = BRAM_A * BRAM_B
    // We accumulate full precision products (in 64-bit) and then shift by FRAC_BITS
    // with rounding to produce a Q-format integer stored in BRAM_gemm.

    const long long ROUND_HALF = (1LL << (FRAC_BITS - 1));

    // Initialize BRAM_gemm to zero
    for (int i = 0; i < WIDTH; i++) {
#pragma HLS UNROLL factor=1
        for (int k = 0; k < WIDTH; k++) {
#pragma HLS UNROLL factor=1
            BRAM_gemm[i][k] = 0;
        }
    }

    // Compute gemm: for each (i,k) accumulate sum_j A[i][j] * B[j][k]
    // Then shift once by FRAC_BITS with rounding.
    for (int i = 0; i < WIDTH; i++) {
        for (int k = 0; k < WIDTH; k++) {
#pragma HLS PIPELINE II=1
            long long acc = 0;
            for (int j = 0; j < WIDTH; j++) {
#pragma HLS UNROLL factor=1
                acc += (long long)BRAM_A[i][j] * (long long)BRAM_B[j][k];
            }
            // Round-to-nearest while shifting right by FRAC_BITS
            if (acc >= 0) acc = (acc + ROUND_HALF) >> FRAC_BITS;
            else acc = (acc - ROUND_HALF) >> FRAC_BITS;
            BRAM_gemm[i][k] = acc;
        }
    }

    // MMV: BRAM_mmv = BRAM_gemm * BRAM_y (matrix-vector multiplication)
    // Each product BRAM_gemm[i][j] * BRAM_y[j] is in Q-format^2, so we sum and shift by FRAC_BITS.
    for (int i = 0; i < WIDTH; i++) {
#pragma HLS UNROLL factor=1
        BRAM_mmv[i] = 0;
    }

    for (int i = 0; i < WIDTH; i++) {
#pragma HLS PIPELINE II=1
        long long acc = 0;
        for (int j = 0; j < WIDTH; j++) {
#pragma HLS UNROLL factor=1
            acc += BRAM_gemm[i][j] * (long long)BRAM_y[j];
        }
        if (acc >= 0) acc = (acc + ROUND_HALF) >> FRAC_BITS;
        else acc = (acc - ROUND_HALF) >> FRAC_BITS;
        BRAM_mmv[i] = acc;
    }

    // Dot product: result = x . mmv
    long long dot_acc = 0;
    for (int i = 0; i < WIDTH; i++) {
#pragma HLS UNROLL factor=1
        dot_acc += (long long)BRAM_x[i] * BRAM_mmv[i];
    }
    if (dot_acc >= 0) dot_acc = (dot_acc + ROUND_HALF) >> FRAC_BITS;
    else dot_acc = (dot_acc - ROUND_HALF) >> FRAC_BITS;

    // Saturate to 16-bit signed before writing back
    long long max_val = (1LL << (TOTAL_BITS - 1)) - 1;
    long long min_val = -(1LL << (TOTAL_BITS - 1));
    long long saturated = dot_acc;
    if (saturated > max_val) saturated = max_val;
    if (saturated < min_val) saturated = min_val;

    BRAM_result_host[0] = (host_t)saturated;

    // Write result back to DRAM
    for (int idx0 = 0; idx0 < 1; idx0++) {
#pragma HLS PIPELINE II=1
        DRAM_result[idx0] = BRAM_result_host[idx0];
    }
}

} // extern "C"

