// tb_hls_cosim.cpp
// C-style testbench for HLS cosimulation (C++98-compatible).
// Comments are in English. This file must remain compatible with Vivado HLS'
// older C++ toolchain, so we use C headers like <stdint.h>.

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>
#include <limits.h>

// Keep macros and typedefs identical to the C testbench
#define WIDTH 64
#define TOTAL_BITS 16
#define INT_BITS 5
#define FRAC_BITS (TOTAL_BITS - INT_BITS)

typedef int16_t data_t;

// Declare top exactly as in HLSC (extern "C" must match HLSC definition)
extern "C" void top(data_t x[WIDTH], data_t A[WIDTH][WIDTH], data_t B[WIDTH][WIDTH], data_t y[WIDTH], data_t bias[1], data_t result[1]);

// Helper conversion functions replicated from the C testbench
static inline double fixed_to_double_int64(int64_t v) {
    return (double)v / (double)(1ULL << FRAC_BITS);
}

// Round-to-nearest implementation without llround (C++98 compatibility)
static inline int64_t round_to_int64(double v) {
    if (v >= 0.0) return (int64_t)(v + 0.5);
    else return (int64_t)(v - 0.5);
}

static inline int64_t double_to_fixed_int64(double d) {
    double scaled = d * (double)(1ULL << FRAC_BITS);
    // Saturate to int64_t bounds if necessary
    if (scaled >= (double)LLONG_MAX) return LLONG_MAX;
    if (scaled <= (double)LLONG_MIN) return LLONG_MIN;
    return round_to_int64(scaled);
}

static inline data_t saturate_to_data_t(int64_t v) {
    if (v > INT16_MAX) return (data_t)INT16_MAX;
    if (v < INT16_MIN) return (data_t)INT16_MIN;
    return (data_t)v;
}

int main() {
    static data_t x[WIDTH];
    static data_t y[WIDTH];
    static data_t A[WIDTH][WIDTH];
    static data_t B[WIDTH][WIDTH];
    static data_t bias[1];
    static data_t result[1];

    // Initialize x and y with the same deterministic small ramp values
    int i, j;
    for (i = 0; i < WIDTH; ++i) {
        double xv = 0.01 * (double)i; // 0, 0.01, 0.02, ...
        double yv = 0.02 * (double)i; // 0, 0.02, 0.04, ...
        int64_t fx = double_to_fixed_int64(xv);
        int64_t fy = double_to_fixed_int64(yv);
        x[i] = saturate_to_data_t(fx);
        y[i] = saturate_to_data_t(fy);
    }

    // Initialize A and B with the same deterministic small values
    for (i = 0; i < WIDTH; ++i) {
        for (j = 0; j < WIDTH; ++j) {
            double aval = ((i + 1) * (j + 1)) * 0.0005; // small positive
            double bval = ((i + 1) - (j + 1)) * 0.0003; // can be negative
            A[i][j] = saturate_to_data_t(double_to_fixed_int64(aval));
            B[i][j] = saturate_to_data_t(double_to_fixed_int64(bval));
        }
    }

    // Prepare deterministic bias test vectors (32 cycles)
    const int CYCLES = 32;
    double bias_dbl[CYCLES];
    // Linearly spaced from -3.0 to +3.0 inclusive
    for (int c = 0; c < CYCLES; ++c) {
        bias_dbl[c] = -3.0 + (6.0 * (double)c) / (double)(CYCLES - 1);
    }

    // Open HLS/RTL output CSV file
    FILE *f = fopen("hls_output.csv", "w");
    if (!f) {
        return 1;
    }

    // CSV header: cycle, then the input(s) we vary (bias), then outputs (result)
    // This mirrors the original C testbench CSV format: cycle,bias,result
    fprintf(f, "cycle,bias,result\n");
    // Roles row
    fprintf(f, "meta,in,out\n");

    // Run cycles: at each cycle set bias and call top, then record outputs
    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        // Set bias deterministically (fixed-point)
        int64_t fb = double_to_fixed_int64(bias_dbl[cycle]);
        bias[0] = saturate_to_data_t(fb);

        // Call DUT (HLS top)
        top(x, A, B, y, bias, result);

        // Output: bias as decimal integer, result as uppercase hex without 0x and without fixed width
        uint16_t result_bits = (uint16_t)result[0];
        fprintf(f, "%d,%d,%X\n", cycle, (int)bias[0], (unsigned)result_bits);
    }

    fclose(f);
    return 0;
}

