// hls.cpp
// HLS top function for blocked matrix multiply (fixed small test sizes)
// Comments in English
#include <stdint.h>

typedef uint32_t DTYPE;
#define SIZE 8
#define BLOCK_SIZE 2

typedef struct {
    DTYPE a[BLOCK_SIZE];
} blockvec;

typedef struct {
    DTYPE out[BLOCK_SIZE][BLOCK_SIZE];
} blockmat;

extern "C" void block_mm(
    const DTYPE Arows[SIZE][BLOCK_SIZE],
    const DTYPE Bcols[SIZE][BLOCK_SIZE],
    DTYPE ABpartial[BLOCK_SIZE][BLOCK_SIZE],
    int it
) {
#pragma HLS INTERFACE m_axi port=Arows offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=Bcols offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=ABpartial offset=slave bundle=gmem2
#pragma HLS INTERFACE s_axilite port=Arows bundle=control
#pragma HLS INTERFACE s_axilite port=Bcols bundle=control
#pragma HLS INTERFACE s_axilite port=ABpartial bundle=control
#pragma HLS INTERFACE s_axilite port=it bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int counter = it % (SIZE / BLOCK_SIZE);

    // Local A is stored with BLOCK_SIZE rows and SIZE columns
    DTYPE A[BLOCK_SIZE][SIZE];
#pragma HLS array_partition variable=A cyclic factor=4 dim=1

    // Load A only when counter == 0 (emulates tiled load)
    if (counter == 0) {
        loadA: for (int i = 0; i < SIZE; i++) {
#pragma HLS unroll factor=4
            for (int j = 0; j < BLOCK_SIZE; j++) {
#pragma HLS unroll factor=4
                A[j][i] = Arows[i][j];
            }
        }
    }

    // Partial AB accumulator
    DTYPE AB[BLOCK_SIZE][BLOCK_SIZE] = {0};
#pragma HLS array_partition variable=AB complete dim=2

    // Compute partial sums over full SIZE dimension
    partialsum: for (int k = 0; k < SIZE; k++) {
#pragma HLS unroll factor=2
        for (int i = 0; i < BLOCK_SIZE; i++) {
#pragma HLS pipeline
            for (int j = 0; j < BLOCK_SIZE; j++) {
#pragma HLS unroll factor=2
                AB[i][j] += A[i][k] * Bcols[k][j];
            }
        }
    }

    // Write back partial result
    writeoutput: for (int i = 0; i < BLOCK_SIZE; i++) {
#pragma HLS unroll factor=8
        for (int j = 0; j < BLOCK_SIZE; j++) {
#pragma HLS pipeline
            ABpartial[i][j] = AB[i][j];
        }
    }
}

