#define GRID_ROWS (1024)
#define SIZE GRID_ROWS
#define TILE_ROWS 32
#define PARA_FACTOR 16
#define TOP 0
#define BOTTOM (GRID_ROWS / TILE_ROWS - 1)
#define GAMMA 1.4
#define NDIM 3
#define NNB 4
#define RK 3
#define ff_mach 1.2
#define deg_angle_of_attack 0.0f
#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)
#define TYPE float

typedef struct { float x, y, z; } float3;

void cfd_flux_kernel(float result[SIZE * NVAR], int elements_surrounding_elements [SIZE * NNB], float normals [SIZE * NNB * NDIM], float variables [SIZE * NVAR], float fc_momentum_x [SIZE * NDIM], float fc_momentum_y [SIZE * NDIM], float fc_momentum_z [SIZE * NDIM], float fc_density_energy [SIZE * NDIM]);

void cfd_flux(float result[SIZE * NVAR], int elements_surrounding_elements [SIZE * NNB], float normals [SIZE * NNB * NDIM], 
                float variables [SIZE * NVAR], float fc_momentum_x [SIZE * NDIM], float fc_momentum_y [SIZE * NDIM], 
                float fc_momentum_z [SIZE * NDIM], float fc_density_energy [SIZE * NDIM]);

static inline void compute_velocity(float density, const float3* momentum, float3* velocity)
{
    velocity->x = momentum->x / density;
    velocity->y = momentum->y / density;
    velocity->z = momentum->z / density;
}

static inline float compute_speed_sqd(const float3* velocity)
{
    return velocity->x*velocity->x + velocity->y*velocity->y + velocity->z*velocity->z;
}

static inline float compute_pressure(float density, float density_energy, float speed_sqd)
{
    return (float)(GAMMA) - (float)(1.0f) ? ((float)(GAMMA) - (float)(1.0f))*(density_energy - (float)(0.5f)*density*speed_sqd) : 0.0f;
}

static inline float compute_speed_of_sound(float density, float pressure)
{
    return sqrtf((float)(GAMMA)*pressure / density);
}

void cfd_flux_kernel(float result[SIZE * NVAR], int elements_surrounding_elements [SIZE * NNB], float normals [SIZE * NNB * NDIM], float variables [SIZE * NVAR], float fc_momentum_x [SIZE * NDIM], float fc_momentum_y [SIZE * NDIM], float fc_momentum_z [SIZE * NDIM], float fc_density_energy [SIZE * NDIM])
{
    const float smoothing_coefficient = (float)0.2f;

    float ff_variable[NVAR] = {1.399999976158142090f, 1.680000066757202148f, 0.0f, 0.0f, 3.507999897003173828f};

    float3 ff_fc_momentum_x, ff_fc_momentum_y, ff_fc_momentum_z, ff_fc_density_energy;

    ff_fc_momentum_x.x = 3.016000270843505859f; ff_fc_momentum_x.y = 0.0f; ff_fc_momentum_x.z = 0.0f;
    ff_fc_momentum_y.x = 0.0f; ff_fc_momentum_y.y = 1.0f; ff_fc_momentum_y.z = 0.0f;
    ff_fc_momentum_z.x = 0.0f; ff_fc_momentum_z.y = 0.0f; ff_fc_momentum_z.z = 1.0f;
    ff_fc_density_energy.x = 5.409600257873535156f; ff_fc_density_energy.y = 0.0f; ff_fc_density_energy.z = 0.0f;

    for(int i = 0; i < SIZE; i++)
    {
        int j, nb;
        float3 normal; float normal_len;
        float factor;

        float density_i = variables[NVAR*i + VAR_DENSITY];
        float3 momentum_i;
        momentum_i.x = variables[NVAR*i + (VAR_MOMENTUM+0)];
        momentum_i.y = variables[NVAR*i + (VAR_MOMENTUM+1)];
        momentum_i.z = variables[NVAR*i + (VAR_MOMENTUM+2)];
        float density_energy_i = variables[NVAR*i + VAR_DENSITY_ENERGY];

        float3 velocity_i;                           compute_velocity(density_i, &momentum_i, &velocity_i);
        float speed_sqd_i                          = compute_speed_sqd(&velocity_i);
        float speed_i                              = sqrtf(speed_sqd_i);
        float pressure_i                           = ( (float)(GAMMA) - (float)(1.0f) ) * (density_energy_i - (float)(0.5f)*density_i*speed_sqd_i);
        float speed_of_sound_i                     = compute_speed_of_sound(density_i, pressure_i);
        float3 fc_i_momentum_x, fc_i_momentum_y, fc_i_momentum_z;
        float3 fc_i_density_energy;

        fc_i_momentum_x.x = fc_momentum_x[i*NDIM + 0];
        fc_i_momentum_x.y = fc_momentum_x[i*NDIM + 1];
        fc_i_momentum_x.z = fc_momentum_x[i*NDIM + 2];

        fc_i_momentum_y.x = fc_momentum_y[i*NDIM + 0];
        fc_i_momentum_y.y = fc_momentum_y[i*NDIM + 1];
        fc_i_momentum_y.z = fc_momentum_y[i*NDIM + 2];

        fc_i_momentum_z.x = fc_momentum_z[i*NDIM + 0];
        fc_i_momentum_z.y = fc_momentum_z[i*NDIM + 1];
        fc_i_momentum_z.z = fc_momentum_z[i*NDIM + 2];

        fc_i_density_energy.x = fc_density_energy[i*NDIM + 0];
        fc_i_density_energy.y = fc_density_energy[i*NDIM + 1];
