        variables[i*NVAR + (VAR_MOMENTUM+1)] = 0.0f;
        variables[i*NVAR + (VAR_MOMENTUM+2)] = 0.0f;
        variables[i*NVAR + VAR_DENSITY_ENERGY] = 3.5f;

        for(int d=0; d<NDIM; d++){
            fc_momentum_x[i*NDIM + d] = 1.0f;
            fc_momentum_y[i*NDIM + d] = 1.0f;
            fc_momentum_z[i*NDIM + d] = 1.0f;
            fc_density_energy[i*NDIM + d] = 1.0f;
        }

        for(int j=0;j<NNB;j++){
            int nb;
            if(j==0) nb = (i == SIZE-1) ? -1 : (i+1);
            else if(j==1) nb = (i == 0) ? -1 : (i-1);
            else if(j==2) nb = -2;
            else nb = -1;
            elements[i*NNB + j] = nb;

            if(j==0){
                normals[(i*NNB + j)*NDIM + 0] = 1.0f; normals[(i*NNB + j)*NDIM + 1] = 0.0f; normals[(i*NNB + j)*NDIM + 2] = 0.0f;
            } else if(j==1){
                normals[(i*NNB + j)*NDIM + 0] = -1.0f; normals[(i*NNB + j)*NDIM + 1] = 0.0f; normals[(i*NNB + j)*NDIM + 2] = 0.0f;
            } else if(j==2){
                normals[(i*NNB + j)*NDIM + 0] = 0.0f; normals[(i*NNB + j)*NDIM + 1] = 1.0f; normals[(i*NNB + j)*NDIM + 2] = 0.0f;
            } else {
                normals[(i*NNB + j)*NDIM + 0] = 0.0f; normals[(i*NNB + j)*NDIM + 1] = 0.0f; normals[(i*NNB + j)*NDIM + 2] = 1.0f;
            }
        }
    }

    // Open CSV file
    FILE *csv = std::fopen("c_output.csv", "w");
    if(!csv) {
        printf("Failed to open c_output.csv for writing\n");
        free(result); free(elements); free(normals); free(variables);
        free(fc_momentum_x); free(fc_momentum_y); free(fc_momentum_z); free(fc_density_energy);
        return 1;
    }

    // CSV header
    // First row: column names. First column must be 'cycle', then all input signal names driven by the testbench, then outputs sampled.
    // We drive arrays: elements, normals, variables, fc_momentum_x, fc_momentum_y, fc_momentum_z, fc_density_energy
    // We sample outputs into scalar variables: out_density/out_momx/out_momy/out_momz/out_deneng
    std::fprintf(csv, "cycle,elements,normals,variables,fc_momentum_x,fc_momentum_y,fc_momentum_z,fc_density_energy,out_density,out_momx,out_momy,out_momz,out_deneng\n");
    // Second row: roles
    std::fprintf(csv, "meta,in,in,in,in,in,in,in,out,out,out,out,out\n");

    // Number of cycles between 20 and 50
    const int cycles = 32;

    for(int cyc = 0; cyc < cycles; ++cyc) {
        // Deterministic variations of a few entries to create diverse test vectors
        // Modify element neighbor for index 0 to cycle through values -1, -2, 1, 2
        int nb_variant = -1;
        switch(cyc % 4) {
            case 0: nb_variant = -1; break;
            case 1: nb_variant = -2; break;
            case 2: nb_variant = 1; break;
            case 3: nb_variant = 2; break;
        }
        elements[0*NNB + 0] = nb_variant;
        // Also vary second neighbor occasionally
        elements[0*NNB + 1] = (cyc % 5 == 0) ? -1 : 0;

        // Vary normals for element 0 (only first component toggles between 0 and 1)
        normals[(0*NNB + 0)*NDIM + 0] = (cyc % 3 == 0) ? 0.0f : 1.0f;
        normals[(0*NNB + 0)*NDIM + 1] = 0.0f;
        normals[(0*NNB + 0)*NDIM + 2] = 0.0f;

        // Vary variables for element 0 in a small deterministic way
        variables[0*NVAR + VAR_DENSITY] = 1.4f + 0.005f * (float)cyc; // 1.4 .. slight increments
        variables[0*NVAR + (VAR_MOMENTUM+0)] = 0.1f * (float)(cyc % 7);
        variables[0*NVAR + (VAR_MOMENTUM+1)] = 0.05f * (float)(cyc % 5);
        variables[0*NVAR + (VAR_MOMENTUM+2)] = 0.02f * (float)(cyc % 3);
        variables[0*NVAR + VAR_DENSITY_ENERGY] = 3.5f + 0.01f * (float)(cyc % 6);

        // Vary flux correction arrays for element 0 slightly
        fc_momentum_x[0*NDIM + 0] = 1.0f + 0.01f * (float)(cyc % 4);
        fc_momentum_x[0*NDIM + 1] = 1.0f;
        fc_momentum_x[0*NDIM + 2] = 1.0f;

        fc_momentum_y[0*NDIM + 0] = 1.0f;
        fc_momentum_y[0*NDIM + 1] = 1.0f + 0.02f * (float)(cyc % 3);
        fc_momentum_y[0*NDIM + 2] = 1.0f;

        fc_momentum_z[0*NDIM + 0] = 1.0f;
        fc_momentum_z[0*NDIM + 1] = 1.0f;
        fc_momentum_z[0*NDIM + 2] = 1.0f + 0.03f * (float)(cyc % 2);

        fc_density_energy[0*NDIM + 0] = 1.0f + 0.005f * (float)(cyc % 10);
        fc_density_energy[0*NDIM + 1] = 1.0f;
        fc_density_energy[0*NDIM + 2] = 1.0f;

        // Call DUT once per cycle
        cfd_flux(result, elements, normals, variables, fc_momentum_x, fc_momentum_y, fc_momentum_z, fc_density_energy);

        // Sample inputs to write into CSV (as decimal integers). For arrays, pick representative element 0 and cast as int if needed.
        int elements_sample = elements[0*NNB + 0];
        int normals_sample = (int)normals[(0*NNB + 0)*NDIM + 0]; // values are 0.0 or 1.0 => cast to int
        int variables_sample = (int)variables[0*NVAR + VAR_DENSITY]; // cast float to int decimal
        int fc_mx_sample = (int)fc_momentum_x[0*NDIM + 0];
        int fc_my_sample = (int)fc_momentum_y[0*NDIM + 0];
        int fc_mz_sample = (int)fc_momentum_z[0*NDIM + 0];
        int fc_deneng_sample = (int)fc_density_energy[0*NDIM + 0];

        // Sample outputs from result array for element 0 and convert floats to uint32 hex (uppercase, no 0x, no fixed width)
        float out_density_f = result[0*NVAR + VAR_DENSITY];
        float out_momx_f = result[0*NVAR + (VAR_MOMENTUM+0)];
        float out_momy_f = result[0*NVAR + (VAR_MOMENTUM+1)];
        float out_momz_f = result[0*NVAR + (VAR_MOMENTUM+2)];
        float out_deneng_f = result[0*NVAR + VAR_DENSITY_ENERGY];

        // Bit-cast floats to uint32_t
        uint32_t out_density_bits;
        uint32_t out_momx_bits;
        uint32_t out_momy_bits;
        uint32_t out_momz_bits;
        uint32_t out_deneng_bits;
        std::memcpy(&out_density_bits, &out_density_f, sizeof(uint32_t));
        std::memcpy(&out_momx_bits, &out_momx_f, sizeof(uint32_t));
        std::memcpy(&out_momy_bits, &out_momy_f, sizeof(uint32_t));
        std::memcpy(&out_momz_bits, &out_momz_f, sizeof(uint32_t));
        std::memcpy(&out_deneng_bits, &out_deneng_f, sizeof(uint32_t));

        // Write CSV row: inputs as decimal integers, outputs as hex uppercase without 0x
        std::fprintf(csv, "%d,%d,%d,%d,%d,%d,%d,%d,%X,%X,%X,%X,%X\n",
            cyc,
            elements_sample,
            normals_sample,
            variables_sample,
            fc_mx_sample,
            fc_my_sample,
            fc_mz_sample,
            fc_deneng_sample,
            out_density_bits,
            out_momx_bits,
            out_momy_bits,
            out_momz_bits,
            out_deneng_bits
        );
    }

    // Close file explicitly
    std::fclose(csv);

    // Free memory
    free(result);
    free(elements);
    free(normals);
    free(variables);
    free(fc_momentum_x);
    free(fc_momentum_y);
    free(fc_momentum_z);
    free(fc_density_energy);

    return 0;
}

