// tb_hls_cosim.cpp
// HLS co-simulation testbench. This testbench is equivalent to the original C testbench:
// it drives the same inputs, invokes the HLS top-level cfd_flux function, and writes a CSV
// file whose contents match exactly the reference c_output.csv (same columns and formatting).
//
// Comments and code written in English.

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>

#define GRID_ROWS (1024)
#define SIZE GRID_ROWS
#define TILE_ROWS 32
#define PARA_FACTOR 16
#define TOP 0
#define BOTTOM (GRID_ROWS / TILE_ROWS - 1)
#define GAMMA 1.4
#define NDIM 3
#define NNB 4
#define RK 3
#define ff_mach 1.2
#define deg_angle_of_attack 0.0f
#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)
#define TYPE float

typedef struct { float x, y, z; } float3;

// Declare the HLS top-level function implemented in hls.cpp
extern "C" void cfd_flux(float result[SIZE * NVAR],
                int elements_surrounding_elements [SIZE * NNB],
                float normals [SIZE * NNB * NDIM],
                float variables [SIZE * NVAR],
                float fc_momentum_x [SIZE * NDIM],
                float fc_momentum_y [SIZE * NDIM],
                float fc_momentum_z [SIZE * NDIM],
                float fc_density_energy [SIZE * NDIM]);

// Small helpers kept consistent with original testbench
static inline void compute_velocity(float density, const float3* momentum, float3* velocity)
{
    velocity->x = momentum->x / density;
    velocity->y = momentum->y / density;
    velocity->z = momentum->z / density;
}

static inline float compute_speed_sqd(const float3* velocity)
{
    return velocity->x*velocity->x + velocity->y*velocity->y + velocity->z*velocity->z;
}

int main()
{
    // Allocate big arrays as required by DUT
    float *result = (float*)malloc(sizeof(float) * SIZE * NVAR);
    int *elements = (int*)malloc(sizeof(int) * SIZE * NNB);
    float *normals = (float*)malloc(sizeof(float) * SIZE * NNB * NDIM);
    float *variables = (float*)malloc(sizeof(float) * SIZE * NVAR);
    float *fc_momentum_x = (float*)malloc(sizeof(float) * SIZE * NDIM);
    float *fc_momentum_y = (float*)malloc(sizeof(float) * SIZE * NDIM);
    float *fc_momentum_z = (float*)malloc(sizeof(float) * SIZE * NDIM);
    float *fc_density_energy = (float*)malloc(sizeof(float) * SIZE * NDIM);

    if(!result || !elements || !normals || !variables || !fc_momentum_x || !fc_momentum_y || !fc_momentum_z || !fc_density_energy) {
        printf("Allocation failed\n");
        return 1;
    }

    // Initialize arrays with deterministic baseline values (matches original C testbench)
    for(int i=0;i<SIZE;i++){
        variables[i*NVAR + VAR_DENSITY] = 1.4f;
        variables[i*NVAR + (VAR_MOMENTUM+0)] = 0.0f;
        variables[i*NVAR + (VAR_MOMENTUM+1)] = 0.0f;
        variables[i*NVAR + (VAR_MOMENTUM+2)] = 0.0f;
        variables[i*NVAR + VAR_DENSITY_ENERGY] = 3.5f;

        for(int d=0; d<NDIM; d++){
            fc_momentum_x[i*NDIM + d] = 1.0f;
            fc_momentum_y[i*NDIM + d] = 1.0f;
            fc_momentum_z[i*NDIM + d] = 1.0f;
            fc_density_energy[i*NDIM + d] = 1.0f;
        }

        for(int j=0;j<NNB;j++){
            int nb;
            if(j==0) nb = (i == SIZE-1) ? -1 : (i+1);
            else if(j==1) nb = (i == 0) ? -1 : (i-1);
            else if(j==2) nb = -2;
            else nb = -1;
            elements[i*NNB + j] = nb;

            if(j==0){
