// hls.cpp
// CFD step factor HLS implementation
// Written for Vivado HLS (C++98 compatibility)

#include <math.h>

// Problem size and configuration
#define GRID_ROWS (1024)
#define SIZE (GRID_ROWS)
#define TILE_ROWS (32)
#define PARA_FACTOR (16)
#define TOP (0)
#define BOTTOM (GRID_ROWS / TILE_ROWS - 1)
#define GAMMA 1.4f
#define NDIM 3
#define NNB 4
#define RK 3
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f
#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM + NDIM)
#define NVAR (VAR_DENSITY_ENERGY + 1)
#define TYPE float

// Simple 3-vector
struct float3 { float x, y, z; };

// Use standard sqrtf for synthesis
static inline float sqrtf_approx(float x) {
    return sqrtf(x);
}

// Compute velocity = momentum / density
static inline void compute_velocity(float density, const float3& momentum, float3* velocity) {
    velocity->x = momentum.x / density;
    velocity->y = momentum.y / density;
    velocity->z = momentum.z / density;
}

static inline float compute_speed_sqd(const float3& velocity) {
    return velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
}

static inline float compute_pressure(float density, float density_energy, float speed_sqd) {
    return (GAMMA - 1.0f) * (density_energy - 0.5f * density * speed_sqd);
}

static inline float compute_speed_of_sound(float density, float pressure) {
    // pressure should be non-negative in typical cases; keep sqrtf for synthesis
    return sqrtf_approx(GAMMA * pressure / density);
}

// Compute step factor for a tile of TILE_ROWS cells
static void cfd_step_factor_kernel(float result[TILE_ROWS], float variables[TILE_ROWS * NVAR], float areas[TILE_ROWS]) {
    #pragma HLS ARRAY_PARTITION variable=result cyclic factor=PARA_FACTOR
    #pragma HLS ARRAY_PARTITION variable=variables cyclic factor=(PARA_FACTOR * NVAR)
    #pragma HLS ARRAY_PARTITION variable=areas cyclic factor=PARA_FACTOR

    // Process PARA_FACTOR elements in parallel per iteration
    const int iters = TILE_ROWS / PARA_FACTOR;
    for (int i = 0; i < iters; i++) {
        #pragma HLS PIPELINE II=1
        #pragma HLS UNROLL factor=PARA_FACTOR

        float density[PARA_FACTOR];
        float3 momentum[PARA_FACTOR];
        float density_energy[PARA_FACTOR];

        #pragma HLS ARRAY_PARTITION variable=density complete
        #pragma HLS ARRAY_PARTITION variable=momentum complete
        #pragma HLS ARRAY_PARTITION variable=density_energy complete

        // Load variables for PARA_FACTOR cells
        for (int j = 0; j < PARA_FACTOR; j++) {
            #pragma HLS UNROLL
            int idx = i * PARA_FACTOR + j;
            density[j] = variables[NVAR*idx + VAR_DENSITY];
            momentum[j].x = variables[NVAR*idx + VAR_MOMENTUM + 0];
            momentum[j].y = variables[NVAR*idx + VAR_MOMENTUM + 1];
            momentum[j].z = variables[NVAR*idx + VAR_MOMENTUM + 2];
            density_energy[j] = variables[NVAR*idx + VAR_DENSITY_ENERGY];
        }

        // Compute result for PARA_FACTOR cells
        for (int j = 0; j < PARA_FACTOR; j++) {
            #pragma HLS UNROLL
            int idx = i * PARA_FACTOR + j;
            float3 velocity;
            compute_velocity(density[j], momentum[j], &velocity);
            float speed_sqd = compute_speed_sqd(velocity);

            // Ensure numerical stability: pressure should be non-negative in practical inputs.
            float pressure = compute_pressure(density[j], density_energy[j], speed_sqd);
            if (pressure <= 0.0f) pressure = 1e-6f;

            float speed_of_sound = compute_speed_of_sound(density[j], pressure);

            // Compute step factor
            float denom = sqrtf_approx(areas[idx]) * (sqrtf_approx(speed_sqd) + speed_of_sound);
            // Guard small denom
            if (denom <= 0.0f) denom = 1e-6f;
            result[idx] = 0.5f / denom;
        }
    }
}

// Buffer load variables for a tile (if flag true)
static void buffer_load_variables(int flag, int k, float variables_inner[TILE_ROWS * NVAR], const float* variables) {
    if (flag) {
        #pragma HLS PIPELINE II=1
        for (int i = 0; i < TILE_ROWS * NVAR; i++) {
            variables_inner[i] = variables[k * TILE_ROWS * NVAR + i];
        }
    }
}

// Buffer load areas for a tile (if flag true)
static void buffer_load_areas(int flag, int k, float areas_inner[TILE_ROWS], const float* areas) {
    if (flag) {
        #pragma HLS PIPELINE II=1
        for (int i = 0; i < TILE_ROWS; i++) {
            areas_inner[i] = areas[k * TILE_ROWS + i];
        }
    }
}

// Compute using buffered data (if flag true)
static void buffer_compute(int flag, float result_inner[TILE_ROWS], float variables_inner[TILE_ROWS * NVAR], float areas_inner[TILE_ROWS]) {
    if (flag) cfd_step_factor_kernel(result_inner, variables_inner, areas_inner);
}

// Store result from buffer to global result array (if flag true)
static void buffer_store(int flag, int k, float* result, float result_inner[TILE_ROWS]) {
    if (flag) {
        #pragma HLS PIPELINE II=1
        for (int i = 0; i < TILE_ROWS; i++) {
            result[k * TILE_ROWS + i] = result_inner[i];
        }
    }
}

// Top-level HLS function (C linkage required)
extern "C" void cfd_step_factor(float result[SIZE], float variables[SIZE * NVAR], float areas[SIZE]) {
    #pragma HLS INTERFACE m_axi port=result offset=slave bundle=result1
    #pragma HLS INTERFACE m_axi port=variables offset=slave bundle=variables1
    #pragma HLS INTERFACE m_axi port=areas offset=slave bundle=areas1
    #pragma HLS INTERFACE s_axilite port=result bundle=control
    #pragma HLS INTERFACE s_axilite port=variables bundle=control
    #pragma HLS INTERFACE s_axilite port=areas bundle=control
    #pragma HLS INTERFACE s_axilite port=return bundle=control

    // 4-way buffering for pipeline
    float result_inner[4][TILE_ROWS];
    float variables_inner[4][TILE_ROWS * NVAR];
    float areas_inner[4][TILE_ROWS];

    #pragma HLS ARRAY_PARTITION variable=result_inner complete dim=1
    #pragma HLS ARRAY_PARTITION variable=variables_inner complete dim=1
    #pragma HLS ARRAY_PARTITION variable=areas_inner complete dim=1

    const int num_tiles = SIZE / TILE_ROWS;

    // Iterate with pipeline prolog/epilog of length 3
    for (int k = 0; k < num_tiles + 3; k++) {
        #pragma HLS PIPELINE II=1

        int load_variables_flag = (k >= 0) && (k < num_tiles);
        int load_areas_flag = (k >= 1) && (k < num_tiles + 1);
        int compute_flag = (k >= 2) && (k < num_tiles + 2);
        int store_flag = (k >= 3) && (k < num_tiles + 3);

        int idx = k % 4;
        int prev_idx = (idx - 1 + 4) % 4;
        int compute_idx = (idx - 2 + 4) % 4;
        int store_idx = (idx - 3 + 4) % 4;

        // Load variables for tile k into buffer slot idx
        buffer_load_variables(load_variables_flag, k, variables_inner[idx], variables);

        // Load areas for tile (k-1) into buffer slot prev_idx
        buffer_load_areas(load_areas_flag, k - 1, areas_inner[prev_idx], areas);

        // Compute for tile (k-2) using buffer slot compute_idx
        buffer_compute(compute_flag, result_inner[compute_idx], variables_inner[compute_idx], areas_inner[compute_idx]);

        // Store result for tile (k-3) from buffer slot store_idx
        buffer_store(store_flag, k - 3, result, result_inner[store_idx]);
    }
}

