// tb_hls_cosim.cpp
// HLS C++ Testbench for cfd_step_factor
// This testbench is functionally equivalent to the provided C testbench (main_tb.cpp).
// It calls the HLS top-level function `cfd_step_factor` via extern "C" and writes
// a single CSV file "hls_output.csv" with the same CSV layout as the original testbench.

// Use C headers for C++98 compatibility with Vivado HLS 2018.3
#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#ifndef TEST_H
#define TEST_H

#define GRID_ROWS 1024
#define SIZE (GRID_ROWS)
#define TILE_ROWS 32 
#define TOP 0
#define BOTTOM (GRID_ROWS / TILE_ROWS - 1)
#define GAMMA 1.4f
#define NDIM 3
#define NNB 4
#define RK 3    
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f
#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM + NDIM)
#define NVAR (VAR_DENSITY_ENERGY + 1)
#define TYPE float

struct float3 { float x, y, z; };

// HLS top-level function (must match HLS C code signature exactly)
extern "C" void cfd_step_factor(float result[SIZE], float variables[SIZE * NVAR], float areas[SIZE]);

#endif // TEST_H

// Helper inline functions (use pass-by-value / const-reference semantics)
inline void compute_velocity(float density, const float3& momentum, float3& velocity)
{
    velocity.x = momentum.x / density;
    velocity.y = momentum.y / density;
    velocity.z = momentum.z / density;
}

inline float compute_speed_sqd(const float3& velocity)
{
    return velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
}

inline float compute_pressure(float density, float density_energy, float speed_sqd)
{
    return ( (float)GAMMA - 1.0f ) * (density_energy - 0.5f * density * speed_sqd);
}

inline float compute_speed_of_sound(float density, float pressure)
{
    return sqrtf((float)GAMMA * pressure / density);
}

int main()
{
    const int N_CYCLES = 64; // increase cycles to exercise more code paths

    // Allocate memory
    float *variables = (float*)malloc(sizeof(float) * SIZE * NVAR);
    float *areas = (float*)malloc(sizeof(float) * SIZE);
    float *result = (float*)malloc(sizeof(float) * SIZE);

    if (!variables || !areas || !result) {
        fprintf(stderr, "Allocation failed\n");
        if (variables) free(variables);
        if (areas) free(areas);
        if (result) free(result);
        return 1;
    }

    // Deterministic initial content for variables and areas
    for (int i = 0; i < SIZE; ++i) {
        float density = 1.0f + 0.001f * (i % 100);
        variables[NVAR*i + VAR_DENSITY] = density;
        variables[NVAR*i + (VAR_MOMENTUM + 0)] = 0.1f * (i % 10);
        variables[NVAR*i + (VAR_MOMENTUM + 1)] = 0.2f * (i % 7);
        variables[NVAR*i + (VAR_MOMENTUM + 2)] = 0.3f * (i % 5);
        variables[NVAR*i + VAR_DENSITY_ENERGY] = 2.5f + 0.01f * (i % 20);
        areas[i] = 1.0f + 0.001f * (i % 50);
    }

    // Open CSV file for HLS/RTL output
    FILE *f = fopen("hls_output.csv", "w");
    if (!f) {
        perror("fopen");
        free(variables);
        free(areas);
        free(result);
        return 1;
    }

    // Header: cycle, rst, en, result
    fprintf(f, "cycle,rst,en,result\n");
    // Roles row: cycle is meta, rst and en are inputs driven by TB, result is DUT output
    fprintf(f, "meta,in,in,out\n");

    // Simulate cycles. First 2 cycles reset active, en=0; afterwards en=1
    for (int cycle = 0; cycle < N_CYCLES; ++cycle) {
        int rst = (cycle < 2) ? 1 : 0;
        int en  = (cycle < 2) ? 0 : 1;

        // During reset: deterministic zeroing of index 0
        if (!en) {
            int idx = 0;
            variables[NVAR*idx + VAR_DENSITY] = 1.0f;
            variables[NVAR*idx + (VAR_MOMENTUM + 0)] = 0.0f;
            variables[NVAR*idx + (VAR_MOMENTUM + 1)] = 0.0f;
            variables[NVAR*idx + (VAR_MOMENTUM + 2)] = 0.0f;
            variables[NVAR*idx + VAR_DENSITY_ENERGY] = 2.5f;
            areas[idx] = 1.0f;
        } else {
            // When enabled make deterministic tweaks to different indices each cycle
            int idx = (cycle * 7 + 3) % SIZE; // spread changes across cells
            variables[NVAR*idx + VAR_DENSITY] = 1.0f + 0.001f * ((idx + cycle) % 100);
            variables[NVAR*idx + (VAR_MOMENTUM + 0)] = 0.1f * ((idx + cycle) % 10);
            variables[NVAR*idx + (VAR_MOMENTUM + 1)] = 0.2f * ((idx + cycle) % 7);
            variables[NVAR*idx + (VAR_MOMENTUM + 2)] = 0.3f * ((idx + cycle) % 5);
            variables[NVAR*idx + VAR_DENSITY_ENERGY] = 2.5f + 0.01f * ((idx + cycle) % 20);
            areas[idx] = 1.0f + 0.001f * ((idx + cycle) % 50);

            // Occasionally (every 11 cycles) introduce a tiny area perturbation to exercise guard
            if ((cycle % 11) == 0) {
                int j = (idx + 5) % SIZE;
                areas[j] = 1e-6f; // very small but positive
            }
        }

        // Call DUT each cycle
        cfd_step_factor(result, variables, areas);

        // Sample an output value to write to CSV.
        int sample_idx = (cycle * 3 + 1) % SIZE;
        float sampled = result[sample_idx];

        // Convert float bits to uint32 for hex output
        uint32_t bits = 0u;
        memcpy(&bits, &sampled, sizeof(bits));

        // Print row: cycle (decimal), rst (decimal 0/1), en (decimal 0/1), result (HEX uppercase, no 0x)
        fprintf(f, "%d,%d,%d,%X\n", cycle, rst, en, bits);
    }

    // Extra direct tests to exercise helper functions and codepaths (increase coverage)

    // 1) Test compute_velocity and compute_speed_sqd with non-zero momenta
    {
        float test_density = 2.0f;
        float3 mom = {0.5f, -0.3f, 0.25f};
        float3 vel;
        compute_velocity(test_density, mom, vel);
        volatile float ssd = compute_speed_sqd(vel); (void)ssd;
    }

    // 2) Test pressure and speed of sound with a low pressure scenario (guard branch)
    {
        float d = 1.2f;
        float de = 0.6f; // intentionally small to trigger small pressure
        float speed_sqd = 0.0f;
        float p = compute_pressure(d, de, speed_sqd);
        if (p < 1e-6f) p = 1e-6f;
        float sos = compute_speed_of_sound(d, p);
        volatile float sink = p + sos; (void)sink;
    }

    // 3) Call cfd_step_factor on a small crafted array to ensure loop body executes with small N (but we call the same function; this is mostly to touch code again)
    {
        for (int i = 0; i < 8 && i < SIZE; ++i) {
            variables[NVAR*i + VAR_DENSITY] = 1.0f + 0.005f * i;
            variables[NVAR*i + VAR_MOMENTUM + 0] = 0.05f * i;
            variables[NVAR*i + VAR_MOMENTUM + 1] = 0.02f * i;
            variables[NVAR*i + VAR_MOMENTUM + 2] = -0.01f * i;
            variables[NVAR*i + VAR_DENSITY_ENERGY] = 3.0f + 0.02f * i;
            areas[i] = 1.0f + 0.002f * i;
        }
        cfd_step_factor(result, variables, areas);
    }

    // Flush and explicitly close file
    fflush(f);
    fclose(f);

    // Optional quick stdout verification
    for (int i = 0; i < 10; ++i) {
        printf("result[%d] = %g\n", i, result[i]);
    }

    // Free memory
    free(variables);
    free(areas);
    free(result);

    return 0;
}

