void sha256(SHA256_CTX *ctx, unsigned char hash[]) {
    unsigned int i;

    i = ctx->datalen;

    if (ctx->datalen < 56) {
        ctx->data[i++] = 0x80;
        while (i < 56) {
            ctx->data[i++] = 0x00;
        }
    } else {
        ctx->data[i++] = 0x80;
        while (i < 64) {
            ctx->data[i++] = 0x00;
        }
        sha256_transform(&ctx->state, &ctx->data);
        memset(ctx->data, 0, 56);
    }

    ctx->bitlen += ctx->datalen * 8;
    ctx->data[63] = ctx->bitlen;
    ctx->data[62] = ctx->bitlen >> 8;
    ctx->data[61] = ctx->bitlen >> 16;
    ctx->data[60] = ctx->bitlen >> 24;
    ctx->data[59] = ctx->bitlen >> 32;
    ctx->data[58] = ctx->bitlen >> 40;
    ctx->data[57] = ctx->bitlen >> 48;
    ctx->data[56] = ctx->bitlen >> 56;
    sha256_transform(&ctx->state, &ctx->data);

    for (i = 0; i < 4; ++i) {
        hash[i] = (ctx->state[0] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 4] = (ctx->state[1] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 8] = (ctx->state[2] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 12] = (ctx->state[3] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 16] = (ctx->state[4] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 20] = (ctx->state[5] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 24] = (ctx->state[6] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 28] = (ctx->state[7] >> (24 - i * 8)) & 0x000000ff;
    }
}

void sha256_compute(SHA256_CTX *ctx, const unsigned char *input, size_t len, unsigned char hash[32]) {
    size_t offset = 0;
    while (len > 0) {
        size_t chunk = len < 64 ? len : 64;
        data_t chunkbuf;
        memset(chunkbuf, 0, 64);
        memcpy(chunkbuf, input + offset, chunk);
        sha256_update(&ctx->data, &ctx->datalen, &ctx->state, &ctx->bitlen, &chunkbuf, chunk);
        offset += chunk;
        len -= chunk;
    }
    sha256(ctx, hash);
}

int main() {
    const unsigned char msg[] = "abc";
    size_t msg_len = sizeof(msg) - 1;
    SHA256_CTX ctx;
    unsigned char hash[32];
    sha256_init(&ctx);
    sha256_compute(&ctx, msg, msg_len, hash);
    for (int i = 0; i < 32; ++i)
        printf("%02x", hash[i]);
    printf("\n");
    return 0;
}

