        hash[i + 24] = (ctx->state[6] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 28] = (ctx->state[7] >> (24 - i * 8)) & 0x000000ff;
    }
}

void sha256_compute(SHA256_CTX *ctx, const unsigned char *input, size_t len, unsigned char hash[32]) {
    size_t offset = 0;
    while (len > 0) {
        size_t chunk = len < 64 ? len : 64;
        data_t chunkbuf;
        memset(chunkbuf, 0, 64);
        memcpy(chunkbuf, input + offset, chunk);
        sha256_update(&ctx->data, &ctx->datalen, &ctx->state, &ctx->bitlen, &chunkbuf, chunk);
        offset += chunk;
        len -= chunk;
    }
    sha256(ctx, hash);
}

