// hls.cpp
// SHA-256 HLS implementation (Vivado HLS friendly, C++98)
// Comments in English as requested.

#include <stdint.h>
#include <string.h>

// HLS pragmas require these definitions to be available
#define SHA256_BLOCK_SIZE 32

#define ROTLEFT(a, b) (((a) << (b)) | ((a) >> (32 - (b))))
#define ROTRIGHT(a, b) (((a) >> (b)) | ((a) << (32 - (b))))

#define CH(x, y, z) (((x) & (y)) ^ (~(x) & (z)))
#define MAJ(x, y, z) (((x) & (y)) ^ ((x) & (z)) ^ ((y) & (z)))
#define EP0(x) (ROTRIGHT(x, 2) ^ ROTRIGHT(x, 13) ^ ROTRIGHT(x, 22))
#define EP1(x) (ROTRIGHT(x, 6) ^ ROTRIGHT(x, 11) ^ ROTRIGHT(x, 25))
#define SIG0(x) (ROTRIGHT(x, 7) ^ ROTRIGHT(x, 18) ^ ((x) >> 3))
#define SIG1(x) (ROTRIGHT(x, 17) ^ ROTRIGHT(x, 19) ^ ((x) >> 10))

typedef unsigned char data_t[64];
typedef unsigned int state_t[8];

// Define the same SHA256_CTX layout as the testbench expects.
// This is the external software-compatible context structure.
typedef struct SHA256_CTX {
    data_t data;
    unsigned int datalen;
    unsigned long long bitlen;
    state_t state;
} SHA256_CTX;

// SHA-256 constants
static const unsigned int k[64] = {
    0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1,
    0x923f82a4, 0xab1c5ed5, 0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3,
    0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174, 0xe49b69c1, 0xefbe4786,
    0x0fc19dc6, 0x240ca1cc, 0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da,
    0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7, 0xc6e00bf3, 0xd5a79147,
    0x06ca6351, 0x14292967, 0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13,
    0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85, 0xa2bfe8a1, 0xa81a664b,
    0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070,
    0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a,
    0x5b9cca4f, 0x682e6ff3, 0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208,
    0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2
};

// Internal transform function (operates on raw state array)
static void sha256_transform(state_t state, const unsigned char data[64]) {
    unsigned int a, b, c, d, e, f, g, h, i, j, t1, t2, m[64];
#pragma HLS array_partition variable=m block factor=16 dim=1

    for (i = 0, j = 0; i < 16; ++i, j += 4) {
#pragma HLS pipeline
        m[i] = (data[j] << 24) | (data[j + 1] << 16) |
               (data[j + 2] << 8) | (data[j + 3]);
    }
    for (; i < 64; ++i) {
#pragma HLS unroll factor=4
        m[i] = SIG1(m[i - 2]) + m[i - 7] + SIG0(m[i - 15]) + m[i - 16];
    }

    a = state[0];
    b = state[1];
    c = state[2];
    d = state[3];
    e = state[4];
    f = state[5];
    g = state[6];
    h = state[7];

    for (i = 0; i < 64; ++i) {
#pragma HLS unroll factor=8
        t1 = h + EP1(e) + CH(e, f, g) + k[i] + m[i];
        t2 = EP0(a) + MAJ(a, b, c);
        h = g;
        g = f;
        f = e;
        e = d + t1;
        d = c;
        c = b;
        b = a;
        a = t1 + t2;
    }

    state[0] += a;
    state[1] += b;
    state[2] += c;
    state[3] += d;
    state[4] += e;
    state[5] += f;
    state[6] += g;
    state[7] += h;
}

// Internal helper to initialize a raw state array
static void sha256_init_state(state_t state) {
    state[0] = 0x6a09e667;
    state[1] = 0xbb67ae85;
    state[2] = 0x3c6ef372;
    state[3] = 0xa54ff53a;
    state[4] = 0x510e527f;
    state[5] = 0x9b05688c;
    state[6] = 0x1f83d9ab;
    state[7] = 0x5be0cd19;
}

// Provide an extern "C" initialization function that the testbench expects.
// This will initialize the SHA256_CTX structure (datalen, bitlen, state).
extern "C" void sha256_init(SHA256_CTX *ctx) {
    ctx->datalen = 0;
    ctx->bitlen = 0ULL;
    sha256_init_state(ctx->state);
}

// Small wrapper used by the accelerator to update bitlen and reset datalen.
static void sha256_transform_wrapper(state_t state, unsigned char data[64], unsigned int *datalen, unsigned long long *bitlen) {
    sha256_transform(state, data);
    *bitlen += 512ULL;
    *datalen = 0;
}

// Top-level accelerator function (kept extern "C" as required for HLS top).
extern "C" void sha256_accel(
    const unsigned char input[],
    unsigned int input_len,
    unsigned char hash[32]) {
#pragma HLS INTERFACE m_axi port=input offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=hash offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=input_len bundle=control
#pragma HLS INTERFACE s_axilite port=input bundle=control
#pragma HLS INTERFACE s_axilite port=hash bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    state_t state;
    unsigned char data[64];
    unsigned int datalen = 0;
    unsigned long long bitlen = 0ULL;
    unsigned int i;

    // Initialize internal state
    sha256_init_state(state);

    // Process input data
    for (i = 0; i < input_len; i++) {
#pragma HLS pipeline II=1
        data[datalen] = input[i];
        datalen++;
        if (datalen == 64) {
            sha256_transform_wrapper(state, data, &datalen, &bitlen);
        }
    }

    // Padding
    i = datalen;
    if (datalen < 56) {
        data[i++] = 0x80;
        while (i < 56) {
#pragma HLS LOOP_TRIPCOUNT min=1 max=56
            data[i++] = 0x00;
        }
    } else {
        data[i++] = 0x80;
        while (i < 64) {
#pragma HLS LOOP_TRIPCOUNT min=1 max=64
            data[i++] = 0x00;
        }
        sha256_transform(state, data);
        for (i = 0; i < 56; i++) {
#pragma HLS pipeline
            data[i] = 0x00;
        }
    }

    bitlen += (unsigned long long)datalen * 8ULL;

    data[63] = (unsigned char)(bitlen);
    data[62] = (unsigned char)(bitlen >> 8);
    data[61] = (unsigned char)(bitlen >> 16);
    data[60] = (unsigned char)(bitlen >> 24);
    data[59] = (unsigned char)(bitlen >> 32);
    data[58] = (unsigned char)(bitlen >> 40);
    data[57] = (unsigned char)(bitlen >> 48);
    data[56] = (unsigned char)(bitlen >> 56);

    sha256_transform(state, data);

    // Convert state to hash (big endian)
    for (i = 0; i < 4; i++) {
#pragma HLS pipeline
        hash[i]      = (unsigned char)((state[0] >> (24 - i * 8)) & 0xff);
        hash[i + 4]  = (unsigned char)((state[1] >> (24 - i * 8)) & 0xff);
        hash[i + 8]  = (unsigned char)((state[2] >> (24 - i * 8)) & 0xff);
        hash[i + 12] = (unsigned char)((state[3] >> (24 - i * 8)) & 0xff);
        hash[i + 16] = (unsigned char)((state[4] >> (24 - i * 8)) & 0xff);
        hash[i + 20] = (unsigned char)((state[5] >> (24 - i * 8)) & 0xff);
        hash[i + 24] = (unsigned char)((state[6] >> (24 - i * 8)) & 0xff);
        hash[i + 28] = (unsigned char)((state[7] >> (24 - i * 8)) & 0xff);
    }
}

