        m[i] = SIG1(m[i - 2]) + m[i - 7] + SIG0(m[i - 15]) + m[i - 16];

    a = (*state)[0];
    b = (*state)[1];
    c = (*state)[2];
    d = (*state)[3];
    e = (*state)[4];
    f = (*state)[5];
    g = (*state)[6];
    h = (*state)[7];

    for (i = 0; i < 64; ++i) {
        t1 = h + EP1(e) + CH(e, f, g) + k_sw[i] + m[i];
        t2 = EP0(a) + MAJ(a, b, c);
        h = g;
        g = f;
        f = e;
        e = d + t1;
        d = c;
        c = b;
        b = a;
