        // Construct message content deterministically from cycle and position.
        unsigned char msg[64];
        for (size_t i = 0; i < 64; ++i) {
            msg[i] = (unsigned char)('a' + ((i + cycle) % 26));
        }

        // Prepare context. Call HLS top-level sha256_init to exercise RTL initializer.
        SHA256_CTX ctx;
        // Call HLS RTL top to initialize ctx in the same way as the SW version would.
        // This invocation is the required call to the DUT top-level function.
        sha256_init(&ctx);

        // After DUT initialization, compute the full SHA-256 in software starting from the
        // context initialized by the DUT. This produces the output 'hash' we record.
        unsigned char hash[32];
        // Continue the processing in software (this testbench's behavioral model).
        sha256_compute_sw(&ctx, msg, len, hash);

