            // initialize input pixels deterministically
            for (uint p = 0; p < 16; ++p) {
                uint r = (p & 0xff);
                uint g = ((p * 2) & 0xff);
                uint b = ((p * 3) & 0xff);
                uint pixel = (r) | (g << 8) | (b << 16);
                in_buf[0].data[p] = pixel;
                out_buf[0].data[p] = 0;
            }
            // Call the HLS DUT
            apply_watermark(in_buf, out_buf, width, height);
            // sample pixel index (cycle-16) to get variety
            uint sample_idx = (uint)(cycle - 16);
            if (sample_idx < 16) {
                aw_out = out_buf[0].data[sample_idx];
            } else {
                aw_out = 0;
            }
            sat_out = 0;
        }

        // Outputs: sat_out and aw_out must be in hexadecimal uppercase without 0x.
        // Inputs must be printed as decimal integers.
        std::fprintf(f, "%d,%d,%d,%d,%d,%X,%X\n",
                     cycle, x, y, width, height, sat_out, aw_out);
    }

    std::fflush(f);
    std::fclose(f);

    return 0;
}

