                fc_nb_momentum_y.z = fc_momentum_y[nb*NDIM + 2];


                fc_nb_momentum_z.x = fc_momentum_z[nb*NDIM + 0];
                fc_nb_momentum_z.y = fc_momentum_z[nb*NDIM + 1];
                fc_nb_momentum_z.z = fc_momentum_z[nb*NDIM + 2];

                fc_nb_density_energy.x = fc_density_energy[nb*NDIM + 0];
                fc_nb_density_energy.y = fc_density_energy[nb*NDIM + 1];
                fc_nb_density_energy.z = fc_density_energy[nb*NDIM + 2];

                factor = -normal_len*smoothing_coefficient*0.5f*(speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor*(density_i-density_nb);
                flux_i_density_energy += factor*(density_energy_i-density_energy_nb);
                flux_i_momentum.x += factor*(momentum_i.x-momentum_nb.x);
                flux_i_momentum.y += factor*(momentum_i.y-momentum_nb.y);
                flux_i_momentum.z += factor*(momentum_i.z-momentum_nb.z);

                factor = 0.5f*normal.x;
                flux_i_density += factor*(momentum_nb.x+momentum_i.x);
                flux_i_density_energy += factor*(fc_nb_density_energy.x+fc_i_density_energy.x);
                flux_i_momentum.x += factor*(fc_nb_momentum_x.x+fc_i_momentum_x.x);
                flux_i_momentum.y += factor*(fc_nb_momentum_y.x+fc_i_momentum_y.x);
                flux_i_momentum.z += factor*(fc_nb_momentum_z.x+fc_i_momentum_z.x);

                factor = 0.5f*normal.y;
                flux_i_density += factor*(momentum_nb.y+momentum_i.y);
                flux_i_density_energy += factor*(fc_nb_density_energy.y+fc_i_density_energy.y);
                flux_i_momentum.x += factor*(fc_nb_momentum_x.y+fc_i_momentum_x.y);
                flux_i_momentum.y += factor*(fc_nb_momentum_y.y+fc_i_momentum_y.y);
                flux_i_momentum.z += factor*(fc_nb_momentum_z.y+fc_i_momentum_z.y);

                factor = 0.5f*normal.z;
                flux_i_density += factor*(momentum_nb.z+momentum_i.z);
                flux_i_density_energy += factor*(fc_nb_density_energy.z+fc_i_density_energy.z);
                flux_i_momentum.x += factor*(fc_nb_momentum_x.z+fc_i_momentum_x.z);
                flux_i_momentum.y += factor*(fc_nb_momentum_y.z+fc_i_momentum_y.z);
                flux_i_momentum.z += factor*(fc_nb_momentum_z.z+fc_i_momentum_z.z);
            }
            else if(nb == -1)
            {
                flux_i_momentum.x += normal.x*pressure_i;
                flux_i_momentum.y += normal.y*pressure_i;
                flux_i_momentum.z += normal.z*pressure_i;
            }
            else if(nb == -2)
            {
                factor = 0.5f*normal.x;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+0]+momentum_i.x);
                flux_i_density_energy += factor*(ff_fc_density_energy.x+fc_i_density_energy.x);
                flux_i_momentum.x += factor*(ff_fc_momentum_x.x + fc_i_momentum_x.x);
                flux_i_momentum.y += factor*(ff_fc_momentum_y.x + fc_i_momentum_y.x);
                flux_i_momentum.z += factor*(ff_fc_momentum_z.x + fc_i_momentum_z.x);

                factor = 0.5f*normal.y;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i.y);
                flux_i_density_energy += factor*(ff_fc_density_energy.y+fc_i_density_energy.y);
                flux_i_momentum.x += factor*(ff_fc_momentum_x.y + fc_i_momentum_x.y);
                flux_i_momentum.y += factor*(ff_fc_momentum_y.y + fc_i_momentum_y.y);
                flux_i_momentum.z += factor*(ff_fc_momentum_z.y + fc_i_momentum_z.y);

                factor = 0.5f*normal.z;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i.z);
                flux_i_density_energy += factor*(ff_fc_density_energy.z+fc_i_density_energy.z);
                flux_i_momentum.x += factor*(ff_fc_momentum_x.z + fc_i_momentum_x.z);
                flux_i_momentum.y += factor*(ff_fc_momentum_y.z + fc_i_momentum_y.z);
                flux_i_momentum.z += factor*(ff_fc_momentum_z.z + fc_i_momentum_z.z);

            }
        }

        result[i*NVAR + VAR_DENSITY] = flux_i_density;
        result[i*NVAR + (VAR_MOMENTUM+0)] = flux_i_momentum.x;
        result[i*NVAR + (VAR_MOMENTUM+1)] = flux_i_momentum.y;
        result[i*NVAR + (VAR_MOMENTUM+2)] = flux_i_momentum.z;
        result[i*NVAR + VAR_DENSITY_ENERGY] = flux_i_density_energy;
    }

    return;
}

void cfd_flux(float result[SIZE * NVAR], int elements_surrounding_elements [SIZE * NNB], float normals [SIZE * NNB * NDIM], 
                float variables [SIZE * NVAR], float fc_momentum_x [SIZE * NDIM], float fc_momentum_y [SIZE * NDIM], 
                float fc_momentum_z [SIZE * NDIM], float fc_density_energy [SIZE * NDIM])
{
    cfd_flux_kernel(result, elements_surrounding_elements, normals, variables, fc_momentum_x, fc_momentum_y, fc_momentum_z, fc_density_energy);
    return;
}

static inline uint32_t float_to_u32(float f) {
    uint32_t u;
    std::memcpy(&u, &f, sizeof(u));
    return u;
}

int main()
{
    // Allocate arrays
    float *result = (float*)malloc(sizeof(float)*SIZE*NVAR);
    int *elements_surrounding_elements = (int*)malloc(sizeof(int)*SIZE*NNB);
    float *normals = (float*)malloc(sizeof(float)*SIZE*NNB*NDIM);
    float *variables = (float*)malloc(sizeof(float)*SIZE*NVAR);
    float *fc_momentum_x = (float*)malloc(sizeof(float)*SIZE*NDIM);
    float *fc_momentum_y = (float*)malloc(sizeof(float)*SIZE*NDIM);
    float *fc_momentum_z = (float*)malloc(sizeof(float)*SIZE*NDIM);
    float *fc_density_energy = (float*)malloc(sizeof(float)*SIZE*NDIM);

    if(!result || !elements_surrounding_elements || !normals || !variables || !fc_momentum_x || !fc_momentum_y || !fc_momentum_z || !fc_density_energy) {
        std::fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    // Initial deterministic fill (based on original reference)
    for(int i=0;i<SIZE;i++){
        variables[i*NVAR + VAR_DENSITY] = 1.4f;
        variables[i*NVAR + (VAR_MOMENTUM+0)] = 1.0f;
        variables[i*NVAR + (VAR_MOMENTUM+1)] = 0.0f;
        variables[i*NVAR + (VAR_MOMENTUM+2)] = 0.0f;
        variables[i*NVAR + VAR_DENSITY_ENERGY] = 2.5f;

        fc_momentum_x[i*NDIM + 0] = 0.0f; fc_momentum_x[i*NDIM + 1] = 0.0f; fc_momentum_x[i*NDIM + 2] = 0.0f;
        fc_momentum_y[i*NDIM + 0] = 0.0f; fc_momentum_y[i*NDIM + 1] = 0.0f; fc_momentum_y[i*NDIM + 2] = 0.0f;
        fc_momentum_z[i*NDIM + 0] = 0.0f; fc_momentum_z[i*NDIM + 1] = 0.0f; fc_momentum_z[i*NDIM + 2] = 0.0f;
        fc_density_energy[i*NDIM + 0] = 0.0f; fc_density_energy[i*NDIM + 1] = 0.0f; fc_density_energy[i*NDIM + 2] = 0.0f;

        for(int j=0;j<NNB;j++){
            elements_surrounding_elements[i*NNB + j] = -2;
            normals[(i*NNB + j)*NDIM + 0] = (j==0)?1.0f:0.0f;
            normals[(i*NNB + j)*NDIM + 1] = (j==1)?1.0f:0.0f;
            normals[(i*NNB + j)*NDIM + 2] = (j==2)?1.0f:0.0f;
            if(j==3){
                normals[(i*NNB + j)*NDIM + 0] = 0.57735026f;
                normals[(i*NNB + j)*NDIM + 1] = 0.57735026f;
                normals[(i*NNB + j)*NDIM + 2] = 0.57735026f;
            }
        }
    }

    // Prepare CSV file
    FILE *csv = std::fopen("c_output.csv", "w");
    if(!csv) {
        std::fprintf(stderr, "Unable to open c_output.csv for writing\n");
        return 1;
    }

    // Header line: cycle, then input variable names, then outputs
    // Variable/parameter names must match the DUT parameter names exactly
    std::fprintf(csv, "cycle,elements_surrounding_elements,normals,variables,fc_momentum_x,fc_momentum_y,fc_momentum_z,fc_density_energy,result\n");
    // Role line
    std::fprintf(csv, "meta,in,in,in,in,in,in,in,out\n");

    // Number of cycles: choose 32 (within 20-50)
    const int CYCLES = 32;

    for(int cycle = 0; cycle < CYCLES; cycle++) {
        // Deterministic variation of a few entries based on cycle index to create varied test vectors
        int idx = cycle % SIZE; // element index to modify this cycle (wraps but deterministic)

        // Vary neighbor flags for this element
        int mode = cycle % 4;
        if(mode == 0) {
            // far-field (-2) for all neighbors
            for(int j=0;j<NNB;j++) elements_surrounding_elements[idx*NNB + j] = -2;
        } else if(mode == 1) {
            // one boundary (-1), others far-field
            elements_surrounding_elements[idx*NNB + 0] = -1;
            elements_surrounding_elements[idx*NNB + 1] = -2;
            elements_surrounding_elements[idx*NNB + 2] = -2;
            elements_surrounding_elements[idx*NNB + 3] = -2;
        } else if(mode == 2) {
            // one valid neighbor (use a small positive index), others far-field
            int nbidx = (idx + 1) % SIZE;
            elements_surrounding_elements[idx*NNB + 0] = nbidx;
            elements_surrounding_elements[idx*NNB + 1] = -2;
            elements_surrounding_elements[idx*NNB + 2] = -2;
            elements_surrounding_elements[idx*NNB + 3] = -2;
            // also modify that neighbor slightly to create asymmetric data
            variables[nbidx*NVAR + VAR_DENSITY] = 1.2f + 0.05f * (float)(cycle % 5);
            variables[nbidx*NVAR + (VAR_MOMENTUM+0)] = 0.5f * (float)((cycle%3)+1);
        } else {
            // a negative value not explicitly handled (-3) to test robustness
            for(int j=0;j<NNB;j++) elements_surrounding_elements[idx*NNB + j] = -3;
        }

        // Vary normals for this element's neighbors
        normals[(idx*NNB + 0)*NDIM + 0] = 1.0f;
        normals[(idx*NNB + 0)*NDIM + 1] = 0.0f;
        normals[(idx*NNB + 0)*NDIM + 2] = 0.0f;
        normals[(idx*NNB + 1)*NDIM + 0] = 0.0f;
        normals[(idx*NNB + 1)*NDIM + 1] = 1.0f;
        normals[(idx*NNB + 1)*NDIM + 2] = 0.0f;
        float diag = 0.57735026f * (1.0f + 0.01f*(cycle%7));
        normals[(idx*NNB + 2)*NDIM + 0] = 0.0f;
        normals[(idx*NNB + 2)*NDIM + 1] = 0.0f;
        normals[(idx*NNB + 2)*NDIM + 2] = 1.0f;
        normals[(idx*NNB + 3)*NDIM + 0] = diag;
        normals[(idx*NNB + 3)*NDIM + 1] = diag;
        normals[(idx*NNB + 3)*NDIM + 2] = diag;

        // Vary variables for this element
        variables[idx*NVAR + VAR_DENSITY] = 1.4f + 0.01f * (float)(cycle % 10);
        variables[idx*NVAR + (VAR_MOMENTUM+0)] = 1.0f + 0.1f * (float)(cycle % 5);
        variables[idx*NVAR + (VAR_MOMENTUM+1)] = 0.1f * (float)(cycle % 3);
        variables[idx*NVAR + (VAR_MOMENTUM+2)] = 0.05f * (float)(cycle % 4);
        variables[idx*NVAR + VAR_DENSITY_ENERGY] = 2.5f + 0.02f * (float)(cycle % 6);

        // Vary flux correction arrays for this element
        fc_momentum_x[idx*NDIM + 0] = 0.1f * (float)(cycle % 4);
        fc_momentum_x[idx*NDIM + 1] = 0.0f;
        fc_momentum_x[idx*NDIM + 2] = 0.0f;
        fc_momentum_y[idx*NDIM + 0] = 0.0f;
        fc_momentum_y[idx*NDIM + 1] = 0.1f * (float)(cycle % 3);
        fc_momentum_y[idx*NDIM + 2] = 0.0f;
        fc_momentum_z[idx*NDIM + 0] = 0.0f;
        fc_momentum_z[idx*NDIM + 1] = 0.0f;
        fc_momentum_z[idx*NDIM + 2] = 0.1f * (float)(cycle % 5);
        fc_density_energy[idx*NDIM + 0] = 0.01f * (float)(cycle % 7);
        fc_density_energy[idx*NDIM + 1] = 0.0f;
        fc_density_energy[idx*NDIM + 2] = 0.0f;

        // Call DUT
        cfd_flux(result, elements_surrounding_elements, normals, variables, fc_momentum_x, fc_momentum_y, fc_momentum_z, fc_density_energy);

        // Prepare recorded input values (as decimal integers) and output value (as hex uppercase, no 0x)
        // For array inputs we record representative first-element bit-patterns (or integer for elements_surrounding_elements)
        int ess_val = elements_surrounding_elements[0]; // integer input recorded as decimal
        uint32_t normals_u = float_to_u32(normals[0]);
        uint32_t variables_u = float_to_u32(variables[0]);
        uint32_t fcmx_u = float_to_u32(fc_momentum_x[0]);
        uint32_t fcmy_u = float_to_u32(fc_momentum_y[0]);
        uint32_t fcmz_u = float_to_u32(fc_momentum_z[0]);
        uint32_t fcd_u = float_to_u32(fc_density_energy[0]);

        // Output: result[0] as hex uppercase without 0x
        uint32_t result_u = float_to_u32(result[0]);

        // Write CSV line: cycle (decimal), inputs (decimal), output (hex uppercase)
        // Inputs printed as unsigned decimal integers (normals/variables bitpatterns), elements_surrounding_elements as signed decimal
        std::fprintf(csv, "%d,%d,%u,%u,%u,%u,%u,%u,%X\n",
                     cycle,
                     ess_val,
                     normals_u,
                     variables_u,
                     fcmx_u,
                     fcmy_u,
                     fcmz_u,
                     fcd_u,
                     result_u);
    }

    // Close CSV
    std::fclose(csv);

    // Free memory
    free(result);
    free(elements_surrounding_elements);
    free(normals);
    free(variables);
    free(fc_momentum_x);
    free(fc_momentum_y);
    free(fc_momentum_z);
    free(fc_density_energy);

    return 0;
}

hls_src:
// hls.cpp
// CFD flux kernel adapted for Vivado HLS
// Top-level function uses C linkage (extern "C") so the HLS testbench can link correctly.
// Comments in English.
// Fixed: tile kernel uses a base index so tile-local loop index is translated to global element index.
// Fixed: top-level function signature matches the testbench (no const qualifiers on array parameters).

#include <cmath>

// Constants and macros
#define GAMMA 1.4f
#define NVAR 5
#define NDIM 3
#define NNB 4
#define SIZE 1024
#define TILE_ROWS 32
#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY 4

// Define float3 struct
struct float3 {
    float x;
    float y;
    float z;
};

// Helper functions
static void compute_velocity(float density, const float3& momentum, float3& velocity) {
    velocity.x = momentum.x / density;
    velocity.y = momentum.y / density;
    velocity.z = momentum.z / density;
}

static float compute_speed_sqd(const float3& velocity) {
    return velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
}

static float compute_pressure(float density, float density_energy, float speed_sqd) {
    return (GAMMA - 1.0f)*(density_energy - 0.5f*density*speed_sqd);
}

static float compute_speed_of_sound(float density, float pressure) {
    return std::sqrt(GAMMA*pressure / density);
}

// Internal compute kernel for one tile
// base_index: global index of the first element in this tile (k * TILE_ROWS)
// This allows the tile kernel to index global arrays correctly while looping 0..TILE_ROWS-1.
static void cfd_flux_tile(float result[TILE_ROWS * NVAR],
                           const int elements_surrounding_elements[TILE_ROWS * NNB],
                           const float normals[TILE_ROWS * NNB * NDIM],
                           const float variables[SIZE * NVAR],
                           const float fc_momentum_x[SIZE * NDIM],
                           const float fc_momentum_y[SIZE * NDIM],
                           const float fc_momentum_z[SIZE * NDIM],
                           const float fc_density_energy[SIZE * NDIM],
                           int base_index) {

    const float smoothing_coefficient = 0.2f;

    // Far-field reference values
    float ff_variable[NVAR] = {1.3999999761581421f, 1.6800000667572021f, 0.0f, 0.0f, 3.5079998970031738f};

    float3 ff_fc_momentum_x = {3.016000270843506f, 0.0f, 0.0f};
    float3 ff_fc_momentum_y = {0.0f, 1.0f, 0.0f};
    float3 ff_fc_momentum_z = {0.0f, 0.0f, 1.0f};
    float3 ff_fc_density_energy = {5.409600257873535f, 0.0f, 0.0f};

    for(int i = 0; i < TILE_ROWS; i++) {
#pragma HLS pipeline
        int j, nb;
        float3 normal; float normal_len;
        float factor;

        // Translate tile-local slot i to global element index
        int gi = base_index + i;

        // Load self element data using global index gi
        float density_i = variables[NVAR*gi + VAR_DENSITY];
        float3 momentum_i;
        momentum_i.x = variables[NVAR*gi + (VAR_MOMENTUM+0)];
        momentum_i.y = variables[NVAR*gi + (VAR_MOMENTUM+1)];
        momentum_i.z = variables[NVAR*gi + (VAR_MOMENTUM+2)];
        float density_energy_i = variables[NVAR*gi + VAR_DENSITY_ENERGY];

        float3 velocity_i; compute_velocity(density_i, momentum_i, velocity_i);
        float speed_sqd_i = compute_speed_sqd(velocity_i);
        float speed_i = std::sqrt(speed_sqd_i);
        float pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
        float speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);

        float3 fc_i_momentum_x, fc_i_momentum_y, fc_i_momentum_z;
        float3 fc_i_density_energy;

        fc_i_momentum_x.x = fc_momentum_x[gi*NDIM + 0];
        fc_i_momentum_x.y = fc_momentum_x[gi*NDIM + 1];
        fc_i_momentum_x.z = fc_momentum_x[gi*NDIM + 2];

        fc_i_momentum_y.x = fc_momentum_y[gi*NDIM + 0];
        fc_i_momentum_y.y = fc_momentum_y[gi*NDIM + 1];
        fc_i_momentum_y.z = fc_momentum_y[gi*NDIM + 2];

        fc_i_momentum_z.x = fc_momentum_z[gi*NDIM + 0];
        fc_i_momentum_z.y = fc_momentum_z[gi*NDIM + 1];
        fc_i_momentum_z.z = fc_momentum_z[gi*NDIM + 2];

        fc_i_density_energy.x = fc_density_energy[gi*NDIM + 0];
        fc_i_density_energy.y = fc_density_energy[gi*NDIM + 1];
        fc_i_density_energy.z = fc_density_energy[gi*NDIM + 2];

        float flux_i_density = 0.0f;
        float3 flux_i_momentum = {0.0f, 0.0f, 0.0f};
        float flux_i_density_energy = 0.0f;

        float3 velocity_nb;
        float density_nb, density_energy_nb;
        float3 momentum_nb;
        float3 fc_nb_momentum_x, fc_nb_momentum_y, fc_nb_momentum_z;
        float3 fc_nb_density_energy;
        float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

        for(j = 0; j < NNB; j++) {
#pragma HLS unroll
            nb = elements_surrounding_elements[i*NNB + j]; // nb is a global index or a sentinel
            normal.x = normals[(i*NNB + j)*NDIM + 0];
            normal.y = normals[(i*NNB + j)*NDIM + 1];
            normal.z = normals[(i*NNB + j)*NDIM + 2];
            normal_len = std::sqrt(normal.x*normal.x + normal.y*normal.y + normal.z*normal.z);

            if(nb >= 0) {
                // Neighbor is a valid global element index
                density_nb = variables[nb*NVAR + VAR_DENSITY];
                momentum_nb.x = variables[nb*NVAR + (VAR_MOMENTUM+0)];
                momentum_nb.y = variables[nb*NVAR + (VAR_MOMENTUM+1)];
                momentum_nb.z = variables[nb*NVAR + (VAR_MOMENTUM+2)];
                density_energy_nb = variables[nb*NVAR + VAR_DENSITY_ENERGY];

                compute_velocity(density_nb, momentum_nb, velocity_nb);
                speed_sqd_nb = compute_speed_sqd(velocity_nb);
                pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
                speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);

                fc_nb_momentum_x.x = fc_momentum_x[nb*NDIM + 0];
                fc_nb_momentum_x.y = fc_momentum_x[nb*NDIM + 1];
                fc_nb_momentum_x.z = fc_momentum_x[nb*NDIM + 2];

                fc_nb_momentum_y.x = fc_momentum_y[nb*NDIM + 0];
                fc_nb_momentum_y.y = fc_momentum_y[nb*NDIM + 1];
                fc_nb_momentum_y.z = fc_momentum_y[nb*NDIM + 2];

                fc_nb_momentum_z.x = fc_momentum_z[nb*NDIM + 0];
                fc_nb_momentum_z.y = fc_momentum_z[nb*NDIM + 1];
                fc_nb_momentum_z.z = fc_momentum_z[nb*NDIM + 2];

                fc_nb_density_energy.x = fc_density_energy[nb*NDIM + 0];
                fc_nb_density_energy.y = fc_density_energy[nb*NDIM + 1];
                fc_nb_density_energy.z = fc_density_energy[nb*NDIM + 2];

                factor = -normal_len*smoothing_coefficient*0.5f*(speed_i + std::sqrt(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor*(density_i-density_nb);
                flux_i_density_energy += factor*(density_energy_i-density_energy_nb);
                flux_i_momentum.x += factor*(momentum_i.x-momentum_nb.x);
                flux_i_momentum.y += factor*(momentum_i.y-momentum_nb.y);
                flux_i_momentum.z += factor*(momentum_i.z-momentum_nb.z);

                factor = 0.5f*normal.x;
                flux_i_density += factor*(momentum_nb.x+momentum_i.x);
                flux_i_density_energy += factor*(fc_nb_density_energy.x+fc_i_density_energy.x);
                flux_i_momentum.x += factor*(fc_nb_momentum_x.x+fc_i_momentum_x.x);
                flux_i_momentum.y += factor*(fc_nb_momentum_y.x+fc_i_momentum_y.x);
                flux_i_momentum.z += factor*(fc_nb_momentum_z.x+fc_i_momentum_z.x);

                factor = 0.5f*normal.y;
                flux_i_density += factor*(momentum_nb.y+momentum_i.y);
                flux_i_density_energy += factor*(fc_nb_density_energy.y+fc_i_density_energy.y);
                flux_i_momentum.x += factor*(fc_nb_momentum_x.y+fc_i_momentum_x.y);
                flux_i_momentum.y += factor*(fc_nb_momentum_y.y+fc_i_momentum_y.y);
                flux_i_momentum.z += factor*(fc_nb_momentum_z.y+fc_i_momentum_z.y);

                factor = 0.5f*normal.z;
                flux_i_density += factor*(momentum_nb.z+momentum_i.z);
                flux_i_density_energy += factor*(fc_nb_density_energy.z+fc_i_density_energy.z);
                flux_i_momentum.x += factor*(fc_nb_momentum_x.z+fc_i_momentum_x.z);
                flux_i_momentum.y += factor*(fc_nb_momentum_y.z+fc_i_momentum_y.z);
                flux_i_momentum.z += factor*(fc_nb_momentum_z.z+fc_i_momentum_z.z);
            } else if(nb == -1) {
                // boundary: add pressure term
                flux_i_momentum.x += normal.x*pressure_i;
                flux_i_momentum.y += normal.y*pressure_i;
                flux_i_momentum.z += normal.z*pressure_i;
            } else if(nb == -2) {
                // far-field: use ff values
                factor = 0.5f*normal.x;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+0]+momentum_i.x);
                flux_i_density_energy += factor*(ff_fc_density_energy.x+fc_i_density_energy.x);
                flux_i_momentum.x += factor*(ff_fc_momentum_x.x + fc_i_momentum_x.x);
                flux_i_momentum.y += factor*(ff_fc_momentum_y.x + fc_i_momentum_y.x);
                flux_i_momentum.z += factor*(ff_fc_momentum_z.x + fc_i_momentum_z.x);

                factor = 0.5f*normal.y;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i.y);
                flux_i_density_energy += factor*(ff_fc_density_energy.y+fc_i_density_energy.y);
                flux_i_momentum.x += factor*(ff_fc_momentum_x.y + fc_i_momentum_x.y);
                flux_i_momentum.y += factor*(ff_fc_momentum_y.y + fc_i_momentum_y.y);
                flux_i_momentum.z += factor*(ff_fc_momentum_z.y + fc_i_momentum_z.y);

                factor = 0.5f*normal.z;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i.z);
                flux_i_density_energy += factor*(ff_fc_density_energy.z+fc_i_density_energy.z);
                flux_i_momentum.x += factor*(ff_fc_momentum_x.z + fc_i_momentum_x.z);
                flux_i_momentum.y += factor*(ff_fc_momentum_y.z + fc_i_momentum_y.z);
                flux_i_momentum.z += factor*(ff_fc_momentum_z.z + fc_i_momentum_z.z);
            }
        }

        // Store tile-local result (i slot corresponds to global element gi)
        result[i*NVAR + VAR_DENSITY] = flux_i_density;
        result[i*NVAR + (VAR_MOMENTUM+0)] = flux_i_momentum.x;
        result[i*NVAR + (VAR_MOMENTUM+1)] = flux_i_momentum.y;
        result[i*NVAR + (VAR_MOMENTUM+2)] = flux_i_momentum.z;
        result[i*NVAR + VAR_DENSITY_ENERGY] = flux_i_density_energy;
    }
}

// Top-level kernel with C linkage so testbench can link to it
extern "C" void cfd_flux(float result[SIZE * NVAR],
              int elements_surrounding_elements[SIZE * NNB],
              float normals[SIZE * NNB * NDIM],
              float variables[SIZE * NVAR],
              float fc_momentum_x[SIZE * NDIM],
              float fc_momentum_y[SIZE * NDIM],
              float fc_momentum_z[SIZE * NDIM],
              float fc_density_energy[SIZE * NDIM]) {

#pragma HLS INTERFACE m_axi port=result offset=slave bundle=result
#pragma HLS INTERFACE m_axi port=elements_surrounding_elements offset=slave bundle=elements_surrounding_elements
#pragma HLS INTERFACE m_axi port=normals offset=slave bundle=normals
#pragma HLS INTERFACE m_axi port=variables offset=slave bundle=variables
#pragma HLS INTERFACE m_axi port=fc_momentum_x offset=slave bundle=fc_momentum_x
#pragma HLS INTERFACE m_axi port=fc_momentum_y offset=slave bundle=fc_momentum_y
#pragma HLS INTERFACE m_axi port=fc_momentum_z offset=slave bundle=fc_momentum_z
#pragma HLS INTERFACE m_axi port=fc_density_energy offset=slave bundle=fc_density_energy

#pragma HLS INTERFACE s_axilite port=result bundle=control
#pragma HLS INTERFACE s_axilite port=elements_surrounding_elements bundle=control
#pragma HLS INTERFACE s_axilite port=normals bundle=control
#pragma HLS INTERFACE s_axilite port=variables bundle=control
#pragma HLS INTERFACE s_axilite port=fc_momentum_x bundle=control
#pragma HLS INTERFACE s_axilite port=fc_momentum_y bundle=control
#pragma HLS INTERFACE s_axilite port=fc_momentum_z bundle=control
#pragma HLS INTERFACE s_axilite port=fc_density_energy bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local buffers
    float result_inner[TILE_ROWS * NVAR];
    int elements_surrounding_elements_inner[TILE_ROWS * NNB];
    float normals_inner[TILE_ROWS * NNB * NDIM];

    // Full-size copies of read-only global arrays for on-chip access
    float variables_inner[SIZE * NVAR];
    float fc_momentum_x_inner[SIZE * NDIM];
    float fc_momentum_y_inner[SIZE * NDIM];
    float fc_momentum_z_inner[SIZE * NDIM];
    float fc_density_energy_inner[SIZE * NDIM];

#pragma HLS array_partition variable=result_inner cyclic factor=16 dim=1
#pragma HLS array_partition variable=elements_surrounding_elements_inner cyclic factor=2 dim=1
#pragma HLS array_partition variable=normals_inner block factor=128 dim=1
#pragma HLS array_partition variable=variables_inner cyclic factor=128 dim=1
#pragma HLS array_partition variable=fc_momentum_x_inner cyclic factor=64 dim=1
#pragma HLS array_partition variable=fc_momentum_y_inner block factor=16 dim=1
#pragma HLS array_partition variable=fc_momentum_z_inner cyclic factor=4 dim=1
#pragma HLS array_partition variable=fc_density_energy_inner block factor=32 dim=1

    // Copy large arrays once into on-chip buffers
    for(int i = 0; i < SIZE * NVAR; i++) {
#pragma HLS pipeline
        variables_inner[i] = variables[i];
    }
    for(int i = 0; i < SIZE * NDIM; i++) {
#pragma HLS pipeline
        fc_momentum_x_inner[i] = fc_momentum_x[i];
        fc_momentum_y_inner[i] = fc_momentum_y[i];
        fc_momentum_z_inner[i] = fc_momentum_z[i];
        fc_density_energy_inner[i] = fc_density_energy[i];
    }

    // Process tiles
    for (int k = 0; k < SIZE / TILE_ROWS; k++) {
#pragma HLS pipeline
        int base = k * TILE_ROWS;

        // Copy tile-specific inputs
        for(int i = 0; i < TILE_ROWS * NNB; i++) {
#pragma HLS pipeline
            elements_surrounding_elements_inner[i] = elements_surrounding_elements[base * NNB + i];
        }
        for(int i = 0; i < TILE_ROWS * NNB * NDIM; i++) {
#pragma HLS pipeline
            normals_inner[i] = normals[base * NNB * NDIM + i];
        }

        // Call tile compute with base index so the tile kernel can index global arrays
        cfd_flux_tile(result_inner, elements_surrounding_elements_inner, normals_inner,
                      variables_inner, fc_momentum_x_inner, fc_momentum_y_inner, fc_momentum_z_inner, fc_density_energy_inner,
                      base);

        // Copy back results to global output buffer
        for(int i = 0; i < TILE_ROWS * NVAR; i++) {
#pragma HLS pipeline
            result[base * NVAR + i] = result_inner[i];
        }
    }
}

