// tb_hls_cosim.cpp
// HLS C/RTL co-simulation testbench for cfd_flux
// Modified to use C stdint.h header for compatibility with older HLS C++ runtime
// Comments in English.

#include <cstdio>
#include <stdint.h>   // use C header for older toolchain compatibility instead of <cstdint>
#include <cstdlib>
#include <cmath>
#include <cstring>

#define GRID_ROWS (1024)
#define SIZE GRID_ROWS
#define TILE_ROWS 32
#define PARA_FACTOR 16
#define TOP 0
#define BOTTOM (GRID_ROWS / TILE_ROWS - 1)
#define GAMMA 1.4f
#define NDIM 3
#define NNB 4
#define RK 3
#define ff_mach 1.2f
#define deg_angle_of_attack 0.0f
#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)
#define TYPE float

struct float3 { float x, y, z; };

void compute_velocity(float density, struct float3 momentum, struct float3 *velocity);
float compute_speed_sqd(struct float3 velocity);
float compute_pressure(float density, float density_energy, float speed_sqd);
float compute_speed_of_sound(float density, float pressure);

// The DUT top-level declaration must match the HLSC definition exactly
extern "C" void cfd_flux(float result[SIZE * NVAR],
                         int elements_surrounding_elements [SIZE * NNB],
                         float normals [SIZE * NNB * NDIM],
                         float variables [SIZE * NVAR],
                         float fc_momentum_x [SIZE * NDIM],
                         float fc_momentum_y [SIZE * NDIM],
                         float fc_momentum_z [SIZE * NDIM],
                         float fc_density_energy [SIZE * NDIM]);

static inline uint32_t float_to_u32(float f) {
    uint32_t u;
    // Use memcpy (C-style) for bit-preserving conversion
    std::memcpy(&u, &f, sizeof(u));
    return u;
}

void compute_velocity(float density, struct float3 momentum, struct float3 *velocity)
{
    velocity->x = momentum.x / density;
    velocity->y = momentum.y / density;
    velocity->z = momentum.z / density;
}

float compute_speed_sqd(struct float3 velocity)
{
    return velocity.x*velocity.x + velocity.y*velocity.y + velocity.z*velocity.z;
}

float compute_pressure(float density, float density_energy, float speed_sqd)
{
    return (GAMMA - 1.0f)*(density_energy - 0.5f*density*speed_sqd);
}

float compute_speed_of_sound(float density, float pressure)
{
    return sqrtf(GAMMA*pressure / density);
}

int main()
{
    // Allocate arrays
    float *result = (float*)malloc(sizeof(float)*SIZE*NVAR);
    int *elements_surrounding_elements = (int*)malloc(sizeof(int)*SIZE*NNB);
    float *normals = (float*)malloc(sizeof(float)*SIZE*NNB*NDIM);
    float *variables = (float*)malloc(sizeof(float)*SIZE*NVAR);
    float *fc_momentum_x = (float*)malloc(sizeof(float)*SIZE*NDIM);
    float *fc_momentum_y = (float*)malloc(sizeof(float)*SIZE*NDIM);
    float *fc_momentum_z = (float*)malloc(sizeof(float)*SIZE*NDIM);
    float *fc_density_energy = (float*)malloc(sizeof(float)*SIZE*NDIM);

    if(!result || !elements_surrounding_elements || !normals || !variables || !fc_momentum_x || !fc_momentum_y || !fc_momentum_z || !fc_density_energy) {
        std::fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    // Initial deterministic fill (based on original reference)
    for(int i=0;i<SIZE;i++){
        variables[i*NVAR + VAR_DENSITY] = 1.4f;
        variables[i*NVAR + (VAR_MOMENTUM+0)] = 1.0f;
        variables[i*NVAR + (VAR_MOMENTUM+1)] = 0.0f;
        variables[i*NVAR + (VAR_MOMENTUM+2)] = 0.0f;
        variables[i*NVAR + VAR_DENSITY_ENERGY] = 2.5f;

        fc_momentum_x[i*NDIM + 0] = 0.0f; fc_momentum_x[i*NDIM + 1] = 0.0f; fc_momentum_x[i*NDIM + 2] = 0.0f;
        fc_momentum_y[i*NDIM + 0] = 0.0f; fc_momentum_y[i*NDIM + 1] = 0.0f; fc_momentum_y[i*NDIM + 2] = 0.0f;
        fc_momentum_z[i*NDIM + 0] = 0.0f; fc_momentum_z[i*NDIM + 1] = 0.0f; fc_momentum_z[i*NDIM + 2] = 0.0f;
        fc_density_energy[i*NDIM + 0] = 0.0f; fc_density_energy[i*NDIM + 1] = 0.0f; fc_density_energy[i*NDIM + 2] = 0.0f;

        for(int j=0;j<NNB;j++){
            elements_surrounding_elements[i*NNB + j] = -2;
            normals[(i*NNB + j)*NDIM + 0] = (j==0)?1.0f:0.0f;
            normals[(i*NNB + j)*NDIM + 1] = (j==1)?1.0f:0.0f;
            normals[(i*NNB + j)*NDIM + 2] = (j==2)?1.0f:0.0f;
            if(j==3){
                normals[(i*NNB + j)*NDIM + 0] = 0.57735026f;
                normals[(i*NNB + j)*NDIM + 1] = 0.57735026f;
                normals[(i*NNB + j)*NDIM + 2] = 0.57735026f;
            }
        }
    }

    // Prepare CSV file for HLS/RTL output
    FILE *csv = std::fopen("hls_output.csv", "w");
    if(!csv) {
        std::fprintf(stderr, "Unable to open hls_output.csv for writing\n");
        return 1;
    }

    // Header line: cycle, then DUT input names (must match DUT ports / testbench signals), then outputs
    std::fprintf(csv, "cycle,elements_surrounding_elements,normals,variables,fc_momentum_x,fc_momentum_y,fc_momentum_z,fc_density_energy,result\n");
    // Role line
    std::fprintf(csv, "meta,in,in,in,in,in,in,in,out\n");

    // Number of cycles: choose 32 (within 20-50)
    const int CYCLES = 32;

    for(int cycle = 0; cycle < CYCLES; cycle++) {
        // Deterministic variation of a few entries based on cycle index to create varied test vectors
        int idx = cycle % SIZE; // element index to modify this cycle (wraps but deterministic)

        // Vary neighbor flags for this element
        int mode = cycle % 4;
        if(mode == 0) {
            // far-field (-2) for all neighbors
            for(int j=0;j<NNB;j++) elements_surrounding_elements[idx*NNB + j] = -2;
        } else if(mode == 1) {
            // one boundary (-1), others far-field
            elements_surrounding_elements[idx*NNB + 0] = -1;
            elements_surrounding_elements[idx*NNB + 1] = -2;
            elements_surrounding_elements[idx*NNB + 2] = -2;
            elements_surrounding_elements[idx*NNB + 3] = -2;
        } else if(mode == 2) {
            // one valid neighbor (use a small positive index), others far-field
            int nbidx = (idx + 1) % SIZE;
            elements_surrounding_elements[idx*NNB + 0] = nbidx;
            elements_surrounding_elements[idx*NNB + 1] = -2;
            elements_surrounding_elements[idx*NNB + 2] = -2;
            elements_surrounding_elements[idx*NNB + 3] = -2;
            // also modify that neighbor slightly to create asymmetric data
            variables[nbidx*NVAR + VAR_DENSITY] = 1.2f + 0.05f * (float)(cycle % 5);
            variables[nbidx*NVAR + (VAR_MOMENTUM+0)] = 0.5f * (float)((cycle%3)+1);
        } else {
            // a negative value not explicitly handled (-3) to test robustness
            for(int j=0;j<NNB;j++) elements_surrounding_elements[idx*NNB + j] = -3;
        }

        // Vary normals for this element's neighbors
        normals[(idx*NNB + 0)*NDIM + 0] = 1.0f;
        normals[(idx*NNB + 0)*NDIM + 1] = 0.0f;
        normals[(idx*NNB + 0)*NDIM + 2] = 0.0f;
        normals[(idx*NNB + 1)*NDIM + 0] = 0.0f;
        normals[(idx*NNB + 1)*NDIM + 1] = 1.0f;
        normals[(idx*NNB + 1)*NDIM + 2] = 0.0f;
        float diag = 0.57735026f * (1.0f + 0.01f*(cycle%7));
        normals[(idx*NNB + 2)*NDIM + 0] = 0.0f;
        normals[(idx*NNB + 2)*NDIM + 1] = 0.0f;
        normals[(idx*NNB + 2)*NDIM + 2] = 1.0f;
        normals[(idx*NNB + 3)*NDIM + 0] = diag;
        normals[(idx*NNB + 3)*NDIM + 1] = diag;
        normals[(idx*NNB + 3)*NDIM + 2] = diag;

        // Vary variables for this element
        variables[idx*NVAR + VAR_DENSITY] = 1.4f + 0.01f * (float)(cycle % 10);
        variables[idx*NVAR + (VAR_MOMENTUM+0)] = 1.0f + 0.1f * (float)(cycle % 5);
        variables[idx*NVAR + (VAR_MOMENTUM+1)] = 0.1f * (float)(cycle % 3);
        variables[idx*NVAR + (VAR_MOMENTUM+2)] = 0.05f * (float)(cycle % 4);
        variables[idx*NVAR + VAR_DENSITY_ENERGY] = 2.5f + 0.02f * (float)(cycle % 6);

        // Vary flux correction arrays for this element
        fc_momentum_x[idx*NDIM + 0] = 0.1f * (float)(cycle % 4);
        fc_momentum_x[idx*NDIM + 1] = 0.0f;
        fc_momentum_x[idx*NDIM + 2] = 0.0f;
        fc_momentum_y[idx*NDIM + 0] = 0.0f;
        fc_momentum_y[idx*NDIM + 1] = 0.1f * (float)(cycle % 3);
        fc_momentum_y[idx*NDIM + 2] = 0.0f;
        fc_momentum_z[idx*NDIM + 0] = 0.0f;
        fc_momentum_z[idx*NDIM + 1] = 0.0f;
        fc_momentum_z[idx*NDIM + 2] = 0.1f * (float)(cycle % 5);
        fc_density_energy[idx*NDIM + 0] = 0.01f * (float)(cycle % 7);
        fc_density_energy[idx*NDIM + 1] = 0.0f;
        fc_density_energy[idx*NDIM + 2] = 0.0f;

        // Call DUT
        cfd_flux(result, elements_surrounding_elements, normals, variables, fc_momentum_x, fc_momentum_y, fc_momentum_z, fc_density_energy);

        // Prepare recorded input values (as decimal integers) and output value (as hex uppercase, no 0x)
        // For array inputs we record representative first-element bit-patterns (or integer for elements_surrounding_elements)
        int ess_val = elements_surrounding_elements[0]; // integer input recorded as decimal
        uint32_t normals_u = float_to_u32(normals[0]);
        uint32_t variables_u = float_to_u32(variables[0]);
        uint32_t fcmx_u = float_to_u32(fc_momentum_x[0]);
        uint32_t fcmy_u = float_to_u32(fc_momentum_y[0]);
        uint32_t fcmz_u = float_to_u32(fc_momentum_z[0]);
        uint32_t fcd_u = float_to_u32(fc_density_energy[0]);

        // Output: result[0] as hex uppercase without 0x
        uint32_t result_u = float_to_u32(result[0]);

        // Write CSV line: cycle (decimal), inputs (decimal/unsigned), output (hex uppercase)
        std::fprintf(csv, "%d,%d,%u,%u,%u,%u,%u,%u,%X\n",
                     cycle,
                     ess_val,
                     normals_u,
                     variables_u,
                     fcmx_u,
                     fcmy_u,
                     fcmz_u,
                     fcd_u,
                     result_u);
    }

    // Close CSV
    std::fclose(csv);

    // Free memory
    free(result);
    free(elements_surrounding_elements);
    free(normals);
    free(variables);
    free(fc_momentum_x);
    free(fc_momentum_y);
    free(fc_momentum_z);
    free(fc_density_energy);

    return 0;
}

