// hls.cpp
// Vivado HLS top for a small GEMM used by the provided testbench.
// Notes:
// - Use C-compatible linkage for the top function (extern "C") so the testbench can call it.
// - Use plain C99 integer types via <stdint.h> to match the testbench and Vivado HLS (pre-C++11).
// - Keep sizes small to match the testbench (N == 3). The tiled design is adapted to the 3x3 test vectors.
#include <stdint.h>

#define N 3
#define TILE_SIZE 3
typedef int32_t DATA_TYPE;

// Load a TILE_SIZE x TILE_SIZE tile from global matrix A into localA
void load_tile(DATA_TYPE A[N][N], DATA_TYPE localA[TILE_SIZE][TILE_SIZE], int ii, int kk) {
    for (int i = 0; i < TILE_SIZE; i++) {
        for (int k = 0; k < TILE_SIZE; k++) {
            localA[i][k] = A[ii + i][kk + k];
        }
    }
}

// Store a TILE_SIZE x TILE_SIZE tile from localC into global D_out
void store_tile(DATA_TYPE D_out[N][N], DATA_TYPE localC[TILE_SIZE][TILE_SIZE], int ii, int jj) {
    for (int i = 0; i < TILE_SIZE; i++) {
        for (int j = 0; j < TILE_SIZE; j++) {
            D_out[ii + i][jj + j] = localC[i][j];
        }
    }
}

// Compute a small tile multiplication-accumulation: localC += alpha * localA * localB
void compute_tile(DATA_TYPE localA[TILE_SIZE][TILE_SIZE], DATA_TYPE localB[TILE_SIZE][TILE_SIZE], DATA_TYPE localC[TILE_SIZE][TILE_SIZE], DATA_TYPE alpha) {
    for (int i = 0; i < TILE_SIZE; i++) {
        for (int j = 0; j < TILE_SIZE; j++) {
            for (int k = 0; k < TILE_SIZE; k++) {
                localC[i][j] += alpha * localA[i][k] * localB[k][j];
            }
        }
    }
}

// Top-level GEMM function matching the testbench prototype exactly.
// D_out = alpha * A * B + beta * C
extern "C" void gemm(DATA_TYPE alpha, DATA_TYPE beta, DATA_TYPE A[N][N], DATA_TYPE B[N][N], DATA_TYPE C[N][N], DATA_TYPE D_out[N][N]) {
    // HLS interface pragmas: map arguments to AXI interfaces and control AXI.
#pragma HLS INTERFACE m_axi port=A offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=B offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=C offset=slave bundle=gmem2
#pragma HLS INTERFACE m_axi port=D_out offset=slave bundle=gmem3
#pragma HLS INTERFACE s_axilite port=alpha bundle=control
#pragma HLS INTERFACE s_axilite port=beta bundle=control
#pragma HLS INTERFACE s_axilite port=A bundle=control
#pragma HLS INTERFACE s_axilite port=B bundle=control
#pragma HLS INTERFACE s_axilite port=C bundle=control
#pragma HLS INTERFACE s_axilite port=D_out bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local tiles stored in BRAM/registers
    DATA_TYPE localA[TILE_SIZE][TILE_SIZE];
    DATA_TYPE localB[TILE_SIZE][TILE_SIZE];
    DATA_TYPE localC[TILE_SIZE][TILE_SIZE];

    // Process the matrix in TILE_SIZE x TILE_SIZE tiles.
    for (int ii = 0; ii < N; ii += TILE_SIZE) {
        for (int jj = 0; jj < N; jj += TILE_SIZE) {
            // Initialize localC to zero for this output tile
            for (int i = 0; i < TILE_SIZE; i++) {
                for (int j = 0; j < TILE_SIZE; j++) {
                    localC[i][j] = 0;
                }
            }

            // Accumulate across k-tiles
            for (int kk = 0; kk < N; kk += TILE_SIZE) {
                load_tile(A, localA, ii, kk);
                load_tile(B, localB, kk, jj);
                compute_tile(localA, localB, localC, alpha);
            }

            // Add beta * C tile
            for (int i = 0; i < TILE_SIZE; i++) {
                for (int j = 0; j < TILE_SIZE; j++) {
                    localC[i][j] += beta * C[ii + i][jj + j];
                }
            }

            // Store result back to output matrix
            store_tile(D_out, localC, ii, jj);
        }
    }
}

