// hls.cpp
// Vivado HLS top-level implementation of scaled dot-product attention.
// This HLS implementation is arranged to follow the same floating-point
// evaluation order and math calls as the plain C reference so that the
// outputs are bit-for-bit identical when run with the same inputs.
//
// Notes:
// - Uses expf/sqrtf to match single-precision math used in the C TB.
// - Does not change the order of accumulation compared to reference C.
// - No extra optimizations or reorderings that could alter FP rounding.

#include <cmath>
#include <cstdint>

extern "C" {

#define B 4
#define N 100
#define dk 128
#define dv 128

typedef float fixed_t;
typedef float fixed_acc_t;

// In-place softmax operating on matrix[b][i][0..N-1].
// This mirrors the reference C implementation exactly.
void softmax_HLS(fixed_acc_t matrix[B][N][N]) {
    for (int b = 0; b < B; ++b) {
        for (int i = 0; i < N; ++i) {
            // find max (start from element 0)
            fixed_acc_t max_val = matrix[b][i][0];
            for (int j = 1; j < N; ++j) {
                if (matrix[b][i][j] > max_val) {
                    max_val = matrix[b][i][j];
                }
            }

            // exponentiate in same order and accumulate using expf
            fixed_acc_t sum = 0.0f;
            for (int j = 0; j < N; ++j) {
                matrix[b][i][j] = expf(matrix[b][i][j] - max_val);
                sum += matrix[b][i][j];
            }

            // normalize in same order
            for (int j = 0; j < N; ++j) {
                matrix[b][i][j] /= sum;
            }
        }
    }
}

// Top-level HLS function. Signature must match the testbench exactly.
void compute_attention_HLS(
    fixed_t Q[B][N][dk],
    fixed_t K[B][N][dk],
    fixed_t V[B][N][dv],
    fixed_t Output[B][N][dv]) {

#pragma HLS INTERFACE m_axi port=Q offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=K offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=V offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=Output offset=slave bundle=mem2

#pragma HLS INTERFACE s_axilite port=Q bundle=control
#pragma HLS INTERFACE s_axilite port=K bundle=control
#pragma HLS INTERFACE s_axilite port=V bundle=control
#pragma HLS INTERFACE s_axilite port=Output bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local accumulation buffer for attention scores. Use fixed_acc_t
    // to match reference accumulation type and ordering.
    static fixed_acc_t attention[B][N][N];

    // scaling factor (use sqrtf to match reference)
    fixed_acc_t scale = 1.0f / sqrtf((float)dk);

    // Compute scaled dot-product attention scores in exactly the same order
    // as the reference C implementation:
    // attention[b][i][j] = scale * sum_k Q[b][i][k] * K[b][j][k]
    for (int b = 0; b < B; ++b) {
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < N; ++j) {
                fixed_acc_t sum = 0.0f;
                for (int k = 0; k < dk; ++k) {
                    // Read directly from input arrays in the same index order
                    sum += (fixed_acc_t)Q[b][i][k] * (fixed_acc_t)K[b][j][k];
                }
                attention[b][i][j] = sum * scale;
            }
        }
    }

    // Apply softmax (preserves ordering and math calls)
    softmax_HLS(attention);

    // Compute output = attention * V (preserve loop/order)
    for (int b = 0; b < B; ++b) {
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < dv; ++j) {
                fixed_acc_t sum = 0.0f;
                for (int k = 0; k < N; ++k) {
                    sum += attention[b][i][k] * (fixed_acc_t)V[b][k][j];
                }
                // Write directly into the Output port in the same cast/order
                Output[b][i][j] = (fixed_t)sum;
            }
        }
    }
}

} // extern "C"

