// bit-for-bit identical to the provided C reference testbench so the
// two CSV files can be compared directly.

#include <cstdio>
#include <cstdint>
#include <cstdlib>
#include <cmath>
#include <cstring>

// Parameters must match the HLS design exactly
typedef float fixed_t;
#define B   4
#define N   100
#define dk  128
#define dv  128

// Extern top-level HLS function; signature must match the HLS C code.
extern "C" void compute_attention_HLS(fixed_t Q[B][N][dk], fixed_t K[B][N][dk], fixed_t V[B][N][dv], fixed_t Output[B][N][dv]);

int main() {
    // Testbench arrays (same shapes as DUT ports)
    static fixed_t Q[B][N][dk];
    static fixed_t K[B][N][dk];
    static fixed_t V[B][N][dv];
    static fixed_t Output[B][N][dv];

    // CSV file for HLS cosimulation outputs
    FILE *f = std::fopen("hls_output.csv", "w");
    if (!f) return 1;

    // Sample same Output elements as original C testbench
    const int SAMPLE_B = 0;
    const int SAMPLE_I = 0;
    const int SAMPLE_J_COUNT = 10;

    // Header line must match the original C testbench: "cycle,Output[0][0][0],..."
    std::fprintf(f, "cycle");
    for (int j = 0; j < SAMPLE_J_COUNT; ++j) {
        std::fprintf(f, ",Output[0][0][%d]", j);
    }
    std::fprintf(f, "\n");

    // Role line must match original: "meta" then outputs marked as out
    std::fprintf(f, "meta");
    for (int j = 0; j < SAMPLE_J_COUNT; ++j) {
        std::fprintf(f, ",out");
    }
    std::fprintf(f, "\n");

    // Number of cycles (between 20 and 50 as in original)
    const int CYCLES = 24;

    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        // Prepare inputs deterministically using same scheme as provided C testbench.
        if (cycle < 2) {
            for (int b = 0; b < B; ++b) {
                for (int i = 0; i < N; ++i) {
                    for (int k = 0; k < dk; ++k) {
                        Q[b][i][k] = 0.0f;
                        K[b][i][k] = 0.0f;
                    }
                    for (int v = 0; v < dv; ++v) {
                        V[b][i][v] = 0.0f;
                    }
                }
            }
        } else {
            for (int b = 0; b < B; ++b) {
                for (int i = 0; i < N; ++i) {
                    int base_idx = b * 100 + i;
                    for (int k = 0; k < dk; ++k) {
                        int qi = (base_idx * 131 + k + cycle) % 997;
                        Q[b][i][k] = (float)qi / 997.0f - 0.5f;
                        int ki = (base_idx * 137 + k * 3 + cycle * 7) % 1009;
                        K[b][i][k] = (float)ki / 1009.0f - 0.5f;
                    }
                    for (int v = 0; v < dv; ++v) {
                        int vi = (base_idx * 149 + v * 5 + cycle * 11) % 1013;
                        V[b][i][v] = (float)vi / 1013.0f - 0.5f;
                    }
                }
            }
        }

        // Call DUT
        compute_attention_HLS(Q, K, V, Output);

        // Write CSV line: cycle decimal, then sampled outputs as hex uppercase without 0x
        std::fprintf(f, "%d", cycle);
        for (int j = 0; j < SAMPLE_J_COUNT; ++j) {
            uint32_t bits = 0;
            static_assert(sizeof(bits) == sizeof(Output[0][0][0]), "Size mismatch");
            std::memcpy(&bits, &Output[SAMPLE_B][SAMPLE_I][j], sizeof(bits));
            std::fprintf(f, ",%X", bits);
        }
        std::fprintf(f, "\n");
    }

    std::fclose(f);
    return 0;
}

