// hls.cpp
// Simple iterative (bottom-up) merge sort implementation suitable for Vivado HLS.
// Top-level function required by the testbench: extern "C" void merge_sort_simple(float arr[], int l, int r, float temp[])
// Uses fixed SIZE matching the testbench (16). Uses only C headers compatible with older HLS toolchains.

#include <stdint.h>

#define SIZE 16

typedef float DTYPE;

extern "C" void merge_sort_simple(DTYPE arr[], int l, int r, DTYPE temp[]) {
    // HLS interface pragmas (kept simple for synthesis/cosim)
#pragma HLS INTERFACE s_axilite port=return bundle=control
#pragma HLS INTERFACE s_axilite port=l bundle=control
#pragma HLS INTERFACE s_axilite port=r bundle=control
#pragma HLS INTERFACE m_axi port=arr offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=temp offset=slave bundle=gmem

    // sanitize bounds
    if (l < 0) l = 0;
    if (r > SIZE) r = SIZE;

    int n = r - l;
    if (n <= 1) return;

    // bottom-up merge sort: merge runs of size width = 1,2,4,...
    for (int width = 1; width < n; width <<= 1) {
        // merge adjacent pairs of runs [i, i+width) and [i+width, i+2*width)
        for (int i = l; i < r; i += 2 * width) {
#pragma HLS pipeline II=1
            int left = i;
            int mid = i + width;
            if (mid > r) mid = r;
            int right = i + 2 * width;
            if (right > r) right = r;

            int p = left;
            int q = mid;
            int k = left;

            // merge into temp
            while (p < mid && q < right) {
                if (arr[p] <= arr[q]) {
                    temp[k++] = arr[p++];
                } else {
                    temp[k++] = arr[q++];
                }
            }
            while (p < mid) temp[k++] = arr[p++];
            while (q < right) temp[k++] = arr[q++];

            // copy merged output back into arr
            for (int t = left; t < right; ++t) {
#pragma HLS pipeline II=1
                arr[t] = temp[t];
            }
        }
    }
}

