void floyd_warshall(int path[60][60]) {
    const int n = 60;
    const int INF = 1000000000;
    int k, i, j;
    for (k = 0; k < n; k++) {
        int *rowk = path[k];
        for (i = 0; i < n; i++) {
            int *rowi = path[i];
            int ik = rowi[k];
            if (ik >= INF) continue;
            for (j = 0; j < n; j++) {
                int through = ik + rowk[j];
                if (through < rowi[j]) rowi[j] = through;
            }
        }
    }
}

static void init_path(int path[60][60], int t) {
    const int INF = 1000000000;
    // initialize to INF and zero diagonal
    for (int i = 0; i < 60; ++i) {
        for (int j = 0; j < 60; ++j) {
            path[i][j] = (i == j) ? 0 : INF;
        }
    }

    // Deterministic, varied test patterns based on t (no randomness).
    int mode = t % 5;
    if (mode == 0) {
        // sparse chain of length L
        int L = 5 + (t % 10); // between 5 and 14
        if (L > 60) L = 60;
        for (int i = 0; i + 1 < L; ++i) {
            path[i][i+1] = (i % 7) + 1;
        }
        // add a back edge occasionally
        if ((t % 3) == 0 && L >= 3) {
            path[L-1][0] = 10 + (t % 5);
        }
    } else if (mode == 1) {
        // symmetric edges based on XOR pattern
        int m = 11 + (t % 5);
        for (int i = 0; i < 60; ++i) {
            for (int j = i+1; j < 60; ++j) {
                if (((i ^ j) + t) % m == 0) {
                    int w = ((i * 3 + j * 2 + t) % 50) + 1;
                    path[i][j] = w;
                    path[j][i] = w;
                }
            }
        }
    } else if (mode == 2) {
        // star from node 0 and some spokes
        for (int j = 1; j < 60; ++j) {
            if ((j + t) % 3 == 0) {
                path[0][j] = (j % 9) + 2;
            }
            if ((j * (t+1)) % 5 == 0) {
                path[j][0] = (j % 7) + 3;
            }
        }
        // add a small clique among first few nodes
        int K = 4 + (t % 4);
        for (int i = 0; i < K; ++i) {
            for (int j = 0; j < K; ++j) if (i != j) {
                path[i][j] = ((i + j + t) % 6) + 1;
            }
        }
    } else if (mode == 3) {
        // simple directed cycle across many nodes
        for (int i = 0; i < 59; ++i) {
            path[i][i+1] = (i % 5) + 1;
        }
        path[59][0] = 10 + (t % 4);
        // add chords occasionally
        for (int i = 0; i < 60; ++i) {
            int j = (i + 5 + (t % 7)) % 60;
            if (i != j) path[i][j] = ((i + j + t) % 12) + 1;
        }
    } else { // mode == 4
        // denser-ish pattern using product modulus
        int m = 13 + (t % 7);
        for (int i = 0; i < 60; ++i) {
            for (int j = 0; j < 60; ++j) if (i != j) {
                if (((i * j) + t) % m == 0) {
                    path[i][j] = ((i + j + t) % 20) + 1;
                }
            }
        }
    }

    // Small additional deterministic tweaks for variety
    if ((t % 4) == 0) {
        // add a short path 10->20->30 with small weights
        path[10][20] = 4;
        path[20][30] = 6;
    }
    if ((t % 6) == 5) {
        // connect ends
        path[0][59] = 7;
        path[59][0] = 9;
    }
}

int main() {
    const int ROWS = 30; // cycles: produce between 20 and 50 lines
    FILE *f = std::fopen("c_output.csv", "w");
