// hls.cpp
// Top-level Floyd-Warshall kernel for Vivado HLS.
// This implementation matches the reference C testbench:
// - same INF constant
// - same loop order (k, i, j)
// - same short-circuit when path[i][k] is INF to avoid spurious updates
// The function is declared extern "C" so the symbol name matches the testbench.

#include <cstdint>

extern "C" {

#define N 60

void floyd_warshall(int path[N][N]) {
#pragma HLS INTERFACE m_axi port=path offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=path bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    const int n = N;
    const int INF = 1000000000;

    int k, i, j;

    // Use same loop order and same short-circuit as reference C implementation.
    for (k = 0; k < n; k++) {
        int *rowk = path[k];
        for (i = 0; i < n; i++) {
            int *rowi = path[i];
            int ik = rowi[k];
            // If path[i][k] is INF, skip the inner loop (no better paths via k).
            if (ik >= INF) continue;
            for (j = 0; j < n; j++) {
                int through = ik + rowk[j];
                if (through < rowi[j]) {
                    rowi[j] = through;
                }
            }
        }
    }
}

} // extern "C"

