// hls.cpp
// Vivado HLS top-level for vector-matrix multiply adapted for cosim with tb_hls_cosim.cpp
// Uses plain C types and C++98-compatible headers so it compiles in Vivado HLS 2018.3.
// The top function uses extern "C" and fixed dimensions to match the testbench.

#include <stdint.h>

// Use float for data type to match the testbench (tb_hls_cosim.cpp).
// For real HLS fixed-point usage replace this typedef with:
// #include <ap_fixed.h>
// typedef ap_fixed<16,5> data_t;
typedef float data_t;

#define ROWS 4
#define COLS 4

extern "C" {
void vec_matrix(
    data_t DRAM_1[ROWS][COLS],
    data_t DRAM_2[COLS],
    data_t DRAM_3[ROWS],
    data_t DRAM_4[ROWS]
) {
#pragma HLS INTERFACE m_axi port=DRAM_1 offset=off bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_2 offset=off bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_3 offset=off bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_4 offset=off bundle=mem2
#pragma HLS INTERFACE s_axilite port=DRAM_1 bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_2 bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_3 bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_4 bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local BRAM buffers
    data_t BRAM_1[ROWS][COLS];
    data_t BRAM_2[COLS];
    data_t BRAM_3[ROWS];
    data_t BRAM_4[ROWS];

    // Load DRAM_1 -> BRAM_1
    for (int r = 0; r < ROWS; ++r) {
        for (int c = 0; c < COLS; ++c) {
#pragma HLS PIPELINE II=1
            BRAM_1[r][c] = DRAM_1[r][c];
        }
    }

    // Load DRAM_2 -> BRAM_2
    for (int c = 0; c < COLS; ++c) {
#pragma HLS PIPELINE II=1
        BRAM_2[c] = DRAM_2[c];
    }

    // Load DRAM_3 -> BRAM_3 (even if unused by compute, keep to match original behavior)
    for (int r = 0; r < ROWS; ++r) {
#pragma HLS PIPELINE II=1
        BRAM_3[r] = DRAM_3[r];
    }

    // Initialize BRAM_4 to zero
    for (int r = 0; r < ROWS; ++r) {
#pragma HLS PIPELINE II=1
        BRAM_4[r] = (data_t)0;
    }

    // Compute BRAM_4 = BRAM_1 * BRAM_2 (row-wise dot product)
    for (int r = 0; r < ROWS; ++r) {
        for (int c = 0; c < COLS; ++c) {
#pragma HLS PIPELINE II=1
            BRAM_4[r] += BRAM_1[r][c] * BRAM_2[c];
        }
    }

    // Store BRAM_4 -> DRAM_4
    for (int r = 0; r < ROWS; ++r) {
#pragma HLS PIPELINE II=1
        DRAM_4[r] = BRAM_4[r];
    }
}
} // extern "C"

