// Testbench program generating c_output.csv
int main() {
    // Declare DUT arrays as static to avoid large stack usage
    static float DRAM_image_input[16][56][28];
    static float DRAM_conv_weight[16][16][1][1];
    static float DRAM_conv_bias[16];
    static float DRAM_batch_norm_weights[4][16];
    static float DRAM_image_output[16][58][30];

    // Open CSV file
    FILE* f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // CSV header (first row: names)
    // Order: cycle, then inputs driven by testbench, then outputs sampled from DUT
    std::fprintf(f, "cycle,DRAM_image_input,DRAM_conv_weight,DRAM_conv_bias,DRAM_batch_norm_weights,DRAM_image_output\n");

    // Second row: roles
    std::fprintf(f, "meta,in,in,in,in,out\n");

    // Number of cycles: choose 32 (within 20-50)
    const int CYCLES = 32;

    // Deterministic pattern fill functions (no randomness)
    auto fill_image = [&](int code) {
        // code is integer; produce varied but bounded floats
        for (int i = 0; i < 16; ++i) {
            for (int h = 0; h < 56; ++h) {
                for (int w = 0; w < 28; ++w) {
                    // pattern depends on indices and code
                    int v = ((i * 7 + h * 13 + w * 17) + code * 31) % 101; // 0..100
                    DRAM_image_input[i][h][w] = (float)(v - 50) * 0.02f;     // range approx -1.0 .. 1.0
                }
            }
        }
    };

    auto fill_weight = [&](int code) {
        for (int o = 0; o < 16; ++o) {
            for (int i = 0; i < 16; ++i) {
                int v = ((o * 11 + i * 19) + code * 5) % 61; // 0..60
                DRAM_conv_weight[o][i][0][0] = (float)(v - 30) * 0.03f; // roughly -0.9..0.9
            }
        }
    };

    auto fill_bias = [&](int code) {
        for (int o = 0; o < 16; ++o) {
            int v = ((o * 3) + code) % 21; // 0..20
            DRAM_conv_bias[o] = (float)(v - 10) * 0.05f; // -0.5 .. 0.5
        }
    };

    auto fill_batchnorm = [&](int code) {
        for (int o = 0; o < 16; ++o) {
            // mean
            int m = (o * 5 + code * 2) % 31;
            DRAM_batch_norm_weights[0][o] = (float)(m - 15) * 0.04f; // approx -0.6 .. 0.6

            // variance: ensure positive and reasonably sized
            int var_base = (o * 7 + code * 3) % 7; // 0..6
            DRAM_batch_norm_weights[1][o] = 0.5f + (float)var_base * 0.3f; // 0.5,0.8,1.1,...

            // gamma
            int g = (o + code) % 5;
            DRAM_batch_norm_weights[2][o] = 0.7f + g * 0.15f; // >0

            // beta
            int b = (o * 2 + code) % 11;
            DRAM_batch_norm_weights[3][o] = (float)(b - 5) * 0.02f;
        }
    };

    // Run cycles
    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        // Determine deterministic pattern codes for inputs (these are the integers we will print in CSV)
        int DRAM_image_input_code = 1 + (cycle % 3);           // 1..3
        int DRAM_conv_weight_code = 2 + (cycle % 4);          // 2..5
        int DRAM_conv_bias_code = cycle % 5;                  // 0..4
        int DRAM_batch_norm_weights_code = (cycle % 6);       // 0..5

        // Fill inputs according to codes
        fill_image(DRAM_image_input_code);
        fill_weight(DRAM_conv_weight_code);
        fill_bias(DRAM_conv_bias_code);
        fill_batchnorm(DRAM_batch_norm_weights_code);

        // Call DUT
        top(DRAM_image_input, DRAM_conv_weight, DRAM_conv_bias, DRAM_batch_norm_weights, DRAM_image_output);

        // Choose an output sample index deterministically per cycle
        int o = cycle % 16;
        int h = cycle % 58;
        int w = (cycle * 3 + 1) % 30;
        float out_val = DRAM_image_output[o][h][w];

        // Convert float bits to uint32 for hex output
        uint32_t out_bits;
        std::memcpy(&out_bits, &out_val, sizeof(out_bits));

        // Prepare hex string (uppercase, no 0x, no fixed width)
        char hexbuf[32];
        std::sprintf(hexbuf, "%X", (unsigned)out_bits);

        // Write CSV line:
        // cycle (decimal), input codes (decimal), output (hex uppercase)
        std::fprintf(f, "%d,%d,%d,%d,%d,%s\n",
                     cycle,
                     DRAM_image_input_code,
                     DRAM_conv_weight_code,
                     DRAM_conv_bias_code,
                     DRAM_batch_norm_weights_code,
                     hexbuf);
    }

    // Explicitly close file
    std::fclose(f);
    return 0;
}

