// hls.cpp
// Vivado HLS top function implementation using ap_fixed types.
// Batch-normalization weight layout expected by the testbench:
//   DRAM_batch_norm_weights[0][c] = mean
//   DRAM_batch_norm_weights[1][c] = variance
//   DRAM_batch_norm_weights[2][c] = gamma (scale)
//   DRAM_batch_norm_weights[3][c] = beta  (shift)

#include <ap_fixed.h>
#include <hls_math.h>

extern "C" {

typedef ap_fixed<16,5> data_t;

void top(
    data_t DRAM_image_input[16][56][28],
    data_t DRAM_conv_weight[16][16][1][1],
    data_t DRAM_conv_bias[16],
    data_t DRAM_batch_norm_weights[4][16],
    data_t DRAM_image_output[16][58][30])
{
#pragma HLS INTERFACE m_axi port=DRAM_image_input offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_conv_weight offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_conv_bias offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_batch_norm_weights offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_image_output offset=slave bundle=mem2
#pragma HLS INTERFACE s_axilite port=DRAM_image_input bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_conv_weight bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_conv_bias bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_batch_norm_weights bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_image_output bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local BRAM buffers (make static to avoid large stack allocations during cosimulation)
    static data_t BRAM_image_input[16][56][28];
    static data_t BRAM_conv_weight[16][16][1][1];
    static data_t BRAM_conv_bias[16];
    static data_t BRAM_batch_norm_weights[4][16];
    static data_t BRAM_buffer_1[16][58][30];
    static data_t BRAM_buffer_2[16][58][30];

    // Copy inputs from DRAM to BRAM
    for (int i0 = 0; i0 < 16; i0++) {
        for (int i1 = 0; i1 < 56; i1++) {
            for (int i2 = 0; i2 < 28; i2++) {
#pragma HLS PIPELINE II=1
                BRAM_image_input[i0][i1][i2] = DRAM_image_input[i0][i1][i2];
            }
        }
    }

    for (int i0 = 0; i0 < 16; i0++) {
        for (int i1 = 0; i1 < 16; i1++) {
#pragma HLS PIPELINE II=1
            BRAM_conv_weight[i0][i1][0][0] = DRAM_conv_weight[i0][i1][0][0];
        }
    }

    for (int i0 = 0; i0 < 16; i0++) {
#pragma HLS PIPELINE II=1
        BRAM_conv_bias[i0] = DRAM_conv_bias[i0];
    }

    for (int i0 = 0; i0 < 4; i0++) {
        for (int i1 = 0; i1 < 16; i1++) {
#pragma HLS PIPELINE II=1
            BRAM_batch_norm_weights[i0][i1] = DRAM_batch_norm_weights[i0][i1];
        }
    }

    // Initialize output buffer (buffer_1) to zero
    for (int co = 0; co < 16; co++) {
        for (int i = 0; i < 58; i++) {
            for (int j = 0; j < 30; j++) {
#pragma HLS PIPELINE II=1
                BRAM_buffer_1[co][i][j] = (data_t)0;
            }
        }
    }

    // group_conv2d with groups=1 (no grouping)
    int groups = 1;
    int c_in_per_group  = 16 / groups;
    int c_out_per_group = 16 / groups;

    for (int g = 0; g < groups; g++) {
        int co_start = g * c_out_per_group;
        int co_end   = co_start + c_out_per_group;

        int ci_start = g * c_in_per_group;
        int ci_end   = ci_start + c_in_per_group;

        for (int i = 0; i < 58; i++) {
            for (int j = 0; j < 30; j++) {
                for (int kh = 0; kh < 1; kh++) {
                    for (int kw = 0; kw < 1; kw++) {
                        int in_row = i * 1 - 1 + kh;
                        int in_col = j * 1 - 1 + kw;
                        if (in_row >= 0 && in_row < 56 && in_col >= 0 && in_col < 28) {
                            for (int ci = ci_start; ci < ci_end; ci++) {
                                for (int co = co_start; co < co_end; co++) {
#pragma HLS PIPELINE II=1
                                    BRAM_buffer_1[co][i][j] += BRAM_image_input[ci][in_row][in_col] * BRAM_conv_weight[co][ci][kh][kw];
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    // Batch normalization
    // NOTE: match the testbench layout:
    //   [0] = mean, [1] = variance, [2] = gamma, [3] = beta
    const data_t eps = (data_t)1e-05;
    for (int c = 0; c < 16; c++) {
        data_t mean  = BRAM_batch_norm_weights[0][c];
        data_t var   = BRAM_batch_norm_weights[1][c];
        data_t gamma = BRAM_batch_norm_weights[2][c];
        data_t beta  = BRAM_batch_norm_weights[3][c];
        for (int h = 0; h < 58; h++) {
            for (int w = 0; w < 30; w++) {
#pragma HLS PIPELINE II=1
                // compute sqrt in float then cast back to data_t to ensure math library is used safely
                float denom_f = hls::sqrt((float)(var + eps));
                data_t denom = (data_t)denom_f;
                data_t norm = (BRAM_buffer_1[c][h][w] - mean) / denom;
                BRAM_buffer_2[c][h][w] = gamma * norm + beta;
            }
        }
    }

    // ReLU activation
    for (int c = 0; c < 16; c++) {
        for (int i = 0; i < 58; i++) {
            for (int j = 0; j < 30; j++) {
#pragma HLS PIPELINE II=1
                BRAM_buffer_1[c][i][j] = (BRAM_buffer_2[c][i][j] > (data_t)0) ? BRAM_buffer_2[c][i][j] : (data_t)0;
            }
        }
    }

    // Store output back to DRAM
    for (int i0 = 0; i0 < 16; i0++) {
        for (int i1 = 0; i1 < 58; i1++) {
            for (int i2 = 0; i2 < 30; i2++) {
#pragma HLS PIPELINE II=1
                DRAM_image_output[i0][i1][i2] = BRAM_buffer_1[i0][i1][i2];
            }
        }
    }
}

} // extern "C"

