    float sum;
    int j, k;

    float l1_buf[65537];
    float l2_buf[17];

    memcpy(l1_buf, l1, sizeof(float) * 65537);

    l1_buf[0] = 1.0f;

    for (j = 1; j < 17; j++) {
        sum = 0.0f;
        for (k = 0; k < 65537; k++) {
            float product = conn[k * 17 + j] * l1_buf[k];
            sum += product;
        }
        l2_buf[j] = (1.0f / (1.0f + expf(-sum)));
    }

    memcpy(l2, l2_buf, sizeof(float) * 17);
}

