// hls.cpp
// Top-level HLS function implementing a simple dense-layer-like computation.
// Computes l2[j] = sum_k l1[k] * conn[k*17 + j] for j in 0..16.
// extern "C" is required for Vivado HLS C linkage of the top function.

extern "C" {

void backprop(float l1[65537], float l2[17], float conn[65537 * 17]) {
#pragma HLS INTERFACE m_axi port=l1   offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=l2   offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=conn offset=slave bundle=gmem2

#pragma HLS INTERFACE s_axilite port=l1   bundle=control
#pragma HLS INTERFACE s_axilite port=l2   bundle=control
#pragma HLS INTERFACE s_axilite port=conn bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Compute output vector l2 as dot-products between l1 and columns of conn.
    // Loop order: iterate over output elements (17) and accumulate over input vector (65537).
    // Simple synthesizable implementation. Additional optimizations can be added later.
    for (int j = 0; j < 17; ++j) {
        float acc = 0.0f;
        // Accumulate dot product for column j
        for (int k = 0; k < 65537; ++k) {
#pragma HLS PIPELINE II=1
            acc += l1[k] * conn[k * 17 + j];
        }
        l2[j] = acc;
    }
}

} // extern "C"

