        uint8_t nib = (v >> (k * 4)) & 0xF;
        if (nib < 10) out[15 - k] = char('0' + nib);
        else out[15 - k] = char('A' + (nib - 10));
    }
    out[16] = '\0';
    return std::string(out);
}

