// hls.cpp
// Top-level HLS function for lower-triangular solve (triangular solve).
// Keep extern "C" linkage so the testbench (C linkage) can link to this symbol.
//
// Note: This file is written to be compatible with Vivado HLS (C++98 mode).
extern "C" {

#define N 40

// Triangular solve: solve L * x = b for x, where L is lower-triangular with non-zero diagonal.
// The function name and signature must match the testbench exactly.
void trisolv(double L[N][N], double x[N], double b[N]) {
#pragma HLS INTERFACE m_axi port=L offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=x offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=b offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=L bundle=control
#pragma HLS INTERFACE s_axilite port=x bundle=control
#pragma HLS INTERFACE s_axilite port=b bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int i, j;

    // Perform forward substitution:
    // for i = 0 .. N-1:
    //   x[i] = ( b[i] - sum_{j=0..i-1} L[i][j] * x[j] ) / L[i][i]
    //
    // Pipeline the outer loop to achieve good throughput in HLS.
#pragma HLS PIPELINE II=1
    for (i = 0; i < N; i++) {
        double acc = b[i];
        // inner loop is data-dependent on i; do not unroll fully to avoid excessive resources.
        for (j = 0; j < i; j++) {
            acc -= L[i][j] * x[j];
        }
        x[i] = acc / L[i][i];
    }
}

} // extern "C"

