					if (p >= 0 && q >= 0 && p < GRID_ROWS && q < GRID_COLS && strel[m * STREL_COLS + n] != 0) {
						temp = img[starting_idx + p * GRID_COLS + q];
						if (temp > max) max = temp;
					}
				}
			}
			result[i * GRID_COLS + j] = max;
		}
	}
}

// Helper: reinterpret float bits to uint32_t
static uint32_t float_to_u32(float f) {
	uint32_t u;
	std::memcpy(&u, &f, sizeof(u));
	return u;
}

int main() {
	const int IMG_ROWS = GRID_ROWS + 2 * MAX_RADIUS;
	const int IMG_COLS = GRID_COLS;
	const int IMG_SIZE = IMG_ROWS * IMG_COLS;
	const int RESULT_SIZE = GRID_ROWS * GRID_COLS;

	float *img = (float*)malloc(sizeof(float) * IMG_SIZE);
	float *result = (float*)malloc(sizeof(float) * RESULT_SIZE);
	if (!img || !result) return 1;

	FILE *f = std::fopen("c_output.csv", "w");
	if (!f) {
		free(img);
		free(result);
		return 1;
	}

	// CSV header and roles
	std::fprintf(f, "cycle,img,result\n");
	std::fprintf(f, "meta,in,out\n");

	const int CYCLES = 25; // between 20 and 50

	for (int cycle = 0; cycle < CYCLES; cycle++) {
		// Initialize entire img buffer to 0
		for (int r = 0; r < IMG_ROWS; r++) {
			for (int ccol = 0; ccol < IMG_COLS; ccol++) {
				img[r * IMG_COLS + ccol] = 0.0f;
			}
		}

		// Fill central GRID_ROWS x GRID_COLS region with deterministic patterns
		int start_r = MAX_RADIUS;
		int start_c = 0;

		int pattern = cycle % 5;
		for (int i = 0; i < GRID_ROWS; i++) {
			for (int j = 0; j < GRID_COLS; j++) {
				int rr = start_r + i;
				int cc = start_c + j;
				float val = 0.0f;
				switch (pattern) {
					case 0: // all zeros
						val = 0.0f;
						break;
					case 1: { // single bright center
						int ci = GRID_ROWS / 2;
						int cj = GRID_COLS / 2;
						if (i == ci && j == cj) val = 100.0f + cycle;
						else val = 0.0f;
						break;
					}
					case 2: // diagonal/increasing values
						val = 10.0f + (float)(i * GRID_COLS + j) + (float)cycle;
						break;
					case 3: // horizontal stripes
						if ((i % 2) == 0) val = 20.0f + cycle;
						else val = 5.0f + cycle;
						break;
					case 4: // checkerboard
						val = ((i + j + cycle) % 2 == 0) ? 30.0f : 0.0f;
						break;
					default:
						val = 0.0f;
				}
				img[rr * IMG_COLS + cc] = val;
			}
		}

		// Additional small perturbations to test boundary conditions deterministically
		// Put some non-zero values in padding rows for certain cycles
		if (cycle % 7 == 0) {
			// top padding row (row 0)
			for (int ccol = 0; ccol < IMG_COLS; ccol++) {
				img[0 * IMG_COLS + ccol] = 1.0f + cycle;
			}
		}
		if (cycle % 11 == 0) {
			// bottom padding row
			for (int ccol = 0; ccol < IMG_COLS; ccol++) {
				img[(IMG_ROWS-1) * IMG_COLS + ccol] = 2.0f + cycle;
			}
		}

		// Call DUT
		dilate(result, img);

		// Serialize img as decimal integers (flatten full img buffer)
		std::string img_cell;
		img_cell.reserve(IMG_SIZE * 4);
		for (int idx = 0; idx < IMG_SIZE; idx++) {
			// input column should be decimal integers per spec; our test vectors are integer-valued floats
			int ival = (int)img[idx];
			img_cell.append(std::to_string(ival));
			if (idx + 1 < IMG_SIZE) img_cell.push_back(';');
		}

		// Serialize result as uppercase hexadecimal (float bit patterns) without 0x or fixed width
		std::string res_cell;
		res_cell.reserve(RESULT_SIZE * 10);
		for (int idx = 0; idx < RESULT_SIZE; idx++) {
			uint32_t bits = float_to_u32(result[idx]);
			// Format to hex uppercase without 0x
			char buf[16];
			std::snprintf(buf, sizeof(buf), "%X", bits);
			res_cell.append(buf);
			if (idx + 1 < RESULT_SIZE) res_cell.push_back(';');
		}

		// Write CSV row: cycle,img_cell,result_cell
		// Ensure no extra commas inside cells (we used semicolons)
		std::fprintf(f, "%d,%s,%s\n", cycle, img_cell.c_str(), res_cell.c_str());
	}

	std::fflush(f);
	std::fclose(f);

	free(img);
	free(result);
	return 0;
}

