// hls.cpp
// HLS implementation: small per-cycle LSTM-like update exposed as an extern "C" top-level
// Keep the top-level function C-linkage so Vivado HLS can find it from a C testbench.

#include <ap_fixed.h>
#include "hls_math.h"

// Number of units in the tiny LSTM-like vector state
#define NUM_UNITS 5

// Fixed-point type used for internal state and arithmetic
typedef ap_fixed<8,2> FIX_TYPE;

// Sigmoid implemented by converting fixed-point input to double, using hls::exp on double,
// then casting the result back to FIX_TYPE. Doing the math in floating point avoids
// relying on hls::exp overloads for ap_fixed.
static inline FIX_TYPE sigmoid(FIX_TYPE x) {
    double xd = (double)x;
    double ex = hls::exp(-xd);
    double result = 1.0 / (1.0 + ex);
    return (FIX_TYPE)result;
}

// Tanh implemented via exp by performing the math in double and then casting back.
static inline FIX_TYPE tanh_inhouse(FIX_TYPE x) {
    double xd = (double)x;
    double ex = hls::exp(xd);
    double emx = hls::exp(-xd);
    double result = (ex - emx) / (ex + emx);
    return (FIX_TYPE)result;
}

extern "C" {

// Top-level function with C linkage. This function is called every cycle by the testbench.
// It maintains internal hidden and cell states across calls (static variables).
void hls_main(double i_d, double f_d, double c_d, double o_d, double* hidden_state_) {
    // Convert inputs to FIX_TYPE
    FIX_TYPE in_i = (FIX_TYPE)i_d;
    FIX_TYPE in_f = (FIX_TYPE)f_d;
    FIX_TYPE in_c = (FIX_TYPE)c_d;
    FIX_TYPE in_o = (FIX_TYPE)o_d;

    // Persistent states across calls emulate an LSTM cell memory
    static FIX_TYPE hidden_states[NUM_UNITS];
    static FIX_TYPE cell_states[NUM_UNITS];
    // Explicit first-call initialization to be clear (static arrays are zero-initialized by default,
    // but initializing explicitly avoids depending on implicit behavior).
    static bool initialized = false;
    if (!initialized) {
        for (int ii = 0; ii < NUM_UNITS; ++ii) {
            hidden_states[ii] = (FIX_TYPE)0;
            cell_states[ii] = (FIX_TYPE)0;
        }
        initialized = true;
    }

    // Simple per-unit LSTM-like update. This is intentionally lightweight to
    // avoid complex interfaces and to ensure easy synthesis/simulation.
    for (int idx = 0; idx < NUM_UNITS; ++idx) {
        // Compute gates. For simplicity we mix the scalar inputs with the previous hidden.
        // Coefficients are small fixed-point constants; using FIX_TYPE conversions keeps behavior deterministic.
        FIX_TYPE f_gate = sigmoid(in_f + hidden_states[idx] * (FIX_TYPE)0.1);
        FIX_TYPE i_gate = sigmoid(in_i + hidden_states[idx] * (FIX_TYPE)0.05);
        FIX_TYPE c_gate = tanh_inhouse(in_c + hidden_states[idx] * (FIX_TYPE)0.02);
        FIX_TYPE o_gate = sigmoid(in_o + hidden_states[idx] * (FIX_TYPE)0.03);

        // Update cell and hidden states
        cell_states[idx] = f_gate * cell_states[idx] + i_gate * c_gate;
        hidden_states[idx] = o_gate * tanh_inhouse(cell_states[idx]);
    }

    // Return the first hidden unit as the observable output (match testbench expectation of a single double output)
    *hidden_state_ = (double)hidden_states[0];
}

} // extern "C"

