// hls.cpp
// Fixes for Vivado HLS (C++98 toolchain): use C stdint.h and make top-level extern "C".
// Adjusted compile-time grid sizes to match the cosim testbench (3x3x3) so that
// simulation does not access out-of-bounds memory when the testbench uses SIZE=27.
//
// Note: Keep the top-level function signature as extern "C" to match the testbench.
#include <stdint.h>

#define HEIGHT_SIZE 3
#define COL_SIZE 3
#define ROW_SIZE 3

#define TYPE int32_t

#define SIZE (ROW_SIZE * COL_SIZE * HEIGHT_SIZE)

/* Index mapping: i -> height index, j -> column index, k -> row index
   Linear index = k + ROW_SIZE * ( j + COL_SIZE * i )
   This matches the testbench INDX(R,C,k,j,i) = i*C*R + j*R + k
*/
#define INDX(_row_size,_col_size,_i,_j,_k) ((_i) + (_row_size) * (((_j) + (_col_size) * (_k))))

extern "C" {

void stencil3d(TYPE C[2], TYPE orig[SIZE], TYPE sol[SIZE]) {
#pragma HLS INTERFACE m_axi port=C offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=orig offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=sol offset=slave bundle=gmem2
#pragma HLS INTERFACE s_axilite port=C bundle=control
#pragma HLS INTERFACE s_axilite port=orig bundle=control
#pragma HLS INTERFACE s_axilite port=sol bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    int i, j, k;
    TYPE sum0, sum1, mul0, mul1;

    // Copy boundary elements on height dimension (i = 0 and i = HEIGHT_SIZE-1)
    for (j = 0; j < COL_SIZE; j++) {
        for (k = 0; k < ROW_SIZE; k++) {
            sol[INDX(ROW_SIZE, COL_SIZE, k, j, 0)] =
                orig[INDX(ROW_SIZE, COL_SIZE, k, j, 0)];
            sol[INDX(ROW_SIZE, COL_SIZE, k, j, HEIGHT_SIZE - 1)] =
                orig[INDX(ROW_SIZE, COL_SIZE, k, j, HEIGHT_SIZE - 1)];
        }
    }

    // Copy boundary elements on column dimension (j = 0 and j = COL_SIZE-1)
    for (i = 1; i < HEIGHT_SIZE - 1; i++) {
        for (k = 0; k < ROW_SIZE; k++) {
            sol[INDX(ROW_SIZE, COL_SIZE, k, 0, i)] =
                orig[INDX(ROW_SIZE, COL_SIZE, k, 0, i)];
            sol[INDX(ROW_SIZE, COL_SIZE, k, COL_SIZE - 1, i)] =
                orig[INDX(ROW_SIZE, COL_SIZE, k, COL_SIZE - 1, i)];
        }
    }

    // Copy boundary elements on row dimension (k = 0 and k = ROW_SIZE-1)
    for (i = 1; i < HEIGHT_SIZE - 1; i++) {
        for (j = 1; j < COL_SIZE - 1; j++) {
            sol[INDX(ROW_SIZE, COL_SIZE, 0, j, i)] =
                orig[INDX(ROW_SIZE, COL_SIZE, 0, j, i)];
            sol[INDX(ROW_SIZE, COL_SIZE, ROW_SIZE - 1, j, i)] =
                orig[INDX(ROW_SIZE, COL_SIZE, ROW_SIZE - 1, j, i)];
        }
    }

    // Compute stencil for inner elements
    for (i = 1; i < HEIGHT_SIZE - 1; i++) {
#pragma HLS pipeline
        for (j = 1; j < COL_SIZE - 1; j++) {
            for (k = 1; k < ROW_SIZE - 1; k++) {
                sum0 = orig[INDX(ROW_SIZE, COL_SIZE, k, j, i)];
                sum1 = orig[INDX(ROW_SIZE, COL_SIZE, k, j, i + 1)] +
                       orig[INDX(ROW_SIZE, COL_SIZE, k, j, i - 1)] +
                       orig[INDX(ROW_SIZE, COL_SIZE, k, j + 1, i)] +
                       orig[INDX(ROW_SIZE, COL_SIZE, k, j - 1, i)] +
                       orig[INDX(ROW_SIZE, COL_SIZE, k + 1, j, i)] +
                       orig[INDX(ROW_SIZE, COL_SIZE, k - 1, j, i)];
                mul0 = sum0 * C[0];
                mul1 = sum1 * C[1];
                sol[INDX(ROW_SIZE, COL_SIZE, k, j, i)] = mul0 + mul1;
            }
        }
    }
}

} // extern "C"

