int main(void) {
    // CSV file setup
    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // Column headers: cycle, inputs..., outputs...
    // Inputs driven by this testbench: reset, en, input_valid, input_byte
