    // Roles row
    std::fprintf(f, "meta,in,in,in,in,out,out,out,out,out,out,out,out,out,out,out\n");

    SHA256_CTX ctx;
    unsigned char hash[SHA256_BLOCK_SIZE];
    // We'll prepare deterministic actions per cycle (total cycles = 20: 0..19)
    const int TOTAL_CYCLES = 20;

    // Predefine input_byte for each cycle and whether input_valid is asserted.
    // Plan:
    // 0-1: reset active (1), en=0 -> call sha256_init
    // 2: reset released, en=1 -> finalize empty message (call sha256)
    // 3-5: feed 'a','b','c' one byte per cycle (input_valid=1)
    // 6: finalize -> sha256 for "abc"
    // 7: call sha256_init (reinit)
    // 8: call sha256_transform with a crafted block
    // 9: finalize -> sha256 after transform
    // 10-15: feed "OpenAI" bytes one per cycle
    // 16: finalize -> sha256 for "OpenAI"
    // 17: sha256_init
    // 18: feed 64-byte block in one DUT call (sha256_update_bytes with len=64)
    // 19: finalize -> sha256 after 64-byte block
    int resets[TOTAL_CYCLES];
    int ens[TOTAL_CYCLES];
    int input_valid[TOTAL_CYCLES];
    int input_byte[TOTAL_CYCLES];
    int action[TOTAL_CYCLES]; // 0=none,1=init,2=feed_byte,3=finalize,4=transform_block,5=feed_64

    for (int i = 0; i < TOTAL_CYCLES; ++i) {
        resets[i] = (i < 2) ? 1 : 0;
        ens[i] = (i < 2) ? 0 : 1;
        input_valid[i] = 0;
        input_byte[i] = 0;
        action[i] = 0;
    }

    action[0] = 1; // sha256_init during reset
    action[1] = 1; // sha256_init during reset
    action[2] = 3; // finalize empty message
    // 'a','b','c'
    action[3] = 2; input_valid[3] = 1; input_byte[3] = (int)('a');
    action[4] = 2; input_valid[4] = 1; input_byte[4] = (int)('b');
    action[5] = 2; input_valid[5] = 1; input_byte[5] = (int)('c');
    action[6] = 3; // finalize "abc"
    action[7] = 1; // reinit
    action[8] = 4; // sha256_transform with crafted block
    action[9] = 3; // finalize after transform
    // "OpenAI"
    const unsigned char openai[] = { 'O','p','e','n','A','I' };
    for (int j = 0; j < 6; ++j) {
        int cyc = 10 + j;
        action[cyc] = 2;
        input_valid[cyc] = 1;
        input_byte[cyc] = (int)openai[j];
    }
    action[16] = 3; // finalize "OpenAI"
    action[17] = 1; // init
    action[18] = 5; // feed 64-byte block in one call
    action[19] = 3; // finalize after 64-byte block

    // Precreate blocks used by transform and 64-byte update
    data_t transform_block;
    for (int i = 0; i < 64; ++i) transform_block[i] = (unsigned char)(i ^ 0xA5); // pattern

    unsigned char block64[64];
    for (int i = 0; i < 64; ++i) block64[i] = (unsigned char)(i + 1); // deterministic 1..64

    // For hash string building
    char hash_str[SHA256_BLOCK_SIZE * 3 + 1];
    hash_str[0] = '\0';

    // Initialize ctx to zero to start (will be initialized by DUT during reset cycles)
    std::memset(&ctx, 0, sizeof(ctx));
    std::memset(hash, 0, sizeof(hash));

    // Simulation cycles
    for (int cyc = 0; cyc < TOTAL_CYCLES; ++cyc) {
        int rst = resets[cyc];
        int en = ens[cyc];
        int ivalid = input_valid[cyc];
        int ibyte = input_byte[cyc];

        // Only one DUT call per cycle as required
        if (rst) {
            // During reset cycles call sha256_init
            sha256_init(&ctx);
            // Clear hash_str to indicate no fresh finalize unless we call finalize
            hash_str[0] = '\0';
        } else {
            if (!en) {
                // If not enabled and not reset, do nothing (no DUT call)
                // To adhere to "one DUT call per cycle", perform a lightweight no-op by calling sha256_init (safe) if action==0
                if (action[cyc] == 0) {
                    // Do no-op: call sha256_init to keep deterministic behavior (counts as DUT call)
                    sha256_init(&ctx);
                    hash_str[0] = '\0';
                }
            } else {
                switch (action[cyc]) {
                    case 0:
                        // Nothing special; call sha256_init as lightweight DUT (ensures one DUT call)
                        sha256_init(&ctx);
                        hash_str[0] = '\0';
                        break;
                    case 1:
                        sha256_init(&ctx);
                        hash_str[0] = '\0';
                        break;
                    case 2:
                        // feed a single byte via sha256_update_bytes (one DUT call)
                        {
                            unsigned char b = (unsigned char)(ibyte & 0xFF);
                            sha256_update_bytes(&ctx, &b, 1);
                            hash_str[0] = '\0';
                        }
                        break;
                    case 3:
                        // finalize: call sha256 and produce hash
                        sha256(&ctx, hash);
                        {
                            // Build hash string as concatenation of hex (uppercase) without 0x and without fixed width
                            char tmp[8];
                            hash_str[0] = '\0';
                            for (int i = 0; i < SHA256_BLOCK_SIZE; ++i) {
                                // use uppercase hex with no 0x and no fixed width
                                std::sprintf(tmp, "%X", (unsigned int)hash[i]);
                                std::strcat(hash_str, tmp);
                            }
                        }
                        break;
                    case 4:
                        {
                            // call sha256_transform directly with transform_block
                            data_t tb;
                            for (int i = 0; i < 64; ++i) tb[i] = transform_block[i];
                            sha256_transform(&ctx.state, &tb);
                            hash_str[0] = '\0';
                        }
                        break;
                    case 5:
                        {
                            // feed 64-byte block in one DUT call
                            sha256_update_bytes(&ctx, block64, 64);
                            hash_str[0] = '\0';
                        }
                        break;
                    default:
                        // fallback: sha256_init
                        sha256_init(&ctx);
                        hash_str[0] = '\0';
                        break;
                }
            }
        }

        // Sample outputs after DUT call this cycle
        // Outputs must be hex uppercase without 0x and without fixed width
        char datalen_str[32];
        char bitlen_str[64];
        std::sprintf(datalen_str, "%X", ctx.datalen);
        std::sprintf(bitlen_str, "%llX", (long long unsigned)ctx.bitlen);

        char state_str[8][32];
        for (int s = 0; s < 8; ++s) {
            std::sprintf(state_str[s], "%X", ctx.state[s]);
        }

        // Write CSV line: cycle,reset,en,input_valid,input_byte,datalen,bitlen,state0..state7,hash
        // Inputs are decimal integers; outputs hex uppercase as strings
        std::fprintf(f, "%d,%d,%d,%d,%d,%s,%s",
                     cyc, rst, en, ivalid, ibyte, datalen_str, bitlen_str);
        for (int s = 0; s < 8; ++s) {
            std::fprintf(f, ",%s", state_str[s]);
        }
        // hash column (may be empty if not computed this cycle)
        std::fprintf(f, ",%s\n", hash_str);

    }

    std::fflush(f);
    std::fclose(f);
    return 0;
}

