};

/* Types used by both testbench and DUT */
typedef unsigned char data_t[64];
typedef unsigned int state_t[8];

/* Mirror the testbench's SHA256_CTX layout exactly so the DUT function
   signature matches the testbench declaration. */
typedef struct {
    data_t data;
    unsigned int datalen;
    unsigned long long bitlen;
    state_t state;
} SHA256_CTX;

/* Internal transform routine: process a single 512-bit block (64 bytes).
   state is an array of 8 32-bit words, data is 64 bytes. */
static void sha256_transform(state_t state, const data_t data_in) {
    unsigned int a, b, c, d, e, f, g, h;
    unsigned int i, j, t1, t2, m[64];
    const unsigned char *dbytes = (const unsigned char *)data_in;

    for (i = 0, j = 0; i < 16; ++i, j += 4) {
        m[i] = ((unsigned int)dbytes[j] << 24) | ((unsigned int)dbytes[j + 1] << 16) |
               ((unsigned int)dbytes[j + 2] << 8) | ((unsigned int)dbytes[j + 3]);
    }
    for (; i < 64; ++i) {
        m[i] = SIG1(m[i - 2]) + m[i - 7] + SIG0(m[i - 15]) + m[i - 16];
    }

    a = state[0];
    b = state[1];
    c = state[2];
    d = state[3];
    e = state[4];
    f = state[5];
    g = state[6];
    h = state[7];

    for (i = 0; i < 64; ++i) {
        t1 = h + EP1(e) + CH(e, f, g) + k[i] + m[i];
        t2 = EP0(a) + MAJ(a, b, c);
        h = g;
        g = f;
        f = e;
        e = d + t1;
        d = c;
        c = b;
        b = a;
        a = t1 + t2;
    }

    state[0] += a;
    state[1] += b;
    state[2] += c;
    state[3] += d;
    state[4] += e;
    state[5] += f;
    state[6] += g;
    state[7] += h;
}

/* Initialize a SHA256_CTX (identical layout/semantics as the testbench). */
static void sha256_init_ctx(SHA256_CTX *ctx) {
    unsigned int i;
    ctx->datalen = 0;
    ctx->bitlen = 0ULL;
    ctx->state[0] = 0x6a09e667;
    ctx->state[1] = 0xbb67ae85;
    ctx->state[2] = 0x3c6ef372;
    ctx->state[3] = 0xa54ff53a;
    ctx->state[4] = 0x510e527f;
    ctx->state[5] = 0x9b05688c;
    ctx->state[6] = 0x1f83d9ab;
    ctx->state[7] = 0x5be0cd19;
    for (i = 0; i < 64; ++i) ctx->data[i] = 0;
}

/* HLS top-level update function expected by the testbench.
   It appends 'len' bytes from data[] into the ctx buffer, calling the
   block transform every 64 bytes. This function uses C linkage (extern "C")
   so the testbench can link to it. */
void sha256_update_bytes(SHA256_CTX *ctx, const unsigned char *data, size_t len) {
#pragma HLS INTERFACE s_axilite port=ctx bundle=control
#pragma HLS INTERFACE m_axi port=data offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=len bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control
    size_t i;

    /* Lazily initialize context if it appears uninitialized (datalen==0 && bitlen==0 && state all zero).
       The testbench usually calls sha256_init on its side, but for robustness initialize here if needed. */
    if (ctx->datalen == 0 && ctx->bitlen == 0ULL &&
        ctx->state[0] == 0 && ctx->state[1] == 0 && ctx->state[2] == 0 &&
        ctx->state[3] == 0 && ctx->state[4] == 0 && ctx->state[5] == 0 &&
        ctx->state[6] == 0 && ctx->state[7] == 0) {
        sha256_init_ctx(ctx);
    }

    for (i = 0; i < len; ++i) {
        ctx->data[ctx->datalen] = data[i];
        ctx->datalen++;
        if (ctx->datalen == 64) {
            sha256_transform(ctx->state, ctx->data);
            ctx->bitlen += 512ULL;
            ctx->datalen = 0;
        }
    }
}

} // extern "C"

