// tb_hls_cosim.cpp
// Testbench for HLS DUT. Adjusted to avoid <cstdint> and <cstddef> C++11 headers;
// uses C headers and plain C-style I/O to be compatible with Vivado HLS toolchain.
// Comments are in English.

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stddef.h>

#define SHA256_BLOCK_SIZE 32

#define ROTLEFT(a, b) (((a) << (b)) | ((a) >> (32 - (b))))
#define ROTRIGHT(a, b) (((a) >> (b)) | ((a) << (32 - (b))))

#define CH(x, y, z) (((x) & (y)) ^ (~(x) & (z)))
#define MAJ(x, y, z) (((x) & (y)) ^ ((x) & (z)) ^ ((y) & (z)))
#define EP0(x) (ROTRIGHT(x, 2) ^ ROTRIGHT(x, 13) ^ ROTRIGHT(x, 22))
#define EP1(x) (ROTRIGHT(x, 6) ^ ROTRIGHT(x, 11) ^ ROTRIGHT(x, 25))
#define SIG0(x) (ROTRIGHT(x, 7) ^ ROTRIGHT(x, 18) ^ ((x) >> 3))
#define SIG1(x) (ROTRIGHT(x, 17) ^ ROTRIGHT(x, 19) ^ ((x) >> 10))

const unsigned int k[64] = {
    0x428a2f98, 0x71374491, 0xb5c0fbcf, 0xe9b5dba5, 0x3956c25b, 0x59f111f1,
    0x923f82a4, 0xab1c5ed5, 0xd807aa98, 0x12835b01, 0x243185be, 0x550c7dc3,
    0x72be5d74, 0x80deb1fe, 0x9bdc06a7, 0xc19bf174, 0xe49b69c1, 0xefbe4786,
    0x0fc19dc6, 0x240ca1cc, 0x2de92c6f, 0x4a7484aa, 0x5cb0a9dc, 0x76f988da,
    0x983e5152, 0xa831c66d, 0xb00327c8, 0xbf597fc7, 0xc6e00bf3, 0xd5a79147,
    0x06ca6351, 0x14292967, 0x27b70a85, 0x2e1b2138, 0x4d2c6dfc, 0x53380d13,
    0x650a7354, 0x766a0abb, 0x81c2c92e, 0x92722c85, 0xa2bfe8a1, 0xa81a664b,
    0xc24b8b70, 0xc76c51a3, 0xd192e819, 0xd6990624, 0xf40e3585, 0x106aa070,
    0x19a4c116, 0x1e376c08, 0x2748774c, 0x34b0bcb5, 0x391c0cb3, 0x4ed8aa4a,
    0x5b9cca4f, 0x682e6ff3, 0x748f82ee, 0x78a5636f, 0x84c87814, 0x8cc70208,
    0x90befffa, 0xa4506ceb, 0xbef9a3f7, 0xc67178f2
};

typedef unsigned char data_t[64];
typedef unsigned int state_t[8];
typedef struct {
    data_t data;
    unsigned int datalen;
    unsigned long long bitlen;
    state_t state;
} SHA256_CTX;

/* Testbench-local transform and finalize functions to compute reference hashes.
   The parameter types are chosen to match how the function is invoked in this TB:
   - state_t *state : pointer to the state array
   - data_t data[]  : pointer to an array-of-64-byte blocks (we always pass a pointer to a single block) */
void sha256_transform(state_t *state, data_t data[]) {
    unsigned int a, b, c, d, e, f, g, h, i, j, t1, t2, m[64];
    /* data is a pointer to array-of-64; cast to byte pointer to read bytes */
    unsigned char *dbytes = (unsigned char*)(data);

    for (i = 0, j = 0; i < 16; ++i, j += 4)
        m[i] = ((unsigned int)dbytes[j] << 24) | ((unsigned int)dbytes[j + 1] << 16) |
               ((unsigned int)dbytes[j + 2] << 8) | ((unsigned int)dbytes[j + 3]);
    for (; i < 64; ++i)
        m[i] = SIG1(m[i - 2]) + m[i - 7] + SIG0(m[i - 15]) + m[i - 16];

    a = (*state)[0];
    b = (*state)[1];
    c = (*state)[2];
    d = (*state)[3];
    e = (*state)[4];
    f = (*state)[5];
    g = (*state)[6];
    h = (*state)[7];

    for (i = 0; i < 64; ++i) {
        t1 = h + EP1(e) + CH(e, f, g) + k[i] + m[i];
        t2 = EP0(a) + MAJ(a, b, c);
        h = g;
        g = f;
        f = e;
        e = d + t1;
        d = c;
        c = b;
        b = a;
        a = t1 + t2;
    }

    (*state)[0] += a;
    (*state)[1] += b;
    (*state)[2] += c;
    (*state)[3] += d;
    (*state)[4] += e;
    (*state)[5] += f;
    (*state)[6] += g;
    (*state)[7] += h;
}

void sha256_init(SHA256_CTX *ctx) {
    ctx->datalen = 0;
    ctx->bitlen = 0;
    ctx->state[0] = 0x6a09e667;
    ctx->state[1] = 0xbb67ae85;
    ctx->state[2] = 0x3c6ef372;
    ctx->state[3] = 0xa54ff53a;
    ctx->state[4] = 0x510e527f;
    ctx->state[5] = 0x9b05688c;
    ctx->state[6] = 0x1f83d9ab;
    ctx->state[7] = 0x5be0cd19;
}

/* Software update used by some internal software helpers (kept for completeness). */
void sha256_update(
    data_t *data_int,
    unsigned int *datalen_int,
    state_t *state,
    unsigned long long int *bitlen_int,
    data_t data[],
    size_t len) {
    size_t i;
    unsigned char *in = (unsigned char*)(data);
    for (i = 0; i < len; ++i) {
        (*data_int)[*datalen_int] = in[i];
        (*datalen_int)++;
        if (*datalen_int == 64) {
            sha256_transform(state, data_int);
            *bitlen_int += 512;
            *datalen_int = 0;
        }
    }
}

/* Finalize routine: pads the message, processes the final block(s), and writes the digest. */
void sha256(SHA256_CTX *ctx, unsigned char hash[]) {
    unsigned int i;

    i = ctx->datalen;

    if (ctx->datalen < 56) {
        ctx->data[i++] = 0x80;
        while (i < 56) {
            ctx->data[i++] = 0x00;
        }
    } else {
        ctx->data[i++] = 0x80;
        while (i < 64) {
            ctx->data[i++] = 0x00;
        }
        sha256_transform(&ctx->state, &ctx->data);
        memset(ctx->data, 0, 56);
    }

    ctx->bitlen += ctx->datalen * 8;
    ctx->data[63] = (unsigned char)(ctx->bitlen);
    ctx->data[62] = (unsigned char)(ctx->bitlen >> 8);
    ctx->data[61] = (unsigned char)(ctx->bitlen >> 16);
    ctx->data[60] = (unsigned char)(ctx->bitlen >> 24);
    ctx->data[59] = (unsigned char)(ctx->bitlen >> 32);
    ctx->data[58] = (unsigned char)(ctx->bitlen >> 40);
    ctx->data[57] = (unsigned char)(ctx->bitlen >> 48);
    ctx->data[56] = (unsigned char)(ctx->bitlen >> 56);
    sha256_transform(&ctx->state, &ctx->data);

    for (i = 0; i < 4; ++i) {
        hash[i] = (ctx->state[0] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 4] = (ctx->state[1] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 8] = (ctx->state[2] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 12] = (ctx->state[3] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 16] = (ctx->state[4] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 20] = (ctx->state[5] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 24] = (ctx->state[6] >> (24 - i * 8)) & 0x000000ff;
        hash[i + 28] = (ctx->state[7] >> (24 - i * 8)) & 0x000000ff;
    }
}

/* Declare the HLS top-level function exactly as in the HLS C code.
   This must match the signature implemented in the DUT (hls.cpp). */
extern "C" void sha256_update_bytes(SHA256_CTX *ctx, const unsigned char *data, size_t len);

/* Provide a software-only update helper (used for non-DUT situations if needed).
   Named differently to avoid colliding with the DUT symbol. */
static void sha256_update_bytes_sw(SHA256_CTX *ctx, const unsigned char *data, size_t len) {
    size_t i;
    for (i = 0; i < len; ++i) {
        ctx->data[ctx->datalen] = data[i];
        ctx->datalen++;
        if (ctx->datalen == 64) {
            sha256_transform(&ctx->state, &ctx->data);
            ctx->bitlen += 512;
            ctx->datalen = 0;
        }
    }
}

/* HLS C testbench that drives the DUT (sha256_update_bytes) and samples outputs into hls_output.csv */
int main(void) {
    /* Open CSV file for HLS/RTL outputs */
    FILE *f = fopen("hls_output.csv", "w");
    if (!f) return 1;

    /* CSV header: cycle, then inputs driven by this testbench, then outputs sampled from DUT */
    /* Inputs driven by this tb: reset, en, input_valid, input_byte */
    /* Outputs sampled from DUT: datalen, bitlen, state_0..state_7, hash */
    fprintf(f, "cycle,reset,en,input_valid,input_byte,datalen,bitlen,state_0,state_1,state_2,state_3,state_4,state_5,state_6,state_7,hash\n");
    fprintf(f, "meta,in,in,in,in,out,out,out,out,out,out,out,out,out,out,out\n");

    SHA256_CTX ctx;
    unsigned char hash[SHA256_BLOCK_SIZE];

    const int TOTAL_CYCLES = 20;

    int resets[TOTAL_CYCLES];
    int ens[TOTAL_CYCLES];
    int input_valid[TOTAL_CYCLES];
    int input_byte[TOTAL_CYCLES];
    int action[TOTAL_CYCLES]; /* 0=none,1=init,2=feed_byte,3=finalize,4=transform_block,5=feed_64 */

    int i;
    for (i = 0; i < TOTAL_CYCLES; ++i) {
        resets[i] = (i < 2) ? 1 : 0;
        ens[i] = (i < 2) ? 0 : 1;
        input_valid[i] = 0;
        input_byte[i] = 0;
        action[i] = 0;
    }

    action[0] = 1; /* sha256_init during reset */
    action[1] = 1; /* sha256_init during reset */
    action[2] = 3; /* finalize empty message */
    /* 'a','b','c' */
    action[3] = 2; input_valid[3] = 1; input_byte[3] = (int)('a');
    action[4] = 2; input_valid[4] = 1; input_byte[4] = (int)('b');
    action[5] = 2; input_valid[5] = 1; input_byte[5] = (int)('c');
    action[6] = 3; /* finalize "abc" */
    action[7] = 1; /* reinit */
    action[8] = 4; /* sha256_transform with crafted block */
    action[9] = 3; /* finalize after transform */
    /* "OpenAI" */
    const unsigned char openai[] = { 'O','p','e','n','A','I' };
    for (i = 0; i < 6; ++i) {
        int cyc = 10 + i;
        action[cyc] = 2;
        input_valid[cyc] = 1;
        input_byte[cyc] = (int)openai[i];
    }
    action[16] = 3; /* finalize "OpenAI" */
    action[17] = 1; /* init */
    action[18] = 5; /* feed 64-byte block in one call (use DUT) */
    action[19] = 3; /* finalize after 64-byte block */

    /* Precreate blocks used by transform and 64-byte update */
    data_t transform_block;
    for (i = 0; i < 64; ++i) transform_block[i] = (unsigned char)(i ^ 0xA5); /* pattern */

    unsigned char block64[64];
    for (i = 0; i < 64; ++i) block64[i] = (unsigned char)(i + 1); /* deterministic 1..64 */

    /* For hash string building */
    char hash_str[SHA256_BLOCK_SIZE * 3 + 1];
    hash_str[0] = '\0';

    /* Initialize ctx to zero to start */
    memset(&ctx, 0, sizeof(ctx));
    memset(hash, 0, sizeof(hash));

    /* Simulation cycles */
    int cyc;
    for (cyc = 0; cyc < TOTAL_CYCLES; ++cyc) {
        int rst = resets[cyc];
        int en = ens[cyc];
        int ivalid = input_valid[cyc];
        int ibyte = input_byte[cyc];

        /* Only one DUT call per cycle is allowed. We will call the HLS DUT only for update operations (action 2 and 5). */
        if (rst) {
            /* During reset cycles call sha256_init (testbench-side initialization) */
            sha256_init(&ctx);
            hash_str[0] = '\0';
        } else {
            if (!en) {
                /* Not enabled: perform a deterministic no-op by calling sha256_init (counts as one tb action but not a DUT update) */
                if (action[cyc] == 0) {
                    sha256_init(&ctx);
                    hash_str[0] = '\0';
                }
            } else {
                switch (action[cyc]) {
                    case 0:
                        /* Lightweight deterministic operation */
                        sha256_init(&ctx);
                        hash_str[0] = '\0';
                        break;
                    case 1:
                        sha256_init(&ctx);
                        hash_str[0] = '\0';
                        break;
                    case 2:
                        {
                            /* Feed a single byte via HLS top-level function (DUT) */
                            unsigned char b = (unsigned char)(ibyte & 0xFF);
                            /* Call the HLS DUT */
                            sha256_update_bytes(&ctx, &b, 1);
                            hash_str[0] = '\0';
                        }
                        break;
                    case 3:
                        /* Finalize using software finalize to produce a hash for logging */
                        sha256(&ctx, hash);
                        {
                            /* Build hash string as concatenation of hex (uppercase) without 0x and without fixed width */
                            char tmp[8];
                            hash_str[0] = '\0';
                            for (i = 0; i < SHA256_BLOCK_SIZE; ++i) {
                                sprintf(tmp, "%X", (unsigned int)hash[i]);
                                strcat(hash_str, tmp);
                            }
                        }
                        break;
                    case 4:
                        {
                            /* Call software sha256_transform directly with transform_block (not a DUT call) */
                            data_t tb;
                            int ii;
                            for (ii = 0; ii < 64; ++ii) tb[ii] = transform_block[ii];
                            sha256_transform(&ctx.state, &tb);
                            hash_str[0] = '\0';
                        }
                        break;
                    case 5:
                        {
                            /* Feed 64-byte block in one call via the HLS DUT */
                            sha256_update_bytes(&ctx, block64, 64);
                            hash_str[0] = '\0';
                        }
                        break;
                    default:
                        sha256_init(&ctx);
                        hash_str[0] = '\0';
                        break;
                }
            }
        }

        /* Sample outputs after the single DUT or testbench call this cycle */
        char datalen_str[32];
        char bitlen_str[64];
        sprintf(datalen_str, "%X", ctx.datalen);
        sprintf(bitlen_str, "%llX", (long long unsigned)ctx.bitlen);

        char state_str[8][32];
        for (int s = 0; s < 8; ++s) {
            sprintf(state_str[s], "%X", ctx.state[s]);
        }

        /* Write CSV line: cycle,reset,en,input_valid,input_byte,datalen,bitlen,state0..state7,hash */
        fprintf(f, "%d,%d,%d,%d,%d,%s,%s",
                     cyc, rst, en, ivalid, ibyte, datalen_str, bitlen_str);
        for (int s = 0; s < 8; ++s) {
            fprintf(f, ",%s", state_str[s]);
        }
        fprintf(f, ",%s\n", hash_str);
    }

    fflush(f);
    fclose(f);
    return 0;
}

