            else if(j==1){ normals[idx+0]=0.0f; normals[idx+1]=1.0f; normals[idx+2]=0.0f; }
            else if(j==2){ normals[idx+0]=0.0f; normals[idx+1]=0.0f; normals[idx+2]=1.0f; }
            else { normals[idx+0]=1.0f; normals[idx+1]=1.0f; normals[idx+2]=1.0f; }
        }
    }

    // Run cycles with deterministic, varied test vectors
    for(int cycle = 0; cycle < total_cycles; cycle++) {
        // Determine compact integer codes for each driven input signal (these are what we'll print in CSV as the input columns)
        int code_elements_surrounding = cycle % 4;       // 0..3
        int code_normals = (cycle / 2) % 5;              // 0..4
        int code_variables = cycle % 7;                  // 0..6
        int code_fcmx = (cycle + 1) % 6;                 // 0..5
        int code_fcmy = (cycle + 2) % 6;                 // 0..5
        int code_fcmz = (cycle + 3) % 6;                 // 0..5
        int code_fcdensity = (cycle + 4) % 6;            // 0..5

        // Drive elements_surrounding_elements according to code_elements_surrounding
        for(int i=0;i<SIZE;i++){
            for(int j=0;j<NNB;j++){
                int idx = i*NNB + j;
                if(code_elements_surrounding == 0) {
                    elements_surrounding_elements[idx] = -2; // far field
                } else if(code_elements_surrounding == 1) {
                    // internal neighbor indices (wrap)
                    int nb = (i + j + 1) % SIZE;
                    elements_surrounding_elements[idx] = nb;
                } else if(code_elements_surrounding == 2) {
                    // one wall face, others far field
                    elements_surrounding_elements[idx] = (j==0) ? -1 : -2;
                } else {
                    // mix: alternate -2 and small positive neighbor
                    elements_surrounding_elements[idx] = ( (i + j + cycle) % 3 == 0 ) ? -2 : ((i + j) % SIZE);
                }
            }
        }

        // Drive normals according to code_normals
        for(int i=0;i<SIZE;i++){
            for(int j=0;j<NNB;j++){
                int base = (i*NNB + j)*NDIM;
                if(code_normals == 0) {
                    normals[base+0] = 1.0f; normals[base+1] = 0.0f; normals[base+2] = 0.0f;
                } else if(code_normals == 1) {
                    normals[base+0] = 0.0f; normals[base+1] = 1.0f; normals[base+2] = 0.0f;
                } else if(code_normals == 2) {
                    normals[base+0] = 0.0f; normals[base+1] = 0.0f; normals[base+2] = 1.0f;
                } else if(code_normals == 3) {
                    normals[base+0] = 1.0f; normals[base+1] = 1.0f; normals[base+2] = 1.0f;
                } else {
                    // varying small normals
                    float a = 0.1f + 0.001f * float((i + j + cycle) % 10);
                    normals[base+0] = a;
                    normals[base+1] = a * 0.5f;
                    normals[base+2] = a * 0.25f;
                }
            }
        }

        // Drive variables according to code_variables
        for(int i=0;i<SIZE;i++){
            // density must be > 0 to avoid division by zero
            float density = 1.2f + 0.02f * float(code_variables) + 0.0001f * float(i % 13);
            float momx = 0.1f * float((i % 5) + code_variables);
            float momy = 0.05f * float(((i+1) % 7) + code_variables);
            float momz = 0.02f * float(((i+2) % 3) + code_variables);
            float density_energy = 2.0f + 0.1f * float(code_variables) + 0.001f * float(i % 11);

            variables[i*NVAR + VAR_DENSITY] = density;
            variables[i*NVAR + (VAR_MOMENTUM+0)] = momx;
            variables[i*NVAR + (VAR_MOMENTUM+1)] = momy;
            variables[i*NVAR + (VAR_MOMENTUM+2)] = momz;
            variables[i*NVAR + VAR_DENSITY_ENERGY] = density_energy;
        }

        // Drive fc arrays according to their codes
        for(int i=0;i<SIZE;i++){
            for(int d=0; d<NDIM; d++){
                fc_momentum_x[i*NDIM + d] = 0.1f * float(code_fcmx) + 0.01f * float(d) + 0.00001f * float(i%17);
                fc_momentum_y[i*NDIM + d] = 0.1f * float(code_fcmy) + 0.01f * float(d) + 0.00002f * float(i%13);
                fc_momentum_z[i*NDIM + d] = 0.1f * float(code_fcmz) + 0.01f * float(d) + 0.00003f * float(i%11);
                fc_density_energy[i*NDIM + d] = 0.2f * float(code_fcdensity) + 0.01f * float(d) + 0.00004f * float(i%9);
            }
        }

        // Initialize result buffer to zero before call (like DUT main did)
        std::memset(result, 0, sizeof(float)*SIZE*NVAR);

        // Call DUT
        cfd_flux(result, elements_surrounding_elements, normals, variables, fc_momentum_x, fc_momentum_y, fc_momentum_z, fc_density_energy);

        // Sample outputs: we will sample the first result element (result[0]) as the representative output.
        // Convert float bits to uint32_t and print as uppercase hex without 0x prefix, no fixed width.
        uint32_t bits;
        {
            float val = result[0];
            // safe bitcopy
            std::memcpy(&bits, &val, sizeof(bits));
        }

        // Write CSV row:
        // cycle (meta), then input columns as decimal integers, then output as hex uppercase (no 0x)
        // Inputs we write are the compact integer codes we used to generate the arrays.
        char hexbuf[32];
        std::sprintf(hexbuf, "%X", (unsigned)bits); // uppercase hex, no 0x, no fixed width

        std::fprintf(f, "%d,%d,%d,%d,%d,%d,%d,%d,%s\n",
            cycle,
            code_elements_surrounding,
            code_normals,
            code_variables,
            code_fcmx,
            code_fcmy,
            code_fcmz,
            code_fcdensity,
            hexbuf
        );
    }

    std::fclose(f);

    // free memory
    free(result);
    free(elements_surrounding_elements);
    free(normals);
    free(variables);
    free(fc_momentum_x);
    free(fc_momentum_y);
    free(fc_momentum_z);
    free(fc_density_energy);

    return 0;
}

