// hls.cpp
// CFD flux kernel for Vivado HLS
// Top-level function is given C linkage (extern "C") so the HLS cosim/testbench can link to it.
// Implementation is kept compatible with Vivado HLS 2018.3 C++98 toolchain.

#include <math.h>

#define GAMMA 1.4f
#define NVAR 5
#define NDIM 3
#define NNB 4
#define SIZE 1024
#define TILE_ROWS 32

#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY 4

typedef struct {
    float x;
    float y;
    float z;
} float3;

static void compute_velocity(float density, const float3 *momentum, float3 *velocity) {
    velocity->x = momentum->x / density;
    velocity->y = momentum->y / density;
    velocity->z = momentum->z / density;
}

static float compute_speed_sqd(const float3 *velocity) {
    return velocity->x*velocity->x + velocity->y*velocity->y + velocity->z*velocity->z;
}

static float compute_pressure(float density, float density_energy, float speed_sqd) {
    return (GAMMA - 1.0f)*(density_energy - 0.5f*density*speed_sqd);
}

static float compute_speed_of_sound(float density, float pressure) {
    return sqrtf(GAMMA*pressure / density);
}

/*
 Top-level HLS function.
 extern "C" is required so the testbench (which declares the function with C linkage)
 can successfully link against this symbol produced by the HLS tool.
 The second argument is an int array (neighbor indices), make sure the types match the testbench.
*/
extern "C" void cfd_flux(
    float result[SIZE * NVAR],
    int elements_surrounding_elements[SIZE * NNB],
    float normals[SIZE * NNB * NDIM],
    float variables[SIZE * NVAR],
    float fc_momentum_x[SIZE * NDIM],
    float fc_momentum_y[SIZE * NDIM],
    float fc_momentum_z[SIZE * NDIM],
    float fc_density_energy[SIZE * NDIM])
{
#pragma HLS INTERFACE m_axi port=result offset=slave bundle=result
#pragma HLS INTERFACE m_axi port=elements_surrounding_elements offset=slave bundle=elements_surrounding_elements
#pragma HLS INTERFACE m_axi port=normals offset=slave bundle=normals
#pragma HLS INTERFACE m_axi port=variables offset=slave bundle=variables
#pragma HLS INTERFACE m_axi port=fc_momentum_x offset=slave bundle=fc_momentum_x
#pragma HLS INTERFACE m_axi port=fc_momentum_y offset=slave bundle=fc_momentum_y
#pragma HLS INTERFACE m_axi port=fc_momentum_z offset=slave bundle=fc_momentum_z
#pragma HLS INTERFACE m_axi port=fc_density_energy offset=slave bundle=fc_density_energy

#pragma HLS INTERFACE s_axilite port=result bundle=control
#pragma HLS INTERFACE s_axilite port=elements_surrounding_elements bundle=control
#pragma HLS INTERFACE s_axilite port=normals bundle=control
#pragma HLS INTERFACE s_axilite port=variables bundle=control
#pragma HLS INTERFACE s_axilite port=fc_momentum_x bundle=control
#pragma HLS INTERFACE s_axilite port=fc_momentum_y bundle=control
#pragma HLS INTERFACE s_axilite port=fc_momentum_z bundle=control
#pragma HLS INTERFACE s_axilite port=fc_density_energy bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    const float smoothing_coefficient = 0.2f;

    float ff_variable[NVAR] = {1.399999976158142090f, 1.680000066757202148f, 0.0f, 0.0f, 3.507999897003173828f};
#pragma HLS array_partition variable=ff_variable complete dim=1

    float3 ff_fc_momentum_x = {3.016000270843505859f, 0.0f, 0.0f};
    float3 ff_fc_momentum_y = {0.0f, 1.0f, 0.0f};
    float3 ff_fc_momentum_z = {0.0f, 0.0f, 1.0f};
    float3 ff_fc_density_energy = {5.409600257873535156f, 0.0f, 0.0f};

    float result_inner[TILE_ROWS * NVAR];
#pragma HLS array_partition variable=result_inner cyclic factor=8 dim=1

    int elements_surrounding_elements_inner[TILE_ROWS * NNB];
#pragma HLS array_partition variable=elements_surrounding_elements_inner block factor=32 dim=1

    float normals_inner[TILE_ROWS * NNB * NDIM];
#pragma HLS array_partition variable=normals_inner block factor=32 dim=1

    float variables_inner[SIZE * NVAR];
#pragma HLS array_partition variable=variables_inner cyclic factor=32 dim=1

    float fc_momentum_x_inner[SIZE * NDIM];
#pragma HLS array_partition variable=fc_momentum_x_inner cyclic factor=32 dim=1

    float fc_momentum_y_inner[SIZE * NDIM];
#pragma HLS array_partition variable=fc_momentum_y_inner cyclic factor=64 dim=1

    float fc_momentum_z_inner[SIZE * NDIM];
#pragma HLS array_partition variable=fc_momentum_z_inner cyclic factor=64 dim=1

    float fc_density_energy_inner[SIZE * NDIM];
#pragma HLS array_partition variable=fc_density_energy_inner cyclic factor=2 dim=1

    // Manual copy instead of memcpy to satisfy HLS
    for (int i = 0; i < SIZE * NVAR; i++) {
#pragma HLS pipeline
        variables_inner[i] = variables[i];
    }
    for (int i = 0; i < SIZE * NDIM; i++) {
#pragma HLS pipeline
        fc_momentum_x_inner[i] = fc_momentum_x[i];
        fc_momentum_y_inner[i] = fc_momentum_y[i];
        fc_momentum_z_inner[i] = fc_momentum_z[i];
        fc_density_energy_inner[i] = fc_density_energy[i];
    }

    // Process tiles
    const int num_tiles = SIZE / TILE_ROWS;
    for (int k = 0; k < num_tiles; k++) {
#pragma HLS unroll factor=2
        // Copy tile neighbors (int)
        for (int i = 0; i < TILE_ROWS * NNB; i++) {
#pragma HLS pipeline
            elements_surrounding_elements_inner[i] = elements_surrounding_elements[k * TILE_ROWS * NNB + i];
        }
        // Copy tile normals
        for (int i = 0; i < TILE_ROWS * NNB * NDIM; i++) {
#pragma HLS pipeline
            normals_inner[i] = normals[k * TILE_ROWS * NNB * NDIM + i];
        }

        // Inner kernel (inlined)
        for (int i = 0; i < TILE_ROWS; i++) {
#pragma HLS unroll factor=8
            int j, nb;
            float3 normal; float normal_len;
            float factor;

            // Compute global element index for this tile-local i
            int elem = k * TILE_ROWS + i;

            float density_i = variables_inner[elem*NVAR + VAR_DENSITY];
            float3 momentum_i;
            momentum_i.x = variables_inner[elem*NVAR + (VAR_MOMENTUM+0)];
            momentum_i.y = variables_inner[elem*NVAR + (VAR_MOMENTUM+1)];
            momentum_i.z = variables_inner[elem*NVAR + (VAR_MOMENTUM+2)];
            float density_energy_i = variables_inner[elem*NVAR + VAR_DENSITY_ENERGY];

            float3 velocity_i;
            compute_velocity(density_i, &momentum_i, &velocity_i);
            float speed_sqd_i = compute_speed_sqd(&velocity_i);
            float speed_i = sqrtf(speed_sqd_i);
            float pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
            float speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);

            float3 fc_i_momentum_x, fc_i_momentum_y, fc_i_momentum_z;
            float3 fc_i_density_energy;

            // Use global element index when reading fc arrays
            fc_i_momentum_x.x = fc_momentum_x_inner[elem*NDIM + 0];
            fc_i_momentum_x.y = fc_momentum_x_inner[elem*NDIM + 1];
            fc_i_momentum_x.z = fc_momentum_x_inner[elem*NDIM + 2];

            fc_i_momentum_y.x = fc_momentum_y_inner[elem*NDIM + 0];
            fc_i_momentum_y.y = fc_momentum_y_inner[elem*NDIM + 1];
            fc_i_momentum_y.z = fc_momentum_y_inner[elem*NDIM + 2];

            fc_i_momentum_z.x = fc_momentum_z_inner[elem*NDIM + 0];
            fc_i_momentum_z.y = fc_momentum_z_inner[elem*NDIM + 1];
            fc_i_momentum_z.z = fc_momentum_z_inner[elem*NDIM + 2];

            fc_i_density_energy.x = fc_density_energy_inner[elem*NDIM + 0];
            fc_i_density_energy.y = fc_density_energy_inner[elem*NDIM + 1];
            fc_i_density_energy.z = fc_density_energy_inner[elem*NDIM + 2];

            float flux_i_density = 0.0f;
            float3 flux_i_momentum = {0.0f, 0.0f, 0.0f};
            float flux_i_density_energy = 0.0f;

            float3 velocity_nb;
            float density_nb, density_energy_nb;
            float3 momentum_nb;
            float3 fc_nb_momentum_x, fc_nb_momentum_y, fc_nb_momentum_z;
            float3 fc_nb_density_energy;
            float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

            for (j = 0; j < NNB; j++) {
#pragma HLS unroll
                nb = elements_surrounding_elements_inner[i*NNB + j];
                normal.x = normals_inner[(i*NNB + j)*NDIM + 0];
                normal.y = normals_inner[(i*NNB + j)*NDIM + 1];
                normal.z = normals_inner[(i*NNB + j)*NDIM + 2];
                normal_len = sqrtf(normal.x*normal.x + normal.y*normal.y + normal.z*normal.z);

                if (nb >= 0) {
                    density_nb = variables_inner[nb*NVAR + VAR_DENSITY];
                    momentum_nb.x = variables_inner[nb*NVAR + (VAR_MOMENTUM+0)];
                    momentum_nb.y = variables_inner[nb*NVAR + (VAR_MOMENTUM+1)];
                    momentum_nb.z = variables_inner[nb*NVAR + (VAR_MOMENTUM+2)];
                    density_energy_nb = variables_inner[nb*NVAR + VAR_DENSITY_ENERGY];
                    compute_velocity(density_nb, &momentum_nb, &velocity_nb);
                    speed_sqd_nb = compute_speed_sqd(&velocity_nb);
                    pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
                    speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);

                    fc_nb_momentum_x.x = fc_momentum_x_inner[nb*NDIM + 0];
                    fc_nb_momentum_x.y = fc_momentum_x_inner[nb*NDIM + 1];
                    fc_nb_momentum_x.z = fc_momentum_x_inner[nb*NDIM + 2];

                    fc_nb_momentum_y.x = fc_momentum_y_inner[nb*NDIM + 0];
                    fc_nb_momentum_y.y = fc_momentum_y_inner[nb*NDIM + 1];
                    fc_nb_momentum_y.z = fc_momentum_y_inner[nb*NDIM + 2];

                    fc_nb_momentum_z.x = fc_momentum_z_inner[nb*NDIM + 0];
                    fc_nb_momentum_z.y = fc_momentum_z_inner[nb*NDIM + 1];
                    fc_nb_momentum_z.z = fc_momentum_z_inner[nb*NDIM + 2];

                    fc_nb_density_energy.x = fc_density_energy_inner[nb*NDIM + 0];
                    fc_nb_density_energy.y = fc_density_energy_inner[nb*NDIM + 1];
                    fc_nb_density_energy.z = fc_density_energy_inner[nb*NDIM + 2];

                    factor = -normal_len*smoothing_coefficient*0.5f*(speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                    flux_i_density += factor*(density_i-density_nb);
                    flux_i_density_energy += factor*(density_energy_i-density_energy_nb);
                    flux_i_momentum.x += factor*(momentum_i.x-momentum_nb.x);
                    flux_i_momentum.y += factor*(momentum_i.y-momentum_nb.y);
                    flux_i_momentum.z += factor*(momentum_i.z-momentum_nb.z);

                    factor = 0.5f*normal.x;
                    flux_i_density += factor*(momentum_nb.x+momentum_i.x);
                    flux_i_density_energy += factor*(fc_nb_density_energy.x+fc_i_density_energy.x);
                    flux_i_momentum.x += factor*(fc_nb_momentum_x.x+fc_i_momentum_x.x);
                    flux_i_momentum.y += factor*(fc_nb_momentum_y.x+fc_i_momentum_y.x);
                    flux_i_momentum.z += factor*(fc_nb_momentum_z.x+fc_i_momentum_z.x);

                    factor = 0.5f*normal.y;
                    flux_i_density += factor*(momentum_nb.y+momentum_i.y);
                    flux_i_density_energy += factor*(fc_nb_density_energy.y+fc_i_density_energy.y);
                    flux_i_momentum.x += factor*(fc_nb_momentum_x.y+fc_i_momentum_x.y);
                    flux_i_momentum.y += factor*(fc_nb_momentum_y.y+fc_i_momentum_y.y);
                    flux_i_momentum.z += factor*(fc_nb_momentum_z.y+fc_i_momentum_z.y);

                    factor = 0.5f*normal.z;
                    flux_i_density += factor*(momentum_nb.z+momentum_i.z);
                    flux_i_density_energy += factor*(fc_nb_density_energy.z+fc_i_density_energy.z);
                    flux_i_momentum.x += factor*(fc_nb_momentum_x.z+fc_i_momentum_x.z);
                    flux_i_momentum.y += factor*(fc_nb_momentum_y.z+fc_i_momentum_y.z);
                    flux_i_momentum.z += factor*(fc_nb_momentum_z.z+fc_i_momentum_z.z);
                } else if (nb == -1) {
                    flux_i_momentum.x += normal.x*pressure_i;
                    flux_i_momentum.y += normal.y*pressure_i;
                    flux_i_momentum.z += normal.z*pressure_i;
                } else if (nb == -2) {
                    factor = 0.5f*normal.x;
                    flux_i_density += factor*(ff_variable[VAR_MOMENTUM+0]+momentum_i.x);
                    flux_i_density_energy += factor*(ff_fc_density_energy.x+fc_i_density_energy.x);
                    flux_i_momentum.x += factor*(ff_fc_momentum_x.x + fc_i_momentum_x.x);
                    flux_i_momentum.y += factor*(ff_fc_momentum_y.x + fc_i_momentum_y.x);
                    flux_i_momentum.z += factor*(ff_fc_momentum_z.x + fc_i_momentum_z.x);

                    factor = 0.5f*normal.y;
                    flux_i_density += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i.y);
                    flux_i_density_energy += factor*(ff_fc_density_energy.y+fc_i_density_energy.y);
                    flux_i_momentum.x += factor*(ff_fc_momentum_x.y + fc_i_momentum_x.y);
                    flux_i_momentum.y += factor*(ff_fc_momentum_y.y + fc_i_momentum_y.y);
                    flux_i_momentum.z += factor*(ff_fc_momentum_z.y + fc_i_momentum_z.y);

                    factor = 0.5f*normal.z;
                    flux_i_density += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i.z);
                    flux_i_density_energy += factor*(ff_fc_density_energy.z+fc_i_density_energy.z);
                    flux_i_momentum.x += factor*(ff_fc_momentum_x.z + fc_i_momentum_x.z);
                    flux_i_momentum.y += factor*(ff_fc_momentum_y.z + fc_i_momentum_y.z);
                    flux_i_momentum.z += factor*(ff_fc_momentum_z.z + fc_i_momentum_z.z);
                }
            }

            // Store tile-local results
            result_inner[i*NVAR + VAR_DENSITY] = flux_i_density;
            result_inner[i*NVAR + (VAR_MOMENTUM+0)] = flux_i_momentum.x;
            result_inner[i*NVAR + (VAR_MOMENTUM+1)] = flux_i_momentum.y;
            result_inner[i*NVAR + (VAR_MOMENTUM+2)] = flux_i_momentum.z;
            result_inner[i*NVAR + VAR_DENSITY_ENERGY] = flux_i_density_energy;
        }

        // Copy tile results back to global result
        for (int i = 0; i < TILE_ROWS * NVAR; i++) {
#pragma HLS pipeline
            result[k * TILE_ROWS * NVAR + i] = result_inner[i];
        }
    }
}

