// tb_hls_cosim.cpp
// C-style testbench for HLS cosimulation
// Uses C headers to be compatible with Vivado HLS 2018.3 (C++98 toolchain).

#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

// Keep macro definitions and types consistent with DUT
#define GRID_ROWS (1024)
#define SIZE GRID_ROWS
#define TILE_ROWS 32
#define PARA_FACTOR 16
#define TOP 0
#define BOTTOM (GRID_ROWS / TILE_ROWS - 1)
#define GAMMA 1.4
#define NDIM 3
#define NNB 4
#define RK 3	
#define ff_mach 1.2
#define deg_angle_of_attack 0.0f
#define VAR_DENSITY 0
#define VAR_MOMENTUM  1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)
#define TYPE float

// Declare top-level HLS function with exact signature as in HLSC code.
// extern "C" is required so the HLS cosimulation will link correctly to the RTL cosim wrapper.
extern "C" void cfd_flux(float result[SIZE * NVAR],
                         int elements_surrounding_elements [SIZE * NNB],
                         float normals [SIZE * NNB * NDIM],
                         float variables [SIZE * NVAR],
                         float fc_momentum_x [SIZE * NDIM],
                         float fc_momentum_y [SIZE * NDIM],
                         float fc_momentum_z [SIZE * NDIM],
                         float fc_density_energy [SIZE * NDIM]);

int main()
{
    // Allocate arrays as DUT expects
    float *result = (float*)malloc(sizeof(float) * SIZE * NVAR);
    int *elements_surrounding_elements = (int*)malloc(sizeof(int) * SIZE * NNB);
    float *normals = (float*)malloc(sizeof(float) * SIZE * NNB * NDIM);
    float *variables = (float*)malloc(sizeof(float) * SIZE * NVAR);
    float *fc_momentum_x = (float*)malloc(sizeof(float) * SIZE * NDIM);
    float *fc_momentum_y = (float*)malloc(sizeof(float) * SIZE * NDIM);
    float *fc_momentum_z = (float*)malloc(sizeof(float) * SIZE * NDIM);
    float *fc_density_energy = (float*)malloc(sizeof(float) * SIZE * NDIM);

    if(!result || !elements_surrounding_elements || !normals || !variables || !fc_momentum_x || !fc_momentum_y || !fc_momentum_z || !fc_density_energy) {
        return 1;
    }

    // Prepare CSV file for HLS/RTL outputs
    FILE *f = fopen("hls_output.csv", "w");
    if(!f) {
        return 1;
    }

    // CSV header: cycle, then the input signal names (as driven by the testbench), then sampled outputs.
    // Column names must match actual DUT port/ testbench signal names.
    fprintf(f, "cycle,elements_surrounding_elements,normals,variables,fc_momentum_x,fc_momentum_y,fc_momentum_z,fc_density_energy,result\n");
    // Roles row: meta for cycle, in for driven signals, out for sampled outputs
    fprintf(f, "meta,in,in,in,in,in,in,in,out\n");

    // We will run a deterministic set of cycles (between 20 and 50). Choose 32 cycles.
    const int total_cycles = 32;

    // Initialize to a safe default to avoid division by zero
    for(int i=0;i<SIZE;i++){
        for(int v=0; v<NVAR; v++){
            variables[i*NVAR + v] = 1.4f; // safe non-zero density
        }
        for(int d=0; d<NDIM; d++){
            fc_momentum_x[i*NDIM + d] = 0.0f;
            fc_momentum_y[i*NDIM + d] = 0.0f;
            fc_momentum_z[i*NDIM + d] = 0.0f;
            fc_density_energy[i*NDIM + d] = 0.0f;
        }
        for(int j=0;j<NNB;j++){
            elements_surrounding_elements[i*NNB + j] = -2;
            int idx = (i*NNB + j)*NDIM;
            if(j==0){ normals[idx+0]=1.0f; normals[idx+1]=0.0f; normals[idx+2]=0.0f; }
            else if(j==1){ normals[idx+0]=0.0f; normals[idx+1]=1.0f; normals[idx+2]=0.0f; }
            else if(j==2){ normals[idx+0]=0.0f; normals[idx+1]=0.0f; normals[idx+2]=1.0f; }
            else { normals[idx+0]=1.0f; normals[idx+1]=1.0f; normals[idx+2]=1.0f; }
        }
    }

    // Run cycles with deterministic, varied test vectors
    for(int cycle = 0; cycle < total_cycles; cycle++) {
        // Determine compact integer codes for each driven input signal (these are what we'll print in CSV as the input columns)
        int code_elements_surrounding = cycle % 4;       // 0..3
        int code_normals = (cycle / 2) % 5;              // 0..4
        int code_variables = cycle % 7;                  // 0..6
        int code_fcmx = (cycle + 1) % 6;                 // 0..5
        int code_fcmy = (cycle + 2) % 6;                 // 0..5
        int code_fcmz = (cycle + 3) % 6;                 // 0..5
        int code_fcdensity = (cycle + 4) % 6;            // 0..5

        // Drive elements_surrounding_elements according to code_elements_surrounding
        for(int i=0;i<SIZE;i++){
            for(int j=0;j<NNB;j++){
                int idx = i*NNB + j;
                if(code_elements_surrounding == 0) {
                    elements_surrounding_elements[idx] = -2; // far field
                } else if(code_elements_surrounding == 1) {
                    // internal neighbor indices (wrap)
                    int nb = (i + j + 1) % SIZE;
                    elements_surrounding_elements[idx] = nb;
                } else if(code_elements_surrounding == 2) {
                    // one wall face, others far field
                    elements_surrounding_elements[idx] = (j==0) ? -1 : -2;
                } else {
                    // mix: alternate -2 and small positive neighbor
                    elements_surrounding_elements[idx] = ( (i + j + cycle) % 3 == 0 ) ? -2 : ((i + j) % SIZE);
                }
            }
        }

        // Drive normals according to code_normals
        for(int i=0;i<SIZE;i++){
            for(int j=0;j<NNB;j++){
                int base = (i*NNB + j)*NDIM;
                if(code_normals == 0) {
                    normals[base+0] = 1.0f; normals[base+1] = 0.0f; normals[base+2] = 0.0f;
                } else if(code_normals == 1) {
                    normals[base+0] = 0.0f; normals[base+1] = 1.0f; normals[base+2] = 0.0f;
                } else if(code_normals == 2) {
                    normals[base+0] = 0.0f; normals[base+1] = 0.0f; normals[base+2] = 1.0f;
                } else if(code_normals == 3) {
                    normals[base+0] = 1.0f; normals[base+1] = 1.0f; normals[base+2] = 1.0f;
                } else {
                    // varying small normals
                    float a = 0.1f + 0.001f * (float)((i + j + cycle) % 10);
                    normals[base+0] = a;
                    normals[base+1] = a * 0.5f;
                    normals[base+2] = a * 0.25f;
                }
            }
        }

        // Drive variables according to code_variables
        for(int i=0;i<SIZE;i++){
            // density must be > 0 to avoid division by zero
            float density = 1.2f + 0.02f * (float)code_variables + 0.0001f * (float)(i % 13);
            float momx = 0.1f * (float)((i % 5) + code_variables);
            float momy = 0.05f * (float)(((i+1) % 7) + code_variables);
            float momz = 0.02f * (float)(((i+2) % 3) + code_variables);
            float density_energy = 2.0f + 0.1f * (float)code_variables + 0.001f * (float)(i % 11);

            variables[i*NVAR + VAR_DENSITY] = density;
            variables[i*NVAR + (VAR_MOMENTUM+0)] = momx;
            variables[i*NVAR + (VAR_MOMENTUM+1)] = momy;
            variables[i*NVAR + (VAR_MOMENTUM+2)] = momz;
            variables[i*NVAR + VAR_DENSITY_ENERGY] = density_energy;
        }

        // Drive fc arrays according to their codes
        for(int i=0;i<SIZE;i++){
            for(int d=0; d<NDIM; d++){
                fc_momentum_x[i*NDIM + d] = 0.1f * (float)code_fcmx + 0.01f * (float)d + 0.00001f * (float)(i%17);
                fc_momentum_y[i*NDIM + d] = 0.1f * (float)code_fcmy + 0.01f * (float)d + 0.00002f * (float)(i%13);
                fc_momentum_z[i*NDIM + d] = 0.1f * (float)code_fcmz + 0.01f * (float)d + 0.00003f * (float)(i%11);
                fc_density_energy[i*NDIM + d] = 0.2f * (float)code_fcdensity + 0.01f * (float)d + 0.00004f * (float)(i%9);
            }
        }

        // Initialize result buffer to zero before call (like DUT main did)
        memset(result, 0, sizeof(float)*SIZE*NVAR);

        // Call DUT (HLS top-level)
        cfd_flux(result, elements_surrounding_elements, normals, variables, fc_momentum_x, fc_momentum_y, fc_momentum_z, fc_density_energy);

        // Sample outputs: we will sample the first result element (result[0]) as the representative output.
        // Convert float bits to uint32_t and print as uppercase hex without 0x prefix, no fixed width.
        uint32_t bits;
        {
            float val = result[0];
            // safe bitcopy
            memcpy(&bits, &val, sizeof(bits));
        }

        // Write CSV row:
        // cycle (meta), then input columns as decimal integers, then output as hex uppercase (no 0x)
        // Inputs we write are the compact integer codes we used to generate the arrays.
        char hexbuf[32];
        sprintf(hexbuf, "%X", (unsigned)bits); // uppercase hex, no 0x, no fixed width

        fprintf(f, "%d,%d,%d,%d,%d,%d,%d,%d,%s\n",
            cycle,
            code_elements_surrounding,
            code_normals,
            code_variables,
            code_fcmx,
            code_fcmy,
            code_fcmz,
            code_fcdensity,
            hexbuf
        );
    }

    fclose(f);

    // free memory
    free(result);
    free(elements_surrounding_elements);
    free(normals);
    free(variables);
    free(fc_momentum_x);
    free(fc_momentum_y);
    free(fc_momentum_z);
    free(fc_density_energy);

    return 0;
}

