// hls.cpp
// Simple single-unit LSTM implementation with C linkage for Vivado HLS cosimulation.
// Implemented in double precision to match the testbench which passes double arguments.
// Exposes three C-callable functions (must match testbench declarations exactly):
// - LSTM_Unit_init
// - LSTM_Unit_performInference
// - LSTM_Unit_get_hidden_state_
// Note: Avoids C++11 features (no lambdas) for compatibility with older Vivado HLS toolchains.

#include <math.h> // for exp

extern "C" {

// The struct definition must match the testbench exactly.
typedef struct {
    double hidden_state_;
    double cell_state_;
} LSTM_Unit;

// Initialize the LSTM unit states to zero.
void LSTM_Unit_init(LSTM_Unit *unit) {
    if (!unit) return;
    unit->hidden_state_ = 0.0;
    unit->cell_state_ = 0.0;
}

// Sigmoid activation function (separate function to avoid lambdas).
static double sigmoid(double x) {
    return 1.0 / (1.0 + exp(-x));
}

// Tanh implemented via exp to avoid depending on std::tanh (portable to HLS).
static double tanh_v(double x) {
    double e_p = exp(x);
    double e_n = exp(-x);
    return (e_p - e_n) / (e_p + e_n);
}

// Perform one inference (one time-step) of a single LSTM unit.
// i, f, c, o are the pre-activation inputs (not necessarily passed through activation yet).
void LSTM_Unit_performInference(LSTM_Unit *unit, double i, double f, double c, double o) {
    if (!unit) return;

    double f_r = sigmoid(f);
    double i_r = sigmoid(i);
    double c_tilde = tanh_v(c);

    // Update cell state
    unit->cell_state_ = f_r * unit->cell_state_ + c_tilde * i_r;

    double o_r = sigmoid(o);

    // Update hidden state
    unit->hidden_state_ = o_r * tanh_v(unit->cell_state_);
}

// Return the current hidden state value.
double LSTM_Unit_get_hidden_state_(const LSTM_Unit *unit) {
    if (!unit) return 0.0;
    return unit->hidden_state_;
}

} // extern "C"

