// test.cpp
#include "test.h"
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

void md_knn(TYPE force_x[nAtoms],  TYPE force_y[nAtoms],   TYPE force_z[nAtoms],
            TYPE position_x[nAtoms], TYPE position_y[nAtoms], TYPE position_z[nAtoms],
            int32_t NL[nAtoms*maxNeighbors])
{
    TYPE delx, dely, delz, r2inv;
    TYPE r6inv, potential, force, j_x, j_y, j_z;
    TYPE i_x, i_y, i_z, fx, fy, fz;

    int32_t i, j, jidx;

    for (i = 0; i < nAtoms; i++) {
        i_x = position_x[i];
        i_y = position_y[i];
        i_z = position_z[i];
        fx = 0;
        fy = 0;
        fz = 0;
        for (j = 0; j < maxNeighbors; j++) {
            jidx = NL[i*maxNeighbors + j];
            if (jidx < 0 || jidx >= nAtoms) continue;
            j_x = position_x[jidx];
            j_y = position_y[jidx];
            j_z = position_z[jidx];

            delx = i_x - j_x;
            dely = i_y - j_y;
            delz = i_z - j_z;
            TYPE r2 = delx*delx + dely*dely + delz*delz;
            if (r2 == 0.0) continue;
            r2inv = 1.0 / r2;

            r6inv = r2inv * r2inv * r2inv;
            potential = r6inv*(lj1*r6inv - lj2);

            force = r2inv * potential;
            fx += delx * force;
            fy += dely * force;
            fz += delz * force;
        }

        force_x[i] = fx;
        force_y[i] = fy;
        force_z[i] = fz;
    }
}

int main()
{
    static TYPE *force_x;
    static TYPE *force_y;
    static TYPE *force_z;
    static TYPE *position_x;
    static TYPE *position_y;
    static TYPE *position_z;
    static int32_t *NL;

    force_x = (TYPE*)malloc(sizeof(TYPE) * nAtoms);
    force_y = (TYPE*)malloc(sizeof(TYPE) * nAtoms);
    force_z = (TYPE*)malloc(sizeof(TYPE) * nAtoms);

    position_x = (TYPE*)malloc(sizeof(TYPE) * nAtoms);
    position_y = (TYPE*)malloc(sizeof(TYPE) * nAtoms);
    position_z = (TYPE*)malloc(sizeof(TYPE) * nAtoms);

    NL = (int32_t*)malloc(sizeof(int32_t) * nAtoms * maxNeighbors);

    if (!force_x || !force_y || !force_z || !position_x || !position_y || !position_z || !NL) {
        fprintf(stderr, "Allocation failed\n");
        return 1;
    }

    for (int i = 0; i < nAtoms; i++) {
        position_x[i] = (TYPE)( (i % 16) * 0.5 );
        position_y[i] = (TYPE)( (i % 32) * 0.25 );
        position_z[i] = (TYPE)( (i % 8) * 0.75 );
        force_x[i] = 0;
        force_y[i] = 0;
        force_z[i] = 0;
    }

    for (int i = 0; i < nAtoms; i++) {
        for (int j = 0; j < maxNeighbors; j++) {
            NL[i*maxNeighbors + j] = (i + 1 + j) % nAtoms;
        }
    }

    md_knn(force_x, force_y, force_z, position_x, position_y, position_z, NL);

    for (int i = 0; i < 10 && i < nAtoms; i++) {
        printf("Atom %d: fx=%g fy=%g fz=%g\n", i, force_x[i], force_y[i], force_z[i]);
    }

    free(force_x);
    free(force_y);
    free(force_z);
    free(position_x);
    free(position_y);
    free(position_z);
    free(NL);

    return 0;
}

