#include <cstdio>
#include <cstdint>
#include <cstdlib>
#include <cstring>
#include <string>
#include <vector>
#include <cmath>
#include <climits>

// Define DUT configuration and types to match the provided function
using TYPE = double;
constexpr int32_t nAtoms = 3;
constexpr int32_t maxNeighbors = 4;
constexpr int FRAC = 16; // match Verilog FRAC = 16 (Q16.16)
const TYPE lj1 = 1.0;
const TYPE lj2 = 1.0;

// DUT implementation (adapted from the provided code)
void md_knn(TYPE force_x[nAtoms],  TYPE force_y[nAtoms],   TYPE force_z[nAtoms],
            TYPE position_x[nAtoms], TYPE position_y[nAtoms], TYPE position_z[nAtoms],
            int32_t NL[nAtoms*maxNeighbors])
{
    TYPE delx, dely, delz, r2inv;
    TYPE r6inv, potential, force, j_x, j_y, j_z;
    TYPE i_x, i_y, i_z, fx, fy, fz;

    int32_t i, j, jidx;

    for (i = 0; i < nAtoms; i++) {
        i_x = position_x[i];
        i_y = position_y[i];
        i_z = position_z[i];
        fx = 0;
        fy = 0;
        fz = 0;
        for (j = 0; j < maxNeighbors; j++) {
            jidx = NL[i*maxNeighbors + j];
            if (jidx < 0 || jidx >= nAtoms) continue;
            j_x = position_x[jidx];
            j_y = position_y[jidx];
            j_z = position_z[jidx];

            delx = i_x - j_x;
            dely = i_y - j_y;
            delz = i_z - j_z;
            TYPE r2 = delx*delx + dely*dely + delz*delz;
            if (r2 == 0.0) continue;
            r2inv = 1.0 / r2;

            r6inv = r2inv * r2inv * r2inv;
            potential = r6inv*(lj1*r6inv - lj2);

            force = r2inv * potential;
            fx += delx * force;
            fy += dely * force;
            fz += delz * force;
        }

        force_x[i] = fx;
        force_y[i] = fy;
        force_z[i] = fz;
    }
}

// Helper: join integer array elements with '|' into a decimal string
static std::string join_int_array_dec(const int32_t* arr, size_t len) {
    std::string s;
    for (size_t i = 0; i < len; ++i) {
        char buf[32];
        std::snprintf(buf, sizeof(buf), "%d", arr[i]);
        if (i) s.push_back('|');
        s += buf;
    }
    return s;
}

// Helper: join TYPE array elements as decimal integers (inputs should be integers per spec)
static std::string join_type_array_as_int_dec(const TYPE* arr, size_t len) {
    std::string s;
    for (size_t i = 0; i < len; ++i) {
        // Cast to long long to ensure integer formatting
        long long ival = static_cast<long long>(arr[i]);
        char buf[32];
        std::snprintf(buf, sizeof(buf), "%lld", ival);
        if (i) s.push_back('|');
        s += buf;
    }
    return s;
}

// Convert a floating TYPE value to signed 32-bit Q(FRAC) fixed-point with rounding and saturation
static int32_t to_q_fixed32(TYPE v) {
    // scale factor
    const int64_t scale = (1LL << FRAC);
    // round to nearest
    long long scaled = llround(v * (TYPE)scale);
    // saturate to int32 range
    if (scaled > INT32_MAX) scaled = INT32_MAX;
    if (scaled < INT32_MIN) scaled = INT32_MIN;
    return static_cast<int32_t>(scaled);
}

// Helper: join TYPE array elements as hex representation of Q(FRAC) 32-bit values
// Output format: uppercase hex, no "0x", fixed width 8 characters, '|' separated
static std::string join_type_array_as_qhex(const TYPE* arr, size_t len) {
    std::string s;
    for (size_t i = 0; i < len; ++i) {
        int32_t q = to_q_fixed32(arr[i]);
        uint32_t bits = static_cast<uint32_t>(static_cast<int32_t>(q)); // two's complement 32-bit
        char buf[16];
        std::snprintf(buf, sizeof(buf), "%08X", (unsigned int)bits); // uppercase, 8 digits
        if (i) s.push_back('|');
        s += buf;
    }
    return s;
}

int main() {
    // Prepare arrays
    TYPE position_x[nAtoms];
    TYPE position_y[nAtoms];
    TYPE position_z[nAtoms];
    int32_t NL[nAtoms * maxNeighbors];

    TYPE force_x[nAtoms];
    TYPE force_y[nAtoms];
    TYPE force_z[nAtoms];

    // Open CSV output
    FILE *f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // CSV header: cycle then inputs then outputs
    // Inputs: position_x, position_y, position_z, NL
    // Outputs: force_x, force_y, force_z
    std::fprintf(f, "cycle,position_x,position_y,position_z,NL,force_x,force_y,force_z\n");
    // Role line: meta/in/out
    std::fprintf(f, "meta,in,in,in,in,out,out,out\n");

    const int total_cycles = 32; // between 20 and 50

    for (int cycle = 0; cycle < total_cycles; ++cycle) {
        // Deterministic test vector generation (no randomness)
        // Create a variety:
        // - Every 5th cycle: set all positions equal to create r2 == 0 cases
        // - Otherwise positions vary with cycle and atom index
        if (cycle % 5 == 0) {
            // all atoms at same coordinates (will produce r2 == 0 and be skipped)
            TYPE v = static_cast<TYPE>((cycle % 7) - 3); // small integer in [-3,3]
            for (int i = 0; i < nAtoms; ++i) {
                position_x[i] = v;
                position_y[i] = v;
                position_z[i] = v;
            }
        } else {
            for (int i = 0; i < nAtoms; ++i) {
                // use different formulas for x,y,z to get diverse distances
                position_x[i] = static_cast<TYPE>((cycle * 3 + i * 5) % 7 - 3); // [-3,3]
                position_y[i] = static_cast<TYPE>(((cycle + 2) * 4 + i * 3) % 5 - 2); // [-2,2]
                position_z[i] = static_cast<TYPE>(((cycle + 3) * 2 + i * 7) % 9 - 4); // [-4,4]
            }
            // Occasionally force exact duplicate for some atoms to test r2==0 only for some pairs
            if (cycle % 3 == 0) {
                position_x[1] = position_x[0];
                position_y[1] = position_y[0];
                position_z[1] = position_z[0];
            }
        }

        // Neighbor list: include valid and invalid indices to test boundary checks
        // Generate values in range [-1, nAtoms+1], so some entries are invalid (<0 or >=nAtoms)
        for (int i = 0; i < nAtoms; ++i) {
            for (int j = 0; j < maxNeighbors; ++j) {
                int idx = (i + j + cycle) % (nAtoms + 3); // 0 .. nAtoms+2
                idx = idx - 1; // shift to -1 .. nAtoms+1
                NL[i*maxNeighbors + j] = idx;
            }
        }

        // Call DUT
        md_knn(force_x, force_y, force_z,
               position_x, position_y, position_z,
               NL);

        // Format inputs (as decimal integers per spec)
        std::string posx_str = join_type_array_as_int_dec(position_x, nAtoms);
        std::string posy_str = join_type_array_as_int_dec(position_y, nAtoms);
        std::string posz_str = join_type_array_as_int_dec(position_z, nAtoms);
        std::string nl_str = join_int_array_dec(NL, nAtoms * maxNeighbors);

        // Format outputs as Q16.16 32-bit hex (uppercase, 8 hex digits each)
        std::string fx_str = join_type_array_as_qhex(force_x, nAtoms);
        std::string fy_str = join_type_array_as_qhex(force_y, nAtoms);
        std::string fz_str = join_type_array_as_qhex(force_z, nAtoms);

        // Write CSV line: cycle,position_x,position_y,position_z,NL,force_x,force_y,force_z
        // Use comma as separator; fields do not contain commas
        std::fprintf(f, "%d,%s,%s,%s,%s,%s,%s,%s\n",
                     cycle,
                     posx_str.c_str(),
                     posy_str.c_str(),
                     posz_str.c_str(),
                     nl_str.c_str(),
                     fx_str.c_str(),
                     fy_str.c_str(),
                     fz_str.c_str());
    }

    // Explicitly close file
    std::fclose(f);
    return 0;
}

