// hls.cpp
// HLS top-level implementation for md_knn adapted to the cosimulation testbench.
// - Use C-style stdint header for Vivado HLS C++98 compatibility
// - Top-level function signature and types match the testbench exactly (double, nAtoms=3, maxNeighbors=4)
// - Protect against invalid neighbor indices and zero-distance to avoid divide-by-zero
// - Keep top-level function extern "C" as required by HLS
#include <stdint.h>

extern "C" {

#define nAtoms 3
#define maxNeighbors 4
#define lj1 1.5
#define lj2 2.0

typedef double TYPE;

void md_knn(TYPE force_x[nAtoms],
            TYPE force_y[nAtoms],
            TYPE force_z[nAtoms],
            TYPE position_x[nAtoms],
            TYPE position_y[nAtoms],
            TYPE position_z[nAtoms],
            int32_t NL[nAtoms*maxNeighbors]) {

#pragma HLS INTERFACE m_axi port=force_x offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=force_y offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=force_z offset=slave bundle=gmem2
#pragma HLS INTERFACE m_axi port=position_x offset=slave bundle=gmem3
#pragma HLS INTERFACE m_axi port=position_y offset=slave bundle=gmem4
#pragma HLS INTERFACE m_axi port=position_z offset=slave bundle=gmem5
#pragma HLS INTERFACE m_axi port=NL offset=slave bundle=gmem6

#pragma HLS INTERFACE s_axilite port=force_x bundle=control
#pragma HLS INTERFACE s_axilite port=force_y bundle=control
#pragma HLS INTERFACE s_axilite port=force_z bundle=control
#pragma HLS INTERFACE s_axilite port=position_x bundle=control
#pragma HLS INTERFACE s_axilite port=position_y bundle=control
#pragma HLS INTERFACE s_axilite port=position_z bundle=control
#pragma HLS INTERFACE s_axilite port=NL bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    TYPE delx, dely, delz, r2inv;
    TYPE r6inv, potential, force, j_x, j_y, j_z;
    TYPE i_x, i_y, i_z, fx, fy, fz;

    int32_t i, j, jidx;

L1_loop_i: for (i = 0; i < nAtoms; i++) {
        // small nAtoms, do not force large unroll; let HLS decide
        i_x = position_x[i];
        i_y = position_y[i];
        i_z = position_z[i];
        fx = (TYPE)0.0;
        fy = (TYPE)0.0;
        fz = (TYPE)0.0;
    L2_loop_j: for (j = 0; j < maxNeighbors; j++) {
#pragma HLS pipeline II=1
            jidx = NL[i*maxNeighbors + j];
            /* Guard against invalid neighbor indices produced by testbench.
               If index is out of range, skip this neighbor. */
            if (jidx < 0 || jidx >= nAtoms) {
                continue;
            }
            j_x = position_x[jidx];
            j_y = position_y[jidx];
            j_z = position_z[jidx];
            delx = i_x - j_x;
            dely = i_y - j_y;
            delz = i_z - j_z;
            /* Compute squared distance and protect against zero (same position).
               If r2 == 0, skip to avoid divide-by-zero. */
            TYPE r2 = delx*delx + dely*dely + delz*delz;
            if (r2 == (TYPE)0.0) {
                continue;
            }
            r2inv = (TYPE)1.0 / r2;
            r6inv = r2inv * r2inv * r2inv;
            potential = r6inv * ( (TYPE)lj1 * r6inv - (TYPE)lj2 );
            force = r2inv * potential;
            fx += delx * force;
            fy += dely * force;
            fz += delz * force;
        }
        force_x[i] = fx;
        force_y[i] = fy;
        force_z[i] = fz;
    }
}

} // extern "C"

