                       double position_x[3], double position_y[3], double position_z[3],
                       int32_t NL[3*4]);

// Match types and configuration used by the original C testbench
typedef double TYPE;
const int32_t nAtoms = 3;
const int32_t maxNeighbors = 4;
const int FRAC = 16; // Q16.16

// Helper: join integer array elements with '|' into a decimal string
static std::string join_int_array_dec(const int32_t* arr, size_t len) {
    std::string s;
    for (size_t i = 0; i < len; ++i) {
        char buf[32];
        std::snprintf(buf, sizeof(buf), "%d", arr[i]);
        if (i) s.push_back('|');
        s += buf;
    }
    return s;
}

// Helper: join TYPE array elements as decimal integers (inputs are generated as integers)
static std::string join_type_array_as_int_dec(const TYPE* arr, size_t len) {
    std::string s;
    for (size_t i = 0; i < len; ++i) {
        long long ival = static_cast<long long>(arr[i]);
        char buf[32];
        std::snprintf(buf, sizeof(buf), "%lld", ival);
        if (i) s.push_back('|');
        s += buf;
    }
    return s;
}

// Simple replacement for llround for C++98 compatibility
static long long my_llround(TYPE x) {
    if (x >= (TYPE)0.0) {
        return (long long) std::floor(x + (TYPE)0.5);
    } else {
        return (long long) std::ceil(x - (TYPE)0.5);
    }
}

// Convert a floating TYPE value to signed 32-bit Q(FRAC) fixed-point with rounding and saturation
static int32_t to_q_fixed32(TYPE v) {
    const long long scale = (1LL << FRAC);
    long long scaled = my_llround(v * (TYPE)scale);
    if (scaled > INT32_MAX) scaled = INT32_MAX;
    if (scaled < INT32_MIN) scaled = INT32_MIN;
    return static_cast<int32_t>(scaled);
}

// Helper: join TYPE array elements as hex representation of Q(FRAC) 32-bit values
