    int32_t NL[nAtoms * maxNeighbors];

    TYPE force_x[nAtoms];
    TYPE force_y[nAtoms];
    TYPE force_z[nAtoms];

    // Open CSV output for HLS/RTL cosim results
    FILE *f = std::fopen("hls_output.csv", "w");
    if (!f) return 1;

    // CSV header: cycle then inputs then outputs
    // Inputs: position_x, position_y, position_z, NL
    // Outputs: force_x, force_y, force_z
    std::fprintf(f, "cycle,position_x,position_y,position_z,NL,force_x,force_y,force_z\n");
    // Role line: meta/in/out
    std::fprintf(f, "meta,in,in,in,in,out,out,out\n");

    const int total_cycles = 32; // between 20 and 50

    for (int cycle = 0; cycle < total_cycles; ++cycle) {
        // Deterministic test vector generation (no randomness)
        if (cycle % 5 == 0) {
            // all atoms at same coordinates (will produce r2 == 0 and be skipped)
            TYPE v = static_cast<TYPE>((cycle % 7) - 3); // small integer in [-3,3]
            for (int i = 0; i < nAtoms; ++i) {
                position_x[i] = v;
                position_y[i] = v;
                position_z[i] = v;
            }
        } else {
            for (int i = 0; i < nAtoms; ++i) {
                position_x[i] = static_cast<TYPE>((cycle * 3 + i * 5) % 7 - 3); // [-3,3]
                position_y[i] = static_cast<TYPE>(((cycle + 2) * 4 + i * 3) % 5 - 2); // [-2,2]
                position_z[i] = static_cast<TYPE>(((cycle + 3) * 2 + i * 7) % 9 - 4); // [-4,4]
            }
            if (cycle % 3 == 0) {
                position_x[1] = position_x[0];
                position_y[1] = position_y[0];
                position_z[1] = position_z[0];
            }
        }

        // Neighbor list: include valid and invalid indices to test boundary checks
        for (int i = 0; i < nAtoms; ++i) {
            for (int j = 0; j < maxNeighbors; ++j) {
                int idx = (i + j + cycle) % (nAtoms + 3); // 0 .. nAtoms+2
                idx = idx - 1; // shift to -1 .. nAtoms+1
