#include "test.h"

void copyKey(present_key_t *from, present_key_t *to) {
    int i;
    for (i = 0; i < PRESENT_80_KEY_SIZE_BYTES; i++) {
        (*to)[i] = (*from)[i];
    }
}

void copyBlock(block_t *from, block_t *to) {
    int i;
    for (i = 0; i < PRESENT_BLOCK_SIZE_BYTES; i++) {
        (*to)[i] = (*from)[i];
    }
}

void generateRoundKeys80(present_key_t *suppliedKey, keys_t *keys) {
    present_key_t key;
    present_key_t newKey;
    unsigned char i, j;
    copyKey(suppliedKey, &key);
    copyBlock((block_t *)&key, &((*keys)[0]));
    for (i = 1; i < ROUNDS; i++) {
        for (j = 0; j < PRESENT_80_KEY_SIZE_BYTES; j++) {
            newKey[j] = (unsigned char)((key[(j + 7) % PRESENT_80_KEY_SIZE_BYTES] << 5) |
                                       (key[(j + 8) % PRESENT_80_KEY_SIZE_BYTES] >> 3));
        }
        copyKey(&newKey, &key);
        key[0] = (unsigned char)((sBox[key[0] >> 4] << 4) | (key[0] & 0xF));
        key[8] ^= (unsigned char)(i << 7);
        key[7] ^= (unsigned char)(i >> 1);
        copyBlock((block_t *)&key, &((*keys)[i]));
    }
}

void addRoundKey(block_t *block, round_key_t *roundKey) {
    unsigned char i;
    for (i = 0; i < PRESENT_BLOCK_SIZE_BYTES; i++) {
        (*block)[i] ^= (*roundKey)[i];
    }
}

void pLayer(block_t *block) {
    unsigned char i, j, indexVal, andVal;
    block_t initial;
    copyBlock(block, &initial);
    for (i = 0; i < PRESENT_BLOCK_SIZE_BYTES; i++) {
        (*block)[i] = 0;
        for (j = 0; j < 8; j++) {
            indexVal = (unsigned char)(4 * (i % 2) + (3 - (j >> 1)));
            andVal = (unsigned char)((8 >> (i >> 1)) << ((j % 2) << 2));
            (*block)[i] |= (unsigned char)(((initial[indexVal] & andVal) != 0) << j);
        }
    }
}

void pLayerInverse(block_t *block) {
    unsigned char i, j, indexVal, andVal;
    block_t initial;
    copyBlock(block, &initial);
    for (i = 0; i < PRESENT_BLOCK_SIZE_BYTES; i++) {
        (*block)[i] = 0;
        for (j = 0; j < 8; j++) {
            indexVal = (unsigned char)((7 - ((2 * j) % 8)) - (i < 4));
            andVal = (unsigned char)((7 - ((2 * i) % 8)) - (j < 4));
            (*block)[i] |= (unsigned char)(((initial[indexVal] & (1 << andVal)) != 0) << j);
        }
    }
}

void present(block_t *block, present_key_t *key) {
    keys_t roundKeys;
    unsigned char i, j;
    generateRoundKeys80(key, &roundKeys);
    for (i = 0; i < ROUNDS - 1; i++) {
        addRoundKey(block, &(roundKeys[i]));
        for (j = 0; j < PRESENT_BLOCK_SIZE_BYTES; j++) {
            (*block)[j] = (unsigned char)((sBox[(*block)[j] >> 4] << 4) | sBox[(*block)[j] & 0xF]);
        }
        pLayer(block);
    }
    addRoundKey(block, &(roundKeys[ROUNDS - 1]));
}

int main() {
    block_t data = {0x00, 0x11, 0x22, 0x33, 0x44, 0x55, 0x66, 0x77};
    present_key_t key = {0x00, 0x01, 0x02, 0x03, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09};
    int i;
    printf("Plaintext: ");
    for (i = 0; i < PRESENT_BLOCK_SIZE_BYTES; i++) {
        printf("%02X ", (unsigned int)data[i]);
    }
    printf("\n");
    present(&data, &key);
    printf("Ciphertext: ");
    for (i = 0; i < PRESENT_BLOCK_SIZE_BYTES; i++) {
        printf("%02X ", (unsigned int)data[i]);
    }
    printf("\n");
    return 0;
}

