// hls.cpp
// Fixed PRESENT implementation for Vivado HLS (C++98 compatible)
// Top-level function 'present' has C linkage (extern "C") as required by the TB.
//
// Notes:
// - Avoids undefined behavior (no shifting of bools, well-defined bit ops).
// - Uses explicit integer loop counters.
// - Implements key schedule using explicit bit rotation (left rotate by 61).
// - Implements pLayer using the standard PRESENT bit permutation.
// - All comments are in English.

extern "C" {

#define PRESENT_80_KEY_SIZE_BYTES 10
#define PRESENT_BLOCK_SIZE_BYTES 8
#define ROUNDS 32
#define ROUND_KEY_SIZE_BYTES 8

typedef unsigned char keys_t[ROUNDS][ROUND_KEY_SIZE_BYTES];
typedef unsigned char present_key_t[PRESENT_80_KEY_SIZE_BYTES];
typedef unsigned char round_key_t[ROUND_KEY_SIZE_BYTES];
typedef unsigned char block_t[PRESENT_BLOCK_SIZE_BYTES];

static const unsigned char sBox[16] = {
    0xC, 0x5, 0x6, 0xB,
    0x9, 0x0, 0xA, 0xD,
    0x3, 0xE, 0xF, 0x8,
    0x4, 0x7, 0x1, 0x2
};

static const unsigned char sBoxInverse[16] = {
    0x5, 0xE, 0xF, 0x8,
    0xC, 0x1, 0x2, 0xD,
    0xB, 0x4, 0x6, 0x3,
    0x0, 0x7, 0x9, 0xA
};

/* Copy full 80-bit key (10 bytes) */
void copyKey(const present_key_t from, present_key_t to) {
    int i;
    for (i = 0; i < PRESENT_80_KEY_SIZE_BYTES; i++) {
        to[i] = from[i];
    }
}

/* Copy 64-bit block (8 bytes) */
void copyBlock(const block_t from, block_t to) {
    int i;
    for (i = 0; i < PRESENT_BLOCK_SIZE_BYTES; i++) {
        to[i] = from[i];
    }
}

/* Helper: get bit from key bytes array (bits[0] = MSB of key[0], bits[79] = LSB of key[9]) */
static unsigned char get_bit_from_bytes(const unsigned char *bytes, int bit_idx) {
    // bit_idx in [0..79], 0 = MSB of bytes[0] (bit7), 7 = LSB of bytes[0] (bit0), etc.
    int byte_index = bit_idx / 8;
    int bit_in_byte = 7 - (bit_idx % 8);
    return (bytes[byte_index] >> bit_in_byte) & 0x1;
}

/* Helper: set bit into key bytes array (bits[0] = MSB of key[0]) */
static void set_bit_in_bytes(unsigned char *bytes, int bit_idx, unsigned char val) {
    int byte_index = bit_idx / 8;
    int bit_in_byte = 7 - (bit_idx % 8);
    if (val)
        bytes[byte_index] |= (1u << bit_in_byte);
    else
        bytes[byte_index] &= (unsigned char)~(1u << bit_in_byte);
}

/* Generate 32 round keys for 80-bit key variant (explicit bitwise rotation by 61) */
void generateRoundKeys80(const present_key_t suppliedKey, keys_t keys) {
    unsigned char key[PRESENT_80_KEY_SIZE_BYTES];
    unsigned char newKey[PRESENT_80_KEY_SIZE_BYTES];
    int round, i;

    copyKey(suppliedKey, key);

    for (round = 0; round < ROUNDS; round++) {
        /* copy first 8 bytes as round key for this round */
        for (i = 0; i < ROUND_KEY_SIZE_BYTES; i++) {
            keys[round][i] = key[i];
        }

        /* Do key schedule for next round (unless last round) */
        if (round == ROUNDS - 1) break;

        /* Convert key bytes to bit array (bits[0] = MSB of key[0], bits[79] = LSB of key[9]) */
        unsigned char bits[80];
        for (i = 0; i < 80; i++) {
            bits[i] = get_bit_from_bytes(key, i);
        }

        /* Rotate left by 61 bits: newbits[i] = bits[(i + 61) % 80] */
        unsigned char newbits[80];
        for (i = 0; i < 80; i++) {
            int src = (i + 61) % 80;
            newbits[i] = bits[src];
        }

        /* Recompose bytes from newbits into newKey (clear first) */
        int b;
        for (b = 0; b < PRESENT_80_KEY_SIZE_BYTES; b++) newKey[b] = 0;
        for (i = 0; i < 80; i++) {
            set_bit_in_bytes(newKey, i, newbits[i]);
        }

        /* Apply S-box to the leftmost 4 bits of newKey[0] (MSB nibble) */
        {
            unsigned char upper_nibble = (newKey[0] >> 4) & 0xF;
            unsigned char lower_nibble = newKey[0] & 0xF;
            newKey[0] = (unsigned char)((sBox[upper_nibble] << 4) | lower_nibble);
        }

        /* XOR round counter i (5-bit value) into bits k19..k15
           Mapping: bits array index for kX is (X mapped to position with 0=MSB of key[0]):
           bit index = 79 - X. So for k19..k15, indices are 79-19..79-15 => 60..64
           We'll XOR the round number's 5 LSBs into those bits with MSB of counter at k19.
        */
        {
            int base_bit_idx = 79 - 19; /* 60 */
            int bitpos;
            for (bitpos = 0; bitpos < 5; bitpos++) {
                unsigned char counter_bit = (unsigned char)((round + 1) >> (4 - bitpos)) & 0x1;
                /* XOR into newbits at index base_bit_idx + bitpos */
                int target_idx = base_bit_idx + bitpos;
                unsigned char cur = get_bit_from_bytes(newKey, target_idx);
                unsigned char res = cur ^ counter_bit;
                set_bit_in_bytes(newKey, target_idx, res);
            }
        }

        /* Update key for next iteration */
        copyKey(newKey, key);
    }
}

/* XOR 64-bit round key into 64-bit block */
void addRoundKey(block_t block, const round_key_t roundKey) {
    int i;
    for (i = 0; i < PRESENT_BLOCK_SIZE_BYTES; i++) {
        block[i] ^= roundKey[i];
    }
}

/* PRESENT pLayer: permute bits according to P(i) = (16 * i) % 63 for i = 0..62, P(63) = 63
   We assume block bits indexing: bits[0] = MSB of block[0], bits[63] = LSB of block[7].
*/
void pLayer(block_t block) {
    unsigned char inbits[64];
    unsigned char outbits[64];
    int i;

    /* extract bits */
    for (i = 0; i < 64; i++) {
        int byte_index = i / 8;
        int bit_in_byte = 7 - (i % 8);
        inbits[i] = (block[byte_index] >> bit_in_byte) & 0x1;
        outbits[i] = 0;
    }

    /* permute */
    for (i = 0; i < 63; i++) {
        int newpos = (16 * i) % 63;
        outbits[newpos] = inbits[i];
    }
    /* last bit maps to itself */
    outbits[63] = inbits[63];

    /* reassemble bytes */
    int b;
    for (b = 0; b < 8; b++) block[b] = 0;
    for (i = 0; i < 64; i++) {
        if (outbits[i]) {
            int byte_index = i / 8;
            int bit_in_byte = 7 - (i % 8);
            block[byte_index] |= (unsigned char)(1u << bit_in_byte);
        }
    }
}

/* Inverse pLayer (for completeness) */
void pLayerInverse(block_t block) {
    unsigned char inbits[64];
    unsigned char outbits[64];
    int i;

    /* extract bits */
    for (i = 0; i < 64; i++) {
        int byte_index = i / 8;
        int bit_in_byte = 7 - (i % 8);
        inbits[i] = (block[byte_index] >> bit_in_byte) & 0x1;
        outbits[i] = 0;
    }

    /* inverse permute: find position j such that P(j) = i, i.e. j = inverse */
    for (i = 0; i < 63; i++) {
        int newpos = (16 * i) % 63;
        outbits[i] = inbits[newpos];
    }
    outbits[63] = inbits[63];

    /* reassemble bytes */
    int b;
    for (b = 0; b < 8; b++) block[b] = 0;
    for (i = 0; i < 64; i++) {
        if (outbits[i]) {
            int byte_index = i / 8;
            int bit_in_byte = 7 - (i % 8);
            block[byte_index] |= (unsigned char)(1u << bit_in_byte);
        }
    }
}

/*
 Top-level HLS function.
 The TB provides pointers-to-arrays (pointer to block_t and pointer to present_key_t),
 so accept those types here. Internally copy into local arrays for processing.
*/
void present(unsigned char (*block)[PRESENT_BLOCK_SIZE_BYTES],
             unsigned char (*key)[PRESENT_80_KEY_SIZE_BYTES]) {
#pragma HLS INTERFACE m_axi port=block offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=key offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=block bundle=control
#pragma HLS INTERFACE s_axilite port=key bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    /* Local copies of inputs (work on local memory) */
    block_t local_block;
    present_key_t local_key;
    int i, j, r;

    /* Copy data from pointer-to-array inputs into local arrays */
    for (i = 0; i < PRESENT_BLOCK_SIZE_BYTES; i++) {
        local_block[i] = (*block)[i];
    }
    for (i = 0; i < PRESENT_80_KEY_SIZE_BYTES; i++) {
        local_key[i] = (*key)[i];
    }

    /* Generate round keys and perform encryption */
    keys_t roundKeys;
    generateRoundKeys80(local_key, roundKeys);

    for (r = 0; r < ROUNDS - 1; r++) {
        addRoundKey(local_block, roundKeys[r]);

        /* apply sBox to each nibble (high then low) */
        for (j = 0; j < PRESENT_BLOCK_SIZE_BYTES; j++) {
            unsigned char high = (local_block[j] >> 4) & 0xF;
            unsigned char low  = local_block[j] & 0xF;
            unsigned char newbyte = (unsigned char)((sBox[high] << 4) | sBox[low]);
            local_block[j] = newbyte;
        }

        pLayer(local_block);
    }

    /* final round key */
    addRoundKey(local_block, roundKeys[ROUNDS - 1]);

    /* Write result back to the pointer-to-array output */
    for (i = 0; i < PRESENT_BLOCK_SIZE_BYTES; i++) {
        (*block)[i] = local_block[i];
    }
}

} // extern "C"

