#include "test.h"
#include <stdio.h>
#include <stdlib.h>
#include <time.h>

float compute_distance(float target[DIMS], float query[DIMS]) {
    float dist = 0.0f;
    for (int i = 0; i < DIMS; i++) {
        float diff = target[i] - query[i];
        dist += diff * diff;
    }
    return dist;
}

void linear_search(float* targets, float* queries, unsigned int indices[QUERIES]) {
    for (int q = 0; q < QUERIES; q++) {
        float min_dist = FLT_MAX;
        unsigned int min_index = 0;
        float* query_ptr = &queries[q * DIMS];
        for (int t = 0; t < TARGETS; t++) {
            float* target_ptr = &targets[t * DIMS];
            float dist = compute_distance(target_ptr, query_ptr);
            if (dist < min_dist) {
                min_dist = dist;
                min_index = t;
            }
        }
        indices[q] = min_index;
    }
}

int main(void) {
    float* targets = (float*)malloc(sizeof(float) * TARGETS * DIMS);
    float* queries = (float*)malloc(sizeof(float) * QUERIES * DIMS);
    unsigned int* indices = (unsigned int*)malloc(sizeof(unsigned int) * QUERIES);
    if (!targets || !queries || !indices) return 1;
    srand((unsigned)time(NULL));
    for (int i = 0; i < TARGETS * DIMS; i++) targets[i] = (float)rand() / (float)RAND_MAX;
    for (int i = 0; i < QUERIES * DIMS; i++) queries[i] = (float)rand() / (float)RAND_MAX;
    linear_search(targets, queries, indices);
    for (int i = 0; i < 10 && i < QUERIES; i++) {
        printf("%u\n", indices[i]);
    }
    free(targets);
    free(queries);
    free(indices);
    return 0;
}

