    float dist = 0.0f;
    for (int i = 0; i < DIMS; i++) {
        float diff = target[i] - query[i];
        dist += diff * diff;
    }
    return dist;
}

void linear_search(float* targets, float* queries, unsigned int indices[QUERIES]) {
    for (int q = 0; q < QUERIES; q++) {
        float min_dist = 3.402823466e+38F; // FLT_MAX without including float.h
        unsigned int min_index = 0;
        float* query_ptr = &queries[q * DIMS];
        for (int t = 0; t < TARGETS; t++) {
            float* target_ptr = &targets[t * DIMS];
            float dist = compute_distance(target_ptr, query_ptr);
            if (dist < min_dist) {
                min_dist = dist;
                min_index = t;
            }
        }
        indices[q] = min_index;
    }
}

int main(void) {
    // Deterministic, small testbench to finish quickly
    float* targets = (float*)malloc(sizeof(float) * TARGETS * DIMS);
    float* queries = (float*)malloc(sizeof(float) * QUERIES * DIMS);
    unsigned int* indices = (unsigned int*)malloc(sizeof(unsigned int) * QUERIES);
    if (!targets || !queries || !indices) {
        return 1;
    }

    // Fill targets and queries with deterministic values
    for (int t = 0; t < TARGETS; t++) {
        for (int d = 0; d < DIMS; d++) {
            // pattern ensures variety: e.g., target 0..TARGETS-1 mapped to different magnitudes
            targets[t * DIMS + d] = (float)(t * 10 + d);
        }
    }
    for (int q = 0; q < QUERIES; q++) {
        for (int d = 0; d < DIMS; d++) {
            // queries offset by 0.5 to avoid exact matches in most cases
            queries[q * DIMS + d] = (float)(q * 10 + d) + 0.5f;
        }
    }

    // Prepare CSV
    FILE* f = std::fopen("c_output.csv", "w");
    if (!f) {
        free(targets);
        free(queries);
        free(indices);
        return 1;
    }

    // CSV header: cycle, then inputs driven by testbench, then outputs sampled from DUT
    std::fprintf(f, "cycle,rst,en,target_idx,query_idx,dist,ls_index\n");
    // Role row: meta/in/out mapping
    std::fprintf(f, "meta,in,in,in,in,out,out\n");

    const int cycles = 30; // between 20 and 50
    for (int cycle = 0; cycle < cycles; cycle++) {
        // Reset/enable policy: first 2 cycles reset active, en=0; afterwards reset released, en=1
        int rst = (cycle < 2) ? 1 : 0;
        int en  = (cycle < 2) ? 0 : 1;

        // Testbench drives indices (integers)
        int target_idx = cycle % TARGETS;
        int query_idx = (cycle * 3 + 1) % QUERIES; // varied pattern

        // Always call compute_distance (DUT) once per cycle
        float dist_f = compute_distance(&targets[target_idx * DIMS], &queries[query_idx * DIMS]);
        uint32_t dist_bits;
        std::memcpy(&dist_bits, &dist_f, sizeof(dist_bits));

        // Call linear_search only when enabled to simulate enable behavior
        unsigned int ls_index = 0;
        if (en) {
            linear_search(targets, queries, indices);
            ls_index = indices[query_idx];
        } else {
            // During reset/disabled, keep a defined value (0)
            ls_index = 0;
        }

        // Output: inputs as decimal integers (rst/en/indices), outputs as hex uppercase without 0x
        std::fprintf(f, "%d,%d,%d,%d,%d,%X,%X\n",
                     cycle,
                     rst,
                     en,
                     target_idx,
                     query_idx,
                     dist_bits,
                     (unsigned int)ls_index);
    }

    std::fclose(f);
    free(targets);
    free(queries);
    free(indices);
    return 0;
}

