// hls.cpp
// Modified small-kernel linear search for Vivado HLS cosimulation testbench.
// Top-level remains extern "C" as required by the cosim environment.
// Comments are in English.

#include "ap_int.h"
#include "ap_fixed.h"

#define TARGETS 10   // Reduced to match the testbench TARGETS
#define QUERIES 8    // Reduced to match the testbench QUERIES
#define DIMS 3

#ifndef COMPUTE_TARGETS
#define COMPUTE_TARGETS (16)
#endif

#ifndef COMPUTE_QUERIES
#define COMPUTE_QUERIES (16)
#endif

#define QUERY_BLOCKS ((QUERIES - 1) / COMPUTE_QUERIES + 1)
#define TARGET_BLOCKS ((TARGETS - 1) / COMPUTE_TARGETS + 1)

typedef ap_ufixed<38, 20> diff_t;

// Helper function to compute squared distance between one target and one query point
inline diff_t linear_search_compute_elem(unsigned int target_x,
                                         unsigned int target_y,
                                         unsigned int target_z,
                                         unsigned int query_x,
                                         unsigned int query_y,
                                         unsigned int query_z) {
    #pragma HLS INLINE

    ap_fixed<32, 16> target_x_fixed, target_y_fixed, target_z_fixed;
    ap_fixed<32, 16> query_x_fixed, query_y_fixed, query_z_fixed;

    // Assign raw bit patterns into fixed variables
    target_x_fixed.range(31, 0) = target_x;
    target_y_fixed.range(31, 0) = target_y;
    target_z_fixed.range(31, 0) = target_z;
    query_x_fixed.range(31, 0) = query_x;
    query_y_fixed.range(31, 0) = query_y;
    query_z_fixed.range(31, 0) = query_z;

    ap_fixed<17, 8, AP_TRN, AP_SAT> target_x_trn = target_x_fixed;
    ap_fixed<17, 8, AP_TRN, AP_SAT> target_y_trn = target_y_fixed;
    ap_fixed<17, 8, AP_TRN, AP_SAT> target_z_trn = target_z_fixed;
    ap_fixed<17, 8, AP_TRN, AP_SAT> query_x_trn = query_x_fixed;
    ap_fixed<17, 8, AP_TRN, AP_SAT> query_y_trn = query_y_fixed;
    ap_fixed<17, 8, AP_TRN, AP_SAT> query_z_trn = query_z_fixed;

    ap_fixed<18, 9, AP_TRN> dist_x = target_x_trn - query_x_trn;
    ap_fixed<18, 9, AP_TRN> dist_y = target_y_trn - query_y_trn;
    ap_fixed<18, 9, AP_TRN> dist_z = target_z_trn - query_z_trn;

    #pragma HLS RESOURCE variable=dist_x core=AddSub_DSP
    #pragma HLS RESOURCE variable=dist_y core=AddSub_DSP
    #pragma HLS RESOURCE variable=dist_z core=AddSub_DSP

    ap_ufixed<36, 18, AP_TRN> pair_dist_x = dist_x * dist_x;
    ap_ufixed<36, 18, AP_TRN> pair_dist_y = dist_y * dist_y;
    ap_ufixed<36, 18, AP_TRN> pair_dist_z = dist_z * dist_z;

    diff_t pair_dist = pair_dist_x;
    pair_dist += pair_dist_y;
    pair_dist += pair_dist_z;
    #pragma HLS RESOURCE variable=pair_dist core=AddSub_DSP

    return pair_dist;
}

inline void linear_search_compute(
    unsigned int targets[TARGET_BLOCKS][COMPUTE_TARGETS][DIMS],
    unsigned int queries[QUERY_BLOCKS][COMPUTE_QUERIES][DIMS],
    unsigned int indices[QUERY_BLOCKS][COMPUTE_QUERIES]) {
    #pragma HLS INLINE

    diff_t dists[QUERY_BLOCKS][COMPUTE_QUERIES];
    #pragma HLS array_partition variable=dists block factor=2 dim=2

    // Use int for loop indices to be compatible with HLS synthesis engine (C++98)
    for (int i = 0; i < (int)(TARGET_BLOCKS * QUERY_BLOCKS); i++) {
        #pragma HLS unroll factor=2
        int t = i / QUERY_BLOCKS;
        int q = i % QUERY_BLOCKS;

        diff_t ldists[COMPUTE_QUERIES][COMPUTE_TARGETS];
        #pragma HLS array_partition variable=ldists cyclic factor=8 dim=1

        diff_t min_dist[COMPUTE_QUERIES];
        #pragma HLS array_partition variable=min_dist block factor=8 dim=1
        unsigned int min_indices[COMPUTE_QUERIES];
        #pragma HLS array_partition variable=min_indices complete dim=1

        // Initialize min values: if first target block, set to max; otherwise load previous mins
        for (int j = 0; j < COMPUTE_QUERIES; j++) {
            #pragma HLS unroll
            if (t == 0) {
                // Set to a very large value (all ones within range bits)
                min_dist[j].range(37, 0) = 0x3FFFFFFFFUL;
                min_indices[j] = 0xFFFFFFFFU;
            } else {
                min_dist[j] = dists[q][j];
                min_indices[j] = indices[q][j];
            }
        }

        unsigned int lqueries[COMPUTE_QUERIES][DIMS];
        #pragma HLS array_partition variable=lqueries block factor=8 dim=1

        // Local copy of queries block
        for (int j = 0; j < COMPUTE_QUERIES; j++) {
            #pragma HLS pipeline
            for (int k = 0; k < DIMS; k++) {
                #pragma HLS pipeline II=1
                lqueries[j][k] = queries[q][j][k];
            }
        }

        unsigned int ltargets[COMPUTE_TARGETS][DIMS];
        #pragma HLS array_partition variable=ltargets complete dim=1

        // Local copy of targets block
        for (int j = 0; j < COMPUTE_TARGETS; j++) {
            #pragma HLS unroll factor=8
            for (int k = 0; k < DIMS; k++) {
                #pragma HLS unroll
                ltargets[j][k] = targets[t][j][k];
            }
        }

        // Compute distances between local targets and local queries
        for (int j = 0; j < COMPUTE_QUERIES; j++) {
            #pragma HLS unroll factor=2
            for (int k = 0; k < COMPUTE_TARGETS; k++) {
                #pragma HLS unroll factor=2
                if (t * COMPUTE_TARGETS + k < TARGETS && q * COMPUTE_QUERIES + j < QUERIES) {
                    ldists[j][k] = linear_search_compute_elem(
                        ltargets[k][0], ltargets[k][1], ltargets[k][2],
                        lqueries[j][0], lqueries[j][1], lqueries[j][2]);
                } else {
                    // out-of-range sentinel (large)
                    ldists[j][k].range(37, 0) = 0x3FFFFFFFFUL;
                }
            }
        }

        // Update minima
        for (int j = 0; j < COMPUTE_QUERIES; j++) {
            #pragma HLS unroll
            for (int k = 0; k < COMPUTE_TARGETS; k++) {
                #pragma HLS unroll factor=2
                if (ldists[j][k] < min_dist[j]) {
                    min_dist[j] = ldists[j][k];
                    min_indices[j] = t * COMPUTE_TARGETS + k;
                }
            }
        }

        // Write back minima for this query-block
        for (int j = 0; j < COMPUTE_QUERIES; j++) {
            #pragma HLS pipeline
            dists[q][j] = min_dist[j];
            indices[q][j] = min_indices[j];
        }
    }
}

extern "C" void linear_search(
    const float *targets,
    const float *queries,
    unsigned int *indices) {

    #pragma HLS INTERFACE m_axi port=targets offset=slave bundle=gmem0
    #pragma HLS INTERFACE m_axi port=queries offset=slave bundle=gmem1
    #pragma HLS INTERFACE m_axi port=indices offset=slave bundle=gmem2
    #pragma HLS INTERFACE s_axilite port=targets bundle=control
    #pragma HLS INTERFACE s_axilite port=queries bundle=control
    #pragma HLS INTERFACE s_axilite port=indices bundle=control
    #pragma HLS INTERFACE s_axilite port=return bundle=control

    unsigned int queries_buf[QUERY_BLOCKS][COMPUTE_QUERIES][DIMS];
    #pragma HLS array_partition variable=queries_buf cyclic factor=8 dim=2

    // Read queries from AXI into local fixed-bit representation
    for (int i = 0; i < (int)(QUERIES * DIMS); i++) {
        #pragma HLS pipeline II=1
        int x = i % DIMS;
        int y = (i / DIMS) % COMPUTE_QUERIES;
        int z = (i / DIMS) / COMPUTE_QUERIES;
        ap_fixed<32, 16, AP_TRN, AP_SAT> tfixed = queries[i];
        // store the raw fixed-point bit pattern into the unsigned int buffer
        queries_buf[z][y][x] = tfixed.range(31, 0);
    }

    unsigned int targets_buf[TARGET_BLOCKS][COMPUTE_TARGETS][DIMS];
    #pragma HLS array_partition variable=targets_buf cyclic factor=8 dim=1

    // Read targets from AXI into local fixed-bit representation
    for (int i = 0; i < (int)(TARGETS * DIMS); i++) {
        #pragma HLS unroll factor=2
        int x = i % DIMS;
        int y = (i / DIMS) % COMPUTE_TARGETS;
        int z = (i / DIMS) / COMPUTE_TARGETS;
        ap_fixed<32, 16, AP_TRN, AP_SAT> tfixed = targets[i];
        targets_buf[z][y][x] = tfixed.range(31, 0);
    }

    unsigned int indices_buf[QUERY_BLOCKS][COMPUTE_QUERIES];
    #pragma HLS array_partition variable=indices_buf block factor=16 dim=1

    linear_search_compute(targets_buf, queries_buf, indices_buf);

    // Write out results to AXI indices buffer (flattened by query)
    for (int i = 0; i < (int)QUERIES; i++) {
        #pragma HLS unroll factor=8
        int x = i % COMPUTE_QUERIES;
        int y = i / COMPUTE_QUERIES;
        indices[i] = indices_buf[y][x];
    }
}

