// hls.cpp
// Vivado HLS top function and helpers
// Comments in English
#include <math.h>

#define STEPS 5
#define NUM_PATHS 4
#define N_BUFF 4

// Simple power helper optimized for exponent == 2
static double hls_pow(double base, double exp) {
    if (exp == 2.0) return base * base;
    else return pow(base, exp);
}

// Simple sqrt wrapper
static double hls_sqrt(double x) {
    return sqrt(x);
}

// Generate one path in-place. The input path[] contains initial noise values
// (e.g., path[0] may be used as the first noise sample).
// Keep this function not inlined to help HLS analysis.
void generatePath(double path[STEPS], double S0, double f1, double f2) {
#pragma HLS INLINE off
    // Use the existing path[0] (which is expected to be loaded from memory
    // before calling this function). The formula follows the original intent.
    path[0] = S0 * exp(f1 + f2 * path[0]);
    for (int i = 1; i < STEPS; i++) {
#pragma HLS pipeline
        path[i] = path[i - 1] * exp(f1 + f2 * path[i]);
    }
}

// Load N_BUFF paths from external memory into small on-chip buffer
void loadPaths(double paths_from_mem[NUM_PATHS][STEPS], double paths_buff[N_BUFF][STEPS], int starting_idx) {
#pragma HLS INLINE off
    for (int i = 0; i < N_BUFF; i++) {
#pragma HLS unroll factor=4
        for (int j = 0; j < STEPS; j++) {
#pragma HLS pipeline
            paths_buff[i][j] = paths_from_mem[i + starting_idx][j];
        }
    }
}

// Write N_BUFF paths back to external memory
void writePaths(double paths_to_mem[NUM_PATHS][STEPS], double paths_buff[N_BUFF][STEPS], int starting_idx) {
#pragma HLS INLINE off
    for (int i = 0; i < N_BUFF; i++) {
#pragma HLS unroll factor=4
        for (int j = 0; j < STEPS; j++) {
#pragma HLS unroll factor=2
            paths_to_mem[i + starting_idx][j] = paths_buff[i][j];
        }
    }
}

// Top-level function for HLS
// Note: Add 'reset' parameter to match testbench signature.
// When reset is asserted, the DUT will not modify the external paths array.
extern "C" void optionValue(double paths[NUM_PATHS][STEPS], double params[4], int reset) {
#pragma HLS INTERFACE m_axi port=paths bundle=pths depth=16384
#pragma HLS INTERFACE m_axi port=params bundle=prms depth=4
#pragma HLS INTERFACE s_axilite port=paths bundle=control
#pragma HLS INTERFACE s_axilite port=params bundle=control
#pragma HLS INTERFACE s_axilite port=reset bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // If reset is asserted, do nothing (testbench re-loads initial noise externally).
    if (reset) return;

    double S0 = params[0];
    double T = params[1];
    double SIGMA = params[2];
    double MU = params[3];

    double dt = T / STEPS;
    double path[N_BUFF][STEPS];
#pragma HLS array_partition variable=path block factor=2 dim=1

    double f1 = (MU - (0.5 * hls_pow(SIGMA, 2.0))) * dt;
    double f2 = SIGMA * hls_sqrt(dt);

    // Process in chunks of N_BUFF
    int chunks = NUM_PATHS / N_BUFF;
    for (int idx = 0; idx < chunks; idx++) {
#pragma HLS pipeline
        int starting_idx = idx * N_BUFF;
        loadPaths(paths, path, starting_idx);

        for (int i = 0; i < N_BUFF; i++) {
#pragma HLS pipeline
            generatePath(path[i], S0, f1, f2);
        }

        writePaths(paths, path, starting_idx);
    }
}

