#include "test.h"
#include <stdio.h>
#include <stdlib.h>

static uint32_t reverse_bits(uint32_t x) {
    uint32_t rev = 0;
    for (int i = 0; i < M; i++) {
        rev = (rev << 1) | (x & 1);
        x >>= 1;
    }
    return rev;
}

void bit_reverse(const float X_R[SIZE], const float X_I[SIZE],
                 float OUT_R[SIZE],     float OUT_I[SIZE])
{
    for (uint32_t i = 0; i < SIZE; i++) {
        uint32_t j = reverse_bits(i);

        if (i < j) {
            OUT_R[i] = X_R[j];
            OUT_I[i] = X_I[j];
            OUT_R[j] = X_R[i];
            OUT_I[j] = X_I[i];
        } else if (i == j) {
            OUT_R[i] = X_R[i];
            OUT_I[i] = X_I[i];
        }
    }
}

void fft_stage(int stage,
               const float  X_R[SIZE], const float  X_I[SIZE],
                     float Out_R[SIZE],       float Out_I[SIZE])
{
    int dft_pts = 1 << stage;       
    int half    = dft_pts >> 1;     
    float angle_step = -2.0f * PI / dft_pts;

    for (int k = 0; k < half; k++) {
        float angle = k * angle_step;
        float c = cosf(angle);
        float s = sinf(angle);

        for (int i = k; i < SIZE; i += dft_pts) {
            int j = i + half;
            float tr =  X_R[j] * c - X_I[j] * s;
            float ti =  X_I[j] * c + X_R[j] * s;
            Out_R[j] = X_R[i] - tr;
            Out_I[j] = X_I[i] - ti;
            Out_R[i] = X_R[i] + tr;
            Out_I[i] = X_I[i] + ti;
        }
    }
}

void fft_multistage(float X_R[SIZE], float X_I[SIZE],
                    float OUT_R[SIZE],       float OUT_I[SIZE])
{
    static float buf1_R[SIZE], buf1_I[SIZE];
    static float buf2_R[SIZE], buf2_I[SIZE];

    bit_reverse(X_R, X_I, buf1_R, buf1_I);

    fft_stage(1, buf1_R, buf1_I, buf2_R, buf2_I);
    fft_stage(2, buf2_R, buf2_I, OUT_R, OUT_I);
}

int main(void) {
    float X_R[SIZE], X_I[SIZE];
    float OUT_R[SIZE], OUT_I[SIZE];

    for (int i = 0; i < SIZE; i++) {
        X_R[i] = sinf(2.0f * PI * i / SIZE);
        X_I[i] = 0.0f;
        OUT_R[i] = 0.0f;
        OUT_I[i] = 0.0f;
    }

    fft_multistage(X_R, X_I, OUT_R, OUT_I);

    for (int i = 0; i < 16; i++) {
