// hls.cpp
// Fixed for Vivado HLS C++98 environment and to match the testbench (float, SIZE=1024).
// All comments in English.

#include <math.h>

#define M 10
#define SIZE (1 << M)

typedef float DTYPE;

// Use standard double-precision math functions and cast to DTYPE to ensure
// availability in Vivado HLS environment (older toolchain headers).
static inline DTYPE my_cos(DTYPE x) {
    return (DTYPE)cos((double)x);
}

static inline DTYPE my_sin(DTYPE x) {
    return (DTYPE)sin((double)x);
}

unsigned int reverse_bits(unsigned int input) {
    unsigned int rev = 0;
    for (int i = 0; i < M; i++) {
        rev = (rev << 1) | (input & 1u);
        input = input >> 1;
    }
    return rev;
}

// Perform a straightforward bit-reverse copy from input arrays to output arrays.
// This implementation avoids in-place swapping logic and is simpler for HLS.
void bit_reverse(DTYPE X_R[SIZE], DTYPE X_I[SIZE], DTYPE OUT_R[SIZE], DTYPE OUT_I[SIZE]) {
    for (unsigned int i = 0; i < SIZE; i++) {
        unsigned int r = reverse_bits(i);
        OUT_R[r] = X_R[i];
        OUT_I[r] = X_I[i];
    }
}

void fft_stage(int stage, DTYPE X_R[SIZE], DTYPE X_I[SIZE], DTYPE Out_R[SIZE], DTYPE Out_I[SIZE]) {
    int DFTpts = 1 << stage;
    int numBF = DFTpts / 2;
    DTYPE a = 0.0f;
    DTYPE e = -6.283185307179586f / (DTYPE)DFTpts;

    // Outer loop over butterflies within a DFT block
    for (int j = 0; j < numBF; j++) {
        DTYPE c = my_cos(a);
        DTYPE s = my_sin(a);
        a = a + e;

        // Apply butterflies across the whole array
        for (int i = j; i < SIZE; i += DFTpts) {
            int i_lower = i + numBF;
            DTYPE temp_R = X_R[i_lower] * c - X_I[i_lower] * s;
            DTYPE temp_I = X_I[i_lower] * c + X_R[i_lower] * s;
            Out_R[i_lower] = X_R[i] - temp_R;
            Out_I[i_lower] = X_I[i] - temp_I;
            Out_R[i] = X_R[i] + temp_R;
            Out_I[i] = X_I[i] + temp_I;
        }
    }
}

extern "C" void fft_multistage(float X_R[SIZE], float X_I[SIZE], float OUT_R[SIZE], float OUT_I[SIZE]) {
#pragma HLS INTERFACE m_axi port=X_R offset=slave bundle=gmem0
#pragma HLS INTERFACE m_axi port=X_I offset=slave bundle=gmem1
#pragma HLS INTERFACE m_axi port=OUT_R offset=slave bundle=gmem2
#pragma HLS INTERFACE m_axi port=OUT_I offset=slave bundle=gmem3
#pragma HLS INTERFACE s_axilite port=X_R bundle=control
#pragma HLS INTERFACE s_axilite port=X_I bundle=control
#pragma HLS INTERFACE s_axilite port=OUT_R bundle=control
#pragma HLS INTERFACE s_axilite port=OUT_I bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local buffers for stage processing
    DTYPE Stage1_R[SIZE];
    DTYPE Stage1_I[SIZE];
    DTYPE Stage2_R[SIZE];
    DTYPE Stage2_I[SIZE];

#pragma HLS array_partition variable=Stage1_R cyclic factor=2 dim=1

    // Bit-reverse and two-stage FFT (matches testbench expectations)
    bit_reverse(X_R, X_I, Stage1_R, Stage1_I);
    fft_stage(1, Stage1_R, Stage1_I, Stage2_R, Stage2_I);
    fft_stage(2, Stage2_R, Stage2_I, OUT_R, OUT_I);
}

