#include <stdint.h>

extern "C" {

#define N 3

typedef int32_t DATA_TYPE;

// Compute tmp = alpha * A * B
void compute_tmp(DATA_TYPE alpha, DATA_TYPE A[N][N], DATA_TYPE B[N][N], DATA_TYPE tmp[N][N]) {
#pragma HLS INLINE
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            DATA_TYPE sum = 0;
            for (int k = 0; k < N; k++) {
                sum += (DATA_TYPE)(alpha * A[i][k] * B[k][j]);
            }
            tmp[i][j] = sum;
        }
    }
}

// Compute E_out = tmp * C + beta * D
void compute_E_out(DATA_TYPE tmp[N][N], DATA_TYPE C[N][N], DATA_TYPE beta, DATA_TYPE D[N][N], DATA_TYPE E_out[N][N]) {
#pragma HLS INLINE
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            DATA_TYPE sum = 0;
            for (int k = 0; k < N; k++) {
                sum += (DATA_TYPE)(tmp[i][k] * C[k][j]);
            }
            E_out[i][j] = (DATA_TYPE)(sum + beta * D[i][j]);
        }
    }
}

// Top-level function (extern "C" linkage must match the testbench declaration)
void k2mm(DATA_TYPE alpha, DATA_TYPE beta, DATA_TYPE A[N][N], DATA_TYPE B[N][N], DATA_TYPE C[N][N], DATA_TYPE D[N][N], DATA_TYPE E_out[N][N]) {
#pragma HLS INTERFACE m_axi port=A offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=B offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=C offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=D offset=slave bundle=gmem
#pragma HLS INTERFACE m_axi port=E_out offset=slave bundle=gmem

#pragma HLS INTERFACE s_axilite port=alpha bundle=control
#pragma HLS INTERFACE s_axilite port=beta bundle=control
#pragma HLS INTERFACE s_axilite port=A bundle=control
#pragma HLS INTERFACE s_axilite port=B bundle=control
#pragma HLS INTERFACE s_axilite port=C bundle=control
#pragma HLS INTERFACE s_axilite port=D bundle=control
#pragma HLS INTERFACE s_axilite port=E_out bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    DATA_TYPE tmp[N][N];

    // Initialize tmp to zero
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            tmp[i][j] = 0;
        }
    }

    compute_tmp(alpha, A, B, tmp);
    compute_E_out(tmp, C, beta, D, E_out);
}

} // extern "C"

