// Testbench for k2mm. Uses C headers compatible with older C++ standard used by Vivado HLS.
// Comments are in English as requested.

#include <cstdio>
#include <cstdlib>
#include <stdint.h> /* Use C header because some Vivado HLS toolchains do not provide <cstdint> */

typedef int32_t DATA_TYPE;
const int N = 3;

/* Extern top-level function declaration must match HLS C function exactly */
extern "C" {
void k2mm(DATA_TYPE alpha, DATA_TYPE beta, DATA_TYPE A[N][N], DATA_TYPE B[N][N], DATA_TYPE C[N][N], DATA_TYPE D[N][N], DATA_TYPE E_out[N][N]);
}

/* HLS testbench:
   - Drives inputs: pattern, alpha, beta (pattern is a testbench signal used to generate matrices)
   - Internally generates A,B,C,D based on pattern and cycle deterministically
   - Calls DUT each cycle and writes CSV rows to hls_output.csv
   - CSV columns: cycle,pattern,alpha,beta,E_out_0_0,...,E_out_2_2
   - Second row roles: meta,in,in,in,out,...
*/
int main()
{
    const int CYCLES = 30; /* between 20 and 50 */

    FILE *f = std::fopen("hls_output.csv", "w");
    if (!f) return 1;

    /* Header row */
    std::fprintf(f, "cycle,pattern,alpha,beta,E_out_0_0,E_out_0_1,E_out_0_2,E_out_1_0,E_out_1_1,E_out_1_2,E_out_2_0,E_out_2_1,E_out_2_2\n");

    /* Role row */
    std::fprintf(f, "meta,in,in,in,out,out,out,out,out,out,out,out,out\n");

    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        /* Driven inputs (deterministic, not random) */
        int pattern = cycle % 5;                 /* vary pattern over 0..4 */
        DATA_TYPE alpha = (DATA_TYPE)((cycle % 5) - 2);       /* values in -2..2 */
        DATA_TYPE beta  = (DATA_TYPE)((cycle % 3) - 1); /* values in -1..1 */

        /* Generate matrices A,B,C,D deterministically from pattern and cycle */
        DATA_TYPE A[N][N];
        DATA_TYPE B[N][N];
        DATA_TYPE Cmat[N][N];
        DATA_TYPE D[N][N];

        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < N; ++j) {
                /* Keep values small to avoid overflow and for variety */
                A[i][j] = (DATA_TYPE)((pattern + 1) * (i + 1) + j - (cycle % 3));
                B[i][j] = (DATA_TYPE)((pattern + 2) * (j + 1) - i + (cycle % 4));
                Cmat[i][j] = (DATA_TYPE)((i + 1) * (j + 1) + pattern - (cycle % 2));
                D[i][j] = (DATA_TYPE)((i - j) + pattern + (cycle % 2));
            }
        }

        DATA_TYPE E_out[N][N];

        /* Call DUT */
        k2mm(alpha, beta, A, B, Cmat, D, E_out);

        /* Write CSV row:
           - cycle, pattern, alpha, beta as decimal integers
           - outputs as uppercase hex without 0x and without fixed width
           For hex printing, cast to uint32_t to get a consistent hex representation. */
        std::fprintf(f, "%d,%d,%d,%d", cycle, pattern, (int)alpha, (int)beta);
        for (int i = 0; i < N; ++i) {
            for (int j = 0; j < N; ++j) {
                uint32_t val = (uint32_t)E_out[i][j];
                std::fprintf(f, ",%X", val);
            }
        }
        std::fprintf(f, "\n");
    }

    std::fclose(f);
    return 0;
}

