#include <cmath>

// Single-file testbench for the provided top(...) function.
// Generates c_output.csv according to the specified CSV format.

typedef float data_t;

// Activation helpers
static inline data_t relu(data_t x) { return x > 0.0f ? x : 0.0f; }
static inline data_t sigmoid(data_t x) { return 1.0f / (1.0f + std::expf(-x)); }

// DUT (copied/adapted from the user's snippet)
void top(data_t DRAM_x[128], data_t DRAM_A[128][64], data_t DRAM_B[64][64],
         data_t DRAM_y[64], data_t DRAM_bias[1], data_t DRAM_result[1]) {

    data_t layer1[64];
    for (int i = 0; i < 64; i++) layer1[i] = 0.0f;
    for (int i = 0; i < 64; i++) {
        for (int j = 0; j < 128; j++) {
            layer1[i] += DRAM_x[j] * DRAM_A[j][i];
        }
        layer1[i] = relu(layer1[i]);
    }

    data_t layer2[64];
    for (int i = 0; i < 64; i++) layer2[i] = 0.0f;
    for (int i = 0; i < 64; i++) {
        for (int j = 0; j < 64; j++) {
            layer2[i] += layer1[j] * DRAM_B[j][i];
        }
        layer2[i] = std::tanh(layer2[i]);
    }

    data_t dot = 0.0f;
    for (int i = 0; i < 64; i++) {
        dot += layer2[i] * DRAM_y[i];
    }
    DRAM_result[0] = sigmoid(dot + DRAM_bias[0]);
}


// Testbench utilities

// Patterns enumerations:
// We treat each whole array (DRAM_x, DRAM_A, DRAM_B, DRAM_y, DRAM_bias) as being
// initialized using one of a small set of deterministic patterns.
// The CSV will record which pattern index was used for each array (decimal integers).

void init_DRAM_x(data_t DRAM_x[128], int pat) {
    if (pat == 0) {
        // all zeros
        for (int i = 0; i < 128; ++i) DRAM_x[i] = 0.0f;
    } else if (pat == 1) {
        // all ones
        for (int i = 0; i < 128; ++i) DRAM_x[i] = 1.0f;
    } else if (pat == 2) {
        // ramp scaled
        for (int i = 0; i < 128; ++i) DRAM_x[i] = i * 0.01f;
    } else if (pat == 3) {
        // alternating +1 / -1
        for (int i = 0; i < 128; ++i) DRAM_x[i] = (i % 2 == 0) ? 1.0f : -1.0f;
    } else if (pat == 4) {
        // sparse: first 8 ones, rest zeros
        for (int i = 0; i < 128; ++i) DRAM_x[i] = (i < 8) ? 1.0f : 0.0f;
    } else {
        // small pseudo-random deterministic pattern based on index
        for (int i = 0; i < 128; ++i) DRAM_x[i] = ((i * 37) % 11 - 5) * 0.02f;
    }
}

void init_DRAM_A(data_t DRAM_A[128][64], int pat) {
    if (pat == 0) {
        for (int j = 0; j < 128; ++j)
            for (int i = 0; i < 64; ++i) DRAM_A[j][i] = 0.0f;
    } else if (pat == 1) {
        // identity-like: A[j][i] = 1 if i == (j % 64)
        for (int j = 0; j < 128; ++j)
            for (int i = 0; i < 64; ++i) DRAM_A[j][i] = (i == (j % 64)) ? 1.0f : 0.0f;
    } else if (pat == 2) {
        // small deterministic integers
        for (int j = 0; j < 128; ++j)
            for (int i = 0; i < 64; ++i) DRAM_A[j][i] = (((j * 31 + i * 7) % 9) - 4) * 0.01f;
    } else if (pat == 3) {
        for (int j = 0; j < 128; ++j)
