    else if (pat == 2) DRAM_bias[0] = -0.1f;
    else DRAM_bias[0] = 0.05f * (pat - 3);
}

int main() {
    // Prepare DUT memory
    static data_t DRAM_x[128];
    static data_t DRAM_A[128][64];
    static data_t DRAM_B[64][64];
    static data_t DRAM_y[64];
    static data_t DRAM_bias[1];
    static data_t DRAM_result[1];

    // Prepare a deterministic list of test vectors (pattern indices).
    // Each test vector selects a pattern for each input array.
    struct TestVec { int px; int pA; int pB; int py; int pb; };
    // We'll create 32 test cycles that sweep various combinations.
    const int CYCLES = 32;
    TestVec tvs[CYCLES];

    // Fill test vectors programmatically to be deterministic and cover variety.
    for (int c = 0; c < CYCLES; ++c) {
        // rotate patterns to get coverage
        tvs[c].px = c % 6;          // DRAM_x pattern 0..5
        tvs[c].pA = (c / 2) % 6;    // DRAM_A pattern
        tvs[c].pB = (c / 3) % 6;    // DRAM_B pattern
        tvs[c].py = (c / 4) % 6;    // DRAM_y pattern
        tvs[c].pb = c % 4;          // DRAM_bias pattern (0..3)
    }

    // Open CSV file
    FILE* f = std::fopen("c_output.csv", "w");
    if (!f) return 1;

    // Header: first line column names
    // First column must be 'cycle'. Then all input signal names driven by testbench,
    // then all outputs sampled from DUT.
    // We use the array variable names as the input column names.
    std::fprintf(f, "cycle,DRAM_x,DRAM_A,DRAM_B,DRAM_y,DRAM_bias,DRAM_result\n");
    // Second line: roles meta/in/out
    std::fprintf(f, "meta,in,in,in,in,in,out\n");

    // Run cycles: on each cycle apply test vector, call DUT, sample outputs
    for (int cycle = 0; cycle < CYCLES; ++cycle) {
        // Initialize inputs according to the selected patterns
        TestVec tv = tvs[cycle];
        init_DRAM_x(DRAM_x, tv.px);
        init_DRAM_A(DRAM_A, tv.pA);
        init_DRAM_B(DRAM_B, tv.pB);
        init_DRAM_y(DRAM_y, tv.py);
        init_DRAM_bias(DRAM_bias, tv.pb);

        // Call DUT
        top(DRAM_x, DRAM_A, DRAM_B, DRAM_y, DRAM_bias, DRAM_result);

        // Convert output float to 32-bit hex uppercase without 0x prefix
        uint32_t out_bits;
        static_assert(sizeof(uint32_t) == sizeof(data_t), "size mismatch");
        std::memcpy(&out_bits, &DRAM_result[0], sizeof(uint32_t));

        // Write CSV row:
        // Inputs are written as decimal integers (pattern indices).
        // Output is written as uppercase hex without 0x, variable width.
        std::fprintf(f, "%d,%d,%d,%d,%d,%d,%X\n",
                     cycle,
                     tv.px, tv.pA, tv.pB, tv.py, tv.pb,
                     (unsigned int)out_bits);
    }

    // Close file explicitly
    std::fclose(f);
    return 0;
}

