// hls.cpp
// HLS top implementation using float arithmetic to match the cosim testbench.
// Top-level function is declared with extern "C" for correct linkage with the testbench.

typedef float data_t;

extern "C" {

void top(data_t DRAM_x[128], data_t DRAM_A[128][64], data_t DRAM_B[64][64], data_t DRAM_y[64], data_t DRAM_bias[1], data_t DRAM_result[1]) {
#pragma HLS INTERFACE m_axi port=DRAM_x offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_A offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_B offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_y offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_bias offset=slave bundle=mem1
#pragma HLS INTERFACE m_axi port=DRAM_result offset=slave bundle=mem2
#pragma HLS INTERFACE s_axilite port=DRAM_x bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_A bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_B bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_y bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_bias bundle=control
#pragma HLS INTERFACE s_axilite port=DRAM_result bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local on-chip buffers
    data_t BRAM_x[128];
    data_t BRAM_A[128][64];
    data_t BRAM_B[64][64];
    data_t BRAM_y[64];
    data_t BRAM_bias[1];
    data_t BRAM_result[1];
    data_t BRAM_xt[64];
    data_t BRAM_yt[64];

#pragma HLS ARRAY_PARTITION variable=BRAM_x cyclic factor=8 dim=1
#pragma HLS ARRAY_PARTITION variable=BRAM_A cyclic factor=8 dim=1
#pragma HLS ARRAY_PARTITION variable=BRAM_A cyclic factor=8 dim=2
#pragma HLS ARRAY_PARTITION variable=BRAM_xt cyclic factor=8 dim=1
#pragma HLS ARRAY_PARTITION variable=BRAM_y cyclic factor=8 dim=1
#pragma HLS ARRAY_PARTITION variable=BRAM_B cyclic factor=8 dim=2
#pragma HLS ARRAY_PARTITION variable=BRAM_yt cyclic factor=8 dim=1

    // Load DRAM to BRAM
    for (int i = 0; i < 128; i++) {
#pragma HLS PIPELINE II=1
        BRAM_x[i] = DRAM_x[i];
        for (int j = 0; j < 64; j++) {
            BRAM_A[i][j] = DRAM_A[i][j];
        }
    }
    for (int i = 0; i < 64; i++) {
#pragma HLS PIPELINE II=1
        BRAM_y[i] = DRAM_y[i];
        for (int j = 0; j < 64; j++) {
            BRAM_B[i][j] = DRAM_B[i][j];
        }
    }
    BRAM_bias[0] = DRAM_bias[0];

    // Compute BRAM_xt = A^T * x
    for (int j = 0; j < 64; j++) {
#pragma HLS UNROLL factor=8
        BRAM_xt[j] = 0;
    }
    for (int j = 0; j < 64; j++) {
#pragma HLS UNROLL factor=8
        for (int i = 0; i < 128; i++) {
#pragma HLS UNROLL factor=8
            BRAM_xt[j] += BRAM_A[i][j] * BRAM_x[i];
        }
    }

    // Compute BRAM_yt = B * y
    for (int i = 0; i < 64; i++) {
        BRAM_yt[i] = 0;
    }
    for (int j = 0; j < 64; j++) {
#pragma HLS UNROLL factor=8
        for (int i = 0; i < 64; i++) {
            BRAM_yt[i] += BRAM_B[i][j] * BRAM_y[j];
        }
    }

    // Compute dot product BRAM_result[0] = BRAM_xt * BRAM_yt
    BRAM_result[0] = 0;
    for (int i = 0; i < 64; i++) {
#pragma HLS UNROLL factor=8
        BRAM_result[0] += BRAM_xt[i] * BRAM_yt[i];
    }

    // Store result back to DRAM
    DRAM_result[0] = BRAM_result[0];
}

} // extern "C"

