#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include "test.h"

void krnl_KALMAN(INTERFACE_WIDTH in[BATCH_SIZE_1 / FLOATS_PER_ELEMENT], INTERFACE_WIDTH out[BATCH_SIZE_1 / FLOATS_PER_ELEMENT]) {
    DTYPE in_local[BATCH_SIZE_1];
    DTYPE out_local[BATCH_SIZE_1];

    int counter = 0;
    for (int i = 0; i < BATCH_SIZE_1 / FLOATS_PER_ELEMENT; i++) {
        for (int j = 0; j < FLOATS_PER_ELEMENT; j++) {
            raw_float t;
            t.raw_val = in[i].data[j];
            in_local[counter] = (DTYPE)t.float_val;
            counter++;
        }
    }

    DTYPE u_hat_arr[INTERNAL_BATCHES];
    DTYPE p_arr_1[INTERNAL_BATCHES];
    DTYPE k_arr[INTERNAL_BATCHES];
    DTYPE calc_temp_arr[INTERNAL_BATCHES];

    for (int i = 0; i < INTERNAL_BATCHES; i++) {
        u_hat_arr[i] = in_local[i * INTERNAL_BATCH_SIZE];
        p_arr_1[i] = 0.5f;
        out_local[i * INTERNAL_BATCH_SIZE] = u_hat_arr[i];
    }

    for (int t = 1; t < INTERNAL_BATCH_SIZE; t++) {
        for (int i = 0; i < INTERNAL_BATCHES; i++) {
            calc_temp_arr[i] = p_arr_1[i] + (DTYPE)0.01f;
            k_arr[i] = calc_temp_arr[i] / (p_arr_1[i] + (DTYPE)1.01f);
            u_hat_arr[i] = u_hat_arr[i] + k_arr[i] * (in_local[i * INTERNAL_BATCH_SIZE + t] - u_hat_arr[i]);
            p_arr_1[i] = ((DTYPE)1 - k_arr[i]) * calc_temp_arr[i];
            out_local[i * INTERNAL_BATCH_SIZE + t] = u_hat_arr[i];
        }
    }

    counter = 0;
    for (int i = 0; i < BATCH_SIZE_1 / FLOATS_PER_ELEMENT; i++) {
        for (int j = 0; j < FLOATS_PER_ELEMENT; j++) {
            raw_float t;
            t.float_val = (float)out_local[counter];
            out[i].data[j] = t.raw_val;
            counter++;
        }
    }
}

int main() {
    const int elems = BATCH_SIZE_1 / FLOATS_PER_ELEMENT;
    INTERFACE_WIDTH *in = (INTERFACE_WIDTH*)malloc(sizeof(INTERFACE_WIDTH) * elems);
    INTERFACE_WIDTH *out = (INTERFACE_WIDTH*)malloc(sizeof(INTERFACE_WIDTH) * elems);
    if (!in || !out) return 1;

    uint32_t counter = 0;
    for (int i = 0; i < elems; i++) {
        for (int j = 0; j < FLOATS_PER_ELEMENT; j++) {
            raw_float t;
            t.float_val = (float)counter;
            in[i].data[j] = t.raw_val;
            counter++;
        }
    }

    krnl_KALMAN(in, out);

    counter = 0;
    for (int i = 0; i < 16 && counter < BATCH_SIZE_1; i++) {
        raw_float t;
        t.raw_val = out[i / FLOATS_PER_ELEMENT].data[i % FLOATS_PER_ELEMENT];
        printf("out[%u] = %f\n", counter, t.float_val);
        counter++;
    }

    free(in);
    free(out);
    return 0;
}

