// hls.cpp
//
// Top-level HLS kernel for a simple sliding Kalman-like filter.
// The top function is declared with C linkage (extern "C") so that the
// testbench (which also uses extern "C") can link against it correctly.
//
// Note: use <stdint.h> instead of <cstdint> for compatibility with
// Vivado HLS 2018.3's toolchain (C++98/libstdc++ older headers).

#include <stdint.h>
#include "ap_fixed.h"

#define FLOATS_PER_ELEMENT 1
#define INTERNAL_BATCHES 4
#define INTERNAL_BATCH_SIZE 4
#define BATCH_SIZE_1 (INTERNAL_BATCHES * INTERNAL_BATCH_SIZE)

#define DEC_BITS 6
#define INT_BITS 13

typedef ap_fixed<INT_BITS + DEC_BITS, INT_BITS, AP_RND> DTYPE;

// INTERFACE_WIDTH must match the testbench's layout exactly.
// The TB defines:
// typedef struct {
//     uint32_t data[FLOATS_PER_ELEMENT];
// } INTERFACE_WIDTH;
// So we mirror that here.
typedef struct {
    uint32_t data[FLOATS_PER_ELEMENT];
} INTERFACE_WIDTH;

// Use a union so writing the float updates the raw bits and vice versa.
// Use uint32_t for the raw representation to match the testbench.
typedef union {
    uint32_t raw_val;
    float float_val;
} raw_float;

// Ensure C linkage so the testbench's extern "C" declaration links properly.
extern "C" void krnl_KALMAN(INTERFACE_WIDTH in[BATCH_SIZE_1 / FLOATS_PER_ELEMENT],
                            INTERFACE_WIDTH out[BATCH_SIZE_1 / FLOATS_PER_ELEMENT]) {
#pragma HLS INTERFACE m_axi port=in bundle=gmem0 offset=slave
#pragma HLS INTERFACE m_axi port=out bundle=gmem1 offset=slave
#pragma HLS INTERFACE s_axilite port=in bundle=control
#pragma HLS INTERFACE s_axilite port=out bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Local buffers holding floats in fixed-point DTYPE
    DTYPE in_local[BATCH_SIZE_1];
#pragma HLS array_partition variable=in_local cyclic factor=2 dim=1
    DTYPE out_local[BATCH_SIZE_1];
#pragma HLS array_partition variable=out_local cyclic factor=8 dim=1

    int counter = 0;

    // Unpack interface words into local fixed-point buffer.
    // FLOATS_PER_ELEMENT == 1 in the testbench, so this becomes a simple copy+convert.
    for (int i = 0; i < BATCH_SIZE_1 / FLOATS_PER_ELEMENT; i++) {
#pragma HLS pipeline
        for (int j = 0; j < FLOATS_PER_ELEMENT; j++) {
#pragma HLS unroll
            raw_float t;
            t.raw_val = in[i].data[j];
            in_local[counter] = (DTYPE)t.float_val;
            counter++;
        }
    }

    // Per-substream state arrays
    DTYPE u_hat_arr[INTERNAL_BATCHES];
#pragma HLS array_partition variable=u_hat_arr cyclic factor=4 dim=1
    DTYPE p_arr_1[INTERNAL_BATCHES];
#pragma HLS array_partition variable=p_arr_1 cyclic factor=4 dim=1
    DTYPE k_arr[INTERNAL_BATCHES];
#pragma HLS array_partition variable=k_arr block factor=2 dim=1
    DTYPE calc_temp_arr[INTERNAL_BATCHES];
#pragma HLS array_partition variable=calc_temp_arr cyclic factor=4 dim=1

    // Initialize substreams
    for (int i = 0; i < INTERNAL_BATCHES; i++) {
#pragma HLS unroll factor=4
        u_hat_arr[i] = in_local[i * INTERNAL_BATCH_SIZE];
        p_arr_1[i] = (DTYPE)0.5;
        out_local[i * INTERNAL_BATCH_SIZE] = u_hat_arr[i];
    }

    // Main processing loop (streamed across t)
    for (int t = 1; t < INTERNAL_BATCH_SIZE; t++) {
#pragma HLS pipeline II=1
        for (int i = 0; i < INTERNAL_BATCHES; i++) {
#pragma HLS unroll factor=4
            calc_temp_arr[i] = p_arr_1[i] + (DTYPE)0.01;
            k_arr[i] = calc_temp_arr[i] / (p_arr_1[i] + (DTYPE)1.01);
            u_hat_arr[i] = u_hat_arr[i] + k_arr[i] * (in_local[i * INTERNAL_BATCH_SIZE + t] - u_hat_arr[i]);
            p_arr_1[i] = ((DTYPE)1 - k_arr[i]) * calc_temp_arr[i];
            out_local[i * INTERNAL_BATCH_SIZE + t] = u_hat_arr[i];
        }
    }

    // Pack local floats back into interface words
    counter = 0;
    for (int i = 0; i < BATCH_SIZE_1 / FLOATS_PER_ELEMENT; i++) {
#pragma HLS unroll factor=2
        for (int j = 0; j < FLOATS_PER_ELEMENT; j++) {
#pragma HLS unroll
            raw_float t;
            t.float_val = (float)out_local[counter];
            out[i].data[j] = t.raw_val;
            counter++;
        }
    }
}

