static void merge_ranges(TYPE a[SIZE], TYPE temp[SIZE], int left, int mid, int right) {
    int i = left;
    int j = mid;
    int k = left;
    while (i < mid && j < right) {
        if (a[i] <= a[j]) {
            temp[k++] = a[i++];
        } else {
            temp[k++] = a[j++];
        }
    }
    while (i < mid) {
        temp[k++] = a[i++];
    }
    while (j < right) {
        temp[k++] = a[j++];
    }
    for (k = left; k < right; k++) {
        a[k] = temp[k];
    }
}

void ms_mergesort(TYPE a[SIZE]) {
    int n = SIZE;
    TYPE temp[SIZE];
    for (int width = 1; width < n; width <<= 1) {
        for (int i = 0; i < n; i += 2 * width) {
            int left = i;
            int mid = i + width;
            if (mid > n) mid = n;
            int right = i + 2 * width;
            if (right > n) right = n;
            if (mid < right) {
                merge_ranges(a, temp, left, mid, right);
            }
        }
    }
}

int main() {
    TYPE a[SIZE];
    srand((unsigned)time(NULL));
    for (int i = 0; i < SIZE; i++) {
        a[i] = (TYPE)(rand() % 100000 - 50000);
    }
    ms_mergesort(a);
    int ok = 1;
    for (int i = 0; i + 1 < SIZE; i++) {
        if (a[i] > a[i+1]) {
            ok = 0;
