                merge_ranges(a, temp, left, mid, right);
            }
        }
    }
}

static void fill_pattern(TYPE a[SIZE], int cycle) {
    int p = cycle % 7;
    if (p == 0) {
        // ascending with small offset
        for (int i = 0; i < SIZE; ++i) a[i] = (TYPE)(i - 1024 + cycle);
    } else if (p == 1) {
        // descending
        for (int i = 0; i < SIZE; ++i) a[i] = (TYPE)(1024 - i + (cycle % 50));
    } else if (p == 2) {
        // all equal
        TYPE v = (TYPE)(cycle - 12);
        for (int i = 0; i < SIZE; ++i) a[i] = v;
    } else if (p == 3) {
        // alternating small/large, with negatives
        for (int i = 0; i < SIZE; ++i) {
            if ((i & 1) == 0) a[i] = (TYPE)((i % 100) - cycle);
            else a[i] = (TYPE)(-((int)(i % 100)) + cycle);
        }
    } else if (p == 4) {
        // many duplicates
        for (int i = 0; i < SIZE; ++i) a[i] = (TYPE)((i % 10) - (cycle % 7));
    } else if (p == 5) {
        // two blocks: first half ascending small, second half descending small
        for (int i = 0; i < SIZE/2; ++i) a[i] = (TYPE)(i % 500);
        for (int i = SIZE/2; i < SIZE; ++i) a[i] = (TYPE)(500 - (i % 500));
    } else { // p == 6
        // few distinct values with small perturbations
        for (int i = 0; i < SIZE; ++i) {
            int r = i % 5;
            if (r == 0) a[i] = 1000 + (cycle % 3);
            else if (r == 1) a[i] = -1000 - (cycle % 5);
            else a[i] = (TYPE)((r * 7) - (cycle % 11));
        }
    }
}

