// hls.cpp
// Merge-sort implementation intended for Vivado HLS (C++98 environment).
// Top-level function is extern "C" to match HLS expectations.

#include <stdint.h>

#define SIZE 2048
#define TYPE int32_t

extern "C" {

// Merge routine: merge the inclusive range [start..m] and [m+1..stop].
// This implementation copies the left half in normal order and the right
// half in reversed order into a temporary buffer and then merges back.
// The temporary buffer is partitioned to help HLS performance.
void merge(TYPE a[SIZE], int start, int m, int stop) {
    TYPE temp[SIZE];
#pragma HLS array_partition variable=temp cyclic factor=32 dim=1

    int i, j, k;

    // Copy left half into temp at same indices
    for (i = start; i <= m; i++) {
        temp[i] = a[i];
    }

    // Copy right half into temp in reversed order into positions m+1..stop
    for (j = m + 1; j <= stop; j++) {
        temp[m + 1 + stop - j] = a[j];
    }

    i = start;
    j = stop;

    // Merge from temp back into a[start..stop]
    for (k = start; k <= stop; k++) {
        TYPE tmp_j = temp[j];
        TYPE tmp_i = temp[i];
        if (tmp_j < tmp_i) {
            a[k] = tmp_j;
            j--;
        } else {
            a[k] = tmp_i;
            i++;
        }
    }
}

// Iterative bottom-up mergesort. Care is taken to avoid invoking merge
// when the left half index (mid) is outside the array bounds.
void sort(TYPE a[SIZE]) {
    const int start = 0;
    const int stop = SIZE - 1;
    const int n = SIZE;

    // Iterative bottom-up mergesort: width doubles each iteration.
    for (int width = 1; width < n; width <<= 1) {
        for (int i = start; i <= stop; i += 2 * width) {
            int from = i;
            int mid = i + width - 1;
            int to = i + 2 * width - 1;

            // If there is no second half (mid >= stop), nothing to merge
            if (mid >= stop) continue;

            if (to <= stop) {
                merge(a, from, mid, to);
            } else {
                // Merge with the available tail
                merge(a, from, mid, stop);
            }
        }
    }
}

void ms_mergesort(TYPE a[SIZE]) {
#pragma HLS INTERFACE m_axi port=a offset=slave bundle=gmem
#pragma HLS INTERFACE s_axilite port=a bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    sort(a);
}

} // extern "C"

