// Testbench for ms_mergesort for use with Vivado HLS C++98 toolchain.
// Uses C headers (stdint.h, limits.h) instead of C++11 <cstdint>.

#include <cstdio>
#include <cstdlib>
#include <climits>
#include <cstring>
#include <limits.h>
#include <stdint.h>

#define SIZE 2048
#define TYPE int32_t
#define TYPE_MAX INT32_MAX

// The DUT is implemented in HLS C (hls.cpp) with this exact signature.
// The extern "C" declaration must match the HLS top-level function exactly.
extern "C" void ms_mergesort(TYPE a[SIZE]);

// Reference merge for software model: merges [left..mid-1] and [mid..right-1]
// where mid and right are treated as indices (mid,right are exclusive for the right bound).
static void merge_ranges(TYPE a[SIZE], TYPE temp[SIZE], int left, int mid, int right) {
    int i = left;
    int j = mid;
    int k = left;
    while (i < mid && j < right) {
        if (a[i] <= a[j]) {
            temp[k++] = a[i++];
        } else {
            temp[k++] = a[j++];
        }
    }
    while (i < mid) {
        temp[k++] = a[i++];
    }
    while (j < right) {
        temp[k++] = a[j++];
    }
    for (k = left; k < right; k++) {
        a[k] = temp[k];
    }
}

// Reference software mergesort used for validation in other contexts.
void ms_mergesort_sw(TYPE a[SIZE]) {
    int n = SIZE;
    TYPE temp[SIZE];
    for (int width = 1; width < n; width <<= 1) {
        for (int i = 0; i < n; i += 2 * width) {
            int left = i;
            int mid = i + width;
            if (mid > n) mid = n;
            int right = i + 2 * width;
            if (right > n) right = n;
            if (mid < right) {
                merge_ranges(a, temp, left, mid, right);
            }
        }
    }
}

// Fill array with a variety of deterministic patterns based on cycle
static void fill_pattern(TYPE a[SIZE], int cycle) {
    int p = cycle % 7;
    if (p == 0) {
        // ascending with small offset
        for (int i = 0; i < SIZE; ++i) a[i] = (TYPE)(i - 1024 + cycle);
    } else if (p == 1) {
        // descending
        for (int i = 0; i < SIZE; ++i) a[i] = (TYPE)(1024 - i + (cycle % 50));
    } else if (p == 2) {
        // all equal
        TYPE v = (TYPE)(cycle - 12);
        for (int i = 0; i < SIZE; ++i) a[i] = v;
    } else if (p == 3) {
        // alternating small/large, with negatives
        for (int i = 0; i < SIZE; ++i) {
            if ((i & 1) == 0) a[i] = (TYPE)((i % 100) - cycle);
            else a[i] = (TYPE)(-((int)(i % 100)) + cycle);
        }
    } else if (p == 4) {
        // many duplicates
        for (int i = 0; i < SIZE; ++i) a[i] = (TYPE)((i % 10) - (cycle % 7));
    } else if (p == 5) {
        // two blocks: first half ascending small, second half descending small
        for (int i = 0; i < SIZE/2; ++i) a[i] = (TYPE)(i % 500);
        for (int i = SIZE/2; i < SIZE; ++i) a[i] = (TYPE)(500 - (i % 500));
    } else { // p == 6
        // few distinct values with small perturbations
        for (int i = 0; i < SIZE; ++i) {
            int r = i % 5;
            if (r == 0) a[i] = 1000 + (cycle % 3);
            else if (r == 1) a[i] = -1000 - (cycle % 5);
            else a[i] = (TYPE)((r * 7) - (cycle % 11));
        }
    }
}

