// hls.cpp
// Top-level SpMV implementation for Vivado HLS (C++98 compatible).
// NOTE: Use C-style stdint header for compatibility with Vivado HLS 2018.3 toolchain.

#include <stdint.h>

#define NNZ 6
#define N 4

typedef int32_t TYPE;

extern "C" {

void spmv(TYPE *val, int32_t *cols, int32_t *rowDelimiters, TYPE *vec, TYPE *out) {
#pragma HLS INTERFACE m_axi port=val offset=slave bundle=gmem0 depth=NNZ
#pragma HLS INTERFACE m_axi port=cols offset=slave bundle=gmem1 depth=NNZ
#pragma HLS INTERFACE m_axi port=rowDelimiters offset=slave bundle=gmem2 depth=N+1
#pragma HLS INTERFACE m_axi port=vec offset=slave bundle=gmem3 depth=N
#pragma HLS INTERFACE m_axi port=out offset=slave bundle=gmem4 depth=N

#pragma HLS INTERFACE s_axilite port=val bundle=control
#pragma HLS INTERFACE s_axilite port=cols bundle=control
#pragma HLS INTERFACE s_axilite port=rowDelimiters bundle=control
#pragma HLS INTERFACE s_axilite port=vec bundle=control
#pragma HLS INTERFACE s_axilite port=out bundle=control
#pragma HLS INTERFACE s_axilite port=return bundle=control

    // Compute sparse matrix-vector product in CSR format.
    // We use compile-time constants NNZ and N that match the testbench sizes.
    for (int i = 0; i < N; i++) {
        TYPE sum = 0;
        int tmp_begin = rowDelimiters[i];
        int tmp_end = rowDelimiters[i + 1];
        for (int j = tmp_begin; j < tmp_end; j++) {
#pragma HLS pipeline II=1
#pragma HLS loop_tripcount min=0 max=NNZ avg=(NNZ/N)
            sum += val[j] * vec[cols[j]];
        }
        out[i] = sum;
    }
}

} // extern "C"

