} LSTM_Unit;

static LSTM_Unit global_lstm_unit = {0.0, 0.0};

double sigmoid(double x)
{
    return (1.0 / (1.0 + exp(-x)));
}

void performInference(double i, double f, double c, double o)
{
    double f_r = sigmoid(f);
    double i_r = sigmoid(i);
    double o_r = sigmoid(o);
    global_lstm_unit.cell_state_ = f_r * global_lstm_unit.cell_state_ + tanh(c) * i_r;
    global_lstm_unit.hidden_state_ = o_r * tanh(global_lstm_unit.cell_state_);
}

double get_hidden_state_(void)
{
    return global_lstm_unit.hidden_state_;
}

